INSERT INTO `Characters` VALUES (1,145,'Haruno, Sakura','{\"Age\":\"12-13 (I), 16-17 (II), 19 (The Last)\",\"Birthday\":\"March 28\",\"Horoscope\":\"Aries\",\"Blood type\":\"O\",\"Height\":\"149cm (I), 161cm (II)\",\"Weight\":\"35kg (I), 45kg (II)\",\"Hair\":\"Pink\",\"Eyes\":\"Green\",\"Rank\":\"Genin (I); Chuunin (II); Jounin (The Last)\",\"Family\":\"Kizashi Haruno (father), Mebuki Haruno (mother)\",\"Likes\":\"Syrup coated anko dumplings; Umeboshi; Anmitsu; Word Puzzles; Studying her medical studdies.\",\"Dislikes\":\"Anything Spicy; Naruto (at first); Ino (at first)\",\"Description\":\"Sakura is the only female ninja of Team 7. When she first meets Naruto she is physically weak and has an immense crush on Sasuke. She dislikes Naruto as well.The only thing she\\u0027s good at is her brain as the smartest girl in ninja academy her excellent chakra control, out of that she could be categorized as a kunoichi. In the first part of the Chuunin exam she is easily able to answer the questions, but in the second part she is unable to defeat the Sound ninja attacking Sasuke and Naruto. She makes a pledge to become a better ninja and a better person. To prove her commitment she cuts her long hair with a kunai.\",\"Description_2\":\"In the third part of the Chuunin Exam she goes up against Ino Yamanaka, her former friend but current rival for Sasuke\\u0027s affections. The two defeat each other simultaneously. This turns their relationship in a rivalry between friends.\",\"Description_3\":\"After the time skip she is now a chuunin having been trained by Tsunade for the past two years. She is now a medic Ninja of considerable skill, enough skill to possibly defeat Tsunade one day. It is shown when she is able to do a complicated surgery to extract poisons out of Kankuro body and make an antidote of the new type poison that Sasori used,which the Suna gakure medical-nin unable to do.\",\"Description_4\":\"During the time skip she\\u0027s also matured in personality, she become calmer compare when she were Genin, but she still has her temper especially when Naruto is fooling around in front of her she will beat him up into a bloody pulp.\",\"Description_5\":\"Sakura has grown not only as a medical-nin, now she\\u0027s also a capable fighter. She can manage to destroy the ground with her fist using her inhuman strength, a chakra control technique she learned from Tsunade, and she is also able to beat Sasori from Akatsuki together with elder Chiyo from Sunagakure.  Additionally she is a genjutsu type, and though she has yet to use that potential she does show an almost complete immunity to being trapped in an illusion.\"}','{\"Age\": \"12-13 (I), 16-17 (II), 19 (The Last)\", \"Eyes\": \"Green\", \"Hair\": \"Pink\", \"Rank\": \"Genin (I); Chuunin (II); Jounin (The Last)\", \"Likes\": \"Syrup coated anko dumplings; Umeboshi; Anmitsu; Word Puzzles; Studying her medical studdies.\", \"Family\": \"Kizashi Haruno (father), Mebuki Haruno (mother)\", \"Height\": \"149cm (I), 161cm (II)\", \"Weight\": \"35kg (I), 45kg (II)\", \"Birthday\": \"March 28\", \"Dislikes\": \"Anything Spicy; Naruto (at first); Ino (at first)\", \"Horoscope\": \"Aries\", \"Blood type\": \"O\", \"Description\": \"Sakura is the only female ninja of Team 7. When she first meets Naruto she is physically weak and has an immense crush on Sasuke. She dislikes Naruto as well.The only thing she\'s good at is her brain as the smartest girl in ninja academy her excellent chakra control, out of that she could be categorized as a kunoichi. In the first part of the Chuunin exam she is easily able to answer the questions, but in the second part she is unable to defeat the Sound ninja attacking Sasuke and Naruto. She makes a pledge to become a better ninja and a better person. To prove her commitment she cuts her long hair with a kunai.\", \"Description_2\": \"In the third part of the Chuunin Exam she goes up against Ino Yamanaka, her former friend but current rival for Sasuke\'s affections. The two defeat each other simultaneously. This turns their relationship in a rivalry between friends.\", \"Description_3\": \"After the time skip she is now a chuunin having been trained by Tsunade for the past two years. She is now a medic Ninja of considerable skill, enough skill to possibly defeat Tsunade one day. It is shown when she is able to do a complicated surgery to extract poisons out of Kankuro body and make an antidote of the new type poison that Sasori used,which the Suna gakure medical-nin unable to do.\", \"Description_4\": \"During the time skip she\'s also matured in personality, she become calmer compare when she were Genin, but she still has her temper especially when Naruto is fooling around in front of her she will beat him up into a bloody pulp.\", \"Description_5\": \"Sakura has grown not only as a medical-nin, now she\'s also a capable fighter. She can manage to destroy the ground with her fist using her inhuman strength, a chakra control technique she learned from Tsunade, and she is also able to beat Sasori from Akatsuki together with elder Chiyo from Sunagakure.  Additionally she is a genjutsu type, and though she has yet to use that potential she does show an almost complete immunity to being trapped in an illusion.\"}'),(2,85,'Hatake, Kakashi','{\"Age\":\"26\\u201327 (Part I); 29\\u201331 (Part II)\",\"Birthday\":\"September 15\",\"Horoscope\":\"Virgo\",\"Blood type\":\"O\",\"Height\":\"5\\u002211\\u0022\",\"Weight\":\"67.5 kg\",\"Hair\":\"Silver\",\"Eyes\":\"Grey, Sharingan\",\"Rank\":\"Jonin, Former ANBU,\",\"Likes\":\"Icha-Icha series, Broiled Saury with salt, Miso soup with eggplant\",\"Dislikes\":\"Anything sweet\",\"Quote\":\"(from Obito) \\u0022A shinobi who violates the rules is scum, but a shinobi who abandons their friends is worse than scum.\\u0022\",\"Description\":\"Major Background Spoilers\",\"Description_2\":\"Kakashi has an ongoing, albeit slightly one-sided, rivalry with Might Guy, with Guy constantly proclaiming that Kakashi is his rival, and considering his and Kakashi\\u0027s subordinates rivals. Kakashi, however, seems indifferent to their rivalry, which annoys Guy to no end. Guy randomly challenges Kakashi to contests of skill, and Kakashi has acquired a record of 49 wins and 50 losses in doing so. Given that the contests that make up this figure are so varied (ranging from Rock, Paper, Scissors to sumo-wrestling), this is not much of an achievement on Guy\\u0027s part. Nevertheless, Guy is proud of his record.\",\"Description_3\":\"Though he evasively says that he has \\u0022many hobbies\\u0022 when asked about himself, he is commonly seen reading of \\u0022Icha Icha Paradise\\u0022 (\\u30A4\\u30C1\\u30E3\\u30A4\\u30C1\\u30E3\\u30D1\\u30E9\\u30C0\\u30A4\\u30B9, Icha Icha Paradaisu, literally \\u0022Make Out Paradise\\u0022), an adult and probably pornographic novel authored by Jiraiya that is a runaway bestseller in the Naruto world. Kakashi most prominently reads it while training and speaking with his team, and is later seen reading the second known volume in the series, \\u0022Icha Icha Violence\\u0022 (\\u30A4\\u30C1\\u30E3\\u30A4\\u30C1\\u30E3\\u30D0\\u30A4\\u30AA\\u30EC\\u30F3\\u30B9, Icha Icha Baiorensu, literally \\u0022Make Out Violence\\u0022). In Part II Naruto gives him the new \\u0022Icha Icha Tactics\\u0022 (\\u30A4\\u30C1\\u30E3\\u30A4\\u30C1\\u30E3\\u30BF\\u30AF\\u30C6\\u30A3\\u30AF\\u30B9, Icha Icha Takutikusu, literally \\u0022Make Out Tactics\\u0022).\",\"Description_4\":\"Kakashi\\u0027s Sharingan eye gives him a significant advantage in battle, as he can copy enemy techniques and use them as his own, as well as track and predict his opponent\\u0027s movements flawlessly. Because it is a transplanted eye, his Sharingan eye is always active. While this would not be much of a problem for an Uchiha, his non-Uchiha blood causes it to use much more chakra than it should. Because of this, he covers it with his headband and only utilizes it in the most dangerous battles. Kakashi\\u0027s use of the Sharingan is as good as that of Itachi Uchiha, though the aforementioned handicaps brought about by the nature of his eye make him somewhat weaker in comparison. In Part II Kakashi is able to develop his own Mangekyo Sharingan. With his variant he is able to manipulate space-time to conduct long range attacks, and in its two uses has been capable of severing another\\u0027s arms and otherwise sending things to different dimensions. Much like the standard Sharingan, the Mangekyo Sharingan tires Kakashi considerably, and after using it only three times he was hospitalized for a week due to its chakra usage.\",\"With his Sharingan Kakashi has been able to copy more than one thousand jutsu, giving him the nickname \\u0022Copy Ninja Kakashi\\u0022. As a result, Kakashi\\u0027s arsenal most prominently features ninjutsu abilities and has led to him becoming a specialist in the field. Many of the jutsu he has been seen copying in the series are water-based attacks, though most of these he only uses against the person he copies them from. He does, however, use Water Release\":\"Water Encampment Wall on occasion as a way to block attacks. He less frequently uses other elemental attacks such as Fire Release: Great Fireball Technique to attack opponents or Earth Release: Inner Decapitation Technique (\\u571F\\u9041\\u30FB\\u5FC3\\u4E2D\\u65AC\\u9996\\u306E\\u8853, Doton: Shinj\\u016B Zanshu no Jutsu, Viz \\u0022Groundhog Technique Decapitation\\u0022, English TV \\u0022Headhunter Jutsu\\u0022) to pull opponents below ground and immobilize them. He can also create shadow clones, though because he lacks Naruto\\u0027s chakra reserves, he exercises the ability with caution, rarely creating more than one at a time.\",\"While Kakashi specializes in the use of ninjutsu due to his Sharingan he is fairly adept with other jutsu types, though his use of them is rarely seen. Demonic Illusion\":\"Hell Viewing Technique (\\u9B54\\u5E7B\\u30FB\\u5948\\u70D9\\u898B\\u306E\\u8853, Magen: Narakumi no Jutsu) causes his opponent to see what they would find a horrifying vision, keeping them preoccupied until they can overcome the illusion. A Thousand Years of Pain (death in english dub) (\\u5343\\u5E74\\u6BBA\\u3057, Sennen Goroshi) consists of Kakashi forcefully plunging his index and middle fingers into an opponent\\u0027s rectum. While only capable of launching the opponent humorous distances in typical uses, the fingers can be replaced with kunai attached with exploding tags to actually do damage to the person one is attacking.\",\"Description_5\":\"When he was younger, Kakashi was taught how to use the Rasengan by the Fourth Hokage. Because the Rasengan is meant to have the user\\u0027s chakra nature mixed with it, Kakashi attempted to add his lightning-based chakra to it, though was ultimately unsuccessful. In time he instead created the Chidori, his only original jutsu. After the jutsu\\u0027s initial creation, Kakashi was unable to use the Chidori to its full potential as the sheer speed of the attack left his normal eyes unable to see any form of an enemy counterattack. After acquiring the Sharingan, however, he was able to overcome this shortcoming. Through repeated use and increased proficiency with it, Kakashi\\u0027s Chidori has been upgraded and renamed to the Lightning Blade due to him having cut through a bolt of lightning with it.\"}','{\"Age\": \"26–27 (Part I); 29–31 (Part II)\", \"Eyes\": \"Grey, Sharingan\", \"Hair\": \"Silver\", \"Rank\": \"Jonin, Former ANBU,\", \"Likes\": \"Icha-Icha series, Broiled Saury with salt, Miso soup with eggplant\", \"Quote\": \"(from Obito) \\\"A shinobi who violates the rules is scum, but a shinobi who abandons their friends is worse than scum.\\\"\", \"Height\": \"5\\\"11\\\"\", \"Weight\": \"67.5 kg\", \"Birthday\": \"September 15\", \"Dislikes\": \"Anything sweet\", \"Horoscope\": \"Virgo\", \"Blood type\": \"O\", \"Description\": \"Major Background Spoilers\", \"Description_2\": \"Kakashi has an ongoing, albeit slightly one-sided, rivalry with Might Guy, with Guy constantly proclaiming that Kakashi is his rival, and considering his and Kakashi\'s subordinates rivals. Kakashi, however, seems indifferent to their rivalry, which annoys Guy to no end. Guy randomly challenges Kakashi to contests of skill, and Kakashi has acquired a record of 49 wins and 50 losses in doing so. Given that the contests that make up this figure are so varied (ranging from Rock, Paper, Scissors to sumo-wrestling), this is not much of an achievement on Guy\'s part. Nevertheless, Guy is proud of his record.\", \"Description_3\": \"Though he evasively says that he has \\\"many hobbies\\\" when asked about himself, he is commonly seen reading of \\\"Icha Icha Paradise\\\" (イチャイチャパラダイス, Icha Icha Paradaisu, literally \\\"Make Out Paradise\\\"), an adult and probably pornographic novel authored by Jiraiya that is a runaway bestseller in the Naruto world. Kakashi most prominently reads it while training and speaking with his team, and is later seen reading the second known volume in the series, \\\"Icha Icha Violence\\\" (イチャイチャバイオレンス, Icha Icha Baiorensu, literally \\\"Make Out Violence\\\"). In Part II Naruto gives him the new \\\"Icha Icha Tactics\\\" (イチャイチャタクティクス, Icha Icha Takutikusu, literally \\\"Make Out Tactics\\\").\", \"Description_4\": \"Kakashi\'s Sharingan eye gives him a significant advantage in battle, as he can copy enemy techniques and use them as his own, as well as track and predict his opponent\'s movements flawlessly. Because it is a transplanted eye, his Sharingan eye is always active. While this would not be much of a problem for an Uchiha, his non-Uchiha blood causes it to use much more chakra than it should. Because of this, he covers it with his headband and only utilizes it in the most dangerous battles. Kakashi\'s use of the Sharingan is as good as that of Itachi Uchiha, though the aforementioned handicaps brought about by the nature of his eye make him somewhat weaker in comparison. In Part II Kakashi is able to develop his own Mangekyo Sharingan. With his variant he is able to manipulate space-time to conduct long range attacks, and in its two uses has been capable of severing another\'s arms and otherwise sending things to different dimensions. Much like the standard Sharingan, the Mangekyo Sharingan tires Kakashi considerably, and after using it only three times he was hospitalized for a week due to its chakra usage.\", \"Description_5\": \"When he was younger, Kakashi was taught how to use the Rasengan by the Fourth Hokage. Because the Rasengan is meant to have the user\'s chakra nature mixed with it, Kakashi attempted to add his lightning-based chakra to it, though was ultimately unsuccessful. In time he instead created the Chidori, his only original jutsu. After the jutsu\'s initial creation, Kakashi was unable to use the Chidori to its full potential as the sheer speed of the attack left his normal eyes unable to see any form of an enemy counterattack. After acquiring the Sharingan, however, he was able to overcome this shortcoming. Through repeated use and increased proficiency with it, Kakashi\'s Chidori has been upgraded and renamed to the Lightning Blade due to him having cut through a bolt of lightning with it.\", \"While Kakashi specializes in the use of ninjutsu due to his Sharingan he is fairly adept with other jutsu types, though his use of them is rarely seen. Demonic Illusion\": \"Hell Viewing Technique (魔幻・奈烙見の術, Magen: Narakumi no Jutsu) causes his opponent to see what they would find a horrifying vision, keeping them preoccupied until they can overcome the illusion. A Thousand Years of Pain (death in english dub) (千年殺し, Sennen Goroshi) consists of Kakashi forcefully plunging his index and middle fingers into an opponent\'s rectum. While only capable of launching the opponent humorous distances in typical uses, the fingers can be replaced with kunai attached with exploding tags to actually do damage to the person one is attacking.\", \"With his Sharingan Kakashi has been able to copy more than one thousand jutsu, giving him the nickname \\\"Copy Ninja Kakashi\\\". As a result, Kakashi\'s arsenal most prominently features ninjutsu abilities and has led to him becoming a specialist in the field. Many of the jutsu he has been seen copying in the series are water-based attacks, though most of these he only uses against the person he copies them from. He does, however, use Water Release\": \"Water Encampment Wall on occasion as a way to block attacks. He less frequently uses other elemental attacks such as Fire Release: Great Fireball Technique to attack opponents or Earth Release: Inner Decapitation Technique (土遁・心中斬首の術, Doton: Shinjū Zanshu no Jutsu, Viz \\\"Groundhog Technique Decapitation\\\", English TV \\\"Headhunter Jutsu\\\") to pull opponents below ground and immobilize them. He can also create shadow clones, though because he lacks Naruto\'s chakra reserves, he exercises the ability with caution, rarely creating more than one at a time.\"}'),(3,13,'Uchiha, Sasuke','{\"Age\":\"12-13 (I); 16-17 (II); 19 (The Last: Naruto the Movie); 32 (Boruto: Naruto the Movie)\",\"Birthday\":\"July 23\",\"Ninja Registration No\":\"012606\",\"Horoscope\":\"Leo\",\"Blood type\":\"AB\",\"Height\":\"153.2 cm(I); 168 cm (II); 175 cm (The Last: Naruto the Movie); 182 cm (Boruto: Naruto the Movie)\",\"Weight\":\"43.5kg(I); 52.2kg (II); 55kg (The Last: Naruto the Movie); 65kg (Boruto: Naruto the Movie)\",\"Hair\":\"Ebony Black with Blue tints\",\"Eyes\":\"Black; Right eye Red (when using Sharingan) \\u0026amp;\",\"Rank\":\"Genin;\",\"Kekkei Genkai\":\"Sharingan (Part 1)\",\"Likes\":\"Omusubi (Okaka) (omusubi is like Onigiri: Okaka is dried Bonito) Tomato\",\"Dislikes\":\"Everything that gets in the way of his revenge, natto (fermented soybeans) and sweet food\",\"Hates\":\"Itachi (Part I)\",\"Talents\":\"Highly skilled ninja, specializes in fire and lightning jutsu.\",\"Description\":\"When Sasuke was young, his clan was murdered by his older brother, Itachi. With his parents and family now gone, his brother spared him and left him to survive by himself. He told Sasuke to hate him. Sasuke tried to forget about the past by applying himself in the ninja academy and fitting in with the rest of the leaf village.\",\"Description_2\":\"After his fight with Naruto, he believes he\\u0027s been wasting his time \\u0022playing ninja\\u0022 with the people of the leaf village. His new goal is to get stronger so he can avenge his clan by killing Itachi and then restore the Uchiha clan.\",\"Description_3\":\"As a wielder of the Sharingan (the kekkei genkai of the Uchiha clan), he learns to use Chidori and has a vast knowledge of the various Fire Jutsus. The curse seal which Orichimaru gives him during the Chuunin exam, at first, enhanced his power but at the risk of killing him. Now he can use it of his own free will.\",\"Description_4\":\"Claiming at first that he doesn\\u0027t need any friends, he is forced to contradict himself when he sees that either Naruto or Sakura are in danger. Remembering this type of Sasuke is what brings motivation to Naruto. Sasuke openly admitted to Naruto that he was his closest friend.\",\"Description_5\":\"Appearance\",\"Description_6\":\"Sasuke has black hair with a blue tint that lengthens as the story goes with onyx eyes and has lighter skin than his brother Itachi. Like many other members of his clan, his hair hangs over both sides of his face to roughly his cheeks. In his curse seal form, he has grey skin with wings on his back that resemble giant webbed hands. He also has hair similar to Madara Uchiha except in a greyish-blue color.\",\"Description_7\":\"At the beginning of Part I, Sasuke\\u0027s clothing made up a blue, short-sleeved shirt with a raised collar and the Uchiha crest on the back and white shorts. An interesting thing is that during Part I the Uchiha symbol on his back gets smaller each time he changes his outfit. In the last stage of the Chunin exams, he wore a black, one pieced version of this outfit but eventually went back to his original clothes.\",\"In Part II, Sasuke has grown noticeably taller (almost eye height with Itachi) and slightly more muscular. wears a white long sleeved shirt that\\u0027s open at the torso with a smaller version of the Uchiha crest on his collar. He wears black pants with a blue cloth hanging from his half way up his stomach to his knees. He also wears a purple rope belt (Japanese name\":\"Shimenawa) tied in a bow fashion found on many Sound ninja, only the bow is in a different style and is tied in the front instead of the back. He also will at points remove his shirt and hang it from his belt around his waist to give his wings in Curse Seal Level 2 room to move (also without transforming).\"}','{\"Age\": \"12-13 (I); 16-17 (II); 19 (The Last: Naruto the Movie); 32 (Boruto: Naruto the Movie)\", \"Eyes\": \"Black; Right eye Red (when using Sharingan) &amp;\", \"Hair\": \"Ebony Black with Blue tints\", \"Rank\": \"Genin;\", \"Hates\": \"Itachi (Part I)\", \"Likes\": \"Omusubi (Okaka) (omusubi is like Onigiri: Okaka is dried Bonito) Tomato\", \"Height\": \"153.2 cm(I); 168 cm (II); 175 cm (The Last: Naruto the Movie); 182 cm (Boruto: Naruto the Movie)\", \"Weight\": \"43.5kg(I); 52.2kg (II); 55kg (The Last: Naruto the Movie); 65kg (Boruto: Naruto the Movie)\", \"Talents\": \"Highly skilled ninja, specializes in fire and lightning jutsu.\", \"Birthday\": \"July 23\", \"Dislikes\": \"Everything that gets in the way of his revenge, natto (fermented soybeans) and sweet food\", \"Horoscope\": \"Leo\", \"Blood type\": \"AB\", \"Description\": \"When Sasuke was young, his clan was murdered by his older brother, Itachi. With his parents and family now gone, his brother spared him and left him to survive by himself. He told Sasuke to hate him. Sasuke tried to forget about the past by applying himself in the ninja academy and fitting in with the rest of the leaf village.\", \"Description_2\": \"After his fight with Naruto, he believes he\'s been wasting his time \\\"playing ninja\\\" with the people of the leaf village. His new goal is to get stronger so he can avenge his clan by killing Itachi and then restore the Uchiha clan.\", \"Description_3\": \"As a wielder of the Sharingan (the kekkei genkai of the Uchiha clan), he learns to use Chidori and has a vast knowledge of the various Fire Jutsus. The curse seal which Orichimaru gives him during the Chuunin exam, at first, enhanced his power but at the risk of killing him. Now he can use it of his own free will.\", \"Description_4\": \"Claiming at first that he doesn\'t need any friends, he is forced to contradict himself when he sees that either Naruto or Sakura are in danger. Remembering this type of Sasuke is what brings motivation to Naruto. Sasuke openly admitted to Naruto that he was his closest friend.\", \"Description_5\": \"Appearance\", \"Description_6\": \"Sasuke has black hair with a blue tint that lengthens as the story goes with onyx eyes and has lighter skin than his brother Itachi. Like many other members of his clan, his hair hangs over both sides of his face to roughly his cheeks. In his curse seal form, he has grey skin with wings on his back that resemble giant webbed hands. He also has hair similar to Madara Uchiha except in a greyish-blue color.\", \"Description_7\": \"At the beginning of Part I, Sasuke\'s clothing made up a blue, short-sleeved shirt with a raised collar and the Uchiha crest on the back and white shorts. An interesting thing is that during Part I the Uchiha symbol on his back gets smaller each time he changes his outfit. In the last stage of the Chunin exams, he wore a black, one pieced version of this outfit but eventually went back to his original clothes.\", \"Kekkei Genkai\": \"Sharingan (Part 1)\", \"Ninja Registration No\": \"012606\", \"In Part II, Sasuke has grown noticeably taller (almost eye height with Itachi) and slightly more muscular. wears a white long sleeved shirt that\'s open at the torso with a smaller version of the Uchiha crest on his collar. He wears black pants with a blue cloth hanging from his half way up his stomach to his knees. He also wears a purple rope belt (Japanese name\": \"Shimenawa) tied in a bow fashion found on many Sound ninja, only the bow is in a different style and is tied in the front instead of the back. He also will at points remove his shirt and hang it from his belt around his waist to give his wings in Curse Seal Level 2 room to move (also without transforming).\"}'),(4,17,'Uzumaki, Naruto','{\"Age\":\"12-13 (Naruto part I), 15-17 (part II), 19 (The Last: Naruto the Movie), 27 (Naruto epilogue), 32 (Boruto: Naruto the Movie)\",\"Birthday\":\"October 10\",\"Blood type\":\"B\",\"Height\":\"145\\u2013147 cm (I), 166 cm (II), 174 cm (The Last: Naruto the Movie), 180 cm (Boruto: Naruto the Movie)\",\"Weight\":\"41\\u201344 kg (I), 52 kg (II), 56 kg (The Last: Naruto the Movie), 66 kg (Boruto: Naruto the Movie)\",\"Favorite food\":\"Ichiraku ramen\",\"Description\":\"Born in Konohagakure, a ninja village hidden in the leaves, Naruto Uzumaki was destined for greatness. When born, a powerful nine-tailed demon fox attacked his village. With a wave of its tail, the demon fox could raise tsunamis and shatter mountains. In a valiant attempt to save the village from destruction, the Fourth Hokage, the leader of the Hidden Leaf Village, sealed the demon fox within Naruto\\u0027s newborn body. This was his final act, for the battle with the fox cost him his life.\",\"Description_2\":\"Despite the Fourth Hokage\\u0027s dying wish that Naruto be viewed as a hero for serving as the container for the demon (a Jinchuuriki) the adult villagers of Konoha harbored a fierce hatred for him, with many believing that Naruto and the demon were one and the same. Cast aside as an inhuman monster, Naruto was outcast and ostracized by the villagers for reasons he could not understand. The children his age could only ever follow their parents\\u0027 example; and they too came to harbor a fierce hatred for Naruto.\",\"Description_3\":\"Naruto eventually came to accept that he would live and die alone, and his external response was to perform harmless pranks on the village. Boisterous, raffish and full of life, Naruto soon came to display a somewhat unexpected determination to succeed and be accepted by others. Upon being assigned to \\u0022Team Seven\\u0022 as a Genin-ranked ninja, his true potential soon became outwardly apparent.\",\"Description_4\":\"Vowing to become Hokage one day and using his will to never give in, Naruto saves the village from invading forces and earns his acceptance. Eventually, Naruto learns to harness the power of the Demon Fox sealed inside him to perform acts of strength far beyond what any other human is capable of.\",\"Description_5\":\"In all, Naruto is an admirable character whose sheer determination to succeed despite the odds, earns him respect and devotion from his fellow villagers.\"}','{\"Age\": \"12-13 (Naruto part I), 15-17 (part II), 19 (The Last: Naruto the Movie), 27 (Naruto epilogue), 32 (Boruto: Naruto the Movie)\", \"Height\": \"145–147 cm (I), 166 cm (II), 174 cm (The Last: Naruto the Movie), 180 cm (Boruto: Naruto the Movie)\", \"Weight\": \"41–44 kg (I), 52 kg (II), 56 kg (The Last: Naruto the Movie), 66 kg (Boruto: Naruto the Movie)\", \"Birthday\": \"October 10\", \"Blood type\": \"B\", \"Description\": \"Born in Konohagakure, a ninja village hidden in the leaves, Naruto Uzumaki was destined for greatness. When born, a powerful nine-tailed demon fox attacked his village. With a wave of its tail, the demon fox could raise tsunamis and shatter mountains. In a valiant attempt to save the village from destruction, the Fourth Hokage, the leader of the Hidden Leaf Village, sealed the demon fox within Naruto\'s newborn body. This was his final act, for the battle with the fox cost him his life.\", \"Description_2\": \"Despite the Fourth Hokage\'s dying wish that Naruto be viewed as a hero for serving as the container for the demon (a Jinchuuriki) the adult villagers of Konoha harbored a fierce hatred for him, with many believing that Naruto and the demon were one and the same. Cast aside as an inhuman monster, Naruto was outcast and ostracized by the villagers for reasons he could not understand. The children his age could only ever follow their parents\' example; and they too came to harbor a fierce hatred for Naruto.\", \"Description_3\": \"Naruto eventually came to accept that he would live and die alone, and his external response was to perform harmless pranks on the village. Boisterous, raffish and full of life, Naruto soon came to display a somewhat unexpected determination to succeed and be accepted by others. Upon being assigned to \\\"Team Seven\\\" as a Genin-ranked ninja, his true potential soon became outwardly apparent.\", \"Description_4\": \"Vowing to become Hokage one day and using his will to never give in, Naruto saves the village from invading forces and earns his acceptance. Eventually, Naruto learns to harness the power of the Demon Fox sealed inside him to perform acts of strength far beyond what any other human is capable of.\", \"Description_5\": \"In all, Naruto is an admirable character whose sheer determination to succeed despite the odds, earns him respect and devotion from his fellow villagers.\", \"Favorite food\": \"Ichiraku ramen\"}'),(5,22894,'A','{\"Birthday\":\"June 1\",\"Gender\":\"Male\",\"Age\":\"Part II: 47\",\"Height\":\"Part II: 198.2 cm\",\"Weight\\u0027 Part II\":\"101.1 kg\",\"Blood type\":\"A\",\"Occupation\":\"\",\"Description\":\"Raikage\",\"Description_2\":\"Supreme Leader of the Allied Shinobi Forces\",\"Description_3\":\"The current Raikage is the older brother of the Jinch\\u016Briki of the Eight-Tailed Beast, Killer Bee. It is hinted that Killer Bee, and therefore the Raikage as well, comes from the Yotsuki clan. Knowing Yugito Nii\\u0027s and Killer Bee\\u0027s immense powers if they were to ever transform into their full power forms, he forbade them from doing so. After learning that Killer Bee is captured by Akatsuki, the Raikage demands a meeting of the five Kage and resolves to eliminate Sasuke, Killer Bee\\u0027s captor.\",\"Description_4\":\"He is very caring and protective towards his brother, despite Killer Bee\\u0027s status as a Jinch\\u016Briki, and cried at the idea of his younger brother being captured by Akatsuki.\",\"Description_5\":\"He is very physically strong, as he appears lifting a large amount of weight with just one hand and broke his desk with a single punch. Killer Bee also mentioned in the fight with Sasuke that before him, only the Raikage was able to deflect the Eight-Tails.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"Part II: 47\", \"Gender\": \"Male\", \"Height\": \"Part II: 198.2 cm\", \"(Source\": \"Narutopedia)\", \"Birthday\": \"June 1\", \"Blood type\": \"A\", \"Occupation\": \"\", \"Description\": \"Raikage\", \"Description_2\": \"Supreme Leader of the Allied Shinobi Forces\", \"Description_3\": \"The current Raikage is the older brother of the Jinchūriki of the Eight-Tailed Beast, Killer Bee. It is hinted that Killer Bee, and therefore the Raikage as well, comes from the Yotsuki clan. Knowing Yugito Nii\'s and Killer Bee\'s immense powers if they were to ever transform into their full power forms, he forbade them from doing so. After learning that Killer Bee is captured by Akatsuki, the Raikage demands a meeting of the five Kage and resolves to eliminate Sasuke, Killer Bee\'s captor.\", \"Description_4\": \"He is very caring and protective towards his brother, despite Killer Bee\'s status as a Jinchūriki, and cried at the idea of his younger brother being captured by Akatsuki.\", \"Description_5\": \"He is very physically strong, as he appears lifting a large amount of weight with just one hand and broke his desk with a single punch. Killer Bee also mentioned in the fight with Sasuke that before him, only the Raikage was able to deflect the Eight-Tails.\", \"Weight\' Part II\": \"101.1 kg\"}'),(6,93639,'A (First Raikage)','{\"Birthdate\":\"December 1\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"210.1 cm\",\"Weight\":\"97.2 kg\",\"Blood type\":\"O\",\"Occupation\":\"Raikage\",\"Affiliation\":\"Kumogakure\",\"Manga Debut\":\"Chapter #648\",\"Anime Debut\":\"Naruto Shippuuden Episode #369\",\"Description\":\"A (Viz \\u0022Ei\\u0022, English TV \\u0022Ay\\u0022) was the First Raikage (\\u521D\\u4EE3\\u96F7\\u5F71, Shodai Raikage; Literally meaning \\u0022First or Founding Lightning Shadow\\u0022) who founded Kumogakure in the Land of Lightning.\",\"(Source\":\"Narutopedia)\"}','{\"Gender\": \"Male\", \"Height\": \"210.1 cm\", \"Status\": \"Deceased\", \"Weight\": \"97.2 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"December 1\", \"Blood type\": \"O\", \"Occupation\": \"Raikage\", \"Affiliation\": \"Kumogakure\", \"Anime Debut\": \"Naruto Shippuuden Episode #369\", \"Description\": \"A (Viz \\\"Ei\\\", English TV \\\"Ay\\\") was the First Raikage (初代雷影, Shodai Raikage; Literally meaning \\\"First or Founding Lightning Shadow\\\") who founded Kumogakure in the Land of Lightning.\", \"Manga Debut\": \"Chapter #648\"}'),(7,93637,'A (Second Raikage)','{\"Birthdate\":\"March 1\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"184.2 cm\",\"Weight\":\"84.2 kg\",\"Blood type\":\"O\",\"Occupation\":\"Raikage\",\"Affiliation\":\"Kumogakure\",\"Description\":\"A (\\u30A8\\u30FC, \\u0112; Viz \\u0022Ei\\u0022, English TV \\u0022Ay\\u0022) was the Second Raikage (\\u4E8C\\u4EE3\\u76EE\\u96F7\\u5F71, Nidaime Raikage; Literally meaning \\u0022Second Lightning Shadow\\u0022) of Kumogakure.\",\"Description_2\":\"During his tenure, he entered Kumogakure into a formal alliance with Konohagakure. During the ceremony, both he, and the Second Hokage were ambushed by the Gold and Silver Brothers, who were attempting to stage a coup d\\u0027\\u00E9tat. It is unknown what happened to him, but the Hokage was said to have barely escaped with his life.\",\"(Source\":\"Narutopedia)\",\"Description_3\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Gender\": \"Male\", \"Height\": \"184.2 cm\", \"Status\": \"Deceased\", \"Weight\": \"84.2 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"March 1\", \"Blood type\": \"O\", \"Occupation\": \"Raikage\", \"Affiliation\": \"Kumogakure\", \"Description\": \"A (エー, Ē; Viz \\\"Ei\\\", English TV \\\"Ay\\\") was the Second Raikage (二代目雷影, Nidaime Raikage; Literally meaning \\\"Second Lightning Shadow\\\") of Kumogakure.\", \"Description_2\": \"During his tenure, he entered Kumogakure into a formal alliance with Konohagakure. During the ceremony, both he, and the Second Hokage were ambushed by the Gold and Silver Brothers, who were attempting to stage a coup d\'état. It is unknown what happened to him, but the Hokage was said to have barely escaped with his life.\", \"Description_3\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(8,65133,'A (Third Raikage)','{\"Birthdate\":\"August 1\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"205 cm\",\"Weight\":\"105 kg\",\"Blood type\":\"O\",\"Occupation\":\"Raikage\",\"Affiliation\":\"Kumogakure\",\"Manga Debut\":\"Chapter #494\",\"Anime Debut\":\"Naruto Shippuuden Episode #244\",\"Description\":\"A (\\u30A8\\u30FC, \\u0112; Viz \\u0022Ei\\u0022, English TV \\u0022Ay\\u0022) was the Third Raikage (\\u4E09\\u4EE3\\u76EE\\u96F7\\u5F71, Sandaime Raikage; Literally meaning \\u0022Third Lightning Shadow\\u0022) of Kumogakure thirty years prior to the Fourth Shinobi World War and renowned to be the greatest Raikage the village has ever had.\",\"(Source\":\"Narutopedia)\"}','{\"Gender\": \"Male\", \"Height\": \"205 cm\", \"Status\": \"Deceased\", \"Weight\": \"105 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"August 1\", \"Blood type\": \"O\", \"Occupation\": \"Raikage\", \"Affiliation\": \"Kumogakure\", \"Anime Debut\": \"Naruto Shippuuden Episode #244\", \"Description\": \"A (エー, Ē; Viz \\\"Ei\\\", English TV \\\"Ay\\\") was the Third Raikage (三代目雷影, Sandaime Raikage; Literally meaning \\\"Third Lightning Shadow\\\") of Kumogakure thirty years prior to the Fourth Shinobi World War and renowned to be the greatest Raikage the village has ever had.\", \"Manga Debut\": \"Chapter #494\"}'),(9,23647,'Aburame, Torune','{\"Description\":\"Torune was a ninja of Konohagakure, a member of the Aburame clan, and a high-ranking member of the Root.\",\"Description_2\":\"Except for the lower half of his face, his features were covered by a mask. Glasses were built into the mask obscuring his eyes as is common for the Aburame clan. He wore a short black jacket with red strands hanging over the shoulders, similar to Sai\\u0027s and his partner, F\\u016B\\u0027s. This most likely shows allegiance to Root. He also wore a high collared, all black outfit with a red sash around his waist and what appeared to be an apron over his pants, similar to that of Neji Hy\\u016Bga\\u0027s. He also carried several pouches with him and wore a pair of black gloves.\",\"Description_3\":\"When first introduced, Torune\\u0027s appearance was that of a regular Konoha ANBU, complete with a white cloak and mask.\",\"Description_4\":\"Danz\\u014D stated that he and F\\u016B are two of the most-skilled ninjas in Root. Torune is part of the Aburame clan, and like the other members, he is skilled at using insects in combat. However, his bug techniques are rare even among the Aburame. He controls the many nano-sized, venomous insects that covers his body, allowing him to infect anyone with a mere touch.\",\"Description_5\":\"Due to this he wears gloves and keeps his skin almost completely covered when not in battle. The insects spread onto the opponent\\u0027s skin causing severe pain which can potentially lead to death. Torune can call off the insects with a touch of a finger and remove the venom using an antidote. Shikuro Aburame is said to be the only one with an antidote for the insects\\u0027 venom and the antibodies in his blood to render him immune to the insect\\u0027s poison, so it is thus assumed that Torune is his son. Like many other Root members, Torune wears a tant\\u014D on his back, though he has not yet been seen using it.\"}','{\"Description\": \"Torune was a ninja of Konohagakure, a member of the Aburame clan, and a high-ranking member of the Root.\", \"Description_2\": \"Except for the lower half of his face, his features were covered by a mask. Glasses were built into the mask obscuring his eyes as is common for the Aburame clan. He wore a short black jacket with red strands hanging over the shoulders, similar to Sai\'s and his partner, Fū\'s. This most likely shows allegiance to Root. He also wore a high collared, all black outfit with a red sash around his waist and what appeared to be an apron over his pants, similar to that of Neji Hyūga\'s. He also carried several pouches with him and wore a pair of black gloves.\", \"Description_3\": \"When first introduced, Torune\'s appearance was that of a regular Konoha ANBU, complete with a white cloak and mask.\", \"Description_4\": \"Danzō stated that he and Fū are two of the most-skilled ninjas in Root. Torune is part of the Aburame clan, and like the other members, he is skilled at using insects in combat. However, his bug techniques are rare even among the Aburame. He controls the many nano-sized, venomous insects that covers his body, allowing him to infect anyone with a mere touch.\", \"Description_5\": \"Due to this he wears gloves and keeps his skin almost completely covered when not in battle. The insects spread onto the opponent\'s skin causing severe pain which can potentially lead to death. Torune can call off the insects with a touch of a finger and remove the venom using an antidote. Shikuro Aburame is said to be the only one with an antidote for the insects\' venom and the antibodies in his blood to render him immune to the insect\'s poison, so it is thus assumed that Torune is his son. Like many other Root members, Torune wears a tantō on his back, though he has not yet been seen using it.\"}'),(10,44981,'Aburame, Muta','{\"Description\":\"Muta had long brown hair and like all other Aburame, his eyes were obscured by dark sunglasses. His attire consisted of a long sleeved light tan jacket with a high, upturned collar. The remainder of his form was largely obstructed by the low hemlines and overlaying clothes. He also had a pouch fastened to the back of his outfit which he used to carry around a jar in which he carried additional Kikaich\\u016B bugs.\"}','{\"Description\": \"Muta had long brown hair and like all other Aburame, his eyes were obscured by dark sunglasses. His attire consisted of a long sleeved light tan jacket with a high, upturned collar. The remainder of his form was largely obstructed by the low hemlines and overlaying clothes. He also had a pouch fastened to the back of his outfit which he used to carry around a jar in which he carried additional Kikaichū bugs.\"}'),(11,3428,'Aburame, Shino','{\"Age\":\"13 (I); 16 (II)\",\"Birthday\":\"January 23\",\"Horoscope\":\"Aquarius\",\"Blood Type\":\"AB\",\"Height\":\"161.1 cm (I); 175.1 cm (II)\",\"Weight\":\"48.5 kg(I); 56.6 kg (II)\",\"Rank\":\"Genin (I); Chuunin (II)\",\"Likes\":\"Salad with herb, winter melon, insects\",\"Dislikes\":\"Anything that smells strong\",\"Description\":\"Shino Aburame is character who has a fascination with bugs; most of his spare time is spent watching bugs, he often makes analogies to bugs when talking. In addition to liking bugs, Shino is characterized by his emotionless, solitary, and collected way of doing things. He speaks very bluntly and never allows emotion to interfere with his judgment, sometimes offending people in doing so. Despite his odd personality and occasionally arguing with Kiba, Shino has a very strong sense of connection with his teammates and allies.\",\"Description_2\":\"Shino alongside Hinata Hyuga and Kiba Inuzuka is in team 8 which is led by Kurenai Yuuhi.\",\"Description_3\":\"In battle, Shino is able to take great use of his intelligence, being able to use his analytical and observational skills to make shrewd judgments with pinpoint reasoning. As a member of the Aburame clan, Shino was infused at birth with a special breed of insects that feed on chakra. In return for becoming a living hive, the insects attack opponents, usually while he distracts them, and carry out other tasks as he commands. Shino has found a number of uses for these bugs, and as such has devised a number of jutsu that utilize them for varying purposes, such as creating copies of himself or using bugs for defensive purposes.\"}','{\"Age\": \"13 (I); 16 (II)\", \"Rank\": \"Genin (I); Chuunin (II)\", \"Likes\": \"Salad with herb, winter melon, insects\", \"Height\": \"161.1 cm (I); 175.1 cm (II)\", \"Weight\": \"48.5 kg(I); 56.6 kg (II)\", \"Birthday\": \"January 23\", \"Dislikes\": \"Anything that smells strong\", \"Horoscope\": \"Aquarius\", \"Blood Type\": \"AB\", \"Description\": \"Shino Aburame is character who has a fascination with bugs; most of his spare time is spent watching bugs, he often makes analogies to bugs when talking. In addition to liking bugs, Shino is characterized by his emotionless, solitary, and collected way of doing things. He speaks very bluntly and never allows emotion to interfere with his judgment, sometimes offending people in doing so. Despite his odd personality and occasionally arguing with Kiba, Shino has a very strong sense of connection with his teammates and allies.\", \"Description_2\": \"Shino alongside Hinata Hyuga and Kiba Inuzuka is in team 8 which is led by Kurenai Yuuhi.\", \"Description_3\": \"In battle, Shino is able to take great use of his intelligence, being able to use his analytical and observational skills to make shrewd judgments with pinpoint reasoning. As a member of the Aburame clan, Shino was infused at birth with a special breed of insects that feed on chakra. In return for becoming a living hive, the insects attack opponents, usually while he distracts them, and carry out other tasks as he commands. Shino has found a number of uses for these bugs, and as such has devised a number of jutsu that utilize them for varying purposes, such as creating copies of himself or using bugs for defensive purposes.\"}'),(12,10697,'Aburame, Shibi','{\"Description\":\"Shibi is Shino\\u0027s father. He is just as stoic as (if not even more so than) his son. He is a self-possessed figure, and the pride of Aburame. Shibi, like all members of his clan, has his eyes obscured by dark glasses which feature a single tassel hanging down from one-side. He has very spiky short black hair and a moustache. He typically wears a high collared outfit, while carrying a gourd on his back that is used for holding more kikaich\\u016B. He also tends to keep his hands in his pockets a lot, another trait he and his son share.\"}','{\"Description\": \"Shibi is Shino\'s father. He is just as stoic as (if not even more so than) his son. He is a self-possessed figure, and the pride of Aburame. Shibi, like all members of his clan, has his eyes obscured by dark glasses which feature a single tassel hanging down from one-side. He has very spiky short black hair and a moustache. He typically wears a high collared outfit, while carrying a gourd on his back that is used for holding more kikaichū. He also tends to keep his hands in his pockets a lot, another trait he and his son share.\"}'),(13,180385,'Aburame, Tatsuma','{\"Description\":\"Tatsuma was a ninja of Konohagakure, a member of the Aburame clan Root.\",\"Description_2\":\"In Kabuto\\u0027s past memories, he appears as Danzou\\u0027s bodyguard at Nonou\\u0027s orphanage.\"}','{\"Description\": \"Tatsuma was a ninja of Konohagakure, a member of the Aburame clan Root.\", \"Description_2\": \"In Kabuto\'s past memories, he appears as Danzou\'s bodyguard at Nonou\'s orphanage.\"}'),(14,180386,'Agara','{\"Description\":\"Agara was a chunin of Takigakure.\",\"Description_2\":\"Agara died while on a mission to find Yakush Kabuto with two other Takikkure Sinobi.\"}','{\"Description\": \"Agara was a chunin of Takigakure.\", \"Description_2\": \"Agara died while on a mission to find Yakush Kabuto with two other Takikkure Sinobi.\"}'),(15,153715,'Aino','{}','{}'),(16,130361,'Ajisai','{\"Description\":\"In the anime, Ajisai was a kunoichi from Amegakure and a teammate of Suiren and Fuyou.\"}','{\"Description\": \"In the anime, Ajisai was a kunoichi from Amegakure and a teammate of Suiren and Fuyou.\"}'),(17,30190,'Akaboshi','{\"Description\":\"Akaboshi (\\u30A2\\u30AB\\u30DC\\u30B7) is ninja who aims the learn the Tsuchigumo clan\\u0027s forbidden jutsu. He appears to be the leader of his group.\",\"Description_2\":\"Voiced by Akimitsu Takase.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Akaboshi (アカボシ) is ninja who aims the learn the Tsuchigumo clan\'s forbidden jutsu. He appears to be the leader of his group.\", \"Description_2\": \"Voiced by Akimitsu Takase.\"}'),(18,9699,'Akado, Yoroi','{\"Description\":\"Yoroi is a member of Kabuto\\u0027s team posing as a group of Leaf Ninja. He uses his chakra absorption technique to drain the chakra of an opponent, leaving them too weak to fight. He is defeated by Sasuke during  the first round of the chunin exams.\"}','{\"Description\": \"Yoroi is a member of Kabuto\'s team posing as a group of Leaf Ninja. He uses his chakra absorption technique to drain the chakra of an opponent, leaving them too weak to fight. He is defeated by Sasuke during  the first round of the chunin exams.\"}'),(19,4799,'Akamaru','{\"Description\":\"Akamaru is the nin-dog of Inuzuka Kiba. He is his best friend and plays an important part in all of Kiba\\u0027s attacks. As a puppy, he is either in Kiba\\u0027s jacket or on his head, but he later grows to be so large that Kiba can ride him. He has very good senses, even for a dog, and can communicate with Kiba.\",\"Description_2\":\"Akamaru\\u0027s name means \\u0022red\\u0022 (with \\u0022maru\\u0022 at the end, which is simply an ending for a boy\\u0027s name. Other males in the show share the suffix). When he eats a solider pill, his fur turns a dark red color.\",\"Description_3\":\"Akamaru\\u0027s seiyuu is Takeuchi Junko, who also plays the main character Uzumaki Naruto.\"}','{\"Description\": \"Akamaru is the nin-dog of Inuzuka Kiba. He is his best friend and plays an important part in all of Kiba\'s attacks. As a puppy, he is either in Kiba\'s jacket or on his head, but he later grows to be so large that Kiba can ride him. He has very good senses, even for a dog, and can communicate with Kiba.\", \"Description_2\": \"Akamaru\'s name means \\\"red\\\" (with \\\"maru\\\" at the end, which is simply an ending for a boy\'s name. Other males in the show share the suffix). When he eats a solider pill, his fur turns a dark red color.\", \"Description_3\": \"Akamaru\'s seiyuu is Takeuchi Junko, who also plays the main character Uzumaki Naruto.\"}'),(20,20645,'Akane','{\"Description\":\"Akane is a boy who pushed Inari in the water in episode 11. After he lost interest in Pochi, Akane threw him into the sea. When Inari hesitated to go in and save him, Akane pushed him in too. Although Inari started to drown, Akane and his friends left. After Kaiza saved Inari, he gave Akane a stern talking to.\"}','{\"Description\": \"Akane is a boy who pushed Inari in the water in episode 11. After he lost interest in Pochi, Akane threw him into the sea. When Inari hesitated to go in and save him, Akane pushed him in too. Although Inari started to drown, Akane and his friends left. After Kaiza saved Inari, he gave Akane a stern talking to.\"}'),(21,23473,'Akatsuchi','{\"Description\":\"Akatsuchi is a large shinobi from Iwagakure who escorts the Tsuchikage.\",\"Description_2\":\"Akatsuchi is very jovial and childish in nature and always seems to have a cheerful disposition. He was excited at the prospect of flying once again, even though there was the possibility that they were going off to a battle.[1] He was even excited when he thought Deidara survived the battle against Sasuke, despite Deidara being a criminal and their enemy. During battles he acts very level-headed and efficient as the Tsuchikage\\u0027s bodyguard. He is also fiercely loyal to the Tsuchikage, as seen when he offered to carry his luggage albeit against his will, refused to leave his side when he heard of Sasuke\\u0027s fight, just in case \\u014Cnoki\\u0027s hip went out and as stated by Deidara.\"}','{\"Description\": \"Akatsuchi is a large shinobi from Iwagakure who escorts the Tsuchikage.\", \"Description_2\": \"Akatsuchi is very jovial and childish in nature and always seems to have a cheerful disposition. He was excited at the prospect of flying once again, even though there was the possibility that they were going off to a battle.[1] He was even excited when he thought Deidara survived the battle against Sasuke, despite Deidara being a criminal and their enemy. During battles he acts very level-headed and efficient as the Tsuchikage\'s bodyguard. He is also fiercely loyal to the Tsuchikage, as seen when he offered to carry his luggage albeit against his will, refused to leave his side when he heard of Sasuke\'s fight, just in case Ōnoki\'s hip went out and as stated by Deidara.\"}'),(22,64461,'Akebino, Jinin','{\"Description\":\"Jinin Akebino (\\u901A\\u8349\\u91CE\\u990C\\u4EBA, Akebino Jinin) was one of the former members of the Seven Ninja Swordsmen of the Mist.\",\"Description_2\":\"He was evidently very skilled at utilising Kabutowari, a blunt sword that consists of a single sided axe and a hammer joined by a leather strap, which is said to be capable of breaking through any defence. This is achieved by first striking with the axe, before hammering it through the remainder of the obstruction with the hammer, resulting in the axe functioning much like a wedge. The \\u0027swords\\u0027 construction still allows the weapons to retain their individual capabilities and thanks to Jinin\\u0027s expertise, both the axe and the hammer can be exploited to their fullest.\",\"Manga Debut\":\"Chapter #522\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #265\",\"(Source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #265\", \"(Source\": \"Narutopedia)\", \"Description\": \"Jinin Akebino (通草野餌人, Akebino Jinin) was one of the former members of the Seven Ninja Swordsmen of the Mist.\", \"Manga Debut\": \"Chapter #522\", \"Description_2\": \"He was evidently very skilled at utilising Kabutowari, a blunt sword that consists of a single sided axe and a hammer joined by a leather strap, which is said to be capable of breaking through any defence. This is achieved by first striking with the axe, before hammering it through the remainder of the obstruction with the hammer, resulting in the axe functioning much like a wedge. The \'swords\' construction still allows the weapons to retain their individual capabilities and thanks to Jinin\'s expertise, both the axe and the hammer can be exploited to their fullest.\"}'),(23,10699,'Akimichi, Chouza','{\"Description\":\"He is father of Chouji Akimichi and former team-mate of Shikaku Nara and Inoichi Yamanaka. Together they were the previous Ino-Shika-Chou trio.\",\"Description_2\":\"During the Nine-Tails\\u0027 Attack on Konoha, Chouza and his teammates assisted in the village\\u0027s defense. A few years later, Chouza learned that Chouji was treated as an outcast because of his weight and the belief that Akimichi were useless ninja. Chouza told him that one day, he would have true friends that would realize that wasn\\u0027t the true Chouji. Chouza is the head of the Akimichi clan, and was part of the first \\u0022Ino-Shika-Chou Trio\\u0022 alongside Shikaku Nara and Inoichi Yamanaka, his name being the Chou part of the group name.\",\"Description_3\":\"He is a gentle and caring man with seemingly great wisdom and understanding of the world, and has deep love for his son, Chouji. Like the rest of his clan, he has a large appetite, and is prone to eat everything on an entire page on the menu.\",\"Description_4\":\"Like his son and the rest of his clan, Chouza uses the special technique that allows him to change calories into chakra. As the leader of his clan, it is highly logical that he is skilled in all of his clan\\u0027s secret techniques. He has been seen using the Multi-Size Technique, the Human Bullet Tank and the Partial Multi-Size Technique, which all revolve around the clan\\u0027s special ability to increase the size of their various body parts. He is also skilled at using a staff in combat, which seems to also grow when he uses the Multi-Size Technique.\"}','{\"Description\": \"He is father of Chouji Akimichi and former team-mate of Shikaku Nara and Inoichi Yamanaka. Together they were the previous Ino-Shika-Chou trio.\", \"Description_2\": \"During the Nine-Tails\' Attack on Konoha, Chouza and his teammates assisted in the village\'s defense. A few years later, Chouza learned that Chouji was treated as an outcast because of his weight and the belief that Akimichi were useless ninja. Chouza told him that one day, he would have true friends that would realize that wasn\'t the true Chouji. Chouza is the head of the Akimichi clan, and was part of the first \\\"Ino-Shika-Chou Trio\\\" alongside Shikaku Nara and Inoichi Yamanaka, his name being the Chou part of the group name.\", \"Description_3\": \"He is a gentle and caring man with seemingly great wisdom and understanding of the world, and has deep love for his son, Chouji. Like the rest of his clan, he has a large appetite, and is prone to eat everything on an entire page on the menu.\", \"Description_4\": \"Like his son and the rest of his clan, Chouza uses the special technique that allows him to change calories into chakra. As the leader of his clan, it is highly logical that he is skilled in all of his clan\'s secret techniques. He has been seen using the Multi-Size Technique, the Human Bullet Tank and the Partial Multi-Size Technique, which all revolve around the clan\'s special ability to increase the size of their various body parts. He is also skilled at using a staff in combat, which seems to also grow when he uses the Multi-Size Technique.\"}'),(24,77435,'Akimichi, Mother','{\"Description\":\"She is a citizen of Konohagakure, the mother of Chouji Akimichi, and the wife of Chouza Akimichi. She is also a member of the Allied Mothers Force.\",\"Description_2\":\"\",\"Anime Debut\":\"Naruto Shippuuden Episode #82\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #82\", \"Description\": \"She is a citizen of Konohagakure, the mother of Chouji Akimichi, and the wife of Chouza Akimichi. She is also a member of the Allied Mothers Force.\", \"Description_2\": \"\"}'),(25,2008,'Akimichi, Chouji','{\"Age\":\"13 (I); 16 (II)\",\"Birthday\":\"May 1\",\"Horoscope\":\"Taurus\",\"Blood type\":\"B\",\"Height\":\"156.3 cm (I); 172.3 cm (II)\",\"Weight\":\"69.3 kg(I); 87.5 kg (II)\",\"Rank\":\"Genin (I); Chuunin (II)\",\"Likes\":\"Yakiniku (broiled meat), snacks, spending money on food\",\"Dislikes\":\"Anything inedible\",\"Description\":\"Choji Akimichi is a childhood friend of Shikamaru Nara. Together with him Ino Yamanaka, and Asuma Sarutobi they make team 10. Choji has a love for food, his favorite being Korean barbecue, general snacks and sweets, and basically anything that is edible. His nigh-constant hunger is a constant annoyance for his teammates, as sating himself often comes before other necessities such as stealth and teamwork. Because of this, his teammates often use food against him, such as offering him food as a reward for accomplishing a task or simply using his favorite foods as a form of blackmail. Despite his open display for his love of food, Choji is very sensitive about his size and becomes highly agitated when somebody calls him \\u0022fat.\\u0022 Once called \\u0022fat,\\u0022 Choji\\u0027s resolve to fight is elevated to new levels and he becomes much more hostile to his opponents than he would otherwise. Just as they use food against him, Choji\\u0027s teammates use this personality trait against him as well. Should Choji be reluctant to fight, one of them need only comment on his size to spur him into combat form.\",\"Description_2\":\"As an Akimichi, Choji\\u0027s style of combat focuses on increasing his size. At the series\\u0027 start he uses Multi-Size Technique to serve this purpose, reshaping him into a large, round form.\"}','{\"Age\": \"13 (I); 16 (II)\", \"Rank\": \"Genin (I); Chuunin (II)\", \"Likes\": \"Yakiniku (broiled meat), snacks, spending money on food\", \"Height\": \"156.3 cm (I); 172.3 cm (II)\", \"Weight\": \"69.3 kg(I); 87.5 kg (II)\", \"Birthday\": \"May 1\", \"Dislikes\": \"Anything inedible\", \"Horoscope\": \"Taurus\", \"Blood type\": \"B\", \"Description\": \"Choji Akimichi is a childhood friend of Shikamaru Nara. Together with him Ino Yamanaka, and Asuma Sarutobi they make team 10. Choji has a love for food, his favorite being Korean barbecue, general snacks and sweets, and basically anything that is edible. His nigh-constant hunger is a constant annoyance for his teammates, as sating himself often comes before other necessities such as stealth and teamwork. Because of this, his teammates often use food against him, such as offering him food as a reward for accomplishing a task or simply using his favorite foods as a form of blackmail. Despite his open display for his love of food, Choji is very sensitive about his size and becomes highly agitated when somebody calls him \\\"fat.\\\" Once called \\\"fat,\\\" Choji\'s resolve to fight is elevated to new levels and he becomes much more hostile to his opponents than he would otherwise. Just as they use food against him, Choji\'s teammates use this personality trait against him as well. Should Choji be reluctant to fight, one of them need only comment on his size to spur him into combat form.\", \"Description_2\": \"As an Akimichi, Choji\'s style of combat focuses on increasing his size. At the series\' start he uses Multi-Size Technique to serve this purpose, reshaping him into a large, round form.\"}'),(26,94811,'Amai','{\"Description\":\"Amai (\\u30A2\\u30DE\\u30A4, Amai) is a medical-nin from Kumogakure.\",\"Description_2\":\"On a mission with the Fourth Raikage and his comrades, Karai was incapacitated and taken back to Amai for treatment. Though his group had successfully acquired the scroll, he was unable to treat Karai. While in town, he saw Tsunade and reported this to the Raikage. Though Karai objected to this, the Raikage noted that he would have Tsunade heal him. When they approached Tsunade, Amai beseeched Tsunade to heal his comrade despite her refusal due to the bad blood between the two nations. He would later aid Shizune during the procedure to remove the Exploding Insect from his chest cavity.\",\"Anime Debut\":\"Naruto Shippuuden Episode #286\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #286\", \"Description\": \"Amai (アマイ, Amai) is a medical-nin from Kumogakure.\", \"Description_2\": \"On a mission with the Fourth Raikage and his comrades, Karai was incapacitated and taken back to Amai for treatment. Though his group had successfully acquired the scroll, he was unable to treat Karai. While in town, he saw Tsunade and reported this to the Raikage. Though Karai objected to this, the Raikage noted that he would have Tsunade heal him. When they approached Tsunade, Amai beseeched Tsunade to heal his comrade despite her refusal due to the bad blood between the two nations. He would later aid Shizune during the procedure to remove the Exploding Insect from his chest cavity.\"}'),(27,127095,'Ameno','{\"Description\":\"Ameno is a kunoichi from Sunagakure and a team-mate of Kouji and Shishio.\",\"Description_2\":\"Ameno is a skilled medical-nin who is able to increase the speed of a body\\u0027s natural healing process by sending chakra from her hands into a wound on an afflicted body part. She is also able to perform fine minor surgery, removing countless poison barbs from an individual.\",\"Description_3\":\"She can also use Water Release. She commonly applies this skill to supplement her medical skills. With it, she can treat poison-related injuries or act as a contingency plan against enemy attacks, healing herself and others. In actual combat, she can form giant pinchers of water to attack her opponent from a greater distance.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Ameno is a kunoichi from Sunagakure and a team-mate of Kouji and Shishio.\", \"Description_2\": \"Ameno is a skilled medical-nin who is able to increase the speed of a body\'s natural healing process by sending chakra from her hands into a wound on an afflicted body part. She is also able to perform fine minor surgery, removing countless poison barbs from an individual.\", \"Description_3\": \"She can also use Water Release. She commonly applies this skill to supplement her medical skills. With it, she can treat poison-related injuries or act as a contingency plan against enemy attacks, healing herself and others. In actual combat, she can form giant pinchers of water to attack her opponent from a greater distance.\"}'),(28,23420,'Ao','{\"Description\":\"Ao is a shinobi of Kirigakure. Ao is a middle aged gentleman with a eyepatch over his right eye; he also wears to talismens on his ears.\"}','{\"Description\": \"Ao is a shinobi of Kirigakure. Ao is a middle aged gentleman with a eyepatch over his right eye; he also wears to talismens on his ears.\"}'),(29,136281,'Aoda','{\"Birthdate\":\"October 1\",\"Gender\":\"Male\",\"Species\":\"Snake\",\"Classification\":\"Summon\",\"Affiliation\":\"Ryuuchi Cave\",\"Description\":\"Aoda is an inhabitant of the Ryuuchi Cave and the personal summon of Sasuke Uchiha.\",\"Description_2\":\"In stark contrast to Manda, a snake of similar size to it, Aoda seems to be very mild mannered and respectful to its summoner, as shown when it addresses Sasuke with the \\u0022-sama\\u0022 suffix and dutifully follows all his orders without needing to be controlled. Aoda also asked Sasuke how he could be of service the instant he was summoned. He was also described as simple.\",\"(Source\":\"Narutopedia, edited)\"}','{\"Gender\": \"Male\", \"(Source\": \"Narutopedia, edited)\", \"Species\": \"Snake\", \"Birthdate\": \"October 1\", \"Affiliation\": \"Ryuuchi Cave\", \"Description\": \"Aoda is an inhabitant of the Ryuuchi Cave and the personal summon of Sasuke Uchiha.\", \"Description_2\": \"In stark contrast to Manda, a snake of similar size to it, Aoda seems to be very mild mannered and respectful to its summoner, as shown when it addresses Sasuke with the \\\"-sama\\\" suffix and dutifully follows all his orders without needing to be controlled. Aoda also asked Sasuke how he could be of service the instant he was summoned. He was also described as simple.\", \"Classification\": \"Summon\"}'),(30,66541,'Atsui','{\"Description\":\"He is a shinobi from Kumogakure.\",\"Description_2\":\"In stark contrast to his sister Samui, Atsui has a rather hot-headed and spirited attitude, which is evident even in battle. He prefers attacking his enemies head on, leaving him entirely devoid of any support at times. He has a tendency of saying the word \\u0022hot\\u0022 (\\u3042\\u3064\\u3044, atsui) and admits that he has created a substantial amount of \\u0022hot-shot\\u0022 catchphrases.\",\"Description_3\":\"Like many other Kumogakure shinobi, Atsui is extremely proficient in kenjutsu, incorporating a long white katana as part of his main fighting style. When this blade is utilised in conjunction with his Fire Release nature transformation techniques, through the application of Chakra Flow, he is capable of incinerating a significant quantity of opponents in a single instant. The anime also showed that he is able to conjure flames with each swing of his sword.\"}','{\"Description\": \"He is a shinobi from Kumogakure.\", \"Description_2\": \"In stark contrast to his sister Samui, Atsui has a rather hot-headed and spirited attitude, which is evident even in battle. He prefers attacking his enemies head on, leaving him entirely devoid of any support at times. He has a tendency of saying the word \\\"hot\\\" (あつい, atsui) and admits that he has created a substantial amount of \\\"hot-shot\\\" catchphrases.\", \"Description_3\": \"Like many other Kumogakure shinobi, Atsui is extremely proficient in kenjutsu, incorporating a long white katana as part of his main fighting style. When this blade is utilised in conjunction with his Fire Release nature transformation techniques, through the application of Chakra Flow, he is capable of incinerating a significant quantity of opponents in a single instant. The anime also showed that he is able to conjure flames with each swing of his sword.\"}'),(31,17310,'Ayame','{\"Description\":\"Ayame is the daughter of the cook Teuchi. Together they run the Ichiraku Ramen Bar.\"}','{\"Description\": \"Ayame is the daughter of the cook Teuchi. Together they run the Ichiraku Ramen Bar.\"}'),(32,84625,'Azami','{\"Description\":\"Appears in Naruto Shipp\\u016Bden episode 312.\",\"Description_2\":\"Azami is the granddaughter of Chen. She was the only one who knew that her grandfather was alive. When she saw Rock Lee, Naruto Uzumaki, and Tenten on her grandfather\\u0027s graveyard, they asked her if she knew how to perform her grandfather\\u0027s technique, and she told them that he was alive, and that he always goes to the graveyard to eat her riceballs.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Appears in Naruto Shippūden episode 312.\", \"Description_2\": \"Azami is the granddaughter of Chen. She was the only one who knew that her grandfather was alive. When she saw Rock Lee, Naruto Uzumaki, and Tenten on her grandfather\'s graveyard, they asked her if she knew how to perform her grandfather\'s technique, and she told them that he was alive, and that he always goes to the graveyard to eat her riceballs.\"}'),(33,41208,'Baji','{\"Description\":\"Baji was a leader of a group of bandits.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #195\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #195\", \"(source\": \")\", \"Description\": \"Baji was a leader of a group of bandits.\"}'),(34,15081,'Baki','{\"Name\":\"Baki\",\"Age\":\"30 ( in Part I ), 32 ( in Part II )\",\"Birthday\":\"4, July\",\"Height\":\"188.2 cm\",\"Weight\":\"80 kg\",\"Blood type\":\"A\",\"Manga Intro\":\"Chapter 65\",\"Anime Intro\":\"Naruto Episode 39\",\"Quote\":\"\\u0022But a blade of the wind cannot be stopped by anyone.\\u0022\",\"Description\":\"Short Overview\",\"Description_2\":\"Baki is one of the strongest Sand Jonin in the Sand village. He is an important member of the Sunagakure\\u0027s advisory council and is probably the second-in-command after the Kazekage and is respected throughout the whole village. He is also probably the Fourth Kazekage\\u0027s most trusted Jonin as he was in charge of the invasion in to Konoha and the team leader of Team Baki, which consists of Gaara,Temari and Kankuro, the Fourth Kazekage \\u0027s children. It is speculated that he is very strong, considering that he was the teacher of Gaara who later became the Fifth Kazekage, who is probably in Part 1 and 2 the strongest and most dangerous ninja in the Sand Village.\",\"Description_3\":\"Personality\",\"Description_4\":\"Baki is a loyal, kind and respected ninja. With his experience in battle, he holds a lot of confidence. He has a soldier personality, a patriot. A caring and kind person, but if anything comes in his village or country\\u0027s way or his loved ones, he will do anything to stop it. During the Chuunin exam, he had confidence in the ability of all of his team members, although he comments on Kankuro not taking the battles seriously enough. He also worries frequently about Gaara\\u0027s mental stability and his control over Shukaku.\"}','{\"Age\": \"30 ( in Part I ), 32 ( in Part II )\", \"Name\": \"Baki\", \"Quote\": \"\\\"But a blade of the wind cannot be stopped by anyone.\\\"\", \"Height\": \"188.2 cm\", \"Weight\": \"80 kg\", \"Birthday\": \"4, July\", \"Blood type\": \"A\", \"Anime Intro\": \"Naruto Episode 39\", \"Description\": \"Short Overview\", \"Manga Intro\": \"Chapter 65\", \"Description_2\": \"Baki is one of the strongest Sand Jonin in the Sand village. He is an important member of the Sunagakure\'s advisory council and is probably the second-in-command after the Kazekage and is respected throughout the whole village. He is also probably the Fourth Kazekage\'s most trusted Jonin as he was in charge of the invasion in to Konoha and the team leader of Team Baki, which consists of Gaara,Temari and Kankuro, the Fourth Kazekage \'s children. It is speculated that he is very strong, considering that he was the teacher of Gaara who later became the Fifth Kazekage, who is probably in Part 1 and 2 the strongest and most dangerous ninja in the Sand Village.\", \"Description_3\": \"Personality\", \"Description_4\": \"Baki is a loyal, kind and respected ninja. With his experience in battle, he holds a lot of confidence. He has a soldier personality, a patriot. A caring and kind person, but if anything comes in his village or country\'s way or his loved ones, he will do anything to stop it. During the Chuunin exam, he had confidence in the ability of all of his team members, although he comments on Kankuro not taking the battles seriously enough. He also worries frequently about Gaara\'s mental stability and his control over Shukaku.\"}'),(35,22896,'Baku','{\"Description\":\"Baku (\\u30D0\\u30AF) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again. Baku is likely not his real name, but a codename.\",\"Description_2\":\"Peeking from behind his mask, his eyes were said to be able to perceive everything.\",\"(Source\":\"Narutopedia)\",\"Description_3\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Baku (バク) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again. Baku is likely not his real name, but a codename.\", \"Description_2\": \"Peeking from behind his mask, his eyes were said to be able to perceive everything.\", \"Description_3\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(36,52031,'Banna','{\"Description\":\"Appears in episode 233.\"}','{\"Description\": \"Appears in episode 233.\"}'),(37,23008,'Bansai','{\"Description\":\"Bansai (\\u677F\\u658E) is an elder ninja monk in the Fire Temple and one of only three known survivors of the Akatsuki attack on the temple. When Asuma Sarutobi and his team went to the temple to gather information on Akatsuki, Bansai, worried about Asuma and his team\\u0027s well-being, said a prayer. This made Asuma go into a trance and see the spirit of his dead comrade Chiriku. Bansai is currently retired.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Bansai (板斎) is an elder ninja monk in the Fire Temple and one of only three known survivors of the Akatsuki attack on the temple. When Asuma Sarutobi and his team went to the temple to gather information on Akatsuki, Bansai, worried about Asuma and his team\'s well-being, said a prayer. This made Asuma go into a trance and see the spirit of his dead comrade Chiriku. Bansai is currently retired.\"}'),(38,30189,'Benten','{\"Description\":\"Benten (\\u30D9\\u30F3\\u30C6\\u30F3) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\\u0027s kinjutsu.\",\"Description_2\":\"Voiced by Chikara \\u014Csaka.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Benten (ベンテン) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\'s kinjutsu.\", \"Description_2\": \"Voiced by Chikara Ōsaka.\"}'),(39,34075,'Bisuke','{\"Description\":\"Bisuke (\\u30D3\\u30B9\\u30B1; English TV \\u0022Biscuit\\u0022) is a ninken and a summoning of Kakashi Hatake.\",\"Description_2\":\"He bears an uncanny resemblance to Gaara with a kanji imprinted on his head and dark rings around his eyes. However, where Gaara has the kanji for \\u0022love\\u0022 (\\u611B, ai), Bisuke has the kanji for \\u0022shinobi\\u0022 (\\u5FCD).\",\"Description_3\":\"(Naruto wiki)\"}','{\"Description\": \"Bisuke (ビスケ; English TV \\\"Biscuit\\\") is a ninken and a summoning of Kakashi Hatake.\", \"Description_2\": \"He bears an uncanny resemblance to Gaara with a kanji imprinted on his head and dark rings around his eyes. However, where Gaara has the kanji for \\\"love\\\" (愛, ai), Bisuke has the kanji for \\\"shinobi\\\" (忍).\", \"Description_3\": \"(Naruto wiki)\"}'),(40,139847,'Biwa, Juuzou','{\"Description\":\"Previous Swordsmen of the Mist.\"}','{\"Description\": \"Previous Swordsmen of the Mist.\"}'),(41,77433,'Blue B','{\"Description\":\"A\\u0027s cousin. He was a high-ranking Kumogakure shinobi as well as the predecessor of Killer B as the jinchuuriki of Gyuuki, the Eight-Tails.\",\"Manga Debut\":\"Chapter #494\",\"Anime Debut\":\"Naruto Shippuuden Episode #244\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #244\", \"Description\": \"A\'s cousin. He was a high-ranking Kumogakure shinobi as well as the predecessor of Killer B as the jinchuuriki of Gyuuki, the Eight-Tails.\", \"Manga Debut\": \"Chapter #494\"}'),(42,215601,'Bunpuku','{\"Description\":\"Bunpuku was an elderly priest of Sunagakure and one of the first two jinch\\u016Briki of Shukaku.\"}','{\"Description\": \"Bunpuku was an elderly priest of Sunagakure and one of the first two jinchūriki of Shukaku.\"}'),(43,93635,'Byakuren','{\"Birthdate\":\"January 20\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"172.2 cm\",\"Weight\":\"78.9 kg\",\"Blood type\":\"B\",\"Occupation\":\"Mizukage\",\"Affiliation\":\"Kirigakure\",\"Description\":\"Byakuren was the First Mizukage who founded Kirigakure in the Land of Water.\",\"(Source\":\"Narutopedia)\"}','{\"Gender\": \"Male\", \"Height\": \"172.2 cm\", \"Status\": \"Deceased\", \"Weight\": \"78.9 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"January 20\", \"Blood type\": \"B\", \"Occupation\": \"Mizukage\", \"Affiliation\": \"Kirigakure\", \"Description\": \"Byakuren was the First Mizukage who founded Kirigakure in the Land of Water.\"}'),(44,84623,'Chen','{\"Description\":\"Chen (\\u30C1\\u30A7\\u30F3, Chen) was a j\\u014Dnin-level shinobi of Konohagakure and a legendary taijutsu master.\",\"Description_2\":\"Chen was known as a hero in Konoha. He once had a student much like Rock Lee who was unable to perform ninjutsu or genjutsu and dedicated himself to become a taijutsu master. Both Chen and his student participated in the Third Shinobi World War, with the latter killed in the war due to his inability to learn ninjutsu. The death of his student greatly affected Chen and the shinobi faked his death and gave up being a shinobi. Years passed, his granddaughter Azami would occasionally leave rice balls for her grandfather, the only person to be aware that he was still alive.\",\"Description_3\":\"One day when his granddaughter was bringing his gravestone rice balls, Rock Lee, Naruto Uzumaki and Tenten came to pay their respects to the \\u0022late\\u0022 hero. When Azami told them that Chen was still alive and to wait for him, they decided to do so. Later, Chen did appear. When the genin believed him to be an impostor, they attacked him, resulting in him dropping his last rice ball. Greatly angered by that, he unleashed his secret technique on them. Realizing that he was the true hero and amazed at his technique, Lee begged Chen to teach it to him so he could further his dream as a great taijutsu-specialising ninja. Shocked at how much alike Lee was to his late student, he furiously attacked Lee. Afterwards, he insisted that Lee give up on his dream and left. Lee however stayed at the gravestone, waiting each day for Chen to acknowledge him. Finally, Lee told Chen that he doesn\\u0027t care if Chen refuses to teach him his technique, but insists to make the old master acknowledge him as a ninja. Begging Chen to use his technique on him, Chen agreed. Despite Lee being completely overwhelmed by it, Chen was amazed that Lee could see the true nature behind it. However, Chen still insisted that Lee give up on his dream and left.\",\"Description_4\":\"Some time afterwards, Chen died. Later, Kabuto Yakushi acquired a DNA sample from Chen for later use.\",\"Anime Debut\":\"Naruto Shippuuden Episode #312\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #312\", \"Description\": \"Chen (チェン, Chen) was a jōnin-level shinobi of Konohagakure and a legendary taijutsu master.\", \"Description_2\": \"Chen was known as a hero in Konoha. He once had a student much like Rock Lee who was unable to perform ninjutsu or genjutsu and dedicated himself to become a taijutsu master. Both Chen and his student participated in the Third Shinobi World War, with the latter killed in the war due to his inability to learn ninjutsu. The death of his student greatly affected Chen and the shinobi faked his death and gave up being a shinobi. Years passed, his granddaughter Azami would occasionally leave rice balls for her grandfather, the only person to be aware that he was still alive.\", \"Description_3\": \"One day when his granddaughter was bringing his gravestone rice balls, Rock Lee, Naruto Uzumaki and Tenten came to pay their respects to the \\\"late\\\" hero. When Azami told them that Chen was still alive and to wait for him, they decided to do so. Later, Chen did appear. When the genin believed him to be an impostor, they attacked him, resulting in him dropping his last rice ball. Greatly angered by that, he unleashed his secret technique on them. Realizing that he was the true hero and amazed at his technique, Lee begged Chen to teach it to him so he could further his dream as a great taijutsu-specialising ninja. Shocked at how much alike Lee was to his late student, he furiously attacked Lee. Afterwards, he insisted that Lee give up on his dream and left. Lee however stayed at the gravestone, waiting each day for Chen to acknowledge him. Finally, Lee told Chen that he doesn\'t care if Chen refuses to teach him his technique, but insists to make the old master acknowledge him as a ninja. Begging Chen to use his technique on him, Chen agreed. Despite Lee being completely overwhelmed by it, Chen was amazed that Lee could see the true nature behind it. However, Chen still insisted that Lee give up on his dream and left.\", \"Description_4\": \"Some time afterwards, Chen died. Later, Kabuto Yakushi acquired a DNA sample from Chen for later use.\"}'),(45,146998,'Chino','{\"Description\":\"Chino is one of the surviving members of the Chinoike Clan, Chino was kidnapped by En Oyashiro, who had been collecting shinobi in possession of a kekkei genkai when she was very young to the point where she forgot her parents\\u0027 faces. He raised her into a merciless and vengeful shinobi, giving her the task of capturing other kekkei genkai users and eliminating threats.\",\"Description_2\":\"Upon learning her entire clan had been wiped out by enemies and angered by the mistreatment from En, Chino flees from him and sets out on her own path. Along the way, she meets Nowaki. The two then band together and travel together, robbing rich people of their goods for themselves to survive. However, Chino was not able to let go of her hatred towards the villages, which she blames for allowing her clan to perish.\",\"Description_3\":\"In the anime version, however, Chino met Nowaki (who is really Fuushin) when she fought and defeated him during her debut at the Coliseum. They bonded over their loneliness of being ostracised for their abilities and having no families. It was Chino\\u0027s desire to find her clan at the Valley of Hell that prompted the escape of herself, F\\u016Bshin, Kary\\u016B, and two others. They formed the Lightning Group and began stealing money for the poor villages before being betrayed when Kirigakure began interfering. The group dissolved with Chino and F\\u016Bshin the only ones left. Upon reaching Valley of Hell and seeing it empty with evidence of her clan being dead, Chino vowed revenge for her clan\\u0027s demise.\"}','{\"Description\": \"Chino is one of the surviving members of the Chinoike Clan, Chino was kidnapped by En Oyashiro, who had been collecting shinobi in possession of a kekkei genkai when she was very young to the point where she forgot her parents\' faces. He raised her into a merciless and vengeful shinobi, giving her the task of capturing other kekkei genkai users and eliminating threats.\", \"Description_2\": \"Upon learning her entire clan had been wiped out by enemies and angered by the mistreatment from En, Chino flees from him and sets out on her own path. Along the way, she meets Nowaki. The two then band together and travel together, robbing rich people of their goods for themselves to survive. However, Chino was not able to let go of her hatred towards the villages, which she blames for allowing her clan to perish.\", \"Description_3\": \"In the anime version, however, Chino met Nowaki (who is really Fuushin) when she fought and defeated him during her debut at the Coliseum. They bonded over their loneliness of being ostracised for their abilities and having no families. It was Chino\'s desire to find her clan at the Valley of Hell that prompted the escape of herself, Fūshin, Karyū, and two others. They formed the Lightning Group and began stealing money for the poor villages before being betrayed when Kirigakure began interfering. The group dissolved with Chino and Fūshin the only ones left. Upon reaching Valley of Hell and seeing it empty with evidence of her clan being dead, Chino vowed revenge for her clan\'s demise.\"}'),(46,15365,'Chiriku','{\"Description\":\"He was once part of the Twelve Guardian Ninja. When six of the members tried a coup d\\u0027etat he alongside Asuma Sarutobi, Kitane, Nauma, Tou\\u0027u, and Seito fought against them. He alongside Asuma and Kazuma was the only survivors of the fight.\",\"Description_2\":\"When the group disbanded he became head monk at the Fire Temple, an elite monastery that is home to monks with special abilities. During his time with the Twelve Guardian Ninja, some underground organization put a 30 Million Ryo bounty on his head.\"}','{\"Description\": \"He was once part of the Twelve Guardian Ninja. When six of the members tried a coup d\'etat he alongside Asuma Sarutobi, Kitane, Nauma, Tou\'u, and Seito fought against them. He alongside Asuma and Kazuma was the only survivors of the fight.\", \"Description_2\": \"When the group disbanded he became head monk at the Fire Temple, an elite monastery that is home to monks with special abilities. During his time with the Twelve Guardian Ninja, some underground organization put a 30 Million Ryo bounty on his head.\"}'),(47,12676,'Chiyo','{\"Description\":\"Chiyo is the grandmother of Sasori and sister to Ebizo.  She was once a powerful shinobi for the Hidden Village of Sand, but has since retired.  She was a founder of the Sand Village\\u2019s puppet division, training many disciples and developing new puppets.  Chiyo was also the one responsible for sealing the One-Tailed Shukaku inside Gaara under the orders of the Fourth Kazekage.  As well as being a puppet master, Chiyo was also a talented poison maker.  But during the last Great Ninja War, she was humiliated when Tsunade of Konoha managed to figure out and develop antidotes for every single one of her poisons.  As a result, Chiyo has had a grudge against Tsunade to this day and refers to her as \\u201Cthat slug woman\\u201D, referring to Tsunade\\u2019s ability to summon giant slugs.\",\"Description_2\":\"Chiyo\\u2019s son, along with his wife, were both killed by the \\u201CWhite Fang of Konoha\\u201D, Kakashi Hatake\\u2019s father, during the Great Ninja War.  This left their only son, Sasori, an orphan.  Chiyo took on the responsibility of raising Sasori.  When she saw his sadness at the loss of his parents, Chiyo decided to teach him puppet jutsu in order to preoccupy him with a new interest.  Sasori proved to be a genius a puppet jutsu and even had the ability to manufacture puppets out of human bodies. His very first creations were the puppet versions of his own parents.  But unbeknownst to Chiyo, a dark hatred dwelled in Sasori\\u2019s heart.  Twenty years before the events of Naruto part II, Sasori fled the Sand Village and eventually joined Akatsuki.  Chiyo confronted his grandson in the \\u201CRescue of Gaara\\u201D story arc and defeated him with help from Sakura.\",\"Description_3\":\"Chiyo sacrificed her life to revive Gaara using a technique originally intended to give life to puppets at the cost of  her own.\",\"Description_4\":\"she has Abilities like Reincarnation jutsu A technique that allows Chiyo to bring the dead back to life or even give life to a puppet.  She is the only one capable of performing the jutsu but the cost is her own life.\",\"Description_5\":\"\",\"Description_6\":\"And even Ten Puppets of Monzaemon Chikamatsu Monzaemon Chikamatsu was the inventor of shinobi puppet jutsus. These ten puppets were his legacy and are superior than regular puppets. They are meant to work together and are capable of performing powerful jutsus when combined.\"}','{\"Description\": \"Chiyo is the grandmother of Sasori and sister to Ebizo.  She was once a powerful shinobi for the Hidden Village of Sand, but has since retired.  She was a founder of the Sand Village’s puppet division, training many disciples and developing new puppets.  Chiyo was also the one responsible for sealing the One-Tailed Shukaku inside Gaara under the orders of the Fourth Kazekage.  As well as being a puppet master, Chiyo was also a talented poison maker.  But during the last Great Ninja War, she was humiliated when Tsunade of Konoha managed to figure out and develop antidotes for every single one of her poisons.  As a result, Chiyo has had a grudge against Tsunade to this day and refers to her as “that slug woman”, referring to Tsunade’s ability to summon giant slugs.\", \"Description_2\": \"Chiyo’s son, along with his wife, were both killed by the “White Fang of Konoha”, Kakashi Hatake’s father, during the Great Ninja War.  This left their only son, Sasori, an orphan.  Chiyo took on the responsibility of raising Sasori.  When she saw his sadness at the loss of his parents, Chiyo decided to teach him puppet jutsu in order to preoccupy him with a new interest.  Sasori proved to be a genius a puppet jutsu and even had the ability to manufacture puppets out of human bodies. His very first creations were the puppet versions of his own parents.  But unbeknownst to Chiyo, a dark hatred dwelled in Sasori’s heart.  Twenty years before the events of Naruto part II, Sasori fled the Sand Village and eventually joined Akatsuki.  Chiyo confronted his grandson in the “Rescue of Gaara” story arc and defeated him with help from Sakura.\", \"Description_3\": \"Chiyo sacrificed her life to revive Gaara using a technique originally intended to give life to puppets at the cost of  her own.\", \"Description_4\": \"she has Abilities like Reincarnation jutsu A technique that allows Chiyo to bring the dead back to life or even give life to a puppet.  She is the only one capable of performing the jutsu but the cost is her own life.\", \"Description_5\": \"\", \"Description_6\": \"And even Ten Puppets of Monzaemon Chikamatsu Monzaemon Chikamatsu was the inventor of shinobi puppet jutsus. These ten puppets were his legacy and are superior than regular puppets. They are meant to work together and are capable of performing powerful jutsus when combined.\"}'),(48,84621,'Chiyo','{\"Description\":\"She appears first in episode 309.\",\"Description_2\":\"She\\u0027s the heir of \\u0022Thisland\\u0022 and was protected by a ronin, called Tatewaki.\"}','{\"Description\": \"She appears first in episode 309.\", \"Description_2\": \"She\'s the heir of \\\"Thisland\\\" and was protected by a ronin, called Tatewaki.\"}'),(49,23418,'Choujuurou','{\"Description\":\"Seems to be one of the Seven Swordsmen. He is protecting the Mizukage while on their journey to the Kage Summit. He seems to be unsure about himself. He appears to wield some form of dual weapon (presumably a Sword) linked together by the handles.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Seems to be one of the Seven Swordsmen. He is protecting the Mizukage while on their journey to the Kage Summit. He seems to be unsure about himself. He appears to wield some form of dual weapon (presumably a Sword) linked together by the handles.\"}'),(50,57881,'Choumei','{\"Description\":\"Choumei, more commonly known as the Seven-Tails or Nanabi, is a tailed beast sealed within Fuu from Takigakure.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Choumei, more commonly known as the Seven-Tails or Nanabi, is a tailed beast sealed within Fuu from Takigakure.\"}'),(51,97793,'Chuukaku','{\"Description\":\"Chuukaku (\\u4E2D\\u899A, Ch\\u016Bkaku) was a ninja monk from the Fire Temple and the mentor of Chiriku.\",\"Description_2\":\"A ninja monk and scholar, Chuukaku taught Chiriku sometime before his death and was eventually interred at the cemetery in the Fire Temple. Kabuto would later reincarnate him by accident while looking for Chiriku.\",\"Description_3\":\"During the Fourth Shinobi World War, Kabuto deployed Ch\\u016Bkaku, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. While attempting to undo the seal holding the Third Raikage, Chuukaku was attacked by Temari and sealed by the Fourth Division. Later, when the Impure World Reincarnation Technique was canceled, Chuukaku\\u0027s soul returned to the afterlife.\",\"Anime Debut\":\"Naruto Shippuuden Episode #316\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #316\", \"Description\": \"Chuukaku (中覚, Chūkaku) was a ninja monk from the Fire Temple and the mentor of Chiriku.\", \"Description_2\": \"A ninja monk and scholar, Chuukaku taught Chiriku sometime before his death and was eventually interred at the cemetery in the Fire Temple. Kabuto would later reincarnate him by accident while looking for Chiriku.\", \"Description_3\": \"During the Fourth Shinobi World War, Kabuto deployed Chūkaku, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. While attempting to undo the seal holding the Third Raikage, Chuukaku was attacked by Temari and sealed by the Fourth Division. Later, when the Impure World Reincarnation Technique was canceled, Chuukaku\'s soul returned to the afterlife.\"}'),(52,62631,'Chuukichi','{\"Description\":\"Chuukichi (\\u4E2D\\u5409, Ch\\u016Bkichi) was a famed Kirigakure shinobi.\",\"Description_2\":\"He was a well noted shinobi during his lifetime, enough to justify his inclusion as a sensor and a backup within Akatsuki\\u0027s Surprise Attack and Diversion Platoon, alongside Deidara, Sasori and Shin.\",\"Manga Debut\":\"Chapter #516\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #261\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #261\", \"Description\": \"Chuukichi (中吉, Chūkichi) was a famed Kirigakure shinobi.\", \"Manga Debut\": \"Chapter #516\", \"Description_2\": \"He was a well noted shinobi during his lifetime, enough to justify his inclusion as a sensor and a backup within Akatsuki\'s Surprise Attack and Diversion Platoon, alongside Deidara, Sasori and Shin.\"}'),(53,30188,'Chuusin','{\"Description\":\"Ch\\u016Bshin (\\u30C1\\u30E5\\u30A6\\u30B7\\u30F3) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\\u0027s forbidden jutsu.\",\"Description_2\":\"Voiced by Y\\u014Dhei Tadano\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Chūshin (チュウシン) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\'s forbidden jutsu.\", \"Description_2\": \"Voiced by Yōhei Tadano\"}'),(54,70989,'Condor','{\"Description\":\"He is an average sized ostrich who wears three pink bows on his neck.\"}','{\"Description\": \"He is an average sized ostrich who wears three pink bows on his neck.\"}'),(55,100275,'Daibutsu','{\"Description\":\"Daibutsu (\\u5927\\u4ECF, Daibutsu) was a member of the original Akatsuki.\",\"Anime Debut\":\"Naruto Shippuuden Episode #347\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #347\", \"Description\": \"Daibutsu (大仏, Daibutsu) was a member of the original Akatsuki.\"}'),(56,97791,'Daimaru','{\"Description\":\"Daimaru (\\u30C0\\u30A4\\u30DE\\u30EB, Daimaru) was a shinobi from Sunagakure.\",\"Description_2\":\"Daimaru was a young shinobi from Sunagakure who grew up alongside Temari. He quickly fell in love with her, seemingly not intimidated by her relation to the Fourth Kazekage or Gaara. Because he couldn\\u0027t express his interest in her, he used to bully her. Some time later, Daimaru died during a C-rank mission.\",\"Description_3\":\"During the Fourth Shinobi World War, Kabuto deployed Daimaru, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. Arriving at the Third Raikage\\u0027s sealing site, Daimaru shifted the sandy terrain to unset traps left behind by the Allied Shinobi Forces. When they arrived, Daimaru quickly went to see Temari, who he declared his love for after deciding that he had nothing left to lose due to being dead. In the end, Daimaru allowed himself to be sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\",\"Anime Debut\":\"Naruto Shippuuden Episode #316\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #316\", \"Description\": \"Daimaru (ダイマル, Daimaru) was a shinobi from Sunagakure.\", \"Description_2\": \"Daimaru was a young shinobi from Sunagakure who grew up alongside Temari. He quickly fell in love with her, seemingly not intimidated by her relation to the Fourth Kazekage or Gaara. Because he couldn\'t express his interest in her, he used to bully her. Some time later, Daimaru died during a C-rank mission.\", \"Description_3\": \"During the Fourth Shinobi World War, Kabuto deployed Daimaru, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. Arriving at the Third Raikage\'s sealing site, Daimaru shifted the sandy terrain to unset traps left behind by the Allied Shinobi Forces. When they arrived, Daimaru quickly went to see Temari, who he declared his love for after deciding that he had nothing left to lose due to being dead. In the end, Daimaru allowed himself to be sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\"}'),(57,23476,'Darui','{\"Description\":\"Darui is a jounin-level shinobi from Kumogakure. He is also the Commander of the First Division of the Allied Shinobi Forces.\",\"Description_2\":\"Darui is portrayed as being easy-going and mellow; when compared to the Fourth Raikage\\u0027s over-the-top exit through a window, he tells C that he\\u0027ll just use the door. Whilst having a laid-back demeanour, Darui isn\\u0027t lazy, leaping to the Raikage\\u0027s defence when the bodyguards of the other Kage overreact to the Raikage\\u0027s actions. He also has a habit of referring to things or events as being \\u0022dull\\u0022 a play on his name. Darui is also very apologetic, even apologizing for other people\\u0027s actions, a trait he\\u0027d never noticed himself; this attribute led him to say \\u0022sorry\\u0022 just as much as \\u0022dull.\\u0022 He is also very loyal to the Raikage who considers Darui his \\u0022second right hand.\\u0022 He adresses the Raikage with \\u0022boss\\u0022 rather than \\u0022Raikage-sama.\\u0022\",\"Description_3\":\"Darui is fairly tall in stature and has a dark skin tone, slightly bulbous nose, a lazy look in his eyes and white, shaggy hair which covers the left side of his face. He wears a high collared sleeveless uniform, loose fitting pants, and one-strap-over-one-shoulder Flak Jacket of a Kumogakure J\\u014Dnin. Darui also has stylized characters for Water (\\u6C34) and Lightning (\\u96F7) tattooed on his right and left shoulders respectively, denoting his chakra\\u0027s elemental nature affinities; Water Release and Lightning Release. The tattoo on his left arm also signifies that he has inherited the Third Raikage\\u0027s technique. As a sword-user, Darui wields a broad, cleaver-like blade, which he carries on his back. He doesn\\u0027t seem to carry it around with him in his village however.\",\"Description_4\":\"Darui is a highly skilled and capable shinobi. He learned how to create Black Lightning under the tutelage of the Third Raikage, making his lightning techniques even more powerful. His chakra reserves are great enough to not die of chakra exhaustion after using three of the Treasured Tools of the Sage of the Six Paths and still have enough chakra left to continue fighting. His abilities have earned him the praise and recognition of the Fourth Raikage himself, who appointed Darui as his personal bodyguard and considers him his right-hand man.\",\"Description_5\":\"Kenjutsu\",\"Description_6\":\"Darui wields a long and fairly broad sword that is peculiar than others swords as it folds in two to be sheathed and unfolds when in use. He has shown exceptional skills in kenjutsu, as he was able to clash with Suigetsu H\\u014Dzuki\\u0027s Kubikirib\\u014Dch\\u014D and easily overwhelm and pin him to a wall with his lightning imbued sword. He was also skilled enough to literally disarm Ginkaku and Kinkaku during their battle, and knock Ginkaku into Kinkaku\\u0027s K\\u014Dkinj\\u014D while quickly seizing the Shichiseiken and Benihisago.\",\"Darui is proficient with water and lightning release techniques, and is able to use two separate techniques of the natures simultaneously. He uses Lightning Release\":\"Wave of Inspiration, together with water release jutsus to let electricity flow through the water and make the jutsus deadlier. He has shown exceptional skills with Lightning Release techniques individually, able to use Black Lightning, a special form of lightning passed down to him by the Third Raikage. With the power of the \\u0022Black Lightning\\u0022, he could use techniques like the Lightning Release: Black Panther to immobilize and/or kill several enemies. According to one of his comrades, he is the only person to have inherited the Third Raikage\\u0027s Black Lightning.\",\"Description_7\":\"Darui is also proficient with the use of chakra flow with ballistic weapon. His skill with chakra flow is such that he was able to cut through a metal blade with a lightning-enhanced shuriken.\",\"Description_8\":\"He also possesses the kekkei genkai known as Storm Release, which combines both lightning and water chakra to create beams of light that can be freely guided like missiles and cause powerful explosions.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Darui is a jounin-level shinobi from Kumogakure. He is also the Commander of the First Division of the Allied Shinobi Forces.\", \"Description_2\": \"Darui is portrayed as being easy-going and mellow; when compared to the Fourth Raikage\'s over-the-top exit through a window, he tells C that he\'ll just use the door. Whilst having a laid-back demeanour, Darui isn\'t lazy, leaping to the Raikage\'s defence when the bodyguards of the other Kage overreact to the Raikage\'s actions. He also has a habit of referring to things or events as being \\\"dull\\\" a play on his name. Darui is also very apologetic, even apologizing for other people\'s actions, a trait he\'d never noticed himself; this attribute led him to say \\\"sorry\\\" just as much as \\\"dull.\\\" He is also very loyal to the Raikage who considers Darui his \\\"second right hand.\\\" He adresses the Raikage with \\\"boss\\\" rather than \\\"Raikage-sama.\\\"\", \"Description_3\": \"Darui is fairly tall in stature and has a dark skin tone, slightly bulbous nose, a lazy look in his eyes and white, shaggy hair which covers the left side of his face. He wears a high collared sleeveless uniform, loose fitting pants, and one-strap-over-one-shoulder Flak Jacket of a Kumogakure Jōnin. Darui also has stylized characters for Water (水) and Lightning (雷) tattooed on his right and left shoulders respectively, denoting his chakra\'s elemental nature affinities; Water Release and Lightning Release. The tattoo on his left arm also signifies that he has inherited the Third Raikage\'s technique. As a sword-user, Darui wields a broad, cleaver-like blade, which he carries on his back. He doesn\'t seem to carry it around with him in his village however.\", \"Description_4\": \"Darui is a highly skilled and capable shinobi. He learned how to create Black Lightning under the tutelage of the Third Raikage, making his lightning techniques even more powerful. His chakra reserves are great enough to not die of chakra exhaustion after using three of the Treasured Tools of the Sage of the Six Paths and still have enough chakra left to continue fighting. His abilities have earned him the praise and recognition of the Fourth Raikage himself, who appointed Darui as his personal bodyguard and considers him his right-hand man.\", \"Description_5\": \"Kenjutsu\", \"Description_6\": \"Darui wields a long and fairly broad sword that is peculiar than others swords as it folds in two to be sheathed and unfolds when in use. He has shown exceptional skills in kenjutsu, as he was able to clash with Suigetsu Hōzuki\'s Kubikiribōchō and easily overwhelm and pin him to a wall with his lightning imbued sword. He was also skilled enough to literally disarm Ginkaku and Kinkaku during their battle, and knock Ginkaku into Kinkaku\'s Kōkinjō while quickly seizing the Shichiseiken and Benihisago.\", \"Description_7\": \"Darui is also proficient with the use of chakra flow with ballistic weapon. His skill with chakra flow is such that he was able to cut through a metal blade with a lightning-enhanced shuriken.\", \"Description_8\": \"He also possesses the kekkei genkai known as Storm Release, which combines both lightning and water chakra to create beams of light that can be freely guided like missiles and cause powerful explosions.\", \"Darui is proficient with water and lightning release techniques, and is able to use two separate techniques of the natures simultaneously. He uses Lightning Release\": \"Wave of Inspiration, together with water release jutsus to let electricity flow through the water and make the jutsus deadlier. He has shown exceptional skills with Lightning Release techniques individually, able to use Black Lightning, a special form of lightning passed down to him by the Third Raikage. With the power of the \\\"Black Lightning\\\", he could use techniques like the Lightning Release: Black Panther to immobilize and/or kill several enemies. According to one of his comrades, he is the only person to have inherited the Third Raikage\'s Black Lightning.\"}'),(58,1902,'Deidara','{\"Birthday\":\"May 5\",\"Age\":\"19\",\"Chakra Element\":\"Doton\",\"Height\":\"166 cm\",\"Weight\":\"50.8 kg\",\"Blood Type\":\"AB\",\"Zodiac\":\"Taurus\",\"Occupation\":\"Akatsuki member\",\"Deidara is a missing-nin from Iwagakure. Before joining Akatsuki, Deidara was as a terrorist bomber for hire, where his work attracted the attention of Pain. Pain sent other Akatsuki members to recruit Deidara, though he refused. After being defeated by Itachi Uchiha, however, Deidara was forced to join the organization. Deidara maintained a deep loathing for Itachi from that point further and became determined to defeat him, even training one of his eyes to overcome Itachi\\u0027s signature ability\":\"genjutsu. Deidara was partnered with Sasori upon joining the organization, whose artistic ability and insight Deidara admired. After Sasori\\u0027s death Deidara is paired with Tobi whom he treats as a disciple. Despite Tobi\\u0027s habit of accidentally angering Deidara, Deidara takes great care to keep Tobi out of harm\\u0027s way and even dedicates his final moments to apologizing to him.\",\"Description\":\"In battle, Deidara uses special mouths in the palm of each hand to create Exploding Clay, chakra-infused clay that explodes on command. He commonly uses the command \\u0022Katsu\\u0022 to trigger it. The blast strength of his creations is determined by how much chakra he adds to them. His clay can take on any size or form, ranging from microscopic in size to copies of himself as tall as a skyscraper. Deidara refers to his creations as art, believing the most beautiful thing about them to be their detonation. His admiration for his art is such that he believes it can\\u0027t be defeated, leading to overconfidence in battle. Depending on the complexity or potency of one of his works, Deidara applies it a designation from anywhere between \\u0022C1\\u0022 to \\u0022C4\\u0022, the former being the most basic and the latter being his strongest and most complex attack. For his final act, Deidara also has a mouth on his chest that, once provided with clay, turns him into a living bomb that destroys everything in a 10 kilometer radius.\"}','{\"Age\": \"19\", \"Height\": \"166 cm\", \"Weight\": \"50.8 kg\", \"Zodiac\": \"Taurus\", \"Birthday\": \"May 5\", \"Blood Type\": \"AB\", \"Occupation\": \"Akatsuki member\", \"Description\": \"In battle, Deidara uses special mouths in the palm of each hand to create Exploding Clay, chakra-infused clay that explodes on command. He commonly uses the command \\\"Katsu\\\" to trigger it. The blast strength of his creations is determined by how much chakra he adds to them. His clay can take on any size or form, ranging from microscopic in size to copies of himself as tall as a skyscraper. Deidara refers to his creations as art, believing the most beautiful thing about them to be their detonation. His admiration for his art is such that he believes it can\'t be defeated, leading to overconfidence in battle. Depending on the complexity or potency of one of his works, Deidara applies it a designation from anywhere between \\\"C1\\\" to \\\"C4\\\", the former being the most basic and the latter being his strongest and most complex attack. For his final act, Deidara also has a mouth on his chest that, once provided with clay, turns him into a living bomb that destroys everything in a 10 kilometer radius.\", \"Chakra Element\": \"Doton\", \"Deidara is a missing-nin from Iwagakure. Before joining Akatsuki, Deidara was as a terrorist bomber for hire, where his work attracted the attention of Pain. Pain sent other Akatsuki members to recruit Deidara, though he refused. After being defeated by Itachi Uchiha, however, Deidara was forced to join the organization. Deidara maintained a deep loathing for Itachi from that point further and became determined to defeat him, even training one of his eyes to overcome Itachi\'s signature ability\": \"genjutsu. Deidara was partnered with Sasori upon joining the organization, whose artistic ability and insight Deidara admired. After Sasori\'s death Deidara is paired with Tobi whom he treats as a disciple. Despite Tobi\'s habit of accidentally angering Deidara, Deidara takes great care to keep Tobi out of harm\'s way and even dedicates his final moments to apologizing to him.\"}'),(59,34114,'Denka','{\"Description\":\"Denka (\\u30C7\\u30F3\\u30AB) is a ninja cat that lives with Nekobaa at an Uchiha supply base. Suigetsu mistakes him for a tanuki. His senses are sharp after sensing Sasuke\\u0027s chakra and remembering him after the years apart\"}','{\"Description\": \"Denka (デンカ) is a ninja cat that lives with Nekobaa at an Uchiha supply base. Suigetsu mistakes him for a tanuki. His senses are sharp after sensing Sasuke\'s chakra and remembering him after the years apart\"}'),(60,94985,'Disonas','{\"Description\":\"Disonas (\\u30C7\\u30A3\\u30BD\\u30CA\\u30B9, Disonasu) was the leader of Hach\\u014D Village\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Disonas (ディソナス, Disonasu) was the leader of Hachō Village\"}'),(61,94973,'Dock','{\"Description\":\"Dock is a citizen of the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Dock is a citizen of the Tonika Village.\"}'),(62,77437,'Dodai','{\"Description\":\"Dodai (\\u30C9\\u30C0\\u30A4, Dodai) is a Kumogakure shinobi.\",\"Manga Debut\":\"Chapter #541\",\"Anime Debut\":\"Naruto Shippuuden Episode #282\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #282\", \"Description\": \"Dodai (ドダイ, Dodai) is a Kumogakure shinobi.\", \"Manga Debut\": \"Chapter #541\"}'),(63,10791,'Ebisu','{\"Description\":\"Ebisu is an elite Jounin tutor; he also serves as the personal tutor to the Third Hokage\\u0027s grandson Konohamaru.\",\"Description_2\":\"Like many in the village Ebisu saw Naruto as the Kyuubi himself. Over time though Naruto\\u0027s hard work impressed Ebisu and he acknowledged that Naruto could be a good role model for Konohamaru.\"}','{\"Description\": \"Ebisu is an elite Jounin tutor; he also serves as the personal tutor to the Third Hokage\'s grandson Konohamaru.\", \"Description_2\": \"Like many in the village Ebisu saw Naruto as the Kyuubi himself. Over time though Naruto\'s hard work impressed Ebisu and he acknowledged that Naruto could be a good role model for Konohamaru.\"}'),(64,31825,'Ebizou','{\"Description\":\"Ebiz\\u014D is called \\u0022Honoured Grandfather Ebiz\\u014D\\u0022 by the Sand villagers. He and his older sister, Chiyo, are highly revered in Sunagakure, and were known as the Honoured Siblings. He is Sasori\\u0027s paternal granduncle.\"}','{\"Description\": \"Ebizō is called \\\"Honoured Grandfather Ebizō\\\" by the Sand villagers. He and his older sister, Chiyo, are highly revered in Sunagakure, and were known as the Honoured Siblings. He is Sasori\'s paternal granduncle.\"}'),(65,95091,'Eff','{\"Description\":\"F is a Kumogakure shinobi.\",\"Description_2\":\"During the Fourth Shinobi World War, F was attacked by a White Zetsu Army clone on the battlefield and was later impersonated by this clone. It is unknown if the real F is still alive.\",\"Manga Debut\":\"Chapter #545\",\"Anime Debut\":\"Naruto Shippuuden Episode #296\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #296\", \"Description\": \"F is a Kumogakure shinobi.\", \"Manga Debut\": \"Chapter #545\", \"Description_2\": \"During the Fourth Shinobi World War, F was attacked by a White Zetsu Army clone on the battlefield and was later impersonated by this clone. It is unknown if the real F is still alive.\"}'),(66,30185,'En no Gyouja','{\"Description\":\"En no Gy\\u014Dja (\\u5F79\\u306E\\u884C\\u8005) was the former leader of the Tsuchigumo clan and the grandfather of Hotaru.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"En no Gyōja (役の行者) was the former leader of the Tsuchigumo clan and the grandfather of Hotaru.\"}'),(67,15757,'Enma','{\"Monkey King\":\"Enma was the personal summon of Hiruzen Sarutobi, the Third Hokage. As he was a long-time companion to Hiruzen, it is implied that he is also rather old.\"}','{\"Monkey King\": \"Enma was the personal summon of Hiruzen Sarutobi, the Third Hokage. As he was a long-time companion to Hiruzen, it is implied that he is also rather old.\"}'),(68,33618,'Fudou','{\"Description\":\"Fud\\u014D was part of the group of grave robbers who dug up four of the dead Twelve Guardian Ninja. He was the brute force of the group, and was usually shown paired up with Fuen.\"}','{\"Description\": \"Fudō was part of the group of grave robbers who dug up four of the dead Twelve Guardian Ninja. He was the brute force of the group, and was usually shown paired up with Fuen.\"}'),(69,33619,'Fuen','{\"Description\":\"Fuen was a kunoichi who was part of the group of grave robbers who dug up four of the dead Twelve Guardian Ninja. She was the strategist and trap expert of the group, and was widely thought of as the weakest member of the team.\"}','{\"Description\": \"Fuen was a kunoichi who was part of the group of grave robbers who dug up four of the dead Twelve Guardian Ninja. She was the strategist and trap expert of the group, and was widely thought of as the weakest member of the team.\"}'),(70,24486,'Fukasaku','{\"Description\":\"Fukasaku (\\u30D5\\u30AB\\u30B5\\u30AF) is the husband of Shima and an elder toad from My\\u014Dbokuzan. As the heirs of the Great Toad Sage, he and his wife are revered as the Two Great Sage Toads. Together with Shima, he taught Jiraiya how to use Senjutsu and later he alone taught Naruto the same. He has a leading position among the toads, being called Head (\\u982D, Kashira).\",\"Source\":\"\"}','{\"Source\": \"\", \"Description\": \"Fukasaku (フカサク) is the husband of Shima and an elder toad from Myōbokuzan. As the heirs of the Great Toad Sage, he and his wife are revered as the Two Great Sage Toads. Together with Shima, he taught Jiraiya how to use Senjutsu and later he alone taught Naruto the same. He has a leading position among the toads, being called Head (頭, Kashira).\"}'),(71,267451,'Funeno, Daikoku','{}','{}'),(72,13929,'Furido','{\"Description\":\"Kazuma also known as Furido, was a member of the Twelve Guardian Ninja, and eventually led half of the group to stage a coup d\\u0027etat against the Hokage. He was also the father of Sora.\"}','{\"Description\": \"Kazuma also known as Furido, was a member of the Twelve Guardian Ninja, and eventually led half of the group to stage a coup d\'etat against the Hokage. He was also the father of Sora.\"}'),(73,38643,'Furofoki','{\"Description\":\"Furofoki is a Konoha medical ninja examining Jofuku flower in Jofuku Forest on the mountain of the same name. When queried by Naruto about her decision to live and work all alone on the mountain, she told him that\\u0027s what she decided and it wasn\\u0027t his business. She has a great understanding of the flowers and seems to have gathered quite a few of them, indicating that she may have either fought off the flowers\\u0027 defenses or discovered a way to safely harvest them, either one being testament to her ability.\",\"(source\":\"naruto.wikia.com)\"}','{\"(source\": \"naruto.wikia.com)\", \"Description\": \"Furofoki is a Konoha medical ninja examining Jofuku flower in Jofuku Forest on the mountain of the same name. When queried by Naruto about her decision to live and work all alone on the mountain, she told him that\'s what she decided and it wasn\'t his business. She has a great understanding of the flowers and seems to have gathered quite a few of them, indicating that she may have either fought off the flowers\' defenses or discovered a way to safely harvest them, either one being testament to her ability.\"}'),(74,63209,'Fusou','{\"Age\":\"28\",\"Status\":\"Deceased\",\"Occupation\":\"Nurse\",\"Affiliation\":\"Amegakure\",\"Family\":\"Nagato (son), Ise (husband)\",\"Description\":\"Fusou was a nurse and a citizen of Amegakure, where she lived in a small village with her son Nagato and her husband.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"28\", \"Family\": \"Nagato (son), Ise (husband)\", \"Status\": \"Deceased\", \"(Source\": \"Narutopedia)\", \"Occupation\": \"Nurse\", \"Affiliation\": \"Amegakure\", \"Description\": \"Fusou was a nurse and a citizen of Amegakure, where she lived in a small village with her son Nagato and her husband.\"}'),(75,270605,'Futami','{}','{}'),(76,23220,'Fuu','{\"Description\":\"Fuu (\\u30D5\\u30A6) was a kunoichi from Takigakure and the jinchuuriki of Choumei, the Seven-Tails. Choumei has been captured and sealed by Akatsuki, causing her death when the beast was extracted.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Fuu (フウ) was a kunoichi from Takigakure and the jinchuuriki of Choumei, the Seven-Tails. Choumei has been captured and sealed by Akatsuki, causing her death when the beast was extracted.\"}'),(77,20741,'Fuuka','{\"Description\":\"A kunoichi that appears in the first filler arc of Shippuuden. She is part of the group of grave robbers who have dug up four of the dead Twelve Guardian Ninja. Despite her young and beautiful appearance, her unusual powers and hagged appearance at one point suggest that she is much older than she seems. She is seen being very interested in people with wind elemental chakra like Naruto.\",\"Description_2\":\"-INFORMATION FROM NARUTO WIKI-\"}','{\"Description\": \"A kunoichi that appears in the first filler arc of Shippuuden. She is part of the group of grave robbers who have dug up four of the dead Twelve Guardian Ninja. Despite her young and beautiful appearance, her unusual powers and hagged appearance at one point suggest that she is much older than she seems. She is seen being very interested in people with wind elemental chakra like Naruto.\", \"Description_2\": \"-INFORMATION FROM NARUTO WIKI-\"}'),(78,126085,'Fuyou','{}','{}'),(79,94979,'Fuzz','{\"Description\":\"Fuzz (\\u30D5\\u30A1\\u30BA, Fazu) is a young citizen of the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Fuzz (ファズ, Fazu) is a young citizen of the Tonika Village.\"}'),(80,1662,'Gaara','{\"Ninja Registration N\\u00BA\":\"56-001\",\"Birth Date\":\"19 January\",\"Age\":\"12-13 (I), 15-16 (II)\",\"Horoscope\":\"Capricorn\",\"Gender\":\"Male\",\"Blood type\":\"AB\",\"Height\":\"146 cm (Part I), 166 cm (Part II)\",\"Personality type\":\"infp\",\"Weight\":\"39 kg (Part I), 50.9 kg (Part II)\",\"Affiliation\":\"Hidden Sand Village, Wind country\",\"Team\":\"Team Baki (Temari, Kankuro and Gaara )\",\"Tailed Beast\":\"One-Tailed Shukaku\",\"Known relatives\":\"Fourth Kazekage (father), Karura (mother), Temari (older sister), Kankuro (older brother), Yashamaru (uncle)\",\"Description\":\"Gaara was introduced in the series in Chuunin Exams arc, as a violent shinobi from Konoha\\u0027s allied country, the Wind country. He came to Konoha with his siblings Temari and Kankuro, and with his mentor Baki, to participate in Chuunin exams.\",\"Description_2\":\"From the first look, he was shown as merciless and violent individual. Due to his hard childhood, and lack of love, Gaara grew up hating everybody around him, loving only himself.\",\"Description_3\":\"In fateful incident about 6 years before the main story time, he made himself a tattoo of Japanese Kanji letter \\u0022Ai,\\u0022 which stands for \\u0022Love.\\u0022 In Gaara\\u0027s case, that Love was for himself, as he was \\u0022Demon loving only himself.\\u0022\",\"Description_4\":\"The Kanji \\u0022\\u611B\\u0022 for love that is on his forehead, is also part of his name.\"}','{\"Age\": \"12-13 (I), 15-16 (II)\", \"Team\": \"Team Baki (Temari, Kankuro and Gaara )\", \"Gender\": \"Male\", \"Height\": \"146 cm (Part I), 166 cm (Part II)\", \"Weight\": \"39 kg (Part I), 50.9 kg (Part II)\", \"Horoscope\": \"Capricorn\", \"Birth Date\": \"19 January\", \"Blood type\": \"AB\", \"Affiliation\": \"Hidden Sand Village, Wind country\", \"Description\": \"Gaara was introduced in the series in Chuunin Exams arc, as a violent shinobi from Konoha\'s allied country, the Wind country. He came to Konoha with his siblings Temari and Kankuro, and with his mentor Baki, to participate in Chuunin exams.\", \"Tailed Beast\": \"One-Tailed Shukaku\", \"Description_2\": \"From the first look, he was shown as merciless and violent individual. Due to his hard childhood, and lack of love, Gaara grew up hating everybody around him, loving only himself.\", \"Description_3\": \"In fateful incident about 6 years before the main story time, he made himself a tattoo of Japanese Kanji letter \\\"Ai,\\\" which stands for \\\"Love.\\\" In Gaara\'s case, that Love was for himself, as he was \\\"Demon loving only himself.\\\"\", \"Description_4\": \"The Kanji \\\"愛\\\" for love that is on his forehead, is also part of his name.\", \"Known relatives\": \"Fourth Kazekage (father), Karura (mother), Temari (older sister), Kankuro (older brother), Yashamaru (uncle)\", \"Personality type\": \"infp\", \"Ninja Registration Nº\": \"56-001\"}'),(81,4223,'Gamabunta','{\"Description\":\"Gamabunta speaks like a yakuza gangster who won\\u0027t work with anyone he doesn\\u0027t respect. Despite this, he is fiercely protective of his children and Naruto, and will fight for their safety regardless of his respect for the summoner (or, more likely, whether or not Jiraiya is on his good side).\"}','{\"Description\": \"Gamabunta speaks like a yakuza gangster who won\'t work with anyone he doesn\'t respect. Despite this, he is fiercely protective of his children and Naruto, and will fight for their safety regardless of his respect for the summoner (or, more likely, whether or not Jiraiya is on his good side).\"}'),(82,78095,'Gamahiro','{\"Gamahiro is a giant toad that resides on Mount Myoboku. He sometimes called\":\"\\u0022Hiro\\u0022.\",\"Description\":\"When Gamahiro first appears in the anime, his skin is colored green and brown. This is updated to a light-blue-greenish color for the Invasion of Pain Arc, keeping up with the manga\\u0027s coloration.\",\"Description_2\":\"Though he was first summoned in part I, he was not named until he was summoned again in part II.\",\"Description_3\":\"Though Gamahiro has spoken in the anime, he has yet to do so in the manga.\"}','{\"Description\": \"When Gamahiro first appears in the anime, his skin is colored green and brown. This is updated to a light-blue-greenish color for the Invasion of Pain Arc, keeping up with the manga\'s coloration.\", \"Description_2\": \"Though he was first summoned in part I, he was not named until he was summoned again in part II.\", \"Description_3\": \"Though Gamahiro has spoken in the anime, he has yet to do so in the manga.\", \"Gamahiro is a giant toad that resides on Mount Myoboku. He sometimes called\": \"\\\"Hiro\\\".\"}'),(83,26933,'Gamaken','{\"Description\":\"Gamaken (\\u30AC\\u30DE\\u30B1\\u30F3; Literally meaning \\u0022Strong Toad\\u0022) is a giant toad that first appeared in Part II. He wields a Sasumata-like weapon and a shield. He seemed to be a skilled fighter whilst fighting alongside Naruto. He also seems to be wearing the same robe as Gamabunta.\"}','{\"Description\": \"Gamaken (ガマケン; Literally meaning \\\"Strong Toad\\\") is a giant toad that first appeared in Part II. He wields a Sasumata-like weapon and a shield. He seemed to be a skilled fighter whilst fighting alongside Naruto. He also seems to be wearing the same robe as Gamabunta.\"}'),(84,16999,'Gamakichi','{\"Description\":\"Gamakichi (\\u30AC\\u30DE\\u5409; Literally meaning \\u0022Propitious Toad\\u0022) is one of Gamabunta\\u0027s children.\",\"Description_2\":\"He was first summoned by Naruto Uzumaki because Naruto couldn\\u0027t focus his chakra during the beginning of the battle with Gaara. However, he is intelligent enough to be aware of the situation around him and realize when it\\u0027s time to flee. During the Sannin battle, Gamakichi was accidentally summoned again by Jiraiya while he was fighting with Orochimaru because Tsunade had secretly fed Jiraiya a chakra-disrupting potion.\"}','{\"Description\": \"Gamakichi (ガマ吉; Literally meaning \\\"Propitious Toad\\\") is one of Gamabunta\'s children.\", \"Description_2\": \"He was first summoned by Naruto Uzumaki because Naruto couldn\'t focus his chakra during the beginning of the battle with Gaara. However, he is intelligent enough to be aware of the situation around him and realize when it\'s time to flee. During the Sannin battle, Gamakichi was accidentally summoned again by Jiraiya while he was fighting with Orochimaru because Tsunade had secretly fed Jiraiya a chakra-disrupting potion.\"}'),(85,30924,'Gamamaru','{\"Description\":\"The Great Toad Sage is the oldest and most respected toad of all the inhabitants of Mount My\\u014Dboku. Because of his age, the other toads affectionately call him Great Honorable Geezer. He is famed for his highly accurate prophecies.\",\"Description_2\":\"Being several thousand years old, he is the oldest and most respected among the population of Mount My\\u014Dboku. At his great age, the Great Toad Sage seems to constantly smile and tends to have his eyes closed or squinting. He is portrayed and described as being senile, and sometimes out of touch with his present situation, so he does tend to forget things easily and quite quickly. However, when reminded, he is still able to remember things and can easily tell things very precisely. As a sage, he is also very wise, and is quick to stop Shima and Fukasaku from bickering and encourages harmony. It would seem that unlike most other toads, he actually has respect for Jiraiya, and has urged both Shima and Fukasaku to cooperate with him\"}','{\"Description\": \"The Great Toad Sage is the oldest and most respected toad of all the inhabitants of Mount Myōboku. Because of his age, the other toads affectionately call him Great Honorable Geezer. He is famed for his highly accurate prophecies.\", \"Description_2\": \"Being several thousand years old, he is the oldest and most respected among the population of Mount Myōboku. At his great age, the Great Toad Sage seems to constantly smile and tends to have his eyes closed or squinting. He is portrayed and described as being senile, and sometimes out of touch with his present situation, so he does tend to forget things easily and quite quickly. However, when reminded, he is still able to remember things and can easily tell things very precisely. As a sage, he is also very wise, and is quick to stop Shima and Fukasaku from bickering and encourages harmony. It would seem that unlike most other toads, he actually has respect for Jiraiya, and has urged both Shima and Fukasaku to cooperate with him\"}'),(86,16952,'Gamatatsu','{\"Description\":\"Gamatatsu (\\u30AC\\u30DE\\u7ADC; Literally meaning \\u0022Toad Dragon\\u0022) is one of Gamabunta\\u0027s children and Gamakichi\\u0027s younger brother who has a fixation with snacks.\",\"Description_2\":\"Gamatatsu has shown that he\\u0027d choose snacks over someone\\u0027s life. When Naruto is injured while fighting with Kabuto Yakushi, he replies, \\u0022Hey Gamakichi, do we have to wait for the kid to croak till we get snacks, cuz\\u0027 I\\u0027m getting hungry\\u0022. Although in the filler arcs Gamatatsu showed that he does care about Naruto\\u0027s life as he was ready to rescue him before Gamakichi talked him out of it. It should be noted that Gamatatsu appears to be the most subservient and loyal of the main frog summons as he was willing to serve Naruto before Gamakichi brought up the snack remark. While being naive and childishly stupid, he does sometimes make use of his natural curiosity to help Naruto solve puzzles (like the mystery of the Ghost Warrior in the filler arcs). Gamatatatsu\\u0027s obsession for snacks is so great that he waited a year since his first summon for the snack he was promised, even though he didn\\u0027t get it. He is always hungry and asking his summoner for snacks, and often gets mixed up in unusual predicaments which he counts on his \\u0022big brother Gamakichi\\u0022 to get him out of. In the english dub, his voice is jocularly high and he is usually used for comic relief when he is summoned. He also openly refers to Gamabunta as \\u0022daddy\\u0022, which the older toad either chooses to ignore or simply doesn\\u0027t mind.\"}','{\"Description\": \"Gamatatsu (ガマ竜; Literally meaning \\\"Toad Dragon\\\") is one of Gamabunta\'s children and Gamakichi\'s younger brother who has a fixation with snacks.\", \"Description_2\": \"Gamatatsu has shown that he\'d choose snacks over someone\'s life. When Naruto is injured while fighting with Kabuto Yakushi, he replies, \\\"Hey Gamakichi, do we have to wait for the kid to croak till we get snacks, cuz\' I\'m getting hungry\\\". Although in the filler arcs Gamatatsu showed that he does care about Naruto\'s life as he was ready to rescue him before Gamakichi talked him out of it. It should be noted that Gamatatsu appears to be the most subservient and loyal of the main frog summons as he was willing to serve Naruto before Gamakichi brought up the snack remark. While being naive and childishly stupid, he does sometimes make use of his natural curiosity to help Naruto solve puzzles (like the mystery of the Ghost Warrior in the filler arcs). Gamatatatsu\'s obsession for snacks is so great that he waited a year since his first summon for the snack he was promised, even though he didn\'t get it. He is always hungry and asking his summoner for snacks, and often gets mixed up in unusual predicaments which he counts on his \\\"big brother Gamakichi\\\" to get him out of. In the english dub, his voice is jocularly high and he is usually used for comic relief when he is summoned. He also openly refers to Gamabunta as \\\"daddy\\\", which the older toad either chooses to ignore or simply doesn\'t mind.\"}'),(87,38453,'Gameru','{\"Description\":\"Gameru is a ninja who possesses one of Iou\\u0027s prototype ninja tools, Dako. Him along with Kusune came to Iou to get ninja tools but he refused to give some to outsiders. Gameru and Kusune fight Naruto Uzumaki and Neji Hy\\u016Bga who are no match against Iou\\u0027s ninja tools. When Iou gives Tenten his latest invention, Jidanda, Tenten easily defeats the two.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Gameru is a ninja who possesses one of Iou\'s prototype ninja tools, Dako. Him along with Kusune came to Iou to get ninja tools but he refused to give some to outsiders. Gameru and Kusune fight Naruto Uzumaki and Neji Hyūga who are no match against Iou\'s ninja tools. When Iou gives Tenten his latest invention, Jidanda, Tenten easily defeats the two.\"}'),(88,62633,'Ganryuu','{\"Description\":\"Ganryuu (\\u5DCC\\u6D41, Ganry\\u016B) is a j\\u014Dnin-level shinobi of Kirigakure.\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #242\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #242\", \"Description\": \"Ganryuu (巌流, Ganryū) is a jōnin-level shinobi of Kirigakure.\"}'),(89,62129,'Gari','{\"Description\":\"Gari (\\u30AC\\u30EA, Gari) was a famed Iwagakure shinobi and a member of the Explosion Corps along with Deidara.\",\"Gari is able to use Explosion Release, a kekkei genkai that allows him to combine two unknown chakra natures to utilise explosive chakra, as seen when he used Explosion Release\":\"Landmine Fist to obliterate an Allied Shinobi ninja simply by punching him.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shippuuden Episode #256\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #256\", \"Description\": \"Gari (ガリ, Gari) was a famed Iwagakure shinobi and a member of the Explosion Corps along with Deidara.\", \"Manga Debut\": \"Chapter #515\", \"Gari is able to use Explosion Release, a kekkei genkai that allows him to combine two unknown chakra natures to utilise explosive chakra, as seen when he used Explosion Release\": \"Landmine Fist to obliterate an Allied Shinobi ninja simply by punching him.\"}'),(90,50545,'Gataro','{}','{}'),(91,63793,'Gatou','{\"Description\":\"Gatou was a shipping magnate and founder of Gat\\u014D Company. He also was secretly a drug dealer as well as the owner of a smuggling business and attempted to take control of the Land of Waves.\",\"Manga Debut\":\"Chapter #10\",\"Anime Debut\":\"Naruto  Episode #6\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto  Episode #6\", \"Description\": \"Gatou was a shipping magnate and founder of Gatō Company. He also was secretly a drug dealer as well as the owner of a smuggling business and attempted to take control of the Land of Waves.\", \"Manga Debut\": \"Chapter #10\"}'),(92,7738,'Gekkou, Hayate','{\"Name\":\"Hayate Gekkou\",\"Gender\":\"Male\",\"Age\":\"23\",\"Birthday\":\"November 2\",\"Height\":\"5\\u00277\\u0022\",\"Weight\":\"128 lbs\",\"Blood Type\":\"AB\",\"Affiliation\":\"Konohagakure\",\"Previous Occupation\":\"Examiner\",\"Description\":\"Hayate Gekkou was the examiner of the preliminary third portion of the Chuunin exams. The name \\u0022Gekkou\\u0022 means \\u0022moonlight\\u0022 and \\u0022Hayate\\u0022 means \\u0022quick as wind\\u0022 or \\u0022hurricane\\u0022.\",\"Description_2\":\"Little is known about Hayate\\u0027s abilities, except for a move which he used on Baki that failed. This technique is called Dance of the Crescent Moon, which is an advanced technique that creates multiple clones of the user while the real person attacks from a blind spot from above. Baki comments that the village has talented ninja, seeing Hayate can use this technique and has mastered it at such a young age. From this we also know that he owns a katana, and possesses great speed, as he demonstrated during the Chuunin Exams when stopping Neji from attacking Hinata.\"}','{\"Age\": \"23\", \"Name\": \"Hayate Gekkou\", \"Gender\": \"Male\", \"Height\": \"5\'7\\\"\", \"Weight\": \"128 lbs\", \"Birthday\": \"November 2\", \"Blood Type\": \"AB\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Hayate Gekkou was the examiner of the preliminary third portion of the Chuunin exams. The name \\\"Gekkou\\\" means \\\"moonlight\\\" and \\\"Hayate\\\" means \\\"quick as wind\\\" or \\\"hurricane\\\".\", \"Description_2\": \"Little is known about Hayate\'s abilities, except for a move which he used on Baki that failed. This technique is called Dance of the Crescent Moon, which is an advanced technique that creates multiple clones of the user while the real person attacks from a blind spot from above. Baki comments that the village has talented ninja, seeing Hayate can use this technique and has mastered it at such a young age. From this we also know that he owns a katana, and possesses great speed, as he demonstrated during the Chuunin Exams when stopping Neji from attacking Hinata.\", \"Previous Occupation\": \"Examiner\"}'),(93,148296,'Gengo','{}','{}'),(94,48839,'Gerotora','{\"Description\":\"Gerotora is a scroll toad, a rare species that closely guards whatever secret has been written on its scroll-abdomen until his contractor dies. He resides in the belly of his contractor, and is known for his excellent endurance.\",\"(Source\":\"Naruto.wikia)\"}','{\"(Source\": \"Naruto.wikia)\", \"Description\": \"Gerotora is a scroll toad, a rare species that closely guards whatever secret has been written on its scroll-abdomen until his contractor dies. He resides in the belly of his contractor, and is known for his excellent endurance.\"}'),(95,65141,'Ginkaku','{\"Description\":\"Ginkaku (\\u9280\\u89D2, Ginkaku) is one of Kumogakure\\u0027s infamous Gold and Silver Brothers alongside his brother Kinkaku.\",\"Manga Debut\":\"Chapter #525\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #267\",\"(source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #267\", \"(source\": \"Narutopedia)\", \"Description\": \"Ginkaku (銀角, Ginkaku) is one of Kumogakure\'s infamous Gold and Silver Brothers alongside his brother Kinkaku.\", \"Manga Debut\": \"Chapter #525\"}'),(96,33791,'Gozu','{\"Description\":\"Gozu (\\u725B\\u982D) is a shinobi who appeared in the second Naruto Shipp\\u016Bden filler arc. He is a subordinate of Guren\",\"Description_2\":\"He is unsociable and quiet, making people unable to figure out what he is thinking, but his battle skills are without a doubt very dexterous. He relies on taijutsu and brute strength and preferred fighting alone. He holds a special sentiment towards Guren and was her most loyal subordinate, even stating \\u0022I will accompany you no matter where you go\\u0022. The reason for this was that Guren saved his life while he was imprisoned by Orochimaru, giving him water when he was dying of thirst.\"}','{\"Description\": \"Gozu (牛頭) is a shinobi who appeared in the second Naruto Shippūden filler arc. He is a subordinate of Guren\", \"Description_2\": \"He is unsociable and quiet, making people unable to figure out what he is thinking, but his battle skills are without a doubt very dexterous. He relies on taijutsu and brute strength and preferred fighting alone. He holds a special sentiment towards Guren and was her most loyal subordinate, even stating \\\"I will accompany you no matter where you go\\\". The reason for this was that Guren saved his life while he was imprisoned by Orochimaru, giving him water when he was dying of thirst.\"}'),(97,20013,'Guren','{\"Description\":\"A kunoichi who appears in the second Naruto Shipp\\u016Bden filler arc. She is the female leader of Orochimaru\\u0027s subordinates. She uses the unique Crystal Release brand of jutsu.\",\"Description_2\":\"As a child, Guren came from an unknown small village where she was shunned by others because she had unique powers. Later, Orochimaru appeared and destroyed the entire village single-handedly. He was intrigued by Guren\\u0027s powers and offered for her to come with him. Guren chose to follow him because she envied his power. Quickly, she became one of Orochimaru\\u0027s most powerful and loyal subordinates. Eventually, she was offered to become one of Orochimaru\\u0027s future vessels. Guren would also later know that the Nine-Tailed Demon Fox, the mightiest of the Tailed Beasts, had ultimately came into the possesion of the Hidden Leaf Village following the events where the Fourth Hokage sealed it into his recently-born son, but due to the extreme secrecy held within that Village regarding this matter, like everybody else outside of Konoha, Guren was left oblivious about the identity of the powerful demon\\u0027s container, Naruto Uzumaki, whom she would later encounter, instead coming to the conclusion that the Nine-Tails capture was for the sake of augmenting the Hidden Leafs military power. When Sasuke Uchiha defected from Konohagakure and Kimimaro was no longer a suitable vessel for Orochimaru, Guren became the next best choice in Orochimaru\\u0027s eyes. Unfortunately by the time she arrived, Orochimaru couldn\\u0027t wait any longer and instead chose Gen\\u0027yumaru. Feeling no longer of use to Orochimaru, Guren went into isolation. It is later revealed that she in fact killed Y\\u016Bkimaru\\u0027s mother.\",\"Description_3\":\"Guren has shown to be very mysterious, apparently preferring to keep to herself despite having a strong loyalty to Orochimaru. During her introduction, she quickly showed herself to be a remorseless and sadistic person. When told by Kabuto that several prisoners would be fighting to the death, she became ecstatic to hear there would be a slaughter. Guren is also shown to be vain by the fact that when she used her Jade Crystal Mirror technique, she looked at her self and said \\u0022Lovely, as always.\\u0022 She has also shown to be very proud. When Naruto offered to carry her she was embarrassed because it was shameful.\",\"Description_4\":\"She is devotedly loyal to Orochimaru, to an almost obsessive state. This devotion was so powerful that she fell into despair when she learned she would not become Orochimaru\\u0027s next vessel, isolating herself from the shame. It has also been shown she has a terrible relationship with Kabuto, as the two argue often, trading scathing remarks.[1] Later, she meets Y\\u016Bkimaru, and at first, she finds him peculiar and somewhat irritating. When Y\\u016Bkimaru became ill, she cared for him, watching over him for an entire night, until she fell asleep from exhaustion. When she woke up, she found that she was alone--and went searching for Y\\u016Bkimaru, who she found a little ways outside under a camellia tree. She then develops a sort of friendship with him as she crystallizes a beautiful flower and gently tells him that the flower will never wither as long as she is alive. He tells her that he lost his mother in similar circumstances while going out to find him a red camellia. Guren later comes across a red camellia patch, where she seems prompted to bring him one.\",\"Description_5\":\"Since coming in contact with Y\\u016Bkimaru, Guren seems to be having conflicting emotions. While part of her still wants to be accepted by Orochimaru as his next vessel, another part of her seems unable to let go of the bond she has made with Y\\u016Bkimaru to the point of protecting from even Orochimaru\\u0027s right-hand man, Kabuto. The emotions seemed to have become more confusing for her in her first one-on-one confrontation with Naruto, who stated bluntly how horrible and selfish a man Orochimaru really is.\",\"Description_6\":\"After realizing the truth behind her past and how it connects her to Y\\u016Bkimaru, Guren feels even more compelled to protect him, out of guilt and repentance for her past sins, as well as love--wishing to become an almost \\u0027surrogate mother\\u0027 to the boy, to replace the mother she killed. She even goes so far as to turn her protection to Naruto, as they faced off against the small Three-Tails clones within the tailed beast\\u0027s stomach, telling him she would protect him to the death if he would watch after Y\\u016Bkimaru. This is a great change from her previous interactions with Naruto, where she was stand-offish and combative. Subsequently, Guren has also begun to have doubts over remaining loyal to Orochimaru, due to her grief over the horrible things she was made to do in his name, and the damage and pain he has caused Y\\u016Bkimaru, and herself.\",\"Description_7\":\"Three-Tails Arrival arc\",\"To aid him in final preparations for his plan, Orochimaru sends Kabuto to fetch Guren (much to Kabuto\\u0027s disapproval). Guren attacks him when he approaches her domain, but he is able to avoid her attacks. When asked why she attacked him, Guren states that she just wanted to make sure Kabuto was worthy of being Orochimaru\\u0027s right-hand man. Upon returning to Orochimaru\\u0027s hideout, she has hundreds of Orochimaru\\u0027s prisoners fight to the death and forms a team with the survivors\":\"Rinji, Gozu, Kigiri, Kih\\u014D and Nurari.\",\"Description_8\":\"Guren, disapproving of Sasuke\\u0027s status as Orochimaru\\u0027s next vessel, is later offered a chance to replace Sasuke if she can prove herself. She and Y\\u016Bkimaru are sent to a certain area. While there, Y\\u016Bkimaru gets sick, forcing Guren to care for him. When he recovers, she is surprised to learn he too knows what it is like to have no one at such a young age and seems to have grown some feelings for him. She then crystallizes one of his flowers, knowing how much he likes them, so it won\\u0027t wither as long as she is alive. Later when finally meeting back up Team Guren, she leaves Y\\u016Bkimaru at the hideout while she goes out to handle the Team Kurenai.\",\"Description_9\":\"While her men fight Team Kurenai and Kakashi, Guren prepares for their arrival. Once done she has her men fall back, drawing the Konoha ninja into a trap and allowing Guren to encase Hinata in crystal. She uses Hinata as a hostage to prevent her men from being followed. Before anything can be done, Team Yamato arrives and breaks through her traps and defenses and subsequently frees Hinata. Annoyed at her enemies escaping, she decides goes back to their hideout to plan their next move, but Kabuto comes in and explains another plan.\",\"Description_10\":\"Kabuto, Guren, and her men go out to the lake so that they can awaken the Three-Tailed Beast. When it appears she tries to restrain it, but proves no match for its strength, the whole time holding Y\\u016Bkimaru in a protective hug. When she uses the last of her chakra to save Y\\u016Bkimaru and the others, she later awakens to find herself in the care of Y\\u016Bkimaru.\",\"Description_11\":\"Guren then finds herself having a dream about the her childhood with Orochimaru and dreams about a woman. After she awakes, she finds that Y\\u016Bkimaru is sick again, speculating that it was because of Kabuto\\u0027s overdose of pills. While taking care of Y\\u016Bkimaru, she detects Naruto coming and intercepts him. After a short scuffle, Y\\u016Bkimaru appears to stop the fight. It is here that Guren hears another view of Orochimaru from Naruto, making her question the path she has taken.\",\"Description_12\":\"After escaping with Y\\u016Bkimaru, she and her team begins preparing for the final confrontation with the Leaf Village and hoping to face Naruto again to settle things with him. Upon facing the Leaf Ninja again, her Crystal Release again proves to be very powerful. Unfortunately for her, Shino\\u0027s insects finally build up a strong enough resistance to make her powers useless. Although nearly perishing against her opponents, Gozu sacrifices himself to allow her to escape. Before escaping, however, Naruto made it clear to Guren that he\\u0027s determined to take Y\\u016Bkimaru away from her no matter what. At first confused at why the younger shinobi could possibly be interested in Y\\u016Bkimaru, Guren quickly rallies up and came to the conclusion that the Hidden Leaf shinobi became aware of Y\\u016Bkimaru\\u0027s powers, and are striving to obtain the boy in order to reign control over the Three-Tails\",\"Description_13\":\"While returning to the hideout, she hears Y\\u016Bkimaru play with a grasswhistle and perform a melody she remembers. She then realizes to her horror that it was her who killed Y\\u016Bkimaru\\u0027s mother. Upon the revelation, Guren begged Kabuto to not put Y\\u016Bkimaru through anymore pain, instead offering her own services to stop the Leaf Ninja from sealing away the Three-Tails. With the help of Rinji, Guren was able to stop the seal. Unfortunately, the Three-Tails then turned its attention to Guren. Luckily, Y\\u016Bkimaru was able to save her by using his powers to stop the Three-Tails.\",\"Description_14\":\"Guren recalls her second encounter with Y\\u016Bkimaru\\u0027s mother\",\"Description_15\":\"After seeing how desperate Y\\u016Bkimaru was to protect her, Guren\\u0027s guilt towards the boy became greater than ever, knowing that the boy was clinging to the person who had killed his mother. Deciding to atone for her crimes to Y\\u016Bkimaru, Guren chose to do everything in her power to protect him. Despite being battle-worn and low on chakra, Guren attacked the Three-Tails head-on. Fortunately, Naruto soon appeared the and the two grudgingly worked together to battle the beast. Ultimately, the Three-Tails managed to capture and swallow the two whole.\",\"Description_16\":\"Inside the beast, Guren is surprised to see Naruto there as well. She tries to attack him, but the injury she sustained earlier caused her to pass out; when she came about, she became even more surprised that Naruto without hesistation treated her wounds. The two quickly begin arguing about where Y\\u016Bkimaru belongs. Guren states bluntly that she refused to let Y\\u016Bkimaru succumb to any harm. When Naruto accuses Guren of using Y\\u016Bkimaru\\u0027s abilities for Orochimaru\\u0027s benefit, Guren retaliates that the Leaf Village being barely any different, only interested in obtaining more demons to create more Jinch\\u016Briki, now that they\\u0027ve learned of Y\\u016Bkimaru\\u0027s ability to tame the Three-Tails. Naruto quickly replied that his Village had no interest in the Tailed Beast itself, Guren calls him a liar, apparently aware that the Hidden Village already owns the host for the Nine-Tailed Fox. Naruto stops her train of thought by revealing that he is that very Jinch\\u016Briki, but one whom, for most of his life, his own Village did not treat as a proper being (much less their ultimate weapon), but rather, a living memory of the horrific catastrophe that the Tailed Beast which now resides within himself once wreaked upon the Hidden Leaf. Upon learning that Naruto refuses to use his demon powers in fear of hurting his loved ones, she begins to see that Naruto genuinely is concerned for Y\\u016Bkimaru\\u0027s well-being. Together, the two begin looking for a way out of the Three-Tails.\",\"Description_17\":\"As they found themselves being cornered by the mini-Three-Tails, Guren felt compelled to admit to Naruto her hand in causing Y\\u016Bkimaru\\u0027s loneliness. After revealing the truth, she decides that Naruto is right, that Y\\u016Bkimaru\\u0027s place should not be with Orochimaru nor her, but with Naruto. Her sincerity towards this statement is proven by her desire to make sure Naruto gets out alive. To her surprise however, Naruto says she has changed and can make up for her mistakes. Together, they manage to escape the Three-Tails. Unfortunately upon escaping, they discover that Y\\u016Bkimaru is again being used to control the Three-Tails.\",\"Description_18\":\"Along the way, Guren has doubts about revealing the truth to Y\\u016Bkimaru, but Naruto convinces her to prove her sincerity of protecting Y\\u016Bkimaru even if refuses to forgive her. Being inspired by this, she and Naruto arrive in time to save Y\\u016Bkimaru from being forced to take a strange drug from Rinji, who turns out to be Kabuto in disguise. Kabuto decides to reveal the truth to Y\\u016Bkimaru, to which Guren makes no attempt to stop. To her shock and joy, Y\\u016Bkimaru decides to forgive her. The two then admit to how much they mean to each other. Guren leaves with Y\\u016Bkimaru under Naruto\\u0027s orders, and Kabuto summoned the deceased Rinji with his reincarnation jutsu, and Guren battles him in an attempt to protect Y\\u016Bkimaru. Taking no chances, she used her signature Crimson Fruit jutsu to keep him safe. Guren tried to trap Rinji in her Crystal Jutsu, but he used his bats\\u0027 supersonic abilities to shatter the crystal, saving himself and subsequently stopping Guren from using her Crystal Style. Devoted to protect Y\\u016Bkimaru with her life, she went behind Rinji and kept his hands apart, to now prevent HIM from using jutsu and controlling the bats. Though unable to perform any hand signs (with her hands busy holding back Rinji\\u0027s arms), Guren still managed to use the Crystal Style and crystallize herself and Rinji. The two fell into the water below. Gozu later saves her. Y\\u016Bkimaru later joined up with them, and the three of them left together.\",\"Description_19\":\"Abilities\",\"Description_20\":\"Guren possesses a unique ninja art; the Crystal Release. It is not clear that it is a kekkei genkai or a power unique to her, also Guren made it clear to Kakashi that he cannot copy her techniques with the Sharingan. By using this power, Guren can summon and manipulate crystal in a number of ways such as creating crushing walls or unique shuriken. It is stated by Kabuto and by Kakashi that she can crystallize moisture in the air, therefore giving her an infinite source of weapons. The density of this power appears to be very high as even the Wood Release was unable to penetrate it. This ability is presumed very powerful as Orochimaru at one point desired it for himself.\",\"Description_21\":\"Guren uses her crystal style\",\"Description_22\":\"In times of desperation, Guren is also able to convert a small portion of her life energy to access extra chakra reserves to allow her to continue fighting at full strength for a short period of time.\",\"Description_23\":\"Guren\\u0027s taijutsu skills are also rather high as she was able to fight on even grounds with an expert like Kakashi, dodge multiple Rasengan attacks from Naruto, and fight Lee and Tenten simultaneously. She is talented at noticing weaknesses in her opponent and using diversions, shown in how she kept the rest of Team 8 busy fighting her clones while she takes Hinata as hostage. After that she is seen to tell Naruto what she feels about Y\\u016Bkimaru. In addition, Guren also has good senses and is a keen observer. She was able to tell when Kakashi and Yamato were near and she was able to conclude that the Sanbi was trying to protect it\\u0027s eye just by watching the way it defended an attack.\"}','{\"Description\": \"A kunoichi who appears in the second Naruto Shippūden filler arc. She is the female leader of Orochimaru\'s subordinates. She uses the unique Crystal Release brand of jutsu.\", \"Description_2\": \"As a child, Guren came from an unknown small village where she was shunned by others because she had unique powers. Later, Orochimaru appeared and destroyed the entire village single-handedly. He was intrigued by Guren\'s powers and offered for her to come with him. Guren chose to follow him because she envied his power. Quickly, she became one of Orochimaru\'s most powerful and loyal subordinates. Eventually, she was offered to become one of Orochimaru\'s future vessels. Guren would also later know that the Nine-Tailed Demon Fox, the mightiest of the Tailed Beasts, had ultimately came into the possesion of the Hidden Leaf Village following the events where the Fourth Hokage sealed it into his recently-born son, but due to the extreme secrecy held within that Village regarding this matter, like everybody else outside of Konoha, Guren was left oblivious about the identity of the powerful demon\'s container, Naruto Uzumaki, whom she would later encounter, instead coming to the conclusion that the Nine-Tails capture was for the sake of augmenting the Hidden Leafs military power. When Sasuke Uchiha defected from Konohagakure and Kimimaro was no longer a suitable vessel for Orochimaru, Guren became the next best choice in Orochimaru\'s eyes. Unfortunately by the time she arrived, Orochimaru couldn\'t wait any longer and instead chose Gen\'yumaru. Feeling no longer of use to Orochimaru, Guren went into isolation. It is later revealed that she in fact killed Yūkimaru\'s mother.\", \"Description_3\": \"Guren has shown to be very mysterious, apparently preferring to keep to herself despite having a strong loyalty to Orochimaru. During her introduction, she quickly showed herself to be a remorseless and sadistic person. When told by Kabuto that several prisoners would be fighting to the death, she became ecstatic to hear there would be a slaughter. Guren is also shown to be vain by the fact that when she used her Jade Crystal Mirror technique, she looked at her self and said \\\"Lovely, as always.\\\" She has also shown to be very proud. When Naruto offered to carry her she was embarrassed because it was shameful.\", \"Description_4\": \"She is devotedly loyal to Orochimaru, to an almost obsessive state. This devotion was so powerful that she fell into despair when she learned she would not become Orochimaru\'s next vessel, isolating herself from the shame. It has also been shown she has a terrible relationship with Kabuto, as the two argue often, trading scathing remarks.[1] Later, she meets Yūkimaru, and at first, she finds him peculiar and somewhat irritating. When Yūkimaru became ill, she cared for him, watching over him for an entire night, until she fell asleep from exhaustion. When she woke up, she found that she was alone--and went searching for Yūkimaru, who she found a little ways outside under a camellia tree. She then develops a sort of friendship with him as she crystallizes a beautiful flower and gently tells him that the flower will never wither as long as she is alive. He tells her that he lost his mother in similar circumstances while going out to find him a red camellia. Guren later comes across a red camellia patch, where she seems prompted to bring him one.\", \"Description_5\": \"Since coming in contact with Yūkimaru, Guren seems to be having conflicting emotions. While part of her still wants to be accepted by Orochimaru as his next vessel, another part of her seems unable to let go of the bond she has made with Yūkimaru to the point of protecting from even Orochimaru\'s right-hand man, Kabuto. The emotions seemed to have become more confusing for her in her first one-on-one confrontation with Naruto, who stated bluntly how horrible and selfish a man Orochimaru really is.\", \"Description_6\": \"After realizing the truth behind her past and how it connects her to Yūkimaru, Guren feels even more compelled to protect him, out of guilt and repentance for her past sins, as well as love--wishing to become an almost \'surrogate mother\' to the boy, to replace the mother she killed. She even goes so far as to turn her protection to Naruto, as they faced off against the small Three-Tails clones within the tailed beast\'s stomach, telling him she would protect him to the death if he would watch after Yūkimaru. This is a great change from her previous interactions with Naruto, where she was stand-offish and combative. Subsequently, Guren has also begun to have doubts over remaining loyal to Orochimaru, due to her grief over the horrible things she was made to do in his name, and the damage and pain he has caused Yūkimaru, and herself.\", \"Description_7\": \"Three-Tails Arrival arc\", \"Description_8\": \"Guren, disapproving of Sasuke\'s status as Orochimaru\'s next vessel, is later offered a chance to replace Sasuke if she can prove herself. She and Yūkimaru are sent to a certain area. While there, Yūkimaru gets sick, forcing Guren to care for him. When he recovers, she is surprised to learn he too knows what it is like to have no one at such a young age and seems to have grown some feelings for him. She then crystallizes one of his flowers, knowing how much he likes them, so it won\'t wither as long as she is alive. Later when finally meeting back up Team Guren, she leaves Yūkimaru at the hideout while she goes out to handle the Team Kurenai.\", \"Description_9\": \"While her men fight Team Kurenai and Kakashi, Guren prepares for their arrival. Once done she has her men fall back, drawing the Konoha ninja into a trap and allowing Guren to encase Hinata in crystal. She uses Hinata as a hostage to prevent her men from being followed. Before anything can be done, Team Yamato arrives and breaks through her traps and defenses and subsequently frees Hinata. Annoyed at her enemies escaping, she decides goes back to their hideout to plan their next move, but Kabuto comes in and explains another plan.\", \"Description_10\": \"Kabuto, Guren, and her men go out to the lake so that they can awaken the Three-Tailed Beast. When it appears she tries to restrain it, but proves no match for its strength, the whole time holding Yūkimaru in a protective hug. When she uses the last of her chakra to save Yūkimaru and the others, she later awakens to find herself in the care of Yūkimaru.\", \"Description_11\": \"Guren then finds herself having a dream about the her childhood with Orochimaru and dreams about a woman. After she awakes, she finds that Yūkimaru is sick again, speculating that it was because of Kabuto\'s overdose of pills. While taking care of Yūkimaru, she detects Naruto coming and intercepts him. After a short scuffle, Yūkimaru appears to stop the fight. It is here that Guren hears another view of Orochimaru from Naruto, making her question the path she has taken.\", \"Description_12\": \"After escaping with Yūkimaru, she and her team begins preparing for the final confrontation with the Leaf Village and hoping to face Naruto again to settle things with him. Upon facing the Leaf Ninja again, her Crystal Release again proves to be very powerful. Unfortunately for her, Shino\'s insects finally build up a strong enough resistance to make her powers useless. Although nearly perishing against her opponents, Gozu sacrifices himself to allow her to escape. Before escaping, however, Naruto made it clear to Guren that he\'s determined to take Yūkimaru away from her no matter what. At first confused at why the younger shinobi could possibly be interested in Yūkimaru, Guren quickly rallies up and came to the conclusion that the Hidden Leaf shinobi became aware of Yūkimaru\'s powers, and are striving to obtain the boy in order to reign control over the Three-Tails\", \"Description_13\": \"While returning to the hideout, she hears Yūkimaru play with a grasswhistle and perform a melody she remembers. She then realizes to her horror that it was her who killed Yūkimaru\'s mother. Upon the revelation, Guren begged Kabuto to not put Yūkimaru through anymore pain, instead offering her own services to stop the Leaf Ninja from sealing away the Three-Tails. With the help of Rinji, Guren was able to stop the seal. Unfortunately, the Three-Tails then turned its attention to Guren. Luckily, Yūkimaru was able to save her by using his powers to stop the Three-Tails.\", \"Description_14\": \"Guren recalls her second encounter with Yūkimaru\'s mother\", \"Description_15\": \"After seeing how desperate Yūkimaru was to protect her, Guren\'s guilt towards the boy became greater than ever, knowing that the boy was clinging to the person who had killed his mother. Deciding to atone for her crimes to Yūkimaru, Guren chose to do everything in her power to protect him. Despite being battle-worn and low on chakra, Guren attacked the Three-Tails head-on. Fortunately, Naruto soon appeared the and the two grudgingly worked together to battle the beast. Ultimately, the Three-Tails managed to capture and swallow the two whole.\", \"Description_16\": \"Inside the beast, Guren is surprised to see Naruto there as well. She tries to attack him, but the injury she sustained earlier caused her to pass out; when she came about, she became even more surprised that Naruto without hesistation treated her wounds. The two quickly begin arguing about where Yūkimaru belongs. Guren states bluntly that she refused to let Yūkimaru succumb to any harm. When Naruto accuses Guren of using Yūkimaru\'s abilities for Orochimaru\'s benefit, Guren retaliates that the Leaf Village being barely any different, only interested in obtaining more demons to create more Jinchūriki, now that they\'ve learned of Yūkimaru\'s ability to tame the Three-Tails. Naruto quickly replied that his Village had no interest in the Tailed Beast itself, Guren calls him a liar, apparently aware that the Hidden Village already owns the host for the Nine-Tailed Fox. Naruto stops her train of thought by revealing that he is that very Jinchūriki, but one whom, for most of his life, his own Village did not treat as a proper being (much less their ultimate weapon), but rather, a living memory of the horrific catastrophe that the Tailed Beast which now resides within himself once wreaked upon the Hidden Leaf. Upon learning that Naruto refuses to use his demon powers in fear of hurting his loved ones, she begins to see that Naruto genuinely is concerned for Yūkimaru\'s well-being. Together, the two begin looking for a way out of the Three-Tails.\", \"Description_17\": \"As they found themselves being cornered by the mini-Three-Tails, Guren felt compelled to admit to Naruto her hand in causing Yūkimaru\'s loneliness. After revealing the truth, she decides that Naruto is right, that Yūkimaru\'s place should not be with Orochimaru nor her, but with Naruto. Her sincerity towards this statement is proven by her desire to make sure Naruto gets out alive. To her surprise however, Naruto says she has changed and can make up for her mistakes. Together, they manage to escape the Three-Tails. Unfortunately upon escaping, they discover that Yūkimaru is again being used to control the Three-Tails.\", \"Description_18\": \"Along the way, Guren has doubts about revealing the truth to Yūkimaru, but Naruto convinces her to prove her sincerity of protecting Yūkimaru even if refuses to forgive her. Being inspired by this, she and Naruto arrive in time to save Yūkimaru from being forced to take a strange drug from Rinji, who turns out to be Kabuto in disguise. Kabuto decides to reveal the truth to Yūkimaru, to which Guren makes no attempt to stop. To her shock and joy, Yūkimaru decides to forgive her. The two then admit to how much they mean to each other. Guren leaves with Yūkimaru under Naruto\'s orders, and Kabuto summoned the deceased Rinji with his reincarnation jutsu, and Guren battles him in an attempt to protect Yūkimaru. Taking no chances, she used her signature Crimson Fruit jutsu to keep him safe. Guren tried to trap Rinji in her Crystal Jutsu, but he used his bats\' supersonic abilities to shatter the crystal, saving himself and subsequently stopping Guren from using her Crystal Style. Devoted to protect Yūkimaru with her life, she went behind Rinji and kept his hands apart, to now prevent HIM from using jutsu and controlling the bats. Though unable to perform any hand signs (with her hands busy holding back Rinji\'s arms), Guren still managed to use the Crystal Style and crystallize herself and Rinji. The two fell into the water below. Gozu later saves her. Yūkimaru later joined up with them, and the three of them left together.\", \"Description_19\": \"Abilities\", \"Description_20\": \"Guren possesses a unique ninja art; the Crystal Release. It is not clear that it is a kekkei genkai or a power unique to her, also Guren made it clear to Kakashi that he cannot copy her techniques with the Sharingan. By using this power, Guren can summon and manipulate crystal in a number of ways such as creating crushing walls or unique shuriken. It is stated by Kabuto and by Kakashi that she can crystallize moisture in the air, therefore giving her an infinite source of weapons. The density of this power appears to be very high as even the Wood Release was unable to penetrate it. This ability is presumed very powerful as Orochimaru at one point desired it for himself.\", \"Description_21\": \"Guren uses her crystal style\", \"Description_22\": \"In times of desperation, Guren is also able to convert a small portion of her life energy to access extra chakra reserves to allow her to continue fighting at full strength for a short period of time.\", \"Description_23\": \"Guren\'s taijutsu skills are also rather high as she was able to fight on even grounds with an expert like Kakashi, dodge multiple Rasengan attacks from Naruto, and fight Lee and Tenten simultaneously. She is talented at noticing weaknesses in her opponent and using diversions, shown in how she kept the rest of Team 8 busy fighting her clones while she takes Hinata as hostage. After that she is seen to tell Naruto what she feels about Yūkimaru. In addition, Guren also has good senses and is a keen observer. She was able to tell when Kakashi and Yamato were near and she was able to conclude that the Sanbi was trying to protect it\'s eye just by watching the way it defended an attack.\", \"To aid him in final preparations for his plan, Orochimaru sends Kabuto to fetch Guren (much to Kabuto\'s disapproval). Guren attacks him when he approaches her domain, but he is able to avoid her attacks. When asked why she attacked him, Guren states that she just wanted to make sure Kabuto was worthy of being Orochimaru\'s right-hand man. Upon returning to Orochimaru\'s hideout, she has hundreds of Orochimaru\'s prisoners fight to the death and forms a team with the survivors\": \"Rinji, Gozu, Kigiri, Kihō and Nurari.\"}'),(98,280884,'Guruguru','{}','{}'),(99,23569,'Guruko','{\"Description\":\"Kakashi\\u0027s ninken.\"}','{\"Description\": \"Kakashi\'s ninken.\"}'),(100,55293,'Gyuuki','{\"Description\":\"The Eight-Tails is a tailed beast sealed within Killer B of Kumogakure after his cousin, cousin\\u0027s uncle and cousin\\u0027s father failed before him.\",\"Description_2\":\"Since Killer B is one of the few jinch\\u016Briki to gain control over his tailed beast, his relationship with the Eight-Tails is very relaxed. Where the Nine-Tailed Demon Fox constantly threatens its jinch\\u016Briki and must be either restrained or confined to be spoken to, B and the Eight-Tails can talk leisurely, with Killer B even sitting on its nose. However, B tends to annoy the Eight-Tails to comical effect; his serious and no-nonsense demeanour often contrasts with B\\u0027s tendency to goof off whenever he likes, adding fuel to the Tailed Beast\\u0027s irritation to his vessel. The Eight-Tails is not above bad-mouthing B as a result. The Eight-Tails is also known to scold him in serious occasions as shown when it criticised B for rapping in his fight with Kisame when he should have been completely focused on their opponent. Because of this, the Eight-Tails appears to be much more note worthy than B as far as responsibility is concerned. Before B learned to control it, the Eight-Tails was infamous to be wild, and violent. It also went on many rampages whenever its former jinch\\u016Briki would lose control of it.\",\"Description_3\":\"Despite the Eight-Tails\\u0027 strong relationship with Killer B, its main goal, like the other beasts, is self preservation. For example, it was more than willing to be released and attack Kisame Hoshigaki despite Sabu and Ponta being close by. The Eight-Tails is also shown to have a good analytical ability, as it told Killer B that if he left Ponta and Sabu and run in the opposite direction Kisame and the water will follow him and they (Sabu and Ponta) would be freed. The Eight-Tails mentioned that it used to be much more aggressive and violent but that Killer B changed it. It also said that it doesn\\u0027t like the Nine-Tails but insisted that was no reason for B to refuse to help Naruto take control of the beast, hinting a benevolent side. Since then, both the beast and B have taken a liking to Naruto. The Eight-Tails also tends to reprimand B. This is usually shown in a comical manner as when it bumped B in the head when the latter started to mention in a perverted matter how Yugito\\u0027s chakra receivers where embedded in her left breast.\",\"Description_4\":\"With regards to its relationship with the other tailed beasts, the Eight-Tails maintaining that they had their own emotions and personalities has expressed dislike of the Nine-Tails\\u0027 habit of ranking their strength based on their number of tails and has also stated that seeing another beast being forcefully controlled angered the rest of them greatly.\"}','{\"Description\": \"The Eight-Tails is a tailed beast sealed within Killer B of Kumogakure after his cousin, cousin\'s uncle and cousin\'s father failed before him.\", \"Description_2\": \"Since Killer B is one of the few jinchūriki to gain control over his tailed beast, his relationship with the Eight-Tails is very relaxed. Where the Nine-Tailed Demon Fox constantly threatens its jinchūriki and must be either restrained or confined to be spoken to, B and the Eight-Tails can talk leisurely, with Killer B even sitting on its nose. However, B tends to annoy the Eight-Tails to comical effect; his serious and no-nonsense demeanour often contrasts with B\'s tendency to goof off whenever he likes, adding fuel to the Tailed Beast\'s irritation to his vessel. The Eight-Tails is not above bad-mouthing B as a result. The Eight-Tails is also known to scold him in serious occasions as shown when it criticised B for rapping in his fight with Kisame when he should have been completely focused on their opponent. Because of this, the Eight-Tails appears to be much more note worthy than B as far as responsibility is concerned. Before B learned to control it, the Eight-Tails was infamous to be wild, and violent. It also went on many rampages whenever its former jinchūriki would lose control of it.\", \"Description_3\": \"Despite the Eight-Tails\' strong relationship with Killer B, its main goal, like the other beasts, is self preservation. For example, it was more than willing to be released and attack Kisame Hoshigaki despite Sabu and Ponta being close by. The Eight-Tails is also shown to have a good analytical ability, as it told Killer B that if he left Ponta and Sabu and run in the opposite direction Kisame and the water will follow him and they (Sabu and Ponta) would be freed. The Eight-Tails mentioned that it used to be much more aggressive and violent but that Killer B changed it. It also said that it doesn\'t like the Nine-Tails but insisted that was no reason for B to refuse to help Naruto take control of the beast, hinting a benevolent side. Since then, both the beast and B have taken a liking to Naruto. The Eight-Tails also tends to reprimand B. This is usually shown in a comical manner as when it bumped B in the head when the latter started to mention in a perverted matter how Yugito\'s chakra receivers where embedded in her left breast.\", \"Description_4\": \"With regards to its relationship with the other tailed beasts, the Eight-Tails maintaining that they had their own emotions and personalities has expressed dislike of the Nine-Tails\' habit of ranking their strength based on their number of tails and has also stated that seeing another beast being forcefully controlled angered the rest of them greatly.\"}'),(101,16304,'Hagane, Kotetsu','{\"Birthday\":\"July 21\",\"Description\":\"Kotetsu Hagane is a Chunin from Konohagakure. He spends most of the time with his partner Izumo Kamizuki watching who enters and leaves at Konohagakure\\u0027s Main Gate.\"}','{\"Birthday\": \"July 21\", \"Description\": \"Kotetsu Hagane is a Chunin from Konohagakure. He spends most of the time with his partner Izumo Kamizuki watching who enters and leaves at Konohagakure\'s Main Gate.\"}'),(102,2039,'Haku','{\"Description\":\"The Country of Mist has had its share of civil wars and has always used their Shinobi with Advanced Bloodlines as the primary weapons. Over time, those with \\u0022Advanced Blood\\u0022 came to be hated and feared. This forced those with advanced bloods into hiding in order to live in peace. Haku was one of the few people in the Mist with Advanced Blood left.\",\"When Haku was just a young child, his father discovered that his wife was part of an Advanced Bloodline. Haku\\u0027s father proceeded to kill his mother and then went after him. In Haku\\u0027s fright, he killed his father and fled his small village, believing himself to be a monster\":\"a monster loved by no one.\",\"Description_2\":\"On one faithful day, Haku looked up in the slums of the back alley to see a Shinobi staring down at him, this Shinobi was Zabuza. Haku then proclaimed, \\u0022You have the same eyes as me\\u0022. Zabuza realized that Haku was one of the Advanced Bloodline limit carriers, and took the child under his wing. Haku was raised by Zabuza as \\u0022a tool\\u0022 to be called upon when needed in exchange for his \\u0022freedom\\u0022 from the slums. He learned how to use his unique abilities and eventually became a Hunter-Nin. When Zabuza\\u0027s plan to kill Mizukage fails, Haku fled the village along with Zabuza to fulfill his job as a veritable \\u0022a tool.\\u0022\",\"Description_3\":\"Haku\\u0027s slender frame and delicate appearance enables him to disguise himself in various ways. In fact, while finding medicine to treat Zabuza\\u0027s wounds Haku runs into Naruto. Naruto mistakenly believes Haku is a girl. As we see in the ensuing brawls, it is not appearance that determines strength. Rather, under that soft face we see that Haku has an adroit knack for speed and Jutsu skill. Combined with his knowledge of the human body, Haku can target his opponent\\u0027s vital organs and kill them instantly using pinpoint accuracy. The main choice to attack these vital organs is with simple needles that are used by physicians in the battle field.\",\"Description_4\":\"Haku\\u0027s bloodline originates in the country of Mist so it is no surprise that his Jutsus are water based. His \\u0022Flying Water Needles\\u0022 is a technique whence he uses his chakra to create ice needles via water on the ground. Furthermore, he uses his chakra to control the path of the needles and strike the enemy. His other technique, \\u0022Demonic Ice Mirrors\\u0022 uses water to create ice mirrors to surround the enemy. He then combines himself with the mirrors and uses the reflection to transport himself from mirror to mirror while attacking his enemy from all angles. His most incredible ability however, is the ability to do one-handed seals. This allows him to complete various tasks that are not capable of being accomplished without having a free hand.\",\"Description_5\":\"Although Haku is an exceptional fighter, he is a kind ninja who is saddened by unnecessary death. His fighting spirit comes from the will to protect his most \\u0022precious person,\\u0022 because \\u0022when a person has something precious to protect, that is when they can become truly strong.\\u0022\"}','{\"Description\": \"The Country of Mist has had its share of civil wars and has always used their Shinobi with Advanced Bloodlines as the primary weapons. Over time, those with \\\"Advanced Blood\\\" came to be hated and feared. This forced those with advanced bloods into hiding in order to live in peace. Haku was one of the few people in the Mist with Advanced Blood left.\", \"Description_2\": \"On one faithful day, Haku looked up in the slums of the back alley to see a Shinobi staring down at him, this Shinobi was Zabuza. Haku then proclaimed, \\\"You have the same eyes as me\\\". Zabuza realized that Haku was one of the Advanced Bloodline limit carriers, and took the child under his wing. Haku was raised by Zabuza as \\\"a tool\\\" to be called upon when needed in exchange for his \\\"freedom\\\" from the slums. He learned how to use his unique abilities and eventually became a Hunter-Nin. When Zabuza\'s plan to kill Mizukage fails, Haku fled the village along with Zabuza to fulfill his job as a veritable \\\"a tool.\\\"\", \"Description_3\": \"Haku\'s slender frame and delicate appearance enables him to disguise himself in various ways. In fact, while finding medicine to treat Zabuza\'s wounds Haku runs into Naruto. Naruto mistakenly believes Haku is a girl. As we see in the ensuing brawls, it is not appearance that determines strength. Rather, under that soft face we see that Haku has an adroit knack for speed and Jutsu skill. Combined with his knowledge of the human body, Haku can target his opponent\'s vital organs and kill them instantly using pinpoint accuracy. The main choice to attack these vital organs is with simple needles that are used by physicians in the battle field.\", \"Description_4\": \"Haku\'s bloodline originates in the country of Mist so it is no surprise that his Jutsus are water based. His \\\"Flying Water Needles\\\" is a technique whence he uses his chakra to create ice needles via water on the ground. Furthermore, he uses his chakra to control the path of the needles and strike the enemy. His other technique, \\\"Demonic Ice Mirrors\\\" uses water to create ice mirrors to surround the enemy. He then combines himself with the mirrors and uses the reflection to transport himself from mirror to mirror while attacking his enemy from all angles. His most incredible ability however, is the ability to do one-handed seals. This allows him to complete various tasks that are not capable of being accomplished without having a free hand.\", \"Description_5\": \"Although Haku is an exceptional fighter, he is a kind ninja who is saddened by unnecessary death. His fighting spirit comes from the will to protect his most \\\"precious person,\\\" because \\\"when a person has something precious to protect, that is when they can become truly strong.\\\"\", \"When Haku was just a young child, his father discovered that his wife was part of an Advanced Bloodline. Haku\'s father proceeded to kill his mother and then went after him. In Haku\'s fright, he killed his father and fled his small village, believing himself to be a monster\": \"a monster loved by no one.\"}'),(103,23223,'Han','{\"Description\":\"Han (\\u30CF\\u30F3) was a shinobi from Iwagakure and was the host of the Five-Tailed Beast, as well as the physically largest jinchuuriki, easily standing a head taller than Kirabii. The Five-Tails has been captured and sealed by Akatsuki, causing this jinchuuriki\\u0027s death when the beast was extracted. Another jinchuuriki, named Roushi, who held the Four-Tailed Beast, also originated from Iwagakure. It is logical to assume that he and Roushi knew each other as they were both jinchuuriki of the same village.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Han (ハン) was a shinobi from Iwagakure and was the host of the Five-Tailed Beast, as well as the physically largest jinchuuriki, easily standing a head taller than Kirabii. The Five-Tails has been captured and sealed by Akatsuki, causing this jinchuuriki\'s death when the beast was extracted. Another jinchuuriki, named Roushi, who held the Four-Tailed Beast, also originated from Iwagakure. It is logical to assume that he and Roushi knew each other as they were both jinchuuriki of the same village.\"}'),(104,40418,'Hanare','{\"Description\":\"Hanare is a kunoichi from the J\\u014Dmae Village. She was an orphan who longed to see her parents and find a home she could call her own.\",\"Description_2\":\"As a young child, Hanare was said to be very lonely since she never knew her family or seen her own village. She was trained from an early age in the art of espionage. One day, she was found crying in a place near her village by the young Kakashi, who spotted her and carried her on his back. He then explained to her that she can look up to the clouds above and find her way. They both then were seen by a ninja from Hanare\\u0027s village and Kakashi put her down on her feet, said goodbye and left. She was then excited that someone like Kakashi was able to help her in her life.\",\"Description_3\":\"Hanare\\u0027s abilities allow her to read someone\\u0027s mind by using her right eye to literally look into it. She is even able to use this ability on those who are looking at her thoughts. She can also erase all of her thoughts that she had gathered. To use this technique, she weaves signs by moving her eye in specific patterns. Hanare\\u0027s special technique can help her in collecting and gathering information in various things.\",\"Description_4\":\"She has also been trained to have an immensely strong will, unyielding to seemingly any form of torture, even by the likes of Ibiki Morino, a master manipulator of the human psyche.\"}','{\"Description\": \"Hanare is a kunoichi from the Jōmae Village. She was an orphan who longed to see her parents and find a home she could call her own.\", \"Description_2\": \"As a young child, Hanare was said to be very lonely since she never knew her family or seen her own village. She was trained from an early age in the art of espionage. One day, she was found crying in a place near her village by the young Kakashi, who spotted her and carried her on his back. He then explained to her that she can look up to the clouds above and find her way. They both then were seen by a ninja from Hanare\'s village and Kakashi put her down on her feet, said goodbye and left. She was then excited that someone like Kakashi was able to help her in her life.\", \"Description_3\": \"Hanare\'s abilities allow her to read someone\'s mind by using her right eye to literally look into it. She is even able to use this ability on those who are looking at her thoughts. She can also erase all of her thoughts that she had gathered. To use this technique, she weaves signs by moving her eye in specific patterns. Hanare\'s special technique can help her in collecting and gathering information in various things.\", \"Description_4\": \"She has also been trained to have an immensely strong will, unyielding to seemingly any form of torture, even by the likes of Ibiki Morino, a master manipulator of the human psyche.\"}'),(105,23055,'Hanzou','{\"Description\":\"Hanzou (\\u534A\\u8535) also known as Hanzou of the Salamander (\\u5C71\\u6912\\u9B5A\\u306E\\u534A\\u8535, Sanshouuo no Hanzou) was a legendary ninja who was the former leader of Amegakure. He was very security-conscious, being guarded twenty-four hours a day and having anyone who wanted to see him thoroughly searched. He became famous around the time of the Second Great Ninja War. Little is known of his abilities aside from his riding on the head of a giant salamander (presumably a summon), but he was so powerful that he with his summon fought off all three Sannin. After their battle, he was so impressed with their strength that he decided to leave them if they agreed to accept the title of Konoha\\u0027s Legendary Three Ninja (\\u4F1D\\u8AAC\\u306E\\u4E09\\u5FCD, Densetsu no Sannin); This makes him responsible for the naming of the trio\\u0027s title. Being capable of defeating all the three Sannin head-on, Hanzou is easily a kage-level ninja. His power was such that Jiraiya expressed intense shock upon hearing that Hanzou had been defeated by Pain.\",\"Description_2\":\"Hanzou\\u0027s insecurities later got the better of him when a group of ninja, lead by Yahiko, Nagato, and Konan began a quest to end war through unorthodox means. He viewed these ninja as a threat to his power and sought to get rid of them. He then teamed up with the ANBU Root\\u0027s leader Danz\\u014D to kill the group\\u0027s leader Yahiko in a treacherous manner. He was later single-handedly killed by Pain (under unknown circumstances). The hatred that Nagato had for him for causing Yahiko\\u0027s death was so severe that he conducted a systematic genocide on anybody even remotely associated with Hanzou (with the exception of Danzou, who somehow escaped the carnage).\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Hanzou (半蔵) also known as Hanzou of the Salamander (山椒魚の半蔵, Sanshouuo no Hanzou) was a legendary ninja who was the former leader of Amegakure. He was very security-conscious, being guarded twenty-four hours a day and having anyone who wanted to see him thoroughly searched. He became famous around the time of the Second Great Ninja War. Little is known of his abilities aside from his riding on the head of a giant salamander (presumably a summon), but he was so powerful that he with his summon fought off all three Sannin. After their battle, he was so impressed with their strength that he decided to leave them if they agreed to accept the title of Konoha\'s Legendary Three Ninja (伝説の三忍, Densetsu no Sannin); This makes him responsible for the naming of the trio\'s title. Being capable of defeating all the three Sannin head-on, Hanzou is easily a kage-level ninja. His power was such that Jiraiya expressed intense shock upon hearing that Hanzou had been defeated by Pain.\", \"Description_2\": \"Hanzou\'s insecurities later got the better of him when a group of ninja, lead by Yahiko, Nagato, and Konan began a quest to end war through unorthodox means. He viewed these ninja as a threat to his power and sought to get rid of them. He then teamed up with the ANBU Root\'s leader Danzō to kill the group\'s leader Yahiko in a treacherous manner. He was later single-handedly killed by Pain (under unknown circumstances). The hatred that Nagato had for him for causing Yahiko\'s death was so severe that he conducted a systematic genocide on anybody even remotely associated with Hanzou (with the exception of Danzou, who somehow escaped the carnage).\"}'),(106,67289,'Haruno, Mebuki','{\"Description\":\"Mebuki Haruno (\\u6625\\u91CE\\u30E1\\u30D6\\u30AD, Haruno Mebuki) is a kunoichi of Konohagakure and the wife of Kizashi and mother of Sakura Haruno.\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #271\",\"Movie Debut\":\"Naruto: Shippuuden Movie 6 - Road to Ninja\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #271\", \"Description\": \"Mebuki Haruno (春野メブキ, Haruno Mebuki) is a kunoichi of Konohagakure and the wife of Kizashi and mother of Sakura Haruno.\", \"Movie Debut\": \"Naruto: Shippuuden Movie 6 - Road to Ninja\"}'),(107,67287,'Haruno, Kizashi','{\"Description\":\"Kizashi Haruno (\\u6625\\u91CE\\u30AD\\u30B6\\u30B7, Haruno Kizashi) is a shinobi of Konohagakure and the husband of Mebuki and father of Sakura Haruno.\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #271\",\"Movie Debut\":\"Naruto: Shippuuden Movie 6 - Road to Ninja\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #271\", \"Description\": \"Kizashi Haruno (春野キザシ, Haruno Kizashi) is a shinobi of Konohagakure and the husband of Mebuki and father of Sakura Haruno.\", \"Movie Debut\": \"Naruto: Shippuuden Movie 6 - Road to Ninja\"}'),(108,31268,'Harusame','{\"Description\":\"Harusame was the former master of Utakata.\",\"Description_2\":\"He was once Utakata\\u0027s master and he had trusted him until Harusame tried to remove the Six-Tailed Slug from his body which resulted in Utakata transforming into the Six-Tails and killing him. Since then, Utakata has held a great grudge against Harusame and made him think a student and master bond is not something to be counted on. Tsurugi states that Harusame tried to remove the Six-Tails to save Utakata, but Utakata believes otherwise.\",\"(source\":\"narutopedia)\"}','{\"(source\": \"narutopedia)\", \"Description\": \"Harusame was the former master of Utakata.\", \"Description_2\": \"He was once Utakata\'s master and he had trusted him until Harusame tried to remove the Six-Tailed Slug from his body which resulted in Utakata transforming into the Six-Tails and killing him. Since then, Utakata has held a great grudge against Harusame and made him think a student and master bond is not something to be counted on. Tsurugi states that Harusame tried to remove the Six-Tails to save Utakata, but Utakata believes otherwise.\"}'),(109,20894,'Hatake, Sakumo','{\"Description\":\"Hatake Sakumo is the father of Hatake Kakashi. He is also known as Konoha\\u0027s White Fang, Sakumo  and in his time, his powers were said to surpass those of the Sannin.\"}','{\"Description\": \"Hatake Sakumo is the father of Hatake Kakashi. He is also known as Konoha\'s White Fang, Sakumo  and in his time, his powers were said to surpass those of the Sannin.\"}'),(110,97797,'Heiji','{\"Description\":\"Heiji (\\u30D8\\u30A4\\u30B8, Heiji), also known as Heiji of the Rain Shelter (\\u96E8\\u5BBF\\u308A\\u306E\\u30D8\\u30A4\\u30B8, Amayadori no Heiji), was a shinobi from Amegakure as well as the right-hand man of Kandachi.\",\"Description_2\":\"Heiji was a subordinate in Hanz\\u014D\\u0027s regime and the right hand of Kandachi who was the right hand of Hanz\\u014D. At some point he was killed within the walls of Amegakure. Some time later, he was accidentally reincarnated by Kabuto Yakushi who was looking for Hanz\\u014D instead.\",\"Description_3\":\"During the Fourth Shinobi World War, Kabuto deployed Heiji, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. During a scuffle between Kabuto\\u0027s weaker pawns and the Allied Shinobi Forces, Heiji created a smokescreen diversion so some of the reincarnated shinobi could escape. Afterwards, he was cornered by the Fourth Division and sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\",\"Anime Debut\":\"Naruto Shippuuden Episode #316\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #316\", \"Description\": \"Heiji (ヘイジ, Heiji), also known as Heiji of the Rain Shelter (雨宿りのヘイジ, Amayadori no Heiji), was a shinobi from Amegakure as well as the right-hand man of Kandachi.\", \"Description_2\": \"Heiji was a subordinate in Hanzō\'s regime and the right hand of Kandachi who was the right hand of Hanzō. At some point he was killed within the walls of Amegakure. Some time later, he was accidentally reincarnated by Kabuto Yakushi who was looking for Hanzō instead.\", \"Description_3\": \"During the Fourth Shinobi World War, Kabuto deployed Heiji, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. During a scuffle between Kabuto\'s weaker pawns and the Allied Shinobi Forces, Heiji created a smokescreen diversion so some of the reincarnated shinobi could escape. Afterwards, he was cornered by the Fourth Division and sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\"}'),(111,50555,'Hibachi','{\"Description\":\"Hibachi was a student at the Ninja Academy, assigned to Iruka Umino\\u0027s class.\",\"Description_2\":\"Hibachi picked on Naruto when he failed to perform the Clone Technique but was stopped by Iruka, saying not to bother with a kid like him.\",\"(Source\":\"naruto.wikia (Narutopedia))\"}','{\"(Source\": \"naruto.wikia (Narutopedia))\", \"Description\": \"Hibachi was a student at the Ninja Academy, assigned to Iruka Umino\'s class.\", \"Description_2\": \"Hibachi picked on Naruto when he failed to perform the Clone Technique but was stopped by Iruka, saying not to bother with a kid like him.\"}'),(112,2792,'Hidan','{\"Age\":\"22 on surface, though immortal.\",\"From\":\"Yugakure, the Village Hidden in the Steam\",\"Weapon\":\"3-headed Scythe\",\"Partner\":\"Kakuzu\",\"Religion\":\"Jashin-ism\",\"Description\":\"Because he is a member of the Jashin religion, Hidan has immortality. This immortality will end, however, if he does not regularly sacrifice people to Jashin. This is a religion that worships a deity of the same name and where anything less than death and utter destruction is considered a sin. His religion\\u0027s experiments have led to the creation of his unique abilities; by consuming an opponent\\u0027s blood and then drawing Jashin\\u0027s triangular-design on the ground, Hidan can create a voodoo doll-like link with his opponent. Once this link is created, any damage done to Hidan\\u0027s body is reflected on his opponent, allowing him to kill them by giving himself fatal injuries. Because he is immortal, Hidan is not impaired while doing this, instead finding pleasure in the pain it causes him.\",\"Description_2\":\"Hidan is sadistic, arrogant, rude, and impatient. All qualities which his partner, Kakuzu, finds annoying. He and his partner, Kakuzu, fight and argue constantly, so it might be a wonder why they are put on the same team.  Kakuzu actually commented that he and Hidan made the perfect team, because even thought Kakuzu has the urge to kill Hidan often, he is unable to due to his partner\\u0027s immortality. Because Kakuzu is considered immortal as well, their own fellow Akatsuki member, Kisame Hoshigake, jokingly referred to the team as the \\u0022Zombi Combi\\u0022.  Hidan likes to annoy the other members of the Akatsuki, and even refers to them by insulting nicknames, such as \\u0022Dei-chan\\u0022. He dislikes Pain\\u0027s authority over him and openly challenges him in front of others. Hidan\\u0027s aggressiveness is the reason he left his village, where he was frustrated by the peace and lack of violence, before leaving he slaughtered many of his neighbours in cold-blood for entertainment.\"}','{\"Age\": \"22 on surface, though immortal.\", \"From\": \"Yugakure, the Village Hidden in the Steam\", \"Weapon\": \"3-headed Scythe\", \"Partner\": \"Kakuzu\", \"Religion\": \"Jashin-ism\", \"Description\": \"Because he is a member of the Jashin religion, Hidan has immortality. This immortality will end, however, if he does not regularly sacrifice people to Jashin. This is a religion that worships a deity of the same name and where anything less than death and utter destruction is considered a sin. His religion\'s experiments have led to the creation of his unique abilities; by consuming an opponent\'s blood and then drawing Jashin\'s triangular-design on the ground, Hidan can create a voodoo doll-like link with his opponent. Once this link is created, any damage done to Hidan\'s body is reflected on his opponent, allowing him to kill them by giving himself fatal injuries. Because he is immortal, Hidan is not impaired while doing this, instead finding pleasure in the pain it causes him.\", \"Description_2\": \"Hidan is sadistic, arrogant, rude, and impatient. All qualities which his partner, Kakuzu, finds annoying. He and his partner, Kakuzu, fight and argue constantly, so it might be a wonder why they are put on the same team.  Kakuzu actually commented that he and Hidan made the perfect team, because even thought Kakuzu has the urge to kill Hidan often, he is unable to due to his partner\'s immortality. Because Kakuzu is considered immortal as well, their own fellow Akatsuki member, Kisame Hoshigake, jokingly referred to the team as the \\\"Zombi Combi\\\".  Hidan likes to annoy the other members of the Akatsuki, and even refers to them by insulting nicknames, such as \\\"Dei-chan\\\". He dislikes Pain\'s authority over him and openly challenges him in front of others. Hidan\'s aggressiveness is the reason he left his village, where he was frustrated by the peace and lack of violence, before leaving he slaughtered many of his neighbours in cold-blood for entertainment.\"}'),(113,94817,'Himushi','{\"Description\":\"Himushi (\\u30D2\\u30E0\\u30B7, Himushi) is a mercenary ninja and the leader of the Nokizaru Group.\",\"Description_2\":\"Himushi and the Nokizaru were hired by the Sugi Village to hunt out the Fourth Raikage and his men after they stole a scroll detailing their employer\\u0027s hidden techniques. While on their tail, the Nokizaru unleashed a blinding light which dispersed microscopic Exploding Insects which the Kumogakure shinobi inhaled. After killing Nigai with this method, A escaped with his ill subordinate.\",\"Description_3\":\"Tracking them down, Himushi spied on A and Tsunade and prepared a plan to retrieve the scroll by unleashing more exploding insects and offering the cure in return for it. The result of this plan is unknown as Himushi and his team fled when backup from Kumo arrived.\",\"Anime Debut\":\"Naruto Shippuuden Episode #287\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #287\", \"Description\": \"Himushi (ヒムシ, Himushi) is a mercenary ninja and the leader of the Nokizaru Group.\", \"Description_2\": \"Himushi and the Nokizaru were hired by the Sugi Village to hunt out the Fourth Raikage and his men after they stole a scroll detailing their employer\'s hidden techniques. While on their tail, the Nokizaru unleashed a blinding light which dispersed microscopic Exploding Insects which the Kumogakure shinobi inhaled. After killing Nigai with this method, A escaped with his ill subordinate.\", \"Description_3\": \"Tracking them down, Himushi spied on A and Tsunade and prepared a plan to retrieve the scroll by unleashing more exploding insects and offering the cure in return for it. The result of this plan is unknown as Himushi and his team fled when backup from Kumo arrived.\"}'),(114,34115,'Hina','{\"Description\":\"Hina (\\u30D2\\u30CA) is a ninja cat that lives with Nekobaa at an Uchiha supply base. Suigetsu mistakes her for a tanuki.\"}','{\"Description\": \"Hina (ヒナ) is a ninja cat that lives with Nekobaa at an Uchiha supply base. Suigetsu mistakes her for a tanuki.\"}'),(115,182620,'Hinoe','{\"Description\":\"In the events to follow the Third Great Shinobi War, Hinoe accompanied Danzou Shimura to a meeting with Orochimaru after the latter had been passed over for the position as Hokage. With nine other Root members, Hinoe received a mission to assassinate Hiruzen Sarutobi before he could be reinstated as Hokage. Disguised as a foreign shinobi, he fought the Anbu accompanying his target, who turned out to be a disguised Kakashi.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"In the events to follow the Third Great Shinobi War, Hinoe accompanied Danzou Shimura to a meeting with Orochimaru after the latter had been passed over for the position as Hokage. With nine other Root members, Hinoe received a mission to assassinate Hiruzen Sarutobi before he could be reinstated as Hokage. Disguised as a foreign shinobi, he fought the Anbu accompanying his target, who turned out to be a disguised Kakashi.\"}'),(116,148695,'Hinoko','{}','{}'),(117,103823,'Hinoto','{\"Description\":\"Hinoto is a member of Konohagakure\\u0027s Anbu faction Root.\",\"Description_2\":\"One day, Hinoto and Hinoe were guarding the entrance to the Root chambers when the two Anbu members Y\\u016Bgao Uzuki and Kakashi Hatake appeared with the order to bring Danz\\u014D Shimura to Hiruzen Sarutobi, the Third Hokage. After Y\\u016Bgao left with the message that Danz\\u014D was absent, Kakashi revealed his face and subdued Hinoe with his Sharingan. Hinoto tried to attack him but was quickly overpowered. Kakashi then used a genjutsu to extract the information about Kinoe\\u0027s whereabouts from her.\",\"Description_3\":\"Hinoto has black hair in a ponytail and she wears the typical attire of the Anbu along with a sword strapped to her shoulder and a cat-like mask. She also has white pearl earrings.\",\"Description_4\":\"Being a member of the Anbu, Hinoto is most likely a powerful kunoichi. She is presumably skilled in bukijutsu, wielding both a sword and a b\\u014D.\",\"Anime Debut\":\"Naruto Shippuuden Episode #350\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #350\", \"Description\": \"Hinoto is a member of Konohagakure\'s Anbu faction Root.\", \"Description_2\": \"One day, Hinoto and Hinoe were guarding the entrance to the Root chambers when the two Anbu members Yūgao Uzuki and Kakashi Hatake appeared with the order to bring Danzō Shimura to Hiruzen Sarutobi, the Third Hokage. After Yūgao left with the message that Danzō was absent, Kakashi revealed his face and subdued Hinoe with his Sharingan. Hinoto tried to attack him but was quickly overpowered. Kakashi then used a genjutsu to extract the information about Kinoe\'s whereabouts from her.\", \"Description_3\": \"Hinoto has black hair in a ponytail and she wears the typical attire of the Anbu along with a sword strapped to her shoulder and a cat-like mask. She also has white pearl earrings.\", \"Description_4\": \"Being a member of the Anbu, Hinoto is most likely a powerful kunoichi. She is presumably skilled in bukijutsu, wielding both a sword and a bō.\"}'),(118,23053,'Hiruko','{\"Description\":\"Hiruko (\\u30D2\\u30EB\\u30B3) was once a great shinobi of Sunagakure. However, once he died, he became one of Sasori\\u0027s first Human Puppets and one of his favorites. As a puppet, he served as Sasori\\u0027s \\u0022puppet armor\\u0022 as he could hide inside of him. Sasori even adorned Hiruko with the Akatsuki\\u0027s robes, and hid inside it so often that others came to recognize him only when he was wearing it.\",\"Description_2\":\"Chiyo stated that Hiruko had changed since she saw him twenty years ago. After all of his strikes failed due to Chiyo\\u0027s manipulation, Haruno Sakura destroyed the puppet.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Hiruko (ヒルコ) was once a great shinobi of Sunagakure. However, once he died, he became one of Sasori\'s first Human Puppets and one of his favorites. As a puppet, he served as Sasori\'s \\\"puppet armor\\\" as he could hide inside of him. Sasori even adorned Hiruko with the Akatsuki\'s robes, and hid inside it so often that others came to recognize him only when he was wearing it.\", \"Description_2\": \"Chiyo stated that Hiruko had changed since she saw him twenty years ago. After all of his strikes failed due to Chiyo\'s manipulation, Haruno Sakura destroyed the puppet.\"}'),(119,50459,'Hishaku','{}','{}'),(120,50553,'Honoka','{\"Description\":\"A kunoichi working with the researchers on a remote island.While researchers worked on the Ultimate Summoning Animal, Honoka was assigned to restrain the beast using her sealing techniques. However, at some point in time the beast got too powerful for her technique to restrain it and killed everyone.\",\"Description_2\":\"Honoka had dark eyes and long red hair in which she wore a white band. She wore a purple, sleeveless kimono blouse with yellow trimmings held close by a traditional obi with a long, streaming bow tied to it, mesh armour underneath it and a short white skirt. She seemed to prefer going barefoot.\",\"Description_3\":\"Honoka had some aptitude for sealing techniques as she was assigned to restrain the Ultimate Summoning Animal. She could use a sealing technique that caused the sealing formula to form into chains to restrain a target.\"}','{\"Description\": \"A kunoichi working with the researchers on a remote island.While researchers worked on the Ultimate Summoning Animal, Honoka was assigned to restrain the beast using her sealing techniques. However, at some point in time the beast got too powerful for her technique to restrain it and killed everyone.\", \"Description_2\": \"Honoka had dark eyes and long red hair in which she wore a white band. She wore a purple, sleeveless kimono blouse with yellow trimmings held close by a traditional obi with a long, streaming bow tied to it, mesh armour underneath it and a short white skirt. She seemed to prefer going barefoot.\", \"Description_3\": \"Honoka had some aptitude for sealing techniques as she was assigned to restrain the Ultimate Summoning Animal. She could use a sealing technique that caused the sealing formula to form into chains to restrain a target.\"}'),(121,62775,'Hoozuki, Mangetsu','{\"Birthdate\":\"February 15\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"172 cm\",\"Weight\":\"54.7 kg\",\"Blood type\":\"AB\",\"Affiliation\":\"Kirigakure\",\"Team\":\"Seven Ninja Swordsmen of the Mist\",\"Clan\":\"Hoozuki\",\"Ninja Rank\":\"J\\u014Dnin\",\"Family\":\"Suigetsu H\\u014Dzuki (younger brother)\",\"Nature type\":\"water release\",\"Description\":\"Mangetsu Hoozuki, reputed as the \\u0022Second Coming of the Demon,\\u0022 was a shinobi from Kirigakure\\u0027s Hoozuki clan, and a member of the previous generation of the Seven Ninja Swordsmen of the Mist.\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Clan\": \"Hoozuki\", \"Team\": \"Seven Ninja Swordsmen of the Mist\", \"Family\": \"Suigetsu Hōzuki (younger brother)\", \"Gender\": \"Male\", \"Height\": \"172 cm\", \"Status\": \"Deceased\", \"Weight\": \"54.7 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"February 15\", \"Blood type\": \"AB\", \"Ninja Rank\": \"Jōnin\", \"Affiliation\": \"Kirigakure\", \"Description\": \"Mangetsu Hoozuki, reputed as the \\\"Second Coming of the Demon,\\\" was a shinobi from Kirigakure\'s Hoozuki clan, and a member of the previous generation of the Seven Ninja Swordsmen of the Mist.\", \"Nature type\": \"water release\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(122,1903,'Hoozuki, Suigetsu','{\"Birthdate\":\"February 18\",\"Sign\":\"Aquarius\",\"Gender\":\"Male\",\"Age\":\"Part II: 16\\u201317\",\"Height\":\"Part II: 177.4 cm\",\"Weight\":\"Part II: 57 kg\",\"Blood type\":\"B\",\"Description\":\"Suigetsu H\\u014Dzuki is a former experimental subject of Orochimaru. Suigetsu once trained to be one of the Seven Swordsmen of the Mist, and as such has a number of traits consistent with other known members. In addition to having shark-like teeth, Suigetsu enjoys killing; Kisame Hoshigaki, one of the Seven Swordsmen, claims Suigetsu is a prodigy at the art of murder, as he has a habit of chopping off his victim\\u0027s limbs before beheading them. He is also very confident in his abilities, since he has threatened Sasuke Uchiha on more than one occasion. Not afraid to speak his mind and always doing as he pleases, Suigetsu clashed with Sasuke at first, but eventually came to accept Sasuke\\u0027s position and even put himself in harm\\u0027s way to protect him.\",\"Description_2\":\"After joining Hebi, Sasuke takes Suigetsu to retrieve Zabuza Momochi\\u0027s giant Kubikiri H\\u014Dch\\u014D from his graveside. Suigetsu can wield the weapon with relative ease, despite its enormous size and weight. In his allegiance with Sasuke, Suigetsu hopes to acquire the sword of Kisame as well, which Karin assumes to mean that he wants to collect all of the swords of the Seven Swordsmen.\",\"Description_3\":\"Suigetsu is able to reduce himself to liquid form and return to bodily form at will. This ability also allows him to change his body shape, giving him the ability to increase the size of his limbs, proportionally increasing his strength, if necessary. It also makes striking him somewhat difficult; since he is made of liquid, any sufficiently powerful strike will go right through his watery form. Suigetsu is the first ninja seen carrying water bottles on his outfit. Given his somewhat frequent desire to consume water, it is suggested that Suigetsu requires regular hydration to sustain his watery form.\"}','{\"Age\": \"Part II: 16–17\", \"Sign\": \"Aquarius\", \"Gender\": \"Male\", \"Height\": \"Part II: 177.4 cm\", \"Weight\": \"Part II: 57 kg\", \"Birthdate\": \"February 18\", \"Blood type\": \"B\", \"Description\": \"Suigetsu Hōzuki is a former experimental subject of Orochimaru. Suigetsu once trained to be one of the Seven Swordsmen of the Mist, and as such has a number of traits consistent with other known members. In addition to having shark-like teeth, Suigetsu enjoys killing; Kisame Hoshigaki, one of the Seven Swordsmen, claims Suigetsu is a prodigy at the art of murder, as he has a habit of chopping off his victim\'s limbs before beheading them. He is also very confident in his abilities, since he has threatened Sasuke Uchiha on more than one occasion. Not afraid to speak his mind and always doing as he pleases, Suigetsu clashed with Sasuke at first, but eventually came to accept Sasuke\'s position and even put himself in harm\'s way to protect him.\", \"Description_2\": \"After joining Hebi, Sasuke takes Suigetsu to retrieve Zabuza Momochi\'s giant Kubikiri Hōchō from his graveside. Suigetsu can wield the weapon with relative ease, despite its enormous size and weight. In his allegiance with Sasuke, Suigetsu hopes to acquire the sword of Kisame as well, which Karin assumes to mean that he wants to collect all of the swords of the Seven Swordsmen.\", \"Description_3\": \"Suigetsu is able to reduce himself to liquid form and return to bodily form at will. This ability also allows him to change his body shape, giving him the ability to increase the size of his limbs, proportionally increasing his strength, if necessary. It also makes striking him somewhat difficult; since he is made of liquid, any sufficiently powerful strike will go right through his watery form. Suigetsu is the first ninja seen carrying water bottles on his outfit. Given his somewhat frequent desire to consume water, it is suggested that Suigetsu requires regular hydration to sustain his watery form.\"}'),(123,65135,'Hoozuki, Gengetsu','{\"Birthdate\":\"October 26\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"186.6 cm\",\"Weight\":\"75.4 kg\",\"Blood type\":\"AB\",\"Occupation\":\"Mizukage\",\"Affiliation\":\"Kirigakure\",\"Clan\":\"Hoozuki\",\"Description\":\"Gengetsu H\\u014Dzuki was the Second Mizukage of Kirigakure and a member of the Hoozuki clan.\",\"(Source\":\"Narutopedia)\"}','{\"Clan\": \"Hoozuki\", \"Gender\": \"Male\", \"Height\": \"186.6 cm\", \"Status\": \"Deceased\", \"Weight\": \"75.4 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"October 26\", \"Blood type\": \"AB\", \"Occupation\": \"Mizukage\", \"Affiliation\": \"Kirigakure\", \"Description\": \"Gengetsu Hōzuki was the Second Mizukage of Kirigakure and a member of the Hoozuki clan.\"}'),(124,2672,'Hoshigaki, Kisame','{\"Age\":\"32\",\"Birthday\":\"18 March\",\"Zodiac\":\"Pisces\",\"Height\":\"195 cm\",\"Weight\":\"83,1 kg\",\"Blood Type\":\"AB\",\"From\":\"Kirigakure (Mist)\",\"Affiliation\":\"Akatsuki\",\"Ring\":\"Nan (South)\",\"Finger Position\":\"Left Ring\",\"Side-kick\":\"Uchiha Itachi\",\"Favorite Foods\":\"Shrimp, Crab\",\"Least Favorite Foods\":\"Shark\\u0027s Fin\",\"Hobby\":\"Taking care of his shark skin\",\"First Manga Appearance\":\"Ch. 139\",\"First Anime Appearance\":\"Ep. 80\",\"Assignments Completed\":\"3 D-Rank, 68 C-Rank, 154 B-Rank, 78 A-Rank, 29 S-Rank\",\"Description\":\"Kisame Hoshigaki is a missing-nin from Kirigakure and is partnered with Itachi Uchiha. He gets along considerably better with Itachi than most Akatsuki members do with their own partners, immediately doing as Itachi asks of him and always looking out for Itachi\\u0027s well-being. His former country, the Land of Water, now seeks him out for plotting to overthrow its government and being involved in numerous assassinations. When he was still loyal to Kirigakure, he was one of the Seven Swordsmen of the Mist, a group of ninja that wield particularly large weapons in battle. Kisame\\u0027s weapon is called Samehada, a scale-covered sword that shaves off skin instead of cutting and is capable of absorbing untold amounts of chakra. Samehada only allows Kisame to wield it; if anyone else tries to pick it up, spikes protrude from its handle and it returns to Kisame\\u0027s side. Like other characters who have trained to be one of the Seven Swordsmen, Kisame enjoys mutilating his opponents, as seen when he suggests cutting off Naruto Uzumaki\\u0027s legs to make him easier to carry.\",\"Kisame has a distinctive shark-like appearance, complete with pale blue skin, small white eyes, gill-like facial structures, and sharp triangular teeth. Even his name, Kisame, means \\u0022demon shark\\u0022. His shark-like qualities carry over to the type of techniques he uses in battle, as he often shapes bodies of water into the forms of sharks that proceed to attack opponents. If there is no water source where he happens to be fighting, Kisame can use Water Release\":\"Exploding Water Shockwave to create a lake\\u0027s worth of water to be used for attacks. Kisame is also noted to have a particularly large reserve of chakra; even when he fights at 30% power in one instance his chakra supply is compared to that of a Nine-Tailed Demon Fox-enhanced Naruto Uzumaki.\",\"(Source\":\"Naruto.com)\"}','{\"Age\": \"32\", \"From\": \"Kirigakure (Mist)\", \"Ring\": \"Nan (South)\", \"Hobby\": \"Taking care of his shark skin\", \"Height\": \"195 cm\", \"Weight\": \"83,1 kg\", \"Zodiac\": \"Pisces\", \"(Source\": \"Naruto.com)\", \"Birthday\": \"18 March\", \"Side-kick\": \"Uchiha Itachi\", \"Blood Type\": \"AB\", \"Affiliation\": \"Akatsuki\", \"Description\": \"Kisame Hoshigaki is a missing-nin from Kirigakure and is partnered with Itachi Uchiha. He gets along considerably better with Itachi than most Akatsuki members do with their own partners, immediately doing as Itachi asks of him and always looking out for Itachi\'s well-being. His former country, the Land of Water, now seeks him out for plotting to overthrow its government and being involved in numerous assassinations. When he was still loyal to Kirigakure, he was one of the Seven Swordsmen of the Mist, a group of ninja that wield particularly large weapons in battle. Kisame\'s weapon is called Samehada, a scale-covered sword that shaves off skin instead of cutting and is capable of absorbing untold amounts of chakra. Samehada only allows Kisame to wield it; if anyone else tries to pick it up, spikes protrude from its handle and it returns to Kisame\'s side. Like other characters who have trained to be one of the Seven Swordsmen, Kisame enjoys mutilating his opponents, as seen when he suggests cutting off Naruto Uzumaki\'s legs to make him easier to carry.\", \"Favorite Foods\": \"Shrimp, Crab\", \"Finger Position\": \"Left Ring\", \"Least Favorite Foods\": \"Shark\'s Fin\", \"Assignments Completed\": \"3 D-Rank, 68 C-Rank, 154 B-Rank, 78 A-Rank, 29 S-Rank\", \"First Anime Appearance\": \"Ep. 80\", \"First Manga Appearance\": \"Ch. 139\", \"Kisame has a distinctive shark-like appearance, complete with pale blue skin, small white eyes, gill-like facial structures, and sharp triangular teeth. Even his name, Kisame, means \\\"demon shark\\\". His shark-like qualities carry over to the type of techniques he uses in battle, as he often shapes bodies of water into the forms of sharks that proceed to attack opponents. If there is no water source where he happens to be fighting, Kisame can use Water Release\": \"Exploding Water Shockwave to create a lake\'s worth of water to be used for attacks. Kisame is also noted to have a particularly large reserve of chakra; even when he fights at 30% power in one instance his chakra supply is compared to that of a Nine-Tailed Demon Fox-enhanced Naruto Uzumaki.\"}'),(125,30084,'Hotaru','{\"Description\":\"Hotaru (\\u30DB\\u30BF\\u30EB) is the granddaughter of the former leader of the Tsuchigumo clan, En no Gy\\u014Dja.\",\"One day Hotaru was under attack by a group of ninja who were actually after Utakata. Utakata saved Hotaru from the ninja, but was wounded in the battle. Hotaru ran for help from her fort, saving Utakata\\u0027s life, causing him to become indebted to her. After this, he became a sort of master to Hotaru in order to hide from anyone who is after him. Later she finds him sleeping under a tree and Utakata got angry when Hotaru called him master, saying that the relationship between a master and a student is not something you can count on. Utakata reluctantly begins to teach her the Water Walking Exercise first, believing that she wouldn\\u0027t master it. In the morning, she shows that she was able to stand on top of the water by training all night. Next, Utakata taught her Water Release\":\"Violent Water Wave, once again believing that she would not be able to master it without water-natured chakra only to discover she does possess water-natured chakra. She later found Utakata under a tree and showed him the she again mastered the technique much to his suprise.\",\"Description_2\":\"When a group ninja came looking for the Tsuchigumo clan\\u0027s kinjutsu, Tonbee had Hotaru, along with Utakata, take the clan\\u0027s forbidden jutsu so that ninja could not retrieve it. While traveling, Utakata got upset at Hotaru for calling him master (\\u5E2B\\u5320, shish\\u014D), at which point Naruto arrived, believing Utakata to be attacking Hotaru. Hotaru broke up the fight and Utakata left her, deciding that Team 7 would be capable in protect her. As she watched him float away in a bubble, she tried to convince him not to leave, but was unsuccessful in doing so.\",\"Description_3\":\"While on the way to the clan\\u0027s secret village, Naruto argues with her only for Yamato to devise a plan to convince Hotaru to accept their protection. Using his unique jutsu, Sai drew mountain leeches to fall on Hotaru, who freaks out and becomes afraid, causing her to accept Team 7\\u0027s protection. When they reached the village, Team 7 leaves Hotaru with the Tsuchigumo clan and Hotaru thanks Naruto before he leaves. When Naruto left he saw the look on the peoples faces back at the clan\\u0027s village, so he decided to return to check things out.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Hotaru (ホタル) is the granddaughter of the former leader of the Tsuchigumo clan, En no Gyōja.\", \"Description_2\": \"When a group ninja came looking for the Tsuchigumo clan\'s kinjutsu, Tonbee had Hotaru, along with Utakata, take the clan\'s forbidden jutsu so that ninja could not retrieve it. While traveling, Utakata got upset at Hotaru for calling him master (師匠, shishō), at which point Naruto arrived, believing Utakata to be attacking Hotaru. Hotaru broke up the fight and Utakata left her, deciding that Team 7 would be capable in protect her. As she watched him float away in a bubble, she tried to convince him not to leave, but was unsuccessful in doing so.\", \"Description_3\": \"While on the way to the clan\'s secret village, Naruto argues with her only for Yamato to devise a plan to convince Hotaru to accept their protection. Using his unique jutsu, Sai drew mountain leeches to fall on Hotaru, who freaks out and becomes afraid, causing her to accept Team 7\'s protection. When they reached the village, Team 7 leaves Hotaru with the Tsuchigumo clan and Hotaru thanks Naruto before he leaves. When Naruto left he saw the look on the peoples faces back at the clan\'s village, so he decided to return to check things out.\", \"One day Hotaru was under attack by a group of ninja who were actually after Utakata. Utakata saved Hotaru from the ninja, but was wounded in the battle. Hotaru ran for help from her fort, saving Utakata\'s life, causing him to become indebted to her. After this, he became a sort of master to Hotaru in order to hide from anyone who is after him. Later she finds him sleeping under a tree and Utakata got angry when Hotaru called him master, saying that the relationship between a master and a student is not something you can count on. Utakata reluctantly begins to teach her the Water Walking Exercise first, believing that she wouldn\'t master it. In the morning, she shows that she was able to stand on top of the water by training all night. Next, Utakata taught her Water Release\": \"Violent Water Wave, once again believing that she would not be able to master it without water-natured chakra only to discover she does possess water-natured chakra. She later found Utakata under a tree and showed him the she again mastered the technique much to his suprise.\"}'),(126,22898,'Hyou','{\"Description\":\"Hy\\u014D (\\u30D2\\u30E7\\u30A6) is a member of Konoha\\u0027s ANBU and a former member of the, now disbanded, Foundation. As most Foundation members, he\\u0027s still loyal to Foundation\\u0027s founder Danz\\u014D and is apparently trustworthy enough to be given the task of delivering top-secret information for him. He is introduced when acting as a go-between for Danz\\u014D and Sai, reminding the latter about the will and purpose of Foundation while doing so. He is presumed to be helping in Danz\\u014D\\u0027s efforts in becoming Hokage.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Hyō (ヒョウ) is a member of Konoha\'s ANBU and a former member of the, now disbanded, Foundation. As most Foundation members, he\'s still loyal to Foundation\'s founder Danzō and is apparently trustworthy enough to be given the task of delivering top-secret information for him. He is introduced when acting as a go-between for Danzō and Sai, reminding the latter about the will and purpose of Foundation while doing so. He is presumed to be helping in Danzō\'s efforts in becoming Hokage.\"}'),(127,12563,'Hyuuga, Hanabi','{\"Affiliations\":\"Konoha\",\"Age\":\"7 (I), 10 (II)\",\"Birthdate\":\"March 27\",\"Height\":\"4.34 ft\",\"Weight\":\"63.7 lb\",\"Blood type\":\"A\",\"Description\":\"Hanabi (means \\u0022fireworks\\u0022) is Hinata\\u0027s sister and youngest daughter of the leader of the Hyuuga clan, Hiashi Hyuuga.  She intially demonstrated to possess more talent than Hinata at her young age, which led Hiashi to focus more attention on her training to rear her into the next heir of the clan.\"}','{\"Age\": \"7 (I), 10 (II)\", \"Height\": \"4.34 ft\", \"Weight\": \"63.7 lb\", \"Birthdate\": \"March 27\", \"Blood type\": \"A\", \"Description\": \"Hanabi (means \\\"fireworks\\\") is Hinata\'s sister and youngest daughter of the leader of the Hyuuga clan, Hiashi Hyuuga.  She intially demonstrated to possess more talent than Hinata at her young age, which led Hiashi to focus more attention on her training to rear her into the next heir of the clan.\", \"Affiliations\": \"Konoha\"}'),(128,60107,'Hyuuga, Tokuma','{\"Description\":\"Tokuma Hy\\u016Bga (\\u65E5\\u5411\\u30C8\\u30AF\\u30DE, Hy\\u016Bga Tokuma) is a shinobi from Konohagakure\\u0027s Hy\\u016Bga clan.\",\"Manga Debut\":\"Chapter #489\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #197\"}','{\"Anime Debut\": \"Naruto Shippūden Episode #197\", \"Description\": \"Tokuma Hyūga (日向トクマ, Hyūga Tokuma) is a shinobi from Konohagakure\'s Hyūga clan.\", \"Manga Debut\": \"Chapter #489\"}'),(129,15039,'Hyuuga, Hiashi','{\"Gender\":\"Male\",\"Age\":\"40 (Part I), 42 (Part II)\",\"Birthday\":\"January 8\",\"Height\":\"5\\u00278\\u0022\",\"Weight\":\"146 lbs.\",\"Blood Type\":\"B\",\"Affiliation\":\"Konohagakure\",\"Description\":\"Hiashi Hyuga is the head of the Hyuga Clan. He is the father of Hinata and Hanabi Hyuga, twin brother of the late Hizashi Hyuga, and uncle of Neji Hyuga.\",\"Description_2\":\"As the father of Hinata Hyuga and the uncle of Neji Hyuga, Hiashi has a significant role in the lives of his daughter and nephew.\",\"Description_3\":\"Hiashi was born seconds before his twin brother Hizashi Hyuga, making him the head of Hyuga clan. The fact that Neji would never be able to succeed the clan, and that he would be marked with a curse mark so that he could be disciplined caused friction between the brothers.\",\"Description_4\":\"When his daughter, Hinata, was kidnapped by a the Head Ninja of Kumogakure no sato, who was acting as an ambassador to Konoha at the time, he had no choice but to kill her kidnapper. The Land of Lightning overlooked the kidnapping, and they demanded a life for a life, asking Hiashi surrender his life and be killed, or else a new wave of warfare between the Hidden Leaf and Cloud villages. While Hiashi planned on accepting the punishment, his brother insisted on taking his place, saying that while he hated the main family, he wanted to save his brother and decide his own destiny. He asked Hiashi to tell Neji about his decision and his reasons before leaving to be killed.\",\"Description_5\":\"Hiashi\\u0027s general personality is very stern and strict, as he assigns both his daughters arduous training, rarely complimenting their performance. This is especially true with Hinata; when she was assigned to Kurenai Yuhi, he told her that he was unconcerned about the possibility that she would die, saying that the Hyuga Clan had no use for a weak successor.\"}','{\"Age\": \"40 (Part I), 42 (Part II)\", \"Gender\": \"Male\", \"Height\": \"5\'8\\\"\", \"Weight\": \"146 lbs.\", \"Birthday\": \"January 8\", \"Blood Type\": \"B\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Hiashi Hyuga is the head of the Hyuga Clan. He is the father of Hinata and Hanabi Hyuga, twin brother of the late Hizashi Hyuga, and uncle of Neji Hyuga.\", \"Description_2\": \"As the father of Hinata Hyuga and the uncle of Neji Hyuga, Hiashi has a significant role in the lives of his daughter and nephew.\", \"Description_3\": \"Hiashi was born seconds before his twin brother Hizashi Hyuga, making him the head of Hyuga clan. The fact that Neji would never be able to succeed the clan, and that he would be marked with a curse mark so that he could be disciplined caused friction between the brothers.\", \"Description_4\": \"When his daughter, Hinata, was kidnapped by a the Head Ninja of Kumogakure no sato, who was acting as an ambassador to Konoha at the time, he had no choice but to kill her kidnapper. The Land of Lightning overlooked the kidnapping, and they demanded a life for a life, asking Hiashi surrender his life and be killed, or else a new wave of warfare between the Hidden Leaf and Cloud villages. While Hiashi planned on accepting the punishment, his brother insisted on taking his place, saying that while he hated the main family, he wanted to save his brother and decide his own destiny. He asked Hiashi to tell Neji about his decision and his reasons before leaving to be killed.\", \"Description_5\": \"Hiashi\'s general personality is very stern and strict, as he assigns both his daughters arduous training, rarely complimenting their performance. This is especially true with Hinata; when she was assigned to Kurenai Yuhi, he told her that he was unconcerned about the possibility that she would die, saying that the Hyuga Clan had no use for a weak successor.\"}'),(130,1694,'Hyuuga, Neji','{\"Age\":\"14 (I) ; 17 (II)\",\"Birthday\":\"3 July\",\"Horoscope\":\"Cancer\",\"Bloodtype\":\"0\",\"Height\":\"172 cm\",\"Weight\":\"54.2 kg\",\"Rank\":\"Genin (I); Jonin (II)\",\"Likes\":\"soba noodles with herring, meditation\",\"Dislikes\":\"pumpkin, spicy things\",\"Description\":\"Neji Hyuuga is a stoic member of Might Guy\\u0027s Team Guy, consisting of himself, Rock Lee, and Tenten. Neji and Lee have somewhat of a rivalry, much like that of Guy and Kakashi Hatake. Lee is determined to prove that a \\u0022failure\\u0022 such as himself can defeat a \\u0022genius\\u0022 such as Neji. Neji, however, doesn\\u0027t seem to be interested in this goal of Lee\\u0027s, and Lee doesn\\u0027t seem to have made an effort to prove the point to Neji. Despite this apparent clashing of ideals between the two, Neji seems to get along fairly well with Tenten, with the latter often helping Neji with his training. Neji and Tenten also tend to share opinions on Lee and Guy\\u0027s overreactive behaviors, often wondering how they can train the way they do.\",\"Description_2\":\"As a member of the Hyuga clan, Neji possesses Byakugan, allowing him to see the chakra flow of others and block the flow upon contact with his Gentle Fist style. As a member of the clan\\u0027s branch house, Neji can never hope to be taught how to use the clan\\u0027s most secret techniques by the clan\\u0027s elders. Despite this, Neji has learned many of the clan\\u0027s strongest techniques independently, even creating a few unique skills of his own. Because of this, Neji is known as a genius ninja and graduated from the Academy as the #1 rookie.\",\"Description_3\":\"Because his father, Hizashi Hyuga, was a member of a branch house of the Hyuga clan, Neji was born into the branch house. As a result, he was branded with the Hyuga branch family seal at a young age so that the members of the main house could keep him in check. Hizashi, believing Neji to be denied his potential as a branch house member, openly resented the main house, causing Neji to acquire the same feelings due to his father\\u0027s influence. In time, Neji\\u0027s hatred for the main house would increase exponentially as result of Hizashi being sacrificed to save the life of Hiashi Hyuga, Hizashi\\u0027s twin brother. Neji believed that his father was forced to die for his twin brother. Because of this, Neji came to feel that fate was something decided at birth and that no matter what one does, people cannot escape their destiny. This idea would go on to shape Neji\\u0027s life, creating a deep hatred for the main house and all of its members.\",\"Description_4\":\"After the Chunnin Exams when Neji fights Naruto both his great skill and potential are recognized by the clan leader, his uncle Hiashi Hyuuga, and is sought out by him to train with the main branch of the family to further enhance Neji\\u0027s skills. This helps ease some of the tensions between the two branches of the Hyuuga clan.\"}','{\"Age\": \"14 (I) ; 17 (II)\", \"Rank\": \"Genin (I); Jonin (II)\", \"Likes\": \"soba noodles with herring, meditation\", \"Height\": \"172 cm\", \"Weight\": \"54.2 kg\", \"Birthday\": \"3 July\", \"Dislikes\": \"pumpkin, spicy things\", \"Bloodtype\": \"0\", \"Horoscope\": \"Cancer\", \"Description\": \"Neji Hyuuga is a stoic member of Might Guy\'s Team Guy, consisting of himself, Rock Lee, and Tenten. Neji and Lee have somewhat of a rivalry, much like that of Guy and Kakashi Hatake. Lee is determined to prove that a \\\"failure\\\" such as himself can defeat a \\\"genius\\\" such as Neji. Neji, however, doesn\'t seem to be interested in this goal of Lee\'s, and Lee doesn\'t seem to have made an effort to prove the point to Neji. Despite this apparent clashing of ideals between the two, Neji seems to get along fairly well with Tenten, with the latter often helping Neji with his training. Neji and Tenten also tend to share opinions on Lee and Guy\'s overreactive behaviors, often wondering how they can train the way they do.\", \"Description_2\": \"As a member of the Hyuga clan, Neji possesses Byakugan, allowing him to see the chakra flow of others and block the flow upon contact with his Gentle Fist style. As a member of the clan\'s branch house, Neji can never hope to be taught how to use the clan\'s most secret techniques by the clan\'s elders. Despite this, Neji has learned many of the clan\'s strongest techniques independently, even creating a few unique skills of his own. Because of this, Neji is known as a genius ninja and graduated from the Academy as the #1 rookie.\", \"Description_3\": \"Because his father, Hizashi Hyuga, was a member of a branch house of the Hyuga clan, Neji was born into the branch house. As a result, he was branded with the Hyuga branch family seal at a young age so that the members of the main house could keep him in check. Hizashi, believing Neji to be denied his potential as a branch house member, openly resented the main house, causing Neji to acquire the same feelings due to his father\'s influence. In time, Neji\'s hatred for the main house would increase exponentially as result of Hizashi being sacrificed to save the life of Hiashi Hyuga, Hizashi\'s twin brother. Neji believed that his father was forced to die for his twin brother. Because of this, Neji came to feel that fate was something decided at birth and that no matter what one does, people cannot escape their destiny. This idea would go on to shape Neji\'s life, creating a deep hatred for the main house and all of its members.\", \"Description_4\": \"After the Chunnin Exams when Neji fights Naruto both his great skill and potential are recognized by the clan leader, his uncle Hiashi Hyuuga, and is sought out by him to train with the main branch of the family to further enhance Neji\'s skills. This helps ease some of the tensions between the two branches of the Hyuuga clan.\"}'),(131,22880,'Hyuuga, Hizashi','{\"Description\":\"Hizashi Hyuuga was a member of the Hyuuga Clan. He was the father of Neji Hyuuga, the younger twin brother of Hiashi Hyuuga, and the uncle of Hinata and Hanabi Hyuuga. Hizashi\\u0027s brother, Hiashi, was supposed to die as punishment for killing a shinobi from the Thunder Country (for kidnapping his daughter, for the byakugun). Hizashi decided that, while he resented how the family was set up, it would be best for him to die, and so he disabled his brother and offered himself. This is part of the basis for Neji\\u0027s resentment.\"}','{\"Description\": \"Hizashi Hyuuga was a member of the Hyuuga Clan. He was the father of Neji Hyuuga, the younger twin brother of Hiashi Hyuuga, and the uncle of Hinata and Hanabi Hyuuga. Hizashi\'s brother, Hiashi, was supposed to die as punishment for killing a shinobi from the Thunder Country (for kidnapping his daughter, for the byakugun). Hizashi decided that, while he resented how the family was set up, it would be best for him to die, and so he disabled his brother and offered himself. This is part of the basis for Neji\'s resentment.\"}'),(132,1555,'Hyuuga, Hinata','{\"Age\":\"13 (I), 15\\u201316 (II) 18 (The Last)\",\"Birthday\":\"December 27 (Capricorn)\",\"Height\":\"147.3 cm\\u2013148.3 cm (I), 160 cm (II)\",\"Weight\":\"37.9 kg\\u201338.2 kg (I); 45 kg (II)\",\"Blood type\":\"A\",\"Ninja registration N\\u00BA\":\"012612\",\"Rank\":\"Genin (I), Chuunin (II)\",\"Likes\":\"Naruto, zenzai (sweet red-bean soup), cinnamon rolls, pressing flowers\",\"Dislikes\":\"crab, shrimp\",\"Description\":\"Hyuuga Hinata is the eldest daughter of the Hyuga clan\\u0027s main branch. \\u0022Hyuga\\u0022 (\\u65E5\\u5411) means \\u0022toward the sun\\u0022 while \\u0022Hinata\\u0022 is a pun, as it is another way to read this kanji and means \\u0022a sunny place.\\u0022 Hinata was trained by her father, Hiashi Hyuga, to become the clan\\u0027s heiress, though in time he came to deem her a lost cause. Believing her to be of lesser skill than her younger sister, Hanabi Hyuga, her father left Hinata in Kurenai Yuhi\\u0027s care once she was assigned to Team 8, claiming he didn\\u0027t care what happened to her. Throughout her early time in Team 8, Hinata\\u0027s lack of self-confidence and unwillingness to fight hamper her abilities. Although she would train to improve her skills, she would immediately give up when faced with competition and failed every mission she was assigned as a result.\",\"Description_2\":\"Hinata has a long-standing crush on Naruto, which has been present since their time in the Academy. Her feelings for him are rooted in his determination, confidence, and strength, all of which Hinata lacks. With her affection for Naruto, Hinata is constantly willing to break away from her normal personality traits in order to help him. She also becomes more assertive for Naruto, and also doesn\\u0027t hesitate to defend him, even to himself. Her feelings for Naruto are one of the driving forces in her self-improvement, as she tries to gain strength in an attempt to both impress him and become like him. When they meet again in Part II, Hinata is unable to bring herself to greet Naruto and passes out when he comes to greet her, her feelings for him having apparently been amplified during his absence. Despite this, she gradually becomes more comfortable around Naruto, going from being unable to look him in the eye to being able to talk to him, and is able to work with him without difficulty when they are on missions together.\",\"Description_3\":\"As a member of the Hyuga clan, Hinata possesses the Byakugan, which gives her an almost 360 field of vision. During the Chunin Exams, she displays the ability to focus the Byakugan\\u0027s sight, increasing the distance that her eyes can see. She also specializes in the Gentle Fist fighting style, which allows her to damage her opponent\\u0027s chakra circulatory system and inner organs directly with even a slight tap. In her quest to get stronger, Hinata creates a new ability during the anime\\u0027s Bikochu arc called Protection of the Eight Trigrams Sixty-Four Palms (\\u5B88\\u8B77\\u516B\\u5366\\u516D\\u5341\\u56DB\\u638C, Shugohakke Rokuj\\u016Byon Sh\\u014D), a combination of the Hyuga clan\\u0027s most powerful techniques. With it Hinata emits streams of chakra from her palms to create extremely sharp blades that she can use to hit any target in her field of vision. Due to the speed at which these blades move, the amount of control she has over them, as well as her ability to manipulate their size, Hinata can use this technique to attack and defend simultaneously.\"}','{\"Age\": \"13 (I), 15–16 (II) 18 (The Last)\", \"Rank\": \"Genin (I), Chuunin (II)\", \"Likes\": \"Naruto, zenzai (sweet red-bean soup), cinnamon rolls, pressing flowers\", \"Height\": \"147.3 cm–148.3 cm (I), 160 cm (II)\", \"Weight\": \"37.9 kg–38.2 kg (I); 45 kg (II)\", \"Birthday\": \"December 27 (Capricorn)\", \"Dislikes\": \"crab, shrimp\", \"Blood type\": \"A\", \"Description\": \"Hyuuga Hinata is the eldest daughter of the Hyuga clan\'s main branch. \\\"Hyuga\\\" (日向) means \\\"toward the sun\\\" while \\\"Hinata\\\" is a pun, as it is another way to read this kanji and means \\\"a sunny place.\\\" Hinata was trained by her father, Hiashi Hyuga, to become the clan\'s heiress, though in time he came to deem her a lost cause. Believing her to be of lesser skill than her younger sister, Hanabi Hyuga, her father left Hinata in Kurenai Yuhi\'s care once she was assigned to Team 8, claiming he didn\'t care what happened to her. Throughout her early time in Team 8, Hinata\'s lack of self-confidence and unwillingness to fight hamper her abilities. Although she would train to improve her skills, she would immediately give up when faced with competition and failed every mission she was assigned as a result.\", \"Description_2\": \"Hinata has a long-standing crush on Naruto, which has been present since their time in the Academy. Her feelings for him are rooted in his determination, confidence, and strength, all of which Hinata lacks. With her affection for Naruto, Hinata is constantly willing to break away from her normal personality traits in order to help him. She also becomes more assertive for Naruto, and also doesn\'t hesitate to defend him, even to himself. Her feelings for Naruto are one of the driving forces in her self-improvement, as she tries to gain strength in an attempt to both impress him and become like him. When they meet again in Part II, Hinata is unable to bring herself to greet Naruto and passes out when he comes to greet her, her feelings for him having apparently been amplified during his absence. Despite this, she gradually becomes more comfortable around Naruto, going from being unable to look him in the eye to being able to talk to him, and is able to work with him without difficulty when they are on missions together.\", \"Description_3\": \"As a member of the Hyuga clan, Hinata possesses the Byakugan, which gives her an almost 360 field of vision. During the Chunin Exams, she displays the ability to focus the Byakugan\'s sight, increasing the distance that her eyes can see. She also specializes in the Gentle Fist fighting style, which allows her to damage her opponent\'s chakra circulatory system and inner organs directly with even a slight tap. In her quest to get stronger, Hinata creates a new ability during the anime\'s Bikochu arc called Protection of the Eight Trigrams Sixty-Four Palms (守護八卦六十四掌, Shugohakke Rokujūyon Shō), a combination of the Hyuga clan\'s most powerful techniques. With it Hinata emits streams of chakra from her palms to create extremely sharp blades that she can use to hit any target in her field of vision. Due to the speed at which these blades move, the amount of control she has over them, as well as her ability to manipulate their size, Hinata can use this technique to attack and defend simultaneously.\", \"Ninja registration Nº\": \"012612\"}'),(133,22988,'Hyuuga, Kou','{\"Description\":\"Kou Hyuuga (\\u65E5\\u5411\\u30B3\\u30A6, Hyuuga Kou) is a shinobi of Konohagakure and a branch member of the Hyuuga clan. He is the protector of Hinata when Pain attacked Konoha, because Hanabi and Hiashi Hyuuga were away on a mission. As Hinata tried to help Naruto, Kou called her back claiming that she would only be a burden to him. Later, he watched in horror with his Byakugan as Hinata went ahead anyway. He was unable to restrain her due to a broken leg he had sustained when Pain used his Shinra Tensei on the entire village.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kou Hyuuga (日向コウ, Hyuuga Kou) is a shinobi of Konohagakure and a branch member of the Hyuuga clan. He is the protector of Hinata when Pain attacked Konoha, because Hanabi and Hiashi Hyuuga were away on a mission. As Hinata tried to help Naruto, Kou called her back claiming that she would only be a burden to him. Later, he watched in horror with his Byakugan as Hinata went ahead anyway. He was unable to restrain her due to a broken leg he had sustained when Pain used his Shinra Tensei on the entire village.\"}'),(134,62635,'Hyuuga, Hoheto','{\"Description\":\"Hoheto Hyuuga (\\u65E5\\u5411\\u30DB\\u30D8\\u30C8, Hy\\u016Bga Hoheto) is a shinobi from Konohagakure\\u0027s Hy\\u016Bga clan.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #256\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #256\", \"Description\": \"Hoheto Hyuuga (日向ホヘト, Hyūga Hoheto) is a shinobi from Konohagakure\'s Hyūga clan.\", \"Manga Debut\": \"Chapter #515\"}'),(135,119785,'Hyuuga, Natsu','{\"Description\":\"Natsu Hy\\u016Bga is a kunoichi of Konohagakure\\u0027s Hy\\u016Bga clan.\",\"Description_2\":\"Natsu was a maid of the Hy\\u016Bga clan, and was the caretaker of Hanabi Hy\\u016Bga. One day when Hanabi wanted to play with her sister, Natsu reminded her that Hinata was busy with her training. The next morning when they were taking a walk through the village, they witnessed Naruto Uzumaki being scolded by a villager. As Hanabi wondered why Naruto was treated as an outcast, Natsu told her to shun him. Later she watched over Hanabi finishing her studies, and told her to finish them before she could play with Hinata.\",\"Description_3\":\"Natsu is a kind and responsible person, having been tasked with looking after Hanabi Hy\\u016Bga. Despite this, like most of the villagers in Konoha she treated Naruto poorly when he was a child.\",\"Description_4\":\"As a member of the Hy\\u016Bga clan, Natsu possesses the Byakugan which grants her an almost 360\\u00B0 field of vision, x-ray vision, and the ability to see through chakra pathway system.\",\"(Source\":\"Narutopedia).\"}','{\"(Source\": \"Narutopedia).\", \"Description\": \"Natsu Hyūga is a kunoichi of Konohagakure\'s Hyūga clan.\", \"Description_2\": \"Natsu was a maid of the Hyūga clan, and was the caretaker of Hanabi Hyūga. One day when Hanabi wanted to play with her sister, Natsu reminded her that Hinata was busy with her training. The next morning when they were taking a walk through the village, they witnessed Naruto Uzumaki being scolded by a villager. As Hanabi wondered why Naruto was treated as an outcast, Natsu told her to shun him. Later she watched over Hanabi finishing her studies, and told her to finish them before she could play with Hinata.\", \"Description_3\": \"Natsu is a kind and responsible person, having been tasked with looking after Hanabi Hyūga. Despite this, like most of the villagers in Konoha she treated Naruto poorly when he was a child.\", \"Description_4\": \"As a member of the Hyūga clan, Natsu possesses the Byakugan which grants her an almost 360° field of vision, x-ray vision, and the ability to see through chakra pathway system.\"}'),(136,149423,'Ibara','{\"Description\":\"Ibara is a citizen of Konohagakure and the mother of one of the students in Naruto Uzumaki\\u0027s class at the Academy.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Ibara is a citizen of Konohagakure and the mother of one of the students in Naruto Uzumaki\'s class at the Academy.\"}'),(137,52029,'Igii','{\"Description\":\"Appears in episode 233.\"}','{\"Description\": \"Appears in episode 233.\"}'),(138,147893,'Inaho','{\"Description\":\"Inaho is a genin from Konohagakure. Like her teammates, she is overconfident in her and her team\\u0027s abilities to the point where she thought Team Ajisai fled because they were too powerful, which wasn\\u0027t the case. She fights using explosive tags in tandem with kunai.\"}','{\"Description\": \"Inaho is a genin from Konohagakure. Like her teammates, she is overconfident in her and her team\'s abilities to the point where she thought Team Ajisai fled because they were too powerful, which wasn\'t the case. She fights using explosive tags in tandem with kunai.\"}'),(139,21365,'Inari','{\"Description\":\"Inari (\\u30A4\\u30CA\\u30EA) is the son of Tsunami and the grandson of Tazuna. Inari\\u0027s father died before he got to know him, but he came to see Kaiza as a father figure. Kaiza took a fatherly role in Inari\\u0027s life and even became close to Tsunami. When Gato put Kaiza to death, Inari changed. He became a sad and angry boy, with little hope or optimism. He blamed Kaiza for what had happened, believing that he, in dying, had broken his promise to protect the land.\",\"Description_2\":\"Inari\\u0027s outlook is changed after he meets Naruto Uzumaki, who also had a horrible past, but learned to deal with it. Naruto\\u0027s unwillingness to quit and concern for others helped Inari to realize the power of will over fate, and that no risk is too great to protect something precious. He therefore grabbed his crossbow and rallied the townspeople, who proceeded to rise up against Gato\\u0027s men. He also attempted to save his mother from the thugs, who would have killed him, had it not been for Naruto. Along with Naruto and Kakashi Hatake, they were able to drive away Gato\\u0027s thugs.\",\"Personal Data\":\"\",\"Birthday\":\"December 25th\",\"Blood Type\":\"A\",\"Height\":\"128.5 cm\",\"Weight\":\"27.6 kg\",\"First Manga Appearance\":\"Chapter 16\",\"First Anime Appearance\":\"Naruto Episode 10\",\"Name Meaning\":\"A fox deity, also a flavored boiled rice\",\"Location\":\"Wave Country\",\"Age\":\"8\",\"See also\":\"Tsunami, Kaiza, Tazuna, Gat\\u00F4, Waraji, Zouri\"}','{\"Age\": \"8\", \"Height\": \"128.5 cm\", \"Weight\": \"27.6 kg\", \"Birthday\": \"December 25th\", \"Location\": \"Wave Country\", \"See also\": \"Tsunami, Kaiza, Tazuna, Gatô, Waraji, Zouri\", \"Blood Type\": \"A\", \"Description\": \"Inari (イナリ) is the son of Tsunami and the grandson of Tazuna. Inari\'s father died before he got to know him, but he came to see Kaiza as a father figure. Kaiza took a fatherly role in Inari\'s life and even became close to Tsunami. When Gato put Kaiza to death, Inari changed. He became a sad and angry boy, with little hope or optimism. He blamed Kaiza for what had happened, believing that he, in dying, had broken his promise to protect the land.\", \"Name Meaning\": \"A fox deity, also a flavored boiled rice\", \"Description_2\": \"Inari\'s outlook is changed after he meets Naruto Uzumaki, who also had a horrible past, but learned to deal with it. Naruto\'s unwillingness to quit and concern for others helped Inari to realize the power of will over fate, and that no risk is too great to protect something precious. He therefore grabbed his crossbow and rallied the townspeople, who proceeded to rise up against Gato\'s men. He also attempted to save his mother from the thugs, who would have killed him, had it not been for Naruto. Along with Naruto and Kakashi Hatake, they were able to drive away Gato\'s thugs.\", \"Personal Data\": \"\", \"First Anime Appearance\": \"Naruto Episode 10\", \"First Manga Appearance\": \"Chapter 16\"}'),(140,145750,'Inari, Shinko','{\"Description\":\"She has appeared in itachi shinden episode 453 that is her only appearnce.\"}','{\"Description\": \"She has appeared in itachi shinden episode 453 that is her only appearnce.\"}'),(141,3495,'Inuzuka, Kiba','{\"Birthday\":\"July 7\",\"Age\":\"12- 13 (Part I), 15- 16 (Part II)\",\"Height\":\"151.2 cm (Part I), 169.1 cm (Part II)\",\"Weight\":\"43.3- 44.7 kg (Part I), 52.5 kg (Part II)\",\"Blood type\":\"B\",\"Ninja Registration\":\"012620\",\"Family\":\"Tsume Inuzuka (Mother), Hana Inuzuka (Sister)\",\"Partner\":\"Akamaru\",\"Team\":\"Team Kurenai (Kurenai, Shino, Hinata, Kiba)\",\"Affiliation\":\"Konohagakure\",\"Description\":\"Kiba Inuzuka  is one of the main supporting characters of the series. He is a Chuunin-level shinobi of Konohagakure and a member of the Inuzuka Dog-User clan, as well as a member of the Chuunin team, Team Kurenai, along with Shino Aburame and Hinata Hyuuga. Kiba is usually seen with and fights in collaboration with his partner, Akamaru.\",\"Description_2\":\"Kiba is often short-tempered and impulsive (in stark contrast to his teammates Shino and Hinata), and can be prone to making mistakes when he becomes agitated in battle. The fact that he enjoys combat, as well as a habit of showing a joyful smile when facing a particularly strong opponent, indicates that he is willing to risk his life for a mission, and is rather bloodthirsty. He deeply cares for Akamaru, and is willing to do whatever is necessary to protect him. And, despite his rather gruff attitude, many of Kiba\\u0027s actions reveal that he is very close to his older sister, Hana Inuzuka, and remains fiercely loyal to the Inuzuka clan.\",\"Description_3\":\"Kiba\\u0027s personality and jutsu style are further enhanced by his wild appearance. While clearly human, he has several physical traits more akin to animals. Like the rest of his clan, he has messy brown hair, sharp black eyes with vertical slit-like pupils, pronounced canine teeth, and nails that he can change into claws. He also has the distinct red fang markings of the Inuzuka clan on his cheeks.\"}','{\"Age\": \"12- 13 (Part I), 15- 16 (Part II)\", \"Team\": \"Team Kurenai (Kurenai, Shino, Hinata, Kiba)\", \"Family\": \"Tsume Inuzuka (Mother), Hana Inuzuka (Sister)\", \"Height\": \"151.2 cm (Part I), 169.1 cm (Part II)\", \"Weight\": \"43.3- 44.7 kg (Part I), 52.5 kg (Part II)\", \"Partner\": \"Akamaru\", \"Birthday\": \"July 7\", \"Blood type\": \"B\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Kiba Inuzuka  is one of the main supporting characters of the series. He is a Chuunin-level shinobi of Konohagakure and a member of the Inuzuka Dog-User clan, as well as a member of the Chuunin team, Team Kurenai, along with Shino Aburame and Hinata Hyuuga. Kiba is usually seen with and fights in collaboration with his partner, Akamaru.\", \"Description_2\": \"Kiba is often short-tempered and impulsive (in stark contrast to his teammates Shino and Hinata), and can be prone to making mistakes when he becomes agitated in battle. The fact that he enjoys combat, as well as a habit of showing a joyful smile when facing a particularly strong opponent, indicates that he is willing to risk his life for a mission, and is rather bloodthirsty. He deeply cares for Akamaru, and is willing to do whatever is necessary to protect him. And, despite his rather gruff attitude, many of Kiba\'s actions reveal that he is very close to his older sister, Hana Inuzuka, and remains fiercely loyal to the Inuzuka clan.\", \"Description_3\": \"Kiba\'s personality and jutsu style are further enhanced by his wild appearance. While clearly human, he has several physical traits more akin to animals. Like the rest of his clan, he has messy brown hair, sharp black eyes with vertical slit-like pupils, pronounced canine teeth, and nails that he can change into claws. He also has the distinct red fang markings of the Inuzuka clan on his cheeks.\", \"Ninja Registration\": \"012620\"}'),(142,15073,'Inuzuka, Hana','{\"Date of Birth\":\"April 13th\",\"Age\":\"18 (Part I), 21 (Part II)\",\"Height\":\"170. 3 cm\",\"Weight\":\"52.5 kg\",\"Occupation\":\"Veterinarian- Medical Nin\",\"Ninja Registration No.\":\"012368\",\"Ninja Rank\":\"Chuunin\",\"Hana Inuzuka is a kunoichi of Konohagakure, and a member of the Inuzuka Dog-user clan. Hana is the daughter of Tsume Inuzuka, and the older sister of Kiba Inuzuka. She is an excellent and respected veterinarian. Her canine companions are a ninken triplet\":\"the Three Haimaru Brothers.\",\"Description\":\"She has the traditional fang-like tattoos of the Inuzuka clan on both of her cheeks, in addition to a tattoo on her upper right arm that resembles a flower\",\"Description_2\":\"Hana is also noted to have a softer appearance than the other members of her family, not having extended canines or slit-like eyes, and her hair isn\\u0027t wild, but tied into a ponytail with one hair bang on each side of her face.\"}','{\"Age\": \"18 (Part I), 21 (Part II)\", \"Height\": \"170. 3 cm\", \"Weight\": \"52.5 kg\", \"Ninja Rank\": \"Chuunin\", \"Occupation\": \"Veterinarian- Medical Nin\", \"Description\": \"She has the traditional fang-like tattoos of the Inuzuka clan on both of her cheeks, in addition to a tattoo on her upper right arm that resembles a flower\", \"Date of Birth\": \"April 13th\", \"Description_2\": \"Hana is also noted to have a softer appearance than the other members of her family, not having extended canines or slit-like eyes, and her hair isn\'t wild, but tied into a ponytail with one hair bang on each side of her face.\", \"Ninja Registration No.\": \"012368\", \"Hana Inuzuka is a kunoichi of Konohagakure, and a member of the Inuzuka Dog-user clan. Hana is the daughter of Tsume Inuzuka, and the older sister of Kiba Inuzuka. She is an excellent and respected veterinarian. Her canine companions are a ninken triplet\": \"the Three Haimaru Brothers.\"}'),(143,15074,'Inuzuka, Tsume','{\"Description\":\"Tsume Inuzuka is the mother of Hana and Kiba Inuzuka. Tsume has the same abilities as the rest of the Inuzuka Clan. She fights with her beloved companion, Kuromaru. It is currently unknown as to exactly what power she possesses, but since she is a Tokubetsu Jonin she is obviously an extremely skillful fighter. She can also use the Dual Piercing Fang as well as many more combinations with Kuromaru.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tsume Inuzuka is the mother of Hana and Kiba Inuzuka. Tsume has the same abilities as the rest of the Inuzuka Clan. She fights with her beloved companion, Kuromaru. It is currently unknown as to exactly what power she possesses, but since she is a Tokubetsu Jonin she is obviously an extremely skillful fighter. She can also use the Dual Piercing Fang as well as many more combinations with Kuromaru.\"}'),(144,97781,'Iou','{\"Description\":\"Iou (\\u30A4\\u30AA\\u30A6, I\\u014D) is a medical-nin from Konohagakure.\",\"Description_2\":\"During the Fourth Shinobi World War, Iou was assigned to the Logistic Support and medical Division. During a quell in the war, with heavy casualties coming into the compound, the KIA scroll was stolen Sukui assigned Iou along with Yokaze, Sakura Haruno, and Yugao Uzuki to retrieve it as it contained the corpses of shinobi with kekkei genkai and other unique abilities sealed away in it. When the team caught up to the opposition, Iou fought alongside his comrades and was successful in sealing away both the Suna, and Kumo-nin. However, his confrontation with Hayate Gekkou ended with him being heavily wounded. Healed by Sakura, Iou was not able to continue on the mission and left the sealing of Hayate to his remaining comrades. Their mission ended in success with all three shinobi being sealed away successfully.\",\"Anime Debut\":\"Naruto Shippuuden Episode #307\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #307\", \"Description\": \"Iou (イオウ, Iō) is a medical-nin from Konohagakure.\", \"Description_2\": \"During the Fourth Shinobi World War, Iou was assigned to the Logistic Support and medical Division. During a quell in the war, with heavy casualties coming into the compound, the KIA scroll was stolen Sukui assigned Iou along with Yokaze, Sakura Haruno, and Yugao Uzuki to retrieve it as it contained the corpses of shinobi with kekkei genkai and other unique abilities sealed away in it. When the team caught up to the opposition, Iou fought alongside his comrades and was successful in sealing away both the Suna, and Kumo-nin. However, his confrontation with Hayate Gekkou ended with him being heavily wounded. Healed by Sakura, Iou was not able to continue on the mission and left the sealing of Hayate to his remaining comrades. Their mission ended in success with all three shinobi being sealed away successfully.\"}'),(145,38454,'Iou','{\"Description\":\"Iou is a ninja tool inventor from Konoha and Shoseki helps him make these tools. Most of his tool creations are shown either be impossible to carry or serves no purpose at all. It is assumed he was relocated to the outskirts of the village due to the random explosions which he claims are \\u0022challenges\\u0022 during his inventing. Team Guy (minus Might Guy and Naruto Uzumaki replacing Rock Lee) go to the Konoha Research Lab to retrieve more tools for the village. When checking up on their progress, they see that Iou and his assistant went down the research lab to work on Iou\\u0027s newest weapon. Suddenly two ninja, Gameru and Kusune arrive to the research lab and demand new weapons from Iou. They both possessed two of his prototype weapons that Shoseki sold to them. Iou gave Tenten his newest weapon, Jidanda, which she used to defeat both the ninja. Iou took Jidanda back from Tenten after the ninja were defeated, saying more work needed to be done on the weapon. Years later, Tenten and Neji Hy\\u016Bga return to the research lab to retrieve more tools for the village after its destruction.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Iou is a ninja tool inventor from Konoha and Shoseki helps him make these tools. Most of his tool creations are shown either be impossible to carry or serves no purpose at all. It is assumed he was relocated to the outskirts of the village due to the random explosions which he claims are \\\"challenges\\\" during his inventing. Team Guy (minus Might Guy and Naruto Uzumaki replacing Rock Lee) go to the Konoha Research Lab to retrieve more tools for the village. When checking up on their progress, they see that Iou and his assistant went down the research lab to work on Iou\'s newest weapon. Suddenly two ninja, Gameru and Kusune arrive to the research lab and demand new weapons from Iou. They both possessed two of his prototype weapons that Shoseki sold to them. Iou gave Tenten his newest weapon, Jidanda, which she used to defeat both the ninja. Iou took Jidanda back from Tenten after the ninja were defeated, saying more work needed to be done on the weapon. Years later, Tenten and Neji Hyūga return to the research lab to retrieve more tools for the village after its destruction.\"}'),(146,23052,'Ise, Udon','{\"Description\":\"Udon is the friend of Konohamaru and Moegi. He is in the Genin-team led by Ebisu. He seems to have a perpetually runny nose and seems to be very sleepy. Udon states many times that he loves math, as he is usually seen writing math problems during class. Udon idolizes Sasuke Uchiha, stating that if he was lucky enough he would be just like Sasuke. \\u0022Udon\\u0022 is also a type of Japanese noodle.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Udon is the friend of Konohamaru and Moegi. He is in the Genin-team led by Ebisu. He seems to have a perpetually runny nose and seems to be very sleepy. Udon states many times that he loves math, as he is usually seen writing math problems during class. Udon idolizes Sasuke Uchiha, stating that if he was lucky enough he would be just like Sasuke. \\\"Udon\\\" is also a type of Japanese noodle.\"}'),(147,63211,'Ise','{\"Description\":\"Nagato\\u0027s father and Fuso\\u0027s husband.\"}','{\"Description\": \"Nagato\'s father and Fuso\'s husband.\"}'),(148,93633,'Ishikawa','{\"Birthdate\":\"May 6\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Height\":\"145 cm\",\"Weight\":\"46.3 kg\",\"Blood type\":\"O\",\"Occupation\":\"Tsuchikage\",\"Affiliation\":\"Iwagakure\",\"Clan\":\"Kamizuru Clan\",\"Description\":\"Ishikawa was the First Tsuchikage who founded Iwagakure in the Land of Earth. In the anime, he was stated to be a member of the Kamizuru clan.\",\"(Source\":\"Narutopedia)\"}','{\"Clan\": \"Kamizuru Clan\", \"Gender\": \"Male\", \"Height\": \"145 cm\", \"Status\": \"Deceased\", \"Weight\": \"46.3 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"May 6\", \"Blood type\": \"O\", \"Occupation\": \"Tsuchikage\", \"Affiliation\": \"Iwagakure\", \"Description\": \"Ishikawa was the First Tsuchikage who founded Iwagakure in the Land of Earth. In the anime, he was stated to be a member of the Kamizuru clan.\"}'),(149,57873,'Isobu','{\"Description\":\"Isobu, more commonly known as the Three-Tails or Sanbi, is a tailed beast that was formerly sealed in Yagura of Kirigakure.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Isobu, more commonly known as the Three-Tails or Sanbi, is a tailed beast that was formerly sealed in Yagura of Kirigakure.\"}'),(150,97785,'Isono','{\"Description\":\"Isono (\\u30A4\\u30BD\\u30CE, Isono) is a man who took part in the eating contest organised in the Land of This.\",\"Description_2\":\"Isono appears like one of the Chouji\\u0027s opponents during the eating contest in the Land of This. Isono manages to pass the first two rounds of the contest. Later, he goes to the final round, in a duel with Chouji and Tamao. The duel consisted in eating barbecue. Seeing the speed of his rivals, Isono use his special technique, \\u0022Lethal Juggler\\u0022, allowing him to cook food with one hand and eat the food with the other. Due to Chouji has to be the second in the contest, Shikamaru avoid his victory, making to Isono the winner. A house is given to Isono as a prize.\",\"Anime Debut\":\"Naruto Shippuuden Episode #309\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #309\", \"Description\": \"Isono (イソノ, Isono) is a man who took part in the eating contest organised in the Land of This.\", \"Description_2\": \"Isono appears like one of the Chouji\'s opponents during the eating contest in the Land of This. Isono manages to pass the first two rounds of the contest. Later, he goes to the final round, in a duel with Chouji and Tamao. The duel consisted in eating barbecue. Seeing the speed of his rivals, Isono use his special technique, \\\"Lethal Juggler\\\", allowing him to cook food with one hand and eat the food with the other. Due to Chouji has to be the second in the contest, Shikamaru avoid his victory, making to Isono the winner. A house is given to Isono as a prize.\"}'),(151,62637,'Ittan','{\"Description\":\"Ittan (\\u30A4\\u30C3\\u30BF\\u30F3, Ittan) is an Iwagakure shinobi.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #256\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #256\", \"Description\": \"Ittan (イッタン, Ittan) is an Iwagakure shinobi.\", \"Manga Debut\": \"Chapter #515\"}'),(152,31829,'Ittetsu','{\"Description\":\"Ittetsu is a genin from Sunagakure. He admired the Kazekage from the bottom of his heart and was part of the group of Suna shinobi who went to rescue the Kazekage from the Akatsuki. When he heard the Kazekage was revived, he was so relieved he had to cry, which Matsuri slugged him for.\"}','{\"Description\": \"Ittetsu is a genin from Sunagakure. He admired the Kazekage from the bottom of his heart and was part of the group of Suna shinobi who went to rescue the Kazekage from the Akatsuki. When he heard the Kazekage was revived, he was so relieved he had to cry, which Matsuri slugged him for.\"}'),(153,63973,'Iwa Kunoichi','{\"Description\":\"Appears in Naruto Shippuuden Episode #190.\",\"Description_2\":\"An Iwagakure kunoichi that led a battalion of Iwagakure ninja to attack Konohagakure\\u0027s border after its invasion by Sunagakure and Otogakure.\",\"Description_3\":\"She is shown to be very cruel as she sacrificed many Iwagakure genin during her fight with Kosuke Maruboshi. She also has a liking of cutting her opponents into pieces.\",\"Description_4\":\"She has long brown-coloured hair which she ties in such a fashion as to form a ball on top of her head, using what appears to be a knitting-needle, while two large locks with darkened tips frame the remainder of her face. Her typical attire is similar to Ino Yamanaka\\u0027s in that it consists of a short sleeveless dress, further adorned by the presence of numerous bandages that encircle various portions of her body, including her waist and thighs.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Appears in Naruto Shippuuden Episode #190.\", \"Description_2\": \"An Iwagakure kunoichi that led a battalion of Iwagakure ninja to attack Konohagakure\'s border after its invasion by Sunagakure and Otogakure.\", \"Description_3\": \"She is shown to be very cruel as she sacrificed many Iwagakure genin during her fight with Kosuke Maruboshi. She also has a liking of cutting her opponents into pieces.\", \"Description_4\": \"She has long brown-coloured hair which she ties in such a fashion as to form a ball on top of her head, using what appears to be a knitting-needle, while two large locks with darkened tips frame the remainder of her face. Her typical attire is similar to Ino Yamanaka\'s in that it consists of a short sleeveless dress, further adorned by the presence of numerous bandages that encircle various portions of her body, including her waist and thighs.\"}'),(154,161529,'Izumo, Tenma','{\"Description\":\"Shinobi from Konohagakure, and a member of Team 2 which young Itachi Uchiha belonged to.\"}','{\"Description\": \"Shinobi from Konohagakure, and a member of Team 2 which young Itachi Uchiha belonged to.\"}'),(155,41209,'Jako','{\"Description\":\"Jak\\u014D (\\u90AA\\u5149, Jak\\u014D) is a thief that stole some treasure from a daimy\\u014D\\u0026amp;#039;s sister.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #194\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #194\", \"(source\": \")\", \"Description\": \"Jakō (邪光, Jakō) is a thief that stole some treasure from a daimyō&amp;#039;s sister.\"}'),(156,23080,'Jei','{\"Description\":\"Jei (\\u30B8\\u30A7\\u30A4) is a shinobi of Kumogakure. His wardrobe is similar to Kir\\u0101b\\u012B. Jei discovers that Kir\\u0101b\\u012B is fighting members of Akatsuki while transformed into the Eight-Tailed Beast. He sends word of his discovery to the Raikage and then uses his lizards to follow Kir\\u0101b\\u012B\\u0027s opponents. He is soon discovered and captured. Jei is later found by other Kumogakure shinobi, but his condition is unknown.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Jei (ジェイ) is a shinobi of Kumogakure. His wardrobe is similar to Kirābī. Jei discovers that Kirābī is fighting members of Akatsuki while transformed into the Eight-Tailed Beast. He sends word of his discovery to the Raikage and then uses his lizards to follow Kirābī\'s opponents. He is soon discovered and captured. Jei is later found by other Kumogakure shinobi, but his condition is unknown.\"}'),(157,2423,'Jiraiya','{\"Age\":\"54\",\"Birthday\":\"November 11\",\"Horoscope\":\"Scorpio\",\"Blood type\":\"B\",\"Height\":\"191.2 cm\",\"Weight\":\"87.5 kg\",\"Likes\":\"peeping, women, garlic pickles with Japanese basil, karaage fried chicken\",\"Dislikes\":\"kiwi fruit, gratin\",\"Description\":\"Jiraiya is one of the three powerful ninjas who originated from Konoha (village hidden in the leaves) and trained by the third Hokage, Hiruzen Sarutobi. His two team mates were Tsunade and Orochimaru. Later on, they became known as the Legendary Three Ninja, also known as \\u0022Sannin.\\u0022\",\"Description_2\":\"Jiraiya is also a full-pledged pervert. He adores good looking women and gets distracted by their sight often. He often gives the reason that he is doing research for his writing. Jiraiya is the author of the Icha Icha Series which Kakashi loves to read.\",\"Description_3\":\"Among other traits, he is a toad-tamer, with the ability to summon powerful toads at will to aid him in battle. He holds a key part in teaching and training Naruto.\"}','{\"Age\": \"54\", \"Likes\": \"peeping, women, garlic pickles with Japanese basil, karaage fried chicken\", \"Height\": \"191.2 cm\", \"Weight\": \"87.5 kg\", \"Birthday\": \"November 11\", \"Dislikes\": \"kiwi fruit, gratin\", \"Horoscope\": \"Scorpio\", \"Blood type\": \"B\", \"Description\": \"Jiraiya is one of the three powerful ninjas who originated from Konoha (village hidden in the leaves) and trained by the third Hokage, Hiruzen Sarutobi. His two team mates were Tsunade and Orochimaru. Later on, they became known as the Legendary Three Ninja, also known as \\\"Sannin.\\\"\", \"Description_2\": \"Jiraiya is also a full-pledged pervert. He adores good looking women and gets distracted by their sight often. He often gives the reason that he is doing research for his writing. Jiraiya is the author of the Icha Icha Series which Kakashi loves to read.\", \"Description_3\": \"Among other traits, he is a toad-tamer, with the ability to summon powerful toads at will to aid him in battle. He holds a key part in teaching and training Naruto.\"}'),(158,8495,'Jiroubou','{\"Birthday\":\"June 26\",\"Description\":\"Jir\\u014Db\\u014D is the physically strongest member of the Sound Four. Through simple physical attacks, he can defeat an opponent in one or two blows. Because he is able to absorb the chakra of others, Jir\\u014Db\\u014D often captures opponents so that he can absorb their chakra as a form of sustenance.\"}','{\"Birthday\": \"June 26\", \"Description\": \"Jirōbō is the physically strongest member of the Sound Four. Through simple physical attacks, he can defeat an opponent in one or two blows. Because he is able to absorb the chakra of others, Jirōbō often captures opponents so that he can absorb their chakra as a form of sustenance.\"}'),(159,31828,'Jouseki','{\"Description\":\"J\\u014Dseki is a senior from Sunagakure. His foremost concern was the peacefulness of the village. He wasn\\u0027t comfortable with Gaara\\u0027s appointment to Kazekage, seeing him as little more than a failed and highly dangerous experiment. When the Kazekage was kidnapped by the Akatsuki, he mused it might be for the best and wanted to quickly elect a new Kazekage.\"}','{\"Description\": \"Jōseki is a senior from Sunagakure. His foremost concern was the peacefulness of the village. He wasn\'t comfortable with Gaara\'s appointment to Kazekage, seeing him as little more than a failed and highly dangerous experiment. When the Kazekage was kidnapped by the Akatsuki, he mused it might be for the best and wanted to quickly elect a new Kazekage.\"}'),(160,3152,'Juugo','{\"Birthdate\":\"October 1\",\"Zodiac sign\":\"Libra\",\"Gender\":\"Male\",\"Age\":\"Part II: 18\\u201319\",\"Height\":\"Part II: 202.1 cm\",\"Weight\":\"Part II: 75.8 kg\",\"Blood type\":\"AB\",\"Description\":\"Juugo is the largest of the three members that comprise Sasuke Uchiha\\u0027s new team, Snake (which is now Hawk). Juugo was being held at Orochimaru\\u0027s North Base, which is also where most of Orochimaru\\u0027s secret research was conducted. Suigetsu can\\u0027t stand Juugo and comments that one of the reasons he had to retrieve Zabuza Momochi\\u0027s sword was because of him. Karin notes that Juugo is mentally unstable, a view confirmed by images of Juugo muttering to himself over who he will kill next, which he determines by gender.\",\"Description_2\":\"Juugo is the means behind Orochimaru\\u0027s development of the cursed seals. Some time in the past, Juugo purposely sought out Orochimaru to cure him of his \\u0022impulses.\\u0022 Juugo has trouble controlling his rage, which unexpectedly causes him to transform into a berserk demon (much like a cursed seal does to its user). Upon examination, Orochimaru was able to isolate enzymes in Juugo\\u0027s blood as the cause of this change. By extracting these enzymes, Orochimaru was able to use them to produce similar, but more controlled, effects in other people.\",\"Description_3\":\"While Juugo initially appears quite bloodthirsty, Karin notes that this is only common behavior for the enraged; Juugo himself doesn\\u0027t want to kill anyone. Juugo\\u0027s fits of rage are random and thus the reason why he willingly remains confined. The only reason he agrees to go with Sasuke is because he views Sasuke as the only person capable of preventing him from killing people while enraged. Before Sasuke, it was Kimimaro who kept Juugo in check and as Kimimaro was the only person Juugo came into any contact with, the two grew close. After hearing that Kimimaro sacrificed his life to deliver Sasuke to Orochimaru, Juugo believes that Kimimaro\\u0027s spirit continues to live on in Sasuke.\",\"Description_4\":\"Juugo has a bracket-shaped symbol on his left palm. Whether or not this is also present on his right palm or if it has any significance has yet to be seen. His brief fight with Sasuke and Suigetsu revealed that Juugo can control his transformation, unlike the static effects of a standard cursed seal. When battling Sasuke he changes his left arm into a piston-like ram to increase his punching power and then alters it into a massive blade from his forearm to fight Suigetsu. He is also capable of doing only a partial transformation, invoking a level two form over one portion of his body without completely changing.\",\"Description_5\":\"While discussing Sasuke\\u0027s team with the other members of Akatsuki, the Akatsuki leader refers to Juugo as Juugo of the Scales (\\u5929\\u79E4\\u306E\\u91CD\\u543E, Tenbin no J\\u016Bgo, \\u0022scale\\u0022 referring to something that determines balance). Whether this is a title or a location is unclear.\",\"Description_6\":\"After Team Snake is dispatched on their mission into the forest, Juugo commences his search by activating his special enzyme and asking a bird for information.\"}','{\"Age\": \"Part II: 18–19\", \"Gender\": \"Male\", \"Height\": \"Part II: 202.1 cm\", \"Weight\": \"Part II: 75.8 kg\", \"Birthdate\": \"October 1\", \"Blood type\": \"AB\", \"Description\": \"Juugo is the largest of the three members that comprise Sasuke Uchiha\'s new team, Snake (which is now Hawk). Juugo was being held at Orochimaru\'s North Base, which is also where most of Orochimaru\'s secret research was conducted. Suigetsu can\'t stand Juugo and comments that one of the reasons he had to retrieve Zabuza Momochi\'s sword was because of him. Karin notes that Juugo is mentally unstable, a view confirmed by images of Juugo muttering to himself over who he will kill next, which he determines by gender.\", \"Zodiac sign\": \"Libra\", \"Description_2\": \"Juugo is the means behind Orochimaru\'s development of the cursed seals. Some time in the past, Juugo purposely sought out Orochimaru to cure him of his \\\"impulses.\\\" Juugo has trouble controlling his rage, which unexpectedly causes him to transform into a berserk demon (much like a cursed seal does to its user). Upon examination, Orochimaru was able to isolate enzymes in Juugo\'s blood as the cause of this change. By extracting these enzymes, Orochimaru was able to use them to produce similar, but more controlled, effects in other people.\", \"Description_3\": \"While Juugo initially appears quite bloodthirsty, Karin notes that this is only common behavior for the enraged; Juugo himself doesn\'t want to kill anyone. Juugo\'s fits of rage are random and thus the reason why he willingly remains confined. The only reason he agrees to go with Sasuke is because he views Sasuke as the only person capable of preventing him from killing people while enraged. Before Sasuke, it was Kimimaro who kept Juugo in check and as Kimimaro was the only person Juugo came into any contact with, the two grew close. After hearing that Kimimaro sacrificed his life to deliver Sasuke to Orochimaru, Juugo believes that Kimimaro\'s spirit continues to live on in Sasuke.\", \"Description_4\": \"Juugo has a bracket-shaped symbol on his left palm. Whether or not this is also present on his right palm or if it has any significance has yet to be seen. His brief fight with Sasuke and Suigetsu revealed that Juugo can control his transformation, unlike the static effects of a standard cursed seal. When battling Sasuke he changes his left arm into a piston-like ram to increase his punching power and then alters it into a massive blade from his forearm to fight Suigetsu. He is also capable of doing only a partial transformation, invoking a level two form over one portion of his body without completely changing.\", \"Description_5\": \"While discussing Sasuke\'s team with the other members of Akatsuki, the Akatsuki leader refers to Juugo as Juugo of the Scales (天秤の重吾, Tenbin no Jūgo, \\\"scale\\\" referring to something that determines balance). Whether this is a title or a location is unclear.\", \"Description_6\": \"After Team Snake is dispatched on their mission into the forest, Juugo commences his search by activating his special enzyme and asking a bird for information.\"}'),(161,279532,'Kageki','{\"Description\":\"Kageki had loaned money to Shikazo one time and after the birth of his child, he needed the money and asked Shikazo if he can be repaid but he refused. After a small scuffle, Shikazo fell and hit his head on a pickling stone that was hard enough to kill him. Since then, Kageki and his family went into hiding, while his twin brother, Katazu, took his identity and got the attention of his pursuers.\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kageki had loaned money to Shikazo one time and after the birth of his child, he needed the money and asked Shikazo if he can be repaid but he refused. After a small scuffle, Shikazo fell and hit his head on a pickling stone that was hard enough to kill him. Since then, Kageki and his family went into hiding, while his twin brother, Katazu, took his identity and got the attention of his pursuers.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(162,22996,'Kaiza','{\"Description\":\"Kaiza (\\u30AB\\u30A4\\u30B6) was a traveling fisherman, who came to the Land of Waves to seek opportunities. When he saved Inari from drowning, he took up the young boy to teach him about life and protect the things that were precious to him. He married Tsunami (Inari\\u0027s mother) and acted as the role model for Inari. When Gat\\u014D tried to take over the Land of Waves, Kaiza tried to stop his business. Gat\\u014D used him as an example to people who had hoped to stand against him, by having his goons cut off his arms and killing him.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kaiza (カイザ) was a traveling fisherman, who came to the Land of Waves to seek opportunities. When he saved Inari from drowning, he took up the young boy to teach him about life and protect the things that were precious to him. He married Tsunami (Inari\'s mother) and acted as the role model for Inari. When Gatō tried to take over the Land of Waves, Kaiza tried to stop his business. Gatō used him as an example to people who had hoped to stand against him, by having his goons cut off his arms and killing him.\"}'),(163,23152,'Kakkou','{\"Description\":\"Kakkou was a shinobi from Iwagakure who fought and died during the Third Great Shinobi World War. He excelled in all shinobi abilities, from ninjutsu, to taijutsu, to genjutsu. This made him a highly influential and powerful figure in Iwagakure.\",\"Description_2\":\"He was highly belligerent and had great experience in battle, allowing him to use advanced tactics to defeat his enemies. He fought using blades attached to his arms. He used his skills while fighting Team Minato, led by Kakashi Hatake. First he tried to extract information from Rin using genjutsu, but this proved unsuccessful. Later when Kakashi and Obito Uchiha attempted to rescue Rin, Kakkou managing to corner them and even kill Obito. However, once Kakashi had received the Sharingan, the tides turned and he was killed by Kakashi\\u0027s Chidori, but not before Kakkou cut in two the famous White Light Chakra Sabre Kakashi had inherited from his father, Sakumo Hatake.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kakkou was a shinobi from Iwagakure who fought and died during the Third Great Shinobi World War. He excelled in all shinobi abilities, from ninjutsu, to taijutsu, to genjutsu. This made him a highly influential and powerful figure in Iwagakure.\", \"Description_2\": \"He was highly belligerent and had great experience in battle, allowing him to use advanced tactics to defeat his enemies. He fought using blades attached to his arms. He used his skills while fighting Team Minato, led by Kakashi Hatake. First he tried to extract information from Rin using genjutsu, but this proved unsuccessful. Later when Kakashi and Obito Uchiha attempted to rescue Rin, Kakkou managing to corner them and even kill Obito. However, once Kakashi had received the Sharingan, the tides turned and he was killed by Kakashi\'s Chidori, but not before Kakkou cut in two the famous White Light Chakra Sabre Kakashi had inherited from his father, Sakumo Hatake.\"}'),(164,3178,'Kakuzu','{\"Age\":\"91\",\"From\":\"Takigagure, The Village Hidden in the Waterfall\",\"Weapon\":\"Elemental Clones from his body\",\"Partner\":\"Hidan\",\"Role In Akatsuki\":\"To gather funds (Through Bounties)\",\"Description\":\"A missing-nin from Takigakure and Hidan\\u0027s partner. The first kanji in Kakuzu\\u0027s name stands for kakugy\\u014D, a bishop in shogi. Kakuzu is a greedy individual, prioritizing things in terms of how much they are worth and finding money to be the only thing that he can depend on. Kakuzu\\u0027s favorite source of income is collecting bounties while carrying out other missions, even putting up with Hidan\\u0027s religion since it allows him to collect bounties faster. His history as a bounty hunter seems to be extensive, as he is on friendly terms with a bounty collector and even seems to have memorized the information and worth of some of the more dangerous bounties. This view of money has caused Kakuzu to refer to himself as the \\u0022Treasurer of Akatsuki,\\u0022 though it is unknown if this is an actual position. Kakuzu also has his own personal banker and accountant. Despite his attachment to money, he places the orders of the Akatsuki leader before any opportunity to make a profit. Kakuzu greatly dislikes the fact that he needs a teammate as a member of Akatsuki, due in part to his habit of killing anyone near him (partners included) when enraged. Having killed all of his previous partners as a result of this, Kakuzu was partnered with Hidan. Neither Kakuzu nor Hidan are fond of their partnership, Kakuzu having little patience for Hidan\\u0027s time-consuming battle style and rituals and Hidan, in turn, detesting how Kakuzu fights solely for money. Still, because Hidan is immortal, Kakuzu can attack him without worrying about finding a new partner.\"}','{\"Age\": \"91\", \"From\": \"Takigagure, The Village Hidden in the Waterfall\", \"Weapon\": \"Elemental Clones from his body\", \"Partner\": \"Hidan\", \"Description\": \"A missing-nin from Takigakure and Hidan\'s partner. The first kanji in Kakuzu\'s name stands for kakugyō, a bishop in shogi. Kakuzu is a greedy individual, prioritizing things in terms of how much they are worth and finding money to be the only thing that he can depend on. Kakuzu\'s favorite source of income is collecting bounties while carrying out other missions, even putting up with Hidan\'s religion since it allows him to collect bounties faster. His history as a bounty hunter seems to be extensive, as he is on friendly terms with a bounty collector and even seems to have memorized the information and worth of some of the more dangerous bounties. This view of money has caused Kakuzu to refer to himself as the \\\"Treasurer of Akatsuki,\\\" though it is unknown if this is an actual position. Kakuzu also has his own personal banker and accountant. Despite his attachment to money, he places the orders of the Akatsuki leader before any opportunity to make a profit. Kakuzu greatly dislikes the fact that he needs a teammate as a member of Akatsuki, due in part to his habit of killing anyone near him (partners included) when enraged. Having killed all of his previous partners as a result of this, Kakuzu was partnered with Hidan. Neither Kakuzu nor Hidan are fond of their partnership, Kakuzu having little patience for Hidan\'s time-consuming battle style and rituals and Hidan, in turn, detesting how Kakuzu fights solely for money. Still, because Hidan is immortal, Kakuzu can attack him without worrying about finding a new partner.\", \"Role In Akatsuki\": \"To gather funds (Through Bounties)\"}'),(165,14032,'Kamizuki, Izumo','{\"Description\":\"Izumo is a chuunin of the Village Hidden in the Leaves, partnered with his friend  Kotetsu Hagane, they make their first appearance trying to discourage the genins from the chuunin exams. It is later discovered that they are both proctors in the exams. After the chuunin exams, the fifth hokage takes them both as assistants, doubling them as guards to the main gate of the village.\",\"Description_2\":\"He is hardly ever seen without Kotetsu and they also appear in Shippuden.\"}','{\"Description\": \"Izumo is a chuunin of the Village Hidden in the Leaves, partnered with his friend  Kotetsu Hagane, they make their first appearance trying to discourage the genins from the chuunin exams. It is later discovered that they are both proctors in the exams. After the chuunin exams, the fifth hokage takes them both as assistants, doubling them as guards to the main gate of the village.\", \"Description_2\": \"He is hardly ever seen without Kotetsu and they also appear in Shippuden.\"}'),(166,38460,'Kanabun','{\"Description\":\"Kanabun is the boss of the Kanabun Gang. Him and his gang watched Tsukado\\u0027s fight and loss against Katazu who killed his distant relative, Shikazo. After seeing his hidden swordsman\\u0027s skills after the fight, Kanabun brings Katazu the next day to Tsukado so him and his gang can profit off their fight. When Katazu reveals that he didn\\u0027t kill Shikazo and the fight ends, Kanabun and his gang try to get them fight again by force but are chased out of town by the two swordsmen, Team 7 and Mr. Ostrich with Kanabun saying they\\u0027ll be sorry.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Kanabun is the boss of the Kanabun Gang. Him and his gang watched Tsukado\'s fight and loss against Katazu who killed his distant relative, Shikazo. After seeing his hidden swordsman\'s skills after the fight, Kanabun brings Katazu the next day to Tsukado so him and his gang can profit off their fight. When Katazu reveals that he didn\'t kill Shikazo and the fight ends, Kanabun and his gang try to get them fight again by force but are chased out of town by the two swordsmen, Team 7 and Mr. Ostrich with Kanabun saying they\'ll be sorry.\"}'),(167,39570,'Kandachi','{\"Description\":\"Kandachi (\\u30AB\\u30F3\\u30C0\\u30C1, Kandachi) is a missing-nin from Amegakure and was Hanz\\u014D\\u0027s right hand man.\",\"Description_2\":\"Sometime after Pain killed Hanz\\u014D, Kandachi and a group of Ame ninja fled the country and went into hiding by taking over a village surrounded by a magnetic force that affects a person\\u0027s chakra flow to the brain similar to genjutsu.\",\"Description_3\":\"Like his superior Hanz\\u014D, he fights mainly using the Summoning Technique. He can command the Conch King with hand seals. All of the hand seals performed also give the Conch King a signal to use a specified technique. Kandachi has shown a rare ability to cast a genjutsu on his opponent though the Conch King. The magnetic field caused by the tree strengthens this genjutsu, as the magnetism disrupts a person\\u0027s chakra flow, similar to a genjutsu. Kandachi can also command the Conch King to propel above water by using Wind Release.\",\"Description_4\":\"When Jiraiya brought Naruto Uzumaki to the forest for training, they encounter Tanishi who tells them of Kandachi\\u0027s takeover. Naruto (disguised as Tanishi) and Jiraiya, pretending to be captured, meet with Kandachi, surprised to see Jiraiya again. Naruto\\u0027s cover is blown when the real Tanishi arrives and Kandashi decides to feed the villagers to the Conch King. Naruto fights against Kandachi and the Conch King but their techniques knocks Naruto down every time. In the end, Naruto defeats them both with his first Great Ball Rasengan.\"}','{\"Description\": \"Kandachi (カンダチ, Kandachi) is a missing-nin from Amegakure and was Hanzō\'s right hand man.\", \"Description_2\": \"Sometime after Pain killed Hanzō, Kandachi and a group of Ame ninja fled the country and went into hiding by taking over a village surrounded by a magnetic force that affects a person\'s chakra flow to the brain similar to genjutsu.\", \"Description_3\": \"Like his superior Hanzō, he fights mainly using the Summoning Technique. He can command the Conch King with hand seals. All of the hand seals performed also give the Conch King a signal to use a specified technique. Kandachi has shown a rare ability to cast a genjutsu on his opponent though the Conch King. The magnetic field caused by the tree strengthens this genjutsu, as the magnetism disrupts a person\'s chakra flow, similar to a genjutsu. Kandachi can also command the Conch King to propel above water by using Wind Release.\", \"Description_4\": \"When Jiraiya brought Naruto Uzumaki to the forest for training, they encounter Tanishi who tells them of Kandachi\'s takeover. Naruto (disguised as Tanishi) and Jiraiya, pretending to be captured, meet with Kandachi, surprised to see Jiraiya again. Naruto\'s cover is blown when the real Tanishi arrives and Kandashi decides to feed the villagers to the Conch King. Naruto fights against Kandachi and the Conch King but their techniques knocks Naruto down every time. In the end, Naruto defeats them both with his first Great Ball Rasengan.\"}'),(168,39606,'Kanden, Tekuno','{\"Description\":\"Tekuno Kanden (\\u611F\\u96FB\\u30C6\\u30AF\\u30CE, Kanden Tekuno) is a shinobi of Konohagakure that protected its borders after the Invasion of Konoha.\",\"Description_2\":\"Tekuno has a robust build and has shaggy brown hair. He wears the standard attire of a Konoha shinobi along with fingerless gloves. He also wears his flak jacket unzipped under which he wears a utility sash with his several scrolls.\",\"Description_3\":\"His abilities primarily revolve around the use of heavy explosive artillery and is also highly skilled at setting traps. He was also very skilled at using wires, often incorporating them into his traps. He was so proficient with them that he is able to lay them all over the battlefield then manipulate them in such a way that he could trap multiple enemy in them at once. During a mission he was shown summoning a crossbow that he used to fire projectiles with exploding tags attached to them. Along with this weapon he also summoned a few katana, so it can be assumed that he is skilled at using them.\",\"Description_4\":\"He was assigned to a squad along with Hayama Shirakumo, Kosuke Maruboshi and Naruto Uzumaki to protect the norther boundaries of the village after Suna and Otogakure\\u0027s invasion of the village. During their mission he was assigned to set traps around the area. Not long after they were ambushed by a battalion of ninja from Iwagakure. Tekuno\\u0027s traps proved useful in hindering the progress of the ninja but when they had breached these securities, he stayed behind to allow the other members of the squad time to escape and report to the village. He summoned a crossbow with explosive tags attached to the projectiles and along with Hayama wiped out the majority of the ninja. Together the team was able to wipe out dozens of Iwa ninja.\",\"Description_5\":\"He was later seen helping to restore the village after Pain\\u0027s Invasion bragging about his heroism on the mission.\"}','{\"Description\": \"Tekuno Kanden (感電テクノ, Kanden Tekuno) is a shinobi of Konohagakure that protected its borders after the Invasion of Konoha.\", \"Description_2\": \"Tekuno has a robust build and has shaggy brown hair. He wears the standard attire of a Konoha shinobi along with fingerless gloves. He also wears his flak jacket unzipped under which he wears a utility sash with his several scrolls.\", \"Description_3\": \"His abilities primarily revolve around the use of heavy explosive artillery and is also highly skilled at setting traps. He was also very skilled at using wires, often incorporating them into his traps. He was so proficient with them that he is able to lay them all over the battlefield then manipulate them in such a way that he could trap multiple enemy in them at once. During a mission he was shown summoning a crossbow that he used to fire projectiles with exploding tags attached to them. Along with this weapon he also summoned a few katana, so it can be assumed that he is skilled at using them.\", \"Description_4\": \"He was assigned to a squad along with Hayama Shirakumo, Kosuke Maruboshi and Naruto Uzumaki to protect the norther boundaries of the village after Suna and Otogakure\'s invasion of the village. During their mission he was assigned to set traps around the area. Not long after they were ambushed by a battalion of ninja from Iwagakure. Tekuno\'s traps proved useful in hindering the progress of the ninja but when they had breached these securities, he stayed behind to allow the other members of the squad time to escape and report to the village. He summoned a crossbow with explosive tags attached to the projectiles and along with Hayama wiped out the majority of the ninja. Together the team was able to wipe out dozens of Iwa ninja.\", \"Description_5\": \"He was later seen helping to restore the village after Pain\'s Invasion bragging about his heroism on the mission.\"}'),(169,4694,'Kankurou','{\"Name\":\"Kankurou\",\"Ninja Registration No\":\"54-002\",\"Age\":\"14 (I) ; 18 (II)\",\"Birthday\":\"15 May\",\"Horoscope\":\"Taurus\",\"Bloodtype\":\"B\",\"Height\":\"165 cm (I); 175 cm (II)\",\"Weight\":\"61.2kg(I); 61.2kg (II)\",\"Hair\":\"Brown\",\"Eyes\":\"Black\",\"Rank\":\"Genin (I); Jonin (II)\",\"Likes\":\"Hamburger stakes, collecting puppets\",\"Dislikes\":\"spinach, children\",\"Description\":\"Kankurou is initially characterized by his apparent dislike for children, as seen when he is noticeably irritated while in the presence of someone younger than him. Though, this seems to have gone away as time passed by. This is most evident when he is with Gaara, who Kankurou is forced to put up with due to the fear his younger brother imposes on him. Despite their apparent differences, Gaara and Kankurou become very close over the timeskip as Gaara begins to confide in Kankurou and shares his dreams of wanting to risk his life to protect Sunagakure. As such, Kankurou has become very protective of Gaara, willing to challenge anyone who puts Gaara down in his presence. When Gaara is captured by Akatsuki, Kankurou rushes to his brother\\u0027s aid in an attempt to save him and even after being nearly killed as a result he does not falter in his resolve to find Gaara.\",\"Description_2\":\"Kankurou has shown to be a rather violent and brutal opponent, often leaving his opponents in extreme pain after battle. He is a talented puppeteer, and with each of his appearances in the major arcs is seen with a new puppet in his arsenal. The three puppets that have been introduced were all originally created by Sasori, and came into Kankurou\\u0027s possession some time after the former left Sunagakure. Karasu, the first of Kankurou\\u0027s puppets to make an appearance, has been heavily modified by Kankurou. Because of this it is highly offensive, having numerous concealed weapons and being able to detach any of its limbs for separate attacks. Kuroari, the second of Kankurou\\u0027s puppets to make an appearance, is used to capture opponents for assassination purposes. Once an opponent is captured within it each of Kuroari\\u0027s arms convert to saw-blades and slice through the confined opponent. Sanshouo, the third of Kankurou\\u0027s puppets to make an appearance, is not seen in action in the manga. In the anime, Sanshouo is shown to have a hollow body that Kankurou can take cover in to defend against attacks. These puppets seem to be designed to work together to some degree, as Kankurou frequently uses them in tandem to increase their effectiveness. Karasu, for example, can blanket an area in smoke while Kuroari fires weapons at the blinded opponent.\"}','{\"Age\": \"14 (I) ; 18 (II)\", \"Eyes\": \"Black\", \"Hair\": \"Brown\", \"Name\": \"Kankurou\", \"Rank\": \"Genin (I); Jonin (II)\", \"Likes\": \"Hamburger stakes, collecting puppets\", \"Height\": \"165 cm (I); 175 cm (II)\", \"Weight\": \"61.2kg(I); 61.2kg (II)\", \"Birthday\": \"15 May\", \"Dislikes\": \"spinach, children\", \"Bloodtype\": \"B\", \"Horoscope\": \"Taurus\", \"Description\": \"Kankurou is initially characterized by his apparent dislike for children, as seen when he is noticeably irritated while in the presence of someone younger than him. Though, this seems to have gone away as time passed by. This is most evident when he is with Gaara, who Kankurou is forced to put up with due to the fear his younger brother imposes on him. Despite their apparent differences, Gaara and Kankurou become very close over the timeskip as Gaara begins to confide in Kankurou and shares his dreams of wanting to risk his life to protect Sunagakure. As such, Kankurou has become very protective of Gaara, willing to challenge anyone who puts Gaara down in his presence. When Gaara is captured by Akatsuki, Kankurou rushes to his brother\'s aid in an attempt to save him and even after being nearly killed as a result he does not falter in his resolve to find Gaara.\", \"Description_2\": \"Kankurou has shown to be a rather violent and brutal opponent, often leaving his opponents in extreme pain after battle. He is a talented puppeteer, and with each of his appearances in the major arcs is seen with a new puppet in his arsenal. The three puppets that have been introduced were all originally created by Sasori, and came into Kankurou\'s possession some time after the former left Sunagakure. Karasu, the first of Kankurou\'s puppets to make an appearance, has been heavily modified by Kankurou. Because of this it is highly offensive, having numerous concealed weapons and being able to detach any of its limbs for separate attacks. Kuroari, the second of Kankurou\'s puppets to make an appearance, is used to capture opponents for assassination purposes. Once an opponent is captured within it each of Kuroari\'s arms convert to saw-blades and slice through the confined opponent. Sanshouo, the third of Kankurou\'s puppets to make an appearance, is not seen in action in the manga. In the anime, Sanshouo is shown to have a hollow body that Kankurou can take cover in to defend against attacks. These puppets seem to be designed to work together to some degree, as Kankurou frequently uses them in tandem to increase their effectiveness. Karasu, for example, can blanket an area in smoke while Kuroari fires weapons at the blinded opponent.\", \"Ninja Registration No\": \"54-002\"}'),(170,94813,'Karai','{\"Description\":\"Karai (\\u30AB\\u30E9\\u30A4, Karai) is a shinobi from Kumogakure.\",\"Description_2\":\"While returning from a covert mission in the Sugi Village having stolen their kinjutsu Karai, Nigai and the Fourth Raikage are set upon by the mercenary Nokizaru Group who had been hired to retrieve the scroll. Though they fled, an Exploding Insect was implanted into them microscopically and after they berated the Raikage, an irate Nigai attacked the group only to explode. Following the same vein, Karai attacked them but stopped before he could be killed. Later, Amai, another comrade and medical-nin attempted to heal him but to no avail. Eventually, despite his initial protest, Tsunade was sought out to heal him, and the insect was removed by Shizune while Amai helped conduct the surgery.\",\"Anime Debut\":\"Naruto Shippuuden Episode #286\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #286\", \"Description\": \"Karai (カライ, Karai) is a shinobi from Kumogakure.\", \"Description_2\": \"While returning from a covert mission in the Sugi Village having stolen their kinjutsu Karai, Nigai and the Fourth Raikage are set upon by the mercenary Nokizaru Group who had been hired to retrieve the scroll. Though they fled, an Exploding Insect was implanted into them microscopically and after they berated the Raikage, an irate Nigai attacked the group only to explode. Following the same vein, Karai attacked them but stopped before he could be killed. Later, Amai, another comrade and medical-nin attempted to heal him but to no avail. Eventually, despite his initial protest, Tsunade was sought out to heal him, and the insect was removed by Shizune while Amai helped conduct the surgery.\"}'),(171,3151,'Karin','{\"Age\":\"ll 16-17\",\"Birthday\":\"June 20\",\"Sign\":\"Gemini\",\"Gender\":\"Female\",\"Description\":\"Karin  is a former subordinate of Orochimaru who assisted him in his experimentations and was left in charge of one of his bases while he was away; and was also the only one loyal to Orochimaru to remain even though his current status is questionable. She has red eyes, matching hair color and an unusual hairstyle; her hair is short and unkempt on one side, and long and combed on the other. Karin will at times appear tough and in control and other times she is flirtatious. Karin\\u0027s name means \\u0027intense sulfur\\u0027 and is also a homonym for the fruit \\u0027quince\\u0027.\",\"Description_2\":\"Sasuke Uchiha recruits her as a member of Snake. While Sasuke admits she may be troublesome, he also notes that her special abilities make her useful. She also seems to have a liking for Sasuke, implying to Sasuke that a team consisting of the two of them would be much better than one with Suigetsu or Jugo. Suigetsu noted that something once happened between her and Sasuke though what this means remains unclear, since she punches Suigetsu before he can finish his sentence.\",\"Description_3\":\"Karin\\u0027s special ability allows her to track specific individuals through chakra, seen when she is able to discern that Jugo is not among a crowd of prisoners through the standard concentration pose for molding chakra. It also allows her to pick up chakra from long distances and notice changes in an individual\\u0027s chakra.\"}','{\"Age\": \"ll 16-17\", \"Sign\": \"Gemini\", \"Gender\": \"Female\", \"Birthday\": \"June 20\", \"Description\": \"Karin  is a former subordinate of Orochimaru who assisted him in his experimentations and was left in charge of one of his bases while he was away; and was also the only one loyal to Orochimaru to remain even though his current status is questionable. She has red eyes, matching hair color and an unusual hairstyle; her hair is short and unkempt on one side, and long and combed on the other. Karin will at times appear tough and in control and other times she is flirtatious. Karin\'s name means \'intense sulfur\' and is also a homonym for the fruit \'quince\'.\", \"Description_2\": \"Sasuke Uchiha recruits her as a member of Snake. While Sasuke admits she may be troublesome, he also notes that her special abilities make her useful. She also seems to have a liking for Sasuke, implying to Sasuke that a team consisting of the two of them would be much better than one with Suigetsu or Jugo. Suigetsu noted that something once happened between her and Sasuke though what this means remains unclear, since she punches Suigetsu before he can finish his sentence.\", \"Description_3\": \"Karin\'s special ability allows her to track specific individuals through chakra, seen when she is able to discern that Jugo is not among a crowd of prisoners through the standard concentration pose for molding chakra. It also allows her to pick up chakra from long distances and notice changes in an individual\'s chakra.\"}'),(172,133890,'Karin\'s Mother','{\"Description\":\"Karin\\u0027s Mother was a member of the Uzumaki Clan who lived in Kusagakure.\",\"Description_2\":\"After her home village was destroyed, Karin\\u0027s mother came to Kusagakure while her daughter was still young. The two were allowed to stay, provided that the mother would use her powers to heal the injured of the village.\",\"Description_3\":\"As a direct descendant of the Uzumaki clan, she had a remarkably powerful life-force, granting her immense vitality, longevity, and healing powers. Even more, she could transmit her healing to anyone who bit her and sucked on her chakra, immediately healing any injury.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Karin\'s Mother was a member of the Uzumaki Clan who lived in Kusagakure.\", \"Description_2\": \"After her home village was destroyed, Karin\'s mother came to Kusagakure while her daughter was still young. The two were allowed to stay, provided that the mother would use her powers to heal the injured of the village.\", \"Description_3\": \"As a direct descendant of the Uzumaki clan, she had a remarkably powerful life-force, granting her immense vitality, longevity, and healing powers. Even more, she could transmit her healing to anyone who bit her and sucked on her chakra, immediately healing any injury.\"}'),(173,22874,'Karui','{\"Description\":\"Karui is a kunoichi of Kumogakure, and a member of Team Samui. The team was sent to Konoha by the Fourth Raikage to inform them that they would be taking care of Sasuke Uchiha and Akatsuki. She, along with the other two members of her team, are Killer Bee\\u0027s students.\",\"Description_2\":\"Karui seems to have a somewhat comedic-negative relationship with her teammate, Omoi. During their debut, they argued over the possible reasons that they could have been called by the Raikage. She assumed that he wanted them to get him more protein shakes. However, the argument started with Omoi implying that she is flat-chested in comparison to their teammate, Samui. However, like the rest of her team, she highly respects Killer Bee.\",\"Description_3\":\"Karui is also quite outspoken and allows her emotions to let out, as she angrily yelled at Team Kakashi to allow the renegade Sasuke to run loose. She came to a violent point when she took out her rage on Naruto and beat him.\",\"Description_4\":\"In terms of fighting style, Karui relies mainly on swordplay, and thus would be considered a swordsmanship specialist. She and Omoi use attack combos together with swords, using slick, precise movements as they work well together. Karui has good strength, she punched Naruto hard enough to make him bleed instantly.\",\"Description_5\":\"\\u0022Karui\\u0022 means \\u0022light\\u0022 or \\u0022non-serious\\u0022 in Japanese, as a contrast to Omoi\\u0027s name.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Karui is a kunoichi of Kumogakure, and a member of Team Samui. The team was sent to Konoha by the Fourth Raikage to inform them that they would be taking care of Sasuke Uchiha and Akatsuki. She, along with the other two members of her team, are Killer Bee\'s students.\", \"Description_2\": \"Karui seems to have a somewhat comedic-negative relationship with her teammate, Omoi. During their debut, they argued over the possible reasons that they could have been called by the Raikage. She assumed that he wanted them to get him more protein shakes. However, the argument started with Omoi implying that she is flat-chested in comparison to their teammate, Samui. However, like the rest of her team, she highly respects Killer Bee.\", \"Description_3\": \"Karui is also quite outspoken and allows her emotions to let out, as she angrily yelled at Team Kakashi to allow the renegade Sasuke to run loose. She came to a violent point when she took out her rage on Naruto and beat him.\", \"Description_4\": \"In terms of fighting style, Karui relies mainly on swordplay, and thus would be considered a swordsmanship specialist. She and Omoi use attack combos together with swords, using slick, precise movements as they work well together. Karui has good strength, she punched Naruto hard enough to make him bleed instantly.\", \"Description_5\": \"\\\"Karui\\\" means \\\"light\\\" or \\\"non-serious\\\" in Japanese, as a contrast to Omoi\'s name.\"}'),(174,22248,'Karura','{\"Description\":\"Karura was the wife of the Fourth Kazekage, and the mother of Gaara, Kankur\\u014D, and Temari. Against her wishes, her husband had the spirit of Shukaku sealed within Gaara before he was born. During his birth, her life was used to power the sealing process. Before she died, she cursed Sunagakure, hoping her son would avenge her death and the horror she had been put through.\"}','{\"Description\": \"Karura was the wife of the Fourth Kazekage, and the mother of Gaara, Kankurō, and Temari. Against her wishes, her husband had the spirit of Shukaku sealed within Gaara before he was born. During his birth, her life was used to power the sealing process. Before she died, she cursed Sunagakure, hoping her son would avenge her death and the horror she had been put through.\"}'),(175,38459,'Katazu','{\"Description\":\"Katazu is a swordsman who took his twin brother Kageki\\u0027s identity after the accidental death of Shikazo. Kageki had loaned money to Shikazo but after the birth of his child, he asked to be repaid by him but Shikazo refused and a scuffle broke out which resulted him hitting his head on a rock hard enough to kill him. Kageki went to Katazu after that and he took his brother\\u0027s identity while Kageki and his family went into hiding. Katazu purposely attracted Shikazo\\u0027s pursuers while they went into hiding. Since then, Tsukado was tasked by his clan to carry out a vendetta against him but failed to defeat Katazu 34 times. The next day, Kanabun brought Katazu to Tsukado to profit off their fight. With Naruto\\u0027s help, Tsukado was able to get the advantage but Naruto stopped their fight, noticing that Katazu couldn\\u0027t have killed Shikazo. Katazu reveals the truth to Tsukado and he decides not to kill him. Kanabun and his gang try to force the two to fight again but the swordsmen and Team 7 chase them out of town.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Katazu is a swordsman who took his twin brother Kageki\'s identity after the accidental death of Shikazo. Kageki had loaned money to Shikazo but after the birth of his child, he asked to be repaid by him but Shikazo refused and a scuffle broke out which resulted him hitting his head on a rock hard enough to kill him. Kageki went to Katazu after that and he took his brother\'s identity while Kageki and his family went into hiding. Katazu purposely attracted Shikazo\'s pursuers while they went into hiding. Since then, Tsukado was tasked by his clan to carry out a vendetta against him but failed to defeat Katazu 34 times. The next day, Kanabun brought Katazu to Tsukado to profit off their fight. With Naruto\'s help, Tsukado was able to get the advantage but Naruto stopped their fight, noticing that Katazu couldn\'t have killed Shikazo. Katazu reveals the truth to Tsukado and he decides not to kill him. Kanabun and his gang try to force the two to fight again but the swordsmen and Team 7 chase them out of town.\"}'),(176,22876,'Katou, Dan','{\"Description\":\"Dan was Shizune\\u0027s uncle, the younger brother of one of Shizune\\u0027s parents. After the death of his younger sister, he began advocating for medical ninja to be assigned to every ninja squad. Tsunade shared a similar belief, and the two soon began dating because of it. During their time together Dan shared with Tsunade his dream of becoming Hokage, wanting the title so that he could better protect the villagers of Konoha. Dan was later fatally wounded during the Second Great Shinobi World War, and, despite Tsunade\\u0027s attempts to save him, died of his injuries.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Dan was Shizune\'s uncle, the younger brother of one of Shizune\'s parents. After the death of his younger sister, he began advocating for medical ninja to be assigned to every ninja squad. Tsunade shared a similar belief, and the two soon began dating because of it. During their time together Dan shared with Tsunade his dream of becoming Hokage, wanting the title so that he could better protect the villagers of Konoha. Dan was later fatally wounded during the Second Great Shinobi World War, and, despite Tsunade\'s attempts to save him, died of his injuries.\"}'),(177,7608,'Katsuyu','{\"Description\":\"Katsuyu is the slug queen summon of Tsunade. Compared to Gamabunta and Manda, the summons of Jiraiya and Orochimaru, respectively, Katsuyu is quiet and more subservient to her master. With her Slug Great Division, Katsuyu can divide herself into smaller slugs to evade attacks or to serve small scale functions, and is able quickly reform herself if need be. She can also spit acid for her Tongue Tooth Sticky Acid, which is strong enough to melt through rock.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Katsuyu is the slug queen summon of Tsunade. Compared to Gamabunta and Manda, the summons of Jiraiya and Orochimaru, respectively, Katsuyu is quiet and more subservient to her master. With her Slug Great Division, Katsuyu can divide herself into smaller slugs to evade attacks or to serve small scale functions, and is able quickly reform herself if need be. She can also spit acid for her Tongue Tooth Sticky Acid, which is strong enough to melt through rock.\"}'),(178,94821,'Kayui','{\"Description\":\"Kayui (\\u30AB\\u30E6\\u30A4, Kayui) is a shinobi of Kumogakure.\",\"Description_2\":\"He and the surviving members of Yurui\\u0027s unit regrouped and the de-facto leader Nurui decided that they should flee from Ameyuri Ringo. Though Omoi was against this and an argument ensued as they fled, Kayui attempted to keep the peace between the two. Later when Omoi went to confront Ameyuri, Kayui and Nurui returned with him and were incapacitated by her attack. When the rest of the Third Division arrived and Ameyuri was sealed in the marsh trap they had prepared, Kayui departed with the other members.\",\"Anime Debut\":\"Naruto Shippuuden Episode #289\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #289\", \"Description\": \"Kayui (カユイ, Kayui) is a shinobi of Kumogakure.\", \"Description_2\": \"He and the surviving members of Yurui\'s unit regrouped and the de-facto leader Nurui decided that they should flee from Ameyuri Ringo. Though Omoi was against this and an argument ensued as they fled, Kayui attempted to keep the peace between the two. Later when Omoi went to confront Ameyuri, Kayui and Nurui returned with him and were incapacitated by her attack. When the rest of the Third Division arrived and Ameyuri was sealed in the marsh trap they had prepared, Kayui departed with the other members.\"}'),(179,13454,'Kazamatsuri, Moegi','{\"Description\":\"Moegi is a kunoichi of Konohagakure. She is quite optimistic, free spirited and very confident. She has been described as being spoiled and determined.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Moegi is a kunoichi of Konohagakure. She is quite optimistic, free spirited and very confident. She has been described as being spoiled and determined.\"}'),(180,166809,'Kazami','{\"Description\":\"Kazami is a shinobi from Kusagakure and a teammate of Muyami and Burami.\"}','{\"Description\": \"Kazami is a shinobi from Kusagakure and a teammate of Muyami and Burami.\"}'),(181,8497,'Kidoumaru','{\"Birthday\":\"December 16\",\"Description\":\"Kidoumaru is the spider-like member of the Sound Four; he possesses four extra arms, has the ability to make webs, and even possesses a third eye. Kidoumaru\\u0027s webbing is made of a special type of liquid that is created by infusing body liquid with chakra, making it as strong as steel. Kidoumaru can create a stronger, golden webbing called Spider Sticky Gold that hardens upon contact with oxygen to metal-like quality. Because of the solid nature of this webbing, Kidoumaru can shape it into armor or weapons to aid him in battle.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Birthday\": \"December 16\", \"Description\": \"Kidoumaru is the spider-like member of the Sound Four; he possesses four extra arms, has the ability to make webs, and even possesses a third eye. Kidoumaru\'s webbing is made of a special type of liquid that is created by infusing body liquid with chakra, making it as strong as steel. Kidoumaru can create a stronger, golden webbing called Spider Sticky Gold that hardens upon contact with oxygen to metal-like quality. Because of the solid nature of this webbing, Kidoumaru can shape it into armor or weapons to aid him in battle.\"}'),(182,33792,'Kigiri','{\"Description\":\"Kigiri (\\u9B3C\\u9727) was a shinobi who appeared in the second Naruto Shipp\\u016Bden filler arc.\",\"Description_2\":\"Kigiri appeared quite laid-back compared to other members of the group. Also, he addressed Rinji as Aniki (Brother) on occasion. In addition, he seemed to be a bit of a gambler as he was shown playing cards with Rinji while in the hideout.\"}','{\"Description\": \"Kigiri (鬼霧) was a shinobi who appeared in the second Naruto Shippūden filler arc.\", \"Description_2\": \"Kigiri appeared quite laid-back compared to other members of the group. Also, he addressed Rinji as Aniki (Brother) on occasion. In addition, he seemed to be a bit of a gambler as he was shown playing cards with Rinji while in the hideout.\"}'),(183,33790,'Kihou','{\"Description\":\"Kih\\u014D (\\u9B3C\\u9CF3) is a shinobi who appears in the second Naruto Shipp\\u016Bden filler arc. He seemed rather blunt and went along with Rinji\\u0027s strategies without complaints. Kih\\u014D also feared death to which he referred to as \\u0022going bon\\u0022.\"}','{\"Description\": \"Kihō (鬼鳳) is a shinobi who appears in the second Naruto Shippūden filler arc. He seemed rather blunt and went along with Rinji\'s strategies without complaints. Kihō also feared death to which he referred to as \\\"going bon\\\".\"}'),(184,279533,'Kiji','{\"Description\":\"Both Kiji and his twin brother Sada seem to have very cheerful dispositions and are often seen smiling. The two brothers also tend to sing while they work or if they speak they say the same thing.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Both Kiji and his twin brother Sada seem to have very cheerful dispositions and are often seen smiling. The two brothers also tend to sing while they work or if they speak they say the same thing.\"}'),(185,18473,'Killer Bee','{\"Age\":\"35\",\"Height\":\"192.1 cm\",\"Hair color\":\"white (in manga), blond (in anime)\",\"Classification\":\"Jinchuuriki of the Hachibi\",\"Affiliation\":\"Kumogakure\",\"Description\":\"At a young age, B along with several other children were gathered in order to select a tag partner for A. Out of all the children gathered, B was the only person able to successfully perform the Double Lariat with A. As such he was given the name \\u0022B\\u0022, and A stated they would be brothers from that day on.  After A\\u0027s cousin, the jinchuuriki of Gy\\u016Bki lost control and killed Motoi\\u0027s father along with seven other ninja on that day, B was chosen as its next Jinchuuriki at the age of 5.\",\"Description_2\":\"During the 3rd Great Shinobi World War, he and his brother encounter Minato Namikaze and had a small scuffle with Minato and his squad.\",\"Description_3\":\"Killer Bee is a muscle-bound shinobi from Kumogakure and the Jinchuuriki of the Eight-Tailed Beast. It is hinted he comes from the Yotsuki clan. He appears to dislike light. On his right shoulder, he has a tattoo that says \\u0022iron\\u0022 (\\u9244, tetsu); and on his left cheek, he has a tattoo of a bull\\u0027s horn (correspondingly, the Eight-Tails has horns like a bull, and the left one is missing). He also carries seven swords and has a brother who is the Raikage.\",\"Description_4\":\"It seems that he demands respect from others and asks to be called \\u0022Lord Jinchuuriki\\u0022 (\\u4EBA\\u67F1\\u529B\\u69D8, Jinchuuriki-sama) and his Tailed Beast be called \\u0022Lord Eight-Tails\\u0022 (\\u516B\\u5C3E\\u69D8, Hachibi-sama). He also appears willing to speak in song, more specifically in rap style, even when confronted with potential threats. He will even stop in a middle of a fight to write whatever rhymes come to him. He has a casual relationship with the Eight-tailed Beast, frequently engaging in friendly conversation with it.\",\"Description_5\":\"As a Jinchuuriki, Killer B has a massive chakra pool enough to make Samehada get very excited and betray Kisame, who is known for his massive amounts of chakra. Killer B is one of the few people to have achieved full control over a tailed beast and is known as a Perfect Jinch\\u016Briki because of this feat along with Yagura, the Fourth Mizukage and Naruto Uzumaki.\",\"Description_6\":\"B is the only known, as well as living Jinchuuriki who can at will, transform and remain in his full tailed beast form indefinitely. Because he has a strong relationship with his own tailed beast, it acts as his partner in battle, disturbing his chakra to dispel even genjutsu from the Mangekyou Sharingan.\",\"(Source\":\"Naruto Wikia)\"}','{\"Age\": \"35\", \"Height\": \"192.1 cm\", \"(Source\": \"Naruto Wikia)\", \"Hair color\": \"white (in manga), blond (in anime)\", \"Affiliation\": \"Kumogakure\", \"Description\": \"At a young age, B along with several other children were gathered in order to select a tag partner for A. Out of all the children gathered, B was the only person able to successfully perform the Double Lariat with A. As such he was given the name \\\"B\\\", and A stated they would be brothers from that day on.  After A\'s cousin, the jinchuuriki of Gyūki lost control and killed Motoi\'s father along with seven other ninja on that day, B was chosen as its next Jinchuuriki at the age of 5.\", \"Description_2\": \"During the 3rd Great Shinobi World War, he and his brother encounter Minato Namikaze and had a small scuffle with Minato and his squad.\", \"Description_3\": \"Killer Bee is a muscle-bound shinobi from Kumogakure and the Jinchuuriki of the Eight-Tailed Beast. It is hinted he comes from the Yotsuki clan. He appears to dislike light. On his right shoulder, he has a tattoo that says \\\"iron\\\" (鉄, tetsu); and on his left cheek, he has a tattoo of a bull\'s horn (correspondingly, the Eight-Tails has horns like a bull, and the left one is missing). He also carries seven swords and has a brother who is the Raikage.\", \"Description_4\": \"It seems that he demands respect from others and asks to be called \\\"Lord Jinchuuriki\\\" (人柱力様, Jinchuuriki-sama) and his Tailed Beast be called \\\"Lord Eight-Tails\\\" (八尾様, Hachibi-sama). He also appears willing to speak in song, more specifically in rap style, even when confronted with potential threats. He will even stop in a middle of a fight to write whatever rhymes come to him. He has a casual relationship with the Eight-tailed Beast, frequently engaging in friendly conversation with it.\", \"Description_5\": \"As a Jinchuuriki, Killer B has a massive chakra pool enough to make Samehada get very excited and betray Kisame, who is known for his massive amounts of chakra. Killer B is one of the few people to have achieved full control over a tailed beast and is known as a Perfect Jinchūriki because of this feat along with Yagura, the Fourth Mizukage and Naruto Uzumaki.\", \"Description_6\": \"B is the only known, as well as living Jinchuuriki who can at will, transform and remain in his full tailed beast form indefinitely. Because he has a strong relationship with his own tailed beast, it acts as his partner in battle, disturbing his chakra to dispel even genjutsu from the Mangekyou Sharingan.\", \"Classification\": \"Jinchuuriki of the Hachibi\"}'),(186,3438,'Kimimaro','{\"Birthday\":\"June 15\",\"Description\":\"Kimimaro was the fifth member of the Sound Four, thus temporarily changing their group name to the Sound Five. The original four were forced to accept him against their will, as Kimimaro\\u0027s combat abilities exceeded all of their skills combined. He was the sole survivor of the Kaguya clan, who could manipulate their bodies\\u0027 skeletal frame. The Kaguya clan was wiped out when they attacked Kirigakure, seemingly for no reason other than the desire to kill. Having underestimated their opponent\\u0027s defenses, they were slaughtered to the last man, with only Kimimaro surviving.\",\"NOTE\":\"Though some fans believe that his full name was Kimimaro Kaguya, the second databook only said his name as Kimimaro.\",\"Description_2\":\"Kimimaro was referred to by Orochimaru as the most powerful member of the clan, having \\u0022abilities that even that war-loving clan feared\\u0022. Because of this, he was locked away in a cage for most of his life, only released occasionally when needed to fight other clans.\",\"Description_3\":\"Like many of Orochimaru\\u0027s closest followers, Kimimaro was branded with a cursed seal, which gives him greater power at the expense of his free will. When in his level 2 form, his appearance is similar to that of a dinosaur, with dark gray skin, six large bone spines on the back of his chest, and a long bone spiked tail. He also possesses a great deal of control over his cursed seal, as he is able to control its spread throughout his body without fully activating it. Kimimaro was apparently friends with Jugo at one point, and his control over his cursed seal impressed the latter. Karin claims that Kimimaro was the only one who could stop Jugo without getting hurt.\",\"(Source\":\"Naruto Wikia)\"}','{\"NOTE\": \"Though some fans believe that his full name was Kimimaro Kaguya, the second databook only said his name as Kimimaro.\", \"(Source\": \"Naruto Wikia)\", \"Birthday\": \"June 15\", \"Description\": \"Kimimaro was the fifth member of the Sound Four, thus temporarily changing their group name to the Sound Five. The original four were forced to accept him against their will, as Kimimaro\'s combat abilities exceeded all of their skills combined. He was the sole survivor of the Kaguya clan, who could manipulate their bodies\' skeletal frame. The Kaguya clan was wiped out when they attacked Kirigakure, seemingly for no reason other than the desire to kill. Having underestimated their opponent\'s defenses, they were slaughtered to the last man, with only Kimimaro surviving.\", \"Description_2\": \"Kimimaro was referred to by Orochimaru as the most powerful member of the clan, having \\\"abilities that even that war-loving clan feared\\\". Because of this, he was locked away in a cage for most of his life, only released occasionally when needed to fight other clans.\", \"Description_3\": \"Like many of Orochimaru\'s closest followers, Kimimaro was branded with a cursed seal, which gives him greater power at the expense of his free will. When in his level 2 form, his appearance is similar to that of a dinosaur, with dark gray skin, six large bone spines on the back of his chest, and a long bone spiked tail. He also possesses a great deal of control over his cursed seal, as he is able to control its spread throughout his body without fully activating it. Kimimaro was apparently friends with Jugo at one point, and his control over his cursed seal impressed the latter. Karin claims that Kimimaro was the only one who could stop Jugo without getting hurt.\"}'),(187,65139,'Kinkaku','{\"Description\":\"Kinkaku (\\u91D1\\u89D2, Kinkaku) is one of Kumogakure\\u0027s infamous Gold and Silver Brothers alongside his brother Ginkaku.\",\"Manga Debut\":\"Chapter #525\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #267\",\"(source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #267\", \"(source\": \"Narutopedia)\", \"Description\": \"Kinkaku (金角, Kinkaku) is one of Kumogakure\'s infamous Gold and Silver Brothers alongside his brother Ginkaku.\", \"Manga Debut\": \"Chapter #525\"}'),(188,9244,'Kinuta, Dosu','{\"Age\":\"14 (I)\",\"Birthday\":\"June 12\",\"Blood type\":\"A\",\"Height\":\"156 cm (I)\",\"Weight\":\"48 kg (I)\",\"Description\":\"Dosu is a genin from the Sound Village, and leader of his squad. They were under the direct supervision of Orochimaru during the chunin exams. Dosu uses a sound amplifying device on his left arm, called a melody arm, to increase the vibrations he makes when he hits something, causing damage to the opponents ears and messes up their sense of balance. He is the only member of his squad to advance to the second stage in the chunin exams after defeating Choji Akimichi.\",\"Description_2\":\"He showed dedication to Orochimaru\\u0027s task of killing Sasuke Uchiha, but later became disillusioned after learning that Orochimaru had given Sasuke a cursed seal. Realising that he and his team were actually pawns used to determine Sasuke\\u0027s worth, Dosu\\u0027s outlook changed as he lost any and all loyalty towards Orochimaru and vowed to kill Sasuke for the purpose of undermining Orochimaru. Because of this, he would attempt to take down Gaara prior to the actual match to lessen the obstacles beforehand, a rather rash decision that cost Dosu his life.\",\"(Source\":\"Naruto Wikia)\"}','{\"Age\": \"14 (I)\", \"Height\": \"156 cm (I)\", \"Weight\": \"48 kg (I)\", \"(Source\": \"Naruto Wikia)\", \"Birthday\": \"June 12\", \"Blood type\": \"A\", \"Description\": \"Dosu is a genin from the Sound Village, and leader of his squad. They were under the direct supervision of Orochimaru during the chunin exams. Dosu uses a sound amplifying device on his left arm, called a melody arm, to increase the vibrations he makes when he hits something, causing damage to the opponents ears and messes up their sense of balance. He is the only member of his squad to advance to the second stage in the chunin exams after defeating Choji Akimichi.\", \"Description_2\": \"He showed dedication to Orochimaru\'s task of killing Sasuke Uchiha, but later became disillusioned after learning that Orochimaru had given Sasuke a cursed seal. Realising that he and his team were actually pawns used to determine Sasuke\'s worth, Dosu\'s outlook changed as he lost any and all loyalty towards Orochimaru and vowed to kill Sasuke for the purpose of undermining Orochimaru. Because of this, he would attempt to take down Gaara prior to the actual match to lessen the obstacles beforehand, a rather rash decision that cost Dosu his life.\"}'),(189,62639,'Kiri','{\"Description\":\"Kiri (\\u30AD\\u30EA, Kiri) is a medical-nin from Kirigakure.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #242\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #242\", \"Description\": \"Kiri (キリ, Kiri) is a medical-nin from Kirigakure.\", \"Manga Debut\": \"Chapter #515\"}'),(190,15364,'Kitane','{\"Description\":\"While he was still alive, he was part of the Twelve Guardian Ninja. Ten years before the start of the series, when six of the members tried a coup d\\u0027etat, he alongside Asuma Sarutobi, Chiriku, Nauma, T\\u014Du, and Seito fought against them, only to be killed by Kazuma when Kitane and the three other lightning users tried to use Limelight on Kazuma.\",\"He along with Nauma, T\\u014Du, and Seito were known as the greatest lightning-chakra masters of their time. Like Asuma, his battle style revolved around combining superb taijutsu skill with his elemental affinity through a unique weapon. He used a three-parted metal staff to fight with, that is also able to conduct his lightning based attacks. Kitane could send lightning through the ground to attack by striking his staff into the ground. When separating his staff into three pieces he can use his jutsu Lightning Release\":\"Thunder Binding to form a barrier around a target. When in one of the four cardinal directions, he along with Nauma, T\\u014Du, and Seito could use a jutsu called Limelight to destroy everything within that area to ash.\"}','{\"Description\": \"While he was still alive, he was part of the Twelve Guardian Ninja. Ten years before the start of the series, when six of the members tried a coup d\'etat, he alongside Asuma Sarutobi, Chiriku, Nauma, Tōu, and Seito fought against them, only to be killed by Kazuma when Kitane and the three other lightning users tried to use Limelight on Kazuma.\", \"He along with Nauma, Tōu, and Seito were known as the greatest lightning-chakra masters of their time. Like Asuma, his battle style revolved around combining superb taijutsu skill with his elemental affinity through a unique weapon. He used a three-parted metal staff to fight with, that is also able to conduct his lightning based attacks. Kitane could send lightning through the ground to attack by striking his staff into the ground. When separating his staff into three pieces he can use his jutsu Lightning Release\": \"Thunder Binding to form a barrier around a target. When in one of the four cardinal directions, he along with Nauma, Tōu, and Seito could use a jutsu called Limelight to destroy everything within that area to ash.\"}'),(191,62641,'Kitsuchi','{\"Description\":\"Kitsuchi (\\u9EC4\\u30C4\\u30C1, Kitsuchi) is a shinobi from Iwagakure.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #256\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #256\", \"Description\": \"Kitsuchi (黄ツチ, Kitsuchi) is a shinobi from Iwagakure.\", \"Manga Debut\": \"Chapter #515\"}'),(192,57879,'Kokuou','{\"Description\":\"Kokuou, more commonly known as the Five-Tails or Gobi, is a tailed beast sealed within Han from Iwagakure.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kokuou, more commonly known as the Five-Tails or Gobi, is a tailed beast sealed within Han from Iwagakure.\"}'),(193,52959,'Kokuyou','{\"Description\":\"Appears in episode 235.\"}','{\"Description\": \"Appears in episode 235.\"}'),(194,88301,'Komushi','{\"Description\":\"Komushi (\\u30B3\\u30E0\\u30B7, Komushi) was a young shinobi from Sunagakure.\",\"Description_2\":\"Komushi grew up during the tenure of the Third Kazekage, where he primarily worked as a messenger for Chiyo to her grandson Sasori, with whom he had a friendly relationship. During a border-patrol mission Komushi was wounded and subsequently lost an arm. This was later replaced by Sasori with that of a puppet. Later he ingested some of Sasori\\u0027s poison by mistake and died while Chiyo tried to save him. Because he knew Sasori would be blamed, Komushi\\u0027s last request was that Sasori would not be blamed for his own careless mistake. Due to his mother\\u0027s pleading to bring Komushi back to her, Sasori later turned him into a human puppet.\",\"Anime Debut\":\"Naruto Shippuuden Episode #319\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #319\", \"Description\": \"Komushi (コムシ, Komushi) was a young shinobi from Sunagakure.\", \"Description_2\": \"Komushi grew up during the tenure of the Third Kazekage, where he primarily worked as a messenger for Chiyo to her grandson Sasori, with whom he had a friendly relationship. During a border-patrol mission Komushi was wounded and subsequently lost an arm. This was later replaced by Sasori with that of a puppet. Later he ingested some of Sasori\'s poison by mistake and died while Chiyo tried to save him. Because he knew Sasori would be blamed, Komushi\'s last request was that Sasori would not be blamed for his own careless mistake. Due to his mother\'s pleading to bring Komushi back to her, Sasori later turned him into a human puppet.\"}'),(195,3179,'Konan','{\"Birthdate\":\"February 20\",\"Zodiac sign\":\"Pisces\",\"Gender\":\"Female\",\"Age\":\"Part II: 35\",\"Height\":\"Part II: 169.4 cm\",\"Weight\":\"Part II: 45.3 kg\",\"Blood type\":\"O\",\"Description\":\"Konan is the partner of the Akatsuki leader, Pain, and the only female ninja in Akatsuki. She was orphaned as a child by one of Amegakure\\u0027s many wars, forcing her to fend for herself until being found by Jiraiya. Jiraiya trained Konan to take advantage of her natural talent with origami, and as a result paper is a key component in her battle style. Konan can divide her body into countless numbers of paper sheets, which she controls and reshapes remotely to scout out an area or form weapons for attack. She can even form wings that mirror her title as \\u0022God\\u0027s Angel\\u0022 amongst the villagers of Amegakure, as she often carries out Pain\\u0027s, who has the title of \\u0022God,\\u0022 will. Her abilities are constrained while wet, as paper clings to itself and loses its stiffness.\"}','{\"Age\": \"Part II: 35\", \"Gender\": \"Female\", \"Height\": \"Part II: 169.4 cm\", \"Weight\": \"Part II: 45.3 kg\", \"Birthdate\": \"February 20\", \"Blood type\": \"O\", \"Description\": \"Konan is the partner of the Akatsuki leader, Pain, and the only female ninja in Akatsuki. She was orphaned as a child by one of Amegakure\'s many wars, forcing her to fend for herself until being found by Jiraiya. Jiraiya trained Konan to take advantage of her natural talent with origami, and as a result paper is a key component in her battle style. Konan can divide her body into countless numbers of paper sheets, which she controls and reshapes remotely to scout out an area or form weapons for attack. She can even form wings that mirror her title as \\\"God\'s Angel\\\" amongst the villagers of Amegakure, as she often carries out Pain\'s, who has the title of \\\"God,\\\" will. Her abilities are constrained while wet, as paper clings to itself and loses its stiffness.\", \"Zodiac sign\": \"Pisces\"}'),(196,38458,'Korobi','{\"Description\":\"Korobi is a ninja from Sunagakure and a subordinate of Gaara, along with Yaoki. Korobi was assigned on a mission along with Yaoki and Gaara to stop a group of bandits that were located between Suna and Konoha which Team 7 were also assigned to. He was shown to be cowardly and wimpy when Gaara due to Gaara\\u0027s killing impulses which he got rid of after Suna\\u0027s invasion. When Gaara was caught in a trap by Suna\\u0027s assassination squad, he told Korobi and Yaoki to get away. Naruto runs into them, learning that Gaara was captured and asks them why they abandoned their friend. Korobi and Yaoki both wondered if Gaara is their friend. Korobi and Yaoki both assisted Naruto in rescuing Gaara. After their mission was finished, Gaara asks Korobi and Yaoki what they said to him and they happily say they\\u0027re his friends.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Korobi is a ninja from Sunagakure and a subordinate of Gaara, along with Yaoki. Korobi was assigned on a mission along with Yaoki and Gaara to stop a group of bandits that were located between Suna and Konoha which Team 7 were also assigned to. He was shown to be cowardly and wimpy when Gaara due to Gaara\'s killing impulses which he got rid of after Suna\'s invasion. When Gaara was caught in a trap by Suna\'s assassination squad, he told Korobi and Yaoki to get away. Naruto runs into them, learning that Gaara was captured and asks them why they abandoned their friend. Korobi and Yaoki both wondered if Gaara is their friend. Korobi and Yaoki both assisted Naruto in rescuing Gaara. After their mission was finished, Gaara asks Korobi and Yaoki what they said to him and they happily say they\'re his friends.\"}'),(197,34172,'Kousuke','{\"Description\":\"K\\u014Dsuke (\\u3053\\u3046\\u3059\\u3051) was a young toad that wore goggles. On K\\u014Dsuke\\u0027s back is the kanji word for \\u0022gold\\u0022 (\\u91D1, kin).\",\"Description_2\":\"He seemed to be a very happy and cheerful toad, and took orders almost directly.\"}','{\"Description\": \"Kōsuke (こうすけ) was a young toad that wore goggles. On Kōsuke\'s back is the kanji word for \\\"gold\\\" (金, kin).\", \"Description_2\": \"He seemed to be a very happy and cheerful toad, and took orders almost directly.\"}'),(198,7407,'Kurama','{\"Description\":\"The Nine-Tailed Demon Fox is the most powerful of the tailed beasts, also considered the \\u0022King of the Tailed Beasts.\\u0022 Its power is such that it is regarded as an age-old natural disaster, as a single swipe of one of its nine tails is enough to raise tsunamis and flatten mountains. One of its special abilities is that it has access to close to unlimited sources of chakra.\",\"Description_2\":\"The demon fox\\u0027s attacks were seemingly random, the only apparent reason for its appearances being its attraction to places of human malice. It attacked Konohagakure twelve years before the start of the series. None of the ninja of the village were able to defeat it until the Fourth Hokage, Minato Namikaze, arrived to deal with it. Minato sacrificed his life to seal the fox into the body of his newborn son, Naruto Uzumaki, with the Dead Demon Consuming Seal. Rather than completely seal off the fox\\u0027s great power, however, Minato only sealed away a portion of it, giving Naruto access to the rest for unknown reasons. Prior to performing the seal Minato gave a key to Jiraiya to either strengthen or weaken the seal should the need arise. The seal naturally becomes weaker as the years pass, and in the event that it is broken the demon fox will be released; however, the bond between Naruto and Kyuubi, and the bond between Jinchuuriki (host) and tailed beast in general, is of a such character that if the seal is broken, Naruto will die immediately thereafter. And if Naruto dies, and the seal is not broken, Kyuubi will die with him. Therefore Kyuubi uses some of its chakra to enhance Naruto\\u0027s healing abilities and will sometimes \\u0022take over\\u0022 (lend Naruto its chakra without him asking for it) in order to keep him alive.\"}','{\"Description\": \"The Nine-Tailed Demon Fox is the most powerful of the tailed beasts, also considered the \\\"King of the Tailed Beasts.\\\" Its power is such that it is regarded as an age-old natural disaster, as a single swipe of one of its nine tails is enough to raise tsunamis and flatten mountains. One of its special abilities is that it has access to close to unlimited sources of chakra.\", \"Description_2\": \"The demon fox\'s attacks were seemingly random, the only apparent reason for its appearances being its attraction to places of human malice. It attacked Konohagakure twelve years before the start of the series. None of the ninja of the village were able to defeat it until the Fourth Hokage, Minato Namikaze, arrived to deal with it. Minato sacrificed his life to seal the fox into the body of his newborn son, Naruto Uzumaki, with the Dead Demon Consuming Seal. Rather than completely seal off the fox\'s great power, however, Minato only sealed away a portion of it, giving Naruto access to the rest for unknown reasons. Prior to performing the seal Minato gave a key to Jiraiya to either strengthen or weaken the seal should the need arise. The seal naturally becomes weaker as the years pass, and in the event that it is broken the demon fox will be released; however, the bond between Naruto and Kyuubi, and the bond between Jinchuuriki (host) and tailed beast in general, is of a such character that if the seal is broken, Naruto will die immediately thereafter. And if Naruto dies, and the seal is not broken, Kyuubi will die with him. Therefore Kyuubi uses some of its chakra to enhance Naruto\'s healing abilities and will sometimes \\\"take over\\\" (lend Naruto its chakra without him asking for it) in order to keep him alive.\"}'),(199,64455,'Kuriarare, Kushimaru','{\"Description\":\"Kushimaru Kuriarare (\\u6817\\u9730\\u4E32\\u4E38, Kuriarare Kushimaru) was one of the former members of the Seven Ninja Swordsmen of the Mist and Kirigakure\\u0027s ANBU.\",\"Description_2\":\"Kushimaru possessed the unique longsword Nuibari. With it, he was not only able to precisely pierce multiple enemies in quick succession, but also stitch them together utilising a substantial length of wire attached to the blade. This aptly demonstrated his proficient dexterity while handling this particular needle-like sword, as he was able to repeatedly catch it securely just mere moments after previously forcing the blade through his adversaries.\",\"Manga Debut\":\"Chapter #522\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #265\",\"(Source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #265\", \"(Source\": \"Narutopedia)\", \"Description\": \"Kushimaru Kuriarare (栗霰串丸, Kuriarare Kushimaru) was one of the former members of the Seven Ninja Swordsmen of the Mist and Kirigakure\'s ANBU.\", \"Manga Debut\": \"Chapter #522\", \"Description_2\": \"Kushimaru possessed the unique longsword Nuibari. With it, he was not only able to precisely pierce multiple enemies in quick succession, but also stitch them together utilising a substantial length of wire attached to the blade. This aptly demonstrated his proficient dexterity while handling this particular needle-like sword, as he was able to repeatedly catch it securely just mere moments after previously forcing the blade through his adversaries.\"}'),(200,22881,'Kuromaru','{\"Description\":\"Kuromaru (\\u9ED2\\u4E38) is the canine companion of Tsume Inuzuka. Kuromaru has a wolfish appearance and is missing his left ear and right eye. As his name suggests, his fur is black. He is able to talk. He helps Tsume protect Konoha during both invasions of the village.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Kuromaru (黒丸) is the canine companion of Tsume Inuzuka. Kuromaru has a wolfish appearance and is missing his left ear and right eye. As his name suggests, his fur is black. He is able to talk. He helps Tsume protect Konoha during both invasions of the village.\"}'),(201,23474,'Kurotsuchi','{\"Description\":\"Kurotsuchi is a female shinobi who along with Akatsuchi escorts the Tsuchikage. She refers to Deidara as Deidara-nii (nii-san = big brother), either as family or a sign of respect.\"}','{\"Description\": \"Kurotsuchi is a female shinobi who along with Akatsuchi escorts the Tsuchikage. She refers to Deidara as Deidara-nii (nii-san = big brother), either as family or a sign of respect.\"}'),(202,38455,'Kusune','{\"Description\":\"Kusune is a ninja who possesses Iou\\u0027s ninja tool, Tsuru-Kame. Him along with Gameru asked for ninja tools from Iou but he refused to give his ninja tools to outsiders. Naruto Uzumaki and Neji Hy\\u016Bga fought Kusune and Gameru but were stalemated by Iou\\u0027s prototype ninja tools. Kusune and Gameru were defeated by Tenten when she used Iou\\u0027s latest ninja tool, Jidanda.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Kusune is a ninja who possesses Iou\'s ninja tool, Tsuru-Kame. Him along with Gameru asked for ninja tools from Iou but he refused to give his ninja tools to outsiders. Naruto Uzumaki and Neji Hyūga fought Kusune and Gameru but were stalemated by Iou\'s prototype ninja tools. Kusune and Gameru were defeated by Tenten when she used Iou\'s latest ninja tool, Jidanda.\"}'),(203,100273,'Kyuusuke','{\"Description\":\"Kyuusuke (\\u9CE9\\u52A9, Ky\\u016Bsuke) was once a shinobi from Amegakure and one of the original founding Akatsuki members.\",\"Manga Debut\":\"Chapter #446\",\"Anime Debut\":\"Naruto Shippuuden Episode #173\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #173\", \"Description\": \"Kyuusuke (鳩助, Kyūsuke) was once a shinobi from Amegakure and one of the original founding Akatsuki members.\", \"Manga Debut\": \"Chapter #446\"}'),(204,94983,'Land','{\"Description\":\"Land (\\u30E9\\u30F3\\u30C9, Rando) is a young citizen of the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Land (ランド, Rando) is a young citizen of the Tonika Village.\"}'),(205,66547,'Land of Earth Daimyo','{\"Description\":\"He appears to have an impatient attitude, as seen when he and the other daimy\\u014D awaited the response of the uncertain Water Daimy\\u014D. He prompted him to respond quickly due to the urgency of the impending war.\"}','{\"Description\": \"He appears to have an impatient attitude, as seen when he and the other daimyō awaited the response of the uncertain Water Daimyō. He prompted him to respond quickly due to the urgency of the impending war.\"}'),(206,48837,'Land of Fire Daimyo','{\"The Fire Daimy\\u014D has a fickle and indecisive nature and is easily swayed in his decisions through biases as well as external influences. When situations call for fast, important decisions, he makes his advisers do the whole work\":\"the one who convinces him most is the \\u0022winner\\u0022. He seemingly had a liking for Jiraiya, wanting to choose him as the next Hokage, and was also impressed by Kakashi Hatake\\u0027s reputation.\",\"(Source\":\"Naruto.wikia)\"}','{\"(Source\": \"Naruto.wikia)\", \"The Fire Daimyō has a fickle and indecisive nature and is easily swayed in his decisions through biases as well as external influences. When situations call for fast, important decisions, he makes his advisers do the whole work\": \"the one who convinces him most is the \\\"winner\\\". He seemingly had a liking for Jiraiya, wanting to choose him as the next Hokage, and was also impressed by Kakashi Hatake\'s reputation.\"}'),(207,66549,'Land of Frost Daimyo','{\"Description\":\"He is an elderly man with short, pale purple hair that spikes up at the back, a bristling moustache and a long beard. He wears a hat of sorts which has the symbol of his village on it, similar to a forehead protector. He also squints and wears what appears to be a purple kimono.\"}','{\"Description\": \"He is an elderly man with short, pale purple hair that spikes up at the back, a bristling moustache and a long beard. He wears a hat of sorts which has the symbol of his village on it, similar to a forehead protector. He also squints and wears what appears to be a purple kimono.\"}'),(208,67281,'Land of Lightning Daimyo','{\"Description\":\"He is the daimy\\u014D of the Land of Lightning.\",\"Description_2\":\"During a meeting of the Five Great Shinobi Countries\\u0027 daimy\\u014D, he agreed to the creation of the Allied Shinobi Forces. In the anime, he was requested to convene a Daimy\\u014D Summit by the Fourth Raikage.\",\"Manga Debut\":\"Chapter #488\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #217\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #217\", \"Description\": \"He is the daimyō of the Land of Lightning.\", \"Manga Debut\": \"Chapter #488\", \"Description_2\": \"During a meeting of the Five Great Shinobi Countries\' daimyō, he agreed to the creation of the Allied Shinobi Forces. In the anime, he was requested to convene a Daimyō Summit by the Fourth Raikage.\"}'),(209,97789,'Land of This Daimyo','{\"Description\":\"He was the daimyo of the Land of This.\",\"Description_2\":\"The daimyo was an eating contest\\u0027s viewer alongside his daughter and Shuu. He was in charge to give the prizes to the winners of the contest. During Akatsuki\\u0027s invasion of his country, he was killed during Sasori\\u0027s puppet assault.\",\"Anime Debut\":\"Naruto Shippuuden Episode #309\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #309\", \"Description\": \"He was the daimyo of the Land of This.\", \"Description_2\": \"The daimyo was an eating contest\'s viewer alongside his daughter and Shuu. He was in charge to give the prizes to the winners of the contest. During Akatsuki\'s invasion of his country, he was killed during Sasori\'s puppet assault.\"}'),(210,67283,'Land of Water Daimyo','{\"Description\":\"He is the daimy\\u014D of the Land of Water.\",\"Description_2\":\"During a meeting of the Five Great Shinobi Countries\\u0027 daimy\\u014D he was cautious that the alliance would give shinobi too much power. This prompted the Earth Daimy\\u014D to suggest he didn\\u0027t trust the ninja of his country. He eventually gave his consent to the formation of the alliance, albeit reluctantly.\",\"Manga Debut\":\"Chapter #488\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #218\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #218\", \"Description\": \"He is the daimyō of the Land of Water.\", \"Manga Debut\": \"Chapter #488\", \"Description_2\": \"During a meeting of the Five Great Shinobi Countries\' daimyō he was cautious that the alliance would give shinobi too much power. This prompted the Earth Daimyō to suggest he didn\'t trust the ninja of his country. He eventually gave his consent to the formation of the alliance, albeit reluctantly.\"}'),(211,66543,'Land of Wind Daimyo','{\"Description\":\"He is the current daimy\\u014D of the Land of Wind, replacing the former wind daimy\\u014D. During a meeting of the Five Great Shinobi Countries\\u0027 daimy\\u014D he was the third daimy\\u014D out of the five, who consented to allow the Allied Shinobi Forces to officially form, being wary of \\u0022Madara Uchiha\\u0022\\u0027s position as the leader of Akatsuki.\"}','{\"Description\": \"He is the current daimyō of the Land of Wind, replacing the former wind daimyō. During a meeting of the Five Great Shinobi Countries\' daimyō he was the third daimyō out of the five, who consented to allow the Allied Shinobi Forces to officially form, being wary of \\\"Madara Uchiha\\\"\'s position as the leader of Akatsuki.\"}'),(212,306,'Lee, Rock','{\"Age\":\"Part I: 13-14, Part II: 16-17 Boruto: 32-33\",\"Birthday\":\"November 27\",\"Horoscope\":\"Sagittarius\",\"Blood Type\":\"A\",\"Height\":\"Part I: 158.5 cm-162.5 cm, Part II: 172 cm, Blank Period: 177 cm\",\"Weight\":\"Part I: 46.6 kg-47.5 kg, Part II: 54.7 kg\",\"Hair\":\"Black\",\"Eyes\":\"Black\",\"Rank\":\"Part I: Genin, Part II: Ch\\u016Bnin, Gaiden: J\\u014Dnin\",\"Occupation\":\"Ch\\u016Bnin Exams Proctor (Boruto only)\",\"Academy Grad. Age\":\"12\",\"Ch\\u016Bnin Prom. Age\":\"15\",\"Description\":\"Rock Lee is a fictional character in the anime and manga series Naruto created by Masashi Kishimoto. Kishimoto considers Lee his favorite character to draw, and at first designed Lee to symbolize human weakness.In the anime and manga, Lee is a ninja affiliated with the village of Konohagakure, and is a member of Team Guy, which consists of himself, Neji Hyuga, Tenten, and Might Guy\\u2014the team\\u0027s leader. Unable to use most ninja techniques, Lee dedicates himself to using solely taijutsu, ninja techniques similar to martial arts. Lee dreams of becoming a \\u0022splendid ninja\\u0022 despite his inabilities.\"}','{\"Age\": \"Part I: 13-14, Part II: 16-17 Boruto: 32-33\", \"Eyes\": \"Black\", \"Hair\": \"Black\", \"Rank\": \"Part I: Genin, Part II: Chūnin, Gaiden: Jōnin\", \"Height\": \"Part I: 158.5 cm-162.5 cm, Part II: 172 cm, Blank Period: 177 cm\", \"Weight\": \"Part I: 46.6 kg-47.5 kg, Part II: 54.7 kg\", \"Birthday\": \"November 27\", \"Horoscope\": \"Sagittarius\", \"Blood Type\": \"A\", \"Occupation\": \"Chūnin Exams Proctor (Boruto only)\", \"Description\": \"Rock Lee is a fictional character in the anime and manga series Naruto created by Masashi Kishimoto. Kishimoto considers Lee his favorite character to draw, and at first designed Lee to symbolize human weakness.In the anime and manga, Lee is a ninja affiliated with the village of Konohagakure, and is a member of Team Guy, which consists of himself, Neji Hyuga, Tenten, and Might Guy—the team\'s leader. Unable to use most ninja techniques, Lee dedicates himself to using solely taijutsu, ninja techniques similar to martial arts. Lee dreams of becoming a \\\"splendid ninja\\\" despite his inabilities.\", \"Academy Grad. Age\": \"12\", \"Chūnin Prom. Age\": \"15\"}'),(213,94975,'Leo','{\"Description\":\"Leo (\\u30EC\\u30AA, Reo) is a young citizen of the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Leo (レオ, Reo) is a young citizen of the Tonika Village.\"}'),(214,41210,'Maboroshi, Kisuke','{\"Debut\":\"Naruto Shippuuden Episode #193\",\"Description\":\"Kisuke Maboroshi was a member of Konohagakure\\u0027s ANBU.\",\"(Source\":\"Naruto Wikia)\"}','{\"Debut\": \"Naruto Shippuuden Episode #193\", \"(Source\": \"Naruto Wikia)\", \"Description\": \"Kisuke Maboroshi was a member of Konohagakure\'s ANBU.\"}'),(215,33736,'Mabui','{\"Description\":\"The Fourth Raikage\\u0027s assistant acts as a go-between for the Raikage and Kumogakure\\u0027s forces, giving them his orders and keeping him updated on their progress.\",\"Description_2\":\"She\\u0027s a dark-skinned girl who is seen wearing a very formal attire during work hours, long earrings, and properly pulling her light-gray hair back into a bun except for the frontal part of it, which consists of two flat side bangs that fall along the sides of her face.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"The Fourth Raikage\'s assistant acts as a go-between for the Raikage and Kumogakure\'s forces, giving them his orders and keeping him updated on their progress.\", \"Description_2\": \"She\'s a dark-skinned girl who is seen wearing a very formal attire during work hours, long earrings, and properly pulling her light-gray hair back into a bun except for the frontal part of it, which consists of two flat side bangs that fall along the sides of her face.\"}'),(216,256932,'Madam Shijimi','{\"Description\":\"Madam Shijimi is the wife of the daimyou of the Land of Fire. Team Kakashi in Part I and Team Ebisu in Part II are assigned to find her lost cat, Tora, soon after becoming genin.\",\"Description_2\":\"She has been described as spendthrift, vain, and philanthropistic. She also loves her cat a lot, although the cat clearly does not share the same degree of affection to her.\",\"Description_3\":\"Madam Shijimi is a corpulent woman with dark brown hair that she keeps in three separate poofs. She wears pink lipstick, pink nail-polish and purple eyeshadow. She also wears many different colored rings.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Madam Shijimi is the wife of the daimyou of the Land of Fire. Team Kakashi in Part I and Team Ebisu in Part II are assigned to find her lost cat, Tora, soon after becoming genin.\", \"Description_2\": \"She has been described as spendthrift, vain, and philanthropistic. She also loves her cat a lot, although the cat clearly does not share the same degree of affection to her.\", \"Description_3\": \"Madam Shijimi is a corpulent woman with dark brown hair that she keeps in three separate poofs. She wears pink lipstick, pink nail-polish and purple eyeshadow. She also wears many different colored rings.\"}'),(217,64447,'Maki','{\"Description\":\"Maki (\\u30DE\\u30AD, Maki) is a kunoichi from Sunagakure.\",\"Manga Debut\":\"Chapter #270\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #12\",\"(source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #12\", \"(source\": \"Narutopedia)\", \"Description\": \"Maki (マキ, Maki) is a kunoichi from Sunagakure.\", \"Manga Debut\": \"Chapter #270\"}'),(218,37929,'Manda','{\"Description\":\"Manda is the personal summon of Orochimaru.\",\"Description_2\":\"Manda was the largest snake in the world, before being recently out-sized by his clone, Manda II. He easily towers over buildings, trees, and large rock formations. Due to his length, he is even larger than Gamabunta and Katsuyu, easily coiling around Katsuyu and having more length behind him, and he could open his jaws wide enough to swallow Gamabunta whole.\",\"Description_3\":\"He is colored purple, and has black rings running down intervals on his body. He has massive fangs, though they are arranged in a way similar to that of a constrictor snake instead of a viper or other venomous snake species, presumably carrying venom in them from the way they were designed, and green eyes. He also has four horn-like protrusions on his head.\"}','{\"Description\": \"Manda is the personal summon of Orochimaru.\", \"Description_2\": \"Manda was the largest snake in the world, before being recently out-sized by his clone, Manda II. He easily towers over buildings, trees, and large rock formations. Due to his length, he is even larger than Gamabunta and Katsuyu, easily coiling around Katsuyu and having more length behind him, and he could open his jaws wide enough to swallow Gamabunta whole.\", \"Description_3\": \"He is colored purple, and has black rings running down intervals on his body. He has massive fangs, though they are arranged in a way similar to that of a constrictor snake instead of a viper or other venomous snake species, presumably carrying venom in them from the way they were designed, and green eyes. He also has four horn-like protrusions on his head.\"}'),(219,39604,'Maruboshi, Kosuke','{\"Description\":\"Kosuke Maruboshi (\\u307E\\u308B\\u307C\\u3057\\u30B3\\u30B9\\u30B1, Maruboshi Kosuke) is a genin of Konohagakure, whom others called the Ten-Thousand-Year Genin (\\u4E07\\u5E74\\u4E0B\\u5FCD, Mannen Genin).\",\"Description_2\":\"Kosuke has been a genin for over fifty years, thus the reason others called him the Ten-Thousand-Year Genin. When he was still a child, he made a reckless decision that cost him the lives of his teammates. Feeling ashamed of this, he felt he was not worthy of being promoted beyond the rank of genin. Despite this, he continued to train arduously to improve his skills, something that was insisted upon him by Tobirama Senju. During his time as a ninja, he had served under the Second, Third, and Fourth Hokage and now apparently even the Fifth Hokage. At other points, he fought alongside Jiraiya and Sakumo Hatake.\",\"Description_3\":\"Kosuke is an elderly man with his once black hair now grayed which he wears in a short ponytail. He wears a mesh armor shirt under a short brown sleeveless kimono as well as gray pants. He is usually seen with a smile on his face. He carries a metal pan that he uses for multiple reasons ranging from cooking in while out on missions to a weapon during battle. He also carries a ladle and a sword sheathed horizontally across his lower back.\",\"Description_4\":\"Even though his official ranks is that of genin, he is skilled enough to become a J\\u014Dnin; a promotion he declined time and time again. He has shown considerable taijutsu skill, able to use only his cooking-ware to defend and maneuver against enemy attacks. He is also a skilled kenjutsu fighter and wields a sword and a hidden blade concealed in his prosthetic left leg, both of which he can use to strike with deadly precision. He also demonstrated the use of a unique technique which incorporated genjutsu along with kenjutsu to confuse and petrify his opponent, making it easier to strike them down.\",\"When he was younger, he was taught many techniques by the Second and Third Hokage. His training under the Second has given him highly proficient skill in high caliber water release techniques, allowing him to use techniques such as the Water Release\":\"Water Dragon Bullet Technique and Water Release: Water Encampment Wall. He also learned the Shuriken Shadow Clone Technique from the Third Hokage.\",\"Description_5\":\"In addition to combat skills, Kosuke is a highly capable survival expert and cook.\",\"Description_6\":\"He was placed on a team alongside Hayama Shirakumo, Tekuno Kanden and Naruto Uzumaki to guard the borders of the village after Orochimaru and Sunagakure\\u0027s invasion of the village. He remarked that Minato had left behind a fine son, showing that he was one of the few people who was aware of Naruto\\u0027s lineage.\"}','{\"Description\": \"Kosuke Maruboshi (まるぼしコスケ, Maruboshi Kosuke) is a genin of Konohagakure, whom others called the Ten-Thousand-Year Genin (万年下忍, Mannen Genin).\", \"Description_2\": \"Kosuke has been a genin for over fifty years, thus the reason others called him the Ten-Thousand-Year Genin. When he was still a child, he made a reckless decision that cost him the lives of his teammates. Feeling ashamed of this, he felt he was not worthy of being promoted beyond the rank of genin. Despite this, he continued to train arduously to improve his skills, something that was insisted upon him by Tobirama Senju. During his time as a ninja, he had served under the Second, Third, and Fourth Hokage and now apparently even the Fifth Hokage. At other points, he fought alongside Jiraiya and Sakumo Hatake.\", \"Description_3\": \"Kosuke is an elderly man with his once black hair now grayed which he wears in a short ponytail. He wears a mesh armor shirt under a short brown sleeveless kimono as well as gray pants. He is usually seen with a smile on his face. He carries a metal pan that he uses for multiple reasons ranging from cooking in while out on missions to a weapon during battle. He also carries a ladle and a sword sheathed horizontally across his lower back.\", \"Description_4\": \"Even though his official ranks is that of genin, he is skilled enough to become a Jōnin; a promotion he declined time and time again. He has shown considerable taijutsu skill, able to use only his cooking-ware to defend and maneuver against enemy attacks. He is also a skilled kenjutsu fighter and wields a sword and a hidden blade concealed in his prosthetic left leg, both of which he can use to strike with deadly precision. He also demonstrated the use of a unique technique which incorporated genjutsu along with kenjutsu to confuse and petrify his opponent, making it easier to strike them down.\", \"Description_5\": \"In addition to combat skills, Kosuke is a highly capable survival expert and cook.\", \"Description_6\": \"He was placed on a team alongside Hayama Shirakumo, Tekuno Kanden and Naruto Uzumaki to guard the borders of the village after Orochimaru and Sunagakure\'s invasion of the village. He remarked that Minato had left behind a fine son, showing that he was one of the few people who was aware of Naruto\'s lineage.\", \"When he was younger, he was taught many techniques by the Second and Third Hokage. His training under the Second has given him highly proficient skill in high caliber water release techniques, allowing him to use techniques such as the Water Release\": \"Water Dragon Bullet Technique and Water Release: Water Encampment Wall. He also learned the Shuriken Shadow Clone Technique from the Third Hokage.\"}'),(220,57871,'Matatabi','{\"Description\":\"Matatabi, more commonly known as the Two-Tails or Nibi, is a tailed beast sealed within Yugito Nii of Kumogakure. It has been captured by Hidan and Kakuzu, then extracted and sealed by Akatsuki.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Matatabi, more commonly known as the Two-Tails or Nibi, is a tailed beast sealed within Yugito Nii of Kumogakure. It has been captured by Hidan and Kakuzu, then extracted and sealed by Akatsuki.\"}'),(221,7310,'Matsuri','{\"Matsuri is one of the first students of the Sunagakure ninja school modeled after the one in Konoha. She chooses Gaara as her teacher, despite his lingering status as the village\\u0027s weapon. When it comes time to begin training her with a weapon, Gaara suggests she uses a jouhyou, it being the safest of all the available options. She is initially fearful of weapons after the murders of her parents, yet becomes accustomed to them after realizing they can be used to help others. She is the first of the anime\\u0027s filler characters to make an appearance in Naruto\":\"Shippuden, where she joins a Sunagakure rescue team meant to rescue Gaara after his capture. She becomes somewhat outspoken over the timeskip, as she complains when her team spends its time protecting Sunagakure\\u0027s borders rather than trying to save Gaara. She later appears during Gaara\\u0027s revival, praising him and boasting about his powers.\"}','{\"Matsuri is one of the first students of the Sunagakure ninja school modeled after the one in Konoha. She chooses Gaara as her teacher, despite his lingering status as the village\'s weapon. When it comes time to begin training her with a weapon, Gaara suggests she uses a jouhyou, it being the safest of all the available options. She is initially fearful of weapons after the murders of her parents, yet becomes accustomed to them after realizing they can be used to help others. She is the first of the anime\'s filler characters to make an appearance in Naruto\": \"Shippuden, where she joins a Sunagakure rescue team meant to rescue Gaara after his capture. She becomes somewhat outspoken over the timeskip, as she complains when her team spends its time protecting Sunagakure\'s borders rather than trying to save Gaara. She later appears during Gaara\'s revival, praising him and boasting about his powers.\"}'),(222,23830,'Mifune','{\"Description\":\"Mifune is the leader of the Iron Country.\"}','{\"Description\": \"Mifune is the leader of the Iron Country.\"}'),(223,307,'Might, Guy','{\"Age\":\"30\",\"Birthday\":\"1 January\",\"Horoscope\":\"Capricorn\",\"Bloodtype\":\"B\",\"Height\":\"184 cm\",\"Weight\":\"76 kg\",\"Rank\":\"Jonin\",\"Likes\":\"Curry and rice, curry udon noodle, Lee, playing catch, repetitive sideways jump\",\"Description\":\"He is the leader of Team Guy, consisting of Rock Lee, Neji Hyuga, and Tenten.\",\"Description_2\":\"Guy, and by extension Lee, lives his life by his own \\u0022My Rules\\u0022 philosophy, which involves setting tougher self-imposed penalties for failure so something good comes of it. For example, he vowed to walk 500 laps around Konoha on his hands if he lost a contest with Kakashi, and proceeded to do so upon losing, even though people eventually stopped paying attention. He also doesn\\u0027t hesitate to do things he doesn\\u0027t enjoy or that others might find embarrassing if it means his own self-improvement, as seen with his belief that one cannot dislike food regardless of its ingredients or taste. In addition, Guy values his youth to a great degree and dislikes the idea that he may not be as young as he once was. To help remedy this problem he spends large amounts of time with his younger teammates, hoping to acquire some of their youthful properties. Likewise, he often refers to himself as \\u0022Konoha\\u0027s Prideful Green Beast\\u0022.\",\"Description_3\":\"Guy is the self-proclaimed rival of Kakashi Hatake. Kakashi, however, is indifferent to their rivalry, which annoys Guy to no end. Kakashi also seems to have a habit of unintentionally ignoring Guy when Guy is lecturing him, which usually results in Guy asking himselif why Kakashi \\u0022has to act so cool\\u0022. Guy randomly challenges Kakashi to contests of skill, and has acquired a record of 50 wins and 49 losses in doing so.\"}','{\"Age\": \"30\", \"Rank\": \"Jonin\", \"Likes\": \"Curry and rice, curry udon noodle, Lee, playing catch, repetitive sideways jump\", \"Height\": \"184 cm\", \"Weight\": \"76 kg\", \"Birthday\": \"1 January\", \"Bloodtype\": \"B\", \"Horoscope\": \"Capricorn\", \"Description\": \"He is the leader of Team Guy, consisting of Rock Lee, Neji Hyuga, and Tenten.\", \"Description_2\": \"Guy, and by extension Lee, lives his life by his own \\\"My Rules\\\" philosophy, which involves setting tougher self-imposed penalties for failure so something good comes of it. For example, he vowed to walk 500 laps around Konoha on his hands if he lost a contest with Kakashi, and proceeded to do so upon losing, even though people eventually stopped paying attention. He also doesn\'t hesitate to do things he doesn\'t enjoy or that others might find embarrassing if it means his own self-improvement, as seen with his belief that one cannot dislike food regardless of its ingredients or taste. In addition, Guy values his youth to a great degree and dislikes the idea that he may not be as young as he once was. To help remedy this problem he spends large amounts of time with his younger teammates, hoping to acquire some of their youthful properties. Likewise, he often refers to himself as \\\"Konoha\'s Prideful Green Beast\\\".\", \"Description_3\": \"Guy is the self-proclaimed rival of Kakashi Hatake. Kakashi, however, is indifferent to their rivalry, which annoys Guy to no end. Kakashi also seems to have a habit of unintentionally ignoring Guy when Guy is lecturing him, which usually results in Guy asking himselif why Kakashi \\\"has to act so cool\\\". Guy randomly challenges Kakashi to contests of skill, and has acquired a record of 50 wins and 49 losses in doing so.\"}'),(224,103209,'Might, Dai','{\"Description\":\"Might Dai was a genin-ranked shinobi of Konohagakure and the father of Might Guy.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Might Dai was a genin-ranked shinobi of Konohagakure and the father of Might Guy.\"}'),(225,94977,'Miina','{\"Description\":\"Miina (\\u30DF\\u30A3\\u30CA, Miina) is a young citizen of the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Miina (ミィナ, Miina) is a young citizen of the Tonika Village.\"}'),(226,161528,'Minazuki, Yuuki','{\"Description\":\"A jounin from Konohagakure, and the former leader of Team 2 which Itachi belonged to as a genin.\"}','{\"Description\": \"A jounin from Konohagakure, and the former leader of Team 2 which Itachi belonged to as a genin.\"}'),(227,153758,'Miru','{}','{}'),(228,809,'Mitarashi, Anko','{\"Birthday\":\"October 24\",\"Zodiac Sign\":\"Scorpio\",\"Age\":\"24\",\"Height\":\"167cm\",\"Weight\":\"45.8kg\",\"Blood type\":\"A\",\"Occupation\":\"Chuunin Examiner\",\"Description\":\"Anko Mitarashi is the proctor for the second exam of the Chuunin Selection Exams and leader of the Infiltration and Reconnaissance Party.\",\"Description_2\":\"Anko was once the student of Orochimaru. Later she, along with nine others, were branded with Orochimaru\\u0027s first ten samples of the Cursed Seal of Heaven. Of the ten, Anko was the only one to survive, establishing the one-in-ten chance of surviving the Cursed Seal. Orochimaru supposedly rejected Anko as a subordinate, believing she did not have the lust for power or vengeance needed to fuel the Cursed Seal. Orochimaru lost interest in her, though he believed there was some value in letting her live. In the anime, after learning of her past, she was glad to discover that she wasn\\u0027t tossed away like trash as she first had thought by Orochimaru, but chose to leave Orochimaru herself.\",\"Description_3\":\"Anko is easygoing, tomboyish, playful, stubborn, and sometimes hyperactive, making her very similar to Naruto Uzumaki in many ways. Despite portraying several \\u0022Naruto-like\\u0022 habits, she has shown to be very knowledgeable and studious.\",\"Description_4\":\"However, she is also shown to have a bloodthirsty (in a literal sense) side, as shown when she scratched Naruto\\u0027s face with a kunai, and licked away his blood. This probably comes from her time with Orochimaru. She regularly makes sure to have at least basic knowledge of the landscape for which her next mission will take place.\",\"Description_5\":\"As shown in flashbacks during the Land of Sea arc, Anko greatly admired Orochimaru while under his tutelage, seeing him as a role model and was inspired to be more like him. After being branded by Orochimaru with the Curse Seal, Anko became enraged and carried a deep loathing for her former teacher. From there on, Anko continues to search for Orochimaru in hopes of taking him down, feeling that it is her duty as his former subordinate to stop him, even at the cost of her life.\"}','{\"Age\": \"24\", \"Height\": \"167cm\", \"Weight\": \"45.8kg\", \"Birthday\": \"October 24\", \"Blood type\": \"A\", \"Occupation\": \"Chuunin Examiner\", \"Description\": \"Anko Mitarashi is the proctor for the second exam of the Chuunin Selection Exams and leader of the Infiltration and Reconnaissance Party.\", \"Zodiac Sign\": \"Scorpio\", \"Description_2\": \"Anko was once the student of Orochimaru. Later she, along with nine others, were branded with Orochimaru\'s first ten samples of the Cursed Seal of Heaven. Of the ten, Anko was the only one to survive, establishing the one-in-ten chance of surviving the Cursed Seal. Orochimaru supposedly rejected Anko as a subordinate, believing she did not have the lust for power or vengeance needed to fuel the Cursed Seal. Orochimaru lost interest in her, though he believed there was some value in letting her live. In the anime, after learning of her past, she was glad to discover that she wasn\'t tossed away like trash as she first had thought by Orochimaru, but chose to leave Orochimaru herself.\", \"Description_3\": \"Anko is easygoing, tomboyish, playful, stubborn, and sometimes hyperactive, making her very similar to Naruto Uzumaki in many ways. Despite portraying several \\\"Naruto-like\\\" habits, she has shown to be very knowledgeable and studious.\", \"Description_4\": \"However, she is also shown to have a bloodthirsty (in a literal sense) side, as shown when she scratched Naruto\'s face with a kunai, and licked away his blood. This probably comes from her time with Orochimaru. She regularly makes sure to have at least basic knowledge of the landscape for which her next mission will take place.\", \"Description_5\": \"As shown in flashbacks during the Land of Sea arc, Anko greatly admired Orochimaru while under his tutelage, seeing him as a role model and was inspired to be more like him. After being branded by Orochimaru with the Curse Seal, Anko became enraged and carried a deep loathing for her former teacher. From there on, Anko continues to search for Orochimaru in hopes of taking him down, feeling that it is her duty as his former subordinate to stop him, even at the cost of her life.\"}'),(229,22648,'Mitokado, Homura','{\"Description\":\"Homura Mitokado is a former member of Team Tobirama, together with Hiruzen Sarutobi and Koharu Utatane. He and Koharu now form the Konoha Council.\",\"Description_2\":\"Ever since their childhood, Homura and Hiruzen Sarutobi have been close friends. Under the guidance of the Second Hokage, Tobirama Senju, they and their third teammate, Koharu Utatane, have completed numerous missions together. When Hiruzen became the Third Hokage, Homura and Koharu became his councilors. With their years of experience and knowledge and their unending effort to make Konohagakure a better place, they eventually gained similar respect and social status as the Hokage himself. Thanks to his prudence and efficiency, Homura especially has gained the absolute faith of the Konoha shinobi.\"}','{\"Description\": \"Homura Mitokado is a former member of Team Tobirama, together with Hiruzen Sarutobi and Koharu Utatane. He and Koharu now form the Konoha Council.\", \"Description_2\": \"Ever since their childhood, Homura and Hiruzen Sarutobi have been close friends. Under the guidance of the Second Hokage, Tobirama Senju, they and their third teammate, Koharu Utatane, have completed numerous missions together. When Hiruzen became the Third Hokage, Homura and Koharu became his councilors. With their years of experience and knowledge and their unending effort to make Konohagakure a better place, they eventually gained similar respect and social status as the Hokage himself. Thanks to his prudence and efficiency, Homura especially has gained the absolute faith of the Konoha shinobi.\"}'),(230,728,'Momochi, Zabuza','{\"Description\":\"Momochi, Zabuza was born in Kirigakure. During one of Kirigakure\\u0027s annual events of pitting graduating ninja against each other, Zabuza singlehandedly killed all of his peers, bringing an end to the ritual and causing him to be called the \\u0022Demon of the Hidden Mist\\u0022. Zabuza would go on to become one of the Seven Shinobi Swordsmen of the Mist where he acquired his zanbat\\u014D, and also became a member of the Kirigakure ANBU. At some point in time, Zabuza found a young boy named Haku wandering the countryside, and offered to take Haku in as his tool. Haku accepted and became loyal to Zabuza, learning from Zabuza and protecting him whenever necessary. Zabuza eventually attempted a coup d\\u0027\\u00E9tat on the Land of Water by trying to assassinate the Mizukage. The coup failed, forcing Zabuza and his subordinates to leave the country. In the hopes of gaining funds for a second coup, Zabuza became a hired assassin, killing anyone if the price was right.\",\"Being from Kirigakure, Zabuza excels in water-oriented jutsu, some of which are exclusive to him. With Water Release\":\"Water Dragon Blast Technique (Suiton: Suiry\\u016Bdan no Jutsu, Viz \\u0022Water Release: Water Dragon Missile\\u0022) he can form a dragon from the surrounding water to attack others as needed. His Water Release: Great Waterfall Technique (Suiton: Daibakufu no Jutsu, English TV \\u0022Water Style: Giant Vortex Jutsu\\u0022) allows him to fire a massive spiraling blast of water at an opponent. In addition to the offensive capabilities of his water jutsu, Zabuza is very skilled in assassinations. By blanketing the area in mist with Hiding Mist Technique (Kirigakure no Jutsu, Viz \\u0022Art of Hiding in the Mist\\u0022), Zabuza can blind an opponent and use his training as an ANBU to find them based on the sounds they make. Once found, Zabuza uses Silent Homicide Technique (Muon Satsujin Jutsu, English TV \\u0022Silent Killing Jutsu\\u0022) to kill the opponent without their noticing his presence. This talent with assassinations is very well-known, as even the ninja of Konohagakure are familiar with Zabuza\\u0027s history.\"}','{\"Description\": \"Momochi, Zabuza was born in Kirigakure. During one of Kirigakure\'s annual events of pitting graduating ninja against each other, Zabuza singlehandedly killed all of his peers, bringing an end to the ritual and causing him to be called the \\\"Demon of the Hidden Mist\\\". Zabuza would go on to become one of the Seven Shinobi Swordsmen of the Mist where he acquired his zanbatō, and also became a member of the Kirigakure ANBU. At some point in time, Zabuza found a young boy named Haku wandering the countryside, and offered to take Haku in as his tool. Haku accepted and became loyal to Zabuza, learning from Zabuza and protecting him whenever necessary. Zabuza eventually attempted a coup d\'état on the Land of Water by trying to assassinate the Mizukage. The coup failed, forcing Zabuza and his subordinates to leave the country. In the hopes of gaining funds for a second coup, Zabuza became a hired assassin, killing anyone if the price was right.\", \"Being from Kirigakure, Zabuza excels in water-oriented jutsu, some of which are exclusive to him. With Water Release\": \"Water Dragon Blast Technique (Suiton: Suiryūdan no Jutsu, Viz \\\"Water Release: Water Dragon Missile\\\") he can form a dragon from the surrounding water to attack others as needed. His Water Release: Great Waterfall Technique (Suiton: Daibakufu no Jutsu, English TV \\\"Water Style: Giant Vortex Jutsu\\\") allows him to fire a massive spiraling blast of water at an opponent. In addition to the offensive capabilities of his water jutsu, Zabuza is very skilled in assassinations. By blanketing the area in mist with Hiding Mist Technique (Kirigakure no Jutsu, Viz \\\"Art of Hiding in the Mist\\\"), Zabuza can blind an opponent and use his training as an ANBU to find them based on the sounds they make. Once found, Zabuza uses Silent Homicide Technique (Muon Satsujin Jutsu, English TV \\\"Silent Killing Jutsu\\\") to kill the opponent without their noticing his presence. This talent with assassinations is very well-known, as even the ninja of Konohagakure are familiar with Zabuza\'s history.\"}'),(231,94807,'Monga','{\"Description\":\"Monga (\\u30E2\\u30F3\\u30AC, Monga) was a shinobi of Iwagakure.\",\"Description_2\":\"As the reincarnated shinobi reappear on the battlefield, most of the Third Division is scattered into small squads. Monga leads a squad consisting of Maki and Ruka that is assigned to protect the Medical, Sealing and Intel squad members. Gari confronts the squad who Monga thought he would never face in battle. Disappointed in Gari\\u0027s attitude of being okay with being controlled, Monga battles his former comrade and blows him to bits with rocks by pushing a mud wall placed with explosive tags. Monga instructed Maki to seal Gari, but he is caught in a sneak attack by Pakura, and ultimately mummified.\",\"Anime Debut\":\"Naruto Shippuuden Episode #285\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #285\", \"Description\": \"Monga (モンガ, Monga) was a shinobi of Iwagakure.\", \"Description_2\": \"As the reincarnated shinobi reappear on the battlefield, most of the Third Division is scattered into small squads. Monga leads a squad consisting of Maki and Ruka that is assigned to protect the Medical, Sealing and Intel squad members. Gari confronts the squad who Monga thought he would never face in battle. Disappointed in Gari\'s attitude of being okay with being controlled, Monga battles his former comrade and blows him to bits with rocks by pushing a mud wall placed with explosive tags. Monga instructed Maki to seal Gari, but he is caught in a sneak attack by Pakura, and ultimately mummified.\"}'),(232,22923,'Morino, Ibiki','{\"Description\":\"Ibiki Morino (\\u68EE\\u4E43\\u30A4\\u30D3\\u30AD, Morino Ibiki) is the examiner for the first part of the Ch\\u016Bnin Exams and the head of the Konoha\\u0027s ANBU Torture and Interrogation Force.\"}','{\"Description\": \"Ibiki Morino (森乃イビキ, Morino Ibiki) is the examiner for the first part of the Chūnin Exams and the head of the Konoha\'s ANBU Torture and Interrogation Force.\"}'),(233,54685,'Motoi','{\"Description\":\"Motoi (\\u30E2\\u30C8\\u30A4, Motoi) is a Kumogakure shinobi who is stationed on the Island Turtle.\",\"Manga debut\":\"Chapter #492\",\"Anime debut\":\"Naruto Shipp\\u016Bden Episode #243\",\"Description_2\":\"When Motoi was five-years-old, he and Killer B were good friends. After Motoi\\u0027s father was killed during an attempt to subdue the Eight-Tails that had broken free from its previous jinch\\u016Briki, Motoi came to hate the Eight-Tails. B was soon chosen to be the beast\\u0027s next jinch\\u016Briki and Motoi, just as many other Kumo villagers did, focused his anger towards B because he was to be the vessel of the beast. He once tried to assassinate B to avenge his father, but was disarmed by B easily. Despite having his face covered, Motoi assumed that B knew it was him, as B ungrudgingly greeted him as they used to with a fist bump. After this, Motoi could never bring himself to face B, and hadn\\u0027t spoken to him for thirty years, but in time he came to admire B as a village hero.\"}','{\"Anime debut\": \"Naruto Shippūden Episode #243\", \"Description\": \"Motoi (モトイ, Motoi) is a Kumogakure shinobi who is stationed on the Island Turtle.\", \"Manga debut\": \"Chapter #492\", \"Description_2\": \"When Motoi was five-years-old, he and Killer B were good friends. After Motoi\'s father was killed during an attempt to subdue the Eight-Tails that had broken free from its previous jinchūriki, Motoi came to hate the Eight-Tails. B was soon chosen to be the beast\'s next jinchūriki and Motoi, just as many other Kumo villagers did, focused his anger towards B because he was to be the vessel of the beast. He once tried to assassinate B to avenge his father, but was disarmed by B easily. Despite having his face covered, Motoi assumed that B knew it was him, as B ungrudgingly greeted him as they used to with a fist bump. After this, Motoi could never bring himself to face B, and hadn\'t spoken to him for thirty years, but in time he came to admire B as a village hero.\"}'),(234,255312,'Mozuku','{\"Description\":\"Mozuku is a chunin from Konohagakure.\",\"Description_2\":\"Mozuku has dark coloured hair that is concealed by his forehead protector which he wears like a bandanna. He also wears glasses and the standard outfit of the Torture and Interrogation Force which consists of a grey suit with pockets and lapels.\",\"Description_3\":\"Not much has been seen in the way of Mozuku\\u0027s abilities but he is skilled enough to aid Inoichi in delving into the minds of the enemy in order to retrieve potentially valuable information.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Mozuku is a chunin from Konohagakure.\", \"Description_2\": \"Mozuku has dark coloured hair that is concealed by his forehead protector which he wears like a bandanna. He also wears glasses and the standard outfit of the Torture and Interrogation Force which consists of a grey suit with pockets and lapels.\", \"Description_3\": \"Not much has been seen in the way of Mozuku\'s abilities but he is skilled enough to aid Inoichi in delving into the minds of the enemy in order to retrieve potentially valuable information.\"}'),(235,23054,'Mukade','{\"Description\":\"Mukade was a J\\u014Dnin from Sunagakure and later left Suna and became a servant of Akatsuki member Sasori. He was used as a sacrifice and was transformed into Kisame Hoshigaki as a means to stall Team Guy while the Akatsuki extracted the One-Tailed Shukaku from Gaara. Might Guy killed the Kisame clone (and in turn Mukade) with his Morning Peacock.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Mukade was a Jōnin from Sunagakure and later left Suna and became a servant of Akatsuki member Sasori. He was used as a sacrifice and was transformed into Kisame Hoshigaki as a means to stall Team Guy while the Akatsuki extracted the One-Tailed Shukaku from Gaara. Might Guy killed the Kisame clone (and in turn Mukade) with his Morning Peacock.\"}'),(236,64457,'Munashi, Jinpachi','{\"Description\":\"Jinpachi Munashi (\\u7121\\u68A8\\u751A\\u516B, Munashi Jinpachi) was a former member of the Seven Ninja Swordsmen of the Mist of Kirigakure.\",\"Description_2\":\"Utilising the unique \\u0022explosion\\u0022 sword Shibuki, Jinpachi intuitively combined expert swordsmanship with destructive explosions, due to the significant quantity of explosive tags incorporated into the platform-like edge. Once these tags detonate an integrated scroll deposits another set along the same edge, allowing the sword to be used consecutively. However, the capabilities of this weapon do not come without risk, as the user themselves can potentially be caught in the resultant blast but Jinpachi\\u0027s skill is such that this does not occur.\",\"Manga Debut\":\"Chapter #522\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #265\",\"(Source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #265\", \"(Source\": \"Narutopedia)\", \"Description\": \"Jinpachi Munashi (無梨甚八, Munashi Jinpachi) was a former member of the Seven Ninja Swordsmen of the Mist of Kirigakure.\", \"Manga Debut\": \"Chapter #522\", \"Description_2\": \"Utilising the unique \\\"explosion\\\" sword Shibuki, Jinpachi intuitively combined expert swordsmanship with destructive explosions, due to the significant quantity of explosive tags incorporated into the platform-like edge. Once these tags detonate an integrated scroll deposits another set along the same edge, allowing the sword to be used consecutively. However, the capabilities of this weapon do not come without risk, as the user themselves can potentially be caught in the resultant blast but Jinpachi\'s skill is such that this does not occur.\"}'),(237,95093,'Musai','{\"Description\":\"Musai is a Kumogakure shinobi.\",\"Description_2\":\"During the Fourth Shinobi World War, he and Nonota were ambushed by a reincarnated Toroi. Recognising his fellow Kumo shinobi, Musai tried to alert Nonota about Toroi\\u0027s techniques, but they were attacked before he could finish. After Nonota was magnetised, he further explained Toroi\\u0027s abilities. Both are saved by the arrival of Naruto Uzumaki and Killer B, Naruto slamming a Rasengan against Toroi.\",\"Description_3\":\"Musai explained how they were headed to Headquarters when they were separated from F and the others, only to be shocked by B, who revealed that F was actually a transformed White Zetsu. In the anime, after they left, Musai and Nonota were briefly suspicious of the other being a transformed White Zetsu as well, before realising the enemy tried to kill them both, meaning they were both on the same side. They laughed it off, and then Musai joked, pretending to be a transformed White Zetsu, only for Nonota to slash his nose with a kunai in defence.\",\"Description_4\":\"He and Nonota later met up with their regiment while carrying Toroi, after explaining how Naruto and B had saved them, Torune arrived and summoned a group of Kabuto\\u0027s \\u0022failures\\u0022 to retrieve Toroi and the Third Raikage, among them was Musai\\u0027s father Osoi, who he noted to a comrade had never made it past ch\\u016Bnin much to his father\\u0027s annoyance. After promising his father to tell the Raikage he and Toroi had died fighting for the sake of the village, they said goodbye as his father was sealed.\",\"Manga Debut\":\"Chapter #546\",\"Anime Debut\":\"Naruto Shippuuden Episode #296\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #296\", \"Description\": \"Musai is a Kumogakure shinobi.\", \"Manga Debut\": \"Chapter #546\", \"Description_2\": \"During the Fourth Shinobi World War, he and Nonota were ambushed by a reincarnated Toroi. Recognising his fellow Kumo shinobi, Musai tried to alert Nonota about Toroi\'s techniques, but they were attacked before he could finish. After Nonota was magnetised, he further explained Toroi\'s abilities. Both are saved by the arrival of Naruto Uzumaki and Killer B, Naruto slamming a Rasengan against Toroi.\", \"Description_3\": \"Musai explained how they were headed to Headquarters when they were separated from F and the others, only to be shocked by B, who revealed that F was actually a transformed White Zetsu. In the anime, after they left, Musai and Nonota were briefly suspicious of the other being a transformed White Zetsu as well, before realising the enemy tried to kill them both, meaning they were both on the same side. They laughed it off, and then Musai joked, pretending to be a transformed White Zetsu, only for Nonota to slash his nose with a kunai in defence.\", \"Description_4\": \"He and Nonota later met up with their regiment while carrying Toroi, after explaining how Naruto and B had saved them, Torune arrived and summoned a group of Kabuto\'s \\\"failures\\\" to retrieve Toroi and the Third Raikage, among them was Musai\'s father Osoi, who he noted to a comrade had never made it past chūnin much to his father\'s annoyance. After promising his father to tell the Raikage he and Toroi had died fighting for the sake of the village, they said goodbye as his father was sealed.\"}'),(238,64453,'Muu','{\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #256\",\"Description\":\"Muu (\\u7121, M\\u016B) was the Second Tsuchikage (\\u4E8C\\u4EE3\\u76EE\\u571F\\u5F71, Nidaime Tsuchikage; Literally meaning \\u0022Second Earth Shadow\\u0022) of Iwagakure.\",\"Description_2\":\"Muu is capable of becoming perfectly camouflaged with the surrounding environment. His camouflage is so good that he has become renowned as the \\u0022Non-Person\\u0022 (\\u7121\\u4EBA, Mujin), a title which he gained for seemingly having neither form nor chakra, while the technique was active. It is impossible to detect him by normal means and so, Muu considers anyone with the ability to sense his presence worthy of praise.\",\"Muu is one of the few people capable of using a kekkei touta, an advanced and extremely powerful form of kekkei genkai. In particular, he possesses the Dust Release, which allows him to combine the fire, earth and wind natures to reduce his opponents to nothing more than mere dust, destroying them down to even a molecular level. Compared with fellow dust-user, Ounoki, his power is implied to be on equal terms, as when the two initiated Dust Release\":\"Detachment of the Primitive World Technique, the disastrous outcome although chaotic, demonstrated no evident victor in regards to strength. This may be due to the fact that Muu\\u0027s power hadn\\u0027t waned since his lifetime, a fact later affirmed by Ounoki.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #256\", \"Description\": \"Muu (無, Mū) was the Second Tsuchikage (二代目土影, Nidaime Tsuchikage; Literally meaning \\\"Second Earth Shadow\\\") of Iwagakure.\", \"Manga Debut\": \"Chapter #515\", \"Description_2\": \"Muu is capable of becoming perfectly camouflaged with the surrounding environment. His camouflage is so good that he has become renowned as the \\\"Non-Person\\\" (無人, Mujin), a title which he gained for seemingly having neither form nor chakra, while the technique was active. It is impossible to detect him by normal means and so, Muu considers anyone with the ability to sense his presence worthy of praise.\", \"Muu is one of the few people capable of using a kekkei touta, an advanced and extremely powerful form of kekkei genkai. In particular, he possesses the Dust Release, which allows him to combine the fire, earth and wind natures to reduce his opponents to nothing more than mere dust, destroying them down to even a molecular level. Compared with fellow dust-user, Ounoki, his power is implied to be on equal terms, as when the two initiated Dust Release\": \"Detachment of the Primitive World Technique, the disastrous outcome although chaotic, demonstrated no evident victor in regards to strength. This may be due to the fact that Muu\'s power hadn\'t waned since his lifetime, a fact later affirmed by Ounoki.\"}'),(239,122169,'Muyami','{\"Description\":\"Muyami is a shinobi from Kusagakure and a team-mate of Kazami and Burami. He and his team took part in the joint Ch\\u016Bnin Exams held by Konohagakure and Sunagakure.\",\"Anime Debut\":\"Naruto Shippuuden Episode #395\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #395\", \"Description\": \"Muyami is a shinobi from Kusagakure and a team-mate of Kazami and Burami. He and his team took part in the joint Chūnin Exams held by Konohagakure and Sunagakure.\"}'),(240,53251,'Nadeshiko Previous Leader','{\"Description\":\"Former leader of the Nadeshiko Village.\",\"Description_2\":\"Decades ago she encountered Jiraiya who has entered her village to do \\u0022research\\u0022 for his next novel. After he escaped she pursued him and challenged him to a duel for his hand in marriage. This match was however postponed, as neither party was making headway against the other. Jiraiya promised that their students instead should one day seek each other out and fight if the two never met again. This promise fell to her pupil Shizuka and Jiraiya\\u0027s last pupil Naruto Uzumaki.\",\"Description_3\":\"She\\u0027s presumed to be Shizuka\\u0027s mother but is not confirmed neither named as such in the credits, instead she\\u0027s named as \\u0022Previous Head of the village (\\u5148\\u4EE3\\u91CC\\u9577)\\u0022.\",\"Description_4\":\"Appears in episode 235.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Former leader of the Nadeshiko Village.\", \"Description_2\": \"Decades ago she encountered Jiraiya who has entered her village to do \\\"research\\\" for his next novel. After he escaped she pursued him and challenged him to a duel for his hand in marriage. This match was however postponed, as neither party was making headway against the other. Jiraiya promised that their students instead should one day seek each other out and fight if the two never met again. This promise fell to her pupil Shizuka and Jiraiya\'s last pupil Naruto Uzumaki.\", \"Description_3\": \"She\'s presumed to be Shizuka\'s mother but is not confirmed neither named as such in the credits, instead she\'s named as \\\"Previous Head of the village (先代里長)\\\".\", \"Description_4\": \"Appears in episode 235.\"}'),(241,41211,'Naho','{\"Description\":\"Naho (\\u30CA\\u30DB, Naho) is a relative of the Fire Daimy\\u014D.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #196\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #196\", \"(source\": \")\", \"Description\": \"Naho (ナホ, Naho) is a relative of the Fire Daimyō.\"}'),(242,17298,'Namiashi, Raidou','{\"Description\":\"Raid\\u014D Namiashi is a Tokubetsu J\\u014Dnin of Konohagakure.\",\"Description_2\":\"Despite the handful of fights he has been in, Raid\\u014D has yet to be seen in extended combat. Given that he was a bodyguard for the Third Hokage, and that the Sound Four needed to activate their cursed seals in order to defeat him, it is likely that he is a formidable fighter. It was shown that when Hidan and Kakuzu attempted to kill Kotetsu and Izumo, Raid\\u014D successfully attacked and fended off Kakuzu with a unique sword called \\u0022Ebony Blade\\u0022 (\\u9ED2\\u5200, Kokut\\u014D), which resembles a katana with a darkened, non-reflective surface.\"}','{\"Description\": \"Raidō Namiashi is a Tokubetsu Jōnin of Konohagakure.\", \"Description_2\": \"Despite the handful of fights he has been in, Raidō has yet to be seen in extended combat. Given that he was a bodyguard for the Third Hokage, and that the Sound Four needed to activate their cursed seals in order to defeat him, it is likely that he is a formidable fighter. It was shown that when Hidan and Kakuzu attempted to kill Kotetsu and Izumo, Raidō successfully attacked and fended off Kakuzu with a unique sword called \\\"Ebony Blade\\\" (黒刀, Kokutō), which resembles a katana with a darkened, non-reflective surface.\"}'),(243,191282,'Namikaze, Menma','{\"Description\":\"Appearance in episode 427.\",\"Description_2\":\"Menma Namikaze is a descendant of the Uzumaki clan in Tenten\\u0027s Infinite Tsukuyomi dream.\",\"Description_3\":\"Menma\\u0027s life was greatly different than Naruto Uzumaki\\u0027s, as Menma didn\\u0027t lose his parents, and had many friends during his childhood. At some point, Kurama was safely transferred from Kushina Uzumaki onto Menma, letting Menma keep his mother while eventually becoming friends with the tailed beast. After graduating from the Academy, Menma became a member of Team Kakashi alongside Sakura Haruno and Sasuke Uchiha. Eventually, Menma became a ch\\u016Bnin.\",\"Description_4\":\"Menma takes more after his father, as opposed to Naruto, who was stated to inherit his mother\\u0027s personality traits. Menma is calm, collected, talking only when he feels it serves a purpose. In contrast to Naruto, who is usually childish and cheerful, Menma is mature and very serious. He is also shown with a sharp wit, carefully thinking before acting, and able to see the underlying nature of the situation at hand. His insight appears to make him the smartest of his graduating class and also acting as the de facto leader of the group.\",\"Description_5\":\"Much like the real world\\u0027s Sasuke, Menma is somewhat distant, showing little respect when talking to others, even his parents. He also shows no interest in women despite both Sakura and Hinata fighting over his love, simply telling them to leave him alone. Despite his seriousness, Menma is very loyal to his friends, as he claimed that Tenten\\u0027s problems were bothering him and wanted to help, and been watching Tenten for a while. When Tenten was framed for treason against the village, Menma worked diligently to clear his friend\\u0027s name. Menma is also not above to show a happier side, as he smiled while openly congratulating Tenten for helping him defeat Hanz\\u014D.\",\"Description_6\":\"Menma looks virtually identical to Naruto, though his blond hair is longer and more shaggy-looking in style with jaw-length bangs framing either side of his face, similar to his father\\u0027s. He wears the same attire as Naruto\\u0027s in Part II, consisting of a black and orange slim outfit, with a long black headband for his forehead protector, and black zori sandals reaching his ankles. Also, Menma wears black fingerless gloves and instead of the Uzumaki symbol on the back of his jacket, he has a green circle with five smaller red circles in it, one in the center and four around the ends connected by two crossed lines, with two more lined-up red circles above and below the green circle.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Appearance in episode 427.\", \"Description_2\": \"Menma Namikaze is a descendant of the Uzumaki clan in Tenten\'s Infinite Tsukuyomi dream.\", \"Description_3\": \"Menma\'s life was greatly different than Naruto Uzumaki\'s, as Menma didn\'t lose his parents, and had many friends during his childhood. At some point, Kurama was safely transferred from Kushina Uzumaki onto Menma, letting Menma keep his mother while eventually becoming friends with the tailed beast. After graduating from the Academy, Menma became a member of Team Kakashi alongside Sakura Haruno and Sasuke Uchiha. Eventually, Menma became a chūnin.\", \"Description_4\": \"Menma takes more after his father, as opposed to Naruto, who was stated to inherit his mother\'s personality traits. Menma is calm, collected, talking only when he feels it serves a purpose. In contrast to Naruto, who is usually childish and cheerful, Menma is mature and very serious. He is also shown with a sharp wit, carefully thinking before acting, and able to see the underlying nature of the situation at hand. His insight appears to make him the smartest of his graduating class and also acting as the de facto leader of the group.\", \"Description_5\": \"Much like the real world\'s Sasuke, Menma is somewhat distant, showing little respect when talking to others, even his parents. He also shows no interest in women despite both Sakura and Hinata fighting over his love, simply telling them to leave him alone. Despite his seriousness, Menma is very loyal to his friends, as he claimed that Tenten\'s problems were bothering him and wanted to help, and been watching Tenten for a while. When Tenten was framed for treason against the village, Menma worked diligently to clear his friend\'s name. Menma is also not above to show a happier side, as he smiled while openly congratulating Tenten for helping him defeat Hanzō.\", \"Description_6\": \"Menma looks virtually identical to Naruto, though his blond hair is longer and more shaggy-looking in style with jaw-length bangs framing either side of his face, similar to his father\'s. He wears the same attire as Naruto\'s in Part II, consisting of a black and orange slim outfit, with a long black headband for his forehead protector, and black zori sandals reaching his ankles. Also, Menma wears black fingerless gloves and instead of the Uzumaki symbol on the back of his jacket, he has a green circle with five smaller red circles in it, one in the center and four around the ends connected by two crossed lines, with two more lined-up red circles above and below the green circle.\"}'),(244,2535,'Namikaze, Minato','{\"Birthday\":\"January 25\",\"Zodiac Sign\":\"Aquarius\",\"Gender\":\"Male\",\"Age\":\"Part II: 24\",\"Height\":\"Part I: 179.2 cm\",\"Weight\":\"Part I: 66.1 kg\",\"Blood type\":\"B\",\"Description\":\"Minato Namikaze was the Yondaime Hokage of Konohagakure and the man responsible for sealing the nine-tailed demon fox inside Naruto Uzumaki when he was born. Doing so cost him his life, and before dying he asked that the villagers not see Naruto as the monster within him, instead wanting him to be viewed as a hero, a request ignored by the villagers. \\u0022Namikaze\\u0022 translates literally as \\u0022Wave wind.\\u0022 \\u0022Minato\\u0022 translates as \\u0022Harbor\\u0022 or \\u0022Port.\\u0022\",\"Description_2\":\"Minato is said to be one of the greatest ninja Konoha has ever produced, with natural talent that had not been seen in many years. He specializes in using the Hiraishin no Jutsu, a technique the Second Hokage, Tobirama created, which essentially allowed him to teleport to any location with the use of a special seal. By attaching the seal to a kunai or an enemy, Minato could teleport to the location of the seal unnoticed, allowing him to wipe out nearby opponents almost instantly. This ability led to his title as \\u0022Konoha\\u0027s Yellow Flash,\\u0022 and it caused him to be seen as so dangerous that a flee-on-sight order was given in regards to him during the Third Ninja War. He also created the Rasengan, a technique that does not rely on hand seals but instead uses a concentration of spinning chakra in one\\u0027s palm that causes immense damage to its victim on contact. Later in the series it is revealed that technique is actually incomplete. Minato had planned to add his own nature manipulation training to the Rasengan, making it even more powerful, but could not manage to prior to his death.\"}','{\"Age\": \"Part II: 24\", \"Gender\": \"Male\", \"Height\": \"Part I: 179.2 cm\", \"Weight\": \"Part I: 66.1 kg\", \"Birthday\": \"January 25\", \"Blood type\": \"B\", \"Description\": \"Minato Namikaze was the Yondaime Hokage of Konohagakure and the man responsible for sealing the nine-tailed demon fox inside Naruto Uzumaki when he was born. Doing so cost him his life, and before dying he asked that the villagers not see Naruto as the monster within him, instead wanting him to be viewed as a hero, a request ignored by the villagers. \\\"Namikaze\\\" translates literally as \\\"Wave wind.\\\" \\\"Minato\\\" translates as \\\"Harbor\\\" or \\\"Port.\\\"\", \"Zodiac Sign\": \"Aquarius\", \"Description_2\": \"Minato is said to be one of the greatest ninja Konoha has ever produced, with natural talent that had not been seen in many years. He specializes in using the Hiraishin no Jutsu, a technique the Second Hokage, Tobirama created, which essentially allowed him to teleport to any location with the use of a special seal. By attaching the seal to a kunai or an enemy, Minato could teleport to the location of the seal unnoticed, allowing him to wipe out nearby opponents almost instantly. This ability led to his title as \\\"Konoha\'s Yellow Flash,\\\" and it caused him to be seen as so dangerous that a flee-on-sight order was given in regards to him during the Third Ninja War. He also created the Rasengan, a technique that does not rely on hand seals but instead uses a concentration of spinning chakra in one\'s palm that causes immense damage to its victim on contact. Later in the series it is revealed that technique is actually incomplete. Minato had planned to add his own nature manipulation training to the Rasengan, making it even more powerful, but could not manage to prior to his death.\"}'),(245,30187,'Nangou','{\"Description\":\"Nang\\u014D (\\u30CA\\u30F3\\u30B4\\u30A6) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\\u0027s kinjutsu.\",\"Description_2\":\"Voiced by Nobuaki Kanemitsu.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Nangō (ナンゴウ) is a ninja who was helping Akaboshi to collect the Tsuchigumo clan\'s kinjutsu.\", \"Description_2\": \"Voiced by Nobuaki Kanemitsu.\"}'),(246,2007,'Nara, Shikamaru','{\"Age\":\"12 (I); 15 (II)\",\"Birthday\":\"September 22\",\"Horoscope\":\"Virgo\",\"Blood Type\":\"AB\",\"Height\":\"170 cm\",\"Weight\":\"53.4 kg\",\"Rank\":\"Genin (I); Chuunin (II)\",\"Likes\":\"taking naps, playing shogi\",\"Dislikes\":\"Hard-boiled eggs\",\"Description\":\"Shikamaru is an extremely unenthusiastic person, and as such, lives his life avoiding work. This is partly due to him seeking paths of least resistance, as he often chooses to do things he would otherwise not do if people nag him enough. In his free time he typically takes naps, watches clouds, and plays strategy games such as Shogi and Go. When put into a situation where he potentially needs to put effort into something, he attempts to try to find a way to avoid it such as forfeiting a battle or by pretending to be preoccupied with something else. In the instances where he can not avoid these situations, Shikamaru tends to remark \\u0022how troublesome.\\u0022\",\"Description_2\":\"Despite his lazy tendencies, Shikamaru is extremely intelligent. His teacher, Asuma, found Shikamaru to have an IQ of over 200, and learned that Shikamaru\\u0027s poor grades were a result of him finding lifting a pencil to be too much work for him. Nevertheless, Shikamaru works very well with his teammates, as their fathers were teamed together in their youth. Of his teammates, Shikamaru is closest with Chouji, who repays Shikamaru\\u0027s confidence in him with unyielding loyalty. Shikamaru also has a strong bond with Asuma, often spending time with him playing strategy games. After Asuma\\u0027s death, he even vows to protect Asuma and Kurenai\\u0027s unborn child for his teacher\\u0027s sake. Shikamaru has stated that he will make the child his apprentice someday.\",\"Description_3\":\"One of Shikamaru\\u0027s more distinctive characteristics is that he finds all women to be bossy and \\u0022a pain.\\u0022 Contrary to this opinion, he has expressed a notably mature interest in marriage and raising a family with a son and daughter. Ironically, Shikamaru seems to constantly find himself surrounded by the very same strong-willed and bossy women he dislikes. In addition to his own mother, and being surrounded by bossy females, he usually ends up fighting against such women. Shikamaru has had a number of his appearances coincide with those of Temari. When they make their Part II debut together, Naruto Uzumaki asks if they are on a date, though both Shikamaru and Temari state that this is not the case.\",\"Description_4\":\"When the need arises, Shikamaru is quick to abandon his lazy nature and act appropriately to complete a mission or save his teammates. Using his Shadow Imitation Technique, the signature technique of his clan, he can capture the shadow of an opponent to either keep them immobilized or force them to mimic his movements. This ability causes Shikamaru to frequently take the task of stalling enemies so that his comrades can get to safety or to simply buy time. Although this role puts him in a dangerous position once he can no longer stall the opponent, Shikamaru is willing to serve it, feeling that sacrificing his life to ensure the safety of his friends is worth it. He then considers every element that is relevant to the situation at hand and analyzes the information to its fullest, planning out a battle ten moves in advance and devising over a hundred strategies to use against an opponent. This combination of intelligence and dedication to his teammates causes Shikamaru to become the first of the primary Konoha Genin to advance to the rank of Chunin.\",\"Description_5\":\"Once becoming a Chunin, Shikamaru\\u0027s father teaches him how to use his shadow technique more effectively, by using it to choke an opponent. This more interactive capability with his shadow is put to great use over the timeskip, and by Part II Shikamaru becomes proficient at using multiple shadow-based techniques at once. He is also able to manipulate his shadow to lift from the ground and either grab or throw weapons simply by utilizing an opponent\\u0027s shadow for the same purpose. After he comes into the possession of Asuma\\u0027s brass knuckles, Shikamaru learns to channel his shadow into them, using them to immobilize opponents by throwing them at an opponent\\u0027s shadow to capture them and save himself the energy.\"}','{\"Age\": \"12 (I); 15 (II)\", \"Rank\": \"Genin (I); Chuunin (II)\", \"Likes\": \"taking naps, playing shogi\", \"Height\": \"170 cm\", \"Weight\": \"53.4 kg\", \"Birthday\": \"September 22\", \"Dislikes\": \"Hard-boiled eggs\", \"Horoscope\": \"Virgo\", \"Blood Type\": \"AB\", \"Description\": \"Shikamaru is an extremely unenthusiastic person, and as such, lives his life avoiding work. This is partly due to him seeking paths of least resistance, as he often chooses to do things he would otherwise not do if people nag him enough. In his free time he typically takes naps, watches clouds, and plays strategy games such as Shogi and Go. When put into a situation where he potentially needs to put effort into something, he attempts to try to find a way to avoid it such as forfeiting a battle or by pretending to be preoccupied with something else. In the instances where he can not avoid these situations, Shikamaru tends to remark \\\"how troublesome.\\\"\", \"Description_2\": \"Despite his lazy tendencies, Shikamaru is extremely intelligent. His teacher, Asuma, found Shikamaru to have an IQ of over 200, and learned that Shikamaru\'s poor grades were a result of him finding lifting a pencil to be too much work for him. Nevertheless, Shikamaru works very well with his teammates, as their fathers were teamed together in their youth. Of his teammates, Shikamaru is closest with Chouji, who repays Shikamaru\'s confidence in him with unyielding loyalty. Shikamaru also has a strong bond with Asuma, often spending time with him playing strategy games. After Asuma\'s death, he even vows to protect Asuma and Kurenai\'s unborn child for his teacher\'s sake. Shikamaru has stated that he will make the child his apprentice someday.\", \"Description_3\": \"One of Shikamaru\'s more distinctive characteristics is that he finds all women to be bossy and \\\"a pain.\\\" Contrary to this opinion, he has expressed a notably mature interest in marriage and raising a family with a son and daughter. Ironically, Shikamaru seems to constantly find himself surrounded by the very same strong-willed and bossy women he dislikes. In addition to his own mother, and being surrounded by bossy females, he usually ends up fighting against such women. Shikamaru has had a number of his appearances coincide with those of Temari. When they make their Part II debut together, Naruto Uzumaki asks if they are on a date, though both Shikamaru and Temari state that this is not the case.\", \"Description_4\": \"When the need arises, Shikamaru is quick to abandon his lazy nature and act appropriately to complete a mission or save his teammates. Using his Shadow Imitation Technique, the signature technique of his clan, he can capture the shadow of an opponent to either keep them immobilized or force them to mimic his movements. This ability causes Shikamaru to frequently take the task of stalling enemies so that his comrades can get to safety or to simply buy time. Although this role puts him in a dangerous position once he can no longer stall the opponent, Shikamaru is willing to serve it, feeling that sacrificing his life to ensure the safety of his friends is worth it. He then considers every element that is relevant to the situation at hand and analyzes the information to its fullest, planning out a battle ten moves in advance and devising over a hundred strategies to use against an opponent. This combination of intelligence and dedication to his teammates causes Shikamaru to become the first of the primary Konoha Genin to advance to the rank of Chunin.\", \"Description_5\": \"Once becoming a Chunin, Shikamaru\'s father teaches him how to use his shadow technique more effectively, by using it to choke an opponent. This more interactive capability with his shadow is put to great use over the timeskip, and by Part II Shikamaru becomes proficient at using multiple shadow-based techniques at once. He is also able to manipulate his shadow to lift from the ground and either grab or throw weapons simply by utilizing an opponent\'s shadow for the same purpose. After he comes into the possession of Asuma\'s brass knuckles, Shikamaru learns to channel his shadow into them, using them to immobilize opponents by throwing them at an opponent\'s shadow to capture them and save himself the energy.\"}'),(247,22247,'Nara, Yoshino','{\"Description\":\"Yoshino Nara is the mother of Shikamaru Nara and the wife of Shikaku Nara. Though very strict and sometimes overbearing, she also has a sweet side.\"}','{\"Description\": \"Yoshino Nara is the mother of Shikamaru Nara and the wife of Shikaku Nara. Though very strict and sometimes overbearing, she also has a sweet side.\"}'),(248,18056,'Nara, Shikaku','{\"Description\":\"Nara is the father of Shikamaru Nara. Shika means \\u0022deer\\u0022 but shikaku can mean \\u0022assassin.\\u0022 He is the father of Shikamaru and the husband of Yoshino Nara. He is rarely seen in either manga or anime, but when he is seen, he greatly resembles his son with the exception of his more matured appearance and the few scars on his face.\",\"Description_2\":\"Nara Shikaku is the father of Shikamaru and the husband of Yoshino, and, like his son, he was part of an Ino-Shika-Cho trio, together with Choza Akimichi and Inoichi Yamanaka. Like his son, he is the Shika in the group name. He is married to Yoshino Nara who, as his son says, has him whipped. Despite his claim that \\u0022a woman is always tender to the man she loves,\\u0022 his son is never convinced. As a member of the Nara clan, he raises deer, whose antlers can be used to make a medicine which halts the destructive effects of the Akimichi clan\\u0027s three colored pills. Since his son became a Chunin, Shikaku has taken a great interest in Shikamaru\\u0027s training as he knows his son has much greater potential than he gives himself credit, regularly playing him at shogi to further refine his son\\u0027s intellect and teaching him more of their clan\\u0027s secret techniques. He is probably the most skilled strategist and shogi player in all of Konoha, he beats Shikamaru on a regular basis.\",\"Description_3\":\"When he is first seen, he is portrayed as a bit of an alcoholic, and at times uses some of Shikamaru\\u0027s catchphrases (\\u0022What a drag\\u0022 in English, \\u0022How troublesome\\u0022 in Japanese). Like his son, he thinks that women should be tender and sweet, but as his son says, his wife has him whipped. Also like his son, he is a very lazy person, but he is also quite caring, and is ready to jump into action when needed. Unlike his son, his resolve is much stronger, as even during the most depressing or dangerous of situations, he has shown to maintain great determination and understanding as shown from how he has repeatedly helped his son regain his sense of worth. He also seems to be very smart as he has defeated Shikamaru in shogi.\",\"Description_4\":\"Like his son, and the rest of his clan, Shikaku uses a special secret clan type of Jutsu, that utilizes the manipulation of shadows in various combatable ways. Although he has only been seen in combat once, as the head of his respective clan, it is highly presumed that he has mastery of his clan\\u0027s techniques. During Orochimaru\\u0027s invasion of Konoha, Shikaku perfectly used the Shadow Neck Bind Technique against three opponents at the same time.\",\"Description_5\":\"He has also shown on several occasions to be a very intelligent man, repeatedly giving insightly words of advise to his Shikamaru, as well as repeatedly beating him in shoji, strongly hinting at having an intellect that surpasses his son\\u0027s.  Shikaku\\u0027s intelligence and skill as a ninja, has also earned him the position of Jonin Commander - the highest-ranking position to which a normal Shinobi can be promoted.\"}','{\"Description\": \"Nara is the father of Shikamaru Nara. Shika means \\\"deer\\\" but shikaku can mean \\\"assassin.\\\" He is the father of Shikamaru and the husband of Yoshino Nara. He is rarely seen in either manga or anime, but when he is seen, he greatly resembles his son with the exception of his more matured appearance and the few scars on his face.\", \"Description_2\": \"Nara Shikaku is the father of Shikamaru and the husband of Yoshino, and, like his son, he was part of an Ino-Shika-Cho trio, together with Choza Akimichi and Inoichi Yamanaka. Like his son, he is the Shika in the group name. He is married to Yoshino Nara who, as his son says, has him whipped. Despite his claim that \\\"a woman is always tender to the man she loves,\\\" his son is never convinced. As a member of the Nara clan, he raises deer, whose antlers can be used to make a medicine which halts the destructive effects of the Akimichi clan\'s three colored pills. Since his son became a Chunin, Shikaku has taken a great interest in Shikamaru\'s training as he knows his son has much greater potential than he gives himself credit, regularly playing him at shogi to further refine his son\'s intellect and teaching him more of their clan\'s secret techniques. He is probably the most skilled strategist and shogi player in all of Konoha, he beats Shikamaru on a regular basis.\", \"Description_3\": \"When he is first seen, he is portrayed as a bit of an alcoholic, and at times uses some of Shikamaru\'s catchphrases (\\\"What a drag\\\" in English, \\\"How troublesome\\\" in Japanese). Like his son, he thinks that women should be tender and sweet, but as his son says, his wife has him whipped. Also like his son, he is a very lazy person, but he is also quite caring, and is ready to jump into action when needed. Unlike his son, his resolve is much stronger, as even during the most depressing or dangerous of situations, he has shown to maintain great determination and understanding as shown from how he has repeatedly helped his son regain his sense of worth. He also seems to be very smart as he has defeated Shikamaru in shogi.\", \"Description_4\": \"Like his son, and the rest of his clan, Shikaku uses a special secret clan type of Jutsu, that utilizes the manipulation of shadows in various combatable ways. Although he has only been seen in combat once, as the head of his respective clan, it is highly presumed that he has mastery of his clan\'s techniques. During Orochimaru\'s invasion of Konoha, Shikaku perfectly used the Shadow Neck Bind Technique against three opponents at the same time.\", \"Description_5\": \"He has also shown on several occasions to be a very intelligent man, repeatedly giving insightly words of advise to his Shikamaru, as well as repeatedly beating him in shoji, strongly hinting at having an intellect that surpasses his son\'s.  Shikaku\'s intelligence and skill as a ninja, has also earned him the position of Jonin Commander - the highest-ranking position to which a normal Shinobi can be promoted.\"}'),(249,64449,'Nara, Ensui','{\"Description\":\"Ensui Nara (\\u5948\\u826F\\u30A8\\u30F3\\u30B9\\u30A4, Nara Ensui) is a member of Konohagakure\\u0027s Nara clan.\",\"Manga Debut\":\"Chapter #523\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #266\",\"(source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #266\", \"(source\": \"Narutopedia)\", \"Description\": \"Ensui Nara (奈良エンスイ, Nara Ensui) is a member of Konohagakure\'s Nara clan.\", \"Manga Debut\": \"Chapter #523\"}'),(250,234151,'Narrator','{}','{}'),(251,98659,'Natsu','{\"Description\":\"Natsu (\\u30CA\\u30C4, Natsu) is a shinobi from Iwagakure.\",\"Description_2\":\"During the Fourth Shinobi World War, Natsu was assigned to the Second Division under Kitsuchi\\u0027s command. During the war, Natsu was deployed to aid Naruto Uzumaki, Killer B, Kakashi Hatake and Might Guy with Neji Hy\\u016Bga and Shun, when they were confronted by members of the White Zetsu Army. He and Shun defeated two of the opponents with some help from Neji. They then got into an argument with each other, but Neji soon broke it up and reminded them both that the next battle was going to be on the front lines.\",\"Anime Debut\":\"Naruto Shippuuden Episode #330\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #330\", \"Description\": \"Natsu (ナツ, Natsu) is a shinobi from Iwagakure.\", \"Description_2\": \"During the Fourth Shinobi World War, Natsu was assigned to the Second Division under Kitsuchi\'s command. During the war, Natsu was deployed to aid Naruto Uzumaki, Killer B, Kakashi Hatake and Might Guy with Neji Hyūga and Shun, when they were confronted by members of the White Zetsu Army. He and Shun defeated two of the opponents with some help from Neji. They then got into an argument with each other, but Neji soon broke it up and reminded them both that the next battle was going to be on the front lines.\"}'),(252,22884,'Nawaki','{\"Description\":\"Nawaki (\\u7E04\\u6A39) was the younger brother of Tsunade and the grandson of the First Hokage. He was very much like Naruto Uzumaki in both appearance and personality and like Naruto, Nawaki also had the dream of becoming Hokage one day. He shared this dream with his sister on his twelfth birthday, who gave him their grandfather\\u0027s necklace in the hopes that it would help him achieve is dream. The day after his birthday, Nawaki died in battle. His body was so heavily mutilated that it was beyond recognition.\",\"Description_2\":\"Orochimaru would later offer Tsunade to bring Nawaki back to life, together with Tsunade\\u0027s lover Dan, in exchange for healing his arms. The resurrection would require a human sacrifice, though. She ultimately refuses, realizing that Nawaki and Dan would not want her to sacrifice the lives of others in exchange for theirs.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Nawaki (縄樹) was the younger brother of Tsunade and the grandson of the First Hokage. He was very much like Naruto Uzumaki in both appearance and personality and like Naruto, Nawaki also had the dream of becoming Hokage one day. He shared this dream with his sister on his twelfth birthday, who gave him their grandfather\'s necklace in the hopes that it would help him achieve is dream. The day after his birthday, Nawaki died in battle. His body was so heavily mutilated that it was beyond recognition.\", \"Description_2\": \"Orochimaru would later offer Tsunade to bring Nawaki back to life, together with Tsunade\'s lover Dan, in exchange for healing his arms. The resurrection would require a human sacrifice, though. She ultimately refuses, realizing that Nawaki and Dan would not want her to sacrifice the lives of others in exchange for theirs.\"}'),(253,23149,'Nekobaa','{\"Description\":\"Nekobaa (\\u306D\\u3053\\u3070\\u3042) is an old woman who lives in an abandoned city together with her granddaughter, Tamaki. She runs a supplies shop that the Uchiha clan used to use. She lives with lots of cats, including talking ones like Denka and Hina. Sasuke Uchiha comes to her to buy some items for his Hebi. She tells Sasuke she remembers how Itachi and he were once \\u0027little kittens\\u0027 and that she can\\u0027t believe they want to kill each other now.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Nekobaa (ねこばあ) is an old woman who lives in an abandoned city together with her granddaughter, Tamaki. She runs a supplies shop that the Uchiha clan used to use. She lives with lots of cats, including talking ones like Denka and Hina. Sasuke Uchiha comes to her to buy some items for his Hebi. She tells Sasuke she remembers how Itachi and he were once \'little kittens\' and that she can\'t believe they want to kill each other now.\"}'),(254,40689,'Nekomata','{\"Description\":\"Nekomata (\\u732B\\u53C8, Nekomata) is giant cat who is the boss of the ninja cat underworld.\",\"Appearance\":\"Konoha History Arc - Episode 189 (Filler Arc)\",\"Description_2\":\"During Sasuke Uchiha\\u0027s childhood, Itachi Uchiha made a game of collecting paw prints of quick, nimble cats from a normal cat to a lion and the last paw print to be collected was Nekomata\\u0027s. Itachi once defeated Nekomata and his ninja cats and requested him to fight Sasuke with all his might when he gets older.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Appearance\": \"Konoha History Arc - Episode 189 (Filler Arc)\", \"Description\": \"Nekomata (猫又, Nekomata) is giant cat who is the boss of the ninja cat underworld.\", \"Description_2\": \"During Sasuke Uchiha\'s childhood, Itachi Uchiha made a game of collecting paw prints of quick, nimble cats from a normal cat to a lion and the last paw print to be collected was Nekomata\'s. Itachi once defeated Nekomata and his ninja cats and requested him to fight Sasuke with all his might when he gets older.\"}'),(255,94815,'Nigai','{\"Description\":\"Nigai (\\u30CB\\u30AC\\u30A4, Nigai) was a Kumogakure shinobi.\",\"Description_2\":\"While on a covert mission to steal a kinjutsu from the Sugi Village, he, A, and Karai were set upon by the mercenary Nokizaru Group who had been hired to retrieve the scroll. Though initially telling his comrades to ignore the taunts of the group, he falls prey to it when they chide the Raikage for running away. Turning to face his opponents he uses a technique and immediately swelled to giant proportions and then exploded.\",\"Anime Debut\":\"Naruto Shippuuden Episode #286\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #286\", \"Description\": \"Nigai (ニガイ, Nigai) was a Kumogakure shinobi.\", \"Description_2\": \"While on a covert mission to steal a kinjutsu from the Sugi Village, he, A, and Karai were set upon by the mercenary Nokizaru Group who had been hired to retrieve the scroll. Though initially telling his comrades to ignore the taunts of the group, he falls prey to it when they chide the Raikage for running away. Turning to face his opponents he uses a technique and immediately swelled to giant proportions and then exploded.\"}'),(256,15362,'Nii, Yugito','{\"Birthdate\":\"July 24\",\"Gender\":\"Female\",\"Age\":\"Part II: 29\",\"Height\":\"Part II: 170.2 cm\",\"Weight\":\"Part II: 50.8 kg\",\"Blood type\":\"A\",\"Description\":\"Yugito Nii is a kunoichi from Kumogakure. When she was two years old, she became the Jinch\\u016Briki of the Two-Tailed Monster Cat.\"}','{\"Age\": \"Part II: 29\", \"Gender\": \"Female\", \"Height\": \"Part II: 170.2 cm\", \"Weight\": \"Part II: 50.8 kg\", \"Birthdate\": \"July 24\", \"Blood type\": \"A\", \"Description\": \"Yugito Nii is a kunoichi from Kumogakure. When she was two years old, she became the Jinchūriki of the Two-Tailed Monster Cat.\"}'),(257,280888,'Ninkame','{}','{}'),(258,14082,'Nohara, Rin','{\"Rank\":\"Chuunin\",\"Birthday\":\"November 15\",\"Blood Type\":\"A\",\"Description\":\"Rin, a medical ninja, was the teammate of Hatake Kakashi and Uchiha Obito during the Kakashi Gaiden arc. She is a sweet and friendly girl who cares for her teammates. She is also the one who implanted Obito\\u0027s left eye into Kakashi, giving him his Sharingan.\",\"Description_2\":\"At the end of The 4th Great Ninja war\"}','{\"Rank\": \"Chuunin\", \"Birthday\": \"November 15\", \"Blood Type\": \"A\", \"Description\": \"Rin, a medical ninja, was the teammate of Hatake Kakashi and Uchiha Obito during the Kakashi Gaiden arc. She is a sweet and friendly girl who cares for her teammates. She is also the one who implanted Obito\'s left eye into Kakashi, giving him his Sharingan.\", \"Description_2\": \"At the end of The 4th Great Ninja war\"}'),(259,95095,'Nonota','{\"Description\":\"Nonota is a Sunagakure shinobi.\",\"Description_2\":\"During the Fourth Shinobi World War, he and Musai were ambushed by a reincarnated Toroi. Musai recognised Toroi, and began explaining his abilities to Nonota, but they\\u0027re attacked before he can finished. After Nonota was magnetised, Musai finished explaining Toroi\\u0027s abilities to an increasingly apprehensive Nonota. Both are saved by the arrival of Naruto Uzumaki and Killer B, Naruto slamming Toroi with a Rasengan. As Toroi regenerated, Nonota proceeded to seal him.\",\"Description_3\":\"In the anime, after they left, Nonota and Musai were briefly suspicious of the other being a transformed White Zetsu as well, before realising the enemy tried to kill them both, meaning they were both on the same side. They laughed it off, and then Musai joked, pretending to be a transformed White Zetsu, only for Nonota to slash his nose with a kunai in defence.\",\"Manga Debut\":\"Chapter #546\",\"Anime Debut\":\"Naruto Shippuuden Episode #296\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #296\", \"Description\": \"Nonota is a Sunagakure shinobi.\", \"Manga Debut\": \"Chapter #546\", \"Description_2\": \"During the Fourth Shinobi World War, he and Musai were ambushed by a reincarnated Toroi. Musai recognised Toroi, and began explaining his abilities to Nonota, but they\'re attacked before he can finished. After Nonota was magnetised, Musai finished explaining Toroi\'s abilities to an increasingly apprehensive Nonota. Both are saved by the arrival of Naruto Uzumaki and Killer B, Naruto slamming Toroi with a Rasengan. As Toroi regenerated, Nonota proceeded to seal him.\", \"Description_3\": \"In the anime, after they left, Nonota and Musai were briefly suspicious of the other being a transformed White Zetsu as well, before realising the enemy tried to kill them both, meaning they were both on the same side. They laughed it off, and then Musai joked, pretending to be a transformed White Zetsu, only for Nonota to slash his nose with a kunai in defence.\"}'),(260,33793,'Nurari','{\"Description\":\"Nurari (\\u6FE1\\u7F85\\u540F) was a shinobi who appeared in the second Naruto Shipp\\u016Bden filler arc.\",\"Description_2\":\"Nurari enjoyed toying with his foes and constantly mocked them. He also was shown to be a bit of a drag queen when he whimpered feminine shrieks or moans whenever he was in danger. Another example was when Rinji, and later Kabuto, gave him a mocking stare, to which he remarked was rude.\"}','{\"Description\": \"Nurari (濡羅吏) was a shinobi who appeared in the second Naruto Shippūden filler arc.\", \"Description_2\": \"Nurari enjoyed toying with his foes and constantly mocked them. He also was shown to be a bit of a drag queen when he whimpered feminine shrieks or moans whenever he was in danger. Another example was when Rinji, and later Kabuto, gave him a mocking stare, to which he remarked was rude.\"}'),(261,94819,'Nurui','{\"Description\":\"Nurui (\\u30CC\\u30EB\\u30A4, Nurui) is a shinobi of Kumogakure.\",\"Description_2\":\"After Yurui\\u0027s death, Nurui became the de-facto captain of one of the Third Division\\u0027s units. He opted to escape from Ameyuri Ringo and refused to confront her even as his comrades fell one by one. When Omoi decided they could run no longer, he tried to persuade him from fighting Ameyuri. When Omoi discarded this Nurui and Kayui went after him and were incapacitated by Ringo\\u0027s attack. Later, when Ameyuri was trapped in a marsh, it was revealed that Nurui and the others had planned this all along and were simply leading Ameyuri to the site.\",\"Anime Debut\":\"Naruto Shippuuden Episode #289\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #289\", \"Description\": \"Nurui (ヌルイ, Nurui) is a shinobi of Kumogakure.\", \"Description_2\": \"After Yurui\'s death, Nurui became the de-facto captain of one of the Third Division\'s units. He opted to escape from Ameyuri Ringo and refused to confront her even as his comrades fell one by one. When Omoi decided they could run no longer, he tried to persuade him from fighting Ameyuri. When Omoi discarded this Nurui and Kayui went after him and were incapacitated by Ringo\'s attack. Later, when Ameyuri was trapped in a marsh, it was revealed that Nurui and the others had planned this all along and were simply leading Ameyuri to the site.\"}'),(262,17619,'Oboro','{\"Description\":\"A genin from Hidden Rain, Oboro specializes in genjutsu along with his teammates Mubi and Kagari. They are bested by Naruto in the Forest of Death and lose their scroll. They later reappear as hired henchmen attempting to sabotage a race in the Tea Country, only to be bested by Naruto once again.\"}','{\"Description\": \"A genin from Hidden Rain, Oboro specializes in genjutsu along with his teammates Mubi and Kagari. They are bested by Naruto in the Forest of Death and lose their scroll. They later reappear as hired henchmen attempting to sabotage a race in the Tea Country, only to be bested by Naruto once again.\"}'),(263,67285,'Okisuke','{\"Description\":\"Okisuke (\\u30AA\\u30AD\\u30B9\\u30B1, Okisuke) is a samurai from the Land of Iron and one of Mifune\\u0027s right-hand-man alongside Urakaku.\",\"Manga Debut\":\"Chapter #456\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #199\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #199\", \"Description\": \"Okisuke (オキスケ, Okisuke) is a samurai from the Land of Iron and one of Mifune\'s right-hand-man alongside Urakaku.\", \"Manga Debut\": \"Chapter #456\"}'),(264,22872,'Omoi','{\"Description\":\"Omoi is a shinobi of Kumogakure, and a member of Team Samui. He is Killer Bee\\u0027s student along with the other two members of his team.\",\"Description_2\":\"Omoi is dark skinned with spiky white hair like most Kumo nin. He is always seen sucking on a lolipop. As a sword user he carries his sword on his back with the one strapped Kumo Flack Jacket.\",\"Description_3\":\"He is a very careful ninja, and likes to think things through before acting. He is more level-headed than his teammate Karui, but has a habit of exaggerating the end result of minor things (like when Karui threw a rock at him and he believed it would cause an avalanche and destroy Konoha). He also has respect for people who stand by their word, even if they are the enemy. He is a very intelligent ninja.\",\"Description_4\":\"He has amazing speed, and is able to move around the battlefield in the blink of an eye. His taijutsu skill is good, being able to move around fluidly with his teammates. He also uses swordplay in his fighting style, like most Kumogakure shinobi.\",\"His name is a pun on two words which have the pronunciation \\u0022Omoi\\u0022\":\"\",\"Description_5\":\"\\u91CD\\u3044, which means \\u0022heavy\\u0022, contrasting with Karui, which means \\u0022light\\u0022.\",\"Description_6\":\"\\u601D\\u3044, which means \\u0022thought\\u0022, alluding to his thoughtful manner.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Omoi is a shinobi of Kumogakure, and a member of Team Samui. He is Killer Bee\'s student along with the other two members of his team.\", \"Description_2\": \"Omoi is dark skinned with spiky white hair like most Kumo nin. He is always seen sucking on a lolipop. As a sword user he carries his sword on his back with the one strapped Kumo Flack Jacket.\", \"Description_3\": \"He is a very careful ninja, and likes to think things through before acting. He is more level-headed than his teammate Karui, but has a habit of exaggerating the end result of minor things (like when Karui threw a rock at him and he believed it would cause an avalanche and destroy Konoha). He also has respect for people who stand by their word, even if they are the enemy. He is a very intelligent ninja.\", \"Description_4\": \"He has amazing speed, and is able to move around the battlefield in the blink of an eye. His taijutsu skill is good, being able to move around fluidly with his teammates. He also uses swordplay in his fighting style, like most Kumogakure shinobi.\", \"Description_5\": \"重い, which means \\\"heavy\\\", contrasting with Karui, which means \\\"light\\\".\", \"Description_6\": \"思い, which means \\\"thought\\\", alluding to his thoughtful manner.\", \"His name is a pun on two words which have the pronunciation \\\"Omoi\\\"\": \"\"}'),(265,23475,'Oonoki','{\"Description\":\"\\u014Cnoki is the current Tsuchikage of Iwagakure.\",\"Description_2\":\"As a young man, \\u014Cnoki was a student to the Second Tsuchikage, M\\u016B who taught him how to use the Dust Release techniques. Later in life, he himself would become teacher to Deidara. Though he often implied that Deidara\\u0027s ideologies and fighting style annoyed him, he was still proud of him. At some time in the past, \\u014Cnoki fought with Madara Uchiha, the only living Kage to do so. His knowledge of Madara\\u0027s power made him wary of him, and was thus surprised that the latter would choose to carry out his designs behind the shadows through Akatsuki. Probably unaware of Madara\\u0027s major role as Akatsuki\\u0027s founder, he hired the former mercenary group many times for their services in the past, which he rationalized by his concern over Kumogakure\\u0027s unwavering militarization. He has also apparently known and dealt with A, the Fourth Raikage, since the latter was young.\",\"Description_3\":\"\\u014Cnoki is very proud but appears frail, with constant complaints referring to his hips and back. He also refuses to retire and choose a successor as Tsuchikage despite his frailty, insisting that he is still strong enough to continue to rule the village. Kurotsuchi describes him as a \\u0022stubborn old man\\u0022. His pride has him give very little respect for those younger than him, as he verbally attacked Gaara (a Kazekage who is many years younger) on numerous occasions, dismissing his presumed naivety on dealing with politics. Deidara also noted \\u014Cnoki to hate art, possibly for ridiculing his Exploding Clay artwork. During the chaos Sasuke Uchiha had started, \\u014Cnoki didn\\u0027t seem to be alarmed once the battle in the Summit Room began. He appeared to be calm, enough to let Mei Terum\\u012B deal with the current situation. Upon observing the fight between the two, he seemed quite entertained, which led him to join the riot.\",\"Description_4\":\"\\u014Cnoki seems to be quite ruthless, taking down a heavily-injured Sasuke who had just been saved yet again after facing the wrath of three other Kage before him, on the claim that the Ninja World wants Sasuke dead even though \\u014Cnoki himself has no grudge against Sasuke personally. He then immediately turned his attention to a devastated Karin, claiming that she\\u0027s next to die. He does, however, seem to be considerate enough to let Madara speak for his actions, reasoning with the Raikage to listen to his reasons before making their own. According to his thinking of strategy, \\u014Cnoki might be the type of person who takes risks. A similarity can be shown with Tsunade, as she has a habit of gambling and taking risks often. Remembering what Gaara said to him, he states to Akatsuchi and Kurotsuchi that he remembered what he really used to be before he became a stubborn old man, likely meaning he had a more kind and friendly heart in his youth.\",\"Description_5\":\"\\u014Cnoki is a powerful and capable Tsuchikage. He is physically frail, however, and as such he isn\\u0027t suited for taijutsu fighting. He has a great deal of experience, having fought Madara Uchiha and survived, thus his knowledge is invaluable to the Allied Shinobi Forces.\",\"Description_6\":\"Nature Transformation\",\"Description_7\":\"\\u014Cnoki possesses the ability to use the Kekkei T\\u014Dta known as Dust Release, by combining three elements, such as Earth, Wind, and Fire. He is only the second shinobi in existence with this ability. \\u014Cnoki\\u0027s dust release ninjutsu allow him to pulverize his enemies to molecule-sized dust. His techniques can be so destructive that they reputably are capable of destroying an entire island.[4] His Earth Release ninjutsu is particularly powerful, and could turn targets into stone by a mere touch.\",\"Description_8\":\"Flight Technique\",\"Description_9\":\"Another one of \\u014Cnoki\\u0027s trademark techniques is his ability to fly, which he is also capable of transferring to others. He can fly at very high speeds even in his old age. Size also doesn\\u0027t seem to matter when using the technique, as he used the technique on the Island Turtle carrying it in the air to Kumogakure.\"}','{\"Description\": \"Ōnoki is the current Tsuchikage of Iwagakure.\", \"Description_2\": \"As a young man, Ōnoki was a student to the Second Tsuchikage, Mū who taught him how to use the Dust Release techniques. Later in life, he himself would become teacher to Deidara. Though he often implied that Deidara\'s ideologies and fighting style annoyed him, he was still proud of him. At some time in the past, Ōnoki fought with Madara Uchiha, the only living Kage to do so. His knowledge of Madara\'s power made him wary of him, and was thus surprised that the latter would choose to carry out his designs behind the shadows through Akatsuki. Probably unaware of Madara\'s major role as Akatsuki\'s founder, he hired the former mercenary group many times for their services in the past, which he rationalized by his concern over Kumogakure\'s unwavering militarization. He has also apparently known and dealt with A, the Fourth Raikage, since the latter was young.\", \"Description_3\": \"Ōnoki is very proud but appears frail, with constant complaints referring to his hips and back. He also refuses to retire and choose a successor as Tsuchikage despite his frailty, insisting that he is still strong enough to continue to rule the village. Kurotsuchi describes him as a \\\"stubborn old man\\\". His pride has him give very little respect for those younger than him, as he verbally attacked Gaara (a Kazekage who is many years younger) on numerous occasions, dismissing his presumed naivety on dealing with politics. Deidara also noted Ōnoki to hate art, possibly for ridiculing his Exploding Clay artwork. During the chaos Sasuke Uchiha had started, Ōnoki didn\'t seem to be alarmed once the battle in the Summit Room began. He appeared to be calm, enough to let Mei Terumī deal with the current situation. Upon observing the fight between the two, he seemed quite entertained, which led him to join the riot.\", \"Description_4\": \"Ōnoki seems to be quite ruthless, taking down a heavily-injured Sasuke who had just been saved yet again after facing the wrath of three other Kage before him, on the claim that the Ninja World wants Sasuke dead even though Ōnoki himself has no grudge against Sasuke personally. He then immediately turned his attention to a devastated Karin, claiming that she\'s next to die. He does, however, seem to be considerate enough to let Madara speak for his actions, reasoning with the Raikage to listen to his reasons before making their own. According to his thinking of strategy, Ōnoki might be the type of person who takes risks. A similarity can be shown with Tsunade, as she has a habit of gambling and taking risks often. Remembering what Gaara said to him, he states to Akatsuchi and Kurotsuchi that he remembered what he really used to be before he became a stubborn old man, likely meaning he had a more kind and friendly heart in his youth.\", \"Description_5\": \"Ōnoki is a powerful and capable Tsuchikage. He is physically frail, however, and as such he isn\'t suited for taijutsu fighting. He has a great deal of experience, having fought Madara Uchiha and survived, thus his knowledge is invaluable to the Allied Shinobi Forces.\", \"Description_6\": \"Nature Transformation\", \"Description_7\": \"Ōnoki possesses the ability to use the Kekkei Tōta known as Dust Release, by combining three elements, such as Earth, Wind, and Fire. He is only the second shinobi in existence with this ability. Ōnoki\'s dust release ninjutsu allow him to pulverize his enemies to molecule-sized dust. His techniques can be so destructive that they reputably are capable of destroying an entire island.[4] His Earth Release ninjutsu is particularly powerful, and could turn targets into stone by a mere touch.\", \"Description_8\": \"Flight Technique\", \"Description_9\": \"Another one of Ōnoki\'s trademark techniques is his ability to fly, which he is also capable of transferring to others. He can fly at very high speeds even in his old age. Size also doesn\'t seem to matter when using the technique, as he used the technique on the Island Turtle carrying it in the air to Kumogakure.\"}'),(266,57883,'Ootsutsuki, Hagoromo','{\"Description\":\"The Sage of the Six Paths (\\u516D\\u9053\\u4ED9\\u4EBA, Rikud\\u014D Sennin) was the legendary figure who founded the arts of ninjutsu and created the ninja world. He defeated the Ten-Tails and sealed it within his own body, thus becoming the first jinch\\u016Briki.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"The Sage of the Six Paths (六道仙人, Rikudō Sennin) was the legendary figure who founded the arts of ninjutsu and created the ninja world. He defeated the Ten-Tails and sealed it within his own body, thus becoming the first jinchūriki.\"}'),(267,127263,'Ootsutsuki, Indra','{\"Manga debut\":\"Chapter #462\",\"Description\":\"Indra Ootsutsuki was the elder son of Hagoromo Ootsutsuki. From a young age, he demonstrated a great aptitude towards ninshuu and anything else he applied his mind to. Due to his prowess, he led a solitary life as he felt no need to depend on others. He is also the ancestor of the Uchiha clan.\"}','{\"Description\": \"Indra Ootsutsuki was the elder son of Hagoromo Ootsutsuki. From a young age, he demonstrated a great aptitude towards ninshuu and anything else he applied his mind to. Due to his prowess, he led a solitary life as he felt no need to depend on others. He is also the ancestor of the Uchiha clan.\", \"Manga debut\": \"Chapter #462\"}'),(268,127264,'Ootsutsuki, Ashura','{\"Description\":\"Ashura Ootsutsuki was the youngest son of Hagoromo Ootsutsuki and heir to his teachings. He is also the ancestor of the Senju clan, as well as the Uzumaki clan.\"}','{\"Description\": \"Ashura Ootsutsuki was the youngest son of Hagoromo Ootsutsuki and heir to his teachings. He is also the ancestor of the Senju clan, as well as the Uzumaki clan.\"}'),(269,127957,'Ootsutsuki, Hamura','{\"Description\":\"Hamura Ootsutsuki is the son of Princess Kaguya Ootsutsuki\\u200E\\u200E, the fraternal twin brother of Hagoromo Ootsutsuki; both of whom were the first two born with the ability to wield chakra. Hamura was also the ancestor of the Hyuuga clan and the founder of the shinobi of the moon.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Hamura Ootsutsuki is the son of Princess Kaguya Ootsutsuki‎‎, the fraternal twin brother of Hagoromo Ootsutsuki; both of whom were the first two born with the ability to wield chakra. Hamura was also the ancestor of the Hyuuga clan and the founder of the shinobi of the moon.\"}'),(270,108297,'Ootsutsuki, Kaguya','{\"Description\":\"Princess Kaguya Ootsutsuki is the mother of Hagoromo Ootsutsuki and Hamura Ootsutsuki, who consumed the fruit of the Shinju and became the progenitor of chakra and part of the creation of the Ten-Tails.\",\"Manga Debut\":\"Chapter #670\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Princess Kaguya Ootsutsuki is the mother of Hagoromo Ootsutsuki and Hamura Ootsutsuki, who consumed the fruit of the Shinju and became the progenitor of chakra and part of the creation of the Ten-Tails.\", \"Manga Debut\": \"Chapter #670\"}'),(271,2455,'Orochimaru','{\"Name Meaning\":\"Orochi= Large Serpent, Maru= Male Name\",\"Age\":\"50-51 (I); 54 (II)\",\"Sex\":\"Male\",\"Birthday\":\"October 27\",\"Zodiac Sign\":\"Scorpio\",\"Height\":\"179.4 cm (Part I); 172.0 cm (Part II)\",\"Weight\":\"67 kg (Part I); 58 kg (Part II)\",\"Blood Type\":\"B\",\"Description\":\"Bloodline Limit Wood Release\",\"Nature Type\":\"Wind, Water, Wood, Earth and Fire.\",\"Originally From\":\"Konohagakure (Leaf)\",\"Affiliations\":\"Konohagakure (Leaf), Root, Akatsuki, Otagakure (Sound)\",\"Classification\":\"Sannin, Sage, S-rank, Missing-nin\",\"Rank\":\"ANBU\",\"Ninja Registration Number\":\"002300\",\"Academy Graduation Age\":\"6\",\"Akatsuki Ring\":\"Void (Sky)\",\"Finger Position\":\"Left little finger\",\"Partner\":\"Sasori, Yakushi Kabuto\",\"Favorite Foods\":\"Eggs\",\"Least Favorite Foods\":\"Cold Food\",\"Personality\":\"Ambitious, cruel, egoistic\",\"Favourite Word\":\"Destruction, chaos\",\"Interests\":\"Developing new jutsu\",\"First Manga Appearance\":\"Chapter 45\",\"First Anime Appearance\":\"Episode 27\",\"Assignments Completed\":\"16 D-Rank, 132 C-Rank, 521 B-Rank, 491 A-Rank, 108 S-Rank\",\"Description_2\":\"Orochimaru is a major antagonist of Naruto series. He is a missing ninja from Konohagakure, who is recognised as one of the most powerful ninjas and known as one of the \\u0022Legendary Sannin\\u0022 (Legendary Three Ninja), which was a title that was given to him and his former team mates, Jiraiya and Tsunade, by Hanz\\u014D during the Second Shinobi World War. His main goals are to capture Uchiha Sasuke as his new body to gain possession of the Sharingan and to destroy Konoha.\",\"Description_3\":\"From his childhood days Orochimaru was identified as a genius shinobi and a once-in-a-generation prodigy. His parents died when he was young and according to Jiraiya, Orochimaru\\u0027s goals, which were quite alien to the ideals within the village, were associated with these painful memories.\",\"Description_4\":\"He was a student of the Third Hokage, who recognized Orochimaru\\u0027s natural talent and often told Jiraiya to be more like Orochimaru. The Third was aware of a malice and a lust for power within Orochimaru, but chose to pretend not to notice and hoped that he could quell this part of Orochimaru\\u0027s personality.\",\"Description_5\":\"Orochimaru\\u0027s desire for power grew as the years went by. One day while visiting his parents\\u0027 grave he found the shedded skin of a white snake. As the Third Hokage explained, it was known to represent good forture and luck which inspired Orochimaru. He began to study kinjutsu (forbidden techniques) and became obsessed with learning all ninjutsu that exists in the world.\",\"Description_6\":\"After leaving Konoha, Orochimaru joined an elite criminal organisation called Akatsuki. What he did while he was a member of the organization is pretty much unknown. The only information that was revealed is that his partner was Sasori and he made an attempt to take control of Uchiha Itachi\\u0027s body to gain the possesion of the Sharingan.\"}','{\"Age\": \"50-51 (I); 54 (II)\", \"Sex\": \"Male\", \"Rank\": \"ANBU\", \"Height\": \"179.4 cm (Part I); 172.0 cm (Part II)\", \"Weight\": \"67 kg (Part I); 58 kg (Part II)\", \"Partner\": \"Sasori, Yakushi Kabuto\", \"Birthday\": \"October 27\", \"Interests\": \"Developing new jutsu\", \"Blood Type\": \"B\", \"Description\": \"Bloodline Limit Wood Release\", \"Nature Type\": \"Wind, Water, Wood, Earth and Fire.\", \"Personality\": \"Ambitious, cruel, egoistic\", \"Zodiac Sign\": \"Scorpio\", \"Affiliations\": \"Konohagakure (Leaf), Root, Akatsuki, Otagakure (Sound)\", \"Name Meaning\": \"Orochi= Large Serpent, Maru= Male Name\", \"Akatsuki Ring\": \"Void (Sky)\", \"Description_2\": \"Orochimaru is a major antagonist of Naruto series. He is a missing ninja from Konohagakure, who is recognised as one of the most powerful ninjas and known as one of the \\\"Legendary Sannin\\\" (Legendary Three Ninja), which was a title that was given to him and his former team mates, Jiraiya and Tsunade, by Hanzō during the Second Shinobi World War. His main goals are to capture Uchiha Sasuke as his new body to gain possession of the Sharingan and to destroy Konoha.\", \"Description_3\": \"From his childhood days Orochimaru was identified as a genius shinobi and a once-in-a-generation prodigy. His parents died when he was young and according to Jiraiya, Orochimaru\'s goals, which were quite alien to the ideals within the village, were associated with these painful memories.\", \"Description_4\": \"He was a student of the Third Hokage, who recognized Orochimaru\'s natural talent and often told Jiraiya to be more like Orochimaru. The Third was aware of a malice and a lust for power within Orochimaru, but chose to pretend not to notice and hoped that he could quell this part of Orochimaru\'s personality.\", \"Description_5\": \"Orochimaru\'s desire for power grew as the years went by. One day while visiting his parents\' grave he found the shedded skin of a white snake. As the Third Hokage explained, it was known to represent good forture and luck which inspired Orochimaru. He began to study kinjutsu (forbidden techniques) and became obsessed with learning all ninjutsu that exists in the world.\", \"Description_6\": \"After leaving Konoha, Orochimaru joined an elite criminal organisation called Akatsuki. What he did while he was a member of the organization is pretty much unknown. The only information that was revealed is that his partner was Sasori and he made an attempt to take control of Uchiha Itachi\'s body to gain the possesion of the Sharingan.\", \"Classification\": \"Sannin, Sage, S-rank, Missing-nin\", \"Favorite Foods\": \"Eggs\", \"Favourite Word\": \"Destruction, chaos\", \"Finger Position\": \"Left little finger\", \"Originally From\": \"Konohagakure (Leaf)\", \"Least Favorite Foods\": \"Cold Food\", \"Assignments Completed\": \"16 D-Rank, 132 C-Rank, 521 B-Rank, 491 A-Rank, 108 S-Rank\", \"Academy Graduation Age\": \"6\", \"First Anime Appearance\": \"Episode 27\", \"First Manga Appearance\": \"Chapter 45\", \"Ninja Registration Number\": \"002300\"}'),(272,97795,'Osoi','{\"Description\":\"Osoi (\\u30AA\\u30BD\\u30A4, Osoi) was a genin-level shinobi from Kumogakure who once fought alongside Toroi. He was also the father of Musai.\",\"Description_2\":\"Osoi fought alongside Toroi in his last battle, which lead to his own death. He was later mistakenly reincarnated by Orochimaru in an attempt to reincarnate Toroi. After explaining the mix-up to Orochimaru and Kabuto, they decided to keep him around for future use.\",\"Description_3\":\"During the Fourth Shinobi World War, Kabuto deployed Osoi, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. During a scuffle between Kabuto\\u0027s weaker pawns and the Allied Shinobi Forces, Osoi spotted his son Musai. After they talked for a while, Osoi was sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\",\"Anime Debut\":\"Naruto Shippuuden Episode #316\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #316\", \"Description\": \"Osoi (オソイ, Osoi) was a genin-level shinobi from Kumogakure who once fought alongside Toroi. He was also the father of Musai.\", \"Description_2\": \"Osoi fought alongside Toroi in his last battle, which lead to his own death. He was later mistakenly reincarnated by Orochimaru in an attempt to reincarnate Toroi. After explaining the mix-up to Orochimaru and Kabuto, they decided to keep him around for future use.\", \"Description_3\": \"During the Fourth Shinobi World War, Kabuto deployed Osoi, who he saw as one of his weaker assets, in an attempt to unseal his other, stronger pawns. During a scuffle between Kabuto\'s weaker pawns and the Allied Shinobi Forces, Osoi spotted his son Musai. After they talked for a while, Osoi was sealed. Later, when the Impure World Reincarnation Technique was canceled, his soul was returned to the afterlife.\"}'),(273,204898,'Oyashiro, En','{\"Description\":\"En Oyashiro is a shinobi and arms dealer from the Chinoike clan. He would occasionally attend the Coliseum as a patron in order to collect kekkei genkai.\",\"(Source\":\"Naruto Wiki)\"}','{\"(Source\": \"Naruto Wiki)\", \"Description\": \"En Oyashiro is a shinobi and arms dealer from the Chinoike clan. He would occasionally attend the Coliseum as a patron in order to collect kekkei genkai.\"}'),(274,3180,'Pain','{\"Description\":\"Pain is the recognized leader of Akatsuki, partnered to Konan, with Tobi acting as his benefactor. He is the principal figure in the tailed beast sealing ceremony.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Pain is the recognized leader of Akatsuki, partnered to Konan, with Tobi acting as his benefactor. He is the principal figure in the tailed beast sealing ceremony.\"}'),(275,2766,'Pakkun','{\"Description\":\"Pakkun is one of Kakashi\\u0027s summoning dogs, probably his favorite. He is a helpful tracker dog that can find and track most things; he\\u0027s very calm, cool, and collected.\"}','{\"Description\": \"Pakkun is one of Kakashi\'s summoning dogs, probably his favorite. He is a helpful tracker dog that can find and track most things; he\'s very calm, cool, and collected.\"}'),(276,63791,'Pakura','{\"Description\":\"Pakura was a famed Sunagakure kunoichi during her lifetime.\",\"She possesses a kekkei genkai known as Scorch Release. By combining two unknown chakra natures, she can create heat orbs that \\u0022mummify\\u0022 her enemies, killing them seemingly by evaporating all the moisture in their bodies. Pakura displays this ability when using Scorch Release\":\"Extremely Steaming Murder; combined with her incredible agility, she managed to kill many Allied Shinobi Forces members in a short amount of time.\",\"Manga Debut\":\"Chapter #516\",\"Anime Debut\":\"Naruto Shippuuden Episode #261\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #261\", \"Description\": \"Pakura was a famed Sunagakure kunoichi during her lifetime.\", \"Manga Debut\": \"Chapter #516\", \"She possesses a kekkei genkai known as Scorch Release. By combining two unknown chakra natures, she can create heat orbs that \\\"mummify\\\" her enemies, killing them seemingly by evaporating all the moisture in their bodies. Pakura displays this ability when using Scorch Release\": \"Extremely Steaming Murder; combined with her incredible agility, she managed to kill many Allied Shinobi Forces members in a short amount of time.\"}'),(277,73781,'Ran','{\"Description\":\"Ran (\\u30E9\\u30F3, Ran) is a kunoichi of Kumogakure.\",\"Description_2\":\"She has a short crop of brown hair and blue eyes. She wore a midriff blouse and a skirt along with a customized midriff Kumogakure flak jacket. She also wore red wrist warmers, stockings and a pair of sandals with the forehead protector of the Allied Shinobi Forces.\",\"Description_3\":\"Not much is known of her abilities but she was presumably skilled in kenjutsu as she carried a tantou strapped to her shoulder.\",\"Description_4\":\"During the Fourth Shinobi World War, Ran was assigned to the Third Division. She and her comrades were set upon by Jinpachi Munashi and Kushimaru Kuriarare and she was rendered unconscious by Jinpachi\\u0027s explosion. She was saved by the arrival of Might Guy and Kakashi Hatake, the latter of whom told her to flee the battle scene. She, however, later returned to the members of the Third Division and the Sealing Team leading to Kushimaru and Jinpachi being successfully sealed away.\",\"Anime Debut\":\"Naruto Shippuuden Episode #288\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #288\", \"Description\": \"Ran (ラン, Ran) is a kunoichi of Kumogakure.\", \"Description_2\": \"She has a short crop of brown hair and blue eyes. She wore a midriff blouse and a skirt along with a customized midriff Kumogakure flak jacket. She also wore red wrist warmers, stockings and a pair of sandals with the forehead protector of the Allied Shinobi Forces.\", \"Description_3\": \"Not much is known of her abilities but she was presumably skilled in kenjutsu as she carried a tantou strapped to her shoulder.\", \"Description_4\": \"During the Fourth Shinobi World War, Ran was assigned to the Third Division. She and her comrades were set upon by Jinpachi Munashi and Kushimaru Kuriarare and she was rendered unconscious by Jinpachi\'s explosion. She was saved by the arrival of Might Guy and Kakashi Hatake, the latter of whom told her to flee the battle scene. She, however, later returned to the members of the Third Division and the Sealing Team leading to Kushimaru and Jinpachi being successfully sealed away.\"}'),(278,60105,'Ranka','{\"Description\":\"Ranka (\\u30E9\\u30F3\\u30AB, Ranka; Viz \\u0022Lanka\\u0022) is a ninja from Konohagakure.\",\"Manga Debut\":\"Chapter #489\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #197\"}','{\"Anime Debut\": \"Naruto Shippūden Episode #197\", \"Description\": \"Ranka (ランカ, Ranka; Viz \\\"Lanka\\\") is a ninja from Konohagakure.\", \"Manga Debut\": \"Chapter #489\"}'),(279,22920,'Rasa','{\"Birthdate\":\"March 29\",\"Gender\":\"Male\",\"Age\":\"40\",\"Height\":\"176.5 cm\",\"Weight\":\"64.1 kg\",\"Blood type\":\"A\",\"Kekkei Genkai\":\"Magnet Release\",\"Occupation\":\"Kazekage\",\"Affiliation\":\"Sunagakure\",\"Description\":\"Rasa was the Fourth Kazekage of Sunagakure. He is the father of Temari, Kankur\\u014D, and Gaara, and husband of Karura.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"40\", \"Gender\": \"Male\", \"Height\": \"176.5 cm\", \"Weight\": \"64.1 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"March 29\", \"Blood type\": \"A\", \"Occupation\": \"Kazekage\", \"Affiliation\": \"Sunagakure\", \"Description\": \"Rasa was the Fourth Kazekage of Sunagakure. He is the father of Temari, Kankurō, and Gaara, and husband of Karura.\", \"Kekkei Genkai\": \"Magnet Release\"}'),(280,93629,'Reto','{\"Birthdate\":\"June 27\",\"Gender\":\"Male\",\"Age\":\"58\",\"Status\":\"Deceased\",\"Height\":\"195.8 cm\",\"Weight\":\"81.8 kg\",\"Blood type\":\"A\",\"Occupation\":\"Kazekage\",\"Affiliation\":\"Sunagakure\",\"Description\":\"Reto was the First Kazekage who founded Sunagakure in the Land of Wind, and was said to have gathered all the desert-dwelling shinobi under his control with his overwhelming power.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"58\", \"Gender\": \"Male\", \"Height\": \"195.8 cm\", \"Status\": \"Deceased\", \"Weight\": \"81.8 kg\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"June 27\", \"Blood type\": \"A\", \"Occupation\": \"Kazekage\", \"Affiliation\": \"Sunagakure\", \"Description\": \"Reto was the First Kazekage who founded Sunagakure in the Land of Wind, and was said to have gathered all the desert-dwelling shinobi under his control with his overwhelming power.\"}'),(281,64459,'Ringo, Ameyuri','{\"Description\":\"Ameyuri Ringo (\\u6797\\u6A8E\\u96E8\\u7531\\u5229, Ringo Ameyuri) is one of the former members of the Seven Ninja Swordsmen of the Mist.\",\"Description_2\":\"Ameyuri was very skilled at utilising the Kiba, twin swords imbued with lightning, which are claimed to be the sharpest sword that were made, having the ability to cut through anything, by apparently functioning in a similar manner to Lightning Release-based chakra flow which she wielded with great dexterit. In the anime, it was shown that Ameyuri uses the Kiba in combination with agile spinning movements, sweeping through her targets while rotating around herself, hitting all enemies around her.\",\"Manga Debut\":\"Chapter #522\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #265\",\"(Source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #265\", \"(Source\": \"Narutopedia)\", \"Description\": \"Ameyuri Ringo (林檎雨由利, Ringo Ameyuri) is one of the former members of the Seven Ninja Swordsmen of the Mist.\", \"Manga Debut\": \"Chapter #522\", \"Description_2\": \"Ameyuri was very skilled at utilising the Kiba, twin swords imbued with lightning, which are claimed to be the sharpest sword that were made, having the ability to cut through anything, by apparently functioning in a similar manner to Lightning Release-based chakra flow which she wielded with great dexterit. In the anime, it was shown that Ameyuri uses the Kiba in combination with agile spinning movements, sweeping through her targets while rotating around herself, hitting all enemies around her.\"}'),(282,22184,'Rinji','{\"Description\":\"Rinji (\\u9E9F\\u5150, Rinji) is a shinobi, under Orochimaru, who appears in the second Naruto Shipp\\u016Bden filler arc.\"}','{\"Description\": \"Rinji (麟児, Rinji) is a shinobi, under Orochimaru, who appears in the second Naruto Shippūden filler arc.\"}'),(283,23221,'Roushi','{\"Description\":\"R\\u014Dshi (\\u8001\\u7D2B) became the Jinch\\u016Briki the Four-Tailed Beast at a very young age. He left his hometown of Iwagakure at some point to understand and control the power of the beast within him. By borrowing the Four-Tails\\u0027 power, R\\u014Dshi was able to use its Lava Release ninjutsu, a combination of Fire and Earth-based chakra. He was captured by Kisame Hoshigaki of Akatsuki and later died as the result of having the Four-Tails extracted from his body.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Rōshi (老紫) became the Jinchūriki the Four-Tailed Beast at a very young age. He left his hometown of Iwagakure at some point to understand and control the power of the beast within him. By borrowing the Four-Tails\' power, Rōshi was able to use its Lava Release ninjutsu, a combination of Fire and Earth-based chakra. He was captured by Kisame Hoshigaki of Akatsuki and later died as the result of having the Four-Tails extracted from his body.\"}'),(284,94809,'Ruka','{\"Description\":\"Ruka (\\u30EB\\u30AB, Ruka) is a kunoichi of Kirigakure.\",\"Description_2\":\"As the reincarnated shinobi reappeared on the battlefield, most of the Third Division is scattered into small squads. Ruka is part of a squad led by Monga. Ruka promised Monga that she would also put her life on the line to save his, if something were to happen to him. Gari appears before the squad and after a short fight, is blown up by Monga. Ruka and the squad look in shock when Monga is mummified by Pakura. Maki explains to Ruka that she was once the kunoichi\\u0027s student. After revealing her death at the hands of Kirigakure, Ruka explains to Pakura that the \\u0022Bloody Mist\\u0022 was no longer the murderous village it used to be thanks to the Fifth Mizukage, however Pakura notes that it would not erase the past. Pakura launched another attack on the squad and incinerates the area to find the hiding shinobi. The squad protect themselves from the blast with Maki\\u0027s Cloth Binding Technique and Ruka\\u0027s Water Release. Pakura finds the squad and prepares to kill them until the arrival of Omoi and Zaji. As Gari\\u0027s regeneration is finished, he joins Pakura in fighting the shinobi but having a change of heart, Pakura allows the squad to flee while halting Gari\\u0027s movements.\",\"Anime Debut\":\"Naruto Shippuuden Episode #285\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #285\", \"Description\": \"Ruka (ルカ, Ruka) is a kunoichi of Kirigakure.\", \"Description_2\": \"As the reincarnated shinobi reappeared on the battlefield, most of the Third Division is scattered into small squads. Ruka is part of a squad led by Monga. Ruka promised Monga that she would also put her life on the line to save his, if something were to happen to him. Gari appears before the squad and after a short fight, is blown up by Monga. Ruka and the squad look in shock when Monga is mummified by Pakura. Maki explains to Ruka that she was once the kunoichi\'s student. After revealing her death at the hands of Kirigakure, Ruka explains to Pakura that the \\\"Bloody Mist\\\" was no longer the murderous village it used to be thanks to the Fifth Mizukage, however Pakura notes that it would not erase the past. Pakura launched another attack on the squad and incinerates the area to find the hiding shinobi. The squad protect themselves from the blast with Maki\'s Cloth Binding Technique and Ruka\'s Water Release. Pakura finds the squad and prepares to kill them until the arrival of Omoi and Zaji. As Gari\'s regeneration is finished, he joins Pakura in fighting the shinobi but having a change of heart, Pakura allows the squad to flee while halting Gari\'s movements.\"}'),(285,41212,'Sabiru','{\"Description\":\"Sabiru (\\u30B5\\u30D3\\u30EB, Sabiru) was a young high level shinobi in Konohagakure\\u0026amp;#039;s tactical division. He was later discovered to be a traitor and a spy.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #193\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #193\", \"(source\": \")\", \"Description\": \"Sabiru (サビル, Sabiru) was a young high level shinobi in Konohagakure&amp;#039;s tactical division. He was later discovered to be a traitor and a spy.\"}'),(286,225053,'Sabu','{}','{}'),(287,279534,'Sada','{\"Description\":\"Both Sada and his twin brother Kiji seem to have very cheerful dispositions and are often seen smiling. The two brothers also tend to sing while they work or if they speak they say the same thing.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Both Sada and his twin brother Kiji seem to have very cheerful dispositions and are often seen smiling. The two brothers also tend to sing while they work or if they speak they say the same thing.\"}'),(288,41213,'Sadai','{\"Description\":\"Sadai (\\u30B5\\u30C0\\u30A4, Sadai) is an assailant who entered Land of Fire to capture Naho. He was on the national wanted list.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #196\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #196\", \"(source\": \")\", \"Description\": \"Sadai (サダイ, Sadai) is an assailant who entered Land of Fire to capture Naho. He was on the national wanted list.\"}'),(289,98655,'Sagan','{\"Description\":\"Sagan (\\u30B5\\u30AC\\u30F3, Sagan) is a shinobi from Iwagakure.\",\"Description_2\":\"During the Fourth Shinobi World War, Sagan was assigned to the Fourth Division. He was one of the few shinobi of that division to survive Madara Uchiha\\u0027s assault on the battlefield. Making his way over to where \\u014Cnoki was, he informed the other that the Tsuchikage was still alive, though gravely injured. He later alerted those present when Madara and M\\u016B had reconstructed, and watched on in despair as Madara continued his assault on the depleted division. When the five Kage assembled on the battlefield, Sagan looked on in amazement as the battle between the titans unfolded, noting that he felt severely out of place. Later, Sagan was seen pursuing M\\u016B alongside Dodai and the Hokage Guard Platoon.\",\"Manga Debut\":\"Chapter #561\",\"Anime Debut\":\"Naruto Shippuuden Episode #322\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #322\", \"Description\": \"Sagan (サガン, Sagan) is a shinobi from Iwagakure.\", \"Manga Debut\": \"Chapter #561\", \"Description_2\": \"During the Fourth Shinobi World War, Sagan was assigned to the Fourth Division. He was one of the few shinobi of that division to survive Madara Uchiha\'s assault on the battlefield. Making his way over to where Ōnoki was, he informed the other that the Tsuchikage was still alive, though gravely injured. He later alerted those present when Madara and Mū had reconstructed, and watched on in despair as Madara continued his assault on the depleted division. When the five Kage assembled on the battlefield, Sagan looked on in amazement as the battle between the titans unfolded, noting that he felt severely out of place. Later, Sagan was seen pursuing Mū alongside Dodai and the Hokage Guard Platoon.\"}'),(290,241432,'Sagiri','{}','{}'),(291,1901,'Sai','{\"Birthdate\":\"November 25\",\"Age\":\"17\",\"Ninja Registration N\\u00BA\":\"012420\",\"Blood type\":\"A\",\"Height\":\"172.1 cm\",\"Weight\":\"53.3 kg\",\"Current rank\":\"ANBU\",\"Description\":\"Sai is the replacement of Sasuke Uchiha in Team 7. The name \\u0022Sai\\u0022 is given to him for the purposes of joining the team, his actual name being unknown. He was recruited at a young age by Root, which trained him to have no emotions so as to make it easier for him to accomplish missions. This lack of personality causes Sai to meet with hardship upon joining Team 7, as he makes the mistake of insulting the other members in an attempt to seem sociable. He tries to seem more caring by smiling, though his teammates come to dislike it due to his obvious insincerity. After spending more time with his team Sai comes to appreciate bonds, particularly the bond that exists between Naruto Uzumaki and Sasuke Uchiha. Wanting to experience bonds for himself, Sai sets out to make as many bonds as he can. His initial attempts consist of giving people pet names, though his habit of calling people as he sees them (\\u0022fat\\u0022, \\u0022ugly\\u0022, etc.) finds little success. Realizing that people dislike hearing how they actually look, Sai begins to say the opposite of how he sees them, such as calling Ino Yamanaka \\u0022beautiful\\u0022. With names proving successful, Sai has since made attempts to be helpful to others, though his attempts have thus far been unwanted by those he is trying to help.\",\"Description_2\":\"Sai is a talented artist, and claims to have drawn thousands of pictures. Despite the magnitude of pictures he has drawn, his lack of emotion makes it impossible for him be inspired to give something a title, and thus all of his works are nameless. Sai\\u0027s drawing ability is also the source of his jutsu; by drawing things with a brush on his scroll he is able to bring his creations to life, giving them an increased size and the ability to move. His Super Beasts Imitation Picture (\\u8D85\\u7363\\u507D\\u753B, Ch\\u014Dj\\u016B Giga) allows him to create birds that he can use for flight and lion-like creatures that he can use for attack. Likewise, by creating an Ink Clone (\\u58A8\\u5206\\u8EAB, Sumi Bunshin?) of himself, he can perform a reconnaissance of an area without actually endangering himself. Sai can also transform words he writes on his scroll into small animals that seek out their target and revert back to words upon arriving, giving Sai an easy way to communicate.\"}','{\"Age\": \"17\", \"Height\": \"172.1 cm\", \"Weight\": \"53.3 kg\", \"Birthdate\": \"November 25\", \"Blood type\": \"A\", \"Description\": \"Sai is the replacement of Sasuke Uchiha in Team 7. The name \\\"Sai\\\" is given to him for the purposes of joining the team, his actual name being unknown. He was recruited at a young age by Root, which trained him to have no emotions so as to make it easier for him to accomplish missions. This lack of personality causes Sai to meet with hardship upon joining Team 7, as he makes the mistake of insulting the other members in an attempt to seem sociable. He tries to seem more caring by smiling, though his teammates come to dislike it due to his obvious insincerity. After spending more time with his team Sai comes to appreciate bonds, particularly the bond that exists between Naruto Uzumaki and Sasuke Uchiha. Wanting to experience bonds for himself, Sai sets out to make as many bonds as he can. His initial attempts consist of giving people pet names, though his habit of calling people as he sees them (\\\"fat\\\", \\\"ugly\\\", etc.) finds little success. Realizing that people dislike hearing how they actually look, Sai begins to say the opposite of how he sees them, such as calling Ino Yamanaka \\\"beautiful\\\". With names proving successful, Sai has since made attempts to be helpful to others, though his attempts have thus far been unwanted by those he is trying to help.\", \"Current rank\": \"ANBU\", \"Description_2\": \"Sai is a talented artist, and claims to have drawn thousands of pictures. Despite the magnitude of pictures he has drawn, his lack of emotion makes it impossible for him be inspired to give something a title, and thus all of his works are nameless. Sai\'s drawing ability is also the source of his jutsu; by drawing things with a brush on his scroll he is able to bring his creations to life, giving them an increased size and the ability to move. His Super Beasts Imitation Picture (超獣偽画, Chōjū Giga) allows him to create birds that he can use for flight and lion-like creatures that he can use for attack. Likewise, by creating an Ink Clone (墨分身, Sumi Bunshin?) of himself, he can perform a reconnaissance of an area without actually endangering himself. Sai can also transform words he writes on his scroll into small animals that seek out their target and revert back to words upon arriving, giving Sai an easy way to communicate.\", \"Ninja Registration Nº\": \"012420\"}'),(292,57875,'Saiken','{\"Description\":\"Saiken, more commonly known as the Six-Tails or Rokubi, is a tailed beast sealed within Utakata of Kirigakure.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Saiken, more commonly known as the Six-Tails or Rokubi, is a tailed beast sealed within Utakata of Kirigakure.\"}'),(293,256933,'Sajou','{\"Description\":\"Sajou is a Senior from Sunagakure.\",\"Description_2\":\"Normally squinting, Sajou has shoulder-length dark hair which is concealed underneath a ghutrah and wears the standard attire of the Sunagakure Seniors.\",\"Description_3\":\"As a member of the advisory council, he is most likely one of Sunagakure\\u0027s wisest shinobi.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Sajou is a Senior from Sunagakure.\", \"Description_2\": \"Normally squinting, Sajou has shoulder-length dark hair which is concealed underneath a ghutrah and wears the standard attire of the Sunagakure Seniors.\", \"Description_3\": \"As a member of the advisory council, he is most likely one of Sunagakure\'s wisest shinobi.\"}'),(294,8760,'Sakon','{\"Birthdate\":\"June 20\",\"Description\":\"Sakon is the twin brother of Ukon. Sakon enjoys bad-mouthing the opposition, and, like the rest of the Sound Five, he constantly refers to his enemies as \\u0022trash\\u0022. Orochimaru noted Sakon to be the fastest and strongest member of the Sound Four, traits Sakon is very proud of. When in battle Sakon likes to prolong the fight by toying with the opponent and use unnecessarily powerful techniques. This tendency of Sakon\\u0027s would cause him to slow down the rest of the group whenever he got interested in an opponent.\"}','{\"Birthdate\": \"June 20\", \"Description\": \"Sakon is the twin brother of Ukon. Sakon enjoys bad-mouthing the opposition, and, like the rest of the Sound Five, he constantly refers to his enemies as \\\"trash\\\". Orochimaru noted Sakon to be the fastest and strongest member of the Sound Four, traits Sakon is very proud of. When in battle Sakon likes to prolong the fight by toying with the opponent and use unnecessarily powerful techniques. This tendency of Sakon\'s would cause him to slow down the rest of the group whenever he got interested in an opponent.\"}'),(295,22873,'Samui','{\"Description\":\"Samui is a kunoichi of Kumogakure, and the leader of Team Samui. She is Killer Bee\\u0027s student along with the other two members of her team.\",\"Description_2\":\"Samui has short blonde hair just around her chin. She wears a revealing skirt with a shirt. She has a body compariable to Tsunade, has fair skin, large breast, and appears very seductive.\",\"Description_3\":\"\\u0022Samui\\u0022 means \\u0022cold\\u0022 in Japanese, in reference to temperature. It could possibly reflect Samui\\u0027s personality.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Samui is a kunoichi of Kumogakure, and the leader of Team Samui. She is Killer Bee\'s student along with the other two members of her team.\", \"Description_2\": \"Samui has short blonde hair just around her chin. She wears a revealing skirt with a shirt. She has a body compariable to Tsunade, has fair skin, large breast, and appears very seductive.\", \"Description_3\": \"\\\"Samui\\\" means \\\"cold\\\" in Japanese, in reference to temperature. It could possibly reflect Samui\'s personality.\"}'),(296,27251,'Sandaime Kazekage','{\"Description\":\"Third Kazekage was once the leader of Sunagakure, though his true name is unknown. He had the unique ability to manipulate his chakra and convert it into magnetic forces, which made him immune to all metallic weapons. After studying the host of Shukaku of the time, he recreated its sand-manipulating powers by combining his own magnetic chakra and iron powder, which produced the Iron Sand technique. It was for this very ability that he was noted as the strongest Kazekage in the entire history of Sunagakure.\",\"Description_2\":\"Sasori kidnapped and killed the Third Kazekage in order to turn him into a Human Puppet. The effort involved in the Third\\u0027s capture made it his favorite puppet. Sunagakure did not know this and searched earnestly for his whereabouts. Their actions are suggested to have sparked the Third Great Shinobi World War. With the war\\u0027s outbreak the village was forced to give up the search and choose a Fourth Kazekage, though there would be other search attempts in later years.\",\"Description_3\":\"The Third\\u0027s fate is discovered during Sasori\\u0027s battle with Sakura and Chiyo when Sasori brings out the Kazekage puppet to use against them. After a long, drawn-out battle, Sakura managed to destroy the puppet.\"}','{\"Description\": \"Third Kazekage was once the leader of Sunagakure, though his true name is unknown. He had the unique ability to manipulate his chakra and convert it into magnetic forces, which made him immune to all metallic weapons. After studying the host of Shukaku of the time, he recreated its sand-manipulating powers by combining his own magnetic chakra and iron powder, which produced the Iron Sand technique. It was for this very ability that he was noted as the strongest Kazekage in the entire history of Sunagakure.\", \"Description_2\": \"Sasori kidnapped and killed the Third Kazekage in order to turn him into a Human Puppet. The effort involved in the Third\'s capture made it his favorite puppet. Sunagakure did not know this and searched earnestly for his whereabouts. Their actions are suggested to have sparked the Third Great Shinobi World War. With the war\'s outbreak the village was forced to give up the search and choose a Fourth Kazekage, though there would be other search attempts in later years.\", \"Description_3\": \"The Third\'s fate is discovered during Sasori\'s battle with Sakura and Chiyo when Sasori brings out the Kazekage puppet to use against them. After a long, drawn-out battle, Sakura managed to destroy the puppet.\"}'),(297,31831,'Sari','{\"Description\":\"Sari is a Genin from Sunagakure.\",\"Description_2\":\"She\\u0027s close friends with Matsuri and like her, she has a strong admiration for the Kazekage. She adores the Kazekage more than anyone except for her friend Matsuri and was willing to do anything to rescue him, even going to volunteer for the mission to save him.\"}','{\"Description\": \"Sari is a Genin from Sunagakure.\", \"Description_2\": \"She\'s close friends with Matsuri and like her, she has a strong admiration for the Kazekage. She adores the Kazekage more than anyone except for her friend Matsuri and was willing to do anything to rescue him, even going to volunteer for the mission to save him.\"}'),(298,7571,'Sarutobi, Hiruzen','{\"Description\":\"The Third Hokage is a former student of the First Hokage and Second Hokage. Because of his surname, Sarutobi, the First and Second called him \\u0022Saru.\\u0022 He is the father of Asuma Sarutobi and the grandfather of Konohamaru. The Third was called The Professor due to his vast knowledge of jutsu, purportedly knowing all the jutsu within Konoha, and also as the \\u0022God of Shinobi\\u0022  due to his immense power.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"The Third Hokage is a former student of the First Hokage and Second Hokage. Because of his surname, Sarutobi, the First and Second called him \\\"Saru.\\\" He is the father of Asuma Sarutobi and the grandfather of Konohamaru. The Third was called The Professor due to his vast knowledge of jutsu, purportedly knowing all the jutsu within Konoha, and also as the \\\"God of Shinobi\\\"  due to his immense power.\"}'),(299,127961,'Sarutobi, Mirai','{\"Description\":\"Mirai Sarutobi is a kunoichi and a member of Konohagakure\\u0027s Sarutobi Clan. She is the daughter of Asuma and Kurenai.\"}','{\"Description\": \"Mirai Sarutobi is a kunoichi and a member of Konohagakure\'s Sarutobi Clan. She is the daughter of Asuma and Kurenai.\"}'),(300,4775,'Sarutobi, Asuma','{\"Birthdate\":\"October 18\",\"Horoscope\":\"Libra\",\"Age\":\"27-28 (Part I), 31 (Part II,\",\"Height\":\"190.8 cm (6\\u002725\\u0027\\u0027)\",\"Weight\":\"81.6 kg\",\"Blood type\":\"O\",\"Clan\":\"Sarutobi clan\",\"Family\":\"\",\"Affiliation\":\"Konohagakure\",\"Team\":\"\",\"Rank\":\"J\\u014Dnin\",\"Registration ID\":\"010829\",\"Academy Grad. Age\":\"9\",\"Ch\\u016Bnin Prom. Age\":\"12\",\"Missions Completed\":\"719 (D-Rank: 111, C-Rank: 193, B-Rank: 217, A-Rank: 178, S-Rank: 20)\",\"Favorite Phrase\":\"\\u0022Not right now!\\u0022\",\"Likes\":\"Sh\\u014Dgi, sausage and soba with tororo\",\"Dislikes\":\"Asparagus\",\"Manga debut\":\"Chapter 34\",\"Anime debut\":\"Naruto episode 3\",\"Nature Type\":\"Wind Release (Affinity), Fire Release\",\"Jutsu\":\"\",\"Description\":\"A Jounin master, he is the leader of Team 10 (Nara Shikamaru, Yamanaka Ino, Akimichi Chouji). Although normally seen smoking, Asuma can quickly dispatch his foes with his knives when the situation warrants. He is also the third Hokage\\u0027s son.\"}','{\"Age\": \"27-28 (Part I), 31 (Part II,\", \"Clan\": \"Sarutobi clan\", \"Rank\": \"Jōnin\", \"Team\": \"\", \"Jutsu\": \"\", \"Likes\": \"Shōgi, sausage and soba with tororo\", \"Family\": \"\", \"Height\": \"190.8 cm (6\'25\'\')\", \"Weight\": \"81.6 kg\", \"Dislikes\": \"Asparagus\", \"Birthdate\": \"October 18\", \"Horoscope\": \"Libra\", \"Blood type\": \"O\", \"Affiliation\": \"Konohagakure\", \"Anime debut\": \"Naruto episode 3\", \"Description\": \"A Jounin master, he is the leader of Team 10 (Nara Shikamaru, Yamanaka Ino, Akimichi Chouji). Although normally seen smoking, Asuma can quickly dispatch his foes with his knives when the situation warrants. He is also the third Hokage\'s son.\", \"Manga debut\": \"Chapter 34\", \"Nature Type\": \"Wind Release (Affinity), Fire Release\", \"Favorite Phrase\": \"\\\"Not right now!\\\"\", \"Registration ID\": \"010829\", \"Academy Grad. Age\": \"9\", \"Chūnin Prom. Age\": \"12\", \"Missions Completed\": \"719 (D-Rank: 111, C-Rank: 193, B-Rank: 217, A-Rank: 178, S-Rank: 20)\"}'),(301,56693,'Sarutobi, Biwako','{\"Description\":\"Biwako Sarutobi (\\u733F\\u98DB\\u30D3\\u30EF\\u30B3, Sarutobi Biwako) was the wife of Hiruzen Sarutobi.\",\"Description_2\":\"\",\"Manga Debut\":\"Chapter #500\",\"Anime Debut\":\"Naruto Shippuuden Episode #247\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #247\", \"Description\": \"Biwako Sarutobi (猿飛ビワコ, Sarutobi Biwako) was the wife of Hiruzen Sarutobi.\", \"Manga Debut\": \"Chapter #500\", \"Description_2\": \"\"}'),(302,3889,'Sarutobi, Konohamaru','{\"Age\":\"8-9 in Part I; 11 in Part II; 27 in Boruto\",\"Birthday\":\"December 30\",\"Blood type\":\"B\",\"Height\":\"Part I: 128.8 cm\\u2013130.6 cm, Part II: 141.1 cm, Gaiden: 177.5 cm\",\"Konohamaru named after the village he lives in\":\"Konoha, is the grandson of the Third Hokage and by extension the nephew of Asuma Sarutobi. Konohamaru usually hangs out with his two friends, Udon and Moegi. Together, they call themselves the \\u0022Konohamaru Corps\\u0022 (\\u0022Konohamaru Ninja Squad\\u0022 in the English dub). In Part II they are teamed together under the leadership of Ebisu, Konohamaru\\u0027s former tutor.\",\"Description\":\"At the start of the series, Konohamaru feels unacknowledged due to his status as the Hokage\\u0027s grandson. As such, he frequently attempts to defeat his grandfather in battle so that he can become Hokage himself and earn the recognition he desires. Once meeting Naruto Uzumaki, Konohamaru realizes that he can\\u0027t become Hokage by simply attacking his grandfather and will need to train hard to accomplish this goal. To help him in this regard Konohamaru begins to view Naruto as a role model, acquiring his determination, fiery attitude, and unique way of ending sentences, \\u0022kore\\u0022 (\\u30B3\\u30EC, a laughing signal or appreciation), much like Naruto\\u0027s \\u0022Dattebayo!\\u0022\",\"Konohamaru\\u0027s most obvious acquisition from Naruto\\u0027s influence is his perverted habits, specifically the perverted jutsu he uses. After their first meeting Konohamaru becomes Naruto\\u0027s disciple in an attempt to learn the Sexy Technique and defeat his grandfather. After mastering the ability he begins to train to create his own perverted jutsu, and after learning the Shadow Clone Technique in Part II he is able to create a smaller version of Naruto\\u0027s Harem Technique. He has named his variant the Sexy\":\"Double Knockout Girls Technique (\\u304A\\u3044\\u308D\\u3051\\u30FB\\u5973\\u306E\\u5B50\\u3069\\u3046\\u3057\\u306E\\u8853, Oiroke: Onna no Ko D\\u014Dshi no Jutsu), which transforms himself and his shadow clone into nude women in a suggestive embrace. Because this jutsu is only effective against men, he also creates the Sexy: Double Knockout Guys Technique (\\u304A\\u3044\\u308D\\u3051\\u30FB\\u7537\\u306E\\u5B50\\u3069\\u3046\\u3057\\u306E\\u8853, Oiroke: Otoko no Ko D\\u014Dshi no Jutsu) to turn into nude men in an equally suggestive embrace.\",\"(Source\":\"Wikipedia)\"}','{\"Age\": \"8-9 in Part I; 11 in Part II; 27 in Boruto\", \"Height\": \"Part I: 128.8 cm–130.6 cm, Part II: 141.1 cm, Gaiden: 177.5 cm\", \"(Source\": \"Wikipedia)\", \"Birthday\": \"December 30\", \"Blood type\": \"B\", \"Description\": \"At the start of the series, Konohamaru feels unacknowledged due to his status as the Hokage\'s grandson. As such, he frequently attempts to defeat his grandfather in battle so that he can become Hokage himself and earn the recognition he desires. Once meeting Naruto Uzumaki, Konohamaru realizes that he can\'t become Hokage by simply attacking his grandfather and will need to train hard to accomplish this goal. To help him in this regard Konohamaru begins to view Naruto as a role model, acquiring his determination, fiery attitude, and unique way of ending sentences, \\\"kore\\\" (コレ, a laughing signal or appreciation), much like Naruto\'s \\\"Dattebayo!\\\"\", \"Konohamaru named after the village he lives in\": \"Konoha, is the grandson of the Third Hokage and by extension the nephew of Asuma Sarutobi. Konohamaru usually hangs out with his two friends, Udon and Moegi. Together, they call themselves the \\\"Konohamaru Corps\\\" (\\\"Konohamaru Ninja Squad\\\" in the English dub). In Part II they are teamed together under the leadership of Ebisu, Konohamaru\'s former tutor.\", \"Konohamaru\'s most obvious acquisition from Naruto\'s influence is his perverted habits, specifically the perverted jutsu he uses. After their first meeting Konohamaru becomes Naruto\'s disciple in an attempt to learn the Sexy Technique and defeat his grandfather. After mastering the ability he begins to train to create his own perverted jutsu, and after learning the Shadow Clone Technique in Part II he is able to create a smaller version of Naruto\'s Harem Technique. He has named his variant the Sexy\": \"Double Knockout Girls Technique (おいろけ・女の子どうしの術, Oiroke: Onna no Ko Dōshi no Jutsu), which transforms himself and his shadow clone into nude women in a suggestive embrace. Because this jutsu is only effective against men, he also creates the Sexy: Double Knockout Guys Technique (おいろけ・男の子どうしの術, Oiroke: Otoko no Ko Dōshi no Jutsu) to turn into nude men in an equally suggestive embrace.\"}'),(303,1900,'Sasori','{\"Birthday\":\"November 8\",\"Zodiac\":\"Scorpio\",\"Age\":\"35\",\"Ninja Registration N\\u00BA\":\"33-001\",\"Blood type\":\"AB\",\"Height\":\"164.1 cm\",\"Weight\":\"47 kg\",\"Classification\":\"S-rank, Missing-nin\",\"Description\":\"Sasori, also known as Sasori of the Red Sand, is a member of Akatsuki and is partnered with Deidara.\"}','{\"Age\": \"35\", \"Height\": \"164.1 cm\", \"Weight\": \"47 kg\", \"Zodiac\": \"Scorpio\", \"Birthday\": \"November 8\", \"Blood type\": \"AB\", \"Description\": \"Sasori, also known as Sasori of the Red Sand, is a member of Akatsuki and is partnered with Deidara.\", \"Classification\": \"S-rank, Missing-nin\", \"Ninja Registration Nº\": \"33-001\"}'),(304,166812,'Sen','{\"Description\":\"Sen is a kunoichi of Sunagakure and a teammate of Shira and Yome.\"}','{\"Description\": \"Sen is a kunoichi of Sunagakure and a teammate of Shira and Yome.\"}'),(305,12464,'Senju, Hashirama','{\"Birthday\":\"October 23\",\"Height\":\"185 cm\",\"Weight\":\"74 kg\",\"Kekkai Genkai\":\"Wood release\",\"Occupation\":\"Co-founder of Konohagakure, leader of the Senju Clan, First Hokage\",\"Affliation\":\"Konohagakure\",\"Clan\":\"Senju Clan\",\"Description\":\"Hashirama was originally the leader of the Senju Clan of the Forest. At some point in his life he fought Kakuzu but the nature of this fight is unknown at this point. In his early years, after they and their clans had been fighting constantly, he had his clan allied with Uchiha Madara, and the two of them, with their clans, founded Konoha. Later on, Madara left the villige over the policies of the village and his clan. This conflict resulted in battle with Uchiha Madara and the nine-tailed fox at the Valley of the End.\",\"Description_2\":\"To commemorate the battle, two statues, of Madara and Hashirama, were carved into the earth around the waterfall. It is for this reason that Naruto Uzumaki and Sasuke Uchiha\\u0027s fight at that location was noted to be ironic.\",\"Description_3\":\"However the war still waged on, and unsure of the title of Hokage he would not only appoint his brother as his successor as the Second Hokage (Nidaime Hokage), but in a common decision with his brother they also decided that one of their students Sarutobi should become the Third Hokage (Sandaime Hokage), which in turn seemed like a wise decision as both brothers would eventually die during the wars.\",\"Description_4\":\"He was most famous for his unique Wood Release techniques, a kekkei genkai that is a mixture of earth and water-natured chakra that creates this new element. By converting chakra into the source of life, he was able to create trees, causing them to grow to great sizes and manipulate them to diverse shapes and battle uses at will. In an instant, he could shape the entire battlefield for his own uses.\",\"(Source\":\"Narutopedia)\"}','{\"Clan\": \"Senju Clan\", \"Height\": \"185 cm\", \"Weight\": \"74 kg\", \"(Source\": \"Narutopedia)\", \"Birthday\": \"October 23\", \"Affliation\": \"Konohagakure\", \"Occupation\": \"Co-founder of Konohagakure, leader of the Senju Clan, First Hokage\", \"Description\": \"Hashirama was originally the leader of the Senju Clan of the Forest. At some point in his life he fought Kakuzu but the nature of this fight is unknown at this point. In his early years, after they and their clans had been fighting constantly, he had his clan allied with Uchiha Madara, and the two of them, with their clans, founded Konoha. Later on, Madara left the villige over the policies of the village and his clan. This conflict resulted in battle with Uchiha Madara and the nine-tailed fox at the Valley of the End.\", \"Description_2\": \"To commemorate the battle, two statues, of Madara and Hashirama, were carved into the earth around the waterfall. It is for this reason that Naruto Uzumaki and Sasuke Uchiha\'s fight at that location was noted to be ironic.\", \"Description_3\": \"However the war still waged on, and unsure of the title of Hokage he would not only appoint his brother as his successor as the Second Hokage (Nidaime Hokage), but in a common decision with his brother they also decided that one of their students Sarutobi should become the Third Hokage (Sandaime Hokage), which in turn seemed like a wise decision as both brothers would eventually die during the wars.\", \"Description_4\": \"He was most famous for his unique Wood Release techniques, a kekkei genkai that is a mixture of earth and water-natured chakra that creates this new element. By converting chakra into the source of life, he was able to create trees, causing them to grow to great sizes and manipulate them to diverse shapes and battle uses at will. In an instant, he could shape the entire battlefield for his own uses.\", \"Kekkai Genkai\": \"Wood release\"}'),(306,23139,'Senju, Touka','{\"Description\":\"T\\u014Dka Senju (\\u5343\\u624B\\u6843\\u83EF, Senju T\\u014Dka) was a member of the Senju clan in the time before Konoha was founded. She was a close associate of the leader of the clan, Hashirama Senju. T\\u014Dka specialized in genjutsu and was well-known throughout the world for her amazing genjutsu abilities.\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tōka Senju (千手桃華, Senju Tōka) was a member of the Senju clan in the time before Konoha was founded. She was a close associate of the leader of the clan, Hashirama Senju. Tōka specialized in genjutsu and was well-known throughout the world for her amazing genjutsu abilities.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(307,109567,'Senju, Itama','{\"Description\":\"Itama Senju (\\u5343\\u624B\\u677F\\u9593, Senju Itama) was a young shinobi from the Senju clan.\",\"Manga Debut\":\"Chapter #622\",\"Anime Debut\":\"Naruto Shippuuden Episode #367\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #367\", \"Description\": \"Itama Senju (千手板間, Senju Itama) was a young shinobi from the Senju clan.\", \"Manga Debut\": \"Chapter #622\"}'),(308,109569,'Senju, Butsuma','{\"Description\":\"Butsuma Senju (\\u5343\\u624B\\u4ECF\\u9593, Senju Butsuma) was a member of the Senju clan during the war-torn era preceding the era of hidden villages.\",\"Manga Debut\":\"Chapter #622\",\"Anime Debut\":\"Naruto Shippuuden Episode #367\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #367\", \"Description\": \"Butsuma Senju (千手仏間, Senju Butsuma) was a member of the Senju clan during the war-torn era preceding the era of hidden villages.\", \"Manga Debut\": \"Chapter #622\"}'),(309,12465,'Senju, Tobirama','{\"Description\":\"The Second Hokage is the younger brother to the First Hokage and Tsunade\\u0027s great-uncle. As the brother of the First, the Second Hokage was a member of the Senju Clan of the forest. The First and Second together fostered Konohagakure into a growing village. He was once the teacher of the Third Hokage. He was hailed for being the greatest master of water jutsu, being able to create water from nothing, allowing him to use any Suiton jutsu without requiring a source.\",\"Description_2\":\"Along with his brother and Madara Uchiha, he was also one of the founders of the Hidden Leaf.\"}','{\"Description\": \"The Second Hokage is the younger brother to the First Hokage and Tsunade\'s great-uncle. As the brother of the First, the Second Hokage was a member of the Senju Clan of the forest. The First and Second together fostered Konohagakure into a growing village. He was once the teacher of the Third Hokage. He was hailed for being the greatest master of water jutsu, being able to create water from nothing, allowing him to use any Suiton jutsu without requiring a source.\", \"Description_2\": \"Along with his brother and Madara Uchiha, he was also one of the founders of the Hidden Leaf.\"}'),(310,134165,'Senjuu, Kawarama','{\"Description\":\"Kawarama Senju  was a young shinobi from the Senju clan.\",\"Manga Debut\":\"Chapter #624\",\"Anime Debut\":\"Naruto Shippuuden Episode #368\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #368\", \"Description\": \"Kawarama Senju  was a young shinobi from the Senju clan.\", \"Manga Debut\": \"Chapter #624\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(311,93631,'Shamon','{\"Birthdate\":\"March 12\",\"Gender\":\"Male\",\"Status\":\"Deceased\",\"Blood type\":\"O\",\"Occupation\":\"Kazekage\",\"Affiliation\":\"Sunagakure\",\"Description\":\"Shamon was the Second Kazekage of Sunagakure. He was the first to research the jinch\\u016Briki, in an attempt to greatly enhance the power of the village.\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Gender\": \"Male\", \"Status\": \"Deceased\", \"(Source\": \"Narutopedia)\", \"Birthdate\": \"March 12\", \"Blood type\": \"O\", \"Occupation\": \"Kazekage\", \"Affiliation\": \"Sunagakure\", \"Description\": \"Shamon was the Second Kazekage of Sunagakure. He was the first to research the jinchūriki, in an attempt to greatly enhance the power of the village.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(312,23156,'Shibire','{\"Description\":\"Shibire is a Genin from Konohagakure. He and the rest of Team Shibire made it to the second phase of the Ch\\u016Bnin Exams. When they started to lose hope in completing the round, he and Minoji decided to read their scroll, leaving them knocked out and unable to complete the exams.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Shibire is a Genin from Konohagakure. He and the rest of Team Shibire made it to the second phase of the Chūnin Exams. When they started to lose hope in completing the round, he and Minoji decided to read their scroll, leaving them knocked out and unable to complete the exams.\"}'),(313,46605,'Shibuki','{\"Description\":\"Shibuki is a chuunin from Takigakure, who succeeds his deceased father as village head.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Shibuki is a chuunin from Takigakure, who succeeds his deceased father as village head.\"}'),(314,22000,'Shiho','{\"Description\":\"Shiho works on the cryptology squad that was tasked by Shikamaru Nara to decipher the code left by Jiraiya.\",\"Description_2\":\"Personality\",\"Description_3\":\"Shiho is an upbeat cheerful girl who appears to be attracted to Shikamaru Nara. She deeply blushes as Shikamaru leaves to seek help with the code. Knowing that Shikamaru said he would return if he found out any new information, Shiho refuses an offer to go home from her boss. Instead she fixes herself up in a mirror, intending to see Shikamaru again when he returns. Shiho also blushes when Shikamaru accepts her offer of accompanying him back to Tsunade\\u0026amp;#039;s office. The side text on chapter 407\\u0026amp;#039;s cover page, which Shiho appears on, makes mention of how excited and nervous she gets around Shikamaru.\",\"Description_4\":\"edit Part II\"}','{\"Description\": \"Shiho works on the cryptology squad that was tasked by Shikamaru Nara to decipher the code left by Jiraiya.\", \"Description_2\": \"Personality\", \"Description_3\": \"Shiho is an upbeat cheerful girl who appears to be attracted to Shikamaru Nara. She deeply blushes as Shikamaru leaves to seek help with the code. Knowing that Shikamaru said he would return if he found out any new information, Shiho refuses an offer to go home from her boss. Instead she fixes herself up in a mirror, intending to see Shikamaru again when he returns. Shiho also blushes when Shikamaru accepts her offer of accompanying him back to Tsunade&amp;#039;s office. The side text on chapter 407&amp;#039;s cover page, which Shiho appears on, makes mention of how excited and nervous she gets around Shikamaru.\", \"Description_4\": \"edit Part II\"}'),(315,23477,'Shii','{\"Description\":\"Shii is a Kumogakure shinobi who escorts the Raikage along with Darui. C is a young man with short blond hair and dark eyes. He wears a sleeveless black shirt with a one-strap-over-one-shoulder white flak jacket, forehead protector, black elbow length arm guards, and red and white Kumogakure shin-guards.\",\"Description_2\":\"In contrast to his easy-going partner, C is portrayed as serious and putting Kumo\\u0027s well being above all else. This is briefly shown when he told Darui there was no time for rest upon their return from the Kage Summit. He also seems to have a slight dislike of Konoha ninja, calling Naruto\\u0027s group \\u0022Konoha Dogs\\u0022.\",\"Description_3\":\"C is a sensor type shinobi, allowing him to sense the chakra of others even from extended distances. He is also a medic-nin and seems to be very knowledgeable on foreign shinobi techniques, as he is shown recognizing Sasuke\\u0027s Mangeky\\u014D Sharingan along with Amaterasu. C was able to deduce how Sasuke\\u0027s Blaze Release worked after only seeing it once. He is also a skilled genjutsu user, as he was shown using Lightning Illusion Flash of Lightning Pillar, followed by a second genjutsu within the first.\",\"Description_4\":\"All of these abilities also imply a mastery of multiple skills requiring very fine chakra control.\",\"Description_5\":\"Also of note is when he went to defend the Raikage from the bodyguards of the other Kage he took a defence taijutsu stance, implying he is competent in close combat as well\"}','{\"Description\": \"Shii is a Kumogakure shinobi who escorts the Raikage along with Darui. C is a young man with short blond hair and dark eyes. He wears a sleeveless black shirt with a one-strap-over-one-shoulder white flak jacket, forehead protector, black elbow length arm guards, and red and white Kumogakure shin-guards.\", \"Description_2\": \"In contrast to his easy-going partner, C is portrayed as serious and putting Kumo\'s well being above all else. This is briefly shown when he told Darui there was no time for rest upon their return from the Kage Summit. He also seems to have a slight dislike of Konoha ninja, calling Naruto\'s group \\\"Konoha Dogs\\\".\", \"Description_3\": \"C is a sensor type shinobi, allowing him to sense the chakra of others even from extended distances. He is also a medic-nin and seems to be very knowledgeable on foreign shinobi techniques, as he is shown recognizing Sasuke\'s Mangekyō Sharingan along with Amaterasu. C was able to deduce how Sasuke\'s Blaze Release worked after only seeing it once. He is also a skilled genjutsu user, as he was shown using Lightning Illusion Flash of Lightning Pillar, followed by a second genjutsu within the first.\", \"Description_4\": \"All of these abilities also imply a mastery of multiple skills requiring very fine chakra control.\", \"Description_5\": \"Also of note is when he went to defend the Raikage from the bodyguards of the other Kage he took a defence taijutsu stance, implying he is competent in close combat as well\"}'),(316,24487,'Shima','{\"Description\":\"Shima (\\u30B7\\u30DE) is the wife of Fukasaku and an elder toad from My\\u014Dbokuzan. As the heirs of the Great Toad Sage, she and her husband are revered as the Two Great Sage Toads. Together with Fukasaku, she taught Jiraiya how to use Senjutsu.\",\"Source\":\"\"}','{\"Source\": \"\", \"Description\": \"Shima (シマ) is the wife of Fukasaku and an elder toad from Myōbokuzan. As the heirs of the Great Toad Sage, she and her husband are revered as the Two Great Sage Toads. Together with Fukasaku, she taught Jiraiya how to use Senjutsu.\"}'),(317,23424,'Shimura, Danzou','{\"Description\":\"Danzou is a Konoha elder, one of the oldest villagers in Konoha. He is also in charge of the ANBU faction named the Foundation. Later he is appointed as the acting Sixth Hokage (\\u516D\\u4EE3\\u76EE\\u706B\\u5F71, Rokudaime Hokage) after Pain\\u0027s invasion.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Danzou is a Konoha elder, one of the oldest villagers in Konoha. He is also in charge of the ANBU faction named the Foundation. Later he is appointed as the acting Sixth Hokage (六代目火影, Rokudaime Hokage) after Pain\'s invasion.\"}'),(318,22817,'Shin','{\"Description\":\"Shin was recruited by the Foundation at a young age and became Sai\\u0027s friend.\"}','{\"Description\": \"Shin was recruited by the Foundation at a young age and became Sai\'s friend.\"}'),(319,50461,'Ship\'s Captain','{\"Description\":\"Captain of the ship in which Hishaku was part of.\",\"Description_2\":\"(episode 225)\"}','{\"Description\": \"Captain of the ship in which Hishaku was part of.\", \"Description_2\": \"(episode 225)\"}'),(320,124066,'Shira','{}','{}'),(321,39605,'Shirakumo, Hayama','{\"Description\":\"Hayama Shirakumo (\\u767D\\u96F2\\u30CF\\u30E4\\u30DE, Shirakumo Hayama) is a j\\u014Dnin of Konohagakure that protected its borders after the Invasion of Konoha.\",\"Description_2\":\"Hayama has long dull purple hair held in a ponytail. He also has a scar running down the right side of his mouth. He wears the standard Konoha shinobi outfit, albeit his uniform has short sleeves. He also wears a pair of fingerless gloves and carries a thin katana strapped horizontally to his back.\",\"Description_3\":\"Hayama is very adept at Kenjutsu. With his sword he can use the Vacuum Sword technique which was able to fend off many Iwagakure ninja as well as weapons.\",\"Description_4\":\"He is assigned to patrol the northern borders along with Tekuno, Naruto Uzumaki, and Kosuke Maruboshi after the Invasion of Konoha. Not long after they were ambushed by a battalion of ninja from Iwagakure. Hayama stayed behind to allow the other members of the squad time to escape and report to the village. He summoned a crossbow with explosive tags attached to the projectiles and along with Tekuno wiped out the majority of the ninja. Together the team was able to wipe out dozens of Iwa ninja.\",\"Description_5\":\"He is seen alongside his fellow village ninja aiding in the restoration of the village after Pain\\u0027s invasion.\"}','{\"Description\": \"Hayama Shirakumo (白雲ハヤマ, Shirakumo Hayama) is a jōnin of Konohagakure that protected its borders after the Invasion of Konoha.\", \"Description_2\": \"Hayama has long dull purple hair held in a ponytail. He also has a scar running down the right side of his mouth. He wears the standard Konoha shinobi outfit, albeit his uniform has short sleeves. He also wears a pair of fingerless gloves and carries a thin katana strapped horizontally to his back.\", \"Description_3\": \"Hayama is very adept at Kenjutsu. With his sword he can use the Vacuum Sword technique which was able to fend off many Iwagakure ninja as well as weapons.\", \"Description_4\": \"He is assigned to patrol the northern borders along with Tekuno, Naruto Uzumaki, and Kosuke Maruboshi after the Invasion of Konoha. Not long after they were ambushed by a battalion of ninja from Iwagakure. Hayama stayed behind to allow the other members of the squad time to escape and report to the village. He summoned a crossbow with explosive tags attached to the projectiles and along with Tekuno wiped out the majority of the ninja. Together the team was able to wipe out dozens of Iwa ninja.\", \"Description_5\": \"He is seen alongside his fellow village ninja aiding in the restoration of the village after Pain\'s invasion.\"}'),(322,30427,'Shiranami','{\"Description\":\"Shiranami (\\u30B7\\u30E9\\u30CA\\u30DF) is the boss of the Magaki group. He wants to steal the forbidden jutsu of the Tsuchigumo Clan.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Shiranami (シラナミ) is the boss of the Magaki group. He wants to steal the forbidden jutsu of the Tsuchigumo Clan.\"}'),(323,3735,'Shiranui, Genma','{\"Name\":\"Genma Shiranui\",\"Gender\":\"Male\",\"Birthday\":\"July 17\",\"Age (Part I)\":\"30\",\"Height\":\"5\\u00279\\u0022\",\"Weight\":\"156.5 lbs.\",\"Blood Type\":\"A\",\"Affiliation\":\"Konohagakure\",\"Current Rank\":\"Special Jonin\",\"Previous Occupation\":\"Examiner\",\"Ninja ID\":\"010203\",\"Favourite food\":\"Pumpkin Broth\",\"Least favourite food\":\"Spinach\",\"Hobby\":\"traveling\",\"Favourite phrase\":\"\\u0022No words, but action\\u0022\",\"Description\":\"Genma Shiranui replaces Hayate Gekkou as examiner of the main matches of the Chunin Exams after Hayate is killed. \\u0022Shiranui\\u0022 means \\u0022phosphorescent light\\u0022. Genma is often seen with a senbon in his mouth. He uses this as a weapon, spitting it out at the enemy to attack them (It can reach up to 60mph), or to deflect ranged weapon attacks. When the invasion of Konoha begins, Genma battles Baki off-screen, presumably to a draw since both of them come out of the fight relatively unscathed. He later appears with Raido Namiashi to confront the Sound Four, who are forced to go level 2 of their cursed seals to defeat them. The Sound Four later comment that if it hadn\\u0027t been for their cursed seals, Genma and Raido would have defeated them.\",\"Description_2\":\"Genma used to be Minato\\u0027s personal body guard along with Raidou and Iwashi. In the ninja war arc, the three perform the flying thunder god jutsu to transport Mei to the main battle field. After doing this he cases after Lord Mu in the desert.\",\"Description_3\":\"Genma\\u0027s three man squad consisted of Maito Guy, Ebisu and himself. Their leader was Chouza Akamichi.\",\"Genma has completed 935 official missions in total\":\"185 D-rank, 220 C-rank, 454 B-rank, 74 A-rank, 2 S-rank.\"}','{\"Name\": \"Genma Shiranui\", \"Hobby\": \"traveling\", \"Gender\": \"Male\", \"Height\": \"5\'9\\\"\", \"Weight\": \"156.5 lbs.\", \"Birthday\": \"July 17\", \"Ninja ID\": \"010203\", \"Blood Type\": \"A\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Genma Shiranui replaces Hayate Gekkou as examiner of the main matches of the Chunin Exams after Hayate is killed. \\\"Shiranui\\\" means \\\"phosphorescent light\\\". Genma is often seen with a senbon in his mouth. He uses this as a weapon, spitting it out at the enemy to attack them (It can reach up to 60mph), or to deflect ranged weapon attacks. When the invasion of Konoha begins, Genma battles Baki off-screen, presumably to a draw since both of them come out of the fight relatively unscathed. He later appears with Raido Namiashi to confront the Sound Four, who are forced to go level 2 of their cursed seals to defeat them. The Sound Four later comment that if it hadn\'t been for their cursed seals, Genma and Raido would have defeated them.\", \"Age (Part I)\": \"30\", \"Current Rank\": \"Special Jonin\", \"Description_2\": \"Genma used to be Minato\'s personal body guard along with Raidou and Iwashi. In the ninja war arc, the three perform the flying thunder god jutsu to transport Mei to the main battle field. After doing this he cases after Lord Mu in the desert.\", \"Description_3\": \"Genma\'s three man squad consisted of Maito Guy, Ebisu and himself. Their leader was Chouza Akamichi.\", \"Favourite food\": \"Pumpkin Broth\", \"Favourite phrase\": \"\\\"No words, but action\\\"\", \"Previous Occupation\": \"Examiner\", \"Least favourite food\": \"Spinach\", \"Genma has completed 935 official missions in total\": \"185 D-rank, 220 C-rank, 454 B-rank, 74 A-rank, 2 S-rank.\"}'),(324,77005,'Shiseru','{\"Description\":\"Shiseru is an officer from the Hachou Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Shiseru is an officer from the Hachou Village.\"}'),(325,52053,'Shizuka','{\"Anime debut\":\"Naruto: Shippuuden Episode #235\",\"Description\":\"A kunoichi and future leader of the Nadeshiko Village. She was destined to marry a student of Jiraiya that can defeat her, because of a law from her village.\",\"Shizuka is a highly capable and powerful kunoichi. She has shown great weapons proficiency, incorporating kunai into her techniques such as the Nadeshiko-Style Deep Crimson Dance Performance, a technique that Tokiwa praised Naruto for being able to dodge as well as the Dance Performance\":\"Second Step where she spins in the air while releasing a volley of kunai at the enemy, greatly increasing her range.\"}','{\"Anime debut\": \"Naruto: Shippuuden Episode #235\", \"Description\": \"A kunoichi and future leader of the Nadeshiko Village. She was destined to marry a student of Jiraiya that can defeat her, because of a law from her village.\", \"Shizuka is a highly capable and powerful kunoichi. She has shown great weapons proficiency, incorporating kunai into her techniques such as the Nadeshiko-Style Deep Crimson Dance Performance, a technique that Tokiwa praised Naruto for being able to dodge as well as the Dance Performance\": \"Second Step where she spins in the air while releasing a volley of kunai at the enemy, greatly increasing her range.\"}'),(326,4643,'Shizune','{\"Birthday\":\"November 18\",\"Age\":\"28 (I); 31(II)\",\"Height\":\"168 cm\",\"Weight\":\"49.2 kg\",\"Blood type\":\"A\",\"Description\":\"Shizune is a jounin-level kunoichi of Konohagakure. She serves as The Fifth Hokage\\u0027s attendant as well as her long time companion. She was Tsunade\\u0027s apprentice, becoming a talented medical-nin under her tutelage. Shizune remains quite close to Tsunade, being one of the few people Tsunade would trust with absolute certainty. She was also appointed the captain of the Allied Shinobi Forces\\u0027 Logistical Support and Medical Division.\",\"Description_2\":\"Shizune is the niece of Dan, the late lover of Tsunade. Some time after Dan died, Tsunade left Konoha, and Shizune went with her as her attendant and apprentice. The bond between Tsunade and Shizune is strong and, above all, Shizune sees her purpose in life as caring for Tsunade.\",\"Description_3\":\"Unlike Tsunade, she is level-headed, practical, and a rational thinker. As a result, she is the one who tends to stress over details, such as Tsunade\\u0027s tendency to gamble and to think with her heart. She often gets comically worked up over any irrational decision Tsunade makes. Shizune also looks after Tonton, Tsunade\\u0027s pet pig.\",\"Description_4\":\"She\\u0027s not the type to tire easily and is very energetic and efficient while acting in her capacity of Hokage\\u0027s Assistant, often urging Tsunade to finish the paperwork in order to avoid mountains of unsigned documents later on. She is often seen asking Tsunade questions about what to do with the village and the shinobi on missions.\",\"Description_5\":\"Shizune is noted to be a very talented medical ninja, in Konoha rivaled only by Tsunade herself and Sakura Haruno, another student of Tsunade\\u0027s. Her training has blessed her with excellent chakra control, which is the primary reason she was assigned to lead the sealing of the Three-Tailed Giant Turtle. She demonstrated her great medical knowledge when she lead a group of medics in healing Neji Hyuuga, even though she had only recently returned to the village after many years of wandering the world with Tsunade. This was again seen when she was put in charge of the autopsy Konoha performed on the Animal Path that Jiraiya had killed.\"}','{\"Age\": \"28 (I); 31(II)\", \"Height\": \"168 cm\", \"Weight\": \"49.2 kg\", \"Birthday\": \"November 18\", \"Blood type\": \"A\", \"Description\": \"Shizune is a jounin-level kunoichi of Konohagakure. She serves as The Fifth Hokage\'s attendant as well as her long time companion. She was Tsunade\'s apprentice, becoming a talented medical-nin under her tutelage. Shizune remains quite close to Tsunade, being one of the few people Tsunade would trust with absolute certainty. She was also appointed the captain of the Allied Shinobi Forces\' Logistical Support and Medical Division.\", \"Description_2\": \"Shizune is the niece of Dan, the late lover of Tsunade. Some time after Dan died, Tsunade left Konoha, and Shizune went with her as her attendant and apprentice. The bond between Tsunade and Shizune is strong and, above all, Shizune sees her purpose in life as caring for Tsunade.\", \"Description_3\": \"Unlike Tsunade, she is level-headed, practical, and a rational thinker. As a result, she is the one who tends to stress over details, such as Tsunade\'s tendency to gamble and to think with her heart. She often gets comically worked up over any irrational decision Tsunade makes. Shizune also looks after Tonton, Tsunade\'s pet pig.\", \"Description_4\": \"She\'s not the type to tire easily and is very energetic and efficient while acting in her capacity of Hokage\'s Assistant, often urging Tsunade to finish the paperwork in order to avoid mountains of unsigned documents later on. She is often seen asking Tsunade questions about what to do with the village and the shinobi on missions.\", \"Description_5\": \"Shizune is noted to be a very talented medical ninja, in Konoha rivaled only by Tsunade herself and Sakura Haruno, another student of Tsunade\'s. Her training has blessed her with excellent chakra control, which is the primary reason she was assigned to lead the sealing of the Three-Tailed Giant Turtle. She demonstrated her great medical knowledge when she lead a group of medics in healing Neji Hyuuga, even though she had only recently returned to the village after many years of wandering the world with Tsunade. This was again seen when she was put in charge of the autopsy Konoha performed on the Animal Path that Jiraiya had killed.\"}'),(327,38456,'Shouseki','{\"Description\":\"Shoseki (\\u7B19\\u95A2, Shoseki) is the apprentice of tool maker Iou.\",\"He is an apprentice of Iou, and is helping him in his tool-making job. He often complains about hard work. One time he mistakenly sold Gameru and Kusune two ninja tools Iou created\":\"Tsuru-Kame and Dako, to increase their budget.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Shoseki (笙関, Shoseki) is the apprentice of tool maker Iou.\", \"He is an apprentice of Iou, and is helping him in his tool-making job. He often complains about hard work. One time he mistakenly sold Gameru and Kusune two ninja tools Iou created\": \"Tsuru-Kame and Dako, to increase their budget.\"}'),(328,11813,'Shukaku','{\"Description\":\"Shukaku is the demon that is in Gaara giving him most of his power and his insanity. Shukaku is able to fire off sand chunks that look like and act like kunai. In the English dub, Shukaku is made sounding like an insane cowboy.\",\"Description_2\":\"Shukaku is the Ichibi, which is the One-Tail Jinchuriki. Shukaku is very powerful as Gaara can still not fully control him.\"}','{\"Description\": \"Shukaku is the demon that is in Gaara giving him most of his power and his insanity. Shukaku is able to fire off sand chunks that look like and act like kunai. In the English dub, Shukaku is made sounding like an insane cowboy.\", \"Description_2\": \"Shukaku is the Ichibi, which is the One-Tail Jinchuriki. Shukaku is very powerful as Gaara can still not fully control him.\"}'),(329,98657,'Shun','{\"Description\":\"Shun (\\u30B7\\u30E5\\u30F3, Shun) is a shinobi from Konohagakure.\",\"Description_2\":\"During the Fourth Shinobi World War, Shun was assigned to the Second Division under Kitsuchi\\u0027s command. During the war, Shun was deployed to aid Naruto Uzumaki, Killer B, Kakashi Hatake and Might Guy with Neji Hy\\u016Bga and Natsu. While en route, he discussed rumors of the intel that had read them, alerting his companions that the real Madara Uchiha had appeared on the battlefield. When attacked by enemy forces, he and Natsu then defeated two of the opponents with some assistance from Neji. He and Natsu then got into an argument with each other, but Neji soon broke it up and reminded them both that the next battle was going to be on the front lines.\",\"Anime Debut\":\"Naruto Shippuuden Episode #330\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #330\", \"Description\": \"Shun (シュン, Shun) is a shinobi from Konohagakure.\", \"Description_2\": \"During the Fourth Shinobi World War, Shun was assigned to the Second Division under Kitsuchi\'s command. During the war, Shun was deployed to aid Naruto Uzumaki, Killer B, Kakashi Hatake and Might Guy with Neji Hyūga and Natsu. While en route, he discussed rumors of the intel that had read them, alerting his companions that the real Madara Uchiha had appeared on the battlefield. When attacked by enemy forces, he and Natsu then defeated two of the opponents with some assistance from Neji. He and Natsu then got into an argument with each other, but Neji soon broke it up and reminded them both that the next battle was going to be on the front lines.\"}'),(330,97783,'Shuu','{\"Description\":\"Shuu (\\u30B7\\u30E5\\u30A6, Sh\\u016B) is the son of the daimyo of the Land of That, a country near the Land of Fire.\",\"Description_2\":\"Shuu was an eating contest\\u0027s viewer alongside princess Chiyo and her father, the daimyo of the Land of This. During the contest, Tatewaki told Shuu that it was time to train, so they went practicing kendo with two wooden swords. The samurai\\u0027s experience was higher when compared to Shuu\\u0027s, and he was therefore having lot of trouble fighting back, until Chiyo appeared and stopped Tatewaki by telling him that he shouldn\\u0027t be so rude, finishing the training. Later, Ino used her Mind Body Switch Technique to control Shuu and to pretend to go to the bathroom.\",\"Description_3\":\"Naruto used the Transformation Technique to impersonate Shuu and Shikamaru gives Shuu a letter from his father, the daimyo of the Land of That, telling him what would happen. Later, the Land of This is attacked by Akatsuki. In this invasion, the daimyo of the country is killed, however thanks to Naruto and Tatewaki, Shuu is able to escape alongside Chiyo. After that, they go to the Land of That with Naruto and Team 10.\",\"Anime Debut\":\"Naruto Shippuuden Episode #309\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #309\", \"Description\": \"Shuu (シュウ, Shū) is the son of the daimyo of the Land of That, a country near the Land of Fire.\", \"Description_2\": \"Shuu was an eating contest\'s viewer alongside princess Chiyo and her father, the daimyo of the Land of This. During the contest, Tatewaki told Shuu that it was time to train, so they went practicing kendo with two wooden swords. The samurai\'s experience was higher when compared to Shuu\'s, and he was therefore having lot of trouble fighting back, until Chiyo appeared and stopped Tatewaki by telling him that he shouldn\'t be so rude, finishing the training. Later, Ino used her Mind Body Switch Technique to control Shuu and to pretend to go to the bathroom.\", \"Description_3\": \"Naruto used the Transformation Technique to impersonate Shuu and Shikamaru gives Shuu a letter from his father, the daimyo of the Land of That, telling him what would happen. Later, the Land of This is attacked by Akatsuki. In this invasion, the daimyo of the country is killed, however thanks to Naruto and Tatewaki, Shuu is able to escape alongside Chiyo. After that, they go to the Land of That with Naruto and Team 10.\"}'),(331,57877,'Son Gokuu','{\"Description\":\"Son Gokuu, more commonly known as the Four-Tails or Yonbi, is a tailed beast sealed within Roushi of Iwagakure.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Son Gokuu, more commonly known as the Four-Tails or Yonbi, is a tailed beast sealed within Roushi of Iwagakure.\"}'),(332,13483,'Sora','{\"Description\":\"As a child, Sora\\u0027s only known family was his father Kazuma, who he looked up to greatly and wanted to follow in his footsteps, later believing him to have been killed. After his father\\u0027s presumed death, Sora went to live with the monks of the Fire Temple. At the temple, Sora trained hard in hopes of some day avenging his father and clearing his name, as Sora refused to believe what a horrible man people claimed him to be.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"As a child, Sora\'s only known family was his father Kazuma, who he looked up to greatly and wanted to follow in his footsteps, later believing him to have been killed. After his father\'s presumed death, Sora went to live with the monks of the Fire Temple. At the temple, Sora trained hard in hopes of some day avenging his father and clearing his name, as Sora refused to believe what a horrible man people claimed him to be.\"}'),(333,94981,'Sora','{\"Description\":\"Sora (\\u30BD\\u30E9, Sora) is a young girl from the Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"Sora (ソラ, Sora) is a young girl from the Tonika Village.\"}'),(334,186450,'Stone carver\'s assistant','{\"Description\":\"As shown in episode 219 he is the assistant of the stone carver who carves all of the hokage\\u0027s faces in the mountain in The Village Hidden In The Leaves.\"}','{\"Description\": \"As shown in episode 219 he is the assistant of the stone carver who carves all of the hokage\'s faces in the mountain in The Village Hidden In The Leaves.\"}'),(335,41214,'Suguro','{\"Description\":\"Suguro is a thief that was part of Jako\\u0026amp;#039;s gang.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #194\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #194\", \"(source\": \")\", \"Description\": \"Suguro is a thief that was part of Jako&amp;#039;s gang.\"}'),(336,52051,'Suika','{}','{}'),(337,40785,'Suikazan, Fuguki','{\"Description\":\"Fuguki Suikazan (\\u897F\\u74DC\\u5C71\\u6CB3\\u8C5A\\u9B3C, Suikazan Fuguki) was a high-ranking shinobi of Kirigakure and a former member of the Seven Ninja Swordsmen of the Mist.\",\"Manga Debut\":\"Chapter #507\",\"Anime Debut\":\"Naruto Shippuuden Episode #251\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #251\", \"Description\": \"Fuguki Suikazan (西瓜山河豚鬼, Suikazan Fuguki) was a high-ranking shinobi of Kirigakure and a former member of the Seven Ninja Swordsmen of the Mist.\", \"Manga Debut\": \"Chapter #507\"}'),(338,63979,'Suiren','{\"Description\":\"Suiren (\\u30B9\\u30A4\\u30EC\\u30F3, Suiren) was a kunoichi of Kirigakure.\",\"Description_2\":\"Ten years prior to the formation of the Allied Shinobi Forces, Suiren was part of Ganry\\u016B\\u0027s team that was tasked with retrieving a scroll along with a team from Iwagakure taken by Kumogakure shinobi. After retrieving the document, Suiren was excited for the prospects of peace that a mission like this would bring. She was however wrong as Iwagakure betrayed them. After Junsai was killed, Suiren sacrificed herself in order to protect Ganry\\u016B. This incident which come to be known as the Tragedy of Yosuga Pass marked the begining of hostility between Kirigakure and Iwagakure.\",\"Description_3\":\"Suiren was a kind and loving person who dearly held onto the ideals of peace. After their mission was seemingly completed she spoke openly of what an alliance like this between Kirigakure and Iwagakure would mean for the shinobi world.\",\"Description_4\":\"She was a very beautiful kunoichi with brown eyes and long blonde hair with two strands framing her face. She wore a pair of earrings along with the standard attire of the Kirigakure-nin complete with forehead protector and flak jacket, along with the jade-green bangle that was worn by her team.\",\"Source\":\"\"}','{\"Source\": \"\", \"Description\": \"Suiren (スイレン, Suiren) was a kunoichi of Kirigakure.\", \"Description_2\": \"Ten years prior to the formation of the Allied Shinobi Forces, Suiren was part of Ganryū\'s team that was tasked with retrieving a scroll along with a team from Iwagakure taken by Kumogakure shinobi. After retrieving the document, Suiren was excited for the prospects of peace that a mission like this would bring. She was however wrong as Iwagakure betrayed them. After Junsai was killed, Suiren sacrificed herself in order to protect Ganryū. This incident which come to be known as the Tragedy of Yosuga Pass marked the begining of hostility between Kirigakure and Iwagakure.\", \"Description_3\": \"Suiren was a kind and loving person who dearly held onto the ideals of peace. After their mission was seemingly completed she spoke openly of what an alliance like this between Kirigakure and Iwagakure would mean for the shinobi world.\", \"Description_4\": \"She was a very beautiful kunoichi with brown eyes and long blonde hair with two strands framing her face. She wore a pair of earrings along with the standard attire of the Kirigakure-nin complete with forehead protector and flak jacket, along with the jade-green bangle that was worn by her team.\"}'),(339,143534,'Sukea','{}','{}'),(340,88307,'Sukui','{\"Description\":\"Sukui (\\u30B9\\u30AF\\u30A4, Sukui) is a medical-nin from Konohagakure.\",\"Description_2\":\"Sukui was assigned to the Logistical Support and Medical Division during the Fourth Shinobi World War. During a lull in the war with the body count rising and the casualties coming in to be healed, the scroll which the division was using to seal away the corpses of the shinobi with kekkei genkai and other unique abilities was stolen by a reincarnated Hayate Gekko and the two other ninja. Realizing the gravity of the situation, Sukui formed a team consisting of Yokaze, Sakura Haruno, Iou, and Yugao Uzuki to retrieve the KIA scroll. After realizing that she was putting Yugao in a terrible spot, Sukui apologized but noted that in order to have the mission turn out well, they needed her to participate in the retrieval.\",\"Description_3\":\"With each of the battlefields wrapping up their fights, Sakura and Shizune leave to aid Naruto and B in their battle, leaving Sukui and the others to tend to the wounded.\",\"Anime Debut\":\"Naruto Shippuuden Episode #307\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #307\", \"Description\": \"Sukui (スクイ, Sukui) is a medical-nin from Konohagakure.\", \"Description_2\": \"Sukui was assigned to the Logistical Support and Medical Division during the Fourth Shinobi World War. During a lull in the war with the body count rising and the casualties coming in to be healed, the scroll which the division was using to seal away the corpses of the shinobi with kekkei genkai and other unique abilities was stolen by a reincarnated Hayate Gekko and the two other ninja. Realizing the gravity of the situation, Sukui formed a team consisting of Yokaze, Sakura Haruno, Iou, and Yugao Uzuki to retrieve the KIA scroll. After realizing that she was putting Yugao in a terrible spot, Sukui apologized but noted that in order to have the mission turn out well, they needed her to participate in the retrieval.\", \"Description_3\": \"With each of the battlefields wrapping up their fights, Sakura and Shizune leave to aid Naruto and B in their battle, leaving Sukui and the others to tend to the wounded.\"}'),(341,39571,'Sukune','{\"Description\":\"Sukune was a brave man who never gave up hope of defending his village against Kandachi. He was similar to Kaiza, and died in the similar manner trying to do the best for his countrymen. His son Tanishi at first, detested him, but when he saw the meaning of his death, began to love him. He was buried in the village\\u0027s graveyard.\",\"Description_2\":\"Jiraiya mentions that Sukune and his family were very kind to him when he visited the Genjutsu Tree Village the first time, and is sad to hear of his death when he returns with Naruto later. He is known to be respected in the village. The husband of Yone and the father of Tanishi. No noticeable skills- he is shown to be fairly strong from the civilian\\u0027s standpoint, but his skills are not nearly equal to those of a ninja.\"}','{\"Description\": \"Sukune was a brave man who never gave up hope of defending his village against Kandachi. He was similar to Kaiza, and died in the similar manner trying to do the best for his countrymen. His son Tanishi at first, detested him, but when he saw the meaning of his death, began to love him. He was buried in the village\'s graveyard.\", \"Description_2\": \"Jiraiya mentions that Sukune and his family were very kind to him when he visited the Genjutsu Tree Village the first time, and is sad to hear of his death when he returns with Naruto later. He is known to be respected in the village. The husband of Yone and the father of Tanishi. No noticeable skills- he is shown to be fairly strong from the civilian\'s standpoint, but his skills are not nearly equal to those of a ninja.\"}'),(342,23154,'Suzume','{\"Description\":\"Suzume (\\u30B9\\u30BA\\u30E1) is a Ch\\u016Bnin from Konohagakure. She taught Ino and Sakura\\u0027s kunoichi class in the past, showing them how to pass themselves off as a normal women when undercover. She appears again in the anime during the Fire Temple arc protecting the village from attackers.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Suzume (スズメ) is a Chūnin from Konohagakure. She taught Ino and Sakura\'s kunoichi class in the past, showing them how to pass themselves off as a normal women when undercover. She appears again in the anime during the Fire Temple arc protecting the village from attackers.\"}'),(343,23151,'Taiseki','{\"Description\":\"Taiseki (\\u30BF\\u30A4\\u30BB\\u30AD) was a shinobi from Iwagakure who fought and died during the Third Great Shinobi World War. He had a quiet and wary personality.\",\"Description_2\":\"He formed a team with Kakk\\u014D, using their superb diversionary tactics to attack the enemy. With his Hiding with Camouflage Technique he was able to approach his enemies from their blind spot, easily killing them with a single strike. He confronted Team Minato, led by Kakashi Hatake, during the Third Great Shinobi World War, managing to take Rin captive. He was later killed by Obito Uchiha, however, while he and Kakashi attempted to rescue Rin.\"}','{\"Description\": \"Taiseki (タイセキ) was a shinobi from Iwagakure who fought and died during the Third Great Shinobi World War. He had a quiet and wary personality.\", \"Description_2\": \"He formed a team with Kakkō, using their superb diversionary tactics to attack the enemy. With his Hiding with Camouflage Technique he was able to approach his enemies from their blind spot, easily killing them with a single strike. He confronted Team Minato, led by Kakashi Hatake, during the Third Great Shinobi World War, managing to take Rin captive. He was later killed by Obito Uchiha, however, while he and Kakashi attempted to rescue Rin.\"}'),(344,56689,'Taji','{\"Description\":\"Taji (\\u30BF\\u30B8, Taji) was a Konoha ANBU and medical-nin of Konohagakure.\",\"Manga Debut\":\"Chapter #500\",\"Anime Debut\":\"Naruto Shippuuden Episode #247\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #247\", \"Description\": \"Taji (タジ, Taji) was a Konoha ANBU and medical-nin of Konohagakure.\", \"Manga Debut\": \"Chapter #500\"}'),(345,23150,'Tamaki','{\"Description\":\"Tamaki is a young girl who works at a shop in an abandoned city with her grandmother, Nekobaa. They live with a lot of cats, including talking ninneko such as Denka and Hina.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tamaki is a young girl who works at a shop in an abandoned city with her grandmother, Nekobaa. They live with a lot of cats, including talking ninneko such as Denka and Hina.\"}'),(346,97787,'Tamao','{\"Description\":\"Tamao (\\u30BF\\u30DE\\u30AA, Tamao) is a woman who took place in the eating contest organised in the Land of This.\",\"Description_2\":\"Tamao was one of the Chouji\\u0027s opponents during the eating contest in the Land of This. Tamao passed the first two rounds of the contest and goes to the final round, in a duel with Isono and Chouji. The duel consisted in eating barbecue. She decided to eat as fast as possible and used the technique \\u0022Double Chopsticks\\u0022 that allowed her eat with two chopstick with both her hands. Finally, she was in third place and won a small wicker basket.\",\"Anime Debut\":\"Naruto Shippuuden Episode #309\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #309\", \"Description\": \"Tamao (タマオ, Tamao) is a woman who took place in the eating contest organised in the Land of This.\", \"Description_2\": \"Tamao was one of the Chouji\'s opponents during the eating contest in the Land of This. Tamao passed the first two rounds of the contest and goes to the final round, in a duel with Isono and Chouji. The duel consisted in eating barbecue. She decided to eat as fast as possible and used the technique \\\"Double Chopsticks\\\" that allowed her eat with two chopstick with both her hands. Finally, she was in third place and won a small wicker basket.\"}'),(347,62643,'Tango','{\"Description\":\"Tango (\\u30BF\\u30F3\\u30B4, Tango) is a Kumogakure shinobi.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #261\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #261\", \"Description\": \"Tango (タンゴ, Tango) is a Kumogakure shinobi.\", \"Manga Debut\": \"Chapter #515\"}'),(348,39572,'Tanishi','{\"Description\":\"Tanishi (\\u30BF\\u30CB\\u30B7, Tanishi) is a boy from the Genjutsu Tree Village. Kandachi, a missing-nin from Amegakure, attacks and takes over the village, and kills Tanishi\\u0027s father, Sukune, in the process. Tanishi is at first scared, but Naruto changes him and helps him in their plan to take back the village. In the end they grieve the death of his father Sukune who gave his life for the village. He was in the battle between Naruto and Kandachi, and he helped by taking the villagers to a safe location.\",\"Description_2\":\"Before meeting Naruto, Tanishi didn\\u0027t seem to believe in himself, but this changes after Kandachi is defeated.\"}','{\"Description\": \"Tanishi (タニシ, Tanishi) is a boy from the Genjutsu Tree Village. Kandachi, a missing-nin from Amegakure, attacks and takes over the village, and kills Tanishi\'s father, Sukune, in the process. Tanishi is at first scared, but Naruto changes him and helps him in their plan to take back the village. In the end they grieve the death of his father Sukune who gave his life for the village. He was in the battle between Naruto and Kandachi, and he helped by taking the villagers to a safe location.\", \"Description_2\": \"Before meeting Naruto, Tanishi didn\'t seem to believe in himself, but this changes after Kandachi is defeated.\"}'),(349,17551,'Tanzou','{\"Description\":\"Tanzou was a Genin from Hidden Leaf who particpated in the Chuunin exam. He and his teammates made it to the second test of the exam. While he was off finding food, his teammates decided to open their Heaven scroll. Unfortunately this served to automatically disqualify the team. When he returned he found his teammates Minoji and Shibire knocked out and their exam over.\"}','{\"Description\": \"Tanzou was a Genin from Hidden Leaf who particpated in the Chuunin exam. He and his teammates made it to the second test of the exam. While he was off finding food, his teammates decided to open their Heaven scroll. Unfortunately this served to automatically disqualify the team. When he returned he found his teammates Minoji and Shibire knocked out and their exam over.\"}'),(350,23759,'Tatami, Iwashi','{\"Description\":\"Konoha ch\\u016Bnin.\"}','{\"Description\": \"Konoha chūnin.\"}'),(351,84619,'Tatewaki','{\"Description\":\"Appears in Naruto Shipp\\u016Bden episode 309.\",\"Description_2\":\"Tatewaki was a former samurai from the Land of Iron.\"}','{\"Description\": \"Appears in Naruto Shippūden episode 309.\", \"Description_2\": \"Tatewaki was a former samurai from the Land of Iron.\"}'),(352,3052,'Tayuya','{\"Birthday\":\"February 15\",\"Description\":\"Tayuya (\\u591A\\u7531\\u4E5F) is a  kunoichi of Orochimaru\\u0027s Sound Four.\",\"Description_2\":\"Personality\",\"Description_3\":\"Tayuya is foul-mouthed towards most people, especially Jirobo, calling him \\u0022fatty\\u0022, as he criticized her over it. She didn\\u0027t think much of Shikamaru Nara as a leader, but as a weak, useless rat, who ran away when she used her Doki to attack him. Of the Sound Four, Tayuya was the only member to show a sense of morality, as she berated Shikamaru for sacrificing his teammates to bring back one person who voluntarily left.\",\"Description_4\":\"Involvement in Plot\"}','{\"Birthday\": \"February 15\", \"Description\": \"Tayuya (多由也) is a  kunoichi of Orochimaru\'s Sound Four.\", \"Description_2\": \"Personality\", \"Description_3\": \"Tayuya is foul-mouthed towards most people, especially Jirobo, calling him \\\"fatty\\\", as he criticized her over it. She didn\'t think much of Shikamaru Nara as a leader, but as a weak, useless rat, who ran away when she used her Doki to attack him. Of the Sound Four, Tayuya was the only member to show a sense of morality, as she berated Shikamaru for sacrificing his teammates to bring back one person who voluntarily left.\", \"Description_4\": \"Involvement in Plot\"}'),(353,17197,'Tazuna','{\"Description\":\"The bridge builder. Tazuna is a grey hared bespectacled man with a moustache. When first introduced, he wore a sleeveless v-neck shirt with an obi, pants and a pair of sandals. He also carried a towel around his neck and wore a pointed hat on his head. When seen in Part II Tazuna wore the same attire inclusive of the towel; a habit Inari has started to mimic.\",\"Description_2\":\"He resolved to build a bridge that would connect the Land of Waves to the mainland to help restore its economic stability, which was against Gat\\u014D\\u0027s interest. He knew that Gat\\u014D would try to kill him, but couldn\\u0027t afford proper protection. It was because of this that Tazuna hired Team 7 under the false pretense of protecting him from bandits (this was considered a C-rank mission, thus reducing the cost). Unlike most of his fellow citizens, Tazuna was brave enough to defy Gat\\u014D\\u0027s interests, although he was perfectly aware of the consequences. In honor of Naruto Uzumaki, and for his example of courage, Tazuna named the bridge the \\u0022Great Naruto Bridge\\u0022 after its completion.\"}','{\"Description\": \"The bridge builder. Tazuna is a grey hared bespectacled man with a moustache. When first introduced, he wore a sleeveless v-neck shirt with an obi, pants and a pair of sandals. He also carried a towel around his neck and wore a pointed hat on his head. When seen in Part II Tazuna wore the same attire inclusive of the towel; a habit Inari has started to mimic.\", \"Description_2\": \"He resolved to build a bridge that would connect the Land of Waves to the mainland to help restore its economic stability, which was against Gatō\'s interest. He knew that Gatō would try to kill him, but couldn\'t afford proper protection. It was because of this that Tazuna hired Team 7 under the false pretense of protecting him from bandits (this was considered a C-rank mission, thus reducing the cost). Unlike most of his fellow citizens, Tazuna was brave enough to defy Gatō\'s interests, although he was perfectly aware of the consequences. In honor of Naruto Uzumaki, and for his example of courage, Tazuna named the bridge the \\\"Great Naruto Bridge\\\" after its completion.\"}'),(354,2174,'Temari','{\"Age\":\"15 (I) ; 19 (II)\",\"Birthday\":\"23 August\",\"Horoscope\":\"Virgo\",\"Bloodtype\":\"0\",\"Height\":\"165 cm\",\"Weight\":\"47.9 kg\",\"Rank\":\"Genin (I); Jonin (II)\",\"Likes\":\"Roasted chestnuts, plant appreciation\",\"Dislikes\":\"Squid, octopus\",\"Description\":\"Temari is the oldest child of the Fourth Kazekage, making her the older sister of Gaara and Kankuro. Temari is generally overbearing, if not crude, toward those around her, often not being afraid to speak her mind. One of the few things shown to intimidate her is her younger brother Gaara. She very rarely stays true to her normally tough, demanding attitude, when around the boy, due to the fear of Gaara\\u0027s wrath. Temari does have a caring side, and is not above showing concern for others. She is often seen with Shikamaru. Temari is a keen analyst, and can easily deduce an opponent\\u0027s strategies and weaknesses soon after a battle begins.  For actual combat she uses her giant iron fan that, in addition to serving as a makeshift club, can be used to glide upon in order to intimidate her foes.\"}','{\"Age\": \"15 (I) ; 19 (II)\", \"Rank\": \"Genin (I); Jonin (II)\", \"Likes\": \"Roasted chestnuts, plant appreciation\", \"Height\": \"165 cm\", \"Weight\": \"47.9 kg\", \"Birthday\": \"23 August\", \"Dislikes\": \"Squid, octopus\", \"Bloodtype\": \"0\", \"Horoscope\": \"Virgo\", \"Description\": \"Temari is the oldest child of the Fourth Kazekage, making her the older sister of Gaara and Kankuro. Temari is generally overbearing, if not crude, toward those around her, often not being afraid to speak her mind. One of the few things shown to intimidate her is her younger brother Gaara. She very rarely stays true to her normally tough, demanding attitude, when around the boy, due to the fear of Gaara\'s wrath. Temari does have a caring side, and is not above showing concern for others. She is often seen with Shikamaru. Temari is a keen analyst, and can easily deduce an opponent\'s strategies and weaknesses soon after a battle begins.  For actual combat she uses her giant iron fan that, in addition to serving as a makeshift club, can be used to glide upon in order to intimidate her foes.\"}'),(355,60103,'Tenga','{\"Description\":\"Tenga (\\u5929\\u753B, Tenga) is a shinobi of Kumogakure.\",\"Manga Debut\":\"Chapter #488\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #218\"}','{\"Anime Debut\": \"Naruto Shippūden Episode #218\", \"Description\": \"Tenga (天画, Tenga) is a shinobi of Kumogakure.\", \"Manga Debut\": \"Chapter #488\"}'),(356,147444,'Tenji','{\"Description\":\"Tenji was the emperor of the Land of Ancestors.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Tenji was the emperor of the Land of Ancestors.\"}'),(357,3710,'Tenten','{\"Age\":\"14 (I) ; 17 (II)\",\"Birthday\":\"9 March\",\"Horoscope\":\"Pisces\",\"Bloodtype\":\"B\",\"Height\":\"164 cm\",\"Weight\":\"47.3 kg\",\"Rank\":\"Genin (I); Chuunin (II)\",\"Likes\":\"Chinese buns, Sesame dumplings, fortune-telling\",\"Dislikes\":\"pickled-plum\",\"Description\":\"Tenten specializes in weaponry, and according to Guy she can hit a bullseye 100 out of 100 times, although her more powerful enemies can often block her attacks.\",\"Description_2\":\"In battle she summons varying types of weapons from the scrolls she carries with her. In Part I she has many scrolls that serve this purpose, but in Part II she has consolidated her arsenal into a single large scroll. The weapons predominately consist of steel projectiles and an assortment of close-combat weapons, though she is seen using a crossbow in the anime and even a spiked bomb in Part II.\"}','{\"Age\": \"14 (I) ; 17 (II)\", \"Rank\": \"Genin (I); Chuunin (II)\", \"Likes\": \"Chinese buns, Sesame dumplings, fortune-telling\", \"Height\": \"164 cm\", \"Weight\": \"47.3 kg\", \"Birthday\": \"9 March\", \"Dislikes\": \"pickled-plum\", \"Bloodtype\": \"B\", \"Horoscope\": \"Pisces\", \"Description\": \"Tenten specializes in weaponry, and according to Guy she can hit a bullseye 100 out of 100 times, although her more powerful enemies can often block her attacks.\", \"Description_2\": \"In battle she summons varying types of weapons from the scrolls she carries with her. In Part I she has many scrolls that serve this purpose, but in Part II she has consolidated her arsenal into a single large scroll. The weapons predominately consist of steel projectiles and an assortment of close-combat weapons, though she is seen using a crossbow in the anime and even a spiked bomb in Part II.\"}'),(358,23478,'Terumi, Mei','{\"Birthdate\":\"May 21\",\"Zodiac sign\":\"Gemini\",\"Gender\":\"Female\",\"Age\":\"Part II: 31\",\"Height\":\"Part II: 174 cm\",\"Weight\":\"Part II: 53 kg\",\"Blood type\":\"AB\",\"Description\":\"Mei Terumi is the Fifth Mizukage and the leader of Kirigakure. As Mizukage, her word holds sway over all political and military issues that present themselves regarding Kirigakure and its inhabitants. She became Mizukage in recent years, after the dreadful reign of Yagura ended.\",\"Description_2\":\"Mei is a slender, young woman in her thirties. She has ankle-length, auburn hair styled into a herringbone pattern at the back, a top-knot tied with a dark-blue band, and with four bangs at the front. Two bang are short, with one covering her right eye, and two are long, crossing each other on her chest, just below her chin. Her eyes are light green.\",\"Description_3\":\"She dresses in a long-sleeved dark-blue dress, that falls just below the knees. It seems to be closed at the front with a zip and is kept open on the front-right side from the waist down. The dress only covers up to the upper part of her upper arms and the underside of her breasts. Underneath, she wears a mesh shirt that covers more of her upper body than her dress, but stops short of covering her shoulders and still leaving a sizable cleavage. She also wears shorts in the same colour as dress and, underneath those, mesh leggings reaching down over her knees. Around her waist, she wears a belt with a pouch attached to the back on the left.\"}','{\"Age\": \"Part II: 31\", \"Gender\": \"Female\", \"Height\": \"Part II: 174 cm\", \"Weight\": \"Part II: 53 kg\", \"Birthdate\": \"May 21\", \"Blood type\": \"AB\", \"Description\": \"Mei Terumi is the Fifth Mizukage and the leader of Kirigakure. As Mizukage, her word holds sway over all political and military issues that present themselves regarding Kirigakure and its inhabitants. She became Mizukage in recent years, after the dreadful reign of Yagura ended.\", \"Zodiac sign\": \"Gemini\", \"Description_2\": \"Mei is a slender, young woman in her thirties. She has ankle-length, auburn hair styled into a herringbone pattern at the back, a top-knot tied with a dark-blue band, and with four bangs at the front. Two bang are short, with one covering her right eye, and two are long, crossing each other on her chest, just below her chin. Her eyes are light green.\", \"Description_3\": \"She dresses in a long-sleeved dark-blue dress, that falls just below the knees. It seems to be closed at the front with a zip and is kept open on the front-right side from the waist down. The dress only covers up to the upper part of her upper arms and the underside of her breasts. Underneath, she wears a mesh shirt that covers more of her upper body than her dress, but stops short of covering her shoulders and still leaving a sizable cleavage. She also wears shorts in the same colour as dress and, underneath those, mesh leggings reaching down over her knees. Around her waist, she wears a belt with a pouch attached to the back on the left.\"}'),(359,17312,'Teuchi','{\"Description\":\"Teuchi is the owner of the Ichiraku Ramen Bar. His daughter is Ayame, and she works at his Ramen bar. Right before the third stage of the Ch\\u016Bnin Exam, he treated Naruto to an expensive bowl of ramen, which surprised him. Some months later, Ayame was kidnapped by Hakaku, who wanted Teuchi\\u0027s recipe. The recipe was just to remove the bitter taste from the soup.\",\"(Source\":\"Naruto Wiki)\"}','{\"(Source\": \"Naruto Wiki)\", \"Description\": \"Teuchi is the owner of the Ichiraku Ramen Bar. His daughter is Ayame, and she works at his Ramen bar. Right before the third stage of the Chūnin Exam, he treated Naruto to an expensive bowl of ramen, which surprised him. Some months later, Ayame was kidnapped by Hakaku, who wanted Teuchi\'s recipe. The recipe was just to remove the bitter taste from the soup.\"}'),(360,3149,'Tobi','{\"Description\":\"Tobi was formerly Zetsu\\u0027s subordinate, and became a full Akatsuki member after Sasori\\u0027s death. He now wears the same ring as Sasori, having recovered it after Sasori\\u0027s death, and took his place as Deidara\\u0027s partner. Unlike the majority of ninja thus far, Tobi has not been shown wearing a visible forehead protector, so his place of origin is unknown. He wears an orange mask with single eye-hole covered in a swirl pattern concentrated towards the right eye. This odd mask that covers his entire face save for his right eye. Furthermore, Tobi has several bolts or pins present on the arms of his uniform, now obscured by his Akatsuki cloak.\",\"Description_2\":\"Tobi\\u0027s area of expertise remains unclear, as he has never been shown fighting. He and Deidara have defeated the three-tailed beast, but Tobi is never shown doing anything but running from it. After the battle, which goes largely unwitnessed, Tobi claims to have knocked it out with a single attack. Deidara disagrees with the assessment, claiming that it was his \\u0022artistic contribution\\u0022 (exploding clay) that allowed them to win. During his fight with Sasuke, Tobi shows the ability to recover from what are presumably debilitating or fatal blows. After being slashed across the midsection by Sasuke\\u0027s sword, Tobi collapses, only to stand up again a few seconds later and complain about the speed of the attack. Aside from this, Tobi has yet to demonstrate any techniques.\",\"Description_3\":\"Tobi has a very formal and correct manner of speech. While his physical appearance remains a mystery, Zetsu has implied that he is relatively young when one side of him referred to Tobi as a \\u0022good boy.\\u0022 He respects Deidara, referring to him as Deidara-senpai. Tobi\\u0027s personality is rather odd in comparison with other Akatsuki members. While most of the members are dedicated and serious, though somewhat argumentative or even hostile towards each other when not fighting, Tobi is more carefree and goofy, much like Naruto. His personality does not please Deidara, who believes that all Akatsuki members should be serious and calm. Tobi unintentionally irritates Deidara frequently, which usually results in Deidara attacking Tobi in a comedic fashion.\"}','{\"Description\": \"Tobi was formerly Zetsu\'s subordinate, and became a full Akatsuki member after Sasori\'s death. He now wears the same ring as Sasori, having recovered it after Sasori\'s death, and took his place as Deidara\'s partner. Unlike the majority of ninja thus far, Tobi has not been shown wearing a visible forehead protector, so his place of origin is unknown. He wears an orange mask with single eye-hole covered in a swirl pattern concentrated towards the right eye. This odd mask that covers his entire face save for his right eye. Furthermore, Tobi has several bolts or pins present on the arms of his uniform, now obscured by his Akatsuki cloak.\", \"Description_2\": \"Tobi\'s area of expertise remains unclear, as he has never been shown fighting. He and Deidara have defeated the three-tailed beast, but Tobi is never shown doing anything but running from it. After the battle, which goes largely unwitnessed, Tobi claims to have knocked it out with a single attack. Deidara disagrees with the assessment, claiming that it was his \\\"artistic contribution\\\" (exploding clay) that allowed them to win. During his fight with Sasuke, Tobi shows the ability to recover from what are presumably debilitating or fatal blows. After being slashed across the midsection by Sasuke\'s sword, Tobi collapses, only to stand up again a few seconds later and complain about the speed of the attack. Aside from this, Tobi has yet to demonstrate any techniques.\", \"Description_3\": \"Tobi has a very formal and correct manner of speech. While his physical appearance remains a mystery, Zetsu has implied that he is relatively young when one side of him referred to Tobi as a \\\"good boy.\\\" He respects Deidara, referring to him as Deidara-senpai. Tobi\'s personality is rather odd in comparison with other Akatsuki members. While most of the members are dedicated and serious, though somewhat argumentative or even hostile towards each other when not fighting, Tobi is more carefree and goofy, much like Naruto. His personality does not please Deidara, who believes that all Akatsuki members should be serious and calm. Tobi unintentionally irritates Deidara frequently, which usually results in Deidara attacking Tobi in a comedic fashion.\"}'),(361,24324,'Tobio','{\"Description\":\"Tobio (\\u30C8\\u30D3\\u30AA) was in the same graduating class as the members of Team 7. He accidentally knocks into Naruto, causing Naruto to kiss Sasuke.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tobio (トビオ) was in the same graduating class as the members of Team 7. He accidentally knocks into Naruto, causing Naruto to kiss Sasuke.\"}'),(362,23140,'Tobitake, Tonbo','{\"Age\":\"27 (part 1), 31 (part 2)\",\"Birthday\":\"April 4\",\"Height\":\"167 cm\",\"Weight\":\"55 kg\",\"Blood type\":\"A\",\"Ninja ID\":\"010997\",\"Description\":\"Tonbo Tobitake is a Konohagakure Ch\\u016Bnin. Most of his face is wrapped in bandages and he usually has a cigarette in his mouth.\",\"Description_2\":\"He works under Inoichi Yamanaka in the intelligence core. He was taught by Mawashi Dokuraku,\",\"Description_3\":\"Tonbo, at first glance gives off a very collected and cool personality. He is described as being very confident in his abilities although not haughty enough to not acknowledge someone else\\u0027s talent. He is also somewhat rash and quick-tempered by nature as witnessed when he roughed up Komaza to get his point across.\",\"Description_4\":\"\\u0022Tonbo\\u0022 (\\u873B\\u86C9) is Japanese for \\u0022dragonfly\\u0022. Dragonflies are famous for their 360\\u00B0 vision, which is ironic considering that Tonbo\\u0027s eyes and upper face are covered with bandages. While \\u0022Tobitake\\u0022 means \\u0022lying [through] the bamboo\\u0022. A taketonbo (\\u7AF9\\u3068\\u3093\\u307C) is a small bamboo toy that flies when spun between the palms of your hands. So Tonbo\\u0027s full name could also mean \\u0022flying taketonbo\\u0022.\",\"Description_5\":\"His favourite food is yakitori and grilled onigiri while his least favourite food is cr\\u00E8me fra\\u00EEche.\"}','{\"Age\": \"27 (part 1), 31 (part 2)\", \"Height\": \"167 cm\", \"Weight\": \"55 kg\", \"Birthday\": \"April 4\", \"Ninja ID\": \"010997\", \"Blood type\": \"A\", \"Description\": \"Tonbo Tobitake is a Konohagakure Chūnin. Most of his face is wrapped in bandages and he usually has a cigarette in his mouth.\", \"Description_2\": \"He works under Inoichi Yamanaka in the intelligence core. He was taught by Mawashi Dokuraku,\", \"Description_3\": \"Tonbo, at first glance gives off a very collected and cool personality. He is described as being very confident in his abilities although not haughty enough to not acknowledge someone else\'s talent. He is also somewhat rash and quick-tempered by nature as witnessed when he roughed up Komaza to get his point across.\", \"Description_4\": \"\\\"Tonbo\\\" (蜻蛉) is Japanese for \\\"dragonfly\\\". Dragonflies are famous for their 360° vision, which is ironic considering that Tonbo\'s eyes and upper face are covered with bandages. While \\\"Tobitake\\\" means \\\"lying [through] the bamboo\\\". A taketonbo (竹とんぼ) is a small bamboo toy that flies when spun between the palms of your hands. So Tonbo\'s full name could also mean \\\"flying taketonbo\\\".\", \"Description_5\": \"His favourite food is yakitori and grilled onigiri while his least favourite food is crème fraîche.\"}'),(363,52055,'Tokiwa','{\"Description\":\"Tokiwa (\\u30C8\\u30AD\\u30EF, Tokiwa) is a kunoichi from the Nadeshiko Village.\",\"Anime debut\":\"Naruto Shipp\\u016Bden Episode #235\"}','{\"Anime debut\": \"Naruto Shippūden Episode #235\", \"Description\": \"Tokiwa (トキワ, Tokiwa) is a kunoichi from the Nadeshiko Village.\"}'),(364,30186,'Tonbei','{\"Description\":\"Tonbee (\\u9041\\u5175\\u885B) is an elderly man who is a servant to Hotaru.\",\"Description_2\":\"Voiced by Sh\\u014Dz\\u014D Sasaki.\",\"Source\":\"naruto.wikia.com\"}','{\"Source\": \"naruto.wikia.com\", \"Description\": \"Tonbee (遁兵衛) is an elderly man who is a servant to Hotaru.\", \"Description_2\": \"Voiced by Shōzō Sasaki.\"}'),(365,94987,'Tonika Village Head','{\"Description\":\"He was the leader of Tonika Village.\",\"Anime Debut\":\"Naruto Shippuuden Episode #290\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #290\", \"Description\": \"He was the leader of Tonika Village.\"}'),(366,90849,'Tonton','{\"Gender\":\"Female\",\"Species\":\"Pig\",\"Affiliation\":\"Konohagakure\",\"Team\":\"Logistical Support and Medical Division\",\"Description\":\"Tonton is Tsunade\\u0027s pet pig, often kept in the care of Shizune.\"}','{\"Team\": \"Logistical Support and Medical Division\", \"Gender\": \"Female\", \"Species\": \"Pig\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Tonton is Tsunade\'s pet pig, often kept in the care of Shizune.\"}'),(367,22905,'Tora','{\"Description\":\"Tora (\\u30C8\\u30E9) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again. Tora is likely not his real name, but a codename.\",\"Description_2\":\"He was said to be very skilled. Endowed with tiger-like strength and walking ability, any target he aimed for had no hopes of escape.\",\"(Source\":\"Narutopedia)\",\"Description_3\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tora (トラ) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again. Tora is likely not his real name, but a codename.\", \"Description_2\": \"He was said to be very skilled. Endowed with tiger-like strength and walking ability, any target he aimed for had no hopes of escape.\", \"Description_3\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(368,95097,'Toroi','{\"Description\":\"Toroi was a famed Kumogakure shinobi.\",\"Description_2\":\"In preparation for the Fourth Shinobi World War, Toroi is reincarnated by Kabuto Yakushi to fight against the Allied Shinobi Forces, before being mobilised alongside Gari, Pakura, Haku and Zabuza Momochi. Separating from this group at some point during their relocation, Toroi is later discovered trailing Musai and Nonota, with numerous shuriken in hand and scroll in mouth. Identified by the Kumo-nin, who attempts to alert his ally to the best method to not fall victim to his Magnet Release, Toroi goes on the offensive.\",\"Description_3\":\"Despite the pre-emptive warning, the unaware Suna-nin still falls foul of the attack and is evidently terrified as the details of the technique are disclosed. Prepared to conclude the battle using even larger shuriken, Toroi is ambushed from behind by Naruto Uzumaki wielding a Rasengan, before being sealed by the previously panic-stricken Suna-nin.\",\"Description_4\":\"Later, with the release of the Impure World Reincarnation technique, a light of sorts encased Toroi\\u0027s sealed body as the technique was dispelled and his soul was returned to the afterlife.\",\"Manga Debut\":\"Chapter #516\",\"Anime Debut\":\"Naruto Shippuuden Episode #261\",\"(Source\":\"Narutopedia)\",\"Description_5\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #261\", \"Description\": \"Toroi was a famed Kumogakure shinobi.\", \"Manga Debut\": \"Chapter #516\", \"Description_2\": \"In preparation for the Fourth Shinobi World War, Toroi is reincarnated by Kabuto Yakushi to fight against the Allied Shinobi Forces, before being mobilised alongside Gari, Pakura, Haku and Zabuza Momochi. Separating from this group at some point during their relocation, Toroi is later discovered trailing Musai and Nonota, with numerous shuriken in hand and scroll in mouth. Identified by the Kumo-nin, who attempts to alert his ally to the best method to not fall victim to his Magnet Release, Toroi goes on the offensive.\", \"Description_3\": \"Despite the pre-emptive warning, the unaware Suna-nin still falls foul of the attack and is evidently terrified as the details of the technique are disclosed. Prepared to conclude the battle using even larger shuriken, Toroi is ambushed from behind by Naruto Uzumaki wielding a Rasengan, before being sealed by the previously panic-stricken Suna-nin.\", \"Description_4\": \"Later, with the release of the Impure World Reincarnation technique, a light of sorts encased Toroi\'s sealed body as the technique was dispelled and his soul was returned to the afterlife.\", \"Description_5\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(369,41215,'Toufu','{\"Description\":\"T\\u014Dfu (\\u30C8\\u30A6\\u30D5\\u30A6, Toufuu) is a self-proclaimed ex-bandit.\",\"Debut\":\"Naruto Shipp\\u016Bden Episode #195\",\"(source\":\")\"}','{\"Debut\": \"Naruto Shippūden Episode #195\", \"(source\": \")\", \"Description\": \"Tōfu (トウフウ, Toufuu) is a self-proclaimed ex-bandit.\"}'),(370,19253,'Touji, Mizuki','{\"Description\":\"Name Touji Mizuki\",\"Description_2\":\"Gender Male\",\"Description_3\":\"Age 26 years old(born on October 21)\",\"Description_4\":\"Hair Light Gray\",\"Description_5\":\"Eyes Black\",\"Description_6\":\"Height 180 cm\",\"Description_7\":\"Weight 69.4 kg\",\"Description_8\":\"Blood Type AB\",\"Description_9\":\"Status Chunin\",\"Description_10\":\"A Chunin level ninja, Mizuki was a former teacher at the Ninja Academy. After Naruto fails to graduate from the Academy, Mizuki tells Naruto that there is another way to graduate, and tricks him into stealing the forbidden scroll of sealings for him.\",\"Description_11\":\"But as fate would have it, Mizuki shows up and pins Iruka to the wooden shack behind him. Mizuki then tells Naruto the truth about his past, the fact that he is the Demon Fox. Mizuki then attempts to kill both Naruto and Iruka, but luckily, Naruto uses the skill he learned from the scroll, Shadow Clone Jutsu, to create clones of himself which defeat Mizuki easily.\",\"Description_12\":\"After that incident, Mizuki was imprisoned in the Konoha Strict Correctional Facility. Mizuki later on leads a prison revolt and sends the brothers, Fuujin and Raijin, to Orochimaru. During his escape, Mizuki remembers back to when Orochimaru gave him a cursed seal after a mission in which he killed his comrade. He was defeated by Naruto\\u0027s Rasengan.\",\"Description_13\":\"Mizuki is from the Village Hidden in the Leaves, and his technique is the Transformation Jutsu.\"}','{\"Description\": \"Name Touji Mizuki\", \"Description_2\": \"Gender Male\", \"Description_3\": \"Age 26 years old(born on October 21)\", \"Description_4\": \"Hair Light Gray\", \"Description_5\": \"Eyes Black\", \"Description_6\": \"Height 180 cm\", \"Description_7\": \"Weight 69.4 kg\", \"Description_8\": \"Blood Type AB\", \"Description_9\": \"Status Chunin\", \"Description_10\": \"A Chunin level ninja, Mizuki was a former teacher at the Ninja Academy. After Naruto fails to graduate from the Academy, Mizuki tells Naruto that there is another way to graduate, and tricks him into stealing the forbidden scroll of sealings for him.\", \"Description_11\": \"But as fate would have it, Mizuki shows up and pins Iruka to the wooden shack behind him. Mizuki then tells Naruto the truth about his past, the fact that he is the Demon Fox. Mizuki then attempts to kill both Naruto and Iruka, but luckily, Naruto uses the skill he learned from the scroll, Shadow Clone Jutsu, to create clones of himself which defeat Mizuki easily.\", \"Description_12\": \"After that incident, Mizuki was imprisoned in the Konoha Strict Correctional Facility. Mizuki later on leads a prison revolt and sends the brothers, Fuujin and Raijin, to Orochimaru. During his escape, Mizuki remembers back to when Orochimaru gave him a cursed seal after a mission in which he killed his comrade. He was defeated by Naruto\'s Rasengan.\", \"Description_13\": \"Mizuki is from the Village Hidden in the Leaves, and his technique is the Transformation Jutsu.\"}'),(371,149424,'Tsubaki','{\"Description\":\"Tsubaki was the mother of one of the students in Naruto\\u0027s class at the Ninja Academy.\",\"(Source\":\"Naruto Wikia)\"}','{\"(Source\": \"Naruto Wikia)\", \"Description\": \"Tsubaki was the mother of one of the students in Naruto\'s class at the Ninja Academy.\"}'),(372,38461,'Tsukado','{\"Description\":\"Tsukado is a master swordsmen of an unnamed clan who had a vendetta against a man that killed a relative of his, Shikazo. Tsukado was chosen with the task of avenging him by the killing the man who killed him, Katazu. He failed 34 times to defeat him. One day, Team 7 meets Tsukado and seeing his poor revenge skills, Naruto decides to train him. Though his lessons were unusual, he managed to get the upper hand in his next fight with the killer. Naruto stops the fight after noticing Katazu\\u0027s sword wasn\\u0027t even sharpened, saying he couldn\\u0027t possibly kill his relative. He says that it was his twin brother, Kageki who killed his relative but it was an accident. Since then, he has been taking his brother\\u0027s identity. The Kanabun Gang, who were profiting off their fight, try to get the two to fight again but with the help of Team 7 manage to chase them out of town. Tsukado is shown to be able to use chakra flow when using his sword.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Tsukado is a master swordsmen of an unnamed clan who had a vendetta against a man that killed a relative of his, Shikazo. Tsukado was chosen with the task of avenging him by the killing the man who killed him, Katazu. He failed 34 times to defeat him. One day, Team 7 meets Tsukado and seeing his poor revenge skills, Naruto decides to train him. Though his lessons were unusual, he managed to get the upper hand in his next fight with the killer. Naruto stops the fight after noticing Katazu\'s sword wasn\'t even sharpened, saying he couldn\'t possibly kill his relative. He says that it was his twin brother, Kageki who killed his relative but it was an accident. Since then, he has been taking his brother\'s identity. The Kanabun Gang, who were profiting off their fight, try to get the two to fight again but with the help of Team 7 manage to chase them out of town. Tsukado is shown to be able to use chakra flow when using his sword.\"}'),(373,2767,'Tsunade','{\"Birthday\":\"August 2\",\"Zodiac sign\":\"Leo\",\"Height\":\"163.1 cm\",\"Weight\":\"48.9 kg\",\"Blood type\":\"B\",\"Description\":\"Tsunade is the granddaughter of the First Hokage. She is one of the legendary Sannin.\",\"Description_2\":\"After his failed invasion of Konoha, Orochimaru approaches Tsunade to get her to heal his arms. While she initially refuses, Orochimaru offers to revive Dan and Nawaki in exchange for healing his arms. Intrigued, Tsunade is left a week to consider the matter. Once meeting Uzumaki Naruto, Tsunade begins to remember the dreams of her two loved ones and how much they loved the village of Konoha. While she longs to see them both again, Tsunade ultimately is unable to bring herself to help Orochimaru, his hopes of destroying Konoha too strong to ignore. Determined to protect the village her loved ones held dear until the end of their lives, Tsunade battles with Orochimaru and eventually defeats him. Having accepted the title of Fifth Hokage, Tsunade returns to Konoha afterwards.\",\"Description_3\":\"Since becoming Hokage, Tsunade has primarily acted as a source of assignments, and mobilizes Konoha\\u0027s forces when need be. In addition, Tsunade plays a large role in healing the more severe injuries that befall upon those she sends on missions. At the end of Part I, Haruno Sakura becomes Tsunade\\u0027s apprentice.\",\"Description_4\":\"Tsunade\\u0027s trademark ability is her inhuman strength, which is derived from her excellent chakra control. By storing chakra and releasing it at the point of contact, she can enhance her strength to the point where she can break through boulders with her bare hands.\",\"Description_5\":\"She is also an extremely talented Medical-nin, and can heal wounds that most others would consider impossible. As a result of her chakra control and her medical abilities, Tsunade has created a form of regeneration. So she really is near 50 years old, but looks like she were in her twenties.\"}','{\"Height\": \"163.1 cm\", \"Weight\": \"48.9 kg\", \"Birthday\": \"August 2\", \"Blood type\": \"B\", \"Description\": \"Tsunade is the granddaughter of the First Hokage. She is one of the legendary Sannin.\", \"Zodiac sign\": \"Leo\", \"Description_2\": \"After his failed invasion of Konoha, Orochimaru approaches Tsunade to get her to heal his arms. While she initially refuses, Orochimaru offers to revive Dan and Nawaki in exchange for healing his arms. Intrigued, Tsunade is left a week to consider the matter. Once meeting Uzumaki Naruto, Tsunade begins to remember the dreams of her two loved ones and how much they loved the village of Konoha. While she longs to see them both again, Tsunade ultimately is unable to bring herself to help Orochimaru, his hopes of destroying Konoha too strong to ignore. Determined to protect the village her loved ones held dear until the end of their lives, Tsunade battles with Orochimaru and eventually defeats him. Having accepted the title of Fifth Hokage, Tsunade returns to Konoha afterwards.\", \"Description_3\": \"Since becoming Hokage, Tsunade has primarily acted as a source of assignments, and mobilizes Konoha\'s forces when need be. In addition, Tsunade plays a large role in healing the more severe injuries that befall upon those she sends on missions. At the end of Part I, Haruno Sakura becomes Tsunade\'s apprentice.\", \"Description_4\": \"Tsunade\'s trademark ability is her inhuman strength, which is derived from her excellent chakra control. By storing chakra and releasing it at the point of contact, she can enhance her strength to the point where she can break through boulders with her bare hands.\", \"Description_5\": \"She is also an extremely talented Medical-nin, and can heal wounds that most others would consider impossible. As a result of her chakra control and her medical abilities, Tsunade has created a form of regeneration. So she really is near 50 years old, but looks like she were in her twenties.\"}'),(374,15077,'Tsunami','{\"Description\":\"Tsunami is the daughter of Tazuna and the mother of Inari.\",\"Description_2\":\"Her husband died shortly after Inari\\u0027s birth, and when Kaiza entered her life as a father figure for Inari, she couldn\\u0027t help but invite him into her home. Like everyone else in the city, Kaiza\\u0027s death broke her spirit. In the years following, she tried to protect Inari from the painful memories of the loss of his friend and mentor.\"}','{\"Description\": \"Tsunami is the daughter of Tazuna and the mother of Inari.\", \"Description_2\": \"Her husband died shortly after Inari\'s birth, and when Kaiza entered her life as a father figure for Inari, she couldn\'t help but invite him into her home. Like everyone else in the city, Kaiza\'s death broke her spirit. In the years following, she tried to protect Inari from the painful memories of the loss of his friend and mentor.\"}'),(375,31269,'Tsurugi','{\"Description\":\"Tsurugi was the head of Kirigakure\\u0027s Hunter-nin.\"}','{\"Description\": \"Tsurugi was the head of Kirigakure\'s Hunter-nin.\"}'),(376,22893,'Uchiha, Shisui','{\"Description\":\"Shisui Uchiha was feared as \\u0022Shisui of the Body Flicker\\u0022 (\\u77AC\\u8EAB\\u306E\\u30B7\\u30B9\\u30A4, Shunshin no Shisui) and was one of the most talented of the Uchiha clan. Shisui was the best friend of Itachi Uchiha; in fact, Itachi thought of him as an older brother. He was found drowned in a river from what appeared to be suicide, though the Konoha Military Police believed it to be murder.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Shisui Uchiha was feared as \\\"Shisui of the Body Flicker\\\" (瞬身のシスイ, Shunshin no Shisui) and was one of the most talented of the Uchiha clan. Shisui was the best friend of Itachi Uchiha; in fact, Itachi thought of him as an older brother. He was found drowned in a river from what appeared to be suicide, though the Konoha Military Police believed it to be murder.\"}'),(377,22891,'Uchiha, Inabi','{\"Description\":\"Inabi Uchiha (\\u3046\\u3061\\u306F\\u30A4\\u30CA\\u30D3, Uchiha Inabi) was a policeman of the Konoha Military Police and a member of the Uchiha clan. He and two other officers, Yashiro and Tekka Uchiha, questioned Itachi Uchiha about his whereabouts during the time when Shisui Uchiha supposedly committed suicide. Itachi replied, very irritated, making it to the list of suspects brought. Inabi was then killed by Itachi in the Uchiha Clan Massacre.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Inabi Uchiha (うちはイナビ, Uchiha Inabi) was a policeman of the Konoha Military Police and a member of the Uchiha clan. He and two other officers, Yashiro and Tekka Uchiha, questioned Itachi Uchiha about his whereabouts during the time when Shisui Uchiha supposedly committed suicide. Itachi replied, very irritated, making it to the list of suspects brought. Inabi was then killed by Itachi in the Uchiha Clan Massacre.\"}'),(378,22908,'Uchiha, Yashiro','{\"Description\":\"Yashiro Uchiha is the only known member of the Uchiha clan whose hair is not visually black. Despite his old age, Yashiro is one of the top-ranked officers in the Konoha Police Force. It has been seen through flashbacks in the anime that he did not get along well with Itachi. Some of the reasons are that he thought Itachi was a show-off and had an easy time getting into ANBU.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Yashiro Uchiha is the only known member of the Uchiha clan whose hair is not visually black. Despite his old age, Yashiro is one of the top-ranked officers in the Konoha Police Force. It has been seen through flashbacks in the anime that he did not get along well with Itachi. Some of the reasons are that he thought Itachi was a show-off and had an easy time getting into ANBU.\"}'),(379,109565,'Uchiha, Tajima','{\"Description\":\"Tajima Uchiha (\\u3046\\u3061\\u306F\\u30BF\\u30B8\\u30DE, Uchiha Tajima) was a member of the famed Uchiha clan during the war-torn era, preceding the era of hidden villages.\",\"Manga Debut\":\"Chapter #623\",\"Anime Debut\":\"Naruto Shippuuden Episode #368\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #368\", \"Description\": \"Tajima Uchiha (うちはタジマ, Uchiha Tajima) was a member of the famed Uchiha clan during the war-torn era, preceding the era of hidden villages.\", \"Manga Debut\": \"Chapter #623\"}'),(380,14,'Uchiha, Itachi','{\"Age\":\"17-18 (I); 21 (II)\",\"Birthday\":\"June 9th (Gemini)\",\"Height\":\"175 cm (I); 178 cm (II)\",\"Weight\":\"57 kg (I); 58 kg (II)\",\"Blood Type\":\"AB\",\"Nature Type\":\"Fire and Water\",\"From\":\"Konohagakure (Leaf)\",\"Rank\":\"S-class Missing-Nin\",\"Registered Ninja #\":\"012110\",\"Affiliation\":\"Akatsuki\",\"Ring\":\"Shu (Red)\",\"Finger Position\":\"Right Ring\",\"Partner\":\"Hoshigaki Kisame\",\"Favorite Foods\":\"Rice balls (kelp), cabbage, Dango\",\"Least Favorite Foods\":\"Steak\",\"Hobby\":\"Visiting traditional Japanese caf\\u00E9s\",\"First Manga Appearance\":\"Ch. 139\",\"First Anime Appearance\":\"Ep. 80\",\"Assignments Completed\":\"53 D-Rank, 152 C-Rank, 134 B-Rank, 0 A-Rank, 1 S-Rank\",\"Famous Quote\":\"Foolish little brother, if you wish to kill me, hate me, detest me, and survive in an unsightly way. Run, run and cling to life.\",\"Background\":\"\",\"Description\":\"Itachi Uchiha is a missing-nin from Konohagakure, and a prominent member of Akatsuki, partnered with Kisame Hoshigaki. He is Sasuke Uchiha\\u0027s older brother.\",\"Description_2\":\"Itachi is relatively popular among many fans of Naruto, often having ranked in the top ten in Shonen Jump magazine\\u0027s popularity polls since his introduction. He was first ranked in the third character popularity poll ranked in 11th place. He was ranked 9th place during the fourth popularity poll, and 6th place in the fifth popularity poll. During the sixth popularity poll, he again was ranked in 11th place. In the last poll, he was ranked in 5th place.\",\"Description_3\":\"Itachi was born into the Uchiha clan and was praised by all as the best of his generation - a genius above all others. Even by the standards of the battle-adept Uchiha clan, Itachi\\u0027s prowess far outshined all others. However, not even his family, friends, or teachers could understand him. When he was only 4, Itachi had already witnessed countless lives lost due to the Third Great Shinobi World War, which emotionally traumatized him and turned him into a pacifist. At age 7, he graduated from the Ninja Academy at the top of his class after only one year, mastered the Sharingan at age 8, passed the Chunin Exams at age 10, and became ANBU Captain at age 13. According to Madara Uchiha, Itachi also had a lover, whom he killed during the Uchiha clan massacre.\",\"Description_4\":\"He was praised highly by his father, who saw the family\\u0027s future in Itachi, hence neglecting his other son - Itachi\\u0027s younger brother, Sasuke. However, during this time Itachi showed great affection towards his little brother, Sasuke, and even encouraged his father to come to the Academy when Sasuke was enrolled, something their dad had otherwise forgotten, by saying that he would not go to an important mission, that would establish Itachi a place in the ANBU ranks, otherwise.\",\"Personality\":\"\",\"Description_5\":\"As a member of Akatsuki, he possessed incredible self-control of his emotions. He constantly displayed an emotionless personality. He only showed surprise when opponents proved more powerful or skilled than he had expected, and even then he didn\\u0027t lose his composure. He did not possess any arrogance, and fully justified any statements he made about his power, even complimenting his opponents at times on their abilities.\",\"Description_6\":\"In addition to being an extremely powerful ninja, Itachi had equally impressive intelligence, and was shown to be very wise. He was exceedingly sharp and observant to any situation at hand, as he was rarely surprised or caught off guard. He also displayed great intuition, as he was almost never deceived and even then almost instantly realized the truth. Despite his status as a wanted criminal, and having murdered a significant portion of his family, Itachi took no enjoyment in violence or combat, instead preferring to avoid battle or, if this was not possible, end it as quickly as he could.\",\"Description_7\":\"Itachi\\u0027s only initial interest was in Akatsuki\\u0027s goals, and his only loyalties appeared to be to the organization and its members, seeming to put the organization\\u0027s success and secrecy before everything else. As such, Itachi got along with his partner, Kisame, much better than most other Akatsuki members did with their own partners. Kisame appeared to have a deep loyalty to Itachi, immediately doing as he instructed and constantly looking out for his well-being. Itachi treated all of his fellow Akatsuki members to this same, more respectful personality, although his courtesy was rarely returned by the other members.\",\"Description_8\":\"Despite his status as an infamous shinobi, his appearance was not the most intimidating, apart from the intensity of his eyes. While living in Konoha, he would regularly have a gentle and caring look in his eyes, especially directed towards his younger brother. After joining Akatsuki, he would regularly have a stern look to them. He was a fairly tall shinobi, whose basic appearance was very much like the rest of his clan.\",\"Description_9\":\"He, like all members of his clan, possessed dark grey eyes, and also had black hair that hung near his cheeks to frame his face. He also had the addition of a long ponytail in the back of his hair (which he obscured with his Akatsuki cloak after joining the organization). Being brothers, Itachi and Sasuke had a similar appearance, but with subtle differences. Itachi\\u0027s hair color appeared slightly duller and with a softer flow to it, without the spiky style at the back. His skin was also slightly darker. Itachi\\u0027s most distinguishing characteristics were the long pronounced creases under his eyes.\",\"Description_10\":\"When he lived in Konoha, his casual clothes would consist of a black shirt with a large Uchiha clan symbol on the back of it, and black pants with a weapons pouch strapped to them. When on duty, he would wear the traditional ANBU uniform, although he was never shown wearing a mask. As a member of Akatsuki, he wore the traditional Akatsuki cloak, and usually kept the center of it buttoned down. After his cloak was incinerated by Sasuke\\u0027s Kirin during their fight in Part II, it was revealed that he still wore his casual clothes underneath it. Like almost all members of Akatsuki, he wore the headband of his home village, Konoha, with a line gouged through it, to symbolize his broken ties with the village\",\"Abilities\":\"\",\"Description_11\":\"Since a young age, Itachi\\u0027s intellect and talent showed their brilliance in everything he did, as even his teachers said his progress hardly required any help. In the few battles he had been seen in since the start of the series, Itachi was shown to be an incredibly powerful ninja, and easily one of the strongest in the Naruto series, as demonstrated by his ability to easily defeat Deidara, Sasuke, Kakashi Hatake, Kurenai Yuhi and Orochimaru (twice), who themselves are considered amongst the strongest ninjas in Naruto. Being a pacifist, Itachi did not actively take part in battle, typically only acting in self-defense.\",\"Sharingan\":\"\",\"Being of the Uchiha Clan, and as noted by Kakashi, Itachi was a true successor of the Sharingan Eye. From a stationary position, he would study an opponent\\u0027s movements with his Sharingan and respond accordingly, often with a genjutsu. He could cast a genjutsu by merely pointing at or looking at someone, and could similarly turn an opponent\\u0027s genjutsu against them with Demonic Illusion\":\"Mirror Heaven and Earth Change. Itachi had trained so much with his eyes that he had reached the stage where he could have his Sharingan activated the entire time, with minimal drain on his chakra levels.\",\"Mangekyo Sharingan\":\"\",\"Description_12\":\"Itachi possessed the Mangekyo Sharingan, which increased his already great power, and enabled him to use his most powerful techniques. With his left eye, he could use Tsukuyomi, a genjutsu that traps an opponent\\u0027s mind in an illusionary world, torturing them for what seems like days in a matter of seconds.With his right eye he could use Amaterasu, a ninjutsu which allowed him to create a black flame that he could direct by moving his eye to burn through seemingly anything in its path, including fire itself. His final technique was Susanoo, a technique that manifested itself as a spectral being, labelled as the \\u0022Raging God of Battle\\u0022 in the databook. It wielded the Totsuka Sword, an ethereal sword with the ability to seal anything it pierces into the gourd that serves as its hilt, and Yata\\u0027s Mirror, a shield that can reflect any attack. Zetsu, a fellow Akatsuki member, stated that Itachi\\u0027s mastery of the Sharingan, combined with the legendary weapons of Susanoo, made him invincible.\",\"(Source\":\"Naruto.com, Naruto Wikia)\"}','{\"Age\": \"17-18 (I); 21 (II)\", \"From\": \"Konohagakure (Leaf)\", \"Rank\": \"S-class Missing-Nin\", \"Ring\": \"Shu (Red)\", \"Hobby\": \"Visiting traditional Japanese cafés\", \"Height\": \"175 cm (I); 178 cm (II)\", \"Weight\": \"57 kg (I); 58 kg (II)\", \"(Source\": \"Naruto.com, Naruto Wikia)\", \"Partner\": \"Hoshigaki Kisame\", \"Birthday\": \"June 9th (Gemini)\", \"Abilities\": \"\", \"Sharingan\": \"\", \"Background\": \"\", \"Blood Type\": \"AB\", \"Affiliation\": \"Akatsuki\", \"Description\": \"Itachi Uchiha is a missing-nin from Konohagakure, and a prominent member of Akatsuki, partnered with Kisame Hoshigaki. He is Sasuke Uchiha\'s older brother.\", \"Nature Type\": \"Fire and Water\", \"Personality\": \"\", \"Famous Quote\": \"Foolish little brother, if you wish to kill me, hate me, detest me, and survive in an unsightly way. Run, run and cling to life.\", \"Description_2\": \"Itachi is relatively popular among many fans of Naruto, often having ranked in the top ten in Shonen Jump magazine\'s popularity polls since his introduction. He was first ranked in the third character popularity poll ranked in 11th place. He was ranked 9th place during the fourth popularity poll, and 6th place in the fifth popularity poll. During the sixth popularity poll, he again was ranked in 11th place. In the last poll, he was ranked in 5th place.\", \"Description_3\": \"Itachi was born into the Uchiha clan and was praised by all as the best of his generation - a genius above all others. Even by the standards of the battle-adept Uchiha clan, Itachi\'s prowess far outshined all others. However, not even his family, friends, or teachers could understand him. When he was only 4, Itachi had already witnessed countless lives lost due to the Third Great Shinobi World War, which emotionally traumatized him and turned him into a pacifist. At age 7, he graduated from the Ninja Academy at the top of his class after only one year, mastered the Sharingan at age 8, passed the Chunin Exams at age 10, and became ANBU Captain at age 13. According to Madara Uchiha, Itachi also had a lover, whom he killed during the Uchiha clan massacre.\", \"Description_4\": \"He was praised highly by his father, who saw the family\'s future in Itachi, hence neglecting his other son - Itachi\'s younger brother, Sasuke. However, during this time Itachi showed great affection towards his little brother, Sasuke, and even encouraged his father to come to the Academy when Sasuke was enrolled, something their dad had otherwise forgotten, by saying that he would not go to an important mission, that would establish Itachi a place in the ANBU ranks, otherwise.\", \"Description_5\": \"As a member of Akatsuki, he possessed incredible self-control of his emotions. He constantly displayed an emotionless personality. He only showed surprise when opponents proved more powerful or skilled than he had expected, and even then he didn\'t lose his composure. He did not possess any arrogance, and fully justified any statements he made about his power, even complimenting his opponents at times on their abilities.\", \"Description_6\": \"In addition to being an extremely powerful ninja, Itachi had equally impressive intelligence, and was shown to be very wise. He was exceedingly sharp and observant to any situation at hand, as he was rarely surprised or caught off guard. He also displayed great intuition, as he was almost never deceived and even then almost instantly realized the truth. Despite his status as a wanted criminal, and having murdered a significant portion of his family, Itachi took no enjoyment in violence or combat, instead preferring to avoid battle or, if this was not possible, end it as quickly as he could.\", \"Description_7\": \"Itachi\'s only initial interest was in Akatsuki\'s goals, and his only loyalties appeared to be to the organization and its members, seeming to put the organization\'s success and secrecy before everything else. As such, Itachi got along with his partner, Kisame, much better than most other Akatsuki members did with their own partners. Kisame appeared to have a deep loyalty to Itachi, immediately doing as he instructed and constantly looking out for his well-being. Itachi treated all of his fellow Akatsuki members to this same, more respectful personality, although his courtesy was rarely returned by the other members.\", \"Description_8\": \"Despite his status as an infamous shinobi, his appearance was not the most intimidating, apart from the intensity of his eyes. While living in Konoha, he would regularly have a gentle and caring look in his eyes, especially directed towards his younger brother. After joining Akatsuki, he would regularly have a stern look to them. He was a fairly tall shinobi, whose basic appearance was very much like the rest of his clan.\", \"Description_9\": \"He, like all members of his clan, possessed dark grey eyes, and also had black hair that hung near his cheeks to frame his face. He also had the addition of a long ponytail in the back of his hair (which he obscured with his Akatsuki cloak after joining the organization). Being brothers, Itachi and Sasuke had a similar appearance, but with subtle differences. Itachi\'s hair color appeared slightly duller and with a softer flow to it, without the spiky style at the back. His skin was also slightly darker. Itachi\'s most distinguishing characteristics were the long pronounced creases under his eyes.\", \"Description_10\": \"When he lived in Konoha, his casual clothes would consist of a black shirt with a large Uchiha clan symbol on the back of it, and black pants with a weapons pouch strapped to them. When on duty, he would wear the traditional ANBU uniform, although he was never shown wearing a mask. As a member of Akatsuki, he wore the traditional Akatsuki cloak, and usually kept the center of it buttoned down. After his cloak was incinerated by Sasuke\'s Kirin during their fight in Part II, it was revealed that he still wore his casual clothes underneath it. Like almost all members of Akatsuki, he wore the headband of his home village, Konoha, with a line gouged through it, to symbolize his broken ties with the village\", \"Description_11\": \"Since a young age, Itachi\'s intellect and talent showed their brilliance in everything he did, as even his teachers said his progress hardly required any help. In the few battles he had been seen in since the start of the series, Itachi was shown to be an incredibly powerful ninja, and easily one of the strongest in the Naruto series, as demonstrated by his ability to easily defeat Deidara, Sasuke, Kakashi Hatake, Kurenai Yuhi and Orochimaru (twice), who themselves are considered amongst the strongest ninjas in Naruto. Being a pacifist, Itachi did not actively take part in battle, typically only acting in self-defense.\", \"Description_12\": \"Itachi possessed the Mangekyo Sharingan, which increased his already great power, and enabled him to use his most powerful techniques. With his left eye, he could use Tsukuyomi, a genjutsu that traps an opponent\'s mind in an illusionary world, torturing them for what seems like days in a matter of seconds.With his right eye he could use Amaterasu, a ninjutsu which allowed him to create a black flame that he could direct by moving his eye to burn through seemingly anything in its path, including fire itself. His final technique was Susanoo, a technique that manifested itself as a spectral being, labelled as the \\\"Raging God of Battle\\\" in the databook. It wielded the Totsuka Sword, an ethereal sword with the ability to seal anything it pierces into the gourd that serves as its hilt, and Yata\'s Mirror, a shield that can reflect any attack. Zetsu, a fellow Akatsuki member, stated that Itachi\'s mastery of the Sharingan, combined with the legendary weapons of Susanoo, made him invincible.\", \"Favorite Foods\": \"Rice balls (kelp), cabbage, Dango\", \"Finger Position\": \"Right Ring\", \"Mangekyo Sharingan\": \"\", \"Registered Ninja #\": \"012110\", \"Least Favorite Foods\": \"Steak\", \"Assignments Completed\": \"53 D-Rank, 152 C-Rank, 134 B-Rank, 0 A-Rank, 1 S-Rank\", \"First Anime Appearance\": \"Ep. 80\", \"First Manga Appearance\": \"Ch. 139\", \"Being of the Uchiha Clan, and as noted by Kakashi, Itachi was a true successor of the Sharingan Eye. From a stationary position, he would study an opponent\'s movements with his Sharingan and respond accordingly, often with a genjutsu. He could cast a genjutsu by merely pointing at or looking at someone, and could similarly turn an opponent\'s genjutsu against them with Demonic Illusion\": \"Mirror Heaven and Earth Change. Itachi had trained so much with his eyes that he had reached the stage where he could have his Sharingan activated the entire time, with minimal drain on his chakra levels.\"}'),(381,139848,'Uchiha, Izumi','{\"Description\":\"Izumi Uchiha was a kunoichi from Konohagakure and a member of the Uchiha Clan. She was a friend of Itachi Uchiha since their childhood and deeply cared about him, being so close to him as to be seen as his lover.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Izumi Uchiha was a kunoichi from Konohagakure and a member of the Uchiha Clan. She was a friend of Itachi Uchiha since their childhood and deeply cared about him, being so close to him as to be seen as his lover.\"}'),(382,53901,'Uchiha, Madara','{\"Birthday\":\"December 24\",\"Classification\":\"Missing-nin\",\"Occupation\":\"Co-founder of Konohagakure, Leader of the Uchiha clan\",\"Affiliation\":\"Konohagakure\",\"Clan\":\"Uchiha clan\",\"Manga Debut\":\"Chapter #370\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #130\",\"Description\":\"Madara Uchiha (\\u3046\\u3061\\u306F\\u30DE\\u30C0\\u30E9, Uchiha Madara) was a legendary ninja who led the Uchiha clan prior to and after the formation of Konohagakure.\",\"Description_2\":\"Before the era of ninja villages, Madara and his younger brother, Izuna, were considered the most gifted members of the Uchiha clan. Even by his clan\\u0027s standards, Madara\\u0027s chakra was especially strong. He grew up constantly competing and training with Izuna and in their efforts to surpass each other, each gained their own Mangeky\\u014D Sharingan. With the power of the Mangeky\\u014D the two brothers took control of the clan, with Madara as its leader. Under his leadership, the clan conquered all they came across. Because of the never-ending series of battles of the time, Madara eventually began to suffer from overuse of the Mangeky\\u014D Sharingan, leaving him blind. In order to regain his sight he took Izuna\\u0027s eyes for himself, granting him an \\u0022eternal\\u0022 Mangeky\\u014D Sharingan with which he led the Uchiha clan to prosperity.\",\"Description_3\":\"Over the years, the Uchiha had constantly fought with the equally powerful Senju clan and as such, Madara had an undying rivalry with Hashirama Senju, the leader of the Senju clan. To bring an end to the constant fighting, Hashirama approached the Uchiha with an offer of peace. Although Madara never wanted peace with the Senju, the rest of the Uchiha wished to end the fighting, and Madara had no choice but to accept. The Senju, the Uchiha, and all the clans they had conquered came together to form the village of Konohagakure.\",\"Description_4\":\"Some time later, the villagers of Konoha selected Hashirama as the village\\u0027s first Hokage much to Madara\\u0027s dismay. Madara feared that Hashirama would oppress the Uchiha, and tried to rally support for challenging his leadership. Rather than help him, the Uchiha turned their backs on him, believing he only desired to rekindle the flames of war.\",\"Description_5\":\"Soon after being rejected the position of Hokage and being abandoned by his clan, Madara left the village, and sought out Nine-Tails. He later returned in order to challenge Hashirama in battle. They fought at the site that would someday be called the Valley of the End, where Madara was defeated, despite having Nine-Tails at his side. Control of Nine-Tails was ultimately taken from him and Madara died.\"}','{\"Clan\": \"Uchiha clan\", \"Birthday\": \"December 24\", \"Occupation\": \"Co-founder of Konohagakure, Leader of the Uchiha clan\", \"Affiliation\": \"Konohagakure\", \"Anime Debut\": \"Naruto Shippūden Episode #130\", \"Description\": \"Madara Uchiha (うちはマダラ, Uchiha Madara) was a legendary ninja who led the Uchiha clan prior to and after the formation of Konohagakure.\", \"Manga Debut\": \"Chapter #370\", \"Description_2\": \"Before the era of ninja villages, Madara and his younger brother, Izuna, were considered the most gifted members of the Uchiha clan. Even by his clan\'s standards, Madara\'s chakra was especially strong. He grew up constantly competing and training with Izuna and in their efforts to surpass each other, each gained their own Mangekyō Sharingan. With the power of the Mangekyō the two brothers took control of the clan, with Madara as its leader. Under his leadership, the clan conquered all they came across. Because of the never-ending series of battles of the time, Madara eventually began to suffer from overuse of the Mangekyō Sharingan, leaving him blind. In order to regain his sight he took Izuna\'s eyes for himself, granting him an \\\"eternal\\\" Mangekyō Sharingan with which he led the Uchiha clan to prosperity.\", \"Description_3\": \"Over the years, the Uchiha had constantly fought with the equally powerful Senju clan and as such, Madara had an undying rivalry with Hashirama Senju, the leader of the Senju clan. To bring an end to the constant fighting, Hashirama approached the Uchiha with an offer of peace. Although Madara never wanted peace with the Senju, the rest of the Uchiha wished to end the fighting, and Madara had no choice but to accept. The Senju, the Uchiha, and all the clans they had conquered came together to form the village of Konohagakure.\", \"Description_4\": \"Some time later, the villagers of Konoha selected Hashirama as the village\'s first Hokage much to Madara\'s dismay. Madara feared that Hashirama would oppress the Uchiha, and tried to rally support for challenging his leadership. Rather than help him, the Uchiha turned their backs on him, believing he only desired to rekindle the flames of war.\", \"Description_5\": \"Soon after being rejected the position of Hokage and being abandoned by his clan, Madara left the village, and sought out Nine-Tails. He later returned in order to challenge Hashirama in battle. They fought at the site that would someday be called the Valley of the End, where Madara was defeated, despite having Nine-Tails at his side. Control of Nine-Tails was ultimately taken from him and Madara died.\", \"Classification\": \"Missing-nin\"}'),(383,2910,'Uchiha, Obito','{\"Description\":\"Obito Uchiha was teammates with Kakashi Hatake and Rin under the Fourth Hokage. Obito was frequently late for missions due to the random good deeds he would carry out, which greatly irritated Kakashi. He also seemed to have had a crush on Rin. When Rin is kidnapped during the Kakashi Gaiden arc, Kakashi, the current team leader, insisted that they continue the mission instead of saving her. Citing that those who do not save their teammates are no better than trash, Obito refused and eventually managed to persuade Kakashi to join him. During their rescue effort, Kakashi lost his left eye as a result of an enemy ninja\\u0027s attack, and Obito awakened his Sharingan to save Kakashi and defeat the ninja. Once finding Rin, Obito again saved Kakashi by pushing him out of the way of a rock slide, though has his right side crushed in the process. Unable to escape with his teammates, Obito had Rin implant his remaining Sharingan eye in Kakashi\\u0027s damaged eye socket as a gift.\"}','{\"Description\": \"Obito Uchiha was teammates with Kakashi Hatake and Rin under the Fourth Hokage. Obito was frequently late for missions due to the random good deeds he would carry out, which greatly irritated Kakashi. He also seemed to have had a crush on Rin. When Rin is kidnapped during the Kakashi Gaiden arc, Kakashi, the current team leader, insisted that they continue the mission instead of saving her. Citing that those who do not save their teammates are no better than trash, Obito refused and eventually managed to persuade Kakashi to join him. During their rescue effort, Kakashi lost his left eye as a result of an enemy ninja\'s attack, and Obito awakened his Sharingan to save Kakashi and defeat the ninja. Once finding Rin, Obito again saved Kakashi by pushing him out of the way of a rock slide, though has his right side crushed in the process. Unable to escape with his teammates, Obito had Rin implant his remaining Sharingan eye in Kakashi\'s damaged eye socket as a gift.\"}'),(384,22889,'Uchiha, Tekka','{\"Description\":\"Tekka Uchiha (\\u3046\\u3061\\u306F\\u30C6\\u30C3\\u30AB, Uchiha Tekka) was a member of the Konoha Military Police. He questioned Itachi about the apparent suicide of Shisui Uchiha with Inabi Uchiha and Yashiro Uchiha. He was killed by Itachi along with the rest of the Uchiha clan.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Tekka Uchiha (うちはテッカ, Uchiha Tekka) was a member of the Konoha Military Police. He questioned Itachi about the apparent suicide of Shisui Uchiha with Inabi Uchiha and Yashiro Uchiha. He was killed by Itachi along with the rest of the Uchiha clan.\"}'),(385,98663,'Uchiha, Baru','{\"Description\":\"Baru Uchiha (\\u3046\\u3061\\u306F\\u30D0\\u30EB, Uchiha Baru) was a shinobi of the Uchiha clan.\",\"Description_2\":\"Born to the Uchiha clan, Baru was of its few members who were able to awaken the Sharingan in his youth, as well as his own Mangeky\\u014D Sharingan.\",\"Description_3\":\"During the continuous struggle between shinobi clans, Baru and his clansmen faced an opposing force who quickly wiped out Rai Uchiha\\u0027s comrades with a trap. However, Rai nullified the outcome by sacrificing one of his eyes in order to use Izanagi. After the enemies were defeated, Baru challenged Rai for the leadership of their group and killed him using his own Izanagi. However, he was killed by his other clansmen when he was just celebrating his victory.\",\"Anime Debut\":\"Naruto Shippuuden Episode #338\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #338\", \"Description\": \"Baru Uchiha (うちはバル, Uchiha Baru) was a shinobi of the Uchiha clan.\", \"Description_2\": \"Born to the Uchiha clan, Baru was of its few members who were able to awaken the Sharingan in his youth, as well as his own Mangekyō Sharingan.\", \"Description_3\": \"During the continuous struggle between shinobi clans, Baru and his clansmen faced an opposing force who quickly wiped out Rai Uchiha\'s comrades with a trap. However, Rai nullified the outcome by sacrificing one of his eyes in order to use Izanagi. After the enemies were defeated, Baru challenged Rai for the leadership of their group and killed him using his own Izanagi. However, he was killed by his other clansmen when he was just celebrating his victory.\"}'),(386,98661,'Uchiha, Rai','{\"Description\":\"Rai Uchiha (\\u3046\\u3061\\u306F\\u30E9\\u30A4, Uchiha Rai) was a shinobi of the Uchiha clan.\",\"Description_2\":\"Born to the Uchiha clan, Rai was able to awaken the Sharingan in his youth, as well as his own Mangeky\\u014D Sharingan.\",\"Description_3\":\"During the continuous struggle between shinobi clans, Rai and his clansmen faced an opposing force who quickly wiped out Rai\\u0027s comrades with a trap. However, Rai nullified the outcome by sacrificing his left eye in order to use Izanagi. With the enemies slaughtered, he boldly declared that the Uchiha clan was invincible due to the powerful d\\u014Djutsu.\",\"Description_4\":\"His prowess in using the forbidden technique made him the leader of the small group of his shinobi until he was challenged by Baru Uchiha, who was able to kill Rai by using Izanagi himself.\",\"Anime Debut\":\"Naruto Shippuuden Episode #338\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #338\", \"Description\": \"Rai Uchiha (うちはライ, Uchiha Rai) was a shinobi of the Uchiha clan.\", \"Description_2\": \"Born to the Uchiha clan, Rai was able to awaken the Sharingan in his youth, as well as his own Mangekyō Sharingan.\", \"Description_3\": \"During the continuous struggle between shinobi clans, Rai and his clansmen faced an opposing force who quickly wiped out Rai\'s comrades with a trap. However, Rai nullified the outcome by sacrificing his left eye in order to use Izanagi. With the enemies slaughtered, he boldly declared that the Uchiha clan was invincible due to the powerful dōjutsu.\", \"Description_4\": \"His prowess in using the forbidden technique made him the leader of the small group of his shinobi until he was challenged by Baru Uchiha, who was able to kill Rai by using Izanagi himself.\"}'),(387,21122,'Uchiha, Mikoto','{\"Birthday\":\"June 1\",\"Description\":\"Mikoto Uchiha was the mother of Sasuke and Itachi. She was also Fugaku\\u0027s wife.\",\"Description_2\":\"While she was alive, she seemed to like Sasuke better where her husband seemed to prefer Itachi. She was a very good mother, seeing as how Sasuke was able to talk to her better than his father. At one point, in order to cheer Sasuke up, she says that when she and Fugaku are alone Sasuke is all he talks about. Although she was Itachi\\u0027s mother, she did have some suspicion about Itachi and knew that something was up. She was found dead with her husband during the Uchiha Clan Massacre, killed by Itachi.\"}','{\"Birthday\": \"June 1\", \"Description\": \"Mikoto Uchiha was the mother of Sasuke and Itachi. She was also Fugaku\'s wife.\", \"Description_2\": \"While she was alive, she seemed to like Sasuke better where her husband seemed to prefer Itachi. She was a very good mother, seeing as how Sasuke was able to talk to her better than his father. At one point, in order to cheer Sasuke up, she says that when she and Fugaku are alone Sasuke is all he talks about. Although she was Itachi\'s mother, she did have some suspicion about Itachi and knew that something was up. She was found dead with her husband during the Uchiha Clan Massacre, killed by Itachi.\"}'),(388,16973,'Uchiha, Fugaku','{\"Description\":\"Fugaku was the leader of the Konoha Military Police Force, the father of Itachi and Sasuke Uchiha, and leader of the Uchiha clan. His wife\\u0027s name was Mikoto Uchiha.\",\"Description_2\":\"As leader of the Uchiha, Fugaku was focused on the clan\\u0027s interest and welfare. His son, Sasuke, saw him as a stern and uncaring man (though his wife revealed he cared deeply for his youngest child) while he was seen as a father figure to the rest of the clan. As Itachi was his successor as head of the clan, Fugaku spent much of his time focusing on the development of his eldest and little time with his youngest. Sasuke trained constantly in order to get his father\\u0027s attention and approval. Near the end of his life, Fugaku had switched his attention to Sasuke, having lost hope in a wayward Itachi. He is only impressed by great feats and rarely praises anyone, having high expectations. Fugaku is very serious, hardly smiling most of the time.\"}','{\"Description\": \"Fugaku was the leader of the Konoha Military Police Force, the father of Itachi and Sasuke Uchiha, and leader of the Uchiha clan. His wife\'s name was Mikoto Uchiha.\", \"Description_2\": \"As leader of the Uchiha, Fugaku was focused on the clan\'s interest and welfare. His son, Sasuke, saw him as a stern and uncaring man (though his wife revealed he cared deeply for his youngest child) while he was seen as a father figure to the rest of the clan. As Itachi was his successor as head of the clan, Fugaku spent much of his time focusing on the development of his eldest and little time with his youngest. Sasuke trained constantly in order to get his father\'s attention and approval. Near the end of his life, Fugaku had switched his attention to Sasuke, having lost hope in a wayward Itachi. He is only impressed by great feats and rarely praises anyone, having high expectations. Fugaku is very serious, hardly smiling most of the time.\"}'),(389,22888,'Uchiha, Yakumi','{\"Description\":\"Yakumi Uchiha was a member of the Uchiha clan during the years preceding the Uchiha Clan Massacre.\",\"Description_2\":\"As a member of the Konoha Military Police, he assisted Fugaku Uchiha. He felt a strong affection toward the Uchiha clan and was fiercely loyal to it.\",\"(Source\":\"Narutopedia)\",\"Description_3\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Yakumi Uchiha was a member of the Uchiha clan during the years preceding the Uchiha Clan Massacre.\", \"Description_2\": \"As a member of the Konoha Military Police, he assisted Fugaku Uchiha. He felt a strong affection toward the Uchiha clan and was fiercely loyal to it.\", \"Description_3\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(390,16406,'Uchiha, Izuna','{\"Description\":\"Izuna Uchiha is Madara Uchiha\\u0027s younger brother. He was alive about 70 years before the start of the series, even before the founding of Konoha. Standing at the top of the Uchiha clan with his brother, Izuna was one of the first to obtain the elusive \\u0022Mangekyou Sharingan\\u0022 (along with Madara). However, Madara went blind due to the use of his. To alleviate this, Izuna gave up his eyes so that Madara would obtain a new, \\u0022permanent\\u0022 Mangekyou.\"}','{\"Description\": \"Izuna Uchiha is Madara Uchiha\'s younger brother. He was alive about 70 years before the start of the series, even before the founding of Konoha. Standing at the top of the Uchiha clan with his brother, Izuna was one of the first to obtain the elusive \\\"Mangekyou Sharingan\\\" (along with Madara). However, Madara went blind due to the use of his. To alleviate this, Izuna gave up his eyes so that Madara would obtain a new, \\\"permanent\\\" Mangekyou.\"}'),(391,94785,'Uchiha, Naka','{\"Description\":\"Naka Uchiha was a shinobi of Konohagakure\\u0027s Uchiha clan.\",\"Description_2\":\"Naka was a close comrade of Naori Uchiha. He came to develop a Mangeky\\u014D Sharingan and he became obsessed with the Izanagi. Naori then used Izanami on him to try and make him accept the truth and see reality and he eventually accepted this and broke the loop caused by the Izanami.\",\"Description_3\":\"Naka was at least skilled with kenjutsu considering he had a sword. He was able to awaken his clan\\u0027s d\\u014Djutsu kekkei genkai, the Sharingan. He was also able to activate the Mangeky\\u014D Sharingan. He was able to use the Izanagi technique, which he apparently used obsessively.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Naka Uchiha was a shinobi of Konohagakure\'s Uchiha clan.\", \"Description_2\": \"Naka was a close comrade of Naori Uchiha. He came to develop a Mangekyō Sharingan and he became obsessed with the Izanagi. Naori then used Izanami on him to try and make him accept the truth and see reality and he eventually accepted this and broke the loop caused by the Izanami.\", \"Description_3\": \"Naka was at least skilled with kenjutsu considering he had a sword. He was able to awaken his clan\'s dōjutsu kekkei genkai, the Sharingan. He was also able to activate the Mangekyō Sharingan. He was able to use the Izanagi technique, which he apparently used obsessively.\"}'),(392,94735,'Uchiha, Naori','{\"Description\":\"Naori Uchiha was a kunoichi of Konohagakure\\u0027s famed Uchiha clan.\",\"Description_2\":\"A close comrade of Naori was able to use Izanagi and apparently became obsessed with it. She was determined to save him from it so he would accept his fate and reality. A user of the Izanami, Naori activated the technique on her comrade and in the end, he ultimately gave up and finally accepted his true fate, thus being freed from Izanami\\u0027s loop.\",\"Description_3\":\"Naori had long wavy purple hair and her bangs hanged over her Konohagakure forehead protector. She also carried a sword.\",\"Description_4\":\"As a member of the Uchiha clan, Naori wielded the Sharingan and had even awakened the Mangekyou Sharingan. She was also apparently able to use one of the clan\\u0027s strongest techniques, the Izanami.\",\"Description_5\":\"She is the one of the two only shown female users of the Sharingan, and the only shown female user of the Mangekyou Sharingan.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Naori Uchiha was a kunoichi of Konohagakure\'s famed Uchiha clan.\", \"Description_2\": \"A close comrade of Naori was able to use Izanagi and apparently became obsessed with it. She was determined to save him from it so he would accept his fate and reality. A user of the Izanami, Naori activated the technique on her comrade and in the end, he ultimately gave up and finally accepted his true fate, thus being freed from Izanami\'s loop.\", \"Description_3\": \"Naori had long wavy purple hair and her bangs hanged over her Konohagakure forehead protector. She also carried a sword.\", \"Description_4\": \"As a member of the Uchiha clan, Naori wielded the Sharingan and had even awakened the Mangekyou Sharingan. She was also apparently able to use one of the clan\'s strongest techniques, the Izanami.\", \"Description_5\": \"She is the one of the two only shown female users of the Sharingan, and the only shown female user of the Mangekyou Sharingan.\"}'),(393,63189,'Uchiha, Kagami','{}','{}'),(394,41366,'Ukon','{\"Birthdate\":\"June 20\",\"Description\":\"Ukon is the twin brother of Sakon. He usually resides in Sakon\\u0027s body (where he\\u0027s said to be sleeping), with only his head protruding on Sakon\\u0027s back. Ukon, unlike his brother, is very impatient and prefers to finish a fight quickly.\"}','{\"Birthdate\": \"June 20\", \"Description\": \"Ukon is the twin brother of Sakon. He usually resides in Sakon\'s body (where he\'s said to be sleeping), with only his head protruding on Sakon\'s back. Ukon, unlike his brother, is very impatient and prefers to finish a fight quickly.\"}'),(395,2011,'Umino, Iruka','{\"Age\":\"23 (Part I), 26 (Part II)\",\"Birthday\":\"May 26\",\"Height\":\"178 cm\",\"Weight\":\"66.2 kg\",\"Blood Type\":\"A\",\"Affiliation\":\"Konohagakure\",\"Current Rank\":\"Chuunin\",\"Occupation\":\"Academy Instructor\",\"Description\":\"Iruka Umino is an instructor at the Ninja Academy, characterized by the distinctive scar across his face that he has had since childhood. The name \\u0022Umino Iruka\\u0022 can be taken as \\u0022umi no iruka\\u0022 (\\u0022sea dolphin\\u0022).\",\"Description_2\":\"Twelve to thirteen years ago, the Nine-Tailed Demon Fox attacked Konoha, killing many people. Iruka\\u0027s parents were still out fighting the Fox and were killed. Iruka was dragged back for protection by an unknown ninja but wanted to stay where he was. After it was over, everyone in the Ninja Academy made fun of him and made him feel just like Naruto Uzumaki. He was always near the K.I.A. (Killed in Action) stone monument where his parents were listed and always cried. The Third Hokage would watch him and tried to cheer Iruka up. Mizuki was a close friend of Iruka back then and usually made him feel better, but he was just acting to get the Hokage\\u0027s approval.\",\"Description_3\":\"Little is known about Iruka\\u0027s abilities, but he is clearly proficient in the basic ninjutsu and genjutsu, seen when he disguises himself as an enemy ninja and menaces Team 7 as a pretest for the Chunin Exam. The anime filler episodes show Iruka using Sealed Bomb Square Release (\\u65B9\\u7206\\u6CD5\\u9663, F\\u016Bbaku Hojin), which consists of setting an array of exploding tags and, once the target has entered, setting the tags to detonate if the target moves. Because this only applies to the target, meaning others can freely enter the array without harm, it is possible that Iruka is skilled in this area.\"}','{\"Age\": \"23 (Part I), 26 (Part II)\", \"Height\": \"178 cm\", \"Weight\": \"66.2 kg\", \"Birthday\": \"May 26\", \"Blood Type\": \"A\", \"Occupation\": \"Academy Instructor\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Iruka Umino is an instructor at the Ninja Academy, characterized by the distinctive scar across his face that he has had since childhood. The name \\\"Umino Iruka\\\" can be taken as \\\"umi no iruka\\\" (\\\"sea dolphin\\\").\", \"Current Rank\": \"Chuunin\", \"Description_2\": \"Twelve to thirteen years ago, the Nine-Tailed Demon Fox attacked Konoha, killing many people. Iruka\'s parents were still out fighting the Fox and were killed. Iruka was dragged back for protection by an unknown ninja but wanted to stay where he was. After it was over, everyone in the Ninja Academy made fun of him and made him feel just like Naruto Uzumaki. He was always near the K.I.A. (Killed in Action) stone monument where his parents were listed and always cried. The Third Hokage would watch him and tried to cheer Iruka up. Mizuki was a close friend of Iruka back then and usually made him feel better, but he was just acting to get the Hokage\'s approval.\", \"Description_3\": \"Little is known about Iruka\'s abilities, but he is clearly proficient in the basic ninjutsu and genjutsu, seen when he disguises himself as an enemy ninja and menaces Team 7 as a pretest for the Chunin Exam. The anime filler episodes show Iruka using Sealed Bomb Square Release (方爆法陣, Fūbaku Hojin), which consists of setting an array of exploding tags and, once the target has entered, setting the tags to detonate if the target moves. Because this only applies to the target, meaning others can freely enter the array without harm, it is possible that Iruka is skilled in this area.\"}'),(396,56697,'Umino, Ikkaku','{\"Age\":\"45\",\"Status\":\"Deceased\",\"Affiliation\":\"Konohagakure\",\"Ninja Rank\":\"J\\u014Dnin\",\"Family\":\"Iruka Umino (son), Kohari Umino (wife)\",\"Description\":\"Ikkaku Umino was a shinobi from Konohagakure and father of Iruka.\",\"Description_2\":\"When Iruka\\u0027s mother was injured while protecting him during the Nine-Tails\\u0027 Attack on Konoha, he offered to look after her. His father said he would look after her since it was the parent\\u0027s job to protect their child, not the other way around. He instructed Iruka to flee. Iruka did not listen, forcing other Konoha ninja to drag him away from the battle. His parents were killed by the Nine-Tails. Their names had been added to Konoha\\u0027s Memorial Stone when they died.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"45\", \"Family\": \"Iruka Umino (son), Kohari Umino (wife)\", \"Status\": \"Deceased\", \"(Source\": \"Narutopedia)\", \"Ninja Rank\": \"Jōnin\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Ikkaku Umino was a shinobi from Konohagakure and father of Iruka.\", \"Description_2\": \"When Iruka\'s mother was injured while protecting him during the Nine-Tails\' Attack on Konoha, he offered to look after her. His father said he would look after her since it was the parent\'s job to protect their child, not the other way around. He instructed Iruka to flee. Iruka did not listen, forcing other Konoha ninja to drag him away from the battle. His parents were killed by the Nine-Tails. Their names had been added to Konoha\'s Memorial Stone when they died.\"}'),(397,56699,'Umino, Kohari','{\"Age\":\"45\",\"Status\":\"Deceased\",\"Affiliation\":\"Konohagakure\",\"Ninja Rank\":\"J\\u014Dnin\",\"Family\":\"Iruka Umino (son), Ikkaku Umino (husband)\",\"Description\":\"Kohari Umino was a kunoichi from Konohagakure and mother of Iruka.\",\"Description_2\":\"During the Nine-Tails\\u0027 attack, she received a severe injury to her back, which her son Iruka noticed, causing him to wish to stay and protect her. Despite her injuries, she was more concerned about Iruka\\u0027s welfare. She and her husband\\u0027s names were added to Konoha Memorial Stone after they died.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"45\", \"Family\": \"Iruka Umino (son), Ikkaku Umino (husband)\", \"Status\": \"Deceased\", \"(Source\": \"Narutopedia)\", \"Ninja Rank\": \"Jōnin\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Kohari Umino was a kunoichi from Konohagakure and mother of Iruka.\", \"Description_2\": \"During the Nine-Tails\' attack, she received a severe injury to her back, which her son Iruka noticed, causing him to wish to stay and protect her. Despite her injuries, she was more concerned about Iruka\'s welfare. She and her husband\'s names were added to Konoha Memorial Stone after they died.\"}'),(398,77441,'Urakaku','{\"Description\":\"Urakaku (\\u30A6\\u30E9\\u30AB\\u30AF, Urakaku) is a samurai from the Land of Iron and one of Mifune\\u0027s right-hand-man alongside Okisuke.\",\"Manga Debut\":\"Chapter #456\",\"Anime Debut\":\"Naruto Shippuuden Episode #199\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #199\", \"Description\": \"Urakaku (ウラカク, Urakaku) is a samurai from the Land of Iron and one of Mifune\'s right-hand-man alongside Okisuke.\", \"Manga Debut\": \"Chapter #456\"}'),(399,96721,'Urushi','{\"Description\":\"Urushi is an orphaned child who lived in the Konoha Orphanage. He later became a shinobi of Konohagakure.\",\"Description_2\":\"At some point in time, Urushi along with some other children and Nonou from an orphanage, found a young boy under a tree wounded. After she had healed him, Urushi assisted the young boy in getting back to the orphanage with them. The next day, he stated that it was odd for someone to have no name, and as such the nun decided to call him Kabuto after the helmet Urushi put on Kabuto\\u0027s head.\",\"Description_3\":\"Over the years, as the orphans aided Nonou and Kabuto in treating some Konohagakure shinobi, Urushi protested having to help ninja, but understood that they needed the money and dutifully helped them.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Urushi is an orphaned child who lived in the Konoha Orphanage. He later became a shinobi of Konohagakure.\", \"Description_2\": \"At some point in time, Urushi along with some other children and Nonou from an orphanage, found a young boy under a tree wounded. After she had healed him, Urushi assisted the young boy in getting back to the orphanage with them. The next day, he stated that it was odd for someone to have no name, and as such the nun decided to call him Kabuto after the helmet Urushi put on Kabuto\'s head.\", \"Description_3\": \"Over the years, as the orphans aided Nonou and Kabuto in treating some Konohagakure shinobi, Urushi protested having to help ninja, but understood that they needed the money and dutifully helped them.\"}'),(400,22907,'Ushi','{\"Description\":\"Ushi (\\u30A6\\u30B7) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again and he did so vigilantly. Ushi is likely not his real name, but a codename.\",\"(Source\":\"Narutopedia)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Ushi (ウシ) was a member of the ANBU, working directly under the supervision of the Second Hokage. He was one of the ANBU ordered to watch the Uchiha clan to keep them from rebelling again and he did so vigilantly. Ushi is likely not his real name, but a codename.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(401,23219,'Utakata','{\"Birthday\":\"June 16\",\"Description\":\"Utakata was a shinobi from Kirigakure and the Jinchuuriki of the Six-Tailed Slug. The Six-Tails has been captured and sealed by Akatsuki, causing this Jinchuuriki\\u0027s death when the beast was extracted. Utakata fought using soap bubble ninjutsu from the Bubble-line of ninjutsu.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Birthday\": \"June 16\", \"Description\": \"Utakata was a shinobi from Kirigakure and the Jinchuuriki of the Six-Tailed Slug. The Six-Tails has been captured and sealed by Akatsuki, causing this Jinchuuriki\'s death when the beast was extracted. Utakata fought using soap bubble ninjutsu from the Bubble-line of ninjutsu.\"}'),(402,22649,'Utatane, Koharu','{\"Description\":\"Under the guidance of the Second Hokage, Tobirama Senju, Koharu and her teammates, Hiruzen and Homura, completed numerous missions and became close friends. When Hiruzen became the Third Hokage, Homura and Koharu became his councilors. With their years of experience and knowledge and their unending effort to make Konohagakure a better place, they eventually gained similar respect and social status as the Hokage himself.\",\"Description_2\":\"She holds the belief that the group is more important than any of its individual members. Because of this, she always tries to do what she thinks is the best for Konoha, even if it goes against the Hokage\\u0027s or her opinion. She is also quite demure, but does not let this stop her from voicing her opinion. In fact, despite this, she is one of the few people able to put the Fifth Hokage in her place when she oversteps her authority. Like Homura, she is more militant than the Hokage she served under have been, and sometimes leans more to Danzo\\u0027s point of view.\"}','{\"Description\": \"Under the guidance of the Second Hokage, Tobirama Senju, Koharu and her teammates, Hiruzen and Homura, completed numerous missions and became close friends. When Hiruzen became the Third Hokage, Homura and Koharu became his councilors. With their years of experience and knowledge and their unending effort to make Konohagakure a better place, they eventually gained similar respect and social status as the Hokage himself.\", \"Description_2\": \"She holds the belief that the group is more important than any of its individual members. Because of this, she always tries to do what she thinks is the best for Konoha, even if it goes against the Hokage\'s or her opinion. She is also quite demure, but does not let this stop her from voicing her opinion. In fact, despite this, she is one of the few people able to put the Fifth Hokage in her place when she oversteps her authority. Like Homura, she is more militant than the Hokage she served under have been, and sometimes leans more to Danzo\'s point of view.\"}'),(403,15045,'Uzuki, Yugao','{\"Name\":\"Yugao Uzuki\",\"Gender\":\"Female\",\"Age\":\"Part I: 22, Part II: 25\",\"Birthday\":\"November 3\",\"Height\":\"169,2 cm (5.551 ft)\",\"Weight\":\"50,5 kg (111.333 lb)\",\"Blood Type\":\"A\",\"Affiliation\":\"Konohagakure\",\"Occupation\":\"ANBU\"}','{\"Age\": \"Part I: 22, Part II: 25\", \"Name\": \"Yugao Uzuki\", \"Gender\": \"Female\", \"Height\": \"169,2 cm (5.551 ft)\", \"Weight\": \"50,5 kg (111.333 lb)\", \"Birthday\": \"November 3\", \"Blood Type\": \"A\", \"Occupation\": \"ANBU\", \"Affiliation\": \"Konohagakure\"}'),(404,56691,'Uzumaki, Mito','{\"Description\":\"Mito Uzumaki was a kunoichi who originated from Uzushiogakure\\u0027s Uzumaki clan and later married into Konohagakure\\u0027s Senju clan. She was also the first jinch\\u016Briki of Kurama the Nine-Tailed Demon Fox.\",\"Manga Debut\":\"Chapter #500\",\"Anime Debut\":\"Naruto Shippuuden Episode #247\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #247\", \"Description\": \"Mito Uzumaki was a kunoichi who originated from Uzushiogakure\'s Uzumaki clan and later married into Konohagakure\'s Senju clan. She was also the first jinchūriki of Kurama the Nine-Tailed Demon Fox.\", \"Manga Debut\": \"Chapter #500\"}'),(405,7302,'Uzumaki, Kushina','{\"Birthdate\":\"July 10\",\"Sign\":\"Cancer\",\"Gender\":\"Female\",\"Age\":\"Part II: 24\",\"Height\":\"Part II: 165 cm\",\"Weight\":\"Part II: 47 kg\",\"Blood type\":\"B\",\"Description\":\"Kushina Uzumaki  is a ninja of the former Land of the Whirlpool. She had a son, Naruto Uzumaki, with the Hokage of the time, Minato Namikaze. She is noted to have had a brash, tomboyish demeanor, long red hair, violet eyes, and as time passed, blossomed into a very beautiful woman. Despite Naruto\\u0027s close resemblance to his father, much of his personality and choice of ninjutsu are said to be similar to that of his mother\\u0027s.\",\"Description_2\":\"She is presumed to be dead, as she is described in past tense. Her face is shown in a couple slides as she is talking with Jiraiya and Minato Namikaze. In this part of the manga Jiraiya is lying on the ground while having flashbacks. In his flashbacks he is with Minato and Kushina as they are naming their unborn child \\u0022Naruto\\u0022.\"}','{\"Age\": \"Part II: 24\", \"Sign\": \"Cancer\", \"Gender\": \"Female\", \"Height\": \"Part II: 165 cm\", \"Weight\": \"Part II: 47 kg\", \"Birthdate\": \"July 10\", \"Blood type\": \"B\", \"Description\": \"Kushina Uzumaki  is a ninja of the former Land of the Whirlpool. She had a son, Naruto Uzumaki, with the Hokage of the time, Minato Namikaze. She is noted to have had a brash, tomboyish demeanor, long red hair, violet eyes, and as time passed, blossomed into a very beautiful woman. Despite Naruto\'s close resemblance to his father, much of his personality and choice of ninjutsu are said to be similar to that of his mother\'s.\", \"Description_2\": \"She is presumed to be dead, as she is described in past tense. Her face is shown in a couple slides as she is talking with Jiraiya and Minato Namikaze. In this part of the manga Jiraiya is lying on the ground while having flashbacks. In his flashbacks he is with Minato and Kushina as they are naming their unborn child \\\"Naruto\\\".\"}'),(406,17552,'Waraji','{\"Description\":\"Personal hired mercenary to Gat\\u014D.\"}','{\"Description\": \"Personal hired mercenary to Gatō.\"}'),(407,77443,'Watase','{\"Anime Debut\":\"Naruto Shippuuden Episode #281\",\"Description\":\"Watase (\\u30EF\\u30BF\\u30BB, Watase) is a genin-level shinobi from Konohagakure. Watase is a somewhat stubborn individual, seen from his wanting to participate in the Fourth Shinobi World War despite being too young. He is also very ambitious, and believed that connections no longer made an individual a hero, or Hokage-worthy but it was in fact, their contributions on the battlefield, citing Naruto as an example.\",\"Description_2\":\"Watase was present at the meeting called by Ebisu where he cursed the fact that he had not been born earlier so that he could be on the battlefield. Later when Konohamaru assembled all the genin in the village to get them to face the upcoming threat, Watase told him to stop playing Hokage. A fight ensued which culminated in Watase pulling a kunai on Konohamaru.\",\"Description_3\":\"Things end before they can escalate any further and Watase later contributes to the efforts against the Sumo Wrestlers. He then told Konohamaru that he would carry on the Will of Fire. Later, he was part of a group of genin tasked with patrolling sectors of the village.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #281\", \"Description\": \"Watase (ワタセ, Watase) is a genin-level shinobi from Konohagakure. Watase is a somewhat stubborn individual, seen from his wanting to participate in the Fourth Shinobi World War despite being too young. He is also very ambitious, and believed that connections no longer made an individual a hero, or Hokage-worthy but it was in fact, their contributions on the battlefield, citing Naruto as an example.\", \"Description_2\": \"Watase was present at the meeting called by Ebisu where he cursed the fact that he had not been born earlier so that he could be on the battlefield. Later when Konohamaru assembled all the genin in the village to get them to face the upcoming threat, Watase told him to stop playing Hokage. A fight ensued which culminated in Watase pulling a kunai on Konohamaru.\", \"Description_3\": \"Things end before they can escalate any further and Watase later contributes to the efforts against the Sumo Wrestlers. He then told Konohamaru that he would carry on the Will of Fire. Later, he was part of a group of genin tasked with patrolling sectors of the village.\"}'),(408,23222,'Yagura','{\"Birthday\":\"April 3\",\"Gender\":\"Male\",\"Height\":\"Part II: 143 cm\",\"Weight\":\"Part II: 38.8 kg\",\"Blood type\":\"AB\",\"Classification\":\"Jinchuuriki\",\"Tailed Beast\":\"Isobu (Forms)\",\"Occupation\":\"Mizukage\",\"Affiliation\":\"Kirigakure Symbol Kirigakure\",\"Clan\":\"Karatachi Family (Anime only)\",\"Description\":\"Yagura (\\u3084\\u3050\\u3089) was a shinobi from Kirigakure and the host of the Three-Tailed Giant Turtle. When the Three-Tails was captured by Akatsuki, it had no host and roamed out in the wild. Why the beast was removed from this jinch\\u016Briki is unknown.\",\"Description_2\":\"Because Y\\u016Bkimaru has some control over the Three-Tails, and because he has some resemblance to this jinch\\u016Briki, it is speculated that they have some connection to each other, however Y\\u016Bkimaru is a anime-only character that does not appear in the manga.\",\"(Source\":\"Narutopedia)\"}','{\"Clan\": \"Karatachi Family (Anime only)\", \"Gender\": \"Male\", \"Height\": \"Part II: 143 cm\", \"Weight\": \"Part II: 38.8 kg\", \"(Source\": \"Narutopedia)\", \"Birthday\": \"April 3\", \"Blood type\": \"AB\", \"Occupation\": \"Mizukage\", \"Affiliation\": \"Kirigakure Symbol Kirigakure\", \"Description\": \"Yagura (やぐら) was a shinobi from Kirigakure and the host of the Three-Tailed Giant Turtle. When the Three-Tails was captured by Akatsuki, it had no host and roamed out in the wild. Why the beast was removed from this jinchūriki is unknown.\", \"Tailed Beast\": \"Isobu (Forms)\", \"Description_2\": \"Because Yūkimaru has some control over the Three-Tails, and because he has some resemblance to this jinchūriki, it is speculated that they have some connection to each other, however Yūkimaru is a anime-only character that does not appear in the manga.\", \"Classification\": \"Jinchuuriki\"}'),(409,23050,'Yahiko','{\"Birthday\":\"February 20\",\"Blood type\":\"O\",\"Affiliation\":\"Amegakure\",\"Team\":\"Ame Orphans\",\"Manga Debut\":\"Chapter #372\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #128\",\"Description\":\"Yahiko was a shinobi from Amegakure and once a student of Jiraiya along with Nagato and Konan.\",\"Background\":\"\",\"Description_2\":\"Yahiko was orphaned during the Second Shinobi World War, and, thus, he started fending for himself, stealing food from others. He later encountered Konan, also an orphan, and the two began to work together to survive. After this, Konan brought another orphan, Nagato, and his dog, Chibi, into the group. At first, Yahiko was upset that she was bringing more people, but he later accepted Nagato and Chibi into his gang. Angered by how unfair the world was to them, Yahiko declared he would become a god to end the fighting.\",\"Description_3\":\"The three eventually encountered Jiraiya, who looked after them and taught them basic ninjutsu. At one point, Nagato saved Yahiko after an Iwagakure ch\\u016Bnin attacked them. Afterwards, Yahiko vowed to become strong enough to protect Konan, Nagato, and eventually all of Amegakure.\",\"Description_4\":\"Some time after Jiraiya\\u0027s departure from Amegakure, the three gained a reputation as a talented shinobi team. Still desiring to create a world of peace, Yahiko and his friends went on to become fully fledged Ame ninja, and gathered many supporters who shared their hope to save their village and the world.\",\"Personality\":\"\",\"Description_5\":\"Yahiko\\u0027s personality is similar to Naruto\\u0027s. His dream was to be a leader of his village, and he never gave up no matter what. When he was alive, Yahiko had a strong \\u0022eye for an eye\\u0022 philosophy. He hated the way Amegakure was looked at by the rest of the world, and hated what it had become. He was defensive of the village, saying that it was his dream to stop the endless rain, which he compared to tears, and protect the nation\\u0027s citizens. Yahiko wanted to become the ruler of the world so there wouldn\\u0027t be any more wars.\",\"Description_6\":\"Among the three Ame Orphans, Yahiko seemed to act as the leader of the group. It was Yahiko who first approached the Sannin to ask for food, and was the first to ask Jiraiya to teach them ninjutsu. He also seemed to act as an older brother for Nagato and Konan, reminding Nagato to not cry and to act more manly (although Yahiko was the one who cried when Jiraiya left them). He also wished to become stronger so as to protect Nagato and Konan. He had faith in Nagato, when he got older.\",\"Abilities\":\"\",\"Yahiko had the ability to use water-based jutsu, although the only example of this shown in the series was Water Release\":\"Violent Water Wave, in which he was able to shoot a jet of water from his mouth.\",\"(Source\":\"Narutopedia)\"}','{\"Team\": \"Ame Orphans\", \"(Source\": \"Narutopedia)\", \"Birthday\": \"February 20\", \"Abilities\": \"\", \"Background\": \"\", \"Blood type\": \"O\", \"Affiliation\": \"Amegakure\", \"Anime Debut\": \"Naruto Shippūden Episode #128\", \"Description\": \"Yahiko was a shinobi from Amegakure and once a student of Jiraiya along with Nagato and Konan.\", \"Manga Debut\": \"Chapter #372\", \"Personality\": \"\", \"Description_2\": \"Yahiko was orphaned during the Second Shinobi World War, and, thus, he started fending for himself, stealing food from others. He later encountered Konan, also an orphan, and the two began to work together to survive. After this, Konan brought another orphan, Nagato, and his dog, Chibi, into the group. At first, Yahiko was upset that she was bringing more people, but he later accepted Nagato and Chibi into his gang. Angered by how unfair the world was to them, Yahiko declared he would become a god to end the fighting.\", \"Description_3\": \"The three eventually encountered Jiraiya, who looked after them and taught them basic ninjutsu. At one point, Nagato saved Yahiko after an Iwagakure chūnin attacked them. Afterwards, Yahiko vowed to become strong enough to protect Konan, Nagato, and eventually all of Amegakure.\", \"Description_4\": \"Some time after Jiraiya\'s departure from Amegakure, the three gained a reputation as a talented shinobi team. Still desiring to create a world of peace, Yahiko and his friends went on to become fully fledged Ame ninja, and gathered many supporters who shared their hope to save their village and the world.\", \"Description_5\": \"Yahiko\'s personality is similar to Naruto\'s. His dream was to be a leader of his village, and he never gave up no matter what. When he was alive, Yahiko had a strong \\\"eye for an eye\\\" philosophy. He hated the way Amegakure was looked at by the rest of the world, and hated what it had become. He was defensive of the village, saying that it was his dream to stop the endless rain, which he compared to tears, and protect the nation\'s citizens. Yahiko wanted to become the ruler of the world so there wouldn\'t be any more wars.\", \"Description_6\": \"Among the three Ame Orphans, Yahiko seemed to act as the leader of the group. It was Yahiko who first approached the Sannin to ask for food, and was the first to ask Jiraiya to teach them ninjutsu. He also seemed to act as an older brother for Nagato and Konan, reminding Nagato to not cry and to act more manly (although Yahiko was the one who cried when Jiraiya left them). He also wished to become stronger so as to protect Nagato and Konan. He had faith in Nagato, when he got older.\", \"Yahiko had the ability to use water-based jutsu, although the only example of this shown in the series was Water Release\": \"Violent Water Wave, in which he was able to shoot a jet of water from his mouth.\"}'),(410,31830,'Yakku','{\"Description\":\"Yakku meets with Temari and Team 7 when they arrive in Sunagakure. He gives them the latest information concerning Gaara\\u0027s abduction and escorts them to Kankur\\u014D.\"}','{\"Description\": \"Yakku meets with Temari and Team 7 when they arrive in Sunagakure. He gives them the latest information concerning Gaara\'s abduction and escorts them to Kankurō.\"}'),(411,93627,'Yakushi, Nonou','{\"Age\":\"31\",\"Birthday\":\"March 5\",\"Status\":\"Deceased\",\"Height\":\"155 cm\",\"Weight\":\"42.1 kg\",\"Blood type\":\"B\",\"Classification\":\"Medical-nin\",\"Occupation\":\"Caretaker of the Konoha Orphanage, Captain of the Medic Corps\",\"Affiliation\":\"Konohagakure, Root, Konoha Orphanage\",\"Team\":\"Medic Corps\",\"Rank\":\"Jounin\",\"Family\":\"Urushi and Kabuto Yakushi (Adoptive Sons)\",\"Manga Debut\":\"Volume #61, Chapter #582\",\"Anime Debut\":\"Naruto Shippuuden Episode #335\",\"Description\":\"Nonou Yakushi, renowned as The Wandering Miko, was a jounin of Konohagakure, and a captain of the Medic Corps. She was previously an Anbu from Root, but left the organisation to become a caretaker at an orphanage located on the outskirts of the village where she was called \\u0022Mother\\u0022. While undercover in Iwagakure, she went by the name \\u0022Nanigashi\\u0022.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"31\", \"Rank\": \"Jounin\", \"Team\": \"Medic Corps\", \"Family\": \"Urushi and Kabuto Yakushi (Adoptive Sons)\", \"Height\": \"155 cm\", \"Status\": \"Deceased\", \"Weight\": \"42.1 kg\", \"(Source\": \"Narutopedia)\", \"Birthday\": \"March 5\", \"Blood type\": \"B\", \"Occupation\": \"Caretaker of the Konoha Orphanage, Captain of the Medic Corps\", \"Affiliation\": \"Konohagakure, Root, Konoha Orphanage\", \"Anime Debut\": \"Naruto Shippuuden Episode #335\", \"Description\": \"Nonou Yakushi, renowned as The Wandering Miko, was a jounin of Konohagakure, and a captain of the Medic Corps. She was previously an Anbu from Root, but left the organisation to become a caretaker at an orphanage located on the outskirts of the village where she was called \\\"Mother\\\". While undercover in Iwagakure, she went by the name \\\"Nanigashi\\\".\", \"Manga Debut\": \"Volume #61, Chapter #582\", \"Classification\": \"Medical-nin\"}'),(412,2405,'Yakushi, Kabuto','{\"Sex\":\"Male\",\"Birthday\":\"February 29\",\"Bloodtype\":\"AB\",\"Age\":\"Part I: 19-20, Part II: 23-24\",\"Height\":\"Part I: 176.2 cm, Part II: 177 cm\",\"Weight\":\"65 kg\",\"Relatives\":\"Nonou Yakushi (Adopted Mother)\",\"Chakra Nature\":\"Earth Release, Water Release\",\"Description\":\"Kabuto Yakushi is Orochimaru\\u0027s personal medic, assistant, and general right-hand man. Kabuto was found as a young boy by a chief medical officer of the Konoha Medical Unit Squad. The officer brought Kabuto with him back to Konoha and raised him as a son. Kabuto eventually began acting as a spy for numerous countries and organizations (such as Akatsuki) before coming under the servitude of Orochimaru. Kabuto has since used his various former affiliations as a means to gather intelligence on Orochimaru\\u0027s behalf, such as entering the Chunin Exams as a Konoha ninja to gather information on his fellow participants for Orochimaru\\u0027s use. Despite his apparent loyalty to Orochimaru, Kabuto\\u0027s true personality is difficult to discern; he frequently switches from a lighthearted and polite teenager to a twisted and sadistic maniac that enjoys playing mind games with his opponents. While he generally obeys Orochimaru\\u0027s orders, he is not above healing Orochimaru\\u0027s enemies or trying to strike up polite conversations with Naruto Uzumaki when they meet. Orochimaru himself seems to have a hard time determining Kabuto\\u0027s thoughts, and has suggested that Kabuto secretly works against him.\",\"Description_2\":\"Kabuto is a talented ninja, being compared to Kakashi Hatake in ability on more than one occasion, as well as being shown capable of killing ANBU members with relative ease. The bulk of Kabuto\\u0027s fighting ability lies in the medical jutsu taught to him by his adoptive father. These abilities have been further enhanced through his allegiance to Orochimaru, as he has been able to experiment on others to increase his medical knowledge. As a result, Kabuto is able to reactivate dead cells in a concentrated area and grow new ones. While he uses this ability in battle to immediately recover from attacks, it can also be used during his experiments to keep test subjects alive for much longer than is feasible. Kabuto can even temporarily reanimate a corpse for use as an ally or a decoy. During his battle with Tsunade, she remarks that his fighting and healing abilities surpass her own when she was his age. Despite his talents, Kabuto has always served others, a fate he is dissatisfied with. As such, after Orochimaru\\u0027s defeat, Kabuto integrates his master\\u0027s remains into his body as a means to become more powerful and to no longer be the mere tool of others. The remains have since begun trying to take over his body.\"}','{\"Age\": \"Part I: 19-20, Part II: 23-24\", \"Sex\": \"Male\", \"Height\": \"Part I: 176.2 cm, Part II: 177 cm\", \"Weight\": \"65 kg\", \"Birthday\": \"February 29\", \"Bloodtype\": \"AB\", \"Relatives\": \"Nonou Yakushi (Adopted Mother)\", \"Description\": \"Kabuto Yakushi is Orochimaru\'s personal medic, assistant, and general right-hand man. Kabuto was found as a young boy by a chief medical officer of the Konoha Medical Unit Squad. The officer brought Kabuto with him back to Konoha and raised him as a son. Kabuto eventually began acting as a spy for numerous countries and organizations (such as Akatsuki) before coming under the servitude of Orochimaru. Kabuto has since used his various former affiliations as a means to gather intelligence on Orochimaru\'s behalf, such as entering the Chunin Exams as a Konoha ninja to gather information on his fellow participants for Orochimaru\'s use. Despite his apparent loyalty to Orochimaru, Kabuto\'s true personality is difficult to discern; he frequently switches from a lighthearted and polite teenager to a twisted and sadistic maniac that enjoys playing mind games with his opponents. While he generally obeys Orochimaru\'s orders, he is not above healing Orochimaru\'s enemies or trying to strike up polite conversations with Naruto Uzumaki when they meet. Orochimaru himself seems to have a hard time determining Kabuto\'s thoughts, and has suggested that Kabuto secretly works against him.\", \"Chakra Nature\": \"Earth Release, Water Release\", \"Description_2\": \"Kabuto is a talented ninja, being compared to Kakashi Hatake in ability on more than one occasion, as well as being shown capable of killing ANBU members with relative ease. The bulk of Kabuto\'s fighting ability lies in the medical jutsu taught to him by his adoptive father. These abilities have been further enhanced through his allegiance to Orochimaru, as he has been able to experiment on others to increase his medical knowledge. As a result, Kabuto is able to reactivate dead cells in a concentrated area and grow new ones. While he uses this ability in battle to immediately recover from attacks, it can also be used during his experiments to keep test subjects alive for much longer than is feasible. Kabuto can even temporarily reanimate a corpse for use as an ally or a decoy. During his battle with Tsunade, she remarks that his fighting and healing abilities surpass her own when she was his age. Despite his talents, Kabuto has always served others, a fate he is dissatisfied with. As such, after Orochimaru\'s defeat, Kabuto integrates his master\'s remains into his body as a means to become more powerful and to no longer be the mere tool of others. The remains have since begun trying to take over his body.\"}'),(413,15072,'Yamanaka, Inoichi','{\"Description\":\"Inoichi Yamanaka is a Jonin from Konohagakure, and alongside Shikaku Nara and Choza Akimichi, he is a part of the first Ino-Shika-Cho trio.\",\"Description_2\":\"He is a member of the Yamanaka clan and owns the Yamanaka flower shop along with his daughter Ino Yamanaka. Inoichi is a member of the Ino-Shika-Cho trio, which consists of three Jonin from the Yamanaka clan, the Nara clan, and the Akimichi Clan, respectively. His daughter, Ino, is a member of her own Ino-Shika-Cho, judging that their fathers were once team-mates themselves in their early days as ninja.\",\"Description_3\":\"Inoichi, presumably the head of the Yamanaka clan, has shown himself to be a highly capable ninja. He is well-versed in all of his clan\\u0027s secret techniques. During the Invasion of Konoha in Part I, Inoichi skilfully performs the Mind Body Disturbance Technique  to make the invaders he encounters fight against their own allies without any self-control. Further proof of his skill was shown from his status as an interrogator during Pain\\u0027s invasion. He was able to skilfully probe the mind of one Pain\\u0027s Amegakure loyalist\\u0027s, able to perceive a person\\u0027s entire day of memories in under a minute, even though Pain had guarded it with mental blocks and traps. He has also shown the ability to communicate telepathically with his daughter, Ino.\",\"Description_4\":\"He is also skilled at tracking targets through their chakra trail, as long as the target\\u0027s chakra signature stays the same.\",\"Techniques\":\"\",\"Description_5\":\"* Chakra Sensing Technique (Manga only)\",\"Description_6\":\"* Formation Ino-Shika-Ch\\u014D\",\"Description_7\":\"* Mind Body Disturbance Technique\",\"Description_8\":\"* Mind Reading\",\"Description_9\":\"* Yamanaka Clan Telepathy\"}','{\"Techniques\": \"\", \"Description\": \"Inoichi Yamanaka is a Jonin from Konohagakure, and alongside Shikaku Nara and Choza Akimichi, he is a part of the first Ino-Shika-Cho trio.\", \"Description_2\": \"He is a member of the Yamanaka clan and owns the Yamanaka flower shop along with his daughter Ino Yamanaka. Inoichi is a member of the Ino-Shika-Cho trio, which consists of three Jonin from the Yamanaka clan, the Nara clan, and the Akimichi Clan, respectively. His daughter, Ino, is a member of her own Ino-Shika-Cho, judging that their fathers were once team-mates themselves in their early days as ninja.\", \"Description_3\": \"Inoichi, presumably the head of the Yamanaka clan, has shown himself to be a highly capable ninja. He is well-versed in all of his clan\'s secret techniques. During the Invasion of Konoha in Part I, Inoichi skilfully performs the Mind Body Disturbance Technique  to make the invaders he encounters fight against their own allies without any self-control. Further proof of his skill was shown from his status as an interrogator during Pain\'s invasion. He was able to skilfully probe the mind of one Pain\'s Amegakure loyalist\'s, able to perceive a person\'s entire day of memories in under a minute, even though Pain had guarded it with mental blocks and traps. He has also shown the ability to communicate telepathically with his daughter, Ino.\", \"Description_4\": \"He is also skilled at tracking targets through their chakra trail, as long as the target\'s chakra signature stays the same.\", \"Description_5\": \"* Chakra Sensing Technique (Manga only)\", \"Description_6\": \"* Formation Ino-Shika-Chō\", \"Description_7\": \"* Mind Body Disturbance Technique\", \"Description_8\": \"* Mind Reading\", \"Description_9\": \"* Yamanaka Clan Telepathy\"}'),(414,64451,'Yamanaka, Santa','{\"Description\":\"Santa Yamanaka (\\u5C71\\u4E2D\\u30B5\\u30F3\\u30BF, Yamanaka Santa) is a shinobi from Konohagakure\\u0027s Yamanaka clan.\",\"Manga Debut\":\"Chapter #523\",\"Anime\":\"Naruto Shipp\\u016Bden Episode #266\",\"(source\":\"Narutopedia)\"}','{\"Anime\": \"Naruto Shippūden Episode #266\", \"(source\": \"Narutopedia)\", \"Description\": \"Santa Yamanaka (山中サンタ, Yamanaka Santa) is a shinobi from Konohagakure\'s Yamanaka clan.\", \"Manga Debut\": \"Chapter #523\"}'),(415,40403,'Yamanaka, Fuu','{\"Birthday\":\"August 20\",\"Age\":\"19\",\"Height\":\"180 cm\",\"Weight\":\"61.7 kg\",\"Blood type\":\"A\",\"Classification\":\"sensor type\",\"Affiliation\":\"Konohagakure, Root\",\"Partner\":\"Torune Aburame\",\"Clan\":\"Yamanaka Clan\",\"Ninja Rank\":\"Anbu\",\"Ninja Registration\":\"012337\",\"Fuu Yamanaka is a shinobi from Konohagakure\\u0027s Yamanaka clan as well as a high-ranking ninja of the Anbu faction\":\"Root. He is one of Danzo\\u0027s chosen bodyguards.\",\"(Source\":\"Narutopedia)\"}','{\"Age\": \"19\", \"Clan\": \"Yamanaka Clan\", \"Height\": \"180 cm\", \"Weight\": \"61.7 kg\", \"(Source\": \"Narutopedia)\", \"Partner\": \"Torune Aburame\", \"Birthday\": \"August 20\", \"Blood type\": \"A\", \"Ninja Rank\": \"Anbu\", \"Affiliation\": \"Konohagakure, Root\", \"Classification\": \"sensor type\", \"Ninja Registration\": \"012337\", \"Fuu Yamanaka is a shinobi from Konohagakure\'s Yamanaka clan as well as a high-ranking ninja of the Anbu faction\": \"Root. He is one of Danzo\'s chosen bodyguards.\"}'),(416,77439,'Yamanaka, Mother','{\"Description\":\"She is a citizen of Konohagakure, the wife of Inoichi Yamanaka, and mother of Ino Yamanaka. She is also a member of the Allied Mothers Force.\",\"Anime Debut\":\"Naruto Shippuuden Episode #281\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #281\", \"Description\": \"She is a citizen of Konohagakure, the wife of Inoichi Yamanaka, and mother of Ino Yamanaka. She is also a member of the Allied Mothers Force.\"}'),(417,2009,'Yamanaka, Ino','{\"Personal Data\":\"\",\"Birthday\":\"September 23\",\"Horoscope\":\"Libra\",\"Gender\":\"Female\",\"Age\":\"12-13 (Part I), 16 (Part II)\",\"Height\":\"149.3 cm (4\\u002789\\u0027\\u0027)-151.2 cm (4\\u002796\\u0027\\u0027) (Part I), 162.2 cm (5\\u002732\\u0027\\u0027) (Part II)\",\"Weight\":\"38.2 kg-38.5 kg (Part I), 46 kg (Part II)\",\"Blood Type\":\"B\",\"Clan\":\"Yamanaka clan\",\"Family\":\"Inoichi Yamanaka (Father)\",\"Affiliation\":\"Konohagakure\",\"Team\":\"\",\"Rank\":\"Genin (Part I), Ch\\u016Bnin (Part II)\",\"Registration ID\":\"012604\",\"Academy Grad. Age\":\"12\",\"Ch\\u016Bnin Prom. Age\":\"14\",\"Missions Completed\":\"40 (D-Rank: 23, C-Rank: 9, B-Rank: 6, A-Rank: 2, S-Rank:0)\",\"Favourite Phrase\":\"\\u0022The many words of flowers.\\u0022\",\"Likes\":\"Cherry tomatoes, custard pudding, Shopping\",\"Dislikes\":\"Sashimi, Sakura at first\",\"Debut\":\"\",\"Manga\":\"Chapter #34\",\"Anime\":\"Naruto Episode #1\",\"Jutsu\":\"\",\"Description\":\"Ino Yamanaka is a childhood friend of Sakura Haruno who was bullied due to her large forehead, ending when Ino befriended her. She acted like a mentor, being tougher and more confident. Under her influence, Sakura began to develope her own identity. Though close to Ino, Sakura could not help but feel she was in her shadow and upon learning they liked the same boy, ended their friendship so that they could compete for his affection, beginning a bitter rivalry. Ino shed her tomboyish look in retaliation and was more open about her feelings towards Sasuke. The rivalry stays till the Chunin Exam. Nevertheless, they have a competitive relationship. She became somewhat superficial, thinking highly of her looks and has no problem telling people what she thinks, no matter how hurtful, such as telling Choji that he should focus more on his appearance because girls dislike overweight boys. On the surface of things, both of her teammates fit the profiles of people she wouldn\\u0027t associate with because of her apparent shallowness, but she actually cares deeply for their well-beings and maintains a strong bond with them. It should be noted that while Ino is portrayed as shallow she came to Sakura\\u0027s aid in the Forest of Death despite their feud. She cares very much about her friends, showing deep loyalty.\",\"Description_2\":\"As a member of the Yamanaka clan, Ino works in her family\\u0027s flower shop and has become particularly talented in ikebana. She has been noted to be sharp upon occasion, such as noticing Asuma\\u0027s affection for Kurenai or using chakra cleverly. The anime\\u0027s filler arcs show that she\\u0027s been able to find other uses for her time in the shop and can tell a person\\u0027s profession by simply glancing at the condition of their hands. Being a Yamanaka has also shaped the mind-altering jutsu she uses. With the Mind Body Switch Technique, Ino can transfer to another\\u0027s body and use it for a time. The anime explains her medical abilities. During the final filler arc, Ino finds herself of no use to her teammates and becomes awed of Sakura\\u0027s skills. As such, Ino becomes Tsunade\\u0027s second apprentice, hoping to be more useful to her friends. The anime has also shown that Ino has developed her own inner-self named \\u0022Inner Ino\\u0022. She, along with team 10 plus Kakashi, aids in the dispersion of two of Akatsuki\\u0027s members.\"}','{\"Age\": \"12-13 (Part I), 16 (Part II)\", \"Clan\": \"Yamanaka clan\", \"Rank\": \"Genin (Part I), Chūnin (Part II)\", \"Team\": \"\", \"Anime\": \"Naruto Episode #1\", \"Debut\": \"\", \"Jutsu\": \"\", \"Likes\": \"Cherry tomatoes, custard pudding, Shopping\", \"Manga\": \"Chapter #34\", \"Family\": \"Inoichi Yamanaka (Father)\", \"Gender\": \"Female\", \"Height\": \"149.3 cm (4\'89\'\')-151.2 cm (4\'96\'\') (Part I), 162.2 cm (5\'32\'\') (Part II)\", \"Weight\": \"38.2 kg-38.5 kg (Part I), 46 kg (Part II)\", \"Birthday\": \"September 23\", \"Dislikes\": \"Sashimi, Sakura at first\", \"Horoscope\": \"Libra\", \"Blood Type\": \"B\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Ino Yamanaka is a childhood friend of Sakura Haruno who was bullied due to her large forehead, ending when Ino befriended her. She acted like a mentor, being tougher and more confident. Under her influence, Sakura began to develope her own identity. Though close to Ino, Sakura could not help but feel she was in her shadow and upon learning they liked the same boy, ended their friendship so that they could compete for his affection, beginning a bitter rivalry. Ino shed her tomboyish look in retaliation and was more open about her feelings towards Sasuke. The rivalry stays till the Chunin Exam. Nevertheless, they have a competitive relationship. She became somewhat superficial, thinking highly of her looks and has no problem telling people what she thinks, no matter how hurtful, such as telling Choji that he should focus more on his appearance because girls dislike overweight boys. On the surface of things, both of her teammates fit the profiles of people she wouldn\'t associate with because of her apparent shallowness, but she actually cares deeply for their well-beings and maintains a strong bond with them. It should be noted that while Ino is portrayed as shallow she came to Sakura\'s aid in the Forest of Death despite their feud. She cares very much about her friends, showing deep loyalty.\", \"Description_2\": \"As a member of the Yamanaka clan, Ino works in her family\'s flower shop and has become particularly talented in ikebana. She has been noted to be sharp upon occasion, such as noticing Asuma\'s affection for Kurenai or using chakra cleverly. The anime\'s filler arcs show that she\'s been able to find other uses for her time in the shop and can tell a person\'s profession by simply glancing at the condition of their hands. Being a Yamanaka has also shaped the mind-altering jutsu she uses. With the Mind Body Switch Technique, Ino can transfer to another\'s body and use it for a time. The anime explains her medical abilities. During the final filler arc, Ino finds herself of no use to her teammates and becomes awed of Sakura\'s skills. As such, Ino becomes Tsunade\'s second apprentice, hoping to be more useful to her friends. The anime has also shown that Ino has developed her own inner-self named \\\"Inner Ino\\\". She, along with team 10 plus Kakashi, aids in the dispersion of two of Akatsuki\'s members.\", \"Personal Data\": \"\", \"Registration ID\": \"012604\", \"Favourite Phrase\": \"\\\"The many words of flowers.\\\"\", \"Academy Grad. Age\": \"12\", \"Chūnin Prom. Age\": \"14\", \"Missions Completed\": \"40 (D-Rank: 23, C-Rank: 9, B-Rank: 6, A-Rank: 2, S-Rank:0)\"}'),(418,17553,'Yamashiro, Aoba','{\"Description\":\"Aoba served as a J\\u014Dnin ninja in Hidden Leaf Village.\",\"Description_2\":\"First appearance in volume 11 chapter 93.\",\"Nature Type\":\"Fire Release (Anime Only)\",\"Height\":\"178cm\",\"Weight\":\"66kg\",\"Birthdate\":\"September 3\"}','{\"Height\": \"178cm\", \"Weight\": \"66kg\", \"Birthdate\": \"September 3\", \"Description\": \"Aoba served as a Jōnin ninja in Hidden Leaf Village.\", \"Nature Type\": \"Fire Release (Anime Only)\", \"Description_2\": \"First appearance in volume 11 chapter 93.\"}'),(419,2006,'Yamato','{\"Birth Date\":\"August 10\",\"Gender\":\"Male\",\"Age\":\"26\",\"Height\":\"178 cm\",\"Weight\":\"58.4 kg\",\"Blood Type\":\"A\",\"Occupation\":\"ANBU, Team Kakashi\",\"Affiliation\":\"Konoha, Fire Country\",\"Academy Graduation Age\":\"6\",\"Chuunin Promotion Age\":\"6\",\"Ninja Registration\":\"010992\",\"Description\":\"Yamato is a member of Konoha\\u0027s ANBU, and a younger peer of Kakashi Hatake. He is also the temporary leader of Team Kakashi, and one of the main protagonists of the series. \\u0022Yamato\\u0022 is actually a codename given to him by Tsunade for the purposes of joining Team Kakashi. While Kakashi was still in the ANBU, his codename was Tenzou. Kakashi sometimes still calls him Tenzou, although Yamato prefers his new codename.\",\"Description_2\":\"Like other ANBU members, Yamato projects a calm, stoic demeanor in stressful situations. Despite this, he can also be quite laid back when not on duty, and is not above using his Wood Release techniques for creating comforts, such as making a house to \\u0022camp out\\u0022 in.\",\"Description_3\":\"Yamato is somewhat reluctant to pay for things unless he has to, as he initially protested at having to pay for lunch at Ichiraku Ramen Bar, stating that Kakashi should pay, being the senior ninja, but was flattered into paying when Kakashi said he considered Yamato an equal.\"}','{\"Age\": \"26\", \"Gender\": \"Male\", \"Height\": \"178 cm\", \"Weight\": \"58.4 kg\", \"Birth Date\": \"August 10\", \"Blood Type\": \"A\", \"Occupation\": \"ANBU, Team Kakashi\", \"Affiliation\": \"Konoha, Fire Country\", \"Description\": \"Yamato is a member of Konoha\'s ANBU, and a younger peer of Kakashi Hatake. He is also the temporary leader of Team Kakashi, and one of the main protagonists of the series. \\\"Yamato\\\" is actually a codename given to him by Tsunade for the purposes of joining Team Kakashi. While Kakashi was still in the ANBU, his codename was Tenzou. Kakashi sometimes still calls him Tenzou, although Yamato prefers his new codename.\", \"Description_2\": \"Like other ANBU members, Yamato projects a calm, stoic demeanor in stressful situations. Despite this, he can also be quite laid back when not on duty, and is not above using his Wood Release techniques for creating comforts, such as making a house to \\\"camp out\\\" in.\", \"Description_3\": \"Yamato is somewhat reluctant to pay for things unless he has to, as he initially protested at having to pay for lunch at Ichiraku Ramen Bar, stating that Kakashi should pay, being the senior ninja, but was flattered into paying when Kakashi said he considered Yamato an equal.\", \"Ninja Registration\": \"010992\", \"Chuunin Promotion Age\": \"6\", \"Academy Graduation Age\": \"6\"}'),(420,38457,'Yaoki','{\"Description\":\"Yaoki (\\u5C4B\\u6C96, Yaoki) is a ninja from Sunagakure and a subordinate of Gaara along with his partner Korobi. He is shown to be cowardly and wimpy around Gaara, due to him formally be a murderous maniac. When Konoha and Suna started to get along again, Yaoki was assigned on a team with Gaara to take out a group of bandits located between Suna and Konoha, which Team 7 was also assigned to. When Gaara was captured by an assassination squad from their village, Gaara tells them to leave because the squad after only him. Naruto runs into Yaoki and Korobi, seeing Gaara is not with them and asking them why they abandoned their friend. The two both wonder if Gaara is their friend. Yaoki and Korobi both assisted Naruto in Gaara\\u0027s rescue and they tell him they\\u0027re his friends. When their mission was accomplished, Gaara asked Yaoki and Korobi what they said and they happily tell him they\\u0027re his friends.\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Description\": \"Yaoki (屋沖, Yaoki) is a ninja from Sunagakure and a subordinate of Gaara along with his partner Korobi. He is shown to be cowardly and wimpy around Gaara, due to him formally be a murderous maniac. When Konoha and Suna started to get along again, Yaoki was assigned on a team with Gaara to take out a group of bandits located between Suna and Konoha, which Team 7 was also assigned to. When Gaara was captured by an assassination squad from their village, Gaara tells them to leave because the squad after only him. Naruto runs into Yaoki and Korobi, seeing Gaara is not with them and asking them why they abandoned their friend. The two both wonder if Gaara is their friend. Yaoki and Korobi both assisted Naruto in Gaara\'s rescue and they tell him they\'re his friends. When their mission was accomplished, Gaara asked Yaoki and Korobi what they said and they happily tell him they\'re his friends.\"}'),(421,13017,'Yashamaru','{\"Description\":\"Including spoilers.\",\"Description_2\":\"Yashamaru (\\u591C\\u53C9\\u4E38) was a medic-nin, the younger brother of Karura, and thus the uncle of Gaara. At first, Gaara thought that he was the only one that cared about him. Yashamaru taught Gaara about physical pain, emotional pain and love; concepts Gaara was completely unaware of in his childhood. He was commanded by the Fourth Kazekage to assassinate Gaara, but was given the choice in deciding whether he wanted to proceed or not. Yashamaru willingly accepted the command in order to avenge his older sister\\u0027s premature death. The assassination attempt, however, ended in a desperate suicide mission and ultimately failed. Before he died, he told Gaara that no one had ever really loved him, not even him. This left Gaara even more of an emotional wreck than he already was. His suicide bombing attempt on Gaara\\u0027s life caused Gaara to become somewhat psychotic. Yashamaru\\u0027s last words, to Gaara, were \\u0022This is it. Please die.\\u0022\",\"(Source\":\"NarutoWiki)\"}','{\"(Source\": \"NarutoWiki)\", \"Description\": \"Including spoilers.\", \"Description_2\": \"Yashamaru (夜叉丸) was a medic-nin, the younger brother of Karura, and thus the uncle of Gaara. At first, Gaara thought that he was the only one that cared about him. Yashamaru taught Gaara about physical pain, emotional pain and love; concepts Gaara was completely unaware of in his childhood. He was commanded by the Fourth Kazekage to assassinate Gaara, but was given the choice in deciding whether he wanted to proceed or not. Yashamaru willingly accepted the command in order to avenge his older sister\'s premature death. The assassination attempt, however, ended in a desperate suicide mission and ultimately failed. Before he died, he told Gaara that no one had ever really loved him, not even him. This left Gaara even more of an emotional wreck than he already was. His suicide bombing attempt on Gaara\'s life caused Gaara to become somewhat psychotic. Yashamaru\'s last words, to Gaara, were \\\"This is it. Please die.\\\"\"}'),(422,97779,'Yokaze','{\"Description\":\"Yokaze (\\u30E8\\u30AB\\u30BC, Yokaze) is a medical-nin from Konohagakure.\",\"Description_2\":\"During the Fourth Shinobi World War, Yokaze was assigned to the Logistical Support and Medical Division. There, with the body count and casualty numbers rising, he marveled as Yugao Uzuki completed her duties with great efficiency, wondering why someone from the ANBU had been assigned to their division. Yokaze was later assigned to a team by Sukui alongside Sakura Haruno, and Iou to retrieve the KIA scroll that was stolen by Hayate Gekko, and two other unnamed reincarnated shinobi from Suna and Kumo. During the battle, Yokaze threw his sword to Yugao for her to use, but she was still unable to get over the shock of having to fight her former lover was not able to take up the sword. Yokaze later sustained an injury during the altercation, but was later attended to by Yugao. Ultimately, the mission turned out as a success as they were able to not only retrieve the scroll, but seal away their comrade and the other two shinobi.\",\"Anime Debut\":\"Naruto Shippuuden Episode #307\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #307\", \"Description\": \"Yokaze (ヨカゼ, Yokaze) is a medical-nin from Konohagakure.\", \"Description_2\": \"During the Fourth Shinobi World War, Yokaze was assigned to the Logistical Support and Medical Division. There, with the body count and casualty numbers rising, he marveled as Yugao Uzuki completed her duties with great efficiency, wondering why someone from the ANBU had been assigned to their division. Yokaze was later assigned to a team by Sukui alongside Sakura Haruno, and Iou to retrieve the KIA scroll that was stolen by Hayate Gekko, and two other unnamed reincarnated shinobi from Suna and Kumo. During the battle, Yokaze threw his sword to Yugao for her to use, but she was still unable to get over the shock of having to fight her former lover was not able to take up the sword. Yokaze later sustained an injury during the altercation, but was later attended to by Yugao. Ultimately, the mission turned out as a success as they were able to not only retrieve the scroll, but seal away their comrade and the other two shinobi.\"}'),(423,166810,'Yome','{\"Description\":\"Yome is a kunoichi of Sunagakure and a teammate of Sen and Shira.\"}','{\"Description\": \"Yome is a kunoichi of Sunagakure and a teammate of Sen and Shira.\"}'),(424,39573,'Yone','{\"Description\":\"Yone is the wife of Sukune and mother of Tanishi. She, along with the other women and children, was held hostage by Kandachi and his men when they killed Sukune and took over their village. Jiraiya stated that she and her husband Sukune were very kind to him the first time he visited the Genjutsu Tree Village.\"}','{\"Description\": \"Yone is the wife of Sukune and mother of Tanishi. She, along with the other women and children, was held hostage by Kandachi and his men when they killed Sukune and took over their village. Jiraiya stated that she and her husband Sukune were very kind to him the first time he visited the Genjutsu Tree Village.\"}'),(425,84627,'Yota','{\"Description\":\"Yota (\\u30E8\\u30BF, Yota) was a young child from an unknown clan with mysterious powers of weather manipulation.\",\"Description_2\":\"Yota was born into a traveling clan who could manipulate weather and use their skills to make a living. Five years before the start of the series, Yota died at a young age of natural causes due to his frailty yet was later reincarnated by Orochimaru as a test subject in his research on Impure World Reincarnation.\",\"Description_3\":\"Sent to Konohagakure on Orochimaru\\u0027s command, Yota met Ch\\u014Dji Akimichi, Shikamaru Nara, and Ino Yamanaka when they came looking for Ch\\u014Dji\\u0027s kunai set, which after being thrown pinned Yota to a tree. The crying Yota caused a downpour that ultimately collapsed the tree and freed him. Soon afterwards, Yota introduced himself to the young Konoha children as they decide not to tell the adults about him as there was already tension between Konohagakure and the other nations. They instead give Yota shelter in a makeshift tree-house and bring him food at a regular basis. Eventually, after meeting Kiba Inuzuka, his dog Akamaru, and Sakura Haruno whom he took a liking to, Yota started acting bold from appearing in the village to playing a small prank on Sasuke Uchiha.\",\"Description_4\":\"Around this time, Yota met Naruto Uzumaki while he was whistling and became friends with him while asking him to teach him how to whistle. However, despite having a good time with his new friends, things changed when Yota decided to hide with Naruto during a game of hide and seek. Mistaking Naruto telling him to hide elsewhere as a sign of dislike, Yota ran off while causing his presence to be known to the Konoha ANBU as they capture him for interrogation with Naruto and the others hatching a scheme to save Yota.\",\"Description_5\":\"After saving Yota, the group reached a very steep river and tries to cross it, but Naruto, Shikamaru, and Ch\\u014Dji were washed away by the strong current only to be saved by Yota, who failed to resurface after the incident. They later find Yota seemingly on the verge of death as he gives the group his goodbyes while erasing their memories of him. Not wanting his friends to be put on danger once more, Yota leaves Konohagakure and lives out the remainder of his manipulation in loneliness before ending up under the thrall of Orochimaru\\u0027s spy and right-hand man Kabuto Yakushi.\",\"Anime Debut\":\"Naruto Shippuuden Episode #313\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #313\", \"Description\": \"Yota (ヨタ, Yota) was a young child from an unknown clan with mysterious powers of weather manipulation.\", \"Description_2\": \"Yota was born into a traveling clan who could manipulate weather and use their skills to make a living. Five years before the start of the series, Yota died at a young age of natural causes due to his frailty yet was later reincarnated by Orochimaru as a test subject in his research on Impure World Reincarnation.\", \"Description_3\": \"Sent to Konohagakure on Orochimaru\'s command, Yota met Chōji Akimichi, Shikamaru Nara, and Ino Yamanaka when they came looking for Chōji\'s kunai set, which after being thrown pinned Yota to a tree. The crying Yota caused a downpour that ultimately collapsed the tree and freed him. Soon afterwards, Yota introduced himself to the young Konoha children as they decide not to tell the adults about him as there was already tension between Konohagakure and the other nations. They instead give Yota shelter in a makeshift tree-house and bring him food at a regular basis. Eventually, after meeting Kiba Inuzuka, his dog Akamaru, and Sakura Haruno whom he took a liking to, Yota started acting bold from appearing in the village to playing a small prank on Sasuke Uchiha.\", \"Description_4\": \"Around this time, Yota met Naruto Uzumaki while he was whistling and became friends with him while asking him to teach him how to whistle. However, despite having a good time with his new friends, things changed when Yota decided to hide with Naruto during a game of hide and seek. Mistaking Naruto telling him to hide elsewhere as a sign of dislike, Yota ran off while causing his presence to be known to the Konoha ANBU as they capture him for interrogation with Naruto and the others hatching a scheme to save Yota.\", \"Description_5\": \"After saving Yota, the group reached a very steep river and tries to cross it, but Naruto, Shikamaru, and Chōji were washed away by the strong current only to be saved by Yota, who failed to resurface after the incident. They later find Yota seemingly on the verge of death as he gives the group his goodbyes while erasing their memories of him. Not wanting his friends to be put on danger once more, Yota leaves Konohagakure and lives out the remainder of his manipulation in loneliness before ending up under the thrall of Orochimaru\'s spy and right-hand man Kabuto Yakushi.\"}'),(426,97799,'Yukai','{\"Description\":\"Yukai (\\u30E6\\u30AB\\u30A4, Yukai) is a young shinobi from Kumogakure and the leader of the Thundercloud Unit.\",\"Description_2\":\"Yukai was a young prodigy from Kumogakure, well versed in kenjutsu and assigned to be the Thundercloud Unit\\u0027s leader in the Fourth Shinobi World War.\",\"During the Fourth Shinobi World War, Yukai and the rest of the Thundercloud Unit, was sent to the Seventh Front in order to back up the Amphibious Search and Destroy Unit, who had been overrun by two thousand White Zetsu clones. Sometime during this, they became trapped within a large statue on the battlefield after the White Zetsu used the surrounding, poisonous red soil to create a vast smokescreen of poisonous gas. After speaking with his team-mates within the statue, Yukai and the others emerge to fight the Zetsu and face their fate. In the ensuing fight, Yukai is injured, however, Omoi appears and fights alongside them. At this point, using the Lightning Release Co-Operation\":\"Thunder Bomb technique, the group is able to neutralize and finish off the remaining White Zetsu.\",\"Anime Debut\":\"Naruto Shippuuden Episode #320\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #320\", \"Description\": \"Yukai (ユカイ, Yukai) is a young shinobi from Kumogakure and the leader of the Thundercloud Unit.\", \"Description_2\": \"Yukai was a young prodigy from Kumogakure, well versed in kenjutsu and assigned to be the Thundercloud Unit\'s leader in the Fourth Shinobi World War.\", \"During the Fourth Shinobi World War, Yukai and the rest of the Thundercloud Unit, was sent to the Seventh Front in order to back up the Amphibious Search and Destroy Unit, who had been overrun by two thousand White Zetsu clones. Sometime during this, they became trapped within a large statue on the battlefield after the White Zetsu used the surrounding, poisonous red soil to create a vast smokescreen of poisonous gas. After speaking with his team-mates within the statue, Yukai and the others emerge to fight the Zetsu and face their fate. In the ensuing fight, Yukai is injured, however, Omoi appears and fights alongside them. At this point, using the Lightning Release Co-Operation\": \"Thunder Bomb technique, the group is able to neutralize and finish off the remaining White Zetsu.\"}'),(427,62645,'Yukata','{\"Description\":\"Yukata (\\u30E6\\u30AB\\u30BF, Yukata) is a young kunoichi from Sunagakure.\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #261\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #261\", \"Description\": \"Yukata (ユカタ, Yukata) is a young kunoichi from Sunagakure.\"}'),(428,20621,'Yukimaru','{\"Description\":\"Yukimaru is a young boy (it is still unknown if he is a shinobi) who appears in the second Naruto Shippuden filler arc. He is a test subject of Orochimaru, because he has the ability to control the Three-Tailed Giant Turtle. Yukimaru is a quiet boy, probably due to his past, he constantly ask questions like \\u0022Is it going to be fun?\\u0022. His main goal is to find home and is told by Naruto that home is a place where people think about you, which lightens his spirit. Yukimaru always telling that he has no home to go to. Later on Kabuto sets off together with Yukimaru for a journey. They eventually arrive at a dark swamp. There, Kabuto conducts an experiment where he forcibly releases the full power of Yukimaru\\u0027s chakra. This results made the Three-Tailed demon to partial emerge before submerging again.\",\"Description_2\":\"Later, he is sent out again with Guren to complete a mission. During which, he succumbs to sickness, forcing Guren to care for him. As a result, he seems to have grown attached to Guren and possibly vice-versa. This is further emphasized from how Yukimaru reacted when Guren tells Yukimaru she has to head out in a manner similar to how Yukimaru\\u0027s mother did before presumeably dying. He then gives her his necklaces with a special charm on it.\",\"Description_3\":\"Later, Yukimaru again bumps into Naruto, who offers for the orphan to join him in Konoha, to which Yukimaru politely declines as he feels his place is with Guren. Soon after, Kabuto returns to conduct another experiment with Yukimaru. He has Yukimaru take several medical pills. Ultimately, this finally causes the Three-Tailed Beast to emerge.\",\"Description_4\":\"He is able to controlled three-tailed beast, for the first time he has to drink the pills from Kabuto to release Three-Tails Chakra but later he manage to release it without pills. Yukimaru also has illusion technique, when he meet Naruto, white camellias appear on everywhere. Then he and white camelias (tsubaki) disappear on the same time.\"}','{\"Description\": \"Yukimaru is a young boy (it is still unknown if he is a shinobi) who appears in the second Naruto Shippuden filler arc. He is a test subject of Orochimaru, because he has the ability to control the Three-Tailed Giant Turtle. Yukimaru is a quiet boy, probably due to his past, he constantly ask questions like \\\"Is it going to be fun?\\\". His main goal is to find home and is told by Naruto that home is a place where people think about you, which lightens his spirit. Yukimaru always telling that he has no home to go to. Later on Kabuto sets off together with Yukimaru for a journey. They eventually arrive at a dark swamp. There, Kabuto conducts an experiment where he forcibly releases the full power of Yukimaru\'s chakra. This results made the Three-Tailed demon to partial emerge before submerging again.\", \"Description_2\": \"Later, he is sent out again with Guren to complete a mission. During which, he succumbs to sickness, forcing Guren to care for him. As a result, he seems to have grown attached to Guren and possibly vice-versa. This is further emphasized from how Yukimaru reacted when Guren tells Yukimaru she has to head out in a manner similar to how Yukimaru\'s mother did before presumeably dying. He then gives her his necklaces with a special charm on it.\", \"Description_3\": \"Later, Yukimaru again bumps into Naruto, who offers for the orphan to join him in Konoha, to which Yukimaru politely declines as he feels his place is with Guren. Soon after, Kabuto returns to conduct another experiment with Yukimaru. He has Yukimaru take several medical pills. Ultimately, this finally causes the Three-Tailed Beast to emerge.\", \"Description_4\": \"He is able to controlled three-tailed beast, for the first time he has to drink the pills from Kabuto to release Three-Tails Chakra but later he manage to release it without pills. Yukimaru also has illusion technique, when he meet Naruto, white camellias appear on everywhere. Then he and white camelias (tsubaki) disappear on the same time.\"}'),(429,102031,'Yukimi','{\"Description\":\"Yukimi is a young girl of the Iburi clan.\",\"Description_2\":\"Like the rest of her clan, Yukimi\\u0027s underdeveloped ability to become smoke made her vulnerable to the outside world, forcing them to live underground. She and her brother, Tenz\\u014D, would regularly go as close to the surface to listen to it. One day, her clan was found by Orochimaru. Taking an interest in their abilities, he was able to partially stabilise their power by branding them with his cursed seal.\",\"Description_3\":\"Yukimi is a very upbeat girl, regularly smiling. She has a great love for her clan and relatives. Even when the rest of her clan insisted that her brother died, she refuses to believe it. Her love for her family can make her overly emotional, growing very sad at the sudden lost of one.\",\"Description_4\":\"Yukimi is a short fair-skinned girl with curly, long brown hair. She has blue eyes and freckles under her eyes. She, like the rest of her clan, wears rag. Along with her clan members, she has Orochimaru\\u0027s cursed seal on the back of her neck.\",\"Description_5\":\"Like the rest of her clan, Yukimi can transform into smoke and still make physical contact with targets. In smoke form, she can possess a person, able to essentially wear the person like a second body.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Yukimi is a young girl of the Iburi clan.\", \"Description_2\": \"Like the rest of her clan, Yukimi\'s underdeveloped ability to become smoke made her vulnerable to the outside world, forcing them to live underground. She and her brother, Tenzō, would regularly go as close to the surface to listen to it. One day, her clan was found by Orochimaru. Taking an interest in their abilities, he was able to partially stabilise their power by branding them with his cursed seal.\", \"Description_3\": \"Yukimi is a very upbeat girl, regularly smiling. She has a great love for her clan and relatives. Even when the rest of her clan insisted that her brother died, she refuses to believe it. Her love for her family can make her overly emotional, growing very sad at the sudden lost of one.\", \"Description_4\": \"Yukimi is a short fair-skinned girl with curly, long brown hair. She has blue eyes and freckles under her eyes. She, like the rest of her clan, wears rag. Along with her clan members, she has Orochimaru\'s cursed seal on the back of her neck.\", \"Description_5\": \"Like the rest of her clan, Yukimi can transform into smoke and still make physical contact with targets. In smoke form, she can possess a person, able to essentially wear the person like a second body.\"}'),(430,173390,'Yurito','{\"Description\":\"Yurito is a shinobi of Konohagakure.\"}','{\"Description\": \"Yurito is a shinobi of Konohagakure.\"}'),(431,94823,'Yurui','{\"Description\":\"Yurui (\\u30E6\\u30EB\\u30A4, Yurui) was a Kumogakure shinobi.\",\"He was made the leader of a unit in the Third Division during the Fourth Shinobi World War. He and his unit were attacked by Ameyuri Ringo where he was severely wounded by her Lightning Release\":\"Thunder Gate technique. He later succumbed to his injuries as Omoi and Nurui watched on. With his dying breath, he left everything to his comrade Nurui.\",\"Anime Debut\":\"Naruto Shippuuden Episode #289\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippuuden Episode #289\", \"Description\": \"Yurui (ユルイ, Yurui) was a Kumogakure shinobi.\", \"He was made the leader of a unit in the Third Division during the Fourth Shinobi World War. He and his unit were attacked by Ameyuri Ringo where he was severely wounded by her Lightning Release\": \"Thunder Gate technique. He later succumbed to his injuries as Omoi and Nurui watched on. With his dying breath, he left everything to his comrade Nurui.\"}'),(432,23057,'Yuudachi','{\"Description\":\"Yuudachi (\\u5915\\u7ACB; Literally meaning \\u0022Evening Thunder Shower in the Summer\\u0022) is a missing-nin from Amegakure. He and his partner Ryuusui are looking for a drink when Jiraiya lures and captures them in his toad. When the Ame-nin refused to tell Jiraiya any information on Pain, the Sannin uses a feather to tickle-torture Yuudachi into giving him the info. When this failed, Jiraiya transformed Y\\u016Bdachi into a frog, which cowarded Ry\\u016Bsui into divulging info about Pain.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Yuudachi (夕立; Literally meaning \\\"Evening Thunder Shower in the Summer\\\") is a missing-nin from Amegakure. He and his partner Ryuusui are looking for a drink when Jiraiya lures and captures them in his toad. When the Ame-nin refused to tell Jiraiya any information on Pain, the Sannin uses a feather to tickle-torture Yuudachi into giving him the info. When this failed, Jiraiya transformed Yūdachi into a frog, which cowarded Ryūsui into divulging info about Pain.\"}'),(433,4773,'Yuuhi, Kurenai','{\"Birth Date\":\"June 11th\",\"Age\":\"27-28 (Part I), 31 (Part II)\",\"Weight\":\"54.4 kg\",\"Height\":\"169.1 cm\",\"Ninja Registry No\":\"010881\",\"Ninja Rank\":\"Jounin\",\"Description\":\"Kurenai Yuuhi  is the Konoha Jounin in charge of Team 8, which consists of Kiba Inuzuka, Shino Aburame, and Hinata Hyuuga. Kurenai\\u0027s team specializes in tracking, and she herself is a highly talented genjutsu specialist.\",\"Description_2\":\"While she has a close bond with all of her students, she is especially concerned for Hinata. Kurenai knows how Hinata is viewed by her father, even though she is technically the heiress of the clan since she is the eldest child. She is also aware of her student\\u0027s infatuation for Naruto Uzumaki. When Hinata tried to offer Naruto some medicine after his fight with Kiba, Naruto was hesitant to take it. Kurenai convinced him to take it. Her personality is unyielding, honest, and simple. She also says she is a \\u0022big sister type\\u0022.\"}','{\"Age\": \"27-28 (Part I), 31 (Part II)\", \"Height\": \"169.1 cm\", \"Weight\": \"54.4 kg\", \"Birth Date\": \"June 11th\", \"Ninja Rank\": \"Jounin\", \"Description\": \"Kurenai Yuuhi  is the Konoha Jounin in charge of Team 8, which consists of Kiba Inuzuka, Shino Aburame, and Hinata Hyuuga. Kurenai\'s team specializes in tracking, and she herself is a highly talented genjutsu specialist.\", \"Description_2\": \"While she has a close bond with all of her students, she is especially concerned for Hinata. Kurenai knows how Hinata is viewed by her father, even though she is technically the heiress of the clan since she is the eldest child. She is also aware of her student\'s infatuation for Naruto Uzumaki. When Hinata tried to offer Naruto some medicine after his fight with Kiba, Naruto was hesitant to take it. Kurenai convinced him to take it. Her personality is unyielding, honest, and simple. She also says she is a \\\"big sister type\\\".\", \"Ninja Registry No\": \"010881\"}'),(434,56695,'Yuuhi, Shinku','{\"Age\":\"45\",\"Affiliation\":\"Konohagakure\",\"Ninja Rank\":\"jounin\",\"Description\":\"Shinku Yuuhi is a shinobi from Konohagakure and father of Kurenai.\",\"Description_2\":\"During the Nine-Tails\\u0027 Attack on Konoha, Shinku was seen placing the young shinobi inside a barrier, informing them that they were to stay out of the fight against the Nine-Tailed Demon Fox, to which his daughter Kurenai voiced her discontentment. Shinku told his daughter that she was a shinobi who may or may not live a long life, and requested of her to live long enough to give him a grandchild whom the Will of Fire could be passed to.\",\"(Source\":\"Narutopedia, Naruto Wikia)\"}','{\"Age\": \"45\", \"(Source\": \"Narutopedia, Naruto Wikia)\", \"Ninja Rank\": \"jounin\", \"Affiliation\": \"Konohagakure\", \"Description\": \"Shinku Yuuhi is a shinobi from Konohagakure and father of Kurenai.\", \"Description_2\": \"During the Nine-Tails\' Attack on Konoha, Shinku was seen placing the young shinobi inside a barrier, informing them that they were to stay out of the fight against the Nine-Tailed Demon Fox, to which his daughter Kurenai voiced her discontentment. Shinku told his daughter that she was a shinobi who may or may not live a long life, and requested of her to live long enough to give him a grandchild whom the Will of Fire could be passed to.\"}'),(435,31818,'Yuura','{\"Description\":\"Y\\u016Bra was a sleeper agent of Sasori. As a Sunagakure ninja, he served as a trusted member of the Kazekage advisory council of Suna for four years. He was also assigned to command the defense of Suna at the time Gaara, the Fifth Kazekage, was kidnapped. He was in charge of guarding the gate when Sasori lifted the jutsu that was blocking memories of him, Y\\u016Bra killed all the guards to allow Sasori\\u0027s partner, Deidara, into the village. Y\\u016Bra was later used by Pain as a sacrifice for the Shapeshifting Technique, becoming a replica of Itachi Uchiha. This replica was defeated by Naruto with the Great Ball Rasengan. His corpse was later devoured by Zetsu.\"}','{\"Description\": \"Yūra was a sleeper agent of Sasori. As a Sunagakure ninja, he served as a trusted member of the Kazekage advisory council of Suna for four years. He was also assigned to command the defense of Suna at the time Gaara, the Fifth Kazekage, was kidnapped. He was in charge of guarding the gate when Sasori lifted the jutsu that was blocking memories of him, Yūra killed all the guards to allow Sasori\'s partner, Deidara, into the village. Yūra was later used by Pain as a sacrifice for the Shapeshifting Technique, becoming a replica of Itachi Uchiha. This replica was defeated by Naruto with the Great Ball Rasengan. His corpse was later devoured by Zetsu.\"}'),(436,49681,'Yuusuke','{\"Description\":\"Yuusuke (\\u30E6\\u30A6\\u30B9\\u30B1, Y\\u016Bsuke) is a fisherman in the Land of Fire.\",\"Description_2\":\"When he was a child, he and his father tried to catch a giant summoned marlin, they failed, resulting in his father\\u0027s death. Yuusuke became determined to avenge his father by catching the marlin.\",\"Trivia\":\"\",\"Yuusuke\\u0027s appearance was modeled after his seiyuu, singer Yuusuke Kamiji. He also performed Otakebi, the movie theme of Naruto Shipp\\u016Bden 5\":\"Blood Prison, which premiered a week before Yuusuke\\u0027s debut in the anime.\",\"(source\":\"naruto.wikia.com)\"}','{\"Trivia\": \"\", \"(source\": \"naruto.wikia.com)\", \"Description\": \"Yuusuke (ユウスケ, Yūsuke) is a fisherman in the Land of Fire.\", \"Description_2\": \"When he was a child, he and his father tried to catch a giant summoned marlin, they failed, resulting in his father\'s death. Yuusuke became determined to avenge his father by catching the marlin.\", \"Yuusuke\'s appearance was modeled after his seiyuu, singer Yuusuke Kamiji. He also performed Otakebi, the movie theme of Naruto Shippūden 5\": \"Blood Prison, which premiered a week before Yuusuke\'s debut in the anime.\"}'),(437,62647,'Zaji','{\"Description\":\"Zaji (\\u30B6\\u30B8, Zaji) is a shinobi from Konohagakure.\",\"Manga Debut\":\"Chapter #515\",\"Anime Debut\":\"Naruto Shipp\\u016Bden Episode #256\",\"(source\":\"Narutopedia)\"}','{\"(source\": \"Narutopedia)\", \"Anime Debut\": \"Naruto Shippūden Episode #256\", \"Description\": \"Zaji (ザジ, Zaji) is a shinobi from Konohagakure.\", \"Manga Debut\": \"Chapter #515\"}'),(438,3150,'Zetsu','{\"Description\":\"Zetsu is easily distinguished by two large venus fly trap-like extensions enveloping his head and upper body, giving him a plant-like appearance. When his extensions are open and his head is visible, it is revealed that Zetsu has two different colored halves of his body, the left side completely white and the right side black. To go with this, Zetsu seems to have a split personality, as in the Japanese version of the manga the black half of his face speaks only in Katakana while the white side uses Kanji and Kana, and in the English episodes the black side has a different voice actor than the white side. The two halves also converse with each other, and occasionally differ in opinion (the black half is more serious and intelligent while the white half is carefree and easygoing). They also seem to communicate with their thoughts. To further his venus fly trap theme, Zetsu is a cannibal.\",\"Description_2\":\"Zetsu is seemingly very trustworthy, being entrusted with knowledge of Pain and Tobi\\u0027s identities. He has apparently been working with the latter for some time, Tobi first appearing as his \\u0022subordinate\\u0022 and Zetsu later commenting that Tobi\\u0027s plans have been in the works for a long time.\",\"Description_3\":\"Zetsu\\u0027s main role within the Akatsuki is to function as a spy, often acting as a hunter-nin for Akatsuki. He has been shown able to move his body and take part in the tailed beasts sealing ritual imultaneously which, in addition to being unique to him, allows him to act as a lookout while the sealing takes place. When an agent to Akatsuki, or possibly even a member, dies, Zetsu is sent to devour their bodies so as to not have their secrets revealed. Zetsu is also the one sent to retrieve the rings of dead Akatsuki members. Due to the role he plays, Zetsu is the only member of Akatsuki to act without a partner on a regular basis. Despite this, Zetsu serves as a sort of superior to other members, as they often report directly to him instead of the actual leader, Pain.\"}','{\"Description\": \"Zetsu is easily distinguished by two large venus fly trap-like extensions enveloping his head and upper body, giving him a plant-like appearance. When his extensions are open and his head is visible, it is revealed that Zetsu has two different colored halves of his body, the left side completely white and the right side black. To go with this, Zetsu seems to have a split personality, as in the Japanese version of the manga the black half of his face speaks only in Katakana while the white side uses Kanji and Kana, and in the English episodes the black side has a different voice actor than the white side. The two halves also converse with each other, and occasionally differ in opinion (the black half is more serious and intelligent while the white half is carefree and easygoing). They also seem to communicate with their thoughts. To further his venus fly trap theme, Zetsu is a cannibal.\", \"Description_2\": \"Zetsu is seemingly very trustworthy, being entrusted with knowledge of Pain and Tobi\'s identities. He has apparently been working with the latter for some time, Tobi first appearing as his \\\"subordinate\\\" and Zetsu later commenting that Tobi\'s plans have been in the works for a long time.\", \"Description_3\": \"Zetsu\'s main role within the Akatsuki is to function as a spy, often acting as a hunter-nin for Akatsuki. He has been shown able to move his body and take part in the tailed beasts sealing ritual imultaneously which, in addition to being unique to him, allows him to act as a lookout while the sealing takes place. When an agent to Akatsuki, or possibly even a member, dies, Zetsu is sent to devour their bodies so as to not have their secrets revealed. Zetsu is also the one sent to retrieve the rings of dead Akatsuki members. Due to the role he plays, Zetsu is the only member of Akatsuki to act without a partner on a regular basis. Despite this, Zetsu serves as a sort of superior to other members, as they often report directly to him instead of the actual leader, Pain.\"}'),(439,182621,'Zou','{\"Description\":\"Zou is a dutiful shinobi who is dedicated to the village\\u0027s well-being. Though not much has been seen of his personality, he showed anguish at not being able to protect Hiruzen during Orochimaru\\u0027s attack on Konoha.\",\"(Source\":\"Narutopedia)\"}','{\"(Source\": \"Narutopedia)\", \"Description\": \"Zou is a dutiful shinobi who is dedicated to the village\'s well-being. Though not much has been seen of his personality, he showed anguish at not being able to protect Hiruzen during Orochimaru\'s attack on Konoha.\"}'),(440,22931,'Zouri','{\"Description\":\"Zouri and his partner Waraji were hired by Gat\\u014D to be his bodyguards.\"}','{\"Description\": \"Zouri and his partner Waraji were hired by Gatō to be his bodyguards.\"}'),(441,98737,'Fujinuma, Satoru','{\"Birthdate\":\"March 2, 1977\",\"Description\":\"Satoru Fujinuma is the main protagonist of the series. In 2006, he is a 29-year-old manga artist who also works part-time as a deliveryman at Oasi Pizza. He possesses an ability he calls \\u0022Revival\\u0022 that can bring him back to a time before a life-threatening incident happens and allows him to then prevent it.\",\"Appearance\":\"\",\"Description_2\":\"Satoru is a fair-skinned man in his late 20s with messy, navy blue hair and eyes, a slim figure, and a tall stature. He often bears a blank expression and rarely smiles. He is most often seen wearing a white polo shirt, black pants, and a pair of loafers in the same color in addition to his maroon-colored prescribed glasses due to his eyesight loss as his age progressed.\",\"Description_3\":\"When he was younger, Satoru had better eyesight and habitually smiled more often. He was of average height for children his age and wore a two-toned brown windbreaker above a light blue tee, dark pants, and navy blue rubber shoes.\"}','{\"Birthdate\": \"March 2, 1977\", \"Appearance\": \"\", \"Description\": \"Satoru Fujinuma is the main protagonist of the series. In 2006, he is a 29-year-old manga artist who also works part-time as a deliveryman at Oasi Pizza. He possesses an ability he calls \\\"Revival\\\" that can bring him back to a time before a life-threatening incident happens and allows him to then prevent it.\", \"Description_2\": \"Satoru is a fair-skinned man in his late 20s with messy, navy blue hair and eyes, a slim figure, and a tall stature. He often bears a blank expression and rarely smiles. He is most often seen wearing a white polo shirt, black pants, and a pair of loafers in the same color in addition to his maroon-colored prescribed glasses due to his eyesight loss as his age progressed.\", \"Description_3\": \"When he was younger, Satoru had better eyesight and habitually smiled more often. He was of average height for children his age and wore a two-toned brown windbreaker above a light blue tee, dark pants, and navy blue rubber shoes.\"}'),(442,126756,'Hinazuki, Kayo','{\"Birthday\":\"March 2, 1977\",\"Description\":\"Kayo Hinazuki is a ten-year-old girl and the first victim of the serial killer/kidnapper. She went missing on the 2nd of March 1988. Her body was found a few days later once the snow had thawed.\"}','{\"Birthday\": \"March 2, 1977\", \"Description\": \"Kayo Hinazuki is a ten-year-old girl and the first victim of the serial killer/kidnapper. She went missing on the 2nd of March 1988. Her body was found a few days later once the snow had thawed.\"}'),(443,148965,'Akemi\'s boyfriend','{\"Description\":\"Boyfriend of Hinazuki Akemi. He didn\\u0027t care at all about her beating her own daughter, Kayo.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Boyfriend of Hinazuki Akemi. He didn\'t care at all about her beating her own daughter, Kayo.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(444,149040,'CPS female member','{\"Description\":\"A member of Ishikari Development Bureau\\u0027s Child Protective Services.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"A member of Ishikari Development Bureau\'s Child Protective Services.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(445,149041,'CPS male member','{\"Description\":\"A member of Ishikari Development Bureau\\u0027s Child Protective Services.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"A member of Ishikari Development Bureau\'s Child Protective Services.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(446,130214,'Fujinuma, Sachiko','{\"Description\":\"Sachiko is Satoru\\u0027s mother and former news announcer. She possesses a sharp eye and is quick to observe any irregularities. She knows about the cold cases of serial kidnapping in her town but decided to keep quiet and ignore it due to her child\\u0027s growth and safety.\"}','{\"Description\": \"Sachiko is Satoru\'s mother and former news announcer. She possesses a sharp eye and is quick to observe any irregularities. She knows about the cold cases of serial kidnapping in her town but decided to keep quiet and ignore it due to her child\'s growth and safety.\"}'),(447,135624,'Hamada, Kouichi','{\"Description\":\"Satoru\\u0027s rival in the ice skating race back in 1988.\"}','{\"Description\": \"Satoru\'s rival in the ice skating race back in 1988.\"}'),(448,138484,'Hinazuki, Akemi','{\"Description\":\"Akemi Hinazuki is the mother of Kayo Hinazuki. She and her boyfriend physically abuse their daughter.\"}','{\"Description\": \"Akemi Hinazuki is the mother of Kayo Hinazuki. She and her boyfriend physically abuse their daughter.\"}'),(449,137635,'Hinazuki, Grandmother','{}','{}'),(450,130213,'Katagiri, Airi','{\"Age\":\"17\",\"Description\":\"Airi is a high school student and Satoru\\u0027s co-worker at Oasi Pizza. She gets involved with Satoru when she realized oddities as Satoru managed to save people from life-threatening incidents.\"}','{\"Age\": \"17\", \"Description\": \"Airi is a high school student and Satoru\'s co-worker at Oasi Pizza. She gets involved with Satoru when she realized oddities as Satoru managed to save people from life-threatening incidents.\"}'),(451,140168,'Katagiri, Mother','{\"Description\":\"Airi Katagiri\\u0027s mother.\"}','{\"Description\": \"Airi Katagiri\'s mother.\"}'),(452,130218,'Kazu','{\"Description\":\"Kazu is Satoru\\u0027s primary school classmate. His favorite type of games is shooters. When Kenya asked if Satoru has feelings for Kayo, Kazu loudly announced that he will support Satoru and arranged his meeting with Kayo. He is quick to act without thinking.\"}','{\"Description\": \"Kazu is Satoru\'s primary school classmate. His favorite type of games is shooters. When Kenya asked if Satoru has feelings for Kayo, Kazu loudly announced that he will support Satoru and arranged his meeting with Kayo. He is quick to act without thinking.\"}'),(453,148970,'Kitamaru, Kumi','{\"Description\":\"Kitamaru Kumi is a nine-year-old girl who has leukemia. She was awaiting an operation to get bone marrow from her older sister.\"}','{\"Description\": \"Kitamaru Kumi is a nine-year-old girl who has leukemia. She was awaiting an operation to get bone marrow from her older sister.\"}'),(454,148969,'Kitamura','{\"Description\":\"The Funabashi general hospital doctor.\"}','{\"Description\": \"The Funabashi general hospital doctor.\"}'),(455,130216,'Kobayashi, Kenya','{\"Description\":\"Kenya is Satoru\\u0027s primary school classmate who has a strong sense of justice.\"}','{\"Description\": \"Kenya is Satoru\'s primary school classmate who has a strong sense of justice.\"}'),(456,138649,'Nakanishi, Aya','{\"Description\":\"Aya is a perfect student studying at Izumi Primary near to Satoru\\u0027s primary school, and is one of the original victims of serial kidnapping.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Aya is a perfect student studying at Izumi Primary near to Satoru\'s primary school, and is one of the original victims of serial kidnapping.\"}'),(457,130217,'Osamu','{\"Description\":\"Osamu is Satoru\\u0027s primary school classmate. His favorite game is Dragon Quest.\"}','{\"Description\": \"Osamu is Satoru\'s primary school classmate. His favorite game is Dragon Quest.\"}'),(458,148955,'Sasaoka, Aunt','{\"Description\":\"Aunt of Katagiri Airi. Airi lives in the house of the Sasaoka couple.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Aunt of Katagiri Airi. Airi lives in the house of the Sasaoka couple.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(459,148954,'Sasaoka, Uncle','{\"Description\":\"Uncle of Katagiri Airi. Airi lives in the house of the Sasaoka couple.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Uncle of Katagiri Airi. Airi lives in the house of the Sasaoka couple.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(460,138207,'Sawada','{\"Description\":\"Former TV reporter and acquaintance of Fujinuma Sachiko.\"}','{\"Description\": \"Former TV reporter and acquaintance of Fujinuma Sachiko.\"}'),(461,130215,'Shiratori, Jun','{\"Description\":\"Jun is a food delivery worker who lived in Satoru\\u0027s hometown and often approaches lone students around his house.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Jun is a food delivery worker who lived in Satoru\'s hometown and often approaches lone students around his house.\"}'),(462,149039,'Shiratori, Seiichiro','{\"Description\":\"Jun\\u0027s father.\"}','{\"Description\": \"Jun\'s father.\"}'),(463,130219,'Sugita, Hiromi','{\"Description\":\"Hiromi Sugita is a ten-year-old boy and the third victim of the serial killer/kidnapper. He had a girly face and a girly name and wasn\\u0027t good with people. He is also Satoru\\u0027s primary school classmate in Mikoto Elementary School.\"}','{\"Description\": \"Hiromi Sugita is a ten-year-old boy and the third victim of the serial killer/kidnapper. He had a girly face and a girly name and wasn\'t good with people. He is also Satoru\'s primary school classmate in Mikoto Elementary School.\"}'),(464,140165,'Takahashi','{\"Description\":\"Takahashi is the manager of Oasi Pizza.\",\"(Source\":\"Boku Dake ga Inai Machi Wikia)\"}','{\"(Source\": \"Boku Dake ga Inai Machi Wikia)\", \"Description\": \"Takahashi is the manager of Oasi Pizza.\"}'),(465,148953,'Urata','{\"Description\":\"Satoru\\u0027s editor in Shounen Flight.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Satoru\'s editor in Shounen Flight.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(466,139659,'Yanagihara, Misato','{\"Description\":\"A classmate of Satoru and Kayo, who dislikes Kayo and accused her of stealing the class\\u0027 lunch money. She was on bad terms with Kayo since third grade when Kayo threw her favorite mechanical pencil out of the window, because Misato kept making fun of Kayo\\u0027s pencils.\"}','{\"Description\": \"A classmate of Satoru and Kayo, who dislikes Kayo and accused her of stealing the class\' lunch money. She was on bad terms with Kayo since third grade when Kayo threw her favorite mechanical pencil out of the window, because Misato kept making fun of Kayo\'s pencils.\"}'),(467,136146,'Yashiro, Gaku','{\"Description\":\"Yashiro Gaku was Satoru\\u0027s homeroom teacher at Mikoto Elementary School in 1988.\"}','{\"Description\": \"Yashiro Gaku was Satoru\'s homeroom teacher at Mikoto Elementary School in 1988.\"}'),(468,12,'Elric, Alphonse','{\"Birthplace\":\"Resembool\",\"Date of Birth\":\"1900\",\"Age\":\"14-15 (10 at the 2003 end, 13 at movie, 17 at the manga/fmab end)\",\"Family\":\"Edward Elric (brother), Trisha Elric (mother, deceased), Van Hohenheim (father)\",\"Species\":\"Human\",\"Occupation\":\"Alchemist\",\"Abilities\":\"Alchemy, Martial Arts, High Intelligence, Highly Resistant Armor Body\",\"Weapon\":\"Fists, Alchemy\",\"Description\":\"Alphonse Elric is a human child who lost his body during a forbidden alchemical transmutation to bring his deceased mother back to life, and had his soul transmuted into a suit of armor by his brother, Edward Elric. Al\\u0027s blood seal lies just below the base of the neck at the back of the suit, on the inside. It is drawn with Ed\\u0027s blood. According to Edward, he needs to be careful whenever he reconstructs Alphonse\\u0027s body because he must keep the blood seal intact during the transmutation. If the blood seal is removed, Al\\u0027s soul will be lost.\",\"Description_2\":\"\",\"Description_3\":\"\\u0022Kindness in a can.\\u0022 - Edward Elric\",\"(Source\":\"Wikipedia)\"}','{\"Age\": \"14-15 (10 at the 2003 end, 13 at movie, 17 at the manga/fmab end)\", \"Family\": \"Edward Elric (brother), Trisha Elric (mother, deceased), Van Hohenheim (father)\", \"Weapon\": \"Fists, Alchemy\", \"(Source\": \"Wikipedia)\", \"Species\": \"Human\", \"Abilities\": \"Alchemy, Martial Arts, High Intelligence, Highly Resistant Armor Body\", \"Birthplace\": \"Resembool\", \"Occupation\": \"Alchemist\", \"Description\": \"Alphonse Elric is a human child who lost his body during a forbidden alchemical transmutation to bring his deceased mother back to life, and had his soul transmuted into a suit of armor by his brother, Edward Elric. Al\'s blood seal lies just below the base of the neck at the back of the suit, on the inside. It is drawn with Ed\'s blood. According to Edward, he needs to be careful whenever he reconstructs Alphonse\'s body because he must keep the blood seal intact during the transmutation. If the blood seal is removed, Al\'s soul will be lost.\", \"Date of Birth\": \"1900\", \"Description_2\": \"\", \"Description_3\": \"\\\"Kindness in a can.\\\" - Edward Elric\"}'),(469,11,'Elric, Edward','{\"Age\":\"15-16 (series), 18 (movie, end of the series)\",\"Birthday\":\"1899\",\"Birthplace\":\"Resembool, Amestris\",\"Family\":\"Alphonse Elric (brother), Trisha Elric (mother, deceased), Van Hohenheim (father)\",\"Affiliations\":\"State Military, Winry Rockbell, Pinako Rockbell, Izumi Curtis (teacher), Roy Mustang (Commander)\",\"Species\":\"Human\",\"Occupation\":\"State Alchemist\",\"Abilities\":\"Alchemy, Martial Arts\",\"Weapon\":\"Alchemy, Automail arm and leg\",\"Description\":\"Edward \\u0022Fullmetal Alchemist\\u0022 Elric is a young alchemical prodigy. He is the youngest State Alchemist ever to be recognized by the Amestris State Military, having received the title at the age of 12. Ed\\u0027s primary motivation throughout the series is to return his younger brother, Alphonse, to his original body, which was lost in a failed human transmutation. Edward, despite his occasional bouts of immaturity, is a selfless boy who gains a reputation as a \\u0022hero of the people\\u0022 throughout his youth. Notably, he doesn\\u0027t seem concerned about returning his own arm and leg, instead focusing entirely on Al\\u0027s suffering.\",\"Description_2\":\"Edward is small for his age, standing at only 149 cm (4\\u002711\\u0022), however, his body is that of an experienced martial artist, with noticeable muscles and a wealth of agility. Although he lacks both his right arm and left leg, Ed\\u0027s ability to fight is not impaired and is in fact improved, as he will often use alchemy to cause his metal arm to partly transform into a blade or shield. His heavy automail limbs are considered by him to be the very best in Amestris. They were made by his childhood friend, Winry Rockbell, and she is constantly working on them. He is able to think quickly, even in desperate situations, though can still be frightened into paralysis. These qualities, combined with his alchemical powers and physical strength, make him a formidable fighter.\",\"Description_3\":\"Born to Trisha Elric and Van Hohenheim of Resembool in the winter of 1899, Edward\\u0027s first few years were relatively happy; but after the sudden departure of his father during the lad\\u0027s formative years, Ed was left with his mother and younger brother Alphonse as his only family. The three Elrics lived in peace in the rural village and the boys began displaying a remarkable talent for alchemy at a young age, much to the joyful astonishment of his mother. However, early in the year 1904, Trisha contracted an illness that had been spreading in the area and died, leaving her two sons orphaned. Even while mourning, mired in grief, Edward vowed to his brother that the two of them would find a way to bring their dead mother back to life with the power of alchemy.\",\"Description_4\":\"Edward and Alphonse spent the next few years living on their own in the Elric family home, supported by their close childhood friend Winry Rockbell and her grandmother Pinako, and pursuing the alchemical knowledge necessary for their planned resurrection. Although they had gained a great deal of information and comprehension regarding the extended basics of the craft, before long it became apparent to the young prodigies that there was only so far they could go while being self-taught. In a stroke of good fortune, Resembool was visited by an exceptionally skilled alchemist named Izumi Curtis who, after some persuasion, agreed to take the Elric brothers on as her apprentices provided they pass a preliminary test. After they do, the Elric brothers were subjected to Izumi\\u0027s intensive alchemy and martial arts training, growing significantly in both mind and body and gaining a great deal of alchemical knowledge before returning to Resembool.\",\"Description_5\":\"Though instructed specifically by Izumi to understand that death is an irreversible part of the flow of the world and that acceptance of such is important to the \\u0022One is All, All is One\\u0022 concept, the boys dove headlong into their plan to resurrect their mother upon their homecoming, having advanced their knowledge while abroad and discovered the basics of a forbidden practice called Human Transmutation.\",\"Description_6\":\"Devising a Human Transmutation Circle, amassing the elemental ingredients for an adult human body and offering their own blood as soul and biological data, the boys secretly initiated the Human Transmutation in their home. Unfortunately, the Human Transmutation resulted in a Rebound.\",\"Description_7\":\"Alphonse and Edward were pulled into The Gate. Encountering the mysterious being called Truth, Edward was stripped of his left leg in exchange for crossing into God\\u0027s domain and peeking at the Gate\\u0027s vast wealth of alchemical knowledge. Maimed and bleeding, Edward was returned to the human dimension to find that Alphonse had not yet returned from his disappearance into the Gate, that the mother they had attempted to revive was a grotesque mass of organs only capable of sustaining life for a few moments and that his own sojourn into the Gate had granted him the curious ability to perform transmutations merely by clapping his hands together, without the aid of a Transmutation Circle - in the same style used by Izumi. Desperate to at least have his brother by his side, Edward willfully performed another Human Transmutation to call him back, this time sacrificing his right arm in exchange for Al\\u0027s soul, which he bound alchemically to an antique suit of armor with a Blood Rune before passing out from severe blood loss. Alphonse carried Ed to the Rockbell house, where a shocked Pinako and Winry performed emergency surgery to save the young boy\\u0027s life.\",\"Description_8\":\"On the night of the failed transmutation. Lt. Colonel Flame Alchemist Roy Mustang came to the Rockbell\\u0027s in response to a letter that Edward and Alphonse had sent him in the mail asking about their Father. He was shocked at the fact that the two boys had tried human alchemy and survived, and informed them that they could become state alchemist and maybe one day find a way to return their bodies to the way they were. Desperate to get His younger brother\\u0027s body back, Edward asked the Rockbells to give him prosthetic limbs called automail. Though they warned him the surgery would be painful, he said the pain was nothing compared to what his brother had given up. He only took a year to adapt to the automail at age 11 when it took most adults three years.\"}','{\"Age\": \"15-16 (series), 18 (movie, end of the series)\", \"Family\": \"Alphonse Elric (brother), Trisha Elric (mother, deceased), Van Hohenheim (father)\", \"Weapon\": \"Alchemy, Automail arm and leg\", \"Species\": \"Human\", \"Birthday\": \"1899\", \"Abilities\": \"Alchemy, Martial Arts\", \"Birthplace\": \"Resembool, Amestris\", \"Occupation\": \"State Alchemist\", \"Description\": \"Edward \\\"Fullmetal Alchemist\\\" Elric is a young alchemical prodigy. He is the youngest State Alchemist ever to be recognized by the Amestris State Military, having received the title at the age of 12. Ed\'s primary motivation throughout the series is to return his younger brother, Alphonse, to his original body, which was lost in a failed human transmutation. Edward, despite his occasional bouts of immaturity, is a selfless boy who gains a reputation as a \\\"hero of the people\\\" throughout his youth. Notably, he doesn\'t seem concerned about returning his own arm and leg, instead focusing entirely on Al\'s suffering.\", \"Affiliations\": \"State Military, Winry Rockbell, Pinako Rockbell, Izumi Curtis (teacher), Roy Mustang (Commander)\", \"Description_2\": \"Edward is small for his age, standing at only 149 cm (4\'11\\\"), however, his body is that of an experienced martial artist, with noticeable muscles and a wealth of agility. Although he lacks both his right arm and left leg, Ed\'s ability to fight is not impaired and is in fact improved, as he will often use alchemy to cause his metal arm to partly transform into a blade or shield. His heavy automail limbs are considered by him to be the very best in Amestris. They were made by his childhood friend, Winry Rockbell, and she is constantly working on them. He is able to think quickly, even in desperate situations, though can still be frightened into paralysis. These qualities, combined with his alchemical powers and physical strength, make him a formidable fighter.\", \"Description_3\": \"Born to Trisha Elric and Van Hohenheim of Resembool in the winter of 1899, Edward\'s first few years were relatively happy; but after the sudden departure of his father during the lad\'s formative years, Ed was left with his mother and younger brother Alphonse as his only family. The three Elrics lived in peace in the rural village and the boys began displaying a remarkable talent for alchemy at a young age, much to the joyful astonishment of his mother. However, early in the year 1904, Trisha contracted an illness that had been spreading in the area and died, leaving her two sons orphaned. Even while mourning, mired in grief, Edward vowed to his brother that the two of them would find a way to bring their dead mother back to life with the power of alchemy.\", \"Description_4\": \"Edward and Alphonse spent the next few years living on their own in the Elric family home, supported by their close childhood friend Winry Rockbell and her grandmother Pinako, and pursuing the alchemical knowledge necessary for their planned resurrection. Although they had gained a great deal of information and comprehension regarding the extended basics of the craft, before long it became apparent to the young prodigies that there was only so far they could go while being self-taught. In a stroke of good fortune, Resembool was visited by an exceptionally skilled alchemist named Izumi Curtis who, after some persuasion, agreed to take the Elric brothers on as her apprentices provided they pass a preliminary test. After they do, the Elric brothers were subjected to Izumi\'s intensive alchemy and martial arts training, growing significantly in both mind and body and gaining a great deal of alchemical knowledge before returning to Resembool.\", \"Description_5\": \"Though instructed specifically by Izumi to understand that death is an irreversible part of the flow of the world and that acceptance of such is important to the \\\"One is All, All is One\\\" concept, the boys dove headlong into their plan to resurrect their mother upon their homecoming, having advanced their knowledge while abroad and discovered the basics of a forbidden practice called Human Transmutation.\", \"Description_6\": \"Devising a Human Transmutation Circle, amassing the elemental ingredients for an adult human body and offering their own blood as soul and biological data, the boys secretly initiated the Human Transmutation in their home. Unfortunately, the Human Transmutation resulted in a Rebound.\", \"Description_7\": \"Alphonse and Edward were pulled into The Gate. Encountering the mysterious being called Truth, Edward was stripped of his left leg in exchange for crossing into God\'s domain and peeking at the Gate\'s vast wealth of alchemical knowledge. Maimed and bleeding, Edward was returned to the human dimension to find that Alphonse had not yet returned from his disappearance into the Gate, that the mother they had attempted to revive was a grotesque mass of organs only capable of sustaining life for a few moments and that his own sojourn into the Gate had granted him the curious ability to perform transmutations merely by clapping his hands together, without the aid of a Transmutation Circle - in the same style used by Izumi. Desperate to at least have his brother by his side, Edward willfully performed another Human Transmutation to call him back, this time sacrificing his right arm in exchange for Al\'s soul, which he bound alchemically to an antique suit of armor with a Blood Rune before passing out from severe blood loss. Alphonse carried Ed to the Rockbell house, where a shocked Pinako and Winry performed emergency surgery to save the young boy\'s life.\", \"Description_8\": \"On the night of the failed transmutation. Lt. Colonel Flame Alchemist Roy Mustang came to the Rockbell\'s in response to a letter that Edward and Alphonse had sent him in the mail asking about their Father. He was shocked at the fact that the two boys had tried human alchemy and survived, and informed them that they could become state alchemist and maybe one day find a way to return their bodies to the way they were. Desperate to get His younger brother\'s body back, Edward asked the Rockbells to give him prosthetic limbs called automail. Though they warned him the surgery would be painful, he said the pain was nothing compared to what his brother had given up. He only took a year to adapt to the automail at age 11 when it took most adults three years.\"}'),(470,246172,'Armstrong, Mother','{}','{}'),(471,3934,'Armstrong, Olivier Mira','{\"Species\":\"Human\",\"Occupation\":\"Military Officer, Briggs General\",\"Weapon\":\"A family heirloom sword\",\"Known relatives\":\"Philip Gargantos Armstrong (father), Mrs. Armstrong (mother) Alex Louis Armstrong (younger brother), Catherine Elle Armstrong (youngest sister), Amue Armstrong (younger sister), Strongine Armstrong (younger sister)\",\"Description\":\"Major General Olivier Mira Armstrong is Alex Louis Armstrong\\u0027s older sister. She is in charge of Briggs, the northern military border. She scoffs at the concept of \\u0022equivalent exchange\\u0022 and believes \\u0022survival of the fittest\\u0022 is the only law in life. Her subordinates are loyal, but if it ensured the survival of Briggs (or for the sake of the greater good), they are instructed to leave her to die if ever the need arose, and she wouldn\\u0027t hold it against them.\",\"Description_2\":\"Being the General of Briggs, Olivier has full command of the Fortress. She is also very skilled with her family heirloom sword which she uses unhesitatingly. She also seems to have some proficiency with tanks and artillery.\"}','{\"Weapon\": \"A family heirloom sword\", \"Species\": \"Human\", \"Occupation\": \"Military Officer, Briggs General\", \"Description\": \"Major General Olivier Mira Armstrong is Alex Louis Armstrong\'s older sister. She is in charge of Briggs, the northern military border. She scoffs at the concept of \\\"equivalent exchange\\\" and believes \\\"survival of the fittest\\\" is the only law in life. Her subordinates are loyal, but if it ensured the survival of Briggs (or for the sake of the greater good), they are instructed to leave her to die if ever the need arose, and she wouldn\'t hold it against them.\", \"Description_2\": \"Being the General of Briggs, Olivier has full command of the Fortress. She is also very skilled with her family heirloom sword which she uses unhesitatingly. She also seems to have some proficiency with tanks and artillery.\", \"Known relatives\": \"Philip Gargantos Armstrong (father), Mrs. Armstrong (mother) Alex Louis Armstrong (younger brother), Catherine Elle Armstrong (youngest sister), Amue Armstrong (younger sister), Strongine Armstrong (younger sister)\"}'),(472,2079,'Armstrong, Alex Louis','{\"Description\":\"Major Alex Louis Armstrong, the Strong Arm Alchemist, was born into an elite family of alchemists and has mastered his family\\u0027s techniques. Members of his family have, in the past, filled the highest military and political positions in the state. He acquired his alchemy titles for his skill of using arm strength in his alchemy. All though he may look intimidating, he is really friendly and (overly)affectionate, and often stays behind or risks his life for the safety of others. He also has a tendency to show off techniques passed down to him to his enemies, and make them feel somewhat awkward during a battle.\",\"Description_2\":\"The scion of the illustrious Armstrong family, Alex is a remarkably caring commander and friend as well as an invaluably skilled ally to Colonel Roy Mustang and Edward Elric.\"}','{\"Description\": \"Major Alex Louis Armstrong, the Strong Arm Alchemist, was born into an elite family of alchemists and has mastered his family\'s techniques. Members of his family have, in the past, filled the highest military and political positions in the state. He acquired his alchemy titles for his skill of using arm strength in his alchemy. All though he may look intimidating, he is really friendly and (overly)affectionate, and often stays behind or risks his life for the safety of others. He also has a tendency to show off techniques passed down to him to his enemies, and make them feel somewhat awkward during a battle.\", \"Description_2\": \"The scion of the illustrious Armstrong family, Alex is a remarkably caring commander and friend as well as an invaluably skilled ally to Colonel Roy Mustang and Edward Elric.\"}'),(473,55287,'Armstrong, Philip Gargantos','{\"Description\":\"Former General Philip Gargantos Armstrong is is the current head of the illustrious Armstrong family, father to Major Alex Louis Armstrong, Major General Olivier Mira Armstrong, and their younger sisters Amue, Strongine, and Kathleen Elle. His wife\\u0027s name is not known.\",\"Description_2\":\"A bit of a windbag, Philip enjoys relating stories of his family\\u0027s grandeur and his own eventful military career to anyone unfortunate enough to become his captive audience, and seems to have passed on this family pride to Alex.\",\"Description_3\":\"Being a former General, it would seem that Philip is a rather insightful man, quickly understanding from Oliver\\u0027s demands for the Armstrong estate that Amestris was no longer safe, and taking his wife and daughter Kathleen off to Xing on an \\u0022extended vacation\\u0022.\",\"(Source\":\"The Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"The Fullmetal Alchemist Wikia)\", \"Description\": \"Former General Philip Gargantos Armstrong is is the current head of the illustrious Armstrong family, father to Major Alex Louis Armstrong, Major General Olivier Mira Armstrong, and their younger sisters Amue, Strongine, and Kathleen Elle. His wife\'s name is not known.\", \"Description_2\": \"A bit of a windbag, Philip enjoys relating stories of his family\'s grandeur and his own eventful military career to anyone unfortunate enough to become his captive audience, and seems to have passed on this family pride to Alex.\", \"Description_3\": \"Being a former General, it would seem that Philip is a rather insightful man, quickly understanding from Oliver\'s demands for the Armstrong estate that Amestris was no longer safe, and taking his wife and daughter Kathleen off to Xing on an \\\"extended vacation\\\".\"}'),(474,20592,'Armstrong, Kathleen Elle','{\"Description\":\"Major Armstrong\\u0027s sister. She likes to lift pianos and dreams of having a boyfriend who\\u0027s as strong as her brother. Her appearance is different from the rest of her family since she looks rather cute.\"}','{\"Description\": \"Major Armstrong\'s sister. She likes to lift pianos and dreams of having a boyfriend who\'s as strong as her brother. Her appearance is different from the rest of her family since she looks rather cute.\"}'),(475,5428,'Barry the Chopper','{\"Description\":\"A butcher who uses the disguise of a female so he can abduct women.\",\"Manga\":\"\",\"Description_2\":\"A wanted serial killer and later an experiment in 5th laboratory. He falls in love with Riza when she was out grocery shopping in vol. 7. By that, he was caught by the military. He later helped Maria Ross escape from prison.\",\"Description_3\":\"In the original anime,\",\"Description_4\":\"\\u0022I kill, therefore I am.\\u0022 ~ Episode 21\"}','{\"Manga\": \"\", \"Description\": \"A butcher who uses the disguise of a female so he can abduct women.\", \"Description_2\": \"A wanted serial killer and later an experiment in 5th laboratory. He falls in love with Riza when she was out grocery shopping in vol. 7. By that, he was caught by the military. He later helped Maria Ross escape from prison.\", \"Description_3\": \"In the original anime,\", \"Description_4\": \"\\\"I kill, therefore I am.\\\" ~ Episode 21\"}'),(476,10968,'Bido','{\"Description\":\"Bido was a chimera created in the Fifth Laboratory; after escaping it, he followed the homunculus Greed. Before his transmutation, he was a member of Martel\\u0027s military special ops team which instigated the Ishval revolt. He was fused with a lizard or a gecko; this enabled him to have a firm grip on surfaces when climbing, and to use his tail as a bludgeoning weapon. He is bald and speaks in a raspy, hacksaw voice, though it\\u0027s unclear whether this is a result of the fusion or not.\"}','{\"Description\": \"Bido was a chimera created in the Fifth Laboratory; after escaping it, he followed the homunculus Greed. Before his transmutation, he was a member of Martel\'s military special ops team which instigated the Ishval revolt. He was fused with a lizard or a gecko; this enabled him to have a firm grip on surfaces when climbing, and to use his tail as a bludgeoning weapon. He is bald and speaks in a raspy, hacksaw voice, though it\'s unclear whether this is a result of the fusion or not.\"}'),(477,7203,'Black Hayate','{\"Description\":\"Lt. Hawkeye\\u0027s pet dog.\"}','{\"Description\": \"Lt. Hawkeye\'s pet dog.\"}'),(478,183599,'Bobby','{\"Description\":\"Bobby is an engineer at Fort Briggs who is working order under the command of Major General Armstrong.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Bobby is an engineer at Fort Briggs who is working order under the command of Major General Armstrong.\"}'),(479,5103,'Bradley, King','{\"Description\":\"King Bradley is the F\\u00FChrer of the Amestris state military and has all state alchemist under his direct command. King Bradley almost always maintains a kind and calm demeanor even when issuing orders to engage in battle. This trait often confuses his subordinates, and Roy Mustang admits that he \\u0022can\\u0027t figure the guy out.\\u0022 King Bradley has a son, Selim, and an unnamed wife.\",\"Description_2\":\"In the 2003 anime series, the F\\u00FChrer maintains his role as the president of the country. Although he is a carefree man, he has a mind like a steel trap and his personality can change rapidly. It was he who finished the Ishval Civil War by sending in the State Alchemists to end it.\",\"Description_3\":\"In the manga and 2009 anime series, he has a slightly strange sense of humor and has a habit of doing rather odd things for someone of his status. Such things as joking with his subordinates, dressing-up as a tourist while visiting Dublith to meet Izumi Curtis, giving watermelons as gifts to Edward Elric, ditching work to meet the brothers in the hospital, and jumping out of a window to get away from his attendants.\",\"(Source\":\"Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"Fullmetal Alchemist Wikia)\", \"Description\": \"King Bradley is the Führer of the Amestris state military and has all state alchemist under his direct command. King Bradley almost always maintains a kind and calm demeanor even when issuing orders to engage in battle. This trait often confuses his subordinates, and Roy Mustang admits that he \\\"can\'t figure the guy out.\\\" King Bradley has a son, Selim, and an unnamed wife.\", \"Description_2\": \"In the 2003 anime series, the Führer maintains his role as the president of the country. Although he is a carefree man, he has a mind like a steel trap and his personality can change rapidly. It was he who finished the Ishval Civil War by sending in the State Alchemists to end it.\", \"Description_3\": \"In the manga and 2009 anime series, he has a slightly strange sense of humor and has a habit of doing rather odd things for someone of his status. Such things as joking with his subordinates, dressing-up as a tourist while visiting Dublith to meet Izumi Curtis, giving watermelons as gifts to Edward Elric, ditching work to meet the brothers in the hospital, and jumping out of a window to get away from his attendants.\"}'),(480,34689,'Bradley, Mrs.','{\"Description\":\"Mrs. Bradley is the wife of the Fuhrer, King Bradley. A kind and trusting wife. Though she rarely appears in either series, usually accompanying Selim, Mrs. Bradley\\u0027s appearances usually fall under the category of comic relief as she speaks jovially of her familial life and romantic past with the Fuhrer.\"}','{\"Description\": \"Mrs. Bradley is the wife of the Fuhrer, King Bradley. A kind and trusting wife. Though she rarely appears in either series, usually accompanying Selim, Mrs. Bradley\'s appearances usually fall under the category of comic relief as she speaks jovially of her familial life and romantic past with the Fuhrer.\"}'),(481,10982,'Bradley, Selim','{\"Description\":\"Selim Bradley is the son of F\\u00FChrer King Bradley.\",\"Description_2\":\"In the manga and 2009 anime series, Selim is the F\\u00FChrer\\u0027s sprightly son. He frequently asks his father to tell him stories from the battlefront and interesting anecdotes from his everyday events. Selim professes a desire to become a State Alchemist so as to be more useful to the F\\u00FChrer and is a self-professed fan of Edward Elric.\",\"(Source\":\"FMA Wikia)\"}','{\"(Source\": \"FMA Wikia)\", \"Description\": \"Selim Bradley is the son of Führer King Bradley.\", \"Description_2\": \"In the manga and 2009 anime series, Selim is the Führer\'s sprightly son. He frequently asks his father to tell him stories from the battlefront and interesting anecdotes from his everyday events. Selim professes a desire to become a State Alchemist so as to be more useful to the Führer and is a self-professed fan of Edward Elric.\"}'),(482,16648,'Breda, Heymans','{\"Description\":\"Heymans Breda is one of Roy Mustang\\u0027s most trusted subordinates. He was recruited by Mustang for his high level of intelligence, indicated by his talent with chess and other strategy games. Despite his intelligence, he still has an irrational fear of dogs. Breda is usually tasked by Mustang with jobs that require he travel abroad. In the course of doing so he uses up all of his days off, showing his dedication to Mustang. He is transferred to Western Headquarters when Mustang\\u0027s group is broken up by the homunculi. In the manga, he eventually defects from the military so that he can help Mustang overthrow King Bradley.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Heymans Breda is one of Roy Mustang\'s most trusted subordinates. He was recruited by Mustang for his high level of intelligence, indicated by his talent with chess and other strategy games. Despite his intelligence, he still has an irrational fear of dogs. Breda is usually tasked by Mustang with jobs that require he travel abroad. In the course of doing so he uses up all of his days off, showing his dedication to Mustang. He is transferred to Western Headquarters when Mustang\'s group is broken up by the homunculi. In the manga, he eventually defects from the military so that he can help Mustang overthrow King Bradley.\"}'),(483,261291,'Briggs Doctor','{\"Description\":\"She is a doctor and automail engineer at Fort Briggs.\",\"Description_2\":\"An expert in the cold\\u0027s effect on the human body as well as in cold climate automail, she is vital to the continued health and well-being of the soldiers of Briggs, and by extension the fort itself. It is likely that she worked on the development of Buccaneer\\u0027s Modified M1910 and Heavy Combat M1913-A limbs alongside Neil.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"She is a doctor and automail engineer at Fort Briggs.\", \"Description_2\": \"An expert in the cold\'s effect on the human body as well as in cold climate automail, she is vital to the continued health and well-being of the soldiers of Briggs, and by extension the fort itself. It is likely that she worked on the development of Buccaneer\'s Modified M1910 and Heavy Combat M1913-A limbs alongside Neil.\"}'),(484,23106,'Brosh, Denny','{\"Description\":\"Denny Brosh is the partner of Maria Ross. He is rather nosy and lazy, and has an enormous infatuation with his partner. He is very sensitive to criticism, and will fall into despair at the slightest insult. Both he and Ross are introduced when they are assigned to protect Edward Elric.[77] In the anime, Brosh later appears in the rebellion against King Bradley, saving various characters from execution. In the manga, he appears again after Ross\\u0027s apparent death. Though he is deeply saddened by the news, Ross feels it is for the best that he not know she is alive, as he has difficulty hiding his emotions. When Roy Mustang begins waging an assault on Central, Brosh rushes into the city to provide assistance. (Wiki)\"}','{\"Description\": \"Denny Brosh is the partner of Maria Ross. He is rather nosy and lazy, and has an enormous infatuation with his partner. He is very sensitive to criticism, and will fall into despair at the slightest insult. Both he and Ross are introduced when they are assigned to protect Edward Elric.[77] In the anime, Brosh later appears in the rebellion against King Bradley, saving various characters from execution. In the manga, he appears again after Ross\'s apparent death. Though he is deeply saddened by the news, Ross feels it is for the best that he not know she is alive, as he has difficulty hiding his emotions. When Roy Mustang begins waging an assault on Central, Brosh rushes into the city to provide assistance. (Wiki)\"}'),(485,15541,'Buccaneer','{\"Description\":\"Captain Buccaneer is an Amestrian State Military Officer stationed at Fort Briggs and a close subordinate of Major General Olivier Mira Armstrong.\",\"Description_2\":\"Abrasive and suspicious, Buccaneer is often one to strike first and ask questions later, in fitting with the Briggs mindset of \\u0022Survival of the Fittest\\u0022, and seems to enjoy violence and combat, often using vicious animal metaphors in his speech. He is loath to trust strangers and does not hold back in dealing out harsh treatment to people with whom he is unfamiliar.\",\"Description_3\":\"Despite this, Buccaneer is an incredibly brave and loyal soldier and shows his more jovial side to those whom he calls \\u0022comrade\\u0022.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Captain Buccaneer is an Amestrian State Military Officer stationed at Fort Briggs and a close subordinate of Major General Olivier Mira Armstrong.\", \"Description_2\": \"Abrasive and suspicious, Buccaneer is often one to strike first and ask questions later, in fitting with the Briggs mindset of \\\"Survival of the Fittest\\\", and seems to enjoy violence and combat, often using vicious animal metaphors in his speech. He is loath to trust strangers and does not hold back in dealing out harsh treatment to people with whom he is unfamiliar.\", \"Description_3\": \"Despite this, Buccaneer is an incredibly brave and loyal soldier and shows his more jovial side to those whom he calls \\\"comrade\\\".\"}'),(486,17103,'Catalina, Rebecca','{\"Description\":\"Second Lieutenant Rebecca Catalina is a soldier under the command of Lieutenant General Grumman at the East City Headquarters and a close friend of Riza Hawkeye.\",\"Description_2\":\"Though an exceptionally skilled soldier with combat abilities on par with Hawkeye and Havoc, Rebecca\\u0027s true ambitions appear to lie with in the marital realm, as she spends much of her time complaining about her single life and trying to get Riza to help her find a man. She declares, after Hawkeye mocks her, that she hopes to \\u0022land a real hunk and retire early\\u0022 from the military.\",\"(Source\":\"Wiki)\"}','{\"(Source\": \"Wiki)\", \"Description\": \"Second Lieutenant Rebecca Catalina is a soldier under the command of Lieutenant General Grumman at the East City Headquarters and a close friend of Riza Hawkeye.\", \"Description_2\": \"Though an exceptionally skilled soldier with combat abilities on par with Hawkeye and Havoc, Rebecca\'s true ambitions appear to lie with in the marital realm, as she spends much of her time complaining about her single life and trying to get Riza to help her find a man. She declares, after Hawkeye mocks her, that she hopes to \\\"land a real hunk and retire early\\\" from the military.\"}'),(487,15532,'Chang, Mei','{\"Gender\":\"Female\",\"Age\":\"\\u224811\",\"Height\":\"\\u22484\\u00273\\u0022, (130 cm)\",\"Birthplace\":\"Xing\",\"Description\":\"The seventeenth princess of Xing, who like Ling Yao, has been tasked with travelling to Amestris to find the secret to immortality. She\\u0027s determined to reach her goal, so she can help her struggling clan.\",\"Description_2\":\"She travels with her pet panda, Xiao-Mei. Adept at Xing\\u0027s style of alchemy, called Alkahestry, she uses kunai to arrange transmutation circles in order to manipulate targets at long range. She\\u0027s also skilled at martial arts, and she can sense the chi of humans and the homunculi.\",\"Description_3\":\"She starts off as a big fan of Edward Elric, and imagines him as her prince. However, her image of him is shattered when she meets him in person. After this, she falls in love with Edward\\u0027s brother, Alphonse instead. She also forms an allience with Scar, despite the man\\u0027s violent past.\"}','{\"Age\": \"≈11\", \"Gender\": \"Female\", \"Height\": \"≈4\'3\\\", (130 cm)\", \"Birthplace\": \"Xing\", \"Description\": \"The seventeenth princess of Xing, who like Ling Yao, has been tasked with travelling to Amestris to find the secret to immortality. She\'s determined to reach her goal, so she can help her struggling clan.\", \"Description_2\": \"She travels with her pet panda, Xiao-Mei. Adept at Xing\'s style of alchemy, called Alkahestry, she uses kunai to arrange transmutation circles in order to manipulate targets at long range. She\'s also skilled at martial arts, and she can sense the chi of humans and the homunculi.\", \"Description_3\": \"She starts off as a big fan of Edward Elric, and imagines him as her prince. However, her image of him is shattered when she meets him in person. After this, she falls in love with Edward\'s brother, Alphonse instead. She also forms an allience with Scar, despite the man\'s violent past.\"}'),(488,50123,'Charlie','{\"Description\":\"The man who introduces himself as Charlie was an enlisted soldier under the command of the Flame Alchemist, Roy Mustang during the Ishval Civil War. When the long fighting finally ceased, Charlie brought it upon himself to speak to his distant commander and thank him for all the work he had done to keep all the men beneath him out of harm\\u0027s way.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"The man who introduces himself as Charlie was an enlisted soldier under the command of the Flame Alchemist, Roy Mustang during the Ishval Civil War. When the long fighting finally ceased, Charlie brought it upon himself to speak to his distant commander and thank him for all the work he had done to keep all the men beneath him out of harm\'s way.\"}'),(489,261152,'Clemin','{\"Description\":\"Brigadier General Clemin was a member of the Amestrian Military Command and as such, is in on Father\\u0027s plan for The Promised Day and has secretly sold out his country for the sake of his own immortality.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Brigadier General Clemin was a member of the Amestrian Military Command and as such, is in on Father\'s plan for The Promised Day and has secretly sold out his country for the sake of his own immortality.\"}'),(490,169503,'Comanche, Giolio','{\"Description\":\"Giolio Comanche, known as the Silver Alchemist, is an elderly, diminutive man whose thirst for battle is belied by his grandfatherly countenance.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Giolio Comanche, known as the Silver Alchemist, is an elderly, diminutive man whose thirst for battle is belied by his grandfatherly countenance.\"}'),(491,10944,'Cornello','{\"Description\":\"Cornello is a low-rate alchemist and a fraud. He uses what he thinks is the Philosopher\\u0027s Stone to fool the people of Lior into thinking that he is sent by the Sun God Leto with the power to perform miracles, including resurrecting the dead. Although he uses alchemy to bring prosperity to the desert city, his true intention is to convert the citizens into a fanatical army. The Elric brothers expose him for a fraud, and shortly afterward the incomplete Philosopher\\u0027s Stone becomes unstable and shatters as it tears his arm into a mass of flesh and metal.\",\"Description_2\":\"After the Elrics undermine his plan and Cornello is no longer of any use to the Homunculi, he is consumed by Gluttony. Envy, disguised as Cornello, maintains the deception until Lior is subjugated by the State Military. In the manga, Lust tells Gluttony he\\u0027d be better off not eating a fourth-rate fraud like Cornello, and kills him herself. Gluttony eats Cornello\\u0027s dead body afterwards, Lust replying to Gluttony rather annoyed, \\u0022I thought I told you not to eat that.\\u0022\"}','{\"Description\": \"Cornello is a low-rate alchemist and a fraud. He uses what he thinks is the Philosopher\'s Stone to fool the people of Lior into thinking that he is sent by the Sun God Leto with the power to perform miracles, including resurrecting the dead. Although he uses alchemy to bring prosperity to the desert city, his true intention is to convert the citizens into a fanatical army. The Elric brothers expose him for a fraud, and shortly afterward the incomplete Philosopher\'s Stone becomes unstable and shatters as it tears his arm into a mass of flesh and metal.\", \"Description_2\": \"After the Elrics undermine his plan and Cornello is no longer of any use to the Homunculi, he is consumed by Gluttony. Envy, disguised as Cornello, maintains the deception until Lior is subjugated by the State Military. In the manga, Lust tells Gluttony he\'d be better off not eating a fourth-rate fraud like Cornello, and kills him herself. Gluttony eats Cornello\'s dead body afterwards, Lust replying to Gluttony rather annoyed, \\\"I thought I told you not to eat that.\\\"\"}'),(492,10948,'Cray','{\"Description\":\"He was Father Cornello\\u0027s right-hand man and a devout follower of his religion. Shortly after Ed and Al\\u0027s arrival in Lior, Cornello explained to Cray that Ed was in fact a State Alchemist, and was most likely in Lior for reconnaissance purposes. Consequently, Cornello ordered Cray to eliminate the Elrics in the name of their god, but he failed when a shot meant to take off Alphonse\\u0027s head only revealed his empty armor. During the siege of Lior, Cray was devoured by Gluttony when he looked for Cornello and found the Homunculi instead.\",\"Description_2\":\"Cray\\u0027s skeleton can be seen in Gluttony\\u0027s stomach near the end of chapter 50.\"}','{\"Description\": \"He was Father Cornello\'s right-hand man and a devout follower of his religion. Shortly after Ed and Al\'s arrival in Lior, Cornello explained to Cray that Ed was in fact a State Alchemist, and was most likely in Lior for reconnaissance purposes. Consequently, Cornello ordered Cray to eliminate the Elrics in the name of their god, but he failed when a shot meant to take off Alphonse\'s head only revealed his empty armor. During the siege of Lior, Cray was devoured by Gluttony when he looked for Cornello and found the Homunculi instead.\", \"Description_2\": \"Cray\'s skeleton can be seen in Gluttony\'s stomach near the end of chapter 50.\"}'),(493,67,'Curtis, Izumi','{\"Izumi Curtis, born Izumi Harnet, the teacher of Ed and Alphonse Elric, agreed to train the brothers to hone their alchemical abilities after their mother died. She expands their training with a regimen of philosophy, martial arts, and living off the land. Her methods are derived from her own alchemy training\":\"in the manga and second anime, she was forced to survive in the northern region surrounding Briggs Fortress for a month (although it turns out she succeeded by stealing supplies from the northern fortress), whereas in the first anime she was taught by Dante. She thinks of the Elrics as her own sons, and although she severs her student-teacher ties with them after learning of their attempts with human transmutation (and similarly Ed\\u0027s joining the State Military), she continues to do all she can to help them. She can be quite violent when punishing or sparring with the Elric brothers, so they tend to be deathly afraid of her. Her claim of \\u0022I\\u0027m a housewife!\\u0022 while confronting Greed was a favorite scene of Arakawa\\u0027s to draw.\",\"Description\":\"Izumi and her husband Sig Curtis were expecting a child years before the start of the series; however, their son was stillborn. Izumi tried and failed to revive the child through human transmutation (an act that created Wrath in the first anime). The failed attempt took some of her internal organs, resulting in infertility, and causing her to periodically cough up blood. Izumi gained the ability to use alchemy without a transmutation circle after seeing the \\u0022truth.\\u0022\",\"Description_2\":\"In the manga, Izumi attracts the attention of the State Military for surviving the failed human transmutation. As she and her husband travel around Amestris in order to avoid the military, they eventually meet Ed and Al\\u0027s father Hohenheim. He rearranges her insides to ease the blood flow, and persuades her to help collaborate in bringing down the State Military.\"}','{\"Description\": \"Izumi and her husband Sig Curtis were expecting a child years before the start of the series; however, their son was stillborn. Izumi tried and failed to revive the child through human transmutation (an act that created Wrath in the first anime). The failed attempt took some of her internal organs, resulting in infertility, and causing her to periodically cough up blood. Izumi gained the ability to use alchemy without a transmutation circle after seeing the \\\"truth.\\\"\", \"Description_2\": \"In the manga, Izumi attracts the attention of the State Military for surviving the failed human transmutation. As she and her husband travel around Amestris in order to avoid the military, they eventually meet Ed and Al\'s father Hohenheim. He rearranges her insides to ease the blood flow, and persuades her to help collaborate in bringing down the State Military.\", \"Izumi Curtis, born Izumi Harnet, the teacher of Ed and Alphonse Elric, agreed to train the brothers to hone their alchemical abilities after their mother died. She expands their training with a regimen of philosophy, martial arts, and living off the land. Her methods are derived from her own alchemy training\": \"in the manga and second anime, she was forced to survive in the northern region surrounding Briggs Fortress for a month (although it turns out she succeeded by stealing supplies from the northern fortress), whereas in the first anime she was taught by Dante. She thinks of the Elrics as her own sons, and although she severs her student-teacher ties with them after learning of their attempts with human transmutation (and similarly Ed\'s joining the State Military), she continues to do all she can to help them. She can be quite violent when punishing or sparring with the Elric brothers, so they tend to be deathly afraid of her. Her claim of \\\"I\'m a housewife!\\\" while confronting Greed was a favorite scene of Arakawa\'s to draw.\"}'),(494,10972,'Curtis, Sig','{\"Description\":\"The husband of Izumi Curtis, an enormous muscular man who works as a butcher in the town of Dublith. He is a man of few words and does not question the judgment of his beloved wife, even after she tried to resurrect their infant son when the child died.\",\"Description_2\":\"Like Izumi, he cares deeply for the Elric brothers and also dislikes the military. In the manga, when greeted by Fuhrer King Bradley, he ignores the Fuhrer\\u0027s inquiries and offer for Izumi to become a State Alchemist, but ends up befriending Major Alex Louis Armstrong in a muscle flexing contest. Strangely, in one episode of the anime, he is seen sleeping with both eyes open.\",\"Description_3\":\"He also becomes friends with Winry Rockbell.\"}','{\"Description\": \"The husband of Izumi Curtis, an enormous muscular man who works as a butcher in the town of Dublith. He is a man of few words and does not question the judgment of his beloved wife, even after she tried to resurrect their infant son when the child died.\", \"Description_2\": \"Like Izumi, he cares deeply for the Elric brothers and also dislikes the military. In the manga, when greeted by Fuhrer King Bradley, he ignores the Fuhrer\'s inquiries and offer for Izumi to become a State Alchemist, but ends up befriending Major Alex Louis Armstrong in a muscle flexing contest. Strangely, in one episode of the anime, he is seen sleeping with both eyes open.\", \"Description_3\": \"He also becomes friends with Winry Rockbell.\"}'),(495,52739,'Damiano','{\"Description\":\"Damiano is a young enlisted soldier who had been transferred to the Daliha region of Ishval and into Major Roy Mustang\\u0027s unit just a few days before the end of the Ishval Civil War. Despite his short deployment, however, Damiano came to respect his commanding officer for all his work keeping the men beneath him out of harm\\u0027s way. Seven years after the war, Damiano remains as a soldier in the East Area of Amestris, stationed under Lieutenant General Grumman. When it becomes apparent that his old commander is planning a coup d\\u0027etat in Central City in order to rid the government of corruption, Damiano and his former squad-mates are only too happy to return to the field in order to help.\"}','{\"Description\": \"Damiano is a young enlisted soldier who had been transferred to the Daliha region of Ishval and into Major Roy Mustang\'s unit just a few days before the end of the Ishval Civil War. Despite his short deployment, however, Damiano came to respect his commanding officer for all his work keeping the men beneath him out of harm\'s way. Seven years after the war, Damiano remains as a soldier in the East Area of Amestris, stationed under Lieutenant General Grumman. When it becomes apparent that his old commander is planning a coup d\'etat in Central City in order to rid the government of corruption, Damiano and his former squad-mates are only too happy to return to the field in order to help.\"}'),(496,15538,'Darius','{\"Description\":\"Originally one of Kimblee\\u0027s bodyguards, Heinkel and Darius are blasted by Kimblee along with Ed, and ends up joining Ed when he saves them. Darius\\u0027 chimera form is that of a gorilla.\"}','{\"Description\": \"Originally one of Kimblee\'s bodyguards, Heinkel and Darius are blasted by Kimblee along with Ed, and ends up joining Ed when he saves them. Darius\' chimera form is that of a gorilla.\"}'),(497,10964,'Dolcetto','{\"Description\":\"A Chimera that swore loyalty to Greed. Like Nina, he was fused with a dog; however, he has retained his human appearance. Because he is part dog, he can use his new-found speed along with his great swordsmanship, and his sense of smell is superior to that of a normal human. However, he is noted saying he is \\u0027too loyal for his own good\\u0027. In the manga, he is often used as comic relief. Such as when Martel (inside Al at the time) should see him pee with one of his legs in the air, much like a real dog. He, like Martel, was not in the war in Ishval but was in the war in Aerugo.\"}','{\"Description\": \"A Chimera that swore loyalty to Greed. Like Nina, he was fused with a dog; however, he has retained his human appearance. Because he is part dog, he can use his new-found speed along with his great swordsmanship, and his sense of smell is superior to that of a normal human. However, he is noted saying he is \'too loyal for his own good\'. In the manga, he is often used as comic relief. Such as when Martel (inside Al at the time) should see him pee with one of his legs in the air, much like a real dog. He, like Martel, was not in the war in Ishval but was in the war in Aerugo.\"}'),(498,260680,'Douglas, Henry','{\"Description\":\"Colonel Henry Douglas is an officer at the Military Police headquarters in Central City and the man ordered to arrest 2nd Lt. Maria Ross for the murder of Brigadier General Maes Hughes.\",\"Description_2\":\"In the 2009 adaptation, there\\u0027s an exclusive scene related to the manga plot where Douglas is interrogating Ross and shows her the bullet that killed Brigadier General Hughes. He reveals that it is the same type she uses and showing her the ammo requisition form he asks why she needed to order a new one. When Ross mentions that she fired a bullet while protecting Alphonse at Laboratory 5, however, she finds there is no way to prove it since the facility was unmanned and is now a pile of rubble making it difficult to find a bullet. When Douglas brings up the fact that Ross was seen by eyewitnesses leaving the scene when Hughes was murdered, Ross finds it impossible since she was off duty visiting her parents, but the testimony of her parents or close friends cannot be considered creditable for an alibi.\",\"Description_3\":\"Douglas reappears after Colonel Roy Mustang apparently burns Ross to an ashy skeleton, admonishing the Flame Alchemist for letting personal issues take him to such an extreme and stating that, thanks to the excessive damage, the identity of the corpse cannot be confirmed. His last appearance was in Chapter 35 when Roy and Lt. Hawkeye attempt to confuse the Military Police as to Scar\\u0027s whereabouts so as to help Edward and Alphonse Elric lure out the Homunculi.\",\"Description_4\":\"His fate still remains unknown, but it\\u0027s possible that he was arrested as a conspirator.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Colonel Henry Douglas is an officer at the Military Police headquarters in Central City and the man ordered to arrest 2nd Lt. Maria Ross for the murder of Brigadier General Maes Hughes.\", \"Description_2\": \"In the 2009 adaptation, there\'s an exclusive scene related to the manga plot where Douglas is interrogating Ross and shows her the bullet that killed Brigadier General Hughes. He reveals that it is the same type she uses and showing her the ammo requisition form he asks why she needed to order a new one. When Ross mentions that she fired a bullet while protecting Alphonse at Laboratory 5, however, she finds there is no way to prove it since the facility was unmanned and is now a pile of rubble making it difficult to find a bullet. When Douglas brings up the fact that Ross was seen by eyewitnesses leaving the scene when Hughes was murdered, Ross finds it impossible since she was off duty visiting her parents, but the testimony of her parents or close friends cannot be considered creditable for an alibi.\", \"Description_3\": \"Douglas reappears after Colonel Roy Mustang apparently burns Ross to an ashy skeleton, admonishing the Flame Alchemist for letting personal issues take him to such an extreme and stating that, thanks to the excessive damage, the identity of the corpse cannot be confirmed. His last appearance was in Chapter 35 when Roy and Lt. Hawkeye attempt to confuse the Military Police as to Scar\'s whereabouts so as to help Edward and Alphonse Elric lure out the Homunculi.\", \"Description_4\": \"His fate still remains unknown, but it\'s possible that he was arrested as a conspirator.\"}'),(499,27028,'Dr. Knox','{\"Description\":\"Though a normal military surgeon, Knox was one of the doctors ordered into Ishval as pathologists to gather information on the effect of burns and pain on the human body by using Ishvalans as test subjects. He became very acquainted with the Flame Alchemist\\u0027s style as the expert assigned to dissect the bodies of Ishvalans that Roy had killed. He continued practicing pathology and forensics after the war, feeling that he had lost the right to treat living people. Even after returning from the battlefield, Knox began suffering from post-traumatic stress disorder in the form of flashbacks, insomnia and nightmares of Ishval.\",\"Description_2\":\"He has an ex-wife and a grown son.\",\"(Source\":\"Wikia)\"}','{\"(Source\": \"Wikia)\", \"Description\": \"Though a normal military surgeon, Knox was one of the doctors ordered into Ishval as pathologists to gather information on the effect of burns and pain on the human body by using Ishvalans as test subjects. He became very acquainted with the Flame Alchemist\'s style as the expert assigned to dissect the bodies of Ishvalans that Roy had killed. He continued practicing pathology and forensics after the war, feeling that he had lost the right to treat living people. Even after returning from the battlefield, Knox began suffering from post-traumatic stress disorder in the form of flashbacks, insomnia and nightmares of Ishval.\", \"Description_2\": \"He has an ex-wife and a grown son.\"}'),(500,261202,'Edison','{\"Description\":\"Brigadier General Edison was a high-ranking member of the Central Command top brass, and as such, has been entrusted with Amestris\\u0027 darkest secrets. Knowing full well of the Homunculi and their plans, Edison blindly follows King Bradley, who he seems to have a great deal of confidence in, as well as Father (whom he refers to as \\u0022The Good Gentleman\\u0022).\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Brigadier General Edison was a high-ranking member of the Central Command top brass, and as such, has been entrusted with Amestris\' darkest secrets. Knowing full well of the Homunculi and their plans, Edison blindly follows King Bradley, who he seems to have a great deal of confidence in, as well as Father (whom he refers to as \\\"The Good Gentleman\\\").\"}'),(501,10085,'Elric, Trisha','{\"Description\":\"Mother of Edward \\u0026amp; Alphonse Elric. She dies of an unexplained illness when Ed and Al are around 7 or 8 years old.\"}','{\"Description\": \"Mother of Edward &amp; Alphonse Elric. She dies of an unexplained illness when Ed and Al are around 7 or 8 years old.\"}'),(502,651,'Envy','{\"Description\":\"Envy is a homunculus who has the ability of shape-shifting. They use this power to assume the form of any person and even copy their voice. They usually serve as a spy, but their abilities are also extremely useful for assassinations. Envy may not be as smart as some of the other homunculi, but is by no means an idiot. In fact, they can be just as good a puppet master as Lust, but this is overshadowed by their cockiness and bad temper. Their temper can easily be set off by insulting their large and delicate ego, causing them to make mistakes.\",\"In the 2003 anime series\":\"\",\"Description_2\":\"As the oldest Homunculus, Envy claimed that they had forgotten what they originally looked like. Envy also greatly hates all humans and follows Dante mostly for the opportunity of killing as many people as they could. This is what drove Envy in all that they did and unlike other Homunculi, Envy does not care about the Philosopher\\u0027s Stone, nor about becoming human.\",\"In the manga and 2009 anime series\":\"\",\"Description_3\":\"Envy was the fourth Homunculus created by Father. Though often referred to as a \\u0022he\\u0022 Envy is apparently genderless and can take almost any form they choose. Referred to by Lust as the most cruel or sadistic of the Homunculi, Envy shows the most open disdain of humans and relishes in any opportunity to hurt, humiliate, or insult them. They are also quite vain, short tempered, and dislike anyone insulting their appearance.\",\"(Source\":\"Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"Fullmetal Alchemist Wikia)\", \"Description\": \"Envy is a homunculus who has the ability of shape-shifting. They use this power to assume the form of any person and even copy their voice. They usually serve as a spy, but their abilities are also extremely useful for assassinations. Envy may not be as smart as some of the other homunculi, but is by no means an idiot. In fact, they can be just as good a puppet master as Lust, but this is overshadowed by their cockiness and bad temper. Their temper can easily be set off by insulting their large and delicate ego, causing them to make mistakes.\", \"Description_2\": \"As the oldest Homunculus, Envy claimed that they had forgotten what they originally looked like. Envy also greatly hates all humans and follows Dante mostly for the opportunity of killing as many people as they could. This is what drove Envy in all that they did and unlike other Homunculi, Envy does not care about the Philosopher\'s Stone, nor about becoming human.\", \"Description_3\": \"Envy was the fourth Homunculus created by Father. Though often referred to as a \\\"he\\\" Envy is apparently genderless and can take almost any form they choose. Referred to by Lust as the most cruel or sadistic of the Homunculi, Envy shows the most open disdain of humans and relishes in any opportunity to hurt, humiliate, or insult them. They are also quite vain, short tempered, and dislike anyone insulting their appearance.\", \"In the 2003 anime series\": \"\", \"In the manga and 2009 anime series\": \"\"}'),(503,5706,'Falman, Vato','{\"Description\":\"Warrant Officer Vato Falman escorts General Hakuro back from his vacation and works in the investigation department under Lieutenant Hughes, as well as aiding Roy Mustang at Eastern Headquarters. After Hughes\\u0027s untimely death, Falman begs Mustang to let him join the team, and after thinking it through Mustang allows him to transfer with him back to Central. Falman is particularly known for his precision and data. Falman is overly formal, causing some of his comrades to wish he would lighten up.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Warrant Officer Vato Falman escorts General Hakuro back from his vacation and works in the investigation department under Lieutenant Hughes, as well as aiding Roy Mustang at Eastern Headquarters. After Hughes\'s untimely death, Falman begs Mustang to let him join the team, and after thinking it through Mustang allows him to transfer with him back to Central. Falman is particularly known for his precision and data. Falman is overly formal, causing some of his comrades to wish he would lighten up.\"}'),(504,261232,'Fessler','{\"Description\":\"Brigadier General Fessler was the Amestrian military officer put in charge of securing the Kanda region of Ishval during the Ishval Civil War.\",\"Description_2\":\"A petty and ignorant man, Fessler was more concerned with enhancing his reputation than with the lives of his subordinates and, in his obsession with clearing out his region before the other officers, made a number of hasty decisions which cost many soldiers\\u0027 lives. When Major Alex Louis Armstrong had his mental breakdown from the emotional strain of massacring Ishvalan civilians, Fessler made it worse by berating him, and, even when his mistakes were devastating to his own troops, he referred to them as \\u0022home runs\\u0022 so long as the mission objective was reached. When Colonel Basque Grand escorted Logue Lowe to Fessler with the hopes of gaining an audience with King Bradley, Fessler stubbornly refused and ordered all his soldiers to return to the fray, at which point he was shot point-blank in the chest by Grand\\u0027s rifle.\",\"Description_3\":\"Though there were several witnesses to the blatant assassination, all the soldiers present agreed that Fessler\\u0027s death had been caused by a stray bullet, truly signifying how much they hated him and his methods. Fessler\\u0027s post as commander of Kanda was succeeded by Basque Grand.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Brigadier General Fessler was the Amestrian military officer put in charge of securing the Kanda region of Ishval during the Ishval Civil War.\", \"Description_2\": \"A petty and ignorant man, Fessler was more concerned with enhancing his reputation than with the lives of his subordinates and, in his obsession with clearing out his region before the other officers, made a number of hasty decisions which cost many soldiers\' lives. When Major Alex Louis Armstrong had his mental breakdown from the emotional strain of massacring Ishvalan civilians, Fessler made it worse by berating him, and, even when his mistakes were devastating to his own troops, he referred to them as \\\"home runs\\\" so long as the mission objective was reached. When Colonel Basque Grand escorted Logue Lowe to Fessler with the hopes of gaining an audience with King Bradley, Fessler stubbornly refused and ordered all his soldiers to return to the fray, at which point he was shot point-blank in the chest by Grand\'s rifle.\", \"Description_3\": \"Though there were several witnesses to the blatant assassination, all the soldiers present agreed that Fessler\'s death had been caused by a stray bullet, truly signifying how much they hated him and his methods. Fessler\'s post as commander of Kanda was succeeded by Basque Grand.\"}'),(505,75268,'Fokker','{\"Description\":\"Captain Focker is an Amestrian soldier who works in the same administrative office as Lieutenant Colonel Maes Hughes and Sheska.\"}','{\"Description\": \"Captain Focker is an Amestrian soldier who works in the same administrative office as Lieutenant Colonel Maes Hughes and Sheska.\"}'),(506,261230,'Fox','{\"Description\":\"Brigadier General Fox was one of the most powerful men in the Amestrian State Military and a high-profile member of Central Command. Privy to the secret plan being orchestrated by Father and the Homunculi, General Fox had no qualms about sacrificing the citizens of his country to attain immortality with his co-conspirator.\",\"Description_2\":\"When The Promised Day arrives and Briggs\\u0027 soldiers begin their offensive in Central City, Fox attempts to coerce General Armstrong into revealing her intentions by gunpoint, but is stabbed through the wrist with her sword and taken hostage. Fox was used as hostage and stabbed in the foot by Armstrong in order to force his cooperation. However, he ordered his troops to seal all entrances to the commander center of Central City before threatening Armstrong\\u0027s forces. He was then smashed through the floor and killed by Sloth.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Brigadier General Fox was one of the most powerful men in the Amestrian State Military and a high-profile member of Central Command. Privy to the secret plan being orchestrated by Father and the Homunculi, General Fox had no qualms about sacrificing the citizens of his country to attain immortality with his co-conspirator.\", \"Description_2\": \"When The Promised Day arrives and Briggs\' soldiers begin their offensive in Central City, Fox attempts to coerce General Armstrong into revealing her intentions by gunpoint, but is stabbed through the wrist with her sword and taken hostage. Fox was used as hostage and stabbed in the foot by Armstrong in order to force his cooperation. However, he ordered his troops to seal all entrances to the commander center of Central City before threatening Armstrong\'s forces. He was then smashed through the floor and killed by Sloth.\"}'),(507,23461,'Fu','{\"Description\":\"Fu is one of Ling Yao\\u0027s bodyguards. He is an older man who is committed to his duties and is generally stern in nature. He is also the grandfather of Ling\\u0027s other bodyguard, Lan Fan, who he cares very much for. Fu sometimes leaves his prince\\u0027s side for an extended period of time to take care of his own business, but despite this Fu remains deeply loyal to his prince and is determined to bring Ling and the immortality he hopes to gain back to Xing.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Fu is one of Ling Yao\'s bodyguards. He is an older man who is committed to his duties and is generally stern in nature. He is also the grandfather of Ling\'s other bodyguard, Lan Fan, who he cares very much for. Fu sometimes leaves his prince\'s side for an extended period of time to take care of his own business, but despite this Fu remains deeply loyal to his prince and is determined to bring Ling and the immortality he hopes to gain back to Xing.\"}'),(508,5705,'Fuery, Kain','{\"Description\":\"Master Sergeant Kain Fuery is a kind man who cares for animals and everyone else. He was the one who brought Black Hayate into the eastern Headquarters, though he freaked out about Riza\\u0027s methods of training. He is part of Roy Mustang\\u0027s group and is the youngest member, the only non-commissioned officer in the group.  Fuery is extremely talented with radio signals. Fuery is the soft-spoken technical wizard under Mustang\\u0027s command. He isn\\u0027t used to much hand to hand fighting, but is handy enough in a pinch.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Master Sergeant Kain Fuery is a kind man who cares for animals and everyone else. He was the one who brought Black Hayate into the eastern Headquarters, though he freaked out about Riza\'s methods of training. He is part of Roy Mustang\'s group and is the youngest member, the only non-commissioned officer in the group.  Fuery is extremely talented with radio signals. Fuery is the soft-spoken technical wizard under Mustang\'s command. He isn\'t used to much hand to hand fighting, but is handy enough in a pinch.\"}'),(509,261238,'Gärtner','{\"Description\":\"Major General G\\u00E4rtner was the commanding officer that was sent to Briggs by Central Command to call for Major General Armstrong to report to Central so she could be questioned about the whereabouts of Lt. General Raven.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Major General Gärtner was the commanding officer that was sent to Briggs by Central Command to call for Major General Armstrong to report to Central so she could be questioned about the whereabouts of Lt. General Raven.\"}'),(510,261239,'Gamelan','{\"Description\":\"Gamelan is a State Military Officer with the Third Sovereign Battalion in Central City. He is exclusive to the 2009 anime series. When his team is called out to provide backup to F\\u00FChrer King Bradley in Episode 56, he moves out in an attempt to retake the Central Command headquarters\\u0027 main gate from the soldiers of Fort Briggs. Unfortunately for Gamelan, he and all the members of his platoon are swiftly rendered unconscious from an attack by the newly arrived Fu. In the manga, his role is instead played by the recurring character Storch, making Gamelan an anime-only substitution.\",\"Description_2\":\"It is possible Gamelan\\u0027s name is based off that of Maurice Gamelin, the French commander-in-chief during the early years of the Second World War.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Gamelan is a State Military Officer with the Third Sovereign Battalion in Central City. He is exclusive to the 2009 anime series. When his team is called out to provide backup to Führer King Bradley in Episode 56, he moves out in an attempt to retake the Central Command headquarters\' main gate from the soldiers of Fort Briggs. Unfortunately for Gamelan, he and all the members of his platoon are swiftly rendered unconscious from an attack by the newly arrived Fu. In the manga, his role is instead played by the recurring character Storch, making Gamelan an anime-only substitution.\", \"Description_2\": \"It is possible Gamelan\'s name is based off that of Maurice Gamelin, the French commander-in-chief during the early years of the Second World War.\"}'),(511,261231,'Gardner','{\"Description\":\"Lieutenant General Gardner was one of the most powerful men in the Amestrian State Military and a high-profile member of Central Command. Privy to the secret plan being orchestrated by Father and the Homunculi, General Gardner has no qualms about sacrificing the citizens of his country to attain immortality with his co-conspirators. After Major General Armstrong is transferred to Central Command, it is General Gardner who reveals to her that the military has a host of Homunculus soldier-dolls in storage deep beneath headquarters ready to strike out at and be reproduced from enemies of the state. When The Promised Day arrives and Briggs\\u0027 soldiers begin their offensive in Central City, Gardner attempts to corral General Armstrong\\u0027s actions, but is shot in the head by her and killed instantly.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Lieutenant General Gardner was one of the most powerful men in the Amestrian State Military and a high-profile member of Central Command. Privy to the secret plan being orchestrated by Father and the Homunculi, General Gardner has no qualms about sacrificing the citizens of his country to attain immortality with his co-conspirators. After Major General Armstrong is transferred to Central Command, it is General Gardner who reveals to her that the military has a host of Homunculus soldier-dolls in storage deep beneath headquarters ready to strike out at and be reproduced from enemies of the state. When The Promised Day arrives and Briggs\' soldiers begin their offensive in Central City, Gardner attempts to corral General Armstrong\'s actions, but is shot in the head by her and killed instantly.\"}'),(512,35144,'Garfiel','{\"Description\":\"Garfiel is a skilled automail engineer and the proprietor of Atelier Garfiel in the town of Rush Valley. When Winry Rockbell is referred to him by Dominic, Garfiel is only too happy to accept the cute young girl as his live-in apprentice and joins the rest of the Rush Valley community in treating her like a beloved family member. Garfiel is rather effeminate and appears to prefer the company of men, which results in his acting largely as a source of comic relief in scenes that involve him.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Garfiel is a skilled automail engineer and the proprietor of Atelier Garfiel in the town of Rush Valley. When Winry Rockbell is referred to him by Dominic, Garfiel is only too happy to accept the cute young girl as his live-in apprentice and joins the rest of the Rush Valley community in treating her like a beloved family member. Garfiel is rather effeminate and appears to prefer the company of men, which results in his acting largely as a source of comic relief in scenes that involve him.\"}'),(513,5411,'Gluttony','{\"Description\":\"Gluttony is the second homunculus to appear in the series, typically being in the company of Lust. He is a large, simple-minded homunculus whose thoughts rarely stray far from eating. He has powerful jaws, acidic saliva, and can and will eat almost anything. He particularly likes eating people, and the only way he can find enjoyment in a battle is if he believes he can eat his opponent afterwards. A running gag in the manga and anime is asking Lust (or any other Homunculi) if he can eat someone. He apparently prefers girls (as in to eat) and also seems to share a bond with his partner Lust.\",\"Description_2\":\"There is no significant information pertaining to his role in the 2003 anime series.\",\"Description_3\":\"In the manga and 2009 anime series\",\"Description_4\":\"Gluttony is the sixth Homunculus created by Father...\",\"(Source\":\"Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"Fullmetal Alchemist Wikia)\", \"Description\": \"Gluttony is the second homunculus to appear in the series, typically being in the company of Lust. He is a large, simple-minded homunculus whose thoughts rarely stray far from eating. He has powerful jaws, acidic saliva, and can and will eat almost anything. He particularly likes eating people, and the only way he can find enjoyment in a battle is if he believes he can eat his opponent afterwards. A running gag in the manga and anime is asking Lust (or any other Homunculi) if he can eat someone. He apparently prefers girls (as in to eat) and also seems to share a bond with his partner Lust.\", \"Description_2\": \"There is no significant information pertaining to his role in the 2003 anime series.\", \"Description_3\": \"In the manga and 2009 anime series\", \"Description_4\": \"Gluttony is the sixth Homunculus created by Father...\"}'),(514,261237,'Gold-Toothed Doctor','{\"Description\":\"The \\u0022Gold-Toothed Doctor\\u0022, also known as \\u0022The Alchemist Doctor\\u0022, is a minor antagonist in the original Fullmetal Alchemist story-line. An unnamed old man who was in possession of his very own Philosopher\\u0027s Stone, he is also one of the few responsible for Wrath\\u0027s creation. He is privy to Amestris\\u0027 top secrets and carries out Father\\u0027s orders in a ruthless fashion.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"The \\\"Gold-Toothed Doctor\\\", also known as \\\"The Alchemist Doctor\\\", is a minor antagonist in the original Fullmetal Alchemist story-line. An unnamed old man who was in possession of his very own Philosopher\'s Stone, he is also one of the few responsible for Wrath\'s creation. He is privy to Amestris\' top secrets and carries out Father\'s orders in a ruthless fashion.\"}'),(515,2439,'Grand, Basque','{\"Description\":\"Brigadier General Basque Grand (the Iron Blood Alchemist) is an ambitious alchemist known for going to any lengths to complete an assignment. His alchemy title refers to Grand\\u0027s ability to transmute the iron in his blood to an assortment of guns and other weapons. Grand was also in charge of the \\u0022defunct\\u0022 Laboratory 5 in Central, which he ran in hope of creating a philosopher\\u0027s stone for his own purposes.\"}','{\"Description\": \"Brigadier General Basque Grand (the Iron Blood Alchemist) is an ambitious alchemist known for going to any lengths to complete an assignment. His alchemy title refers to Grand\'s ability to transmute the iron in his blood to an assortment of guns and other weapons. Grand was also in charge of the \\\"defunct\\\" Laboratory 5 in Central, which he ran in hope of creating a philosopher\'s stone for his own purposes.\"}'),(516,351,'Greed','{\"Description\":\"Greed is a greedy Homunculus, nicknamed the \\u0022Ultimate Shield\\u0022. He is able to rearrange the carbon in his body to make his skin as hard as diamond, thus making himself almost impossible to injure. As his name implies he is a very avaricious character, who likes living in luxury, surrounded by powerful minions and beautiful women. Despite his generally greedy nature, he is shown to honestly care for his subordinates. He also has a habit of flipping people off in the manga.\",\"Description_2\":\"In the 2003 anime series\",\"Description_3\":\"In the manga and 2009 anime series\",\"(Source\":\"Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"Fullmetal Alchemist Wikia)\", \"Description\": \"Greed is a greedy Homunculus, nicknamed the \\\"Ultimate Shield\\\". He is able to rearrange the carbon in his body to make his skin as hard as diamond, thus making himself almost impossible to injure. As his name implies he is a very avaricious character, who likes living in luxury, surrounded by powerful minions and beautiful women. Despite his generally greedy nature, he is shown to honestly care for his subordinates. He also has a habit of flipping people off in the manga.\", \"Description_2\": \"In the 2003 anime series\", \"Description_3\": \"In the manga and 2009 anime series\"}'),(517,15531,'Grumman','{\"Description\":\"The commander of the eastern headquarters and grandfather of Riza Hawkeye. As he is not under the constant surveillance of the Humonculi, he aids Mustang in trying to topple the Humonculi controlled government, but seems to do so strictly out of personal ambition.\"}','{\"Description\": \"The commander of the eastern headquarters and grandfather of Riza Hawkeye. As he is not under the constant surveillance of the Humonculi, he aids Mustang in trying to topple the Humonculi controlled government, but seems to do so strictly out of personal ambition.\"}'),(518,21072,'Hakuro','{}','{}'),(519,261293,'Halling, Kyle','{\"Description\":\"Kyle is a resident of Youswell and the young son of , the town\\u0027s unofficial chief.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Kyle is a resident of Youswell and the young son of , the town\'s unofficial chief.\"}'),(520,105499,'Harris','{\"Description\":\"Is an Amestrian soldier who is searching for Ed.\"}','{\"Description\": \"Is an Amestrian soldier who is searching for Ed.\"}'),(521,4685,'Havoc, Jean','{\"Description\":\"Second Lieutenant Jean Havoc likes to smoke, and is almost always pictured with a cigarette in his mouth. He is a fair shot with a gun, and one of Roy Mustang\\u0027s loyal followers; he gives Edward a stern talking-to when Ed bad-mouths Mustang for only caring about promotions. Havoc is a strict man of duty, a very by-the-book soldier, even if he doesn\\u0027t always agree with the orders.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Second Lieutenant Jean Havoc likes to smoke, and is almost always pictured with a cigarette in his mouth. He is a fair shot with a gun, and one of Roy Mustang\'s loyal followers; he gives Edward a stern talking-to when Ed bad-mouths Mustang for only caring about promotions. Havoc is a strict man of duty, a very by-the-book soldier, even if he doesn\'t always agree with the orders.\"}'),(522,70,'Hawkeye, Riza','{\"Description\":\"Riza Hawkeye is Roy Mustang\\u0027s most trusted subordinate. She carries out many of the tasks he is too lazy to do, acts as his personal assistant, and protects him from danger. She also doubles as his voice of reason, keeping cool in heated situations and scolding him when he allows his emotions to get in the way. Riza and Roy seem to share a close relationship in both adaptations of Fullmetal Alchemist; in the anime she identifies him as her most precious person, whereas in the manga she loses her resolve to live when believing he has been killed. Riza specializes in firearms, particularly sniper rifles, and can hit nearly any target with lethal accuracy. She adopts a dog, called Black Hayate in both the anime and the manga, which she raises with stern discipline; when Hayate goes to the bathroom inside, she shoots at the wall behind him to reinforce that doing so is bad.\"}','{\"Description\": \"Riza Hawkeye is Roy Mustang\'s most trusted subordinate. She carries out many of the tasks he is too lazy to do, acts as his personal assistant, and protects him from danger. She also doubles as his voice of reason, keeping cool in heated situations and scolding him when he allows his emotions to get in the way. Riza and Roy seem to share a close relationship in both adaptations of Fullmetal Alchemist; in the anime she identifies him as her most precious person, whereas in the manga she loses her resolve to live when believing he has been killed. Riza specializes in firearms, particularly sniper rifles, and can hit nearly any target with lethal accuracy. She adopts a dog, called Black Hayate in both the anime and the manga, which she raises with stern discipline; when Hayate goes to the bathroom inside, she shoots at the wall behind him to reinforce that doing so is bad.\"}'),(523,75922,'Hawkeye, Berthold','{\"Description\":\"Master Berthold Hawkeye was both the alchemist who mentored Roy Mustang as well as the estranged father of Riza Hawkeye.\",\"Description_2\":\"A brilliant alchemist, Hawkeye postulated the complex and intricate theorems necessary to apply flame alchemy at its most powerful and efficient level, but refused to pass on his flame alchemy secrets to his pupil, thinking them too dangerous for young and naive Roy. Riza describes her father as a frightening man with whom she did not generally associate and could not at all relate. Afraid of his life\\u0027s work being destroyed and what his Flame Alchemy knowledge could do if it fell into the wrong hands, Master Hawkeye refrained from keeping notes in the normal fashion and, instead, tattooed a large Transmutation Array containing the culmination of his craft and findings on his daughter\\u0027s back, perhaps further straining - or serving as an indication of - the Hawkeyes\\u0027 already shaky relationship.\",\"Description_3\":\"Master Hawkeye, as an independent alchemist, appears to hold some disdain for the State Military (much like Izumi Curtis), as revealed by his flippant reaction to Roy\\u0027s enlistment during the Ishval Civil War as well as his preference of living in squalor with all his genius over joining the State Alchemist Program.\",\"Description_4\":\"As Roy returned to his teacher\\u0027s house in an attempt to get hold of the theory of Flame Alchemy to enlist as a State Alchemist (he was just a regular soldier at that time), Master Hawkeye revealed to him his daughter possessed the theory and succumbed to illness, coughing up blood as he died in Roy\\u0027s arms.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Master Berthold Hawkeye was both the alchemist who mentored Roy Mustang as well as the estranged father of Riza Hawkeye.\", \"Description_2\": \"A brilliant alchemist, Hawkeye postulated the complex and intricate theorems necessary to apply flame alchemy at its most powerful and efficient level, but refused to pass on his flame alchemy secrets to his pupil, thinking them too dangerous for young and naive Roy. Riza describes her father as a frightening man with whom she did not generally associate and could not at all relate. Afraid of his life\'s work being destroyed and what his Flame Alchemy knowledge could do if it fell into the wrong hands, Master Hawkeye refrained from keeping notes in the normal fashion and, instead, tattooed a large Transmutation Array containing the culmination of his craft and findings on his daughter\'s back, perhaps further straining - or serving as an indication of - the Hawkeyes\' already shaky relationship.\", \"Description_3\": \"Master Hawkeye, as an independent alchemist, appears to hold some disdain for the State Military (much like Izumi Curtis), as revealed by his flippant reaction to Roy\'s enlistment during the Ishval Civil War as well as his preference of living in squalor with all his genius over joining the State Alchemist Program.\", \"Description_4\": \"As Roy returned to his teacher\'s house in an attempt to get hold of the theory of Flame Alchemy to enlist as a State Alchemist (he was just a regular soldier at that time), Master Hawkeye revealed to him his daughter possessed the theory and succumbed to illness, coughing up blood as he died in Roy\'s arms.\"}'),(524,15536,'Heinkel','{\"Description\":\"Originally one of Kimblee\\u0027s bodyguards, Heinkel and Darius are blasted by Kimblee along with Ed, and ends up joining Ed when he saves them. Heinkel\\u0027s chimera form is that of a humanoid lion.\"}','{\"Description\": \"Originally one of Kimblee\'s bodyguards, Heinkel and Darius are blasted by Kimblee along with Ed, and ends up joining Ed when he saves them. Heinkel\'s chimera form is that of a humanoid lion.\"}'),(525,261242,'Henschel','{\"Description\":\"Second Lieutenant Henschel is an Amestrian State Military Officer stationed at Fort Briggs, and one of Major General Olivier Mira Armstrong\\u0027s loyal subordinates. After the inadvertent attack on Briggs by the Homunculus Sloth, Henschel opposes the sealing of the tunnel\\u0027s opening proposed by Lt. General Raven because he fears for the soldiers who had been sent in to examine the channel. Though the Major General initially appears to ignore Henschel\\u0027s protests, she reveals to him in secret that Edward Elric had alchemically created a second entrance behind Raven\\u0027s back. Along with Captain Buccaneer and a few others, 2nd Lt. Henschel enters the tunnel and is overjoyed to find a pair of survivors despite the apparent carnage caused by the Homunculus Pride. After Major General Armstrong is transferred to Central Command, Henschel discusses the coming change of regime with Buccaneer and the two agree that Central\\u0027s impending flunkies have no idea what to expect from Briggs\\u0027 soldiers.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Second Lieutenant Henschel is an Amestrian State Military Officer stationed at Fort Briggs, and one of Major General Olivier Mira Armstrong\'s loyal subordinates. After the inadvertent attack on Briggs by the Homunculus Sloth, Henschel opposes the sealing of the tunnel\'s opening proposed by Lt. General Raven because he fears for the soldiers who had been sent in to examine the channel. Though the Major General initially appears to ignore Henschel\'s protests, she reveals to him in secret that Edward Elric had alchemically created a second entrance behind Raven\'s back. Along with Captain Buccaneer and a few others, 2nd Lt. Henschel enters the tunnel and is overjoyed to find a pair of survivors despite the apparent carnage caused by the Homunculus Pride. After Major General Armstrong is transferred to Central Command, Henschel discusses the coming change of regime with Buccaneer and the two agree that Central\'s impending flunkies have no idea what to expect from Briggs\' soldiers.\"}'),(526,9792,'Hohenheim, Van','{\"Description\":\"He is the father of the protagonists, Edward and Alphonse Elric. He is a brilliant and well-known alchemist. He left Ed, Al, and their mother Trisha when Al was a baby and when Ed was very young. Years later, Ed still holds a grudge against him for abandoning his mother, which he believes contributed to her death.\",\"Description_2\":\"In the Fullmetal Alchemist manga, he is referred to as \\u0022Van Hohenheim,\\u0022 not Hohenheim Elric. As Edward Elric points out in book 14 of the Fullmetal Alchemist manga, \\u0022Elric is my mother\\u0027s name!\\u0022\",\"Description_3\":\"In the 2003 anime\",\"Description_4\":\"In the manga and 2009 anime\",\"(Source\":\"Wikipedia, edited)\"}','{\"(Source\": \"Wikipedia, edited)\", \"Description\": \"He is the father of the protagonists, Edward and Alphonse Elric. He is a brilliant and well-known alchemist. He left Ed, Al, and their mother Trisha when Al was a baby and when Ed was very young. Years later, Ed still holds a grudge against him for abandoning his mother, which he believes contributed to her death.\", \"Description_2\": \"In the Fullmetal Alchemist manga, he is referred to as \\\"Van Hohenheim,\\\" not Hohenheim Elric. As Edward Elric points out in book 14 of the Fullmetal Alchemist manga, \\\"Elric is my mother\'s name!\\\"\", \"Description_3\": \"In the 2003 anime\", \"Description_4\": \"In the manga and 2009 anime\"}'),(527,261295,'Hohenheim\'s Master','{}','{}'),(528,15542,'Homunculus','{\"Description\":\"During the course of FMA\\u0027s story, \\u0022Father\\u0022 commands the other Homunculi and orchestrates the various conflicts like the Ishvalian war, plotting something involving a transmutation circle encircling the entirety of Amestris.\"}','{\"Description\": \"During the course of FMA\'s story, \\\"Father\\\" commands the other Homunculi and orchestrates the various conflicts like the Ishvalian war, plotting something involving a transmutation circle encircling the entirety of Amestris.\"}'),(529,10954,'Hughes, Gracia','{\"Description\":\"Gracia Hughes is Maes Hughes\\u0027s wife and Elicia Hughes\\u0027s mother. She is a kind and caring person. Gracia appears periodically throughout the series. She allows Winry to stay at her house when she is in Central and Sheska to frequently visit.\",\"Description_2\":\"In the manga, it is revealed that she and Hughes met before he was sent out to the battlefield during the Ishval War.\"}','{\"Description\": \"Gracia Hughes is Maes Hughes\'s wife and Elicia Hughes\'s mother. She is a kind and caring person. Gracia appears periodically throughout the series. She allows Winry to stay at her house when she is in Central and Sheska to frequently visit.\", \"Description_2\": \"In the manga, it is revealed that she and Hughes met before he was sent out to the battlefield during the Ishval War.\"}'),(530,69,'Hughes, Maes','{\"Description\":\"Maes Hughes is often seen as the comedy relief, but has his debuts as a serious and skilled fighter. He is best friends with Roy Mustang (and would do anything to help Roy achieve his goals) and a loving and devoted husband/father. Maes would do anything for his wife Gracia and always carries pictures of his daughter Elycia in his uniform and never misses a chance to show everyone how cute she is. He starts out in the anime as a Major in the Investigation Division and eventually becomes a Lieutenant Colonel.\"}','{\"Description\": \"Maes Hughes is often seen as the comedy relief, but has his debuts as a serious and skilled fighter. He is best friends with Roy Mustang (and would do anything to help Roy achieve his goals) and a loving and devoted husband/father. Maes would do anything for his wife Gracia and always carries pictures of his daughter Elycia in his uniform and never misses a chance to show everyone how cute she is. He starts out in the anime as a Major in the Investigation Division and eventually becomes a Lieutenant Colonel.\"}'),(531,22474,'Hughes, Elicia','{\"Description\":\"Daughter of Maes and Gracia Hughes. She is an innocent, 3 year old girl. Her Dad loves her and he says every time how cute and talented she is.\"}','{\"Description\": \"Daughter of Maes and Gracia Hughes. She is an innocent, 3 year old girl. Her Dad loves her and he says every time how cute and talented she is.\"}'),(532,15533,'Jerso','{\"Description\":\"A frog-like chimera who was initially one of Kimblee\\u0027s bodyguards, but deserted and joined Scar instead.\"}','{\"Description\": \"A frog-like chimera who was initially one of Kimblee\'s bodyguards, but deserted and joined Scar instead.\"}'),(533,92915,'Karley','{\"Description\":\"\\u0022Karley is an Amestrian State Military officer stationed at Fort Briggs under the command of Major General Armstrong. As a primary communications officer for the fort, he is frequently seen toting a large radio transmitter or wired communications pack on his back while in transit and is often put in charge of relaying information and orders to Briggs troops in combat. Karley is first seen participating in Captain Buccaneer\\u0027s mission to rescue the lost search party inside the tunnel created by the Homunculus Sloth and later appears as the head of communications during Major General Armstrong\\u0027s role in the capture of Central Command.\\u0022\",\"(Source\":\"Full Metal Alchemist Wiki)\"}','{\"(Source\": \"Full Metal Alchemist Wiki)\", \"Description\": \"\\\"Karley is an Amestrian State Military officer stationed at Fort Briggs under the command of Major General Armstrong. As a primary communications officer for the fort, he is frequently seen toting a large radio transmitter or wired communications pack on his back while in transit and is often put in charge of relaying information and orders to Briggs troops in combat. Karley is first seen participating in Captain Buccaneer\'s mission to rescue the lost search party inside the tunnel created by the Homunculus Sloth and later appears as the head of communications during Major General Armstrong\'s role in the capture of Central Command.\\\"\"}'),(534,6590,'Kimblee, Solf J.','{\"Description\":\"Solf J. Kimblee is an ex-war criminal and a veteran of the Ishbal War. His alchemy title refers to his use of sulfur in the human body to create explosive fluids, turning people into living bombs.\",\"Description_2\":\"With a far more subtle, polite approach to evil than his Anime counterpart, the Manga\\u0027s Kimblee spearheaded the Ishballan Extermination Campaign, and was one of the few, if not the only, State Alchemists to utilized the full power of the Philosopher\\u0027s Stones fabricated at Lab 5. His personality seems almost split in two; at times he can be polite, if curt, straightforward, rational, and \\u0022civilized.\\u0022 He even seemed to have a certain respect for Winry\\u0027s parents because of their devotion to their duty. However, in battle he displays an uncanny and foreboding demeanor in favor of destruction and damnation (he once reprimand Riza and others for being \\u0022ununderstandable\\u0022, for not accepting their role as murderers, as soldiers, despite many humans they killed), using one of his own subordinates to demonstrate his destructive powers. Kimblee\\u0027s powers appear to be much the same as those in the Anime, except that he can transmute and detonate from a distance as well, using the ground as a connecting force, causing huge explosions (though probably it is because his force is imbued with Philosopher\\u0027s Stone).\",\"Description_3\":\"He was initially given a Philosopher\\u0027s Stone made of Ishvalan souls, but when the army tried to confiscate it after the war was over, he swallowed it whole. Throughout the series, he is seen making himself choke it back up to get a good look at it.\"}','{\"Description\": \"Solf J. Kimblee is an ex-war criminal and a veteran of the Ishbal War. His alchemy title refers to his use of sulfur in the human body to create explosive fluids, turning people into living bombs.\", \"Description_2\": \"With a far more subtle, polite approach to evil than his Anime counterpart, the Manga\'s Kimblee spearheaded the Ishballan Extermination Campaign, and was one of the few, if not the only, State Alchemists to utilized the full power of the Philosopher\'s Stones fabricated at Lab 5. His personality seems almost split in two; at times he can be polite, if curt, straightforward, rational, and \\\"civilized.\\\" He even seemed to have a certain respect for Winry\'s parents because of their devotion to their duty. However, in battle he displays an uncanny and foreboding demeanor in favor of destruction and damnation (he once reprimand Riza and others for being \\\"ununderstandable\\\", for not accepting their role as murderers, as soldiers, despite many humans they killed), using one of his own subordinates to demonstrate his destructive powers. Kimblee\'s powers appear to be much the same as those in the Anime, except that he can transmute and detonate from a distance as well, using the ground as a connecting force, causing huge explosions (though probably it is because his force is imbued with Philosopher\'s Stone).\", \"Description_3\": \"He was initially given a Philosopher\'s Stone made of Ishvalan souls, but when the army tried to confiscate it after the war was over, he swallowed it whole. Throughout the series, he is seen making himself choke it back up to get a good look at it.\"}'),(535,261252,'King of Xerxes','{\"Description\":\"Known by history as the last Xerxesian monarch, the King of Xerxes, the ancient and prosperous land, ruled over his subjects well into his old age, acting in a manner that caused him to be beloved by the happy citizens.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Known by history as the last Xerxesian monarch, the King of Xerxes, the ancient and prosperous land, ruled over his subjects well into his old age, acting in a manner that caused him to be beloved by the happy citizens.\"}'),(536,135041,'Knox\'s Son','{\"Description\":\"Dr. Knox\\u0027s son. He wants to become a doctor like his father and spurrs Dr. Knox to return to his work as a doctor.\",\"Description_2\":\"He appears in episode 31 and in chapter 63 of the manga.\"}','{\"Description\": \"Dr. Knox\'s son. He wants to become a doctor like his father and spurrs Dr. Knox to return to his work as a doctor.\", \"Description_2\": \"He appears in episode 31 and in chapter 63 of the manga.\"}'),(537,3292,'Lan Fan','{\"Description\":\"Lan Fan is one of two bodyguards of Ling Yao and the granddaughter of Ling\\u0027s other bodyguard, Fu. She is very quiet and cares deeply for Ling. As a result, she is constantly thinking of his safety and often forgets her own. Lan Fan is a very skilled fighter and is able to sense the presence of a soul (referred to as chi); thus she can quickly identify Homunculi like Envy that have more than one soul in their Philosopher\\u0027s Stones (meaning she can easily see through Envy\\u0027s disguises). Although we are never told her age Ling refers to her as a \\u0022girl\\u0022 so we can assume that she and Ling are around the same age.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Lan Fan is one of two bodyguards of Ling Yao and the granddaughter of Ling\'s other bodyguard, Fu. She is very quiet and cares deeply for Ling. As a result, she is constantly thinking of his safety and often forgets her own. Lan Fan is a very skilled fighter and is able to sense the presence of a soul (referred to as chi); thus she can quickly identify Homunculi like Envy that have more than one soul in their Philosopher\'s Stones (meaning she can easily see through Envy\'s disguises). Although we are never told her age Ling refers to her as a \\\"girl\\\" so we can assume that she and Ling are around the same age.\"}'),(538,112213,'LeCoulte, Satella','{\"Description\":\"Satella LeCoulte, also known as Satera, lives in the mountains outside of Rush Valley with her husband, Ridel, and her father-in-law, Dominic. She is a very kind and loving woman, who - at the start of her introduction - is nine months pregnant.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Satella LeCoulte, also known as Satera, lives in the mountains outside of Rush Valley with her husband, Ridel, and her father-in-law, Dominic. She is a very kind and loving woman, who - at the start of her introduction - is nine months pregnant.\"}'),(539,10976,'LeCoulte, Dominic','{\"Description\":\"An old reclusive automail master. His lifelong dream was to build automail with hidden cannons inside them, and he had the opportunity to do just that with Paninya\\u0027s automail legs. Winry begs him to let her be his apprentice, but he defers her to Garfiel instead, even though Winry helped deliver his grandson.\",\"Description_2\":\"It is noteworthy that when he found out Winry was the granddaughter of Pinako Rockbell, he flipped out, as apparently he has some memories about the \\u0022Pantheress of Resembool\\u0022 that he would rather forget (\\u0022Leopardess of Resembool\\u0022 in the dubbed anime).\",\"Description_3\":\"In the anime, no mention is made of any desire to build hidden cannons, though he did build one into Paninya\\u0027s right leg. He refuses to sell an automail arm to a young rich man because it is an arm for a fighter, and the young man does not really need it. At the end of the series, he is seen helping Winry train to become an even better mechanic.\"}','{\"Description\": \"An old reclusive automail master. His lifelong dream was to build automail with hidden cannons inside them, and he had the opportunity to do just that with Paninya\'s automail legs. Winry begs him to let her be his apprentice, but he defers her to Garfiel instead, even though Winry helped deliver his grandson.\", \"Description_2\": \"It is noteworthy that when he found out Winry was the granddaughter of Pinako Rockbell, he flipped out, as apparently he has some memories about the \\\"Pantheress of Resembool\\\" that he would rather forget (\\\"Leopardess of Resembool\\\" in the dubbed anime).\", \"Description_3\": \"In the anime, no mention is made of any desire to build hidden cannons, though he did build one into Paninya\'s right leg. He refuses to sell an automail arm to a young rich man because it is an arm for a fighter, and the young man does not really need it. At the end of the series, he is seen helping Winry train to become an even better mechanic.\"}'),(540,260814,'LeCoulte, Ridel','{\"Description\":\"Ridel LeCoulte is an automail manufacturer in Rush Valley. He lives on the outskirts of town with his wife and father.\",\"Description_2\":\"Ridel is introduced to the Elric brothers and Winry by Paninya in Chapter Eighteen when she takes them to see Dominic. When his wife goes into labor, his father is forced to go into town to find a doctor, only to find the bridge destroyed by lightning. Faced with no other options, Winry successfully delivers the baby herself.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Ridel LeCoulte is an automail manufacturer in Rush Valley. He lives on the outskirts of town with his wife and father.\", \"Description_2\": \"Ridel is introduced to the Elric brothers and Winry by Paninya in Chapter Eighteen when she takes them to see Dominic. When his wife goes into labor, his father is forced to go into town to find a doctor, only to find the bridge destroyed by lightning. Faced with no other options, Winry successfully delivers the baby herself.\"}'),(541,650,'Lust','{\"Description\":\"Lust is a Homunculus, nicknamed the \\u0022Ultimate Spear\\u0022, and one of the first antagonists in the Fullmetal Alchemist series. She is the first Homunculus to appear in the series and plays a significant role in the plot of both the manga and 2003 anime series. Lust is also usually partnered with Gluttony to whom she appears to have a particular almost motherly closeness. Her Ouroboros mark is located on her collarbone, just above her breasts.\",\"Description_2\":\"In the 2003 anime series;\",\"Description_3\":\"Like her manga counterpart, she is highly intelligent, manipulative, and devoted to her own ideals; however, she begins to crave becoming a human as the series progresses. Her main purposes amongst the Homunculi are gathering information, and traveling to manipulate alchemists into creating Philosopher\\u0027s Stones. Gaining true humanity is the focal point of her ambition, arguably much more so than the rest of the Homunculi.\",\"Description_4\":\"In the manga and 2009 anime series;\",\"Description_5\":\"Lust is the only female Homunculus and the second to be created by Father. Due to her high intelligence and devotion to Father\\u0027s plan, Lust appears to have a great deal of free reign and authority within the organization, seeming to have a position second only to Pride and on par with Wrath. Lust also has a great disdain for humans, thinking them frail, predictable and generally stupid. Moreover, she appears to take pleasure in using and throwing them away. Lust is the first to introduce the idea of Homunculi as superhuman, the next wave of evolution of humanity, and takes pride in her nature.\",\"Description_6\":\"-Taken in part from Wikia.\"}','{\"Description\": \"Lust is a Homunculus, nicknamed the \\\"Ultimate Spear\\\", and one of the first antagonists in the Fullmetal Alchemist series. She is the first Homunculus to appear in the series and plays a significant role in the plot of both the manga and 2003 anime series. Lust is also usually partnered with Gluttony to whom she appears to have a particular almost motherly closeness. Her Ouroboros mark is located on her collarbone, just above her breasts.\", \"Description_2\": \"In the 2003 anime series;\", \"Description_3\": \"Like her manga counterpart, she is highly intelligent, manipulative, and devoted to her own ideals; however, she begins to crave becoming a human as the series progresses. Her main purposes amongst the Homunculi are gathering information, and traveling to manipulate alchemists into creating Philosopher\'s Stones. Gaining true humanity is the focal point of her ambition, arguably much more so than the rest of the Homunculi.\", \"Description_4\": \"In the manga and 2009 anime series;\", \"Description_5\": \"Lust is the only female Homunculus and the second to be created by Father. Due to her high intelligence and devotion to Father\'s plan, Lust appears to have a great deal of free reign and authority within the organization, seeming to have a position second only to Pride and on par with Wrath. Lust also has a great disdain for humans, thinking them frail, predictable and generally stupid. Moreover, she appears to take pleasure in using and throwing them away. Lust is the first to introduce the idea of Homunculi as superhuman, the next wave of evolution of humanity, and takes pride in her nature.\", \"Description_6\": \"-Taken in part from Wikia.\"}'),(542,29798,'Madame Christmas','{\"Description\":\"A rather gruff woman, Madame Christmas is the proprietor of a hostess bar in Central City frequently patronaged by Colonel Roy Mustang. At first, it would merely seem that this bar is further proof of Mustang\\u0027s unapologetic debauchery, but it becomes quite apparent that the women under Madame Christmas\\u0027 care act as secret informants to Mustang and his squad and that Madame Christmas herself is a skilled intelligencer and contact between Roy and Lt. General Grumman in East City.\",\"(Source\":\"Wikia)\"}','{\"(Source\": \"Wikia)\", \"Description\": \"A rather gruff woman, Madame Christmas is the proprietor of a hostess bar in Central City frequently patronaged by Colonel Roy Mustang. At first, it would merely seem that this bar is further proof of Mustang\'s unapologetic debauchery, but it becomes quite apparent that the women under Madame Christmas\' care act as secret informants to Mustang and his squad and that Madame Christmas herself is a skilled intelligencer and contact between Roy and Lt. General Grumman in East City.\"}'),(543,35595,'Madame Shan','{}','{}'),(544,10956,'Marcoh, Tim','{\"Description\":\"Formerly the Crystal Alchemist, Marcoh was the leading researcher in the creation of the Philosopher\\u0027s Stone. Tormented by the fact that his research was used in the Ishval War to kill many innocent people, he fled from his position as a State Alchemist and took his research with him to prevent it from being used for further destruction. Hiding from the military and posing as a medical doctor, he uses the Red Stone he created to help the sick.\"}','{\"Description\": \"Formerly the Crystal Alchemist, Marcoh was the leading researcher in the creation of the Philosopher\'s Stone. Tormented by the fact that his research was used in the Ishval War to kill many innocent people, he fled from his position as a State Alchemist and took his research with him to prevent it from being used for further destruction. Hiding from the military and posing as a medical doctor, he uses the Red Stone he created to help the sick.\"}'),(545,8840,'Martel','{\"Description\":\"Martel is one of the Chimeras that joined Greed to get revenge on the military for what they did to them in the 5th Laboratory.\"}','{\"Description\": \"Martel is one of the Chimeras that joined Greed to get revenge on the military for what they did to them in the 5th Laboratory.\"}'),(546,10978,'Mason','{\"Description\":\"An assistant at the Curtises\\u0027 butcher shop who is more outspoken than his employer. He has worked for Sig and Izumi at least since the Elrics initially became Izumi\\u0027s apprentices. During Izumi\\u0027s challenge to survive on Yock Island for one month without using alchemy and to discover the meaning behind \\u0022All is one, one is all\\u0022, Mason was the monster who kept attacking the brothers. Izumi had ordered him, in disguise, to make sure nothing happened to the boys during their stay on the island.\"}','{\"Description\": \"An assistant at the Curtises\' butcher shop who is more outspoken than his employer. He has worked for Sig and Izumi at least since the Elrics initially became Izumi\'s apprentices. During Izumi\'s challenge to survive on Yock Island for one month without using alchemy and to discover the meaning behind \\\"All is one, one is all\\\", Mason was the monster who kept attacking the brothers. Izumi had ordered him, in disguise, to make sure nothing happened to the boys during their stay on the island.\"}'),(547,23338,'May, Shao','{\"Description\":\"Shao May is May Chang\\u0027s pet panda and traveling companion. Abandoned as a cub due to her abnormally small size, Shao May was cared for by May as if she were family and, therefore, has a particularly strong bond with the little girl. The two are constantly together and, as a bit of comic relief, Shao May frequently mimics May\\u0027s actions whether it be in expression, practicing alchemy or performing martial arts, taking whatever pose her master takes and moving in synchronized union with her.\",\"(Source\":\"Wikia)\"}','{\"(Source\": \"Wikia)\", \"Description\": \"Shao May is May Chang\'s pet panda and traveling companion. Abandoned as a cub due to her abnormally small size, Shao May was cared for by May as if she were family and, therefore, has a particularly strong bond with the little girl. The two are constantly together and, as a bit of comic relief, Shao May frequently mimics May\'s actions whether it be in expression, practicing alchemy or performing martial arts, taking whatever pose her master takes and moving in synchronized union with her.\"}'),(548,21005,'McDougal, Isaac','{\"Description\":\"The Ice Alchemist and defector from the Amestris army after the Ishbal war. Apparently aware of a conspiracy within the military government and is attempting to destroy it.\"}','{\"Description\": \"The Ice Alchemist and defector from the Amestris army after the Ishbal war. Apparently aware of a conspiracy within the military government and is attempting to destroy it.\"}'),(549,15540,'Miles','{\"Description\":\"One of the higher ranking soldiers at Briggs\\u0027 Fortress under Olivier Mira Armstrong. As he is partly Ishvalian, Armstrong was ordered to imprison him during the Ishvalian war, but she refused to do such a thing only because of his ethnicity.\",\"Description_2\":\"Miles is very loyal to Armstrong, and wants to stay in the military to change their perspective on Ishvalians.\"}','{\"Description\": \"One of the higher ranking soldiers at Briggs\' Fortress under Olivier Mira Armstrong. As he is partly Ishvalian, Armstrong was ordered to imprison him during the Ishvalian war, but she refused to do such a thing only because of his ethnicity.\", \"Description_2\": \"Miles is very loyal to Armstrong, and wants to stay in the military to change their perspective on Ishvalians.\"}'),(550,239348,'Mr. Halling','{\"Description\":\"Mister Halling is one of the many miners who live in the Frontier Mining Town of Youswell and, due to his amicable and clear-headed nature, has been chosen by the Youswell mining community to be their unofficial chief and spokesman in their ongoing (albeit fruitless) negotiations with the landowner of Youswell - Lieutenant Yoki.\",\"Description_2\":\"As a result of Yoki\\u0027s exorbitant property taxes, Halling (along with many other Youswell residents) runs a tavern with his wife and his son Kyle partly as a place where the tired laborers of the town can rest and unwind after a hard day in the coal mines, but mostly as a way to bilk tourists out of their money with an admittedly unreasonable 200,000 cenz per night fee so as to keep up with Yoki\\u0027s equally unreasonable demands. He is a friendly and kindhearted man, described by his friends and family as someone who will gladly take a loss if he can help out an ailing friend by doing so.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Mister Halling is one of the many miners who live in the Frontier Mining Town of Youswell and, due to his amicable and clear-headed nature, has been chosen by the Youswell mining community to be their unofficial chief and spokesman in their ongoing (albeit fruitless) negotiations with the landowner of Youswell - Lieutenant Yoki.\", \"Description_2\": \"As a result of Yoki\'s exorbitant property taxes, Halling (along with many other Youswell residents) runs a tavern with his wife and his son Kyle partly as a place where the tired laborers of the town can rest and unwind after a hard day in the coal mines, but mostly as a way to bilk tourists out of their money with an admittedly unreasonable 200,000 cenz per night fee so as to keep up with Yoki\'s equally unreasonable demands. He is a friendly and kindhearted man, described by his friends and family as someone who will gladly take a loss if he can help out an ailing friend by doing so.\"}'),(551,261292,'Mr. Han','{\"Description\":\"Mr. Han is a smuggler specializing in transporting people illegally and secretly between Amestris and Xing. It is his agency that allows Ling Yao, Lan Fan, and Fu to cross the Great Desert safely and enter Amestris without detection.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Mr. Han is a smuggler specializing in transporting people illegally and secretly between Amestris and Xing. It is his agency that allows Ling Yao, Lan Fan, and Fu to cross the Great Desert safely and enter Amestris without detection.\"}'),(552,261251,'Murray, Mick','{\"Description\":\"Mick Murray is an Amestrian State Military Officer stationed at Fort Briggs under the command of Major General Armstrong.\",\"Description_2\":\"Mick first appeared under the command of Major Miles in Baschool with the goal of capturing Scar. When Miles was preparing the squads for the search parties, Edward Elric sat with a dummy that he made of Alphonse Elric\\u0027s armor. Mick was inside it, masquerading as Al. After that, he received orders to assassinate Solf J. Kimblee, who later escaped.\",\"Description_3\":\"Months had passed and he, along with Liam Roach, was responsible for getting Winry Rockbell back home safely. During the promised day, Mick and Liam stayed at Rockbell Automail to protect Pinako Rockbell and Winry Rockbell, but couldn\\u0027t do anything against the Nationwide Transmutation Circle.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Mick Murray is an Amestrian State Military Officer stationed at Fort Briggs under the command of Major General Armstrong.\", \"Description_2\": \"Mick first appeared under the command of Major Miles in Baschool with the goal of capturing Scar. When Miles was preparing the squads for the search parties, Edward Elric sat with a dummy that he made of Alphonse Elric\'s armor. Mick was inside it, masquerading as Al. After that, he received orders to assassinate Solf J. Kimblee, who later escaped.\", \"Description_3\": \"Months had passed and he, along with Liam Roach, was responsible for getting Winry Rockbell back home safely. During the promised day, Mick and Liam stayed at Rockbell Automail to protect Pinako Rockbell and Winry Rockbell, but couldn\'t do anything against the Nationwide Transmutation Circle.\"}'),(553,68,'Mustang, Roy','{\"Birthday\":\"1885 (Age 30 from vol. 10)\",\"Height\":\"5\\u00278\\u0022 (173 cm)\",\"Description\":\"Roy Mustang is the \\u0022Flame Alchemist,\\u0022 having absolute control over heat and fire through alchemy. Using special gloves that create a spark when he snaps his fingers, Roy can create anything from a tiny ember to burn a letter, to a raging inferno that can destroy a humanoid body in seconds. His precise control over the alchemically enhanced flame is so accurate that he can boil the water in a persons\\u0027 eyes and can also attack enemies amongst a riot without hurting any allies.\",\"Description_2\":\"Outwardly arrogant and playfully manipulative, Mustang is intelligent and almost always one step ahead of his opponents, and likes to feel in control of the situation. He is one of the superiors of Edward Elric. On the surface, he appears to be nothing more than a man of the military who pursues promotions and praise and is considered a ladies\\u0027 man who constantly goes on dates with different women. Mustang\\u0027s true goal is to become F\\u00FChrer in order to gain the power to reform the government in order to absolve his sins in the Ishval War as well as change the country for the better, along with the joking requirement for female officers to wear tiny miniskirts (which considerably increased Havoc\\u0027s loyalty to him and caused Hawkeye to be angry with him).\",\"Description_3\":\"His goals are admirable enough that he earns the fierce loyalty of his good friends Lt Col. Maes Hughes, Major Alex Louis Armstrong, and his own subordinates, among whom are Riza Hawkeye, Jean Havoc, Heymans Breda, Vato Falman, and Kain Fuery. While Mustang has a close and amicable relationship with all of his subordinates, he appears to share a deeper bond of affection with his second-in-command Riza Hawkeye, who has devoted her life to supporting him. This bond culminates in the final episodes of the anime when Mustang chooses Hawkeye alone to accompany him on his greatest and most dangerous mission.\",\"Description_4\":\"Though a hero of the Ishval War, he remains haunted by the horrors of war and suffers great remorse for the lives he took.\",\"(Source\":\"Wikipedia)\"}','{\"Height\": \"5\'8\\\" (173 cm)\", \"(Source\": \"Wikipedia)\", \"Birthday\": \"1885 (Age 30 from vol. 10)\", \"Description\": \"Roy Mustang is the \\\"Flame Alchemist,\\\" having absolute control over heat and fire through alchemy. Using special gloves that create a spark when he snaps his fingers, Roy can create anything from a tiny ember to burn a letter, to a raging inferno that can destroy a humanoid body in seconds. His precise control over the alchemically enhanced flame is so accurate that he can boil the water in a persons\' eyes and can also attack enemies amongst a riot without hurting any allies.\", \"Description_2\": \"Outwardly arrogant and playfully manipulative, Mustang is intelligent and almost always one step ahead of his opponents, and likes to feel in control of the situation. He is one of the superiors of Edward Elric. On the surface, he appears to be nothing more than a man of the military who pursues promotions and praise and is considered a ladies\' man who constantly goes on dates with different women. Mustang\'s true goal is to become Führer in order to gain the power to reform the government in order to absolve his sins in the Ishval War as well as change the country for the better, along with the joking requirement for female officers to wear tiny miniskirts (which considerably increased Havoc\'s loyalty to him and caused Hawkeye to be angry with him).\", \"Description_3\": \"His goals are admirable enough that he earns the fierce loyalty of his good friends Lt Col. Maes Hughes, Major Alex Louis Armstrong, and his own subordinates, among whom are Riza Hawkeye, Jean Havoc, Heymans Breda, Vato Falman, and Kain Fuery. While Mustang has a close and amicable relationship with all of his subordinates, he appears to share a deeper bond of affection with his second-in-command Riza Hawkeye, who has devoted her life to supporting him. This bond culminates in the final episodes of the anime when Mustang chooses Hawkeye alone to accompany him on his greatest and most dangerous mission.\", \"Description_4\": \"Though a hero of the Ishval War, he remains haunted by the horrors of war and suffers great remorse for the lives he took.\"}'),(554,31562,'Narrator','{}','{}'),(555,41216,'Neil','{\"Description\":\"Neil is one of the chief engineers in the Research \\u0026amp; Development sector of Fort Briggs. While privy to all the mechanical goings-on in the fort, Neil is especially knowledgeable on the subject of cold-climate metals such as those used in North Area automail limbs and is often seen acting as Captain Buccaneer\\u0027s automail mechanic. A laid back and easygoing fellow, Neil is quick to make friends with those who come to the fort and is even more eager to share his expertise on the technological advancements the facility has made.\"}','{\"Description\": \"Neil is one of the chief engineers in the Research &amp; Development sector of Fort Briggs. While privy to all the mechanical goings-on in the fort, Neil is especially knowledgeable on the subject of cold-climate metals such as those used in North Area automail limbs and is often seen acting as Captain Buccaneer\'s automail mechanic. A laid back and easygoing fellow, Neil is quick to make friends with those who come to the fort and is even more eager to share his expertise on the technological advancements the facility has made.\"}'),(556,10960,'Old Man','{\"Description\":\"The leader of a group of Ishvalan survivors, he has repeatedly cared for Scar when Scar was injured in Central. After the mercenary raids against the Ishabalan camp in Central he moves his group further south. He is never mentioned by name in the anime nor the manga, though he was identified as Rick and Leo\\u0027s grandfather in the anime episode Marcoh\\u0027s Notes.\"}','{\"Description\": \"The leader of a group of Ishvalan survivors, he has repeatedly cared for Scar when Scar was injured in Central. After the mercenary raids against the Ishabalan camp in Central he moves his group further south. He is never mentioned by name in the anime nor the manga, though he was identified as Rick and Leo\'s grandfather in the anime episode Marcoh\'s Notes.\"}'),(557,10974,'Paninya','{\"Description\":\"A resident of Rush Valley, she lost her legs and right arm at a young age in a train wreck, but Dominic takes pity on her (in the form of social outrage) and gives her free automail legs and an arm. Thanks to these legs, she can run at great speed and jump great lengths. One leg also conceals a cannon, while the other has a long switchblade.\",\"Description_2\":\"She takes Ed, Al and Winry to see Dominic at Winry\\u0027s wish. Paninya had made a living out of pickpocketing tourists in Rush Valley, but after a talk with Winry she realizes that being a criminal would defeat the purpose that Dominic intended for her when he gave her free legs. She is currently working legitimate odd jobs around Garfiel\\u0027s shop.\",\"Description_3\":\"In the anime she also has an automail arm, which gets damaged in an arm wrestling contest. It also appears that Dominic adopted her after she lost her limbs in a train crash. No mention was made of what she did for a living, though in the chase with Edward, she was taking his pocketwatch to a pawn shop. However, this was most likely Winry\\u0027s idea for Ed cheating in an automail contest. Since she is seen in Dominics shop it can be assumed that she might work for him.\",\"Description_4\":\"She was seen at the end of the anime, helping Winry perfect her skills.\",\"Description_5\":\"In the manga the only automail she possesses is her prosthetic legs. It is noted that one leg has a Carbine rifle built into it by Dominic and the other a blade. She pickpocketed from tourists to try to pay back Dominic, who lives out in the mountains of Rush Valley with his son, his wife, and herself, for her automail. Dominic always refuses to accept her stolen money. After reforming her ways, she becomes a roofer and Dominic begins to reluctantly accept her money.\"}','{\"Description\": \"A resident of Rush Valley, she lost her legs and right arm at a young age in a train wreck, but Dominic takes pity on her (in the form of social outrage) and gives her free automail legs and an arm. Thanks to these legs, she can run at great speed and jump great lengths. One leg also conceals a cannon, while the other has a long switchblade.\", \"Description_2\": \"She takes Ed, Al and Winry to see Dominic at Winry\'s wish. Paninya had made a living out of pickpocketing tourists in Rush Valley, but after a talk with Winry she realizes that being a criminal would defeat the purpose that Dominic intended for her when he gave her free legs. She is currently working legitimate odd jobs around Garfiel\'s shop.\", \"Description_3\": \"In the anime she also has an automail arm, which gets damaged in an arm wrestling contest. It also appears that Dominic adopted her after she lost her limbs in a train crash. No mention was made of what she did for a living, though in the chase with Edward, she was taking his pocketwatch to a pawn shop. However, this was most likely Winry\'s idea for Ed cheating in an automail contest. Since she is seen in Dominics shop it can be assumed that she might work for him.\", \"Description_4\": \"She was seen at the end of the anime, helping Winry perfect her skills.\", \"Description_5\": \"In the manga the only automail she possesses is her prosthetic legs. It is noted that one leg has a Carbine rifle built into it by Dominic and the other a blade. She pickpocketed from tourists to try to pay back Dominic, who lives out in the mountains of Rush Valley with his son, his wife, and herself, for her automail. Dominic always refuses to accept her stolen money. After reforming her ways, she becomes a roofer and Dominic begins to reluctantly accept her money.\"}'),(558,39241,'Raven','{}','{}'),(559,10958,'Rick','{\"Description\":\"Leo\\u0027s younger brother. He carries a locket of his mother with him, even though it was broken and would not open. He was captured briefly by mercenaries in Central, but was rescued by Scar, Alphonse, and Edward. Rick was nearly killed during the rescue attempt, only the locket of his mother saved him. The force placed on the locket caused it to open, revealing a picture of Rick, Leo, and their mother; additionally, several small pills for the treatment of blindness were discovered inside it. Toward the end of the anime series Edward receives permission from the military to have Rick and his older brother Leo released and transferred to Resembool; however both Rick and Leo turn down the offer.\",\"Description_2\":\"In the manga, Rick and the old man pull Scar out of the sewer in East City after Scar\\u0027s first encounter with the Homunculi. They tend to his wounds until the mercenaries try to arrest Scar, then Scar leaves the slum and they are not seen again. It is implied that the fair-skinned and fair-haired manga version of this boy is half-Ishvalan (as he reassures an injured Scar that he\\u0027s safe because \\u0022Mom and I are Ishvalan too!\\u0022) Rick wasn\\u0027t named in the manga.\"}','{\"Description\": \"Leo\'s younger brother. He carries a locket of his mother with him, even though it was broken and would not open. He was captured briefly by mercenaries in Central, but was rescued by Scar, Alphonse, and Edward. Rick was nearly killed during the rescue attempt, only the locket of his mother saved him. The force placed on the locket caused it to open, revealing a picture of Rick, Leo, and their mother; additionally, several small pills for the treatment of blindness were discovered inside it. Toward the end of the anime series Edward receives permission from the military to have Rick and his older brother Leo released and transferred to Resembool; however both Rick and Leo turn down the offer.\", \"Description_2\": \"In the manga, Rick and the old man pull Scar out of the sewer in East City after Scar\'s first encounter with the Homunculi. They tend to his wounds until the mercenaries try to arrest Scar, then Scar leaves the slum and they are not seen again. It is implied that the fair-skinned and fair-haired manga version of this boy is half-Ishvalan (as he reassures an injured Scar that he\'s safe because \\\"Mom and I are Ishvalan too!\\\") Rick wasn\'t named in the manga.\"}'),(560,10966,'Roa','{\"Description\":\"A chimera that follows Greed. He was fused with a bull, making him as strong as one, as demonstrated to Al when he literally knocks Greed\\u0027s head off with his hammer (Greed, naturally, recovers from this). He wields a hammer as his weapon and has an ability to transform into an enhanced version of himself with more bull-like aspects like horns and greater strength. He\\u0027s the only one of the three that fought in Ishval. He cameos in the 15th volume, shown as a background soldier, after Roy Mustang\\u0027s appearance in the battle ground.\"}','{\"Description\": \"A chimera that follows Greed. He was fused with a bull, making him as strong as one, as demonstrated to Al when he literally knocks Greed\'s head off with his hammer (Greed, naturally, recovers from this). He wields a hammer as his weapon and has an ability to transform into an enhanced version of himself with more bull-like aspects like horns and greater strength. He\'s the only one of the three that fought in Ishval. He cameos in the 15th volume, shown as a background soldier, after Roy Mustang\'s appearance in the battle ground.\"}'),(561,261250,'Roach, Liam','{\"Description\":\"Liam Roach is an Amestrian State Military Officer stationed at Fort Briggs under the command of Major General Armstrong.\",\"Description_2\":\"Liam first appeared under the command of Major Miles in Baschool with the goal of capturing Scar. In the spring of the year 1915, he, along with Mick Murray, was responsible for getting Winry Rockbell back home safely. During the promised day he and Mick stayed at Rockbell Automail to protect Pinako Rockbell and Winry Rockbell, but couldn\\u0027t do anything against the Nationwide Transmutation Circle.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Liam Roach is an Amestrian State Military Officer stationed at Fort Briggs under the command of Major General Armstrong.\", \"Description_2\": \"Liam first appeared under the command of Major Miles in Baschool with the goal of capturing Scar. In the spring of the year 1915, he, along with Mick Murray, was responsible for getting Winry Rockbell back home safely. During the promised day he and Mick stayed at Rockbell Automail to protect Pinako Rockbell and Winry Rockbell, but couldn\'t do anything against the Nationwide Transmutation Circle.\"}'),(562,260678,'Rockbell, Sarah','{\"Description\":\"Dr. Sarah Rockbell (also spelled Sara in the 2003 anime) was a surgeon and the mother of Winry Rockbell, the daughter-in-law of Pinako Rockbell, the mother-in-law of Edward Elric and the maternal grandmother of Edward and Winry\\u0027s unnamed children. She married into the Rockbell family by wedding Yuriy Rockbell, Pinako Rockbell\\u0027s son and practiced medicine alongside her husband. When the Ishval Civil War reached its peak, the two left their family home in Resembool to help treat the wounded on the front lines. Though both Amestrian, the Rockbells were rather well known in the Kanda region of Ishval for treating the injured on either side of the conflict. Though many, including Doctors Marcoh and Knox, viewed them as a medical inspiration and several Ishvalan people owe their lives to the husband and wife medical team, the Amestrian military officials began to view their humanitarian effort as a nuisance and sought to have them killed.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Dr. Sarah Rockbell (also spelled Sara in the 2003 anime) was a surgeon and the mother of Winry Rockbell, the daughter-in-law of Pinako Rockbell, the mother-in-law of Edward Elric and the maternal grandmother of Edward and Winry\'s unnamed children. She married into the Rockbell family by wedding Yuriy Rockbell, Pinako Rockbell\'s son and practiced medicine alongside her husband. When the Ishval Civil War reached its peak, the two left their family home in Resembool to help treat the wounded on the front lines. Though both Amestrian, the Rockbells were rather well known in the Kanda region of Ishval for treating the injured on either side of the conflict. Though many, including Doctors Marcoh and Knox, viewed them as a medical inspiration and several Ishvalan people owe their lives to the husband and wife medical team, the Amestrian military officials began to view their humanitarian effort as a nuisance and sought to have them killed.\"}'),(563,24923,'Rockbell, Den','{\"Description\":\"Winry Rockbell\\u0027s dog that has an auto-mail left leg.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Winry Rockbell\'s dog that has an auto-mail left leg.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(564,260679,'Rockbell, Yuriy','{\"Description\":\"Dr. Yuriy Rockbell (also spelled Urey in the 2003 anime) was the father of Winry Rockbell, the son of Pinako Rockbell, the father-in-law of Edward Elric, and the paternal grandfather of Edward and Winry\\u0027s unnamed children. He grew up, lived and worked in Resembool as a surgeon alongside his wife, Sarah Rockbell. When the Ishval Civil War reached its peak, the two Doctors Rockbell left their family home in Resembool to help treat the wounded on the front lines. Though both Amestrian, the Rockbells were rather well known in the Kanda region of Ishval for treating the injured on either side of the conflict. Though many, including Doctors Marcoh and Knox, viewed them as a medical inspiration and several Ishvalan people owe their lives to the husband and wife medical team, the Amestrian military officials began to view their humanitarian effort as a nuisance and sought to have them killed.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Dr. Yuriy Rockbell (also spelled Urey in the 2003 anime) was the father of Winry Rockbell, the son of Pinako Rockbell, the father-in-law of Edward Elric, and the paternal grandfather of Edward and Winry\'s unnamed children. He grew up, lived and worked in Resembool as a surgeon alongside his wife, Sarah Rockbell. When the Ishval Civil War reached its peak, the two Doctors Rockbell left their family home in Resembool to help treat the wounded on the front lines. Though both Amestrian, the Rockbells were rather well known in the Kanda region of Ishval for treating the injured on either side of the conflict. Though many, including Doctors Marcoh and Knox, viewed them as a medical inspiration and several Ishvalan people owe their lives to the husband and wife medical team, the Amestrian military officials began to view their humanitarian effort as a nuisance and sought to have them killed.\"}'),(565,63,'Rockbell, Winry','{\"Birthplace\":\"Resembool\",\"Birth date\":\"1899\",\"Age\":\"15-16 (around 18 at the end)\",\"Family\":\"Pinako Rockbell (grandmother), Urey Rockbell (father, deceased), Sara Rockbell (mother, deceased)\",\"Affiliations\":\"Rockbell Automail, Atelier Garfiel\",\"Occupation\":\"Automail mechanic\",\"Abilities\":\"Automail specialist and mechanic, amateur surgeon\",\"Unique Trait\":\"An unusual love for machines and tools\",\"Description\":\"A childhood friend of the central characters, the Elric brothers, Winry is often seen in their company throughout the series. She is evidently Edward\\u0027s love interest. Specializing in mechanical repair, specifically with automail, Winry services Edward\\u0027s arm and leg whenever it is in need of repair or replacement.\"}','{\"Age\": \"15-16 (around 18 at the end)\", \"Family\": \"Pinako Rockbell (grandmother), Urey Rockbell (father, deceased), Sara Rockbell (mother, deceased)\", \"Abilities\": \"Automail specialist and mechanic, amateur surgeon\", \"Birth date\": \"1899\", \"Birthplace\": \"Resembool\", \"Occupation\": \"Automail mechanic\", \"Description\": \"A childhood friend of the central characters, the Elric brothers, Winry is often seen in their company throughout the series. She is evidently Edward\'s love interest. Specializing in mechanical repair, specifically with automail, Winry services Edward\'s arm and leg whenever it is in need of repair or replacement.\", \"Affiliations\": \"Rockbell Automail, Atelier Garfiel\", \"Unique Trait\": \"An unusual love for machines and tools\"}'),(566,65,'Rockbell, Pinako','{\"Description\":\"Pinako Rockbell is the grandmother of Winry, and an old resident of Risembool. She\\u0027s also a parent-like figure to both Edward and Alphonse, after they lost their mother.\",\"Description_2\":\"It is shown that Pinako was Hohenheim\\u0027s drinking buddy and that she was the one to introduce Hohenheim to his future wife, Trisha.\"}','{\"Description\": \"Pinako Rockbell is the grandmother of Winry, and an old resident of Risembool. She\'s also a parent-like figure to both Edward and Alphonse, after they lost their mother.\", \"Description_2\": \"It is shown that Pinako was Hohenheim\'s drinking buddy and that she was the one to introduce Hohenheim to his future wife, Trisha.\"}'),(567,9319,'Ross, Maria','{\"Description\":\"Second Lieutenant Maria Ross is put in charge of taking care of the Elric brothers during their stay in Central. She and her partner Brosh were assigned the task of guarding the Elrics due to Scar\\u0027s return in Central and his previous attempt on Ed and Al\\u0027s lives. Almost immediately, she takes on the role of a parental figure. She tries to give guidance to the brothers whenever she can. She took a liking to Ed and Al, and risked her life to calm Ed down when he was absorbing the red stone material inside laboratory 5. Both she and her partner Denny Brosh work under Major Alex Louis Armstrong.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Second Lieutenant Maria Ross is put in charge of taking care of the Elric brothers during their stay in Central. She and her partner Brosh were assigned the task of guarding the Elrics due to Scar\'s return in Central and his previous attempt on Ed and Al\'s lives. Almost immediately, she takes on the role of a parental figure. She tries to give guidance to the brothers whenever she can. She took a liking to Ed and Al, and risked her life to calm Ed down when he was absorbing the red stone material inside laboratory 5. Both she and her partner Denny Brosh work under Major Alex Louis Armstrong.\"}'),(568,66,'Scar','{\"Description\":\"Though his real name and his past are unknown, Scar is a well-known killer in Central City, who targets State Alchemists due to his tortured history surrounding the Ishvalan Civil War.\"}','{\"Description\": \"Though his real name and his past are unknown, Scar is a well-known killer in Central City, who targets State Alchemists due to his tortured history surrounding the Ishvalan Civil War.\"}'),(569,25547,'Scar\'s Brother','{\"Description\":\"Scar\\u0027s Brother giving up his life and arm to save Scar\\u0027s after he had been gravely wounded.\",\"Description_2\":\"Just like Scar his real name has never been revealed.\"}','{\"Description\": \"Scar\'s Brother giving up his life and arm to save Scar\'s after he had been gravely wounded.\", \"Description_2\": \"Just like Scar his real name has never been revealed.\"}'),(570,10970,'Scar\'s Master','{\"Description\":\"Scar\\u0027s mentor from Ishval, a holy man. The two got separated when Kimblee attacked the group of refugees of which they were a part. Upon learning of his student\\u0027s \\u0022crusade\\u0022 against State Alchemists, he counsels him on the teachings of Ishvala. In the anime, he says, \\u0022Even in the darkest of suffering, a man can sleep. But for the man who inflicts the suffering, his mind cannot rest. Ever.\\u0022 In the manga, he explains \\u0022Revenge only grows seeds of revenge,\\u0022 (which Scar didn\\u0027t care for much until he found Winry pointing a gun at him, intending to seek revenge for her parents\\u0027 deaths, as Scar was responsible for their deaths). He later speaks on behalf of the Ishvalans at a refugee camp when Mustang and his men arrive looking for Scar. Scar\\u0027s master was one of the few survivors of the covert op of which Martel was a part, and which triggered the Ishval massacre. He is never mentioned by name in the anime. He also appears in the manga, as he is seen in Chapter 58 and in chapter 72 in a flashback when stating that although they may (and should) not forgive the damage Amestris has done to the Ishval, but they must not surrender to the hatred; they should endure it to sever the bonds of hatred, since they\\u0027re human beings.\"}','{\"Description\": \"Scar\'s mentor from Ishval, a holy man. The two got separated when Kimblee attacked the group of refugees of which they were a part. Upon learning of his student\'s \\\"crusade\\\" against State Alchemists, he counsels him on the teachings of Ishvala. In the anime, he says, \\\"Even in the darkest of suffering, a man can sleep. But for the man who inflicts the suffering, his mind cannot rest. Ever.\\\" In the manga, he explains \\\"Revenge only grows seeds of revenge,\\\" (which Scar didn\'t care for much until he found Winry pointing a gun at him, intending to seek revenge for her parents\' deaths, as Scar was responsible for their deaths). He later speaks on behalf of the Ishvalans at a refugee camp when Mustang and his men arrive looking for Scar. Scar\'s master was one of the few survivors of the covert op of which Martel was a part, and which triggered the Ishval massacre. He is never mentioned by name in the anime. He also appears in the manga, as he is seen in Chapter 58 and in chapter 72 in a flashback when stating that although they may (and should) not forgive the damage Amestris has done to the Ishval, but they must not surrender to the hatred; they should endure it to sever the bonds of hatred, since they\'re human beings.\"}'),(571,8452,'Sheska','{\"Description\":\"Sheska is a bookworm to the letter. Her house is full with piles of books. One could say, \\u0022No one can possibly live here.\\u0022\",\"Description_2\":\"She was a librarian at the First Branch of the Central City library, but when she was at the Central City library, she forgot she was supposed to be working and read books instead. As one could expect, she got fired.\",\"Description_3\":\"When the Central City library burnt down, she was the key to the books that got lost in the fire because Sheska is gifted with the talent to remember and reproduce anything she has ever read with word-for-word accuracy. Therefore, she got rehired by the military.\",\"Description_4\":\"When looking at the fact that Sheska has collector\\u0027s mania; forgets anything around her when she reads a book; and her extraordinary talent to reproduce books she read times ago, one could conclude she has savant autism.\"}','{\"Description\": \"Sheska is a bookworm to the letter. Her house is full with piles of books. One could say, \\\"No one can possibly live here.\\\"\", \"Description_2\": \"She was a librarian at the First Branch of the Central City library, but when she was at the Central City library, she forgot she was supposed to be working and read books instead. As one could expect, she got fired.\", \"Description_3\": \"When the Central City library burnt down, she was the key to the books that got lost in the fire because Sheska is gifted with the talent to remember and reproduce anything she has ever read with word-for-word accuracy. Therefore, she got rehired by the military.\", \"Description_4\": \"When looking at the fact that Sheska has collector\'s mania; forgets anything around her when she reads a book; and her extraordinary talent to reproduce books she read times ago, one could conclude she has savant autism.\"}'),(572,10962,'Slicer Brothers','{\"Description\":\"A pair of serial killers who had their souls sealed into a single suit of armor (one sealed in the head and one sealed in the suit) and became one of the guardians of the 5th laboratory under the joint alias of \\u0022Number 48,\\u0022 assigned to kill any intruders.\",\"Description_2\":\"In an omake (a short bonus comic), the older brother is a cat lover while the younger is a dog lover, which leads them to bicker at times. However, the younger brother always wins because he actually has body parts, while the older brother only has a head.\"}','{\"Description\": \"A pair of serial killers who had their souls sealed into a single suit of armor (one sealed in the head and one sealed in the suit) and became one of the guardians of the 5th laboratory under the joint alias of \\\"Number 48,\\\" assigned to kill any intruders.\", \"Description_2\": \"In an omake (a short bonus comic), the older brother is a cat lover while the younger is a dog lover, which leads them to bicker at times. However, the younger brother always wins because he actually has body parts, while the older brother only has a head.\"}'),(573,15543,'Sloth','{\"Description\":\"Sloth is the fifth Homunculus created by Father. Appearing as a giant, muscular, but mentally slow man, Sloth spends most of the story digging the country spanning underground tunnels that make up the Father\\u0027s mysterious transmutation circle. A conversation between Greed and Lust implies that Sloth have dug tunnels for at least a hundred years. Not surprisingly, he seems eager to finish his work so he can rest at last.\",\"In the first anime, Sloth was inadvertently created in the failed human transmutation of Ed and Al, and appeared as their mother, quite the opposite of what he is characterized as in Fullmetal Alchemist\":\"Brotherhood.\",\"Description_2\":\"After completion of the tunnel, Sloth is ordered to Central on the Promised Day, where he is to kill anyone who could potentially ruin Father\\u0027s plan, most notably General Armstrong. She manages to hold him off with the help of her younger brother, but the appearance of the Mannequin Soldiers and Central troops throw off their tactics. Sloth reveals his Homunculus trait, the ability to move at supersonic speeds, and nearly kills the two before Izumi and Sig Curtis arrive and help destroy Sloth\\u0027s Philosopher\\u0027s Stone.\"}','{\"Description\": \"Sloth is the fifth Homunculus created by Father. Appearing as a giant, muscular, but mentally slow man, Sloth spends most of the story digging the country spanning underground tunnels that make up the Father\'s mysterious transmutation circle. A conversation between Greed and Lust implies that Sloth have dug tunnels for at least a hundred years. Not surprisingly, he seems eager to finish his work so he can rest at last.\", \"Description_2\": \"After completion of the tunnel, Sloth is ordered to Central on the Promised Day, where he is to kill anyone who could potentially ruin Father\'s plan, most notably General Armstrong. She manages to hold him off with the help of her younger brother, but the appearance of the Mannequin Soldiers and Central troops throw off their tactics. Sloth reveals his Homunculus trait, the ability to move at supersonic speeds, and nearly kills the two before Izumi and Sig Curtis arrive and help destroy Sloth\'s Philosopher\'s Stone.\", \"In the first anime, Sloth was inadvertently created in the failed human transmutation of Ed and Al, and appeared as their mother, quite the opposite of what he is characterized as in Fullmetal Alchemist\": \"Brotherhood.\"}'),(574,261233,'Storch','{\"Description\":\"Storch is an Amestrian State Military Officer stationed in Central City and the personal secretary of the F\\u00FChrer, King Bradley, until Lt. Riza Hawkeye is given the position so as to allow Bradley to keep an eye on her and the other members of Colonel Mustang\\u0027s team. He arrives outside Central Command to deliver Hawkeye\\u0027s new orders personally and is accompanied by Yakovlev from Internal Affairs. However, his first appearance was in Edward Elric\\u0027s practical exam when Edward tries to scare the country\\u0027s leader through his spear. Storch and some more soldiers berate the young alchemist for that arrogant act and intend to disqualify him in that particular moment. The lieutenant colonel reappears again in Southern Command accompanied with the F\\u00FChrer and Alex Louis Armstrong in Edward\\u0027s presence who pretends to submit his annual assessment report.\",\"(Source\":\"Fullmetal Alchemist)\"}','{\"(Source\": \"Fullmetal Alchemist)\", \"Description\": \"Storch is an Amestrian State Military Officer stationed in Central City and the personal secretary of the Führer, King Bradley, until Lt. Riza Hawkeye is given the position so as to allow Bradley to keep an eye on her and the other members of Colonel Mustang\'s team. He arrives outside Central Command to deliver Hawkeye\'s new orders personally and is accompanied by Yakovlev from Internal Affairs. However, his first appearance was in Edward Elric\'s practical exam when Edward tries to scare the country\'s leader through his spear. Storch and some more soldiers berate the young alchemist for that arrogant act and intend to disqualify him in that particular moment. The lieutenant colonel reappears again in Southern Command accompanied with the Führer and Alex Louis Armstrong in Edward\'s presence who pretends to submit his annual assessment report.\"}'),(575,261294,'Tetsu','{\"Description\":\"Tetsu is a young boy living in the town of Rush Valley in southern Amestris.\",\"Description_2\":\"With his right leg replaced with an automail prosthesis due to an unknown accident, Tetsu relies on the Atelier Garfiel for his mechanical upkeep and repairs, specifically Atelier Garfiel\\u0027s pretty new apprentice Winry Rockbell.\",\"Description_3\":\"During Winry\\u0027s long absence in Central City, Tetsu is one of the clients who speaks to her over the phone, enthusiastically requesting her speedy return and he himself comments cheekily that he would prefer to have a pretty girl like Winry working on his leg than chief engineer Garfiel.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Tetsu is a young boy living in the town of Rush Valley in southern Amestris.\", \"Description_2\": \"With his right leg replaced with an automail prosthesis due to an unknown accident, Tetsu relies on the Atelier Garfiel for his mechanical upkeep and repairs, specifically Atelier Garfiel\'s pretty new apprentice Winry Rockbell.\", \"Description_3\": \"During Winry\'s long absence in Central City, Tetsu is one of the clients who speaks to her over the phone, enthusiastically requesting her speedy return and he himself comments cheekily that he would prefer to have a pretty girl like Winry working on his leg than chief engineer Garfiel.\"}'),(576,5988,'Tomas, Rosé','{\"Description\":\"Ros\\u00E9 is from the city of Lior in a remote region of the East. She was a devout follower of Cornello\\u0027s teachings because she felt that he would use his powers to bring her boyfriend, Kain, back to life. Instead, Cornello created a talking parrot chimera to mimic Kain\\u0027s voice. When Ros\\u00E9 discovered this, he locked her in the room with it, using the incomplete Philosopher\\u0027s Stone to get it to attack her. Al saved her, and together with Ed, they discredited Cornello.\",\"Description_2\":\"In the 2003 anime\",\"Description_3\":\"In the 2009 anime\",\"(Source\":\"Wikipedia, edited)\"}','{\"(Source\": \"Wikipedia, edited)\", \"Description\": \"Rosé is from the city of Lior in a remote region of the East. She was a devout follower of Cornello\'s teachings because she felt that he would use his powers to bring her boyfriend, Kain, back to life. Instead, Cornello created a talking parrot chimera to mimic Kain\'s voice. When Rosé discovered this, he locked her in the room with it, using the incomplete Philosopher\'s Stone to get it to attack her. Al saved her, and together with Ed, they discredited Cornello.\", \"Description_2\": \"In the 2003 anime\", \"Description_3\": \"In the 2009 anime\"}'),(577,33816,'Truth','{\"Description\":\"Truth is the most commonly used name for the mysterious and ethereal being that sits before The Gate and addresses alchemists who have stepped into God\\u0027s domain through the use of alchemy. It appears as a pure white, nearly formless being almost indistinguishable from the rest of the endless white expanse which surrounds the Gate but for a shadowy outline which causes Truth to reflect the shape of the person it is talking to, thereby supporting its claim to be another shade of that very person. When Edward and Alphonse Elric each appeared before the Gate, Truth took on the shape of a young boy and when Izumi Curtis appeared, Truth\\u0027s shape reflected that of a young woman, appeared as a vigorous man to Roy Mustang, and a white version of Father\\u0027s flask form.\",\"Description_2\":\"Truth initially introduces itself as the being some people call God, the World or the Universe, at first seeming welcoming and jovial to its guests before calling attention to their hubris and opening the Gate, which forces them inside. At this point, Truth often smiles with an eerily wide and insane grin that is similar to that of the Homunculus Gluttony and Father.\",\"Description_3\":\"When the alchemist in question returns from his or her sojourn through the Gate, Truth informs them of the necessary toll for accessing the Universe\\u0027s knowledge and collects it, usually in the form of a body part which disintegrates off the alchemist and reappears on Truth\\u0027s form. In this way Truth is responsible for the taking of Edward\\u0027s left leg and right arm, some of Izumi\\u0027s internal organs, Roy\\u0027s eyesight, and Alphonse\\u0027s entire body.\",\"Description_4\":\"It would appear that Truth\\u0027s goal is to discourage humans from treading in God\\u0027s domain, as it calls Edward a fool when the young boy returns and sacrifices his arm to recover his brother\\u0027s soul.\",\"(Source\":\"Fullmetal Alchemist Wikia)\"}','{\"(Source\": \"Fullmetal Alchemist Wikia)\", \"Description\": \"Truth is the most commonly used name for the mysterious and ethereal being that sits before The Gate and addresses alchemists who have stepped into God\'s domain through the use of alchemy. It appears as a pure white, nearly formless being almost indistinguishable from the rest of the endless white expanse which surrounds the Gate but for a shadowy outline which causes Truth to reflect the shape of the person it is talking to, thereby supporting its claim to be another shade of that very person. When Edward and Alphonse Elric each appeared before the Gate, Truth took on the shape of a young boy and when Izumi Curtis appeared, Truth\'s shape reflected that of a young woman, appeared as a vigorous man to Roy Mustang, and a white version of Father\'s flask form.\", \"Description_2\": \"Truth initially introduces itself as the being some people call God, the World or the Universe, at first seeming welcoming and jovial to its guests before calling attention to their hubris and opening the Gate, which forces them inside. At this point, Truth often smiles with an eerily wide and insane grin that is similar to that of the Homunculus Gluttony and Father.\", \"Description_3\": \"When the alchemist in question returns from his or her sojourn through the Gate, Truth informs them of the necessary toll for accessing the Universe\'s knowledge and collects it, usually in the form of a body part which disintegrates off the alchemist and reappears on Truth\'s form. In this way Truth is responsible for the taking of Edward\'s left leg and right arm, some of Izumi\'s internal organs, Roy\'s eyesight, and Alphonse\'s entire body.\", \"Description_4\": \"It would appear that Truth\'s goal is to discourage humans from treading in God\'s domain, as it calls Edward a fool when the young boy returns and sacrifices his arm to recover his brother\'s soul.\"}'),(578,4159,'Tucker, Nina','{\"Description\":\"Nina\\u0027s father was Shou Tucker, the Sewing Life Alchemist.\"}','{\"Description\": \"Nina\'s father was Shou Tucker, the Sewing Life Alchemist.\"}'),(579,3696,'Tucker, Shou','{\"Description\":\"The \\u0022Sewing-Life\\u0022 Alchemist who created a talking chimera. Later on it is realized that the first speaking chimera he created was made from lab animals and his wife who he transmuted into a chimera out of a fit of anger.\",\"In the 2003 Series\":\"\"}','{\"Description\": \"The \\\"Sewing-Life\\\" Alchemist who created a talking chimera. Later on it is realized that the first speaking chimera he created was made from lab animals and his wife who he transmuted into a chimera out of a fit of anger.\", \"In the 2003 Series\": \"\"}'),(580,261234,'Yakovlev','{\"Description\":\"Yakovlev is an Amestrian State Military Officer from the Internal Affairs office at Central Command in Central City.\",\"Description_2\":\"Along with Storch, he approaches Riza Hawkeye with transfer orders from the top, reassigning her to the post of F\\u00FChrer\\u0027s personal secretary.\",\"(Source\":\"Fullmetal Alchemist Wiki)\"}','{\"(Source\": \"Fullmetal Alchemist Wiki)\", \"Description\": \"Yakovlev is an Amestrian State Military Officer from the Internal Affairs office at Central Command in Central City.\", \"Description_2\": \"Along with Storch, he approaches Riza Hawkeye with transfer orders from the top, reassigning her to the post of Führer\'s personal secretary.\"}'),(581,3293,'Yao, Ling','{\"Description\":\"Ling Yao is a Xingese character exclusive to the manga and the 2009 anime series. Due to his father, the Emperor\\u0027s, declining health, Ling left his country to find the Philosopher\\u0027s Stone to stabilize Xing, as well as grant him the key to immortality. Although he is the 12th son of the Emperor, Ling hopes the Philosopher\\u0027s Stone will help him rise in the order of succession and achieve the throne thereby securing his clan\\u0027s welfare. Though he is often laid back and hungry, he\\u0027s very noble and will do whatever it takes to help his clan. He is also a skilled fighter and has had many incidents involving assassination attempts at his life. He has formed a strong rivalry with Ed, by doing things such as use Ed\\u0027s money to annoy him.\"}','{\"Description\": \"Ling Yao is a Xingese character exclusive to the manga and the 2009 anime series. Due to his father, the Emperor\'s, declining health, Ling left his country to find the Philosopher\'s Stone to stabilize Xing, as well as grant him the key to immortality. Although he is the 12th son of the Emperor, Ling hopes the Philosopher\'s Stone will help him rise in the order of succession and achieve the throne thereby securing his clan\'s welfare. Though he is often laid back and hungry, he\'s very noble and will do whatever it takes to help his clan. He is also a skilled fighter and has had many incidents involving assassination attempts at his life. He has formed a strong rivalry with Ed, by doing things such as use Ed\'s money to annoy him.\"}'),(582,21907,'Yoki','{\"Description\":\"Yoki  is, when first introduced, a corrupt member of the military who imposes heavy taxes on the town of Youswell, bankrupting its citizens. When the Elric brothers arrive in town, they trick Yoki into giving up ownership of the town and promptly report his actions to the military He is stripped of his rank and lives as a homeless person on the outskirts of Central, where he meets the fugitive Scar. In the anime, Yoki alerts the military to Scar\\u0027s location, and in the subsequent raid to apprehend Scar he is killed by Lust. In the manga, Yoki is forced to work for Scar under the threat of death. Though he tries to convince those they encounter that Scar is his servant, Yoki does as Scar commands and calls him \\u0022master\\u0022. Since he has started following Scar around the country, Yoki has assumed a role as comic relief, often having pain inflicted upon him when he tries to seem superior to others.\",\"(Source\":\"Wikipedia)\"}','{\"(Source\": \"Wikipedia)\", \"Description\": \"Yoki  is, when first introduced, a corrupt member of the military who imposes heavy taxes on the town of Youswell, bankrupting its citizens. When the Elric brothers arrive in town, they trick Yoki into giving up ownership of the town and promptly report his actions to the military He is stripped of his rank and lives as a homeless person on the outskirts of Central, where he meets the fugitive Scar. In the anime, Yoki alerts the military to Scar\'s location, and in the subsequent raid to apprehend Scar he is killed by Lust. In the manga, Yoki is forced to work for Scar under the threat of death. Though he tries to convince those they encounter that Scar is his servant, Yoki does as Scar commands and calls him \\\"master\\\". Since he has started following Scar around the country, Yoki has assumed a role as comic relief, often having pain inflicted upon him when he tries to seem superior to others.\"}'),(583,15534,'Zampano','{\"Description\":\"A boar-like chimera who was initially one of Kimblee\\u0027s bodyguards, but deserted and joined Scar instead.\"}','{\"Description\": \"A boar-like chimera who was initially one of Kimblee\'s bodyguards, but deserted and joined Scar instead.\"}'),(584,29455,'Gotou, Kazutoshi','{\"Description\":\"Detective Kazutoshi Gotou is a middle-aged clumsy workaholic detective. He is an action over words/thinking person. He knows Yakumo from a long time ago. He considers Yakumo like family and worries about him despite how he often gets angry at Yakumo for his contrary attitude. He asks for Yakumo\\u0027s help whenever there is a paranormal involvement in the case he\\u0027s investigating in. Despite Gotou\\u0027s rough ways he is actually very kind, he sometimes gets too involved in a case and if it does not work out right he blames himself for it.\",\"Secret Files - Kizuna\":\"\"}','{\"Description\": \"Detective Kazutoshi Gotou is a middle-aged clumsy workaholic detective. He is an action over words/thinking person. He knows Yakumo from a long time ago. He considers Yakumo like family and worries about him despite how he often gets angry at Yakumo for his contrary attitude. He asks for Yakumo\'s help whenever there is a paranormal involvement in the case he\'s investigating in. Despite Gotou\'s rough ways he is actually very kind, he sometimes gets too involved in a case and if it does not work out right he blames himself for it.\", \"Secret Files - Kizuna\": \"\"}'),(585,26959,'Ozawa, Haruka','{\"Description\":\"Haruka is a second year university student. Her twin sister died in a car accident when she was seven years old which she blames herself for, seeing as her sister was chasing a ball she threw onto the road. She asks Yakumo to save her friend Miki from demons possesing her. She is the first person who is not frightened of Yakumo\\u0027s different eyes or his ability to see ghosts. She even says they are beautiful, as Yakumo\\u0027s uncle once predicted. Because of Yakumo, she is able to see her twin sister who died in an car accident when she was seven years old.\",\"Description_2\":\"Haruka seems to have some feelings toward Yakumo, which developed into some kind of crush.\"}','{\"Description\": \"Haruka is a second year university student. Her twin sister died in a car accident when she was seven years old which she blames herself for, seeing as her sister was chasing a ball she threw onto the road. She asks Yakumo to save her friend Miki from demons possesing her. She is the first person who is not frightened of Yakumo\'s different eyes or his ability to see ghosts. She even says they are beautiful, as Yakumo\'s uncle once predicted. Because of Yakumo, she is able to see her twin sister who died in an car accident when she was seven years old.\", \"Description_2\": \"Haruka seems to have some feelings toward Yakumo, which developed into some kind of crush.\"}'),(586,23272,'Saitou, Yakumo','{\"Description\":\"Saitou Yakumo is a college student. He was born with different eye colors. His red left eye gives him a special ability to see ghosts and spirits. He believes ghosts and spirits are bound to earth because of a certain \\u0027cause\\u0027 and simply eliminating that \\u0027cause\\u0027 will those spirits rest in peace. Being asked for help by Ozawa Haruka, they begin the investigation together.\"}','{\"Description\": \"Saitou Yakumo is a college student. He was born with different eye colors. His red left eye gives him a special ability to see ghosts and spirits. He believes ghosts and spirits are bound to earth because of a certain \'cause\' and simply eliminating that \'cause\' will those spirits rest in peace. Being asked for help by Ozawa Haruka, they begin the investigation together.\"}'),(587,45227,'Gotou, Atsuko','{\"Description\":\"Gotou\\u0027s wife.\"}','{\"Description\": \"Gotou\'s wife.\"}'),(588,42688,'Hata, Hideyoshi','{\"Description\":\"Through the anime he has seen to be a forensic doctor who deals with dead people he helps Yakumo and the detectives out.\"}','{\"Description\": \"Through the anime he has seen to be a forensic doctor who deals with dead people he helps Yakumo and the detectives out.\"}'),(589,38342,'Hijikata, Makoto','{\"Description\":\"She is a reporter who seems to have a crush on Ishii Yuutarou. She sometimes help the characters with cases.\"}','{\"Description\": \"She is a reporter who seems to have a crush on Ishii Yuutarou. She sometimes help the characters with cases.\"}'),(590,29454,'Ishii, Yuutarou','{\"Description\":\"Detective who works under Detective Gotou and who starts out loving the supernatural but after experiencing it first hand is scared of the supernatural. However, he still remains very interested in supernatural phenomena, at times suggesting the causes behind events are because of it.\",\"Description_2\":\"Although Gotou doesn\\u0027t think too highly of Ishii, Miyawaka and Yakumo thinks highly of Ishii. Throughout the series, Ishii slowly changes into a person more sure and confident of his abilities, even later starting to voice his opinions against Gotou. He admires and respects Gotou, wanting to be a detective like Gotou. He has a crush on Haruka.\",\"Shinrei Tantei Yakumo\":\"Another Files\"}','{\"Description\": \"Detective who works under Detective Gotou and who starts out loving the supernatural but after experiencing it first hand is scared of the supernatural. However, he still remains very interested in supernatural phenomena, at times suggesting the causes behind events are because of it.\", \"Description_2\": \"Although Gotou doesn\'t think too highly of Ishii, Miyawaka and Yakumo thinks highly of Ishii. Throughout the series, Ishii slowly changes into a person more sure and confident of his abilities, even later starting to voice his opinions against Gotou. He admires and respects Gotou, wanting to be a detective like Gotou. He has a crush on Haruka.\", \"Shinrei Tantei Yakumo\": \"Another Files\"}'),(591,54463,'Kinoshita, Eiichi','{\"Description\":\"Dr. Kinoshita was the doctor who delivered Yakumo and asked after his mother. His daughter Ayaka died during a typhoon and drown in the river.\"}','{\"Description\": \"Dr. Kinoshita was the doctor who delivered Yakumo and asked after his mother. His daughter Ayaka died during a typhoon and drown in the river.\"}'),(592,45911,'Mamiya, Yoshiko','{}','{}'),(593,45221,'Miyagawa, Eriko','{}','{}'),(594,43922,'Nanase, Miyuki','{\"Description\":\"Assistant in evil to Yakumo\\u0027s biological father. Miyuki is shown as being physically strong mentally twisted and very loyal to Yakumo\\u0027s father.\",\"Light novel\":\"\"}','{\"Description\": \"Assistant in evil to Yakumo\'s biological father. Miyuki is shown as being physically strong mentally twisted and very loyal to Yakumo\'s father.\", \"Light novel\": \"\"}'),(595,45225,'Ozawa, Keiko','{\"Description\":\"Haruka\\u0027s mother.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Haruka\'s mother.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(596,38261,'Ozawa, Ayaka','{\"Description\":\"Haruka\\u0027s older twin sister dies after a car accident when she was playing with her sister\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Haruka\'s older twin sister dies after a car accident when she was playing with her sister\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(597,56737,'Saitou, Unkai','{\"Description\":\"He appears with both of his eyes red and has the ability to see ghosts the same as Yakumo. He is actually a cruel and twisted person. He sees everyone\\u0027s true nature as darkness.\"}','{\"Description\": \"He appears with both of his eyes red and has the ability to see ghosts the same as Yakumo. He is actually a cruel and twisted person. He sees everyone\'s true nature as darkness.\"}'),(598,39580,'Saitou, Nao','{\"Description\":\"Nao is the younger cousin of Yakumo. She has been deaf since birth and lives with Isshin Saito in a Buddhist temple. She is unable to hear but is able to sense the feelings of those around her very clearly.\",\"Description_2\":\"Secret Files - Kizuna\"}','{\"Description\": \"Nao is the younger cousin of Yakumo. She has been deaf since birth and lives with Isshin Saito in a Buddhist temple. She is unable to hear but is able to sense the feelings of those around her very clearly.\", \"Description_2\": \"Secret Files - Kizuna\"}'),(599,45223,'Saitou, Azusa','{\"Description\":\"Yakumo\\u0027s mother.\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"Description\": \"Yakumo\'s mother.\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(600,45219,'Saitou, Isshin','{\"Description\":\"He is Yakumo\\u0027s uncle and father of Nao. He is kind of a father for Yakumo and lives in a Buddhist temple. In order to make Yakumo feel a little bit more comfortable he wears a red adherent lens. Also Isshin was the one who named Yakumo.\"}','{\"Description\": \"He is Yakumo\'s uncle and father of Nao. He is kind of a father for Yakumo and lives in a Buddhist temple. In order to make Yakumo feel a little bit more comfortable he wears a red adherent lens. Also Isshin was the one who named Yakumo.\"}'),(601,45913,'Sakakibara, Genichiro','{\"Description\":\"He is the doctor in charge of Yoshiko.\"}','{\"Description\": \"He is the doctor in charge of Yoshiko.\"}'),(602,55495,'Takeda, Shunsuke','{\"Description\":\"Takeda was a suspect in the Nanase family murder. However, he disappeared before he could be taken into questioning.\",\"Light novel\":\"\"}','{\"Description\": \"Takeda was a suspect in the Nanase family murder. However, he disappeared before he could be taken into questioning.\", \"Light novel\": \"\"}'),(603,83017,'Hiiragi, Shinoa','{\"Age\":\"15-16\",\"Birthday\":\"December 25, 2005\",\"Height\":\"150 cm (4\\u002711\\u0022)\",\"Weight\":\"39 kg (86 lbs)\",\"Blood type\":\"AB\",\"Rank\":\"Sergeant\",\"Demon weapon\":\"Shikama Douji\",\"Description\":\"Shinoa Hiiragi is Guren\\u0027s sergeant and one of the squad leaders of the Moon Demon Company. She is appointed to supervise Yuuichirou during his suspension from the Japanese Imperial Demon Army for his reckless behavior. She is sarcastic and enjoys teasing others, especially Yuuichirou.\",\"Description_2\":\"Her Demon Weapon is Shikama Douji (\\u56DB\\u938C\\u7AE5\\u5B50, lit. Four-Scythe Child), a manifestation-type demon weapon which takes the form of a large scythe, but can be condensed into a pen-like object. She can call out the demon, which she fondly addresses as \\u0022Shi,\\u0022 inhabiting it out of the weapon to attack an enemy. Her primary ability is to detect anything that comes within the attack radius of her scythe.\",\"(Source\":\"Wikipedia, Owari no Seraph Wikia)\"}','{\"Age\": \"15-16\", \"Rank\": \"Sergeant\", \"Height\": \"150 cm (4\'11\\\")\", \"Weight\": \"39 kg (86 lbs)\", \"(Source\": \"Wikipedia, Owari no Seraph Wikia)\", \"Birthday\": \"December 25, 2005\", \"Blood type\": \"AB\", \"Description\": \"Shinoa Hiiragi is Guren\'s sergeant and one of the squad leaders of the Moon Demon Company. She is appointed to supervise Yuuichirou during his suspension from the Japanese Imperial Demon Army for his reckless behavior. She is sarcastic and enjoys teasing others, especially Yuuichirou.\", \"Demon weapon\": \"Shikama Douji\", \"Description_2\": \"Her Demon Weapon is Shikama Douji (四鎌童子, lit. Four-Scythe Child), a manifestation-type demon weapon which takes the form of a large scythe, but can be condensed into a pen-like object. She can call out the demon, which she fondly addresses as \\\"Shi,\\\" inhabiting it out of the weapon to attack an enemy. Her primary ability is to detect anything that comes within the attack radius of her scythe.\"}'),(604,83015,'Hyakuya, Yuuichirou','{\"Age\":\"16-17\",\"Birthday\":\"October 16, 2004\",\"Blood type\":\"A\",\"Height\":\"170 cm (5\\u00277\\u0022)\",\"Weight\":\"59 kg (130 lb)\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Section\":\"Moon Demon Company\",\"Description\":\"Yuuichirou Hyakuya is a member of Japanese Imperial Demon Army\\u0027s Demon Moon Squad and the main protagonist of the Owari no Seraph series.\",\"Description_2\":\"He was abandoned by his parents since he was a child and he ended up at Hyakuya Orphanage. Since then, the kids of this orphanage were his only family. A bit after while he was still a child, the vampires took him and the rest of the orphanage to their city to become \\u0022livestock.\\u0022 After Michaela gets possession of a map of the underground, both of them decide to escape the place with the rest of the children of the orphanage. However it is revealed that is was all a plan of Felid Bathory, one the Seven Founder, and the attempt to escape is frustrated leading to death of all the family except for him. After getting to the outside world he is found by Guren Ichinose, a captain of the Japanese Imperial Demon Army. In order to take revenge for his family, he decides to join the Japanese Imperial Demon Army to gain the power he needs.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"Age\": \"16-17\", \"Height\": \"170 cm (5\'7\\\")\", \"Weight\": \"59 kg (130 lb)\", \"(Source\": \"Owari no Seraph Wikia)\", \"Section\": \"Moon Demon Company\", \"Birthday\": \"October 16, 2004\", \"Blood type\": \"A\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Yuuichirou Hyakuya is a member of Japanese Imperial Demon Army\'s Demon Moon Squad and the main protagonist of the Owari no Seraph series.\", \"Description_2\": \"He was abandoned by his parents since he was a child and he ended up at Hyakuya Orphanage. Since then, the kids of this orphanage were his only family. A bit after while he was still a child, the vampires took him and the rest of the orphanage to their city to become \\\"livestock.\\\" After Michaela gets possession of a map of the underground, both of them decide to escape the place with the rest of the children of the orphanage. However it is revealed that is was all a plan of Felid Bathory, one the Seven Founder, and the attempt to escape is frustrated leading to death of all the family except for him. After getting to the outside world he is found by Guren Ichinose, a captain of the Japanese Imperial Demon Army. In order to take revenge for his family, he decides to join the Japanese Imperial Demon Army to gain the power he needs.\"}'),(605,87287,'Hyakuya, Mikaela','{\"Age\":\"16-17\",\"Birthday\":\"May 1\",\"Height\":\"173 cm (5\\u00278\\u0022)\",\"Weight\":\"57 kg (126 lb)\",\"Blood type\":\"O\",\"Description\":\"Mikaela is kind and upbeat in spite of the harsh events in his childhood, when he was abused by his parents and then dropped out of a car. He was then taken in by the Hyakuya orphanage. He was able to keep smiling and be happy because of his adopted family at the orphanage and even managed to befriend the extremely stubborn Yu. Mikaela was shown to be cunning. He allowed Ferid Bathory to drink his blood in exchange for good food, but Mikaela\\u0027s true purpose was to steal a map in order to escape with the other children.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"Age\": \"16-17\", \"Height\": \"173 cm (5\'8\\\")\", \"Weight\": \"57 kg (126 lb)\", \"(Source\": \"Owari no Seraph Wikia)\", \"Birthday\": \"May 1\", \"Blood type\": \"O\", \"Description\": \"Mikaela is kind and upbeat in spite of the harsh events in his childhood, when he was abused by his parents and then dropped out of a car. He was then taken in by the Hyakuya orphanage. He was able to keep smiling and be happy because of his adopted family at the orphanage and even managed to befriend the extremely stubborn Yu. Mikaela was shown to be cunning. He allowed Ferid Bathory to drink his blood in exchange for good food, but Mikaela\'s true purpose was to steal a map in order to escape with the other children.\"}'),(606,112741,'Ichinose, Guren','{\"Race\":\"Human\",\"Age\":\"24\",\"Birthday\":\"August 28, 1996\",\"Height\":\"183 cm (6\\u00270\\u0022)\",\"Weight\":\"65 kg (143 lb)\",\"Blood type\":\"O\",\"Rank\":\"Lieutenant Colonel\",\"Section\":\"Moon Demon Squad\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Demon Weapon Series\":\"Black Demon\",\"Demon\":\"Mahiru-no-Yo\",\"Guren Ichinose is the main protagonist of the Owari no Seraph\":\"Ichinose Guren, Jyuurokusai no Catastrophe series and an important character in the Owari no Seraph series. He is a Lieutenant Colonel of the Japanese Imperial Demon Army and the commanding officer of the Vampire Extermination Unit, Moon Demon Company.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"Age\": \"24\", \"Race\": \"Human\", \"Rank\": \"Lieutenant Colonel\", \"Demon\": \"Mahiru-no-Yo\", \"Height\": \"183 cm (6\'0\\\")\", \"Weight\": \"65 kg (143 lb)\", \"(Source\": \"Owari no Seraph Wikia)\", \"Section\": \"Moon Demon Squad\", \"Birthday\": \"August 28, 1996\", \"Blood type\": \"O\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Demon Weapon Series\": \"Black Demon\", \"Guren Ichinose is the main protagonist of the Owari no Seraph\": \"Ichinose Guren, Jyuurokusai no Catastrophe series and an important character in the Owari no Seraph series. He is a Lieutenant Colonel of the Japanese Imperial Demon Army and the commanding officer of the Vampire Extermination Unit, Moon Demon Company.\"}'),(607,112755,'Kimizuki, Shihou','{\"Birthday\":\"November 26, 2004\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Section\":\"Moon Demon Squad\",\"Rank\":\"Lieutenant Colonel\",\"Demon Weapon Series\":\"Black Demon\",\"Description\":\"Classmate of Yuuichirou and eventually member of Japanese Imperial Demon Army\\u0027s Demon Moon Squad.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Race\": \"Human\", \"Rank\": \"Lieutenant Colonel\", \"(Source\": \"Seraph of the End Wikia)\", \"Section\": \"Moon Demon Squad\", \"Birthday\": \"November 26, 2004\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Classmate of Yuuichirou and eventually member of Japanese Imperial Demon Army\'s Demon Moon Squad.\", \"Demon Weapon Series\": \"Black Demon\"}'),(608,112761,'Sanguu, Mitsuba','{\"Birthday\":\"July 7, 2004\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Section\":\"Moon Demon Squad\",\"Description\":\"A member of the Japanese Imperial Demon Army and a member of Yuu team of the Moon Demon Squad.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Race\": \"Human\", \"(Source\": \"Seraph of the End Wikia)\", \"Section\": \"Moon Demon Squad\", \"Birthday\": \"July 7, 2004\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"A member of the Japanese Imperial Demon Army and a member of Yuu team of the Moon Demon Squad.\"}'),(609,104637,'Saotome, Yoichi','{\"Age\":\"16-17\",\"Birthday\":\"November 23, 2004\",\"Blood type\":\"B\",\"Height\":\"165 cm (5\\u00275\\u0022)\",\"Weight\":\"50 kg (110 lbs)\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Section\":\"Moon Demon Company\",\"Description\":\"Yoichi Saotome is a member of the Japanese Imperial Demon Army\\u0027s Moon Demon Squad.\",\"Description_2\":\"In the past, his family was attacked by vampires and his sister was killed trying to protect him whilst he remained hidden underneath the bed. This incident stimulated his desire to fight against the vampires in order to avenge his sister\\u0027s death.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"Age\": \"16-17\", \"Height\": \"165 cm (5\'5\\\")\", \"Weight\": \"50 kg (110 lbs)\", \"(Source\": \"Owari no Seraph Wikia)\", \"Section\": \"Moon Demon Company\", \"Birthday\": \"November 23, 2004\", \"Blood type\": \"B\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Yoichi Saotome is a member of the Japanese Imperial Demon Army\'s Moon Demon Squad.\", \"Description_2\": \"In the past, his family was attacked by vampires and his sister was killed trying to protect him whilst he remained hidden underneath the bed. This incident stimulated his desire to fight against the vampires in order to avenge his sister\'s death.\"}'),(610,104387,'Ashuramaru','{\"Description\":\"The demon into the black series demon blade used by Yuuchirou.\",\"Description_2\":\"It often warns Yuuchirou about how humans are dangerous and cannot be trusted.\",\"Description_3\":\"Novel spoiler\"}','{\"Description\": \"The demon into the black series demon blade used by Yuuchirou.\", \"Description_2\": \"It often warns Yuuchirou about how humans are dangerous and cannot be trusted.\", \"Description_3\": \"Novel spoiler\"}'),(611,112757,'Bathory, Ferid','{\"Race\":\"Vampire\",\"Height\":\"182 cm (6\\u00270\\u0022)\",\"Birthday\":\"October 31\",\"Blood type\":\"O\",\"Affiliation\":\"Vampires\",\"Section\":\"Ferid Bathory\\u0027s Faction\",\"Rank\":\"Seventh Progenitor\",\"Description\":\"Ferid Bathory is the seventh founder among the Vampires. He is the one who killed Yuuichirou\\u0027s family, thus fueling his desire for revenge against all vampires.\",\"Description_2\":\"Ferid is chatty, happy, enthusiastic, playful, and sneaky. He is often described as unpredictable. He often says things to incite someone\\u0027s temper but then says he is just kidding. Ferid enjoys irritating Krul Tepes and Mikaela Hyakuya to a dangerous level, and he has a great deal of fun teasing Mika as well. He is infamous for his eccentric behavior and tends to cause \\u0022interesting\\u0022 things to happen, according to Crowley Eusford. When Crowley suspects a high-ranking noble may be giving information to the humans, Ferid Bathory is the first one he suspects. Ferid is self-serving and traitorous to serve his own ends, and he really appears to be assisting the humans somehow. He uses blackmail to stay Krul\\u0027s hand when she desperately wants to see him dead.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Race\": \"Vampire\", \"Rank\": \"Seventh Progenitor\", \"Height\": \"182 cm (6\'0\\\")\", \"(Source\": \"Seraph of the End Wikia)\", \"Section\": \"Ferid Bathory\'s Faction\", \"Birthday\": \"October 31\", \"Blood type\": \"O\", \"Affiliation\": \"Vampires\", \"Description\": \"Ferid Bathory is the seventh founder among the Vampires. He is the one who killed Yuuichirou\'s family, thus fueling his desire for revenge against all vampires.\", \"Description_2\": \"Ferid is chatty, happy, enthusiastic, playful, and sneaky. He is often described as unpredictable. He often says things to incite someone\'s temper but then says he is just kidding. Ferid enjoys irritating Krul Tepes and Mikaela Hyakuya to a dangerous level, and he has a great deal of fun teasing Mika as well. He is infamous for his eccentric behavior and tends to cause \\\"interesting\\\" things to happen, according to Crowley Eusford. When Crowley suspects a high-ranking noble may be giving information to the humans, Ferid Bathory is the first one he suspects. Ferid is self-serving and traitorous to serve his own ends, and he really appears to be assisting the humans somehow. He uses blackmail to stay Krul\'s hand when she desperately wants to see him dead.\"}'),(612,127661,'Belle, Chess','{\"Race\":\"Vampire\",\"Description\":\"Chess Belle is a Seventeenth Progenitor vampire who serves Crowley. Even though she is a noble, her personality is freewheeling gets jealous easily and behavior is very careless. She often can\\u0027t control her desire while drinking blood and end up killing humans.\"}','{\"Race\": \"Vampire\", \"Description\": \"Chess Belle is a Seventeenth Progenitor vampire who serves Crowley. Even though she is a noble, her personality is freewheeling gets jealous easily and behavior is very careless. She often can\'t control her desire while drinking blood and end up killing humans.\"}'),(613,125190,'Eusford, Crowley','{\"Race\":\"Vampire\",\"Height\":\"190 cm (6\\u00273\\u0022)\",\"Birthday\":\"December 5\",\"Blood type\":\"A\",\"Affiliation\":\"Vampires\",\"Section\":\"Ferid Bathory\\u0027s Faction\",\"Rank\":\"Thirteenth Progenitor\",\"Description\":\"Crowley is the thirteenth progenitor among vampires and a member of Seventh Progenitor Ferid Bathory\\u0027s faction. He is willing to kill humans without hesitation and use them as bait to attract the more enemy soldiers. Crowley is almost always in the company of his aides, Horn Skuld and Seventeenth Progenitor Chess Belle. Crowley is a calm and patient vampire who enjoys fighting any opponent. Even when he is in a tight spot, he remains calm and pleasant with a smile on his face. When Ferid orders him to run across the battlefield, lets him fight for a minute, and then tells him he does not care if he lives or dies, he only looks mildly disappointed.\",\"Description_2\":\"Whether things are interesting seems to be an important motive for Crowley\\u0027s actions and movements. He joined Ferid Bathory\\u0027s faction for this reason and while on the battlefield constantly exclaims when/if something impresses him with an almost childlike curiosity.\",\"Description_3\":\"He has also displayed insight, noticing how fast humans are evolving and even deducing they can\\u0027t have done it by themselves, which would mean a vampire has gone traitor. He discussed this with his aides Horn and Chess, whom he also warned about the weapons after testing the ability of one.\"}','{\"Race\": \"Vampire\", \"Rank\": \"Thirteenth Progenitor\", \"Height\": \"190 cm (6\'3\\\")\", \"Section\": \"Ferid Bathory\'s Faction\", \"Birthday\": \"December 5\", \"Blood type\": \"A\", \"Affiliation\": \"Vampires\", \"Description\": \"Crowley is the thirteenth progenitor among vampires and a member of Seventh Progenitor Ferid Bathory\'s faction. He is willing to kill humans without hesitation and use them as bait to attract the more enemy soldiers. Crowley is almost always in the company of his aides, Horn Skuld and Seventeenth Progenitor Chess Belle. Crowley is a calm and patient vampire who enjoys fighting any opponent. Even when he is in a tight spot, he remains calm and pleasant with a smile on his face. When Ferid orders him to run across the battlefield, lets him fight for a minute, and then tells him he does not care if he lives or dies, he only looks mildly disappointed.\", \"Description_2\": \"Whether things are interesting seems to be an important motive for Crowley\'s actions and movements. He joined Ferid Bathory\'s faction for this reason and while on the battlefield constantly exclaims when/if something impresses him with an almost childlike curiosity.\", \"Description_3\": \"He has also displayed insight, noticing how fast humans are evolving and even deducing they can\'t have done it by themselves, which would mean a vampire has gone traitor. He discussed this with his aides Horn and Chess, whom he also warned about the weapons after testing the ability of one.\"}'),(614,112753,'Goshi, Norito','{\"Birthday\":\"May 15, 1996\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Rank\":\"Colonel\",\"Description\":\"Colonel in the Japanese Imperial Demon Army.\"}','{\"Race\": \"Human\", \"Rank\": \"Colonel\", \"Birthday\": \"May 15, 1996\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Colonel in the Japanese Imperial Demon Army.\"}'),(615,112751,'Hanayori, Sayuri','{\"Birthday\":\"May 23, 1996\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Rank\":\"Second Lieutenant\",\"Description\":\"Second Lieutenant in the Japanese Imperial Demon Army.\"}','{\"Race\": \"Human\", \"Rank\": \"Second Lieutenant\", \"Birthday\": \"May 23, 1996\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Second Lieutenant in the Japanese Imperial Demon Army.\"}'),(616,122691,'Hiiragi, Seishirou','{\"Birthday\":\"January 25, 1997\",\"Description\":\"Seishirou Hiiragi is a Major General of the Japanese Imperial Demon Army.\"}','{\"Birthday\": \"January 25, 1997\", \"Description\": \"Seishirou Hiiragi is a Major General of the Japanese Imperial Demon Army.\"}'),(617,122693,'Hiiragi, Tenri','{\"Birthday\":\"September 27, 1971\",\"Description\":\"Tenri Hiiragi is the general of the Japanese Imperial Demon Army.\"}','{\"Birthday\": \"September 27, 1971\", \"Description\": \"Tenri Hiiragi is the general of the Japanese Imperial Demon Army.\"}'),(618,112743,'Hiiragi, Kureto','{\"Race\":\"Human\",\"Age\":\"25\",\"Birthday\":\"March 31, 1995\",\"Height\":\"187 cm (6\\u00272\\u0022)\",\"Weight\":\"73 kg (161 lbs)\",\"Blood type\":\"A\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Rank\":\"Lieutenant General\",\"Description\":\"Lieutenant General of the Japanese Imperial Demon Army.\",\"(Source\":\"Seraph of the End Wiki)\"}','{\"Age\": \"25\", \"Race\": \"Human\", \"Rank\": \"Lieutenant General\", \"Height\": \"187 cm (6\'2\\\")\", \"Weight\": \"73 kg (161 lbs)\", \"(Source\": \"Seraph of the End Wiki)\", \"Birthday\": \"March 31, 1995\", \"Blood type\": \"A\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Lieutenant General of the Japanese Imperial Demon Army.\"}'),(619,112745,'Hiiragi, Shinya','{\"Race\":\"Human\",\"Age\":\"24\",\"Birthday\":\"November 22, 1996\",\"Height\":\"183 cm (6\\u00270\\u0022)\",\"Weight\":\"62 kg (137 lbs)\",\"Blood type\":\"B\",\"Rank\":\"Major General\",\"Section\":\"Moon Demon Company\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Demon Weapon Series\":\"Black Demon Series\",\"Demon\":\"Byakkomaru\",\"Description\":\"Shinya is the Major General of the Japanese Imperial Demon Army. He is shown to be a very calm and somewhat gentle person. He has been friends with Guren since their school days and cares about him, even though he seems to enjoy picking on him, often by forcing Guren into awkward situations or simply annoying him.\",\"Description_2\":\"He is highly skilled in long combat battle and fights with his Demon Gun \\u0022Byakkomaru,\\u0022 which can spot his enemy perfectly and shoot when Shinya says \\u0022Bang\\u0022. Byakkomaru\\u0027s bullet holds the image of a \\u0022White Tiger.\\u0022 He has high capacity of spellcraft from since childhood, Shinya is not comfortable about being with the H\\u012Bragi\\u0027s.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Age\": \"24\", \"Race\": \"Human\", \"Rank\": \"Major General\", \"Demon\": \"Byakkomaru\", \"Height\": \"183 cm (6\'0\\\")\", \"Weight\": \"62 kg (137 lbs)\", \"(Source\": \"Seraph of the End Wikia)\", \"Section\": \"Moon Demon Company\", \"Birthday\": \"November 22, 1996\", \"Blood type\": \"B\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Shinya is the Major General of the Japanese Imperial Demon Army. He is shown to be a very calm and somewhat gentle person. He has been friends with Guren since their school days and cares about him, even though he seems to enjoy picking on him, often by forcing Guren into awkward situations or simply annoying him.\", \"Description_2\": \"He is highly skilled in long combat battle and fights with his Demon Gun \\\"Byakkomaru,\\\" which can spot his enemy perfectly and shoot when Shinya says \\\"Bang\\\". Byakkomaru\'s bullet holds the image of a \\\"White Tiger.\\\" He has high capacity of spellcraft from since childhood, Shinya is not comfortable about being with the Hīragi\'s.\", \"Demon Weapon Series\": \"Black Demon Series\"}'),(620,126838,'Hyakuya, Chihiro','{}','{}'),(621,126841,'Hyakuya, Fumie','{}','{}'),(622,126842,'Hyakuya, Taichi','{}','{}'),(623,126839,'Hyakuya, Kyouta','{}','{}'),(624,126840,'Hyakuya, Ako','{}','{}'),(625,122685,'Hyakuya, Akane','{\"Description\":\"One of the orphans from Hyakuya Orphanage along with Yuuichirou and Mika.\"}','{\"Description\": \"One of the orphans from Hyakuya Orphanage along with Yuuichirou and Mika.\"}'),(626,112747,'Juujou, Mito','{\"Birthday\":\"January 1, 1997\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Rank\":\"Colonel\",\"Description\":\"Colonel of the Japanese Imperial Demon Army.\"}','{\"Race\": \"Human\", \"Rank\": \"Colonel\", \"Birthday\": \"January 1, 1997\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Colonel of the Japanese Imperial Demon Army.\"}'),(627,128304,'Kimizuki, Mirai','{\"Description\":\"Mirai Kimizuki is the younger sister of Shihou Kimizuki. She was infected with the Apocalypse Virus despite being a child and is being treated in a hospital. Shihou took care of her, even though they lived in the outside world with monsters. She wanted Kimizuki to kill her, but he refused and they eventually entered Shibuya. He also joined the Japanese Imperial Demon Army in order to gain access to the military resources that are needed to cure her as the virus cannot be treated in civilian hospitals.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"(Source\": \"Owari no Seraph Wikia)\", \"Description\": \"Mirai Kimizuki is the younger sister of Shihou Kimizuki. She was infected with the Apocalypse Virus despite being a child and is being treated in a hospital. Shihou took care of her, even though they lived in the outside world with monsters. She wanted Kimizuki to kill her, but he refused and they eventually entered Shibuya. He also joined the Japanese Imperial Demon Army in order to gain access to the military resources that are needed to cure her as the virus cannot be treated in civilian hospitals.\"}'),(628,129395,'Nagai','{}','{}'),(629,128266,'Saotome, Tomoe','{\"Description\":\"Older sister of Yoichi Saotome.\"}','{\"Description\": \"Older sister of Yoichi Saotome.\"}'),(630,127213,'Shishido','{}','{}'),(631,122687,'Simm, René','{\"Race\":\"Vampire\",\"Birthday\":\"September 9\",\"Blood type\":\"A\",\"Height\":\"180 cm (5\\u002711\\u0022)\",\"Description\":\"Like all Vampires he sees Humans as mere livestock. He doesn\\u0027t approve of Mika behavior when it come to battle and sees that he still a wretched greedy human for rushing into battle as he take all the glory for himself; however, he seemed to find it amusing when he was told by Mika that he doesn\\u0027t care about glory as he was shown to smile after hearing that.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Race\": \"Vampire\", \"Height\": \"180 cm (5\'11\\\")\", \"(Source\": \"Seraph of the End Wikia)\", \"Birthday\": \"September 9\", \"Blood type\": \"A\", \"Description\": \"Like all Vampires he sees Humans as mere livestock. He doesn\'t approve of Mika behavior when it come to battle and sees that he still a wretched greedy human for rushing into battle as he take all the glory for himself; however, he seemed to find it amusing when he was told by Mika that he doesn\'t care about glory as he was shown to smile after hearing that.\"}'),(632,127662,'Skuld, Horn','{\"Birthday\":\"September 21\",\"Blood type\":\"A\",\"Race\":\"Vampire\",\"Description\":\"Horn Skuld is a vampire noble who serves Thirteenth Progenitor Crowley Eusford. She is fond of both him and her partner, Seventeenth Progenitor Chess Belle, and she can usually be found in their company.\"}','{\"Race\": \"Vampire\", \"Birthday\": \"September 21\", \"Blood type\": \"A\", \"Description\": \"Horn Skuld is a vampire noble who serves Thirteenth Progenitor Crowley Eusford. She is fond of both him and her partner, Seventeenth Progenitor Chess Belle, and she can usually be found in their company.\"}'),(633,112559,'Tepes, Krul','{\"Race\":\"Vampire\",\"Birthday\":\"October 27\",\"Blood type\":\"AB\",\"Height\":\"145 cm (4\\u00279\\u0022)\",\"Affiliation\":\"Vampires\",\"Section\":\"Krul Tepes\\u0027s Faction\",\"Rank\":\"Third Progenitor, Queen Vampire Of Japan\",\"Description\":\"Krul Tepes is the third progenitor among the vampires and the vampire queen of Japan. She is responsible for turning Mikaela Hyakuya into a vampire. Being a Vampire, she is far stronger than a Human and being a Founder among the vampires, she is capable of easily defeating other vampires.\",\"Description_2\":\"Just like all other vampires (minus Mikaela), she views the humans as nothing more than livestock. She sees them as foul and endlessly greedy creatures who will do anything for their own personal gain. When Ferid Bathory slaughters the Hyakuya Sect orphans she carefully hid in Sanguinem and protected as livestock, she becomes enraged because he fatally wounded one of the seraph and allowed another to escape. She never mentions a word about the orphans and displays no interest in them. She saves Mika\\u0027s life against his will by turning him into a vampire, but this appears to have been done for her own personal interests. He refuses to drink human blood, so she gives her blood to him in exchange for making him dependent on her.\",\"Description_3\":\"Even so, she is the only vampire who shows him kindness, and there are several moments when she hugs him or treats him gently. After developing a close bond with Mikaela Hyakuya, she shows concern for his family member, Yuichiro Hyakuya. She claims to like both Mika and Yu. However, it is uncertain if this is because she is close with Mika and is concerned for Mika\\u0027s sake or if this is because she wants to use the seraph for her own purposes. She also appears to trust Mika, and only she and Mika appear to know Krul\\u0027s true goals.\",\"(Source\":\"Owari no Seraph Wikia)\"}','{\"Race\": \"Vampire\", \"Rank\": \"Third Progenitor, Queen Vampire Of Japan\", \"Height\": \"145 cm (4\'9\\\")\", \"(Source\": \"Owari no Seraph Wikia)\", \"Section\": \"Krul Tepes\'s Faction\", \"Birthday\": \"October 27\", \"Blood type\": \"AB\", \"Affiliation\": \"Vampires\", \"Description\": \"Krul Tepes is the third progenitor among the vampires and the vampire queen of Japan. She is responsible for turning Mikaela Hyakuya into a vampire. Being a Vampire, she is far stronger than a Human and being a Founder among the vampires, she is capable of easily defeating other vampires.\", \"Description_2\": \"Just like all other vampires (minus Mikaela), she views the humans as nothing more than livestock. She sees them as foul and endlessly greedy creatures who will do anything for their own personal gain. When Ferid Bathory slaughters the Hyakuya Sect orphans she carefully hid in Sanguinem and protected as livestock, she becomes enraged because he fatally wounded one of the seraph and allowed another to escape. She never mentions a word about the orphans and displays no interest in them. She saves Mika\'s life against his will by turning him into a vampire, but this appears to have been done for her own personal interests. He refuses to drink human blood, so she gives her blood to him in exchange for making him dependent on her.\", \"Description_3\": \"Even so, she is the only vampire who shows him kindness, and there are several moments when she hugs him or treats him gently. After developing a close bond with Mikaela Hyakuya, she shows concern for his family member, Yuichiro Hyakuya. She claims to like both Mika and Yu. However, it is uncertain if this is because she is close with Mika and is concerned for Mika\'s sake or if this is because she wants to use the seraph for her own purposes. She also appears to trust Mika, and only she and Mika appear to know Krul\'s true goals.\"}'),(634,112759,'Welt, Lacus','{\"Birthday\":\"August 21\",\"Height\":\"175 cm (5\\u00279\\u0022)\",\"Race\":\"Vampire; Human (formerly)\",\"Blood type\":\"AB\",\"Description\":\"Like all Vampires he sees Humans as mere livestock and laughed at the Humans who thought that the Vampires came to protect saying that one don\\u0027t protect livestock and own it instead.\",\"Description_2\":\"What is known about Lacus is that in his human life he had siblings, and in 2012, he killed Yoichi Saotome\\u0027s sister, Tomoe Saotome, when he drank too much of her blood.\",\"(Source\":\"Seraph of the End Wikia)\"}','{\"Race\": \"Vampire; Human (formerly)\", \"Height\": \"175 cm (5\'9\\\")\", \"(Source\": \"Seraph of the End Wikia)\", \"Birthday\": \"August 21\", \"Blood type\": \"AB\", \"Description\": \"Like all Vampires he sees Humans as mere livestock and laughed at the Humans who thought that the Vampires came to protect saying that one don\'t protect livestock and own it instead.\", \"Description_2\": \"What is known about Lacus is that in his human life he had siblings, and in 2012, he killed Yoichi Saotome\'s sister, Tomoe Saotome, when he drank too much of her blood.\"}'),(635,127212,'Yamanaka, Satoshi','{}','{}'),(636,112749,'Yukimi, Shigure','{\"Birthday\":\"May 10, 1996\",\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Rank\":\"Colonel\",\"Description\":\"Second Lieutenant in the Japanese Imperial Demon Army.\"}','{\"Race\": \"Human\", \"Rank\": \"Colonel\", \"Birthday\": \"May 10, 1996\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Second Lieutenant in the Japanese Imperial Demon Army.\"}'),(637,127214,'Yuuji','{}','{}'),(638,134714,'Aihara, Aiko','{}','{}'),(639,134521,'Amane, Father','{\"Description\":\"Yuuichirou\\u0027s biological father.\"}','{\"Description\": \"Yuuichirou\'s biological father.\"}'),(640,133733,'Endou, Yayoi','{}','{}'),(641,112763,'Hiiragi, Mahiru','{\"Race\":\"Human\",\"Affiliation\":\"Japanese Imperial Demon Army\",\"Description\":\"Shinoa\\u0027s deceased elder sister.\",\"(Source\":\"Seraph of the End Wiki)\"}','{\"Race\": \"Human\", \"(Source\": \"Seraph of the End Wiki)\", \"Affiliation\": \"Japanese Imperial Demon Army\", \"Description\": \"Shinoa\'s deceased elder sister.\"}'),(642,133732,'Inoue, Rika','{}','{}'),(643,133731,'Iwasaki, Shuusaku','{\"Description\":\"Shuusaku Iwasak was a member of the Japanese Imperial Demon Army and Makoto Narumi\\u0027s squad in the Moon Demon Company. Shuusaku has medium length purple hair with bangs and blue eyes.\"}','{\"Description\": \"Shuusaku Iwasak was a member of the Japanese Imperial Demon Army and Makoto Narumi\'s squad in the Moon Demon Company. Shuusaku has medium length purple hair with bangs and blue eyes.\"}'),(644,133734,'Kagiyama, Tarou','{}','{}'),(645,134520,'Karr, Lest','{\"Description\":\"Lest is a third progenitor of the vampires who resides in Europe.\"}','{\"Description\": \"Lest is a third progenitor of the vampires who resides in Europe.\"}'),(646,122683,'Kisekiou','{\"Description\":\"One of the Black Demon series, the strongest demon weapons. Twin swords used by Shihou Kimizuki.\"}','{\"Description\": \"One of the Black Demon series, the strongest demon weapons. Twin swords used by Shihou Kimizuki.\"}'),(647,135423,'Kusunoki, Eita','{\"Description\":\"Eita was a member of the Japanese Imperial Demon Army and the Moon Demon Company.\"}','{\"Description\": \"Eita was a member of the Japanese Imperial Demon Army and the Moon Demon Company.\"}'),(648,135431,'Lee, Esther','{\"Description\":\"Esther was a servant of the Fifteenth Progenitor Lucal Wesker and a member of the Third Progenitor Lest Karr\\u0027s faction.\"}','{\"Description\": \"Esther was a servant of the Fifteenth Progenitor Lucal Wesker and a member of the Third Progenitor Lest Karr\'s faction.\"}'),(649,133349,'Narumi, Makoto','{\"Description\":\"Makoto Narumi is a sergeant of the Japanese Imperial Demon Army and the leader of his squad in the Moon Demon Company.\",\"Description_2\":\"Narumi has long brown hair pulled back into a ponytail and brown eyes. His bangs frame his face. He has a mole under the outer corner of his right eye. He has heavy upper eyelids.\",\"Description_3\":\"He wears the standard JIDA uniform which consists of a long-sleeved black coat with light green details including the shoulder epaulettes which has a brown Sam Browne belt along with another strap crossing over his chest to form an X and two rows of gold buttons on the front; he has his sleeves rolled up. Along with that, he wears a pair of white gloves and a white web belt with a gold waist-plate. He also wears the uniform trousers and black boots which go over the trouser\\u0027s leggings.\"}','{\"Description\": \"Makoto Narumi is a sergeant of the Japanese Imperial Demon Army and the leader of his squad in the Moon Demon Company.\", \"Description_2\": \"Narumi has long brown hair pulled back into a ponytail and brown eyes. His bangs frame his face. He has a mole under the outer corner of his right eye. He has heavy upper eyelids.\", \"Description_3\": \"He wears the standard JIDA uniform which consists of a long-sleeved black coat with light green details including the shoulder epaulettes which has a brown Sam Browne belt along with another strap crossing over his chest to form an X and two rows of gold buttons on the front; he has his sleeves rolled up. Along with that, he wears a pair of white gloves and a white web belt with a gold waist-plate. He also wears the uniform trousers and black boots which go over the trouser\'s leggings.\"}'),(650,133735,'Sanguu, Aoi','{\"Description\":\"She was a student at First Shibuya High and is now a member of the Japanese Imperial Demon Army. She works as Kureto Hiiragi\\u0027s personal assistant.\"}','{\"Description\": \"She was a student at First Shibuya High and is now a member of the Japanese Imperial Demon Army. She works as Kureto Hiiragi\'s personal assistant.\"}'),(651,138407,'Stefano, Mel','{\"Description\":\"A nineteenth progenitor among the vampires. As a vampire, he was far stronger than a human. Also, as a nineteenth progenitor, he surpassed vampires of a lower class.\",\"Description_2\":\"It was revealed by his squad that Mel nearly killed Guren eight times. The fight was enough to make Guren use at least two squads in their next attack against a vampire noble, until Mel was defeated by Guren Ichinose\"}','{\"Description\": \"A nineteenth progenitor among the vampires. As a vampire, he was far stronger than a human. Also, as a nineteenth progenitor, he surpassed vampires of a lower class.\", \"Description_2\": \"It was revealed by his squad that Mel nearly killed Guren eight times. The fight was enough to make Guren use at least two squads in their next attack against a vampire noble, until Mel was defeated by Guren Ichinose\"}'),(652,135270,'Weskar, Lucal','{}','{}'),(653,170329,'Forger, Yor','{\"Age\":\"27\",\"Description\":\"Yor Forger is one of three main characters of the Spy x Family series. She works as a clerk at Berlint City Hall, but is secretly a skilled assassin who acts under the codename Thorn Princess. Yor possesses impressive strength and endurance for her slim frame, capable of easily piercing the skull of a human with her weapons and destroying a pumpkin with the sheer thrust of her bare hand.\",\"Description_2\":\"She agrees in pretending to be Loid\\u0027s wife and Anya\\u0027s mother in order to serve as cover so she can continue with her assassin work. Yor is consistently bad at cooking and usually leaves the cooking to Loid.\"}','{\"Age\": \"27\", \"Description\": \"Yor Forger is one of three main characters of the Spy x Family series. She works as a clerk at Berlint City Hall, but is secretly a skilled assassin who acts under the codename Thorn Princess. Yor possesses impressive strength and endurance for her slim frame, capable of easily piercing the skull of a human with her weapons and destroying a pumpkin with the sheer thrust of her bare hand.\", \"Description_2\": \"She agrees in pretending to be Loid\'s wife and Anya\'s mother in order to serve as cover so she can continue with her assassin work. Yor is consistently bad at cooking and usually leaves the cooking to Loid.\"}'),(654,170258,'Forger, Loid','{\"Agent Name\":\"Twilight\",\"Occupation\":\"Intelligence Agent, Psychiatrist (False Front)\",\"Known Alias\":\"Loid, Robert\",\"Height\":\"187 cm\",\"Weight\":\"70-90 kg\",\"Skills\":\"Genius-level intellect, Espionage, Peak physical attributes, Expert marksmanship, Skilled hand-to-hand combatant, Master of disguise, Observation, Tennis skills\",\"Hair color\":\"Blond\",\"Eye color\":\"Blue\",\"Address\":\"128 Park Ave. West Berlint\",\"Description\":\"Codename \\u0022Twilight\\u0022, he is an undercover spy and was tasked with the mission to create a fake family in order to infiltrate a politician by the name of Donovan Desmond. He thus in seven days was able to adopt a daughter called Anya Forger and marry a woman named Yor Briar.\",\"Description_2\":\"It is unknown as to what his real name or age is, as he was a war orphan. He became a spy in order to make a \\u0022world where children wouldn\\u0027t cry.\\u0022\"}','{\"Height\": \"187 cm\", \"Skills\": \"Genius-level intellect, Espionage, Peak physical attributes, Expert marksmanship, Skilled hand-to-hand combatant, Master of disguise, Observation, Tennis skills\", \"Weight\": \"70-90 kg\", \"Address\": \"128 Park Ave. West Berlint\", \"Eye color\": \"Blue\", \"Agent Name\": \"Twilight\", \"Hair color\": \"Blond\", \"Occupation\": \"Intelligence Agent, Psychiatrist (False Front)\", \"Description\": \"Codename \\\"Twilight\\\", he is an undercover spy and was tasked with the mission to create a fake family in order to infiltrate a politician by the name of Donovan Desmond. He thus in seven days was able to adopt a daughter called Anya Forger and marry a woman named Yor Briar.\", \"Known Alias\": \"Loid, Robert\", \"Description_2\": \"It is unknown as to what his real name or age is, as he was a war orphan. He became a spy in order to make a \\\"world where children wouldn\'t cry.\\\"\"}'),(655,170256,'Forger, Anya','{\"Description\":\"Anya is a young girl who can read other people\\u0027s thoughts and is the only one who knows of her family\\u0027s secrets. She is 5 years old, but claims to be 6. Originally an experimental human test subject dubbed \\u0022Subject 007,\\u0022 she escaped and moved from one orphanage to another before being adopted by Loid. She likes spy anime and thinks anything involving \\u0022secrets\\u0022 and \\u0022missions\\u0022 are exciting.\"}','{\"Description\": \"Anya is a young girl who can read other people\'s thoughts and is the only one who knows of her family\'s secrets. She is 5 years old, but claims to be 6. Originally an experimental human test subject dubbed \\\"Subject 007,\\\" she escaped and moved from one orphanage to another before being adopted by Loid. She likes spy anime and thinks anything involving \\\"secrets\\\" and \\\"missions\\\" are exciting.\"}'),(656,214065,'Aquarist','{\"Description\":\"Appears in episode 12.\"}','{\"Description\": \"Appears in episode 12.\"}'),(657,210565,'Barnes','{}','{}'),(658,220743,'Black-Suited Man A','{\"Description\":\"Appears in episode 2.\"}','{\"Description\": \"Appears in episode 2.\"}'),(659,220744,'Black-Suited Man B','{\"Description\":\"Appears in episode 2.\"}','{\"Description\": \"Appears in episode 2.\"}'),(660,177510,'Blackbell, Becky','{\"Age\":\"6\",\"Gender\":\"Female\",\"Hair Color\":\"Brown\",\"Eye Color\":\"Light Brown\",\"Occupation\":\"Student\",\"Description\":\"She is the daughter of CEO Blackbell, a major military manufacturer. She attends Eden Academy as part of Cecile House, Group 3, and becomes Anya Forger\\u0027s close friend.\"}','{\"Age\": \"6\", \"Gender\": \"Female\", \"Eye Color\": \"Light Brown\", \"Hair Color\": \"Brown\", \"Occupation\": \"Student\", \"Description\": \"She is the daughter of CEO Blackbell, a major military manufacturer. She attends Eden Academy as part of Cecile House, Group 3, and becomes Anya Forger\'s close friend.\"}'),(661,208895,'Bondman','{}','{}'),(662,211227,'Bondman\'s Boss','{\"Description\":\"He is the headman of Bondman\\u0027s organization.\"}','{\"Description\": \"He is the headman of Bondman\'s organization.\"}'),(663,209754,'Brennan','{}','{}'),(664,177507,'Briar, Yuri','{\"Age\":\"20\",\"Height\":\"179 cm (5\\u203210\\u0022)\",\"Hair color\":\"black\",\"Eye color\":\"red\",\"Description\":\"Yuri Briar is Yor Forger\\u0027s younger brother and a twenty-year-old man who works in the State Security Service. He keeps his job at the SSS a secret from his sister and instead pretends to be a normal civil servant at the foreign ministry.\",\"Description_2\":\"Yuri is popular with girls due to his face, but they leave when they discover his personality.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"Age\": \"20\", \"Height\": \"179 cm (5′10\\\")\", \"(Source\": \"Spy x Family Wiki)\", \"Eye color\": \"red\", \"Hair color\": \"black\", \"Description\": \"Yuri Briar is Yor Forger\'s younger brother and a twenty-year-old man who works in the State Security Service. He keeps his job at the SSS a secret from his sister and instead pretends to be a normal civil servant at the foreign ministry.\", \"Description_2\": \"Yuri is popular with girls due to his face, but they leave when they discover his personality.\"}'),(665,177523,'Camilla','{\"Description\":\"Camilla is one of Yor Forger\\u0027s three co-workers at Berlint City Hall. Camilla is initially shown to be snobbish and mean, inviting Yor to a party simply to make fun of her being single and attempting to spill hot gratin on Yor. Despite her thorny exterior, she has a soft side and accedes to patiently teach Yor cooking when she pleads, despite her initial frustration.\",\"Description_2\":\"Camilla appears to live alone and seems fairly wealthy, having a two-story house large enough to hold a party in.\",\"Description_3\":\"She seems to be a good cook, being able to recreate Yor and Yuri\\u0027s childhood stew from just their memories. She is also knowledgeable about cooking variations from other parts of Ostania as she adjusts the recipe after asking about Yor\\u0027s hometown.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Camilla is one of Yor Forger\'s three co-workers at Berlint City Hall. Camilla is initially shown to be snobbish and mean, inviting Yor to a party simply to make fun of her being single and attempting to spill hot gratin on Yor. Despite her thorny exterior, she has a soft side and accedes to patiently teach Yor cooking when she pleads, despite her initial frustration.\", \"Description_2\": \"Camilla appears to live alone and seems fairly wealthy, having a two-story house large enough to hold a party in.\", \"Description_3\": \"She seems to be a good cook, being able to recreate Yor and Yuri\'s childhood stew from just their memories. She is also knowledgeable about cooking variations from other parts of Ostania as she adjusts the recipe after asking about Yor\'s hometown.\"}'),(666,214064,'Chief Aquarist','{\"Description\":\"Appears in episode 12.\"}','{\"Description\": \"Appears in episode 12.\"}'),(667,214061,'Chief Nurse','{\"Description\":\"Appears in episode 11.\"}','{\"Description\": \"Appears in episode 11.\"}'),(668,177508,'Desmond, Donovan','{\"Description\":\"Donovan Desmond is the President of the Nation Unity Party and Twilight\\u0027s current target.\"}','{\"Description\": \"Donovan Desmond is the President of the Nation Unity Party and Twilight\'s current target.\"}'),(669,177509,'Desmond, Damian','{\"Description\":\"Damian Desmond is the second son of Donovan Desmond and attends Eden Academy as part of Cecile Hall, Group 3. Due to his upbringing as a child of an important and powerful man, Damian gained a highly respected status among his peers by default, making him grow incredibly arrogant, assuming Anya gained a crush on him when she stared at him. He is shown to prefer being called Lord Damian when spoken to.\",\"Description_2\":\"Later, it is hinted that a possible reason for Damian\\u0027s behavior can be attributed to his brother\\u0027s success as an Imperial Scholar and his father having set a high expectation for him to strive and become part of the Imperial Scholars. His father\\u0027s influence and lack of attention to his life motivated him even further to meet his expectations, causing him to look down on people beneath his social class, for if they are not a benefit to him, they are only slowing him down to becoming an Imperial Scholar and in turn slowing his progress in getting his father\\u0027s attention.\"}','{\"Description\": \"Damian Desmond is the second son of Donovan Desmond and attends Eden Academy as part of Cecile Hall, Group 3. Due to his upbringing as a child of an important and powerful man, Damian gained a highly respected status among his peers by default, making him grow incredibly arrogant, assuming Anya gained a crush on him when she stared at him. He is shown to prefer being called Lord Damian when spoken to.\", \"Description_2\": \"Later, it is hinted that a possible reason for Damian\'s behavior can be attributed to his brother\'s success as an Imperial Scholar and his father having set a high expectation for him to strive and become part of the Imperial Scholars. His father\'s influence and lack of attention to his life motivated him even further to meet his expectations, causing him to look down on people beneath his social class, for if they are not a benefit to him, they are only slowing him down to becoming an Imperial Scholar and in turn slowing his progress in getting his father\'s attention.\"}'),(670,177528,'Dominic','{\"Description\":\"Camilia\\u0027s Boyfriend.\"}','{\"Description\": \"Camilia\'s Boyfriend.\"}'),(671,210566,'Driver','{\"Description\":\"Appears in episode 1.\"}','{\"Description\": \"Appears in episode 1.\"}'),(672,220742,'Eden Academy Announcer','{\"Episode\":\"4\",\"Description\":\"An announcer from Eden Academy, warning that the animals have escaped from their enclosure.\"}','{\"Episode\": \"4\", \"Description\": \"An announcer from Eden Academy, warning that the animals have escaped from their enclosure.\"}'),(673,211229,'Eden Academy Geometry Teacher','{\"Description\":\"The Geometry teacher at Eden Academy who feared that Anya Forger was a delinquent because she fell asleep on the first day of class.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"The Geometry teacher at Eden Academy who feared that Anya Forger was a delinquent because she fell asleep on the first day of class.\"}'),(674,211941,'Eden Academy Gutter Student','{\"Manga Debut\":\"Chapter 4\",\"Anime Debut\":\"Episode 4\",\"Description\":\"An Eden Academy student who was involved in the entrance exam. In order to obtain extra credit, he reluctantly pretended to be stuck in a gutter as a test for the applicants. He felt guilty when he believed the Forgers would fail because of him.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 4\", \"Description\": \"An Eden Academy student who was involved in the entrance exam. In order to obtain extra credit, he reluctantly pretended to be stuck in a gutter as a test for the applicants. He felt guilty when he believed the Forgers would fail because of him.\", \"Manga Debut\": \"Chapter 4\"}'),(675,212418,'Eden Academy Math Teacher','{\"Description\":\"Appears in episode 8.\"}','{\"Description\": \"Appears in episode 8.\"}'),(676,211654,'Eden Academy Science Teacher','{\"Description\":\"Appears in episode 7.\"}','{\"Description\": \"Appears in episode 7.\"}'),(677,211655,'Eden Academy Teacher','{\"Description\":\"Appears in episode 6.\"}','{\"Description\": \"Appears in episode 6.\"}'),(678,177526,'Edgar','{}','{}'),(679,214698,'Edgar\'s Subordinate','{\"Description\":\"Appears in episode 1.\"}','{\"Description\": \"Appears in episode 1.\"}'),(680,209461,'Egeburg, Ewen','{\"Description\":\"Ewen Egeburg is one of Damian Desmond\\u0027s followers at Eden Academy and a student of Cecile Hall. Ewen quickly become friends with Damian Desmond and Emile Elman, praising Damian and commenting that he will become Imperial Scholar in no time. He often suggests Damian needs to work on his vocabulary or grammar.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Ewen Egeburg is one of Damian Desmond\'s followers at Eden Academy and a student of Cecile Hall. Ewen quickly become friends with Damian Desmond and Emile Elman, praising Damian and commenting that he will become Imperial Scholar in no time. He often suggests Damian needs to work on his vocabulary or grammar.\"}'),(681,209460,'Elman, Emile','{\"Description\":\"Emile Elman is the heir to the Elman Family and one of Damian Desmond\\u0027s followers at Eden Academy. As one of Damian\\u0027s followers, he is frequently praising Damian\\u0027s abilities and making fun of Anya and Becky. It is his dream to eat a lot of candy.\",\"Description_2\":\"Emile quickly become friends with Damian Desmond and Ewen Egeburg, praising Damian and commenting that he will become Imperial Scholar in no time.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Emile Elman is the heir to the Elman Family and one of Damian Desmond\'s followers at Eden Academy. As one of Damian\'s followers, he is frequently praising Damian\'s abilities and making fun of Anya and Becky. It is his dream to eat a lot of candy.\", \"Description_2\": \"Emile quickly become friends with Damian Desmond and Ewen Egeburg, praising Damian and commenting that he will become Imperial Scholar in no time.\"}'),(682,177522,'Evans, Walter','{}','{}'),(683,211226,'Feiss, Zachry','{\"Description\":\"Appears in episode 5.\"}','{\"Description\": \"Appears in episode 5.\"}'),(684,203871,'Forger, Bond','{\"Description\":\"Bond Forger is the pet of the Forger Family. Formerly known as Subject 8, Bond has been used for experiments that resulted in him gaining precognition abilities.\",\"Description_2\":\"Bond is shown to be a very kind dog, as he uses his precognition abilities to rescue a child from being hit by a falling board. He also helps Anya Forger to retrieve her favorite pair of gloves from a fierce dog by intimidating him.\",\"(Source\":\"Spy X Family Wiki)\"}','{\"(Source\": \"Spy X Family Wiki)\", \"Description\": \"Bond Forger is the pet of the Forger Family. Formerly known as Subject 8, Bond has been used for experiments that resulted in him gaining precognition abilities.\", \"Description_2\": \"Bond is shown to be a very kind dog, as he uses his precognition abilities to rescue a child from being hit by a falling board. He also helps Anya Forger to retrieve her favorite pair of gloves from a fierce dog by intimidating him.\"}'),(685,177512,'Franklin, Franky','{\"Description\":\"Franky Franklin is an informant who seemingly works at a tobacco store and presumably works for Loid Forger\\u0027s agency. He gets information regarding Eden Academy\\u0027s exam and Anya Forger\\u0027s past records for Loid Forger.\",\"Description_2\":\"Franky is a kind person willing to help Loid out when he\\u0027s in a pinch even though the danger is high. He frequently warns Loid Forger not to get too close to other people in their line of work.\",\"Description_3\":\"He frequently falls in love with other women but his love life typically fails due to lack of mutual interest or they are already with someone else.\",\"Description_4\":\"He\\u0027s rather money-driven as he is willing to perform favors for Loid as long as Loid promises to give him material goods, even though he was previously reluctant to do so or even if the situation is extremely dangerous.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Franky Franklin is an informant who seemingly works at a tobacco store and presumably works for Loid Forger\'s agency. He gets information regarding Eden Academy\'s exam and Anya Forger\'s past records for Loid Forger.\", \"Description_2\": \"Franky is a kind person willing to help Loid out when he\'s in a pinch even though the danger is high. He frequently warns Loid Forger not to get too close to other people in their line of work.\", \"Description_3\": \"He frequently falls in love with other women but his love life typically fails due to lack of mutual interest or they are already with someone else.\", \"Description_4\": \"He\'s rather money-driven as he is willing to perform favors for Loid as long as Loid promises to give him material goods, even though he was previously reluctant to do so or even if the situation is extremely dangerous.\"}'),(686,211228,'Goodfellow, Benedict Ivan','{}','{}'),(687,211939,'Hayward, Jim','{}','{}'),(688,177521,'Henderson, Henry','{\"Description\":\"Henry Henderson is a history teacher and the housemaster of dormitory 3, Cecile Hall at Eden Academy. Henry is a mature and noble person, who places a high importance on \\u0022elegance\\u0022. To him, elegance seems to be the way a person conducts themselves, and is not afraid to correct inelegant behavior in others.\",\"Description_2\":\"When teaching, he observes and assesses the \\u0022elegance\\u0022 of the students, although he understands that children occasionally need to frolic too.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Henry Henderson is a history teacher and the housemaster of dormitory 3, Cecile Hall at Eden Academy. Henry is a mature and noble person, who places a high importance on \\\"elegance\\\". To him, elegance seems to be the way a person conducts themselves, and is not afraid to correct inelegant behavior in others.\", \"Description_2\": \"When teaching, he observes and assesses the \\\"elegance\\\" of the students, although he understands that children occasionally need to frolic too.\"}'),(689,210599,'Heywood, Anakin','{\"Manga Debut\":\"Chapter 1\",\"Anime Debut\":\"Episode 1\",\"Description\":\"Anakin Heywood is the foreign minister of Ostania and the man that Edgar attempts to blackmail via photos of him wearing a hairpiece. He is secretly backing Westalis, thus one of Twilight\\u0027s missions is to save him by acquiring the photos and the negatives himself.\",\"(Source\":\"Spy x Family Wiki)\",\"Description_2\":\"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 1\", \"Description\": \"Anakin Heywood is the foreign minister of Ostania and the man that Edgar attempts to blackmail via photos of him wearing a hairpiece. He is secretly backing Westalis, thus one of Twilight\'s missions is to save him by acquiring the photos and the negatives himself.\", \"Manga Debut\": \"Chapter 1\", \"Description_2\": \"No voice actors have been added to this character. Help improve our database by searching for a voice actor, and adding this character to their roles .\"}'),(690,214699,'Investigator','{\"Manga Debut\":\"Chapter 1\",\"Anime Debut\":\"Episode 1\",\"Description\":\"He is responsible for investigating and taking photos of Foreign Minister Heywood\\u0027s hairpiece to give to Edgar. However, he is duped by Twilight\\u0027s disguise and fails.\",\"(Source\":\"SPY x FAMILY Wiki)\"}','{\"(Source\": \"SPY x FAMILY Wiki)\", \"Anime Debut\": \"Episode 1\", \"Description\": \"He is responsible for investigating and taking photos of Foreign Minister Heywood\'s hairpiece to give to Edgar. However, he is duped by Twilight\'s disguise and fails.\", \"Manga Debut\": \"Chapter 1\"}'),(691,177527,'Karen','{}','{}'),(692,214058,'Ken','{\"Description\":\"Appears in episode 11.\"}','{\"Description\": \"Appears in episode 11.\"}'),(693,220737,'Mailman','{\"Description\":\"Appears in episode 1 and episode 20.\"}','{\"Description\": \"Appears in episode 1 and episode 20.\"}'),(694,177524,'Millie','{\"Description\":\"Millie is one of Yor Forger\\u0027s three co-workers at Berlint City Hall. Millie is shown to be lively and mischievous, suggesting to Yor that they put snot in the Chief\\u0027s coffee as a joke and most often seen smiling or giggling. Even though she breaks up with her boyfriend, she doesn\\u0027t seem bothered and remains cheerful, even asking Yor to introduce her to Yuri.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Millie is one of Yor Forger\'s three co-workers at Berlint City Hall. Millie is shown to be lively and mischievous, suggesting to Yor that they put snot in the Chief\'s coffee as a joke and most often seen smiling or giggling. Even though she breaks up with her boyfriend, she doesn\'t seem bothered and remains cheerful, even asking Yor to introduce her to Yuri.\"}'),(695,211223,'Minister of Finance','{\"Description\":\"Appears in episode 4.\"}','{\"Description\": \"Appears in episode 4.\"}'),(696,208892,'Narrator','{}','{}'),(697,214066,'Neighbour #1','{\"Description\":\"Appears in episode 12.\"}','{\"Description\": \"Appears in episode 12.\"}'),(698,214067,'Neighbour #2','{\"Description\":\"Appears in episode 12.\"}','{\"Description\": \"Appears in episode 12.\"}'),(699,208894,'Nguyen','{}','{}'),(700,214690,'Nurse','{\"Appearance\":\"Episode 11\",\"Description\":\"A nurse who alerts Loid.\"}','{\"Appearance\": \"Episode 11\", \"Description\": \"A nurse who alerts Loid.\"}'),(701,210523,'Old Woman','{\"Description\":\"Appears in episode 3.\"}','{\"Description\": \"Appears in episode 3.\"}'),(702,177529,'Orphanage Owner','{\"Description\":\"An inebriated middle-aged man who is the owner of the orphanage where Anya Forger is adopted by Loid Forger. He is apathetic about his orphanage, as shown by the neglected state of the children and his indifference to Loid\\u0027s given background. He thinks of Anya as a \\u0022creepy little brat\\u0022, attempting to give her away to Loid upon hearing he wants a literate child.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"An inebriated middle-aged man who is the owner of the orphanage where Anya Forger is adopted by Loid Forger. He is apathetic about his orphanage, as shown by the neglected state of the children and his indifference to Loid\'s given background. He thinks of Anya as a \\\"creepy little brat\\\", attempting to give her away to Loid upon hearing he wants a literate child.\"}'),(703,210521,'Politician','{\"Description\":\"Appears in episode 3.\"}','{\"Description\": \"Appears in episode 3.\"}'),(704,214059,'Pool Instructor #1','{\"Description\":\"Appears in episode 11.\"}','{\"Description\": \"Appears in episode 11.\"}'),(705,214060,'Pool Instructor #2','{\"Description\":\"Appears in episode 11.\"}','{\"Description\": \"Appears in episode 11.\"}'),(706,211225,'Princess Honey','{\"Description\":\"Appears in episode 5.\"}','{\"Description\": \"Appears in episode 5.\"}'),(707,210522,'Purse Snatcher','{\"Description\":\"Appears in episode 3.\"}','{\"Description\": \"Appears in episode 3.\"}'),(708,214695,'Real Estate Agent','{\"Manga Debut\":\"Chapter 1\",\"Anime Debut\":\"Episode 1\",\"Description\":\"He sells the single-family apartment unit that becomes the first residence of the Forgers to Loid. He has two sons aged eight and ten.\",\"(Source\":\"SPY x FAMILY Wiki)\"}','{\"(Source\": \"SPY x FAMILY Wiki)\", \"Anime Debut\": \"Episode 1\", \"Description\": \"He sells the single-family apartment unit that becomes the first residence of the Forgers to Loid. He has two sons aged eight and ten.\", \"Manga Debut\": \"Chapter 1\"}'),(709,214692,'Rehab Patient A','{\"Description\":\"Appears in episode 11.\"}','{\"Description\": \"Appears in episode 11.\"}'),(710,214743,'Scientist A','{\"Manga Debut\":\"Chapter 1 (flashback)\",\"Anime Debut\":\"Episode 1 (flashback)\",\"Description\":\"One of the several scientists that were involved in Anya Forger\\u0027s experimentation in the organization prior to her escape. They were indifferent to Anya\\u0027s desires, forbidding her to draw, play or cry, and strictly forcing her to study for world peace. Two of the male scientists were also involved in Bond\\u0027s cruel experimentation in \\u0022Project Apple\\u0022.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 1 (flashback)\", \"Description\": \"One of the several scientists that were involved in Anya Forger\'s experimentation in the organization prior to her escape. They were indifferent to Anya\'s desires, forbidding her to draw, play or cry, and strictly forcing her to study for world peace. Two of the male scientists were also involved in Bond\'s cruel experimentation in \\\"Project Apple\\\".\", \"Manga Debut\": \"Chapter 1 (flashback)\"}'),(711,214744,'Scientist B','{\"Manga Debut\":\"Chapter 1 (flashback)\",\"Anime Debut\":\"Episode 1 (flashback)\",\"Description\":\"One of the several scientists that were involved in Anya Forger\\u0027s experimentation in the organization prior to her escape. They were indifferent to Anya\\u0027s desires, forbidding her to draw, play or cry, and strictly forcing her to study for world peace. Two of the male scientists were also involved in Bond\\u0027s cruel experimentation in \\u0022Project Apple\\u0022.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 1 (flashback)\", \"Description\": \"One of the several scientists that were involved in Anya Forger\'s experimentation in the organization prior to her escape. They were indifferent to Anya\'s desires, forbidding her to draw, play or cry, and strictly forcing her to study for world peace. Two of the male scientists were also involved in Bond\'s cruel experimentation in \\\"Project Apple\\\".\", \"Manga Debut\": \"Chapter 1 (flashback)\"}'),(712,177525,'Sharon','{\"Description\":\"Sharon is one of Yor Forger\\u0027s three co-workers at Berlint City Hall. She has a child and is shown to have attended the admissions interview at Eden Academy.\",\"Description_2\":\"Sharon is shown to be largely indifferent or disinterested, not actively making fun of Yor like her co-workers nor preventing them, though she tells Millie to cool it after Millie suggests Yor may be able to find a man if she stopped being air-headed.\",\"Description_3\":\"She is usually seen smoking at work, using her left hand. She hires a maid to do all the cooking.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Sharon is one of Yor Forger\'s three co-workers at Berlint City Hall. She has a child and is shown to have attended the admissions interview at Eden Academy.\", \"Description_2\": \"Sharon is shown to be largely indifferent or disinterested, not actively making fun of Yor like her co-workers nor preventing them, though she tells Millie to cool it after Millie suggests Yor may be able to find a man if she stopped being air-headed.\", \"Description_3\": \"She is usually seen smoking at work, using her left hand. She hires a maid to do all the cooking.\"}'),(713,177511,'Sherwood, Sylvia','{\"Description\":\"Main contact of Twilight (Loid Forger) at WISE and previously involved in war between West and East. Not much has been to shown to get an understanding of her personality but from what\\u0027s been shown, it\\u0027s that she is similar to Twilight in which she is dedicated, skilled and logical with her approach to ideas but still is a somewhat impatient person. It can be assumed that she doesn\\u0027t really understand kids, as seen when she told Loid to just bribe Anya with candy.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Main contact of Twilight (Loid Forger) at WISE and previously involved in war between West and East. Not much has been to shown to get an understanding of her personality but from what\'s been shown, it\'s that she is similar to Twilight in which she is dedicated, skilled and logical with her approach to ideas but still is a somewhat impatient person. It can be assumed that she doesn\'t really understand kids, as seen when she told Loid to just bribe Anya with candy.\"}'),(714,209877,'Shopkeeper','{\"Description\":\"He is Yor\\u0027s employer.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"He is Yor\'s employer.\"}'),(715,214696,'SSS Boss','{\"Manga Debut\":\"Chapter 11\",\"Anime Debut\":\"Episode 8\",\"Description\":\"The boss of the SSS who dotes on Yuri because he finds him adorable like a puppy.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 8\", \"Description\": \"The boss of the SSS who dotes on Yuri because he finds him adorable like a puppy.\", \"Manga Debut\": \"Chapter 11\"}'),(716,211940,'SSS Lieutenant','{\"Description\":\"A scarred man who is a lieutenant and a higher position than Yuri Briar in the SSS. He seems to be fairly close to Yuri and is aware of his drinking habits and sister complex, advising Yuri to get over his sister and focus on his work.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"A scarred man who is a lieutenant and a higher position than Yuri Briar in the SSS. He seems to be fairly close to Yuri and is aware of his drinking habits and sister complex, advising Yuri to get over his sister and focus on his work.\"}'),(717,211942,'SSS Member','{\"Appearance\":\"Episode 8\",\"Description\":\"A member of the SSS.\"}','{\"Appearance\": \"Episode 8\", \"Description\": \"A member of the SSS.\"}'),(718,217868,'SSS Secretary','{\"Description\":\"Appears in episode 8.\"}','{\"Description\": \"Appears in episode 8.\"}'),(719,177520,'Swan, Murdoch','{\"Description\":\"Murdoch Swan is a 47-year-old man. He is the Economics Teacher and the Housemaster of Dormitory 2, Cline Hall at Eden Academy. He is the only son of the former Headmaster of Eden Academy. His wife filed for divorce a month before the Eden Academy admissions interview, where she won full custody of their only daughter.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"Murdoch Swan is a 47-year-old man. He is the Economics Teacher and the Housemaster of Dormitory 2, Cline Hall at Eden Academy. He is the only son of the former Headmaster of Eden Academy. His wife filed for divorce a month before the Eden Academy admissions interview, where she won full custody of their only daughter.\"}'),(720,220740,'Tailor Shop Clerk','{\"Description\":\"An elderly lady who works as a clerk at Mona \\u0026amp; Monacca.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Description\": \"An elderly lady who works as a clerk at Mona &amp; Monacca.\"}'),(721,214697,'Tailor Shop Owner','{\"Manga Debut\":\"Chapter 2\",\"Anime Debut\":\"Episode 2\",\"Description\":\"The owner of Mona \\u0026amp; Monacca, a tailor shop. She was one of Loid\\u0027s candidates as an unmarried woman, but was rejected due to having been arrested for political activites in the past and her somewhat older age. When the Forgers come to her shop to purchase Eden Academy\\u0027s uniforms for Anya, she warns them about the bullying and discrimination in Eden Academy. She also appears to be familiar with Yor as she is suggested to be a regular at the shop.\",\"(Source\":\"Spy x Family Wiki)\"}','{\"(Source\": \"Spy x Family Wiki)\", \"Anime Debut\": \"Episode 2\", \"Description\": \"The owner of Mona &amp; Monacca, a tailor shop. She was one of Loid\'s candidates as an unmarried woman, but was rejected due to having been arrested for political activites in the past and her somewhat older age. When the Forgers come to her shop to purchase Eden Academy\'s uniforms for Anya, she warns them about the bullying and discrimination in Eden Academy. She also appears to be familiar with Yor as she is suggested to be a regular at the shop.\", \"Manga Debut\": \"Chapter 2\"}'),(722,214693,'Thug A','{\"Description\":\"Appears in episode 6.\"}','{\"Description\": \"Appears in episode 6.\"}')