INSERT INTO `ClubPosts` VALUES (1,2,'5043e8f3-d504-11f0-96f1-0242ac120002','New test Post','2025-12-18 07:20:55.100576'),(2,2,'5043e8f3-d504-11f0-96f1-0242ac120002','New test Post','2025-12-18 07:26:41.821064'),(3,2,'5043e8f3-d504-11f0-96f1-0242ac120002','Do You remember this legend, Yea, without him this history couldnt be appear.','2025-12-24 10:21:08.985382'),(4,5,'5043e8f3-d504-11f0-96f1-0242ac120002','<h2>OF COURSE!</h2>\r\n<img src=\"https://res.cloudinary.com/dd0oqs9r2/image/upload/v1768844515/temp/club-posts/req1tn1nverqve6nmjrh.jpg\" alt=\"media\" />\r\n<p>I really dont understand people whom just said its very long and not so interesting as talking. I really offer you watch this anime, cause in our live , at this moment war is the word number ONE! I want to stop this, and this anime shows how we can do it!</p>','2026-01-19 17:44:23.898992');
