INSERT INTO `Clubs` VALUES (2,'Naruto Fan Club','I hope there is millions of people who really love this Anime, so this on club will be posted news about something new of this Anime.','2025-12-15 19:21:46.010816','5043e8f3-d504-11f0-96f1-0242ac120002'),(3,'TEST Club','Test Description','2025-12-15 19:22:07.751279','5043e8f3-d504-11f0-96f1-0242ac120002'),(4,'Fullmetal Alchemist Fan Club','Here I will post the latest news about this anime. There are many stories circulating on the internet about alternative plots and the history of the characters, and what happened to the Hamunculi long before the Elric brothers appeared! And, of course, there are many debates about which version is better.','2026-01-19 14:26:16.161704','5043e8f3-d504-11f0-96f1-0242ac120002'),(5,'What to watch now? 🤔','In this club, I will try to recommend anime that are currently very popular, as well as underrated ones that you can watch in one sitting!','2026-01-19 14:30:28.842578','5043e8f3-d504-11f0-96f1-0242ac120002');
/*!40000 ALTER TABLE `Clubs` ENABLE KEYS */;
