INSERT INTO `Comments` VALUES (1,'855772d8-0454-4f6a-9f67-b9896db52736',3,3,NULL,'<p>Yea, I remember this fucking creep :)</p>','2025-12-25 18:55:07.362573',NULL,NULL),(2,'855772d8-0454-4f6a-9f67-b9896db52736',3,3,NULL,'<p>nope</p>','2025-12-25 19:00:14.957085',NULL,NULL),(3,'855772d8-0454-4f6a-9f67-b9896db52736',3,3,NULL,'<p>gg</p>','2025-12-25 19:00:24.778645',NULL,NULL),(4,'855772d8-0454-4f6a-9f67-b9896db52736',3,3,NULL,'<p><strong>TEST</strong></p>','2025-12-25 19:14:52.122206',NULL,NULL),(5,'855772d8-0454-4f6a-9f67-b9896db52736',0,1735,NULL,'<p>This anime was my first. Remember when I turned on the TV the first time, there was an anime on the QTV channel. Then I still didn’t suspect that you would become such an important part of my life. I was amazed twice now. And the deeds of the series are 6-10 times. Axis like this... :)</p>','2026-01-12 15:01:44.284920',NULL,NULL),(6,'a5012cc9-f44b-4f28-b07d-9939f3d59a67',0,1735,NULL,'<p>Legend!!!</p>','2026-01-12 15:54:24.590270',NULL,NULL),(7,'a5012cc9-f44b-4f28-b07d-9939f3d59a67',0,1735,NULL,'<p>Yes, I also remember how I always waited for this cartoon on TV in the evenings, when I was still a teenager.</p>','2026-01-12 15:55:56.602304',NULL,5),(8,'a5012cc9-f44b-4f28-b07d-9939f3d59a67',0,1735,NULL,'<p>And i really was noisy in asking my parents to turn it on XD</p>','2026-01-12 15:57:26.368126',NULL,7),(9,'855772d8-0454-4f6a-9f67-b9896db52736',0,1735,NULL,'<p>Its increadible XDDD</p>','2026-01-12 16:29:34.865601',NULL,8),(10,'855772d8-0454-4f6a-9f67-b9896db52736',0,0,NULL,'<p>Do you remember me? :)</p>','2026-01-12 17:32:37.547249',NULL,NULL),(11,'09643c23-d4cb-43b5-96de-adf1fe0e299c',0,0,NULL,'<p>What?</p><p><br></p>','2026-01-12 17:33:26.819167',NULL,NULL),(15,'855772d8-0454-4f6a-9f67-b9896db52736',1,NULL,'09643c23-d4cb-43b5-96de-adf1fe0e299c','<p>Do you remember me? :)</p>','2026-01-13 10:42:11.166822',NULL,NULL),(18,'09643c23-d4cb-43b5-96de-adf1fe0e299c',1,NULL,'09643c23-d4cb-43b5-96de-adf1fe0e299c','<p>No. Who are u? :)</p>','2026-01-13 10:43:22.365037',NULL,15),(20,'855772d8-0454-4f6a-9f67-b9896db52736',1,NULL,'09643c23-d4cb-43b5-96de-adf1fe0e299c','<p>I am your mother fucker XD</p>','2026-01-13 10:44:13.569982',NULL,18),(21,'855772d8-0454-4f6a-9f67-b9896db52736',3,3,NULL,'<p>Hi, i really like ur post</p>','2026-01-14 20:08:11.969408',NULL,NULL),(25,'855772d8-0454-4f6a-9f67-b9896db52736',3,2,NULL,'<p><em>test comment</em></p>','2026-01-20 20:52:51.223532',NULL,NULL),(27,'94593487-ebdb-4cdc-ae13-5adc7f54b8ef',0,1735,NULL,'<p>jakieś gówno a nie strona.</p>','2026-01-23 15:59:19.191725',NULL,NULL),(28,'94593487-ebdb-4cdc-ae13-5adc7f54b8ef',3,3,NULL,'<p>idiot *_*</p>','2026-01-23 16:09:56.441550',NULL,21),(29,'94593487-ebdb-4cdc-ae13-5adc7f54b8ef',3,3,NULL,'<p>What test, konc</p>','2026-01-23 16:10:16.232909',NULL,4),(30,'855772d8-0454-4f6a-9f67-b9896db52736',1,NULL,'94593487-ebdb-4cdc-ae13-5adc7f54b8ef','<p>Hi</p>','2026-01-23 16:40:29.852458',NULL,NULL);
