INSERT INTO `HomeAnnouncements` VALUES (1,'Finally, we came into the world','<div class=\"home-announcement-root\">\r\n  <style>\r\n    .home-announcement-root {\r\n      width: 100%;\r\n      padding: 56px 64px;\r\n      background: var(--bg-surface);\r\n      color: var(--text-main);\r\n      border-radius: 28px;\r\n      font-family: system-ui, -apple-system, BlinkMacSystemFont, \'Segoe UI\', sans-serif;\r\n    }\r\n\r\n    /* внутрішній readable контейнер */\r\n    .ha-inner {\r\n      max-width: 1200px;\r\n    }\r\n\r\n    .ha-title {\r\n      font-size: 44px;\r\n      font-weight: 900;\r\n      margin-bottom: 32px;\r\n      line-height: 1.1;\r\n      background: linear-gradient(90deg, #f59e0b, #ef4444);\r\n      -webkit-background-clip: text;\r\n      -webkit-text-fill-color: transparent;\r\n    }\r\n\r\n    .ha-image-float {\r\n      float: left;\r\n      width: 420px;\r\n      margin: 0 36px 24px 0;\r\n      border-radius: 22px;\r\n      overflow: hidden;\r\n      box-shadow: 0 22px 56px rgba(0,0,0,0.35);\r\n    }\r\n\r\n    .ha-image-float img {\r\n      width: 100%;\r\n      display: block;\r\n    }\r\n\r\n    .ha-content {\r\n      font-size: 17px;\r\n      line-height: 1.8;\r\n      color: var(--text-main);\r\n    }\r\n\r\n    .ha-content p {\r\n      margin-bottom: 22px;\r\n    }\r\n\r\n    .ha-content ul {\r\n      margin-left: 22px;\r\n      margin-bottom: 28px;\r\n    }\r\n\r\n    .ha-clear {\r\n      clear: both;\r\n    }\r\n\r\n    /* Dark theme polish */\r\n    [data-theme=\"dark\"] .home-announcement-root {\r\n      background: linear-gradient(\r\n        160deg,\r\n        rgba(255,255,255,0.05),\r\n        rgba(255,255,255,0.015)\r\n      );\r\n      box-shadow: 0 28px 80px rgba(0,0,0,0.55);\r\n    }\r\n\r\n    /* Mobile */\r\n    @media (max-width: 900px) {\r\n      .home-announcement-root {\r\n        padding: 36px 24px;\r\n      }\r\n\r\n      .ha-image-float {\r\n        float: none;\r\n        width: 100%;\r\n        margin: 0 0 28px 0;\r\n      }\r\n\r\n      .ha-title {\r\n        font-size: 34px;\r\n      }\r\n    }\r\n  </style>\r\n\r\n  <div class=\"ha-inner\">\r\n    <h1 class=\"ha-title\">AniRise Is Officially Live</h1>\r\n\r\n    <div class=\"ha-image-float\">\r\n      <img\r\n        src=\"https://res.cloudinary.com/dd0oqs9r2/image/upload/v1768948635/home-announcements/sktwq6yo90hrao8ezgld.jpg\"\r\n        alt=\"AniRise launch\"\r\n      />\r\n    </div>\r\n\r\n    <div class=\"ha-content\">\r\n      <p>\r\n        After a long journey, hundreds of commits, and countless sleepless nights —\r\n        we are finally here. AniRise is live.\r\n      </p>\r\n\r\n      <p>\r\n        AniRise is more than just an anime website. It is a platform built\r\n        with attention to detail, care for the community, and genuine love\r\n        for anime culture.\r\n      </p>\r\n\r\n      <p>Here you will find:</p>\r\n\r\n      <ul>\r\n        <li>personal anime collection management</li>\r\n        <li>interest-based clubs</li>\r\n        <li>posts, comments, and discussions</li>\r\n        <li>profile personalization</li>\r\n        <li>and much more coming soon</li>\r\n      </ul>\r\n\r\n      <p>\r\n        This release is only the beginning. We are already working on new features,\r\n        improving stability, and expanding the platform’s capabilities.\r\n      </p>\r\n\r\n      <p>\r\n        Thank you to everyone who becomes part of this journey.\r\n        AniRise is alive — and this is just the start.\r\n      </p>\r\n    </div>\r\n\r\n    <div class=\"ha-clear\"></div>\r\n  </div>\r\n</div>\r\n',4590,1,'2026-01-20 22:37:16.270073');
/*!40000 ALTER TABLE `HomeAnnouncements` ENABLE KEYS */;
UNLOCK TABLES;

