INSERT INTO `News` VALUES (2,'First Test News','<p style=\"background:#ccc;color:red;\">Ja pierdole pierdole , It works!</p>','5043e8f3-d504-11f0-96f1-0242ac120002','2025-12-09 13:57:45.594311',NULL,''),(3,'WE TRY HARD','<p>\n  Currently, there is only a small selection of anime available on our platform.\n  However, our team is working hard to add as much data as possible!\n</p>\n\n<video\n  src=\"https://res.cloudinary.com/dd0oqs9r2/video/upload/v1769014819/news/tv0inw2zz8zls0gkvsqa.mp4\"\n  controls\n  style=\"\n    width: 350px;\n    height: 400px;\n    object-fit: cover;\n    border-radius: 12px;\n    box-shadow: 0 10px 25px rgba(0,0,0,0.15);\n    display: block;\n    margin: 16px;\n  \"\n>\n  Your browser does not support the video tag.\n</video>\n\n<p>\n  You will be able to browse information, create your own watchlists,\n  and plan your anime sessions. This is just the beginning!\n</p>','5043e8f3-d504-11f0-96f1-0242ac120002','2026-01-21 17:05:04.390936',NULL,'<p>\n  Currently, there is only a small selection of anime available on our platform.\n  However, our team is working hard to add as much data as possible!\n</p>\n\n<video\n  src=\"https://res.cloudinary.com/dd0oqs9r2/video/upload/v1769014819/news/tv0inw2zz8zls0gkvsqa.mp4\"\n  controls\n  style=\"\n    width: 350px;\n    height: 400px;\n    object-fit: cover;\n    border-radius: 12px;\n    box-shadow: 0 10px 25px rgba(0,0,0,0.15);\n    display: block;\n    margin: 16px auto;\n  \"\n>\n  Your browser does not support the video tag.\n</video>\n\n<p>\n  You will be able to browse information, create your own watchlists,\n  and plan your anime sessions. This is just the beginning!\n</p>\n'),(4,'Platform Progress','<div\n  style=\"\n    width: 100%;\n    padding: 32px;\n    border-radius: 18px;\n    background: linear-gradient(\n      135deg,\n      rgba(139, 92, 246, 0.08),\n      rgba(236, 72, 153, 0.06)\n    );\n    color: var(--text-main);\n  \"\n>\n  <!-- BADGE -->\n  <div\n    style=\"\n      display: inline-block;\n      padding: 6px 14px;\n      border-radius: 999px;\n      font-size: 13px;\n      font-weight: 600;\n      background: rgba(139, 92, 246, 0.15);\n      color: var(--accent);\n      margin-bottom: 16px;\n    \"\n  >\n    Platform Update\n  </div>\n\n  <!-- TITLE -->\n  <h2\n    style=\"\n      font-size: 32px;\n      font-weight: 800;\n      line-height: 1.2;\n      margin-bottom: 16px;\n    \"\n  >\n    AniRise Is Growing — Step by Step\n  </h2>\n\n  <!-- IMAGE -->\n  <img\n    src=\"https://res.cloudinary.com/YOUR_CLOUD_NAME/image/upload/v1768948635/news/anime_update.jpg\"\n    alt=\"AniRise progress\"\n    style=\"\n      width: 100%;\n      max-height: 420px;\n      object-fit: cover;\n      border-radius: 14px;\n      margin: 24px 0;\n      box-shadow: 0 20px 40px rgba(0,0,0,0.18);\n    \"\n  />\n\n  <!-- CONTENT -->\n  <div\n    style=\"\n      font-size: 17px;\n      line-height: 1.75;\n      color: var(--text-secondary);\n      max-width: 900px;\n    \"\n  >\n    <p style=\"margin-bottom: 18px;\">\n      Currently, the amount of anime available on AniRise is still limited.\n      This is a natural stage for a growing platform, and we want to be open about it.\n    </p>\n\n    <p style=\"margin-bottom: 18px;\">\n      Our team is actively working on expanding the database — adding new titles,\n      improving metadata, and making sure the information stays accurate and useful.\n    </p>\n\n    <p style=\"margin-bottom: 18px;\">\n      Very soon, you will be able to build larger watchlists, explore more anime,\n      and plan your future viewing sessions with ease.\n    </p>\n\n    <p>\n      AniRise is evolving every day.\n      Thank you for being part of this journey from the very beginning.\n    </p>\n  </div>\n</div>\n','5043e8f3-d504-11f0-96f1-0242ac120002','2026-01-21 17:15:24.719200',NULL,'<div\n  style=\"\n    width: 100%;\n    padding: 32px;\n    border-radius: 18px;\n    background: linear-gradient(\n      135deg,\n      rgba(139, 92, 246, 0.08),\n      rgba(236, 72, 153, 0.06)\n    );\n    color: var(--text-main);\n  \"\n>\n  <!-- BADGE -->\n  <div\n    style=\"\n      display: inline-block;\n      padding: 6px 14px;\n      border-radius: 999px;\n      font-size: 13px;\n      font-weight: 600;\n      background: rgba(139, 92, 246, 0.15);\n      color: var(--accent);\n      margin-bottom: 16px;\n    \"\n  >\n    Platform Update\n  </div>\n\n  <!-- TITLE -->\n  <h2\n    style=\"\n      font-size: 32px;\n      font-weight: 800;\n      line-height: 1.2;\n      margin-bottom: 16px;\n    \"\n  >\n    AniRise Is Growing — Step by Step\n  </h2>\n\n  <!-- IMAGE -->\n  <img\n    src=\"https://res.cloudinary.com/YOUR_CLOUD_NAME/image/upload/v1768948635/news/anime_update.jpg\"\n    alt=\"AniRise progress\"\n    style=\"\n      width: 100%;\n      max-height: 420px;\n      object-fit: cover;\n      border-radius: 14px;\n      margin: 24px 0;\n      box-shadow: 0 20px 40px rgba(0,0,0,0.18);\n    \"\n  />\n\n  <!-- CONTENT -->\n  <div\n    style=\"\n      font-size: 17px;\n      line-height: 1.75;\n      color: var(--text-secondary);\n      max-width: 900px;\n    \"\n  >\n    <p style=\"margin-bottom: 18px;\">\n      Currently, the amount of anime available on AniRise is still limited.\n      This is a natural stage for a growing platform, and we want to be open about it.\n    </p>\n\n    <p style=\"margin-bottom: 18px;\">\n      Our team is actively working on expanding the database — adding new titles,\n      improving metadata, and making sure the information stays accurate and useful.\n    </p>\n\n    <p style=\"margin-bottom: 18px;\">\n      Very soon, you will be able to build larger watchlists, explore more anime,\n      and plan your future viewing sessions with ease.\n    </p>\n\n    <p>\n      AniRise is evolving every day.\n      Thank you for being part of this journey from the very beginning.\n    </p>\n  </div>\n</div>\n');
/*!40000 ALTER TABLE `News` ENABLE KEYS */;
